import zmq
import threading
import os
import json
from typing import Dict, Any

def start_zmq_server(host: str = "127.0.0.1", port: int = 5555) -> tuple[Dict[str, Any], threading.Condition]:
    shared_data = {}
    data_condition = threading.Condition()

    def server_thread():
        context = zmq.Context()
        socket = context.socket(zmq.REP)
        address = f"tcp://{host}:{port}"
        socket.bind(address)

        os.environ["ZMQ_SERVER_ADDRESS"] = address

        while True:
            try:
                message = socket.recv_json()

                with data_condition:
                    if message["action"] == "get":
                        response = {"status": "ok", "data": shared_data.get(message["key"])}
                    elif message["action"] == "set":
                        shared_data[message["key"]] = message["value"]
                        response = {"status": "ok"}
                    elif message["action"] == "delete":
                        if message["key"] in shared_data:
                            del shared_data[message["key"]]
                            response = {"status": "ok"}
                        else:
                            response = {"status": "error", "message": "Key not found"}
                    else:
                        response = {"status": "error", "message": "Invalid action"}

                    data_condition.notify_all()

                socket.send_json(response)

            except Exception as e:
                socket.send_json({"status": "error", "message": str(e)})

    server = threading.Thread(target=server_thread, daemon=True)
    server.start()

    return shared_data, data_condition
