import json
from typing import Dict, Type, Callable, Any, Optional
from abc import ABC, abstractmethod

class JSONSerializable(ABC):
    _factory_registry: Dict[str, Callable[..., 'JSONSerializable']] = {}

    def to_json(self) -> str:
        return json.dumps(self.to_dict())

    @abstractmethod
    def to_dict(self) -> dict:
        pass

    @classmethod
    def from_json(cls, json_str: str) -> 'JSONSerializable':
        data = json.loads(json_str)
        return cls.from_dict(data)

    @classmethod
    def from_dict(cls, data: dict) -> 'JSONSerializable':
        if '_type' not in data:
            raise ValueError("Missing '_type' field in JSON data")

        type_id = data['_type']
        if type_id not in cls._factory_registry:
            raise ValueError(f"Unknown type ID: {type_id}")

        factory = cls._factory_registry[type_id]
        return factory(data)

    @classmethod
    def register_factory(cls, type_id: str, factory: Callable[..., 'JSONSerializable']):
        cls._factory_registry[type_id] = factory

    @classmethod
    def create(cls, type_id: str, *args, **kwargs) -> 'JSONSerializable':
        if type_id not in cls._factory_registry:
            raise ValueError(f"Unknown type ID: {type_id}")
        return cls._factory_registry[type_id](*args, **kwargs)

class Person(JSONSerializable):
    def __init__(self, name: str, age: int):
        self.name = name
        self.age = age

    def to_dict(self) -> dict:
        return {
            '_type': 'person',
            'name': self.name,
            'age': self.age
        }

    @classmethod
    def from_dict(cls, data: dict) -> 'Person':
        return cls(data['name'], data['age'])

class Book(JSONSerializable):
    def __init__(self, title: str, author: str):
        self.title = title
        self.author = author

    def to_dict(self) -> dict:
        return {
            '_type': 'book',
            'title': self.title,
            'author': self.author
        }

    @classmethod
    def from_dict(cls, data: dict) -> 'Book':
        return cls(data['title'], data['author'])

# Register factory functions
JSONSerializable.register_factory('person', Person.from_dict)
JSONSerializable.register_factory('book', Book.from_dict)
