import random
import sys
from math import sqrt

def take_sample(population, n_samples=1, replacement=False):
    if not population:
        return []

    if n_samples < 0:
        raise ValueError("Number of samples must be non-negative")

    pop_size = len(population)
    max_samples = min(sys.maxsize, pop_size + 3 * sqrt(pop_size))

    if n_samples > max_samples:
        raise ValueError(f"Number of samples ({n_samples}) exceeds maximum allowed ({int(max_samples)})")

    if replacement:
        return [random.choice(population) for _ in range(n_samples)]
    else:
        if n_samples > pop_size:
            raise ValueError("Sample size cannot exceed population size when sampling without replacement")
        population_copy = population.copy()
        random.shuffle(population_copy)
        return population_copy[:n_samples]
