class ParsedData:
    def __init__(self, type_val, intensity, size, generation, choice):
        self.type = type_val
        self.intensity = intensity
        self.size = size
        self.generation = generation
        self.choice = choice

def parse_string(input_str):
    try:
        parts = input_str.split(',')
        if len(parts) != 5:
            raise ValueError("Invalid input format")

        type_val = parts[0].strip()
        intensity = eval(parts[1].strip())
        size = eval(parts[2].strip())
        generation = eval(parts[3].strip())
        choice = eval(parts[4].strip())

        if not isinstance(intensity, int) or not isinstance(size, int) or \
           not isinstance(generation, int) or not isinstance(choice, int):
            raise ValueError("Values must be integers")

        if not type_val:
            raise ValueError("Type cannot be empty")

        return ParsedData(type_val, intensity, size, generation, choice)

    except (SyntaxError, NameError, ValueError) as e:
        raise ValueError(f"Invalid input string: {str(e)}")

def update_model_weights(model, layer_names, weights_dict, output_path, save_format='h5'):
    """
    Updates specific layers' weights in a model and saves it.
    """
    for layer_name in layer_names:
        if layer_name in weights_dict and layer_name in [layer.name for layer in model.layers]:
            layer = model.get_layer(layer_name)
            current_weights = layer.get_weights()
            new_weights = weights_dict[layer_name]

            if len(current_weights) == len(new_weights):
                layer.set_weights(new_weights)
            else:
                raise ValueError(f"Weight shapes mismatch for layer {layer_name}")

    try:
        if save_format.lower() == 'h5':
            model.save(output_path, save_format='h5')
        elif save_format.lower() == 'tf':
            model.save(output_path, save_format='tf')
        else:
            raise ValueError("Unsupported save format. Use 'h5' or 'tf'")
        return True
    except Exception as e:
        print(f"Error saving model: {str(e)}")
        return False

