import socket
import threading
import time
from http.server import HTTPServer, BaseHTTPRequestHandler
from typing import Optional, Dict, Any, Callable
import json

class MockServer:
    def __init__(self, port: int = 8080):
        self.port = port
        self.server: Optional[HTTPServer] = None
        self.thread: Optional[threading.Thread] = None
        self.routes: Dict[str, Callable] = {}
        self.is_running = False

    class RequestHandler(BaseHTTPRequestHandler):
        def do_GET(self):
            response = self.server.routes.get(self.path)
            if response:
                self.send_response(200)
                self.send_header('Content-Type', 'application/json')
                self.end_headers()
                if callable(response):
                    response_data = response()
                else:
                    response_data = response
                self.wfile.write(json.dumps(response_data).encode())
            else:
                self.send_response(404)
                self.end_headers()

        def do_POST(self):
            content_length = int(self.headers.get('Content-Length', 0))
            post_data = self.rfile.read(content_length)

            response = self.server.routes.get(self.path)
            if response:
                self.send_response(200)
                self.send_header('Content-Type', 'application/json')
                self.end_headers()
                if callable(response):
                    response_data = response(json.loads(post_data))
                else:
                    response_data = response
                self.wfile.write(json.dumps(response_data).encode())
            else:
                self.send_response(404)
                self.end_headers()

        def log_message(self, format, *args):
            # Suppress logging
            pass

    def add_route(self, path: str, response: Any):
        self.routes[path] = response

    def start(self):
        if self.is_running:
            return

        self.RequestHandler.routes = self.routes
        self.server = HTTPServer(('localhost', self.port), self.RequestHandler)
        self.thread = threading.Thread(target=self.server.serve_forever)
        self.thread.daemon = True
        self.thread.start()
        self.is_running = True

        # Wait for server to start
        retry = 0
        while retry < 5:
            try:
                with socket.create_connection(('localhost', self.port), timeout=1.0):
                    return
            except (socket.error, ConnectionRefusedError):
                time.sleep(0.1)
                retry += 1
        raise RuntimeError("Failed to start mock server")

    def stop(self):
        if self.server and self.is_running:
            self.server.shutdown()
            self.server.server_close()
            self.thread.join()
            self.is_running = False
            self.server = None
            self.thread = None

    def __enter__(self):
        self.start()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.stop()

# Example usage:
if __name__ == "__main__":
    def dynamic_response(data=None):
        return {"message": "Hello", "received_data": data}

    mock_server = MockServer(port=8080)
    mock_server.add_route("/static", {"status": "ok"})
    mock_server.add_route("/dynamic", dynamic_response)

    with mock_server:
        # Server is running here
        input("Press Enter to stop server...")
