def generate_dataset(columns, runs, size):
    import random
    dataset = []
    samples_per_run = size // runs

    for col in range(columns):
        column_data = []
        range_start = col * 10
        range_end = (col + 1) * 10

        for _ in range(runs):
            sample = [random.uniform(range_start, range_end) for _ in range(samples_per_run)]
            column_data.extend(sample)

        dataset.append(column_data)

    return list(zip(*dataset))

def block_ip_addresses(ip_port_dict, countries_to_block):
    blocked_ips = {}

    for ip, port in ip_port_dict.items():
        try:
            response = requests.get(f'http://ip-api.com/json/{ip}')
            data = response.json()

            if data['status'] == 'success':
                country_code = data['countryCode'].lower()
                if country_code in [country.lower() for country in countries_to_block]:
                    blocked_ips[ip] = port
        except:
            continue

    return blocked_ips

