            if not args:
                random_arg = generate_random_string(10)
                args = (random_arg,)
            return super(cls, cls).__new__(cls, *args, **kwargs)

        attrs['__new__'] = staticmethod(__new__)
        return super().__new__(cls, name, bases, attrs)

class Example(metaclass=TypeMeta):
