import requests
import math
import os

def download_file_in_parts(file_url, max_part_size_bytes, output_path=None):
    MIN_PART_SIZE = 1024 * 1024  # 1MB minimum part size
    MAX_PARTS = 10000  # Maximum number of parts allowed

    # Get file size
    response = requests.head(file_url)
    file_size = int(response.headers.get('content-length', 0))

    if file_size == 0:
        raise ValueError("Could not determine file size")

    # Calculate optimal part size and number of parts
    num_parts = math.ceil(file_size / max_part_size_bytes)

    if num_parts > MAX_PARTS:
        # Recalculate part size to stay within MAX_PARTS limit
        part_size = math.ceil(file_size / MAX_PARTS)
        num_parts = MAX_PARTS
    else:
        part_size = max_part_size_bytes

    if part_size < MIN_PART_SIZE:
        part_size = MIN_PART_SIZE
        num_parts = math.ceil(file_size / part_size)

    # Set output path
    if output_path is None:
        output_path = os.path.basename(file_url)

    # Download parts
    with open(output_path, 'wb') as f:
        for i in range(num_parts):
            start = i * part_size
            end = min(start + part_size - 1, file_size - 1)

            headers = {'Range': f'bytes={start}-{end}'}
            response = requests.get(file_url, headers=headers, stream=True)

            if response.status_code not in [200, 206]:
                raise Exception(f"Failed to download part {i+1}/{num_parts}")

            for chunk in response.iter_content(chunk_size=8192):
                if chunk:
                    f.write(chunk)

    return {
        'file_size': file_size,
        'num_parts': num_parts,
        'part_size': part_size,
        'output_path': output_path
    }
