import os
from datetime import datetime, timedelta

def get_current_date():
    return datetime.now()

def get_previous_date(days_ago):
    current_date = get_current_date()
    previous_date = current_date - timedelta(days=days_ago)
    return previous_date

def read_last_entry():
    try:
        data_dir = os.path.join(os.getcwd(), 'data')
        file_path = os.path.join(data_dir, 'last_entry')

        if not os.path.exists(data_dir):
            os.makedirs(data_dir)
            return None

        if os.path.exists(file_path):
            with open(file_path, 'r') as file:
                lines = file.readlines()
                return lines[-1].strip() if lines else None
        return None
    except Exception as e:
        print(f"Error reading last entry: {e}")
        return None

def main():
    current_date = get_current_date()
    days_ago = int(input("Enter number of days to look back: "))
    previous_date = get_previous_date(days_ago)

    print(f"Current Year: {current_date.year}")
    print(f"Current Month: {current_date.month}")
    print(f"Current Day: {current_date.day}")

    print(f"\nPrevious Year: {previous_date.year}")
    print(f"Previous Month: {previous_date.month}")
    print(f"Previous Day: {previous_date.day}")

    last_entry = read_last_entry()
    if last_entry:
        print(f"\nLast Entry: {last_entry}")
    else:
        print("\nNo last entry found")

if __name__ == "__main__":
    main()

