import mock
import random

def get_oldest_non_default_policy(policy_index):
    fake_headers = [
        {'X-Backend-Storage-Policy-Index': '0'},
        {'X-Backend-Storage-Policy-Index': '1'},
        {'X-Backend-Storage-Policy-Index': '2'},
        {'X-Backend-Storage-Policy-Index': str(policy_index)}
    ]
    random.shuffle(fake_headers)

    def mock_get_container_policy_index(self, account, container, req=None):
        if not fake_headers:
            return 0
        header = fake_headers.pop()
        return int(header['X-Backend-Storage-Policy-Index'])

    with mock.patch('swift.proxy.controllers.base.get_container_policy_index', 
                   mock_get_container_policy_index):
        oldest_non_default = None
        for header in fake_headers:
            policy_idx = int(header['X-Backend-Storage-Policy-Index'])
            if policy_idx != 0:
                if oldest_non_default is None or policy_idx < oldest_non_default:
                    oldest_non_default = policy_idx

        return oldest_non_default if oldest_non_default is not None else 0
