import itertools
import random

def batch_iterator(lists, batch_size, num_cycles):
    if not lists or not all(lists):
        raise ValueError("Empty lists are not allowed")

    lengths = [len(lst) for lst in lists]
    if len(set(lengths)) > 1:
        raise ValueError("All lists must have the same length")

    indices = list(range(lengths[0]))
    cycle_count = 0

    while cycle_count < num_cycles:
        random.shuffle(indices)

        for i in range(0, len(indices), batch_size):
            if i + batch_size > len(indices):
                break

            batch_indices = indices[i:i + batch_size]
            yield tuple(zip(*[[lst[idx] for idx in batch_indices] for lst in lists]))

        cycle_count += 1

    raise StopIteration()

