import psycopg2
from psycopg2 import Error

def create_db_and_user(db_name, db_user=None):
    try:
        # Connect to default postgres database
        conn = psycopg2.connect(
            host="localhost",
            database="postgres",
            user="postgres",
            password="postgres"
        )
        conn.autocommit = True
        cursor = conn.cursor()

        # Create new user if specified
        if db_user:
            cursor.execute(f"SELECT 1 FROM pg_roles WHERE rolname='{db_user}'")
            if not cursor.fetchone():
                cursor.execute(f"CREATE USER {db_user} WITH PASSWORD '{db_user}'")

        # Create new database
        cursor.execute(f"SELECT 1 FROM pg_database WHERE datname='{db_name}'")
        if not cursor.fetchone():
            if db_user:
                cursor.execute(f"CREATE DATABASE {db_name} OWNER {db_user}")
            else:
                cursor.execute(f"CREATE DATABASE {db_name}")

    except (Exception, Error) as error:
        print(f"Error creating database/user: {error}")
    finally:
        if conn:
            cursor.close()
            conn.close()
