import sys
import importlib
from types import ModuleType
from typing import List, Dict, Optional

def import_with_dynamic_loading(module_names: List[str], dynamic_flags: Dict[str, bool]) -> List[Optional[ModuleType]]:
    original_flags = {}
    imported_modules = []

    try:
        # Save original flags
        for flag_name in dynamic_flags:
            if hasattr(sys.flags, flag_name):
                original_flags[flag_name] = getattr(sys.flags, flag_name)

        # Set dynamic flags
        for flag_name, value in dynamic_flags.items():
            if hasattr(sys.flags, flag_name):
                setattr(sys.flags, flag_name, value)

        # Import modules
        for module_name in module_names:
            try:
                module = importlib.import_module(module_name)
                imported_modules.append(module)
            except ImportError:
                imported_modules.append(None)

    finally:
        # Restore original flags
        for flag_name, value in original_flags.items():
            if hasattr(sys.flags, flag_name):
                setattr(sys.flags, flag_name, value)

    return imported_modules

