class Quantity:
    def __init__(self, amount, unit, error_low=None, error_high=None):
        self.amount = amount
        self.unit = unit
        self.error_low = error_low
        self.error_high = error_high

    @classmethod
    def from_json(cls, json_data):
        return cls(
            amount=json_data['amount'],
            unit=json_data['unit'],
            error_low=json_data.get('error_low'),
            error_high=json_data.get('error_high')
        )

    def to_json(self):
        json_data = {
            'amount': self.amount,
            'unit': self.unit
        }
        if self.error_low is not None:
            json_data['error_low'] = self.error_low
        if self.error_high is not None:
            json_data['error_high'] = self.error_high
        return json_data

    def __str__(self):
        base = f"{self.amount} {self.unit}"
        if self.error_low is not None and self.error_high is not None:
            return f"{base} (+{self.error_high}/-{self.error_low})"
        return base

    def __eq__(self, other):
        if not isinstance(other, Quantity):
            return False
        return (self.amount == other.amount and
                self.unit == other.unit and
                self.error_low == other.error_low and
                self.error_high == other.error_high)
