import random

class Person:
    def __init__(self, name, age, height):
        self.name = name
        self.age = age
        self.height = height

    def __eq__(self, other):
        if not isinstance(other, Person):
            return False
        return self.age == other.age and self.height == other.height

def create_and_compare_people():
    names = ["Alice", "Bob", "Charlie", "David", "Eve"]

    person1 = Person(
        random.choice(names),
        random.randint(18, 80),
        random.uniform(150, 200)
    )

    person2 = Person(
        random.choice(names),
        person1.age,
        person1.height
    )

    assert person1 == person2, "People should be equal based on age and height"

    person3 = Person(
        random.choice(names),
        random.randint(18, 80),
        random.uniform(150, 200)
    )

    try:
        assert person1 == person3
    except AssertionError:
        return True

    return False

if __name__ == "__main__":
    result = create_and_compare_people()
    print(f"Test completed successfully: {result}")

import random

def modify_list(input_list):
    if not input_list or not all(1 <= x <= 50 for x in input_list):
        return []

    faza = random.choice([0, 1])
    subset_size = random.randint(1, len(input_list))
    subset = random.sample(input_list, subset_size)

    if faza == 0:
        num_to_remove = random.randint(1, len(subset))
        for _ in range(num_to_remove):
            if subset:
                subset.remove(random.choice(subset))
    else:
        num_to_add = random.randint(1, 5)
        for _ in range(num_to_add):
            new_num = random.randint(1, 50)
            subset.append(new_num)

    remaining = [x for x in input_list if x not in subset]
    result = remaining + subset
    random.shuffle(result)

    return result

