            # Apply curve if present
            if note['curve']:
                new_note['x'], new_note['y'] = apply_curve(
                    note['curve'],
                    note['x'],
                    note['y'],
                    i
                )

            musical_sequence.append(new_note)

    # Sort sequence by time
    musical_sequence.sort(key=lambda x: x['time'])
    return musical_sequence

def get_note_duration(note_type):
    durations = {
        'whole': 4.0,
        'half': 2.0,
        'quarter': 1.0,
        'eighth': 0.5,
        'sixteenth': 0.25
    }
    return durations.get(note_type, 1.0)

def apply_curve(curve_type, x, y, step):
    from math import sin, cos, pi

    if curve_type == 'circle':
        radius = ((x ** 2 + y ** 2) ** 0.5)
        angle = step * (pi/4)
        return (radius * cos(angle), radius * sin(angle))

    elif curve_type == 'sine':
        return (x + step, y + sin(step))

    elif curve_type == 'linear':
        return (x + step, y + step)

    return (x, y)
