import subprocess
import time
import os
from datetime import datetime
import re

class AndroidMonitor:
    def __init__(self, screenshot_interval=5):
        self.screenshot_interval = screenshot_interval
        self.last_screenshot = 0
        self.screenshot_dir = "screenshots"
        self.log_file = "device_logs.txt"

        if not os.path.exists(self.screenshot_dir):
            os.makedirs(self.screenshot_dir)

    def check_device_connected(self):
        try:
            result = subprocess.run(['adb', 'devices'], capture_output=True, text=True)
            return len(result.stdout.strip().split('\n')) > 1
        except:
            return False

    def capture_screenshot(self):
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        filename = f"{self.screenshot_dir}/screen_{timestamp}.png"

        try:
            subprocess.run([
                'adb', 'exec-out', 'screencap', '-p'
            ], stdout=open(filename, 'wb'))
            print(f"Screenshot saved: {filename}")
        except Exception as e:
            print(f"Failed to capture screenshot: {e}")

    def parse_logcat_line(self, line):
        # Basic log parsing - customize based on your needs
        pattern = r'(\d{2}-\d{2}\s\d{2}:\d{2}:\d{2}\.\d{3})\s+(\d+)\s+(\d+)\s+([VDIWE])\s+([^:]+):\s+(.+)'
        match = re.match(pattern, line)
        if match:
            return {
                'timestamp': match.group(1),
                'pid': match.group(2),
                'tid': match.group(3),
                'level': match.group(4),
                'tag': match.group(5),
                'message': match.group(6)
            }
        return None

    def monitor_logcat(self):
        try:
            process = subprocess.Popen(
                ['adb', 'logcat'],
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                bufsize=1,
                universal_newlines=True
            )

            with open(self.log_file, 'a') as log_file:
                while True:
                    line = process.stdout.readline()
                    if not line:
                        break

                    parsed_log = self.parse_logcat_line(line)
                    if parsed_log:
                        log_file.write(f"{str(parsed_log)}\n")
                        log_file.flush()

        except Exception as e:
            print(f"Error monitoring logcat: {e}")

    def run(self):
        print("Starting Android device monitoring...")

        while True:
            if not self.check_device_connected():
                print("Device disconnected. Exiting...")
                break

            current_time = time.time()
            if current_time - self.last_screenshot >= self.screenshot_interval:
                self.capture_screenshot()
                self.last_screenshot = current_time

            # Start logcat monitoring in parallel
            try:
                self.monitor_logcat()
            except KeyboardInterrupt:
                break
            except Exception as e:
                print(f"Error: {e}")
                time.sleep(1)

            time.sleep(0.1)

if __name__ == "__main__":
    monitor = AndroidMonitor(screenshot_interval=5)
    monitor.run()
