def modify_instance_variable(instance, code_string):
    globals_dict = instance.__class__.__dict__.copy()
    locals_dict = instance.__dict__.copy()

    exec(code_string, globals_dict, locals_dict)

    for key, value in locals_dict.items():
        if not key.startswith('__'):
