def compile_model(config):
    """Compiles a machine learning model based on configuration parameters."""
    import tensorflow as tf
    from tensorflow.keras.models import Sequential
    from tensorflow.keras.layers import Dense, Dropout, Conv2D, MaxPooling2D, Flatten
    from tensorflow.keras.optimizers import Adam, SGD, RMSprop
    import numpy as np
    import pandas as pd
    from sklearn.preprocessing import StandardScaler

    def load_data(data_path):
        if data_path.endswith('.csv'):
            data = pd.read_csv(data_path)
        elif data_path.endswith('.npy'):
            data = np.load(data_path)
        else:
            raise ValueError("Unsupported file format")
        return data

    def preprocess_data(data, preprocessing_config):
        if preprocessing_config.get('scaling', False):
            scaler = StandardScaler()
            data = scaler.fit_transform(data)
        return data

    # Load data
    X_train = load_data(config['train_data_path'])
    y_train = load_data(config['train_labels_path'])

    # Preprocess data if specified
    if 'preprocessing' in config:
        X_train = preprocess_data(X_train, config['preprocessing'])

    # Define model architecture
    model = Sequential()

    # Add layers based on configuration
    for layer in config['layers']:
        if layer['type'] == 'dense':
            model.add(Dense(layer['units'], activation=layer['activation']))
        elif layer['type'] == 'dropout':
            model.add(Dropout(layer['rate']))
        elif layer['type'] == 'conv2d':
            model.add(Conv2D(layer['filters'], layer['kernel_size'], activation=layer['activation']))
        elif layer['type'] == 'maxpool2d':
            model.add(MaxPooling2D(pool_size=layer['pool_size']))
        elif layer['type'] == 'flatten':
            model.add(Flatten())

    # Set optimizer
    optimizer_name = config['optimizer']['name'].lower()
    optimizer_params = config['optimizer'].get('params', {})

    if optimizer_name == 'adam':
        optimizer = Adam(**optimizer_params)
    elif optimizer_name == 'sgd':
        optimizer = SGD(**optimizer_params)
    elif optimizer_name == 'rmsprop':
        optimizer = RMSprop(**optimizer_params)
    else:
        raise ValueError(f"Unsupported optimizer: {optimizer_name}")

    # Compile model
    model.compile(
        optimizer=optimizer,
        loss=config['loss'],
        metrics=config['metrics']
    )

    return model

