def send_message_with_retry(text_input, context=None, max_retries=3, retry_delay=1):
    import time
    from typing import Optional, Dict, Any

    def call_ai_api(text: str, context: Optional[Dict[str, Any]] = None):
        try:
            # Replace with actual AI API call
            response = ai_service.send_message(
                text=text,
                context=context or {}
            )
            return response
        except Exception as e:
            raise e

    attempts = 0
    last_error = None

    while attempts < max_retries:
        try:
            response = call_ai_api(text_input, context)
            return response

        except Exception as e:
            last_error = e
            attempts += 1

            if attempts < max_retries:
                time.sleep(retry_delay)
            else:
                raise Exception(f"Failed after {max_retries} attempts. Last error: {str(last_error)}")

    return None
