import gzip
import re

def gff3_to_gtf(input_file, output_file, dialect='ensembl'):
    def parse_attributes(attr_string, dialect):
        attributes = {}
        if dialect == 'ensembl':
            for attr in attr_string.split(';'):
                if '=' in attr:
                    key, value = attr.strip().split('=', 1)
                    attributes[key] = value.strip('"')
        return attributes

    def format_gtf_attributes(attributes, dialect):
        if dialect == 'ensembl':
            formatted = []
            if 'ID' in attributes:
                formatted.append(f'gene_id "{attributes["ID"]}";')
            if 'Parent' in attributes:
                formatted.append(f'transcript_id "{attributes["Parent"]}";')
            if 'Name' in attributes:
                formatted.append(f'gene_name "{attributes["Name"]}";')
            return ' '.join(formatted)
        return ''

    def is_gzipped(filename):
        with open(filename, 'rb') as f:
            return f.read(2).startswith(b'\x1f\x8b')

    def get_file_handle(filename):
        if is_gzipped(filename):
            return gzip.open(filename, 'rt')
        return open(filename, 'r')

    with get_file_handle(input_file) as infile, open(output_file, 'w') as outfile:
        for line in infile:
            if line.startswith('#'):
                continue

            fields = line.strip().split('\t')
            if len(fields) != 9:
                continue

            seqname, source, feature, start, end, score, strand, frame, attributes = fields

            # Parse GFF3 attributes
            attr_dict = parse_attributes(attributes, dialect)

            # Format GTF attributes
            gtf_attributes = format_gtf_attributes(attr_dict, dialect)

            # Convert score and frame to GTF format
            score = '.' if score == '.' else score
            frame = '.' if frame == '.' else frame

            # Write GTF line
            gtf_line = '\t'.join([
                seqname,
                source,
                feature,
                start,
                end,
                score,
                strand,
                frame,
                gtf_attributes
            ]) + '\n'

            outfile.write(gtf_line)

