import json

class Quantity:
    def __init__(self, data):
        self.amount = float(data['amount'])
        self.unit = data['unit']
        self.upper_bound = float(data['upperBound'])
        self.lower_bound = self.amount - (self.upper_bound - self.amount)

    @classmethod
    def from_wikibase(cls, wb_data):
        data = {
            'amount': wb_data['amount'],
            'unit': wb_data['unit'],
            'upperBound': wb_data['upperBound'] if 'upperBound' in wb_data else wb_data['amount']
        }
        return cls(data)

    def __str__(self):
        return json.dumps({
            'amount': self.amount,
            'unit': self.unit,
            'upperBound': self.upper_bound,
            'lowerBound': self.lower_bound
        })

    def __eq__(self, other):
        if not isinstance(other, Quantity):
            return False
        return (self.amount == other.amount and
                self.unit == other.unit and
                self.upper_bound == other.upper_bound and
                self.lower_bound == other.lower_bound)
