def run_tests(test_cases):
    passed = 0
    failed = 0

    for test_func, expected in test_cases:
        try:
            result = str(eval(test_func))
            if result == expected:
                passed += 1
            else:
                failed += 1
                print(f"Test failed: {test_func}")
                print(f"Expected: {expected}")
                print(f"Got: {result}\n")
        except Exception as e:
            failed += 1
            print(f"Test failed: {test_func}")
            print(f"Error: {str(e)}\n")

    if failed == 0:
        print(f"All {passed} tests passed!")
    else:
        print(f"Tests completed: {passed + failed} total, {passed} passed, {failed} failed")

def read_settings(filename, defaults=None):
    if defaults is None:
        defaults = {}

    settings = defaults.copy()

    try:
        with open(filename, 'r') as file:
            for line in file:
                line = line.strip()
                if line and not line.startswith('#'):
                    try:
                        key, value = line.split('=', 1)
                        key = key.strip()
                        value = value.strip()

                        # Try to convert to appropriate type
                        if value.lower() == 'true':
                            value = True
                        elif value.lower() == 'false':
                            value = False
                        elif value.isdigit():
                            value = int(value)
                        elif value.replace('.', '', 1).isdigit():
                            value = float(value)

                        settings[key] = value
                    except ValueError:
                        continue
    except (IOError, OSError):
        pass

    return settings

import os
import glob

def generate_report(directory_path, coefficient=1.0):
    # Initialize lists to store data
    reticulations_list = []
    taxa_list = []
    increase_list = []
    decrease_list = []
    outgroup_list = []

    # Read statistics files
    for filename in glob.glob(os.path.join(directory_path, "*.statistics")):
        with open(filename, 'r') as f:
            lines = f.readlines()
            for line in lines:
                if "Reticulations:" in line:
                    reticulations_list.append(int(line.split(":")[1].strip()))
                elif "Taxa:" in line:
                    taxa_list.append(int(line.split(":")[1].strip()))
                elif "Increase:" in line:
                    increase_list.append(float(line.split(":")[1].strip()))
                elif "Decrease:" in line:
                    decrease_list.append(float(line.split(":")[1].strip()))
                elif "Outgroup:" in line:
                    outgroup_list.append(line.split(":")[1].strip())

    # Resize increase and decrease values
    increase_list = [x * coefficient for x in increase_list]
    decrease_list = [x * coefficient for x in decrease_list]

    # Concatenate alignment files
    alignment_content = ""
    for filename in glob.glob(os.path.join(directory_path, "*.aln")):
        with open(filename, 'r') as f:
            alignment_content += f.read() + "\n"

    # Generate report
    report = f"""Statistical Report
=================
Average Reticulations: {sum(reticulations_list)/len(reticulations_list):.2f}
Average Taxa: {sum(taxa_list)/len(taxa_list):.2f}
Average Increase: {sum(increase_list)/len(increase_list):.2f}
Average Decrease: {sum(decrease_list)/len(decrease_list):.2f}
Outgroups: {', '.join(outgroup_list)}

Concatenated Alignments:
======================
{alignment_content}
"""

    # Write report to file
    output_file = os.path.join(directory_path, "report.txt")
    with open(output_file, 'w') as f:
        f.write(report)

    return output_file

