import hashlib
from typing import Optional

class HashGenerator:
    def __init__(self, algorithm: str = 'sha256'):
        self.algorithm = algorithm
        self.hasher = self._create_hasher()

    def _create_hasher(self):
        if self.algorithm.lower() == 'md5':
            return hashlib.md5()
        elif self.algorithm.lower() == 'sha1':
            return hashlib.sha1()
        elif self.algorithm.lower() == 'sha256':
            return hashlib.sha256()
        elif self.algorithm.lower() == 'sha512':
            return hashlib.sha512()
        else:
            raise ValueError(f"Unsupported hash algorithm: {self.algorithm}")

    def get_hash(self, input_string: str) -> str:
        hasher_clone = self.hasher.copy()
        hasher_clone.update(input_string.encode())
        return hasher_clone.hexdigest()

    def update(self, input_string: str) -> None:
        self.hasher.update(input_string.encode())

    def get_current_hash(self) -> str:
        return self.hasher.copy().hexdigest()

    def clone(self) -> 'HashGenerator':
        new_generator = HashGenerator(self.algorithm)
        new_generator.hasher = self.hasher.copy()
        return new_generator

def compute_hash(input_string: str, algorithm: str = 'sha256') -> str:
    generator = HashGenerator(algorithm)
    return generator.get_hash(input_string)
