import hashlib
import hmac

def get_md5_hash(input_string):
    md5_hash = hashlib.md5()
    md5_hash.update(input_string.encode('utf-8'))
    return md5_hash.hexdigest()

def constant_time_compare(hash1, hash2):
    return hmac.compare_digest(hash1.encode('utf-8'), hash2.encode('utf-8'))

def secure_md5_hash_verify(input_string, expected_hash):
    calculated_hash = get_md5_hash(input_string)
    return constant_time_compare(calculated_hash, expected_hash)

import os
import hashlib

def read_file_contents(file_path):
    try:
        with open(file_path, 'r') as file:
            return file.read()
    except FileNotFoundError:
        return None

def calculate_hash(content):
    return hashlib.md5(content.encode()).hexdigest()

def save_version(file_path, content):
    version_path = f"{file_path}.version"
    with open(version_path, 'w') as version_file:
        version_file.write(calculate_hash(content))

def check_and_update_version(file_path):
    current_content = read_file_contents(file_path)
    if current_content is None:
        return False

    version_path = f"{file_path}.version"

    if not os.path.exists(version_path):
        save_version(file_path, current_content)
        return True

    stored_version = read_file_contents(version_path)
    current_hash = calculate_hash(current_content)

    if stored_version != current_hash:
        save_version(file_path, current_content)
        return True

    return False

if __name__ == "__main__":
    file_path = "example.txt"
    if check_and_update_version(file_path):
        print(f"File {file_path} was updated or version file was created")
    else:
        print(f"File {file_path} matches stored version")

