from scipy import stats
import numpy as np

def calculate_percentile_function(distribution_name, values, **kwargs):
    try:
        # Get distribution from scipy.stats
        distribution = getattr(stats, distribution_name)

        # Check if distribution has ppf method
        if not hasattr(distribution, 'ppf'):
            raise AttributeError(f"Distribution '{distribution_name}' does not have a percentile function")

        # Convert values to numpy array
        values = np.array(values)

        # Calculate percentile function
        if kwargs:
            ppf = distribution.ppf(values, **kwargs)
        else:
            ppf = distribution.ppf(values)

        return ppf

    except AttributeError as e:
        raise AttributeError(f"Error: {str(e)}")
    except Exception as e:
        raise Exception(f"Error calculating percentile function: {str(e)}")
