import shelve
from typing import Any, Dict, List, Optional, Union
from datetime import datetime
import os

class DataFilter:
    def __init__(self, filename: str):
        self.filename = filename
        self.recording = False
        self.playback = False
        self.current_session = None

    def start_recording(self, session_name: Optional[str] = None) -> None:
        if session_name is None:
            session_name = datetime.now().strftime("%Y%m%d_%H%M%S")
        self.current_session = session_name
        self.recording = True
        self.playback = False

    def stop_recording(self) -> None:
        self.recording = False
        self.current_session = None

    def start_playback(self, session_name: str) -> None:
        self.playback = True
        self.recording = False
        self.current_session = session_name

    def stop_playback(self) -> None:
        self.playback = False
        self.current_session = None

    def filter_data(self, data: Any, data_type: str) -> Any:
        if self.recording:
            self._save_data(data, data_type)
            return data
        elif self.playback:
            return self._load_data(data_type)
        return data

    def _save_data(self, data: Any, data_type: str) -> None:
        with shelve.open(self.filename) as db:
            if self.current_session not in db:
                db[self.current_session] = {}
            if data_type not in db[self.current_session]:
                db[self.current_session][data_type] = []
            db[self.current_session][data_type].append(data)

    def _load_data(self, data_type: str) -> Any:
        with shelve.open(self.filename) as db:
            if self.current_session in db and data_type in db[self.current_session]:
                data_list = db[self.current_session][data_type]
                if data_list:
                    return data_list.pop(0)
        return None

    def list_sessions(self) -> List[str]:
        with shelve.open(self.filename) as db:
            return list(db.keys())

    def get_session_data(self, session_name: str) -> Dict[str, List[Any]]:
        with shelve.open(self.filename) as db:
            return db.get(session_name, {})

    def delete_session(self, session_name: str) -> bool:
        with shelve.open(self.filename) as db:
            if session_name in db:
                del db[session_name]
                return True
        return False

    def clear_all_sessions(self) -> None:
        if os.path.exists(self.filename):
            os.remove(self.filename)

