    # Key file paths
    key_files = {
        'rsa1': ('ssh_host_key', ['-t', 'rsa1', '-b', '1024']),
        'rsa': ('ssh_host_rsa_key', ['-t', 'rsa', '-b', '2048']),
        'dsa': ('ssh_host_dsa_key', ['-t', 'dsa'])
    }

    try:
        # Create SSH directory if it doesn't exist
        if not ssh_path.exists():
            ssh_path.mkdir(parents=True, mode=0o755)

        # Remove existing keys
        for key_type, (key_name, _) in key_files.items():
            key_file = ssh_path / key_name
            pub_key_file = ssh_path / f"{key_name}.pub"

            try:
                if key_file.exists():
                    key_file.unlink()
                if pub_key_file.exists():
                    pub_key_file.unlink()
            except OSError as e:
                logger.error(f"Failed to remove existing {key_type} key: {str(e)}")

        # Generate new keys
        for key_type, (key_name, key_args) in key_files.items():
            key_file = ssh_path / key_name

            try:
                cmd = ['ssh-keygen', '-q', '-f', str(key_file), '-N', ''] + key_args
                subprocess.run(cmd, check=True, capture_output=True)

                # Set correct permissions
                key_file.chmod(0o600)
                pub_key_file = Path(str(key_file) + '.pub')
                pub_key_file.chmod(0o644)

                logger.info(f"Generated {key_type} SSH key: {key_file}")

            except subprocess.CalledProcessError as e:
                logger.error(f"Failed to generate {key_type} key: {e.stderr.decode()}")
            except OSError as e:
                logger.error(f"Failed to set permissions for {key_type} key: {str(e)}")

        # Update SSH configuration
        sshd_config = ssh_path / 'sshd_config'
        if sshd_config.exists():
            try:
                with open(sshd_config, 'r') as f:
                    config_lines = f.readlines()

                with open(sshd_config, 'w') as f:
                    for line in config_lines:
                        if not any(line.startswith(f"HostKey {ssh_path}/{key[0]}")
                                 for key in key_files.values()):
                            f.write(line)

                    # Add new host key entries
                    for key_name, _ in key_files.values():
                        f.write(f"HostKey {ssh_path}/{key_name}\n")

                logger.info("Updated SSH configuration successfully")

            except IOError as e:
                logger.error(f"Failed to update SSH configuration: {str(e)}")
        else:
            logger.error("SSH configuration file not found")

    except Exception as e:
        logger.error(f"Unexpected error during SSH key regeneration: {str(e)}")
        raise

    return True
