import warnings
import functools

def deprecate_attribute(old_name, new_name, version):
    def decorator(cls):
        def _get_deprecated(self):
            warnings.warn(
                f"{old_name} is deprecated since version {version}. Use {new_name} instead.",
                DeprecationWarning,
                stacklevel=2
            )
            return getattr(self, new_name)

        def _set_deprecated(self, value):
            warnings.warn(
                f"{old_name} is deprecated since version {version}. Use {new_name} instead.",
                DeprecationWarning,
                stacklevel=2
            )
            setattr(self, new_name, value)

        setattr(cls, old_name, property(_get_deprecated, _set_deprecated))
        return cls

    return decorator
