import pickle
import os

def load_pickle_file(filename):
    with open(filename, 'rb') as f:
        return pickle.load(f)

def save_pickle_file(data, filename):
    with open(filename, 'wb') as f:
        pickle.dump(data, f)

def linear_interpolate(data, x):
    x1 = max([x0 for x0 in data.keys() if x0 <= x])
    x2 = min([x0 for x0 in data.keys() if x0 >= x])

    if x1 == x2:
        return data[x1]

    y1, y2 = data[x1], data[x2]
    return y1 + (y2 - y1) * (x - x1) / (x2 - x1)

def interpolate_data(data):
    keys = sorted(data.keys())
    new_data = {}

    for i in range(len(keys) - 1):
        step = (keys[i + 1] - keys[i]) / 10
        for j in range(10):
            x = keys[i] + j * step
            new_data[x] = linear_interpolate(data, x)

    return new_data

def search_and_replace(data, search_val, replace_val):
    if isinstance(data, dict):
        return {k: search_and_replace(v, search_val, replace_val) for k, v in data.items()}
    elif isinstance(data, list):
        return [search_and_replace(x, search_val, replace_val) for x in data]
    elif isinstance(data, tuple):
        return tuple(search_and_replace(x, search_val, replace_val) for x in data)
    else:
        return replace_val if data == search_val else data

def main():
    # Load data from three pickle files
    data1 = load_pickle_file('file1.pickle')
    data2 = load_pickle_file('file2.pickle')
    data3 = load_pickle_file('file3.pickle')

    # Perform interpolation on data1
    interpolated_data = interpolate_data(data1)
    save_pickle_file(interpolated_data, 'interpolated.pickle')

    # Perform search and replace on data2
    modified_data = search_and_replace(data2, search_val=0, replace_val=1)
    save_pickle_file(modified_data, 'modified.pickle')

    # Combine and process data3
    processed_data = {
        'original': data3,
        'processed': search_and_replace(data3, None, 0)
    }
    save_pickle_file(processed_data, 'processed.pickle')

if __name__ == '__main__':
    main()

import sys

def execute_script(local_vars, script_str, secondary_script=None):
    try:
        if secondary_script and len(sys.argv) > 1:
            with open(secondary_script, 'r') as f:
                script_str = f.read()

        exec_globals = {}
        exec_globals.update(globals())
        exec_globals.update(local_vars)

        result = exec(script_str, exec_globals, local_vars)
        print(f"Execution result: {result}")
        return result

    except FileNotFoundError:
        print(f"Error: Secondary script '{secondary_script}' not found.")
        return None
    except Exception as e:
        print(f"Error during execution: {str(e)}")
        return None

if __name__ == "__main__":
