from collections import namedtuple
import ast
import inspect

def execute_function(function_str, options=None):
    if options is None:
        options = {}

    # Create namespace for execution
    namespace = {}

    # Add any named tuples defined in options
    for key, value in options.items():
        if isinstance(value, tuple) and hasattr(value, '_fields'):
            # Get the named tuple class
            fields = value._fields
            tuple_class = type(value)
            namespace[tuple_class.__name__] = tuple_class

    # Parse function string to AST
    tree = ast.parse(function_str)

    # Extract function name
    function_name = None
    for node in ast.walk(tree):
        if isinstance(node, ast.FunctionDef):
            function_name = node.name
            break

    if not function_name:
        raise ValueError("No function definition found in string")

    # Execute the function definition
    exec(function_str, namespace)

    # Get the function object
    function = namespace[function_name]

    # Get function signature
    sig = inspect.signature(function)

    # Prepare arguments
    kwargs = {}
    for param in sig.parameters.values():
        if param.name in options:
            kwargs[param.name] = options[param.name]

    # Execute function with provided arguments
    return function(**kwargs)
