def get_bool_env_var(var_name):
    import os
    value = os.getenv(var_name)
    if value is None:
        raise RuntimeError(f"Environment variable {var_name} is not set")

    value = value.lower()
    if value == 'true':
        return True
    elif value == 'false':
        return False
    else:
        raise RuntimeError(f"Environment variable {var_name} must be 'True' or 'False', got '{value}'")

def create_user_account(username, email, password, is_staff=False, permissions=None):
    from django.contrib.auth.models import User, Permission
    from django.contrib.auth.hashers import make_password

    try:
        user = User.objects.get(username=username)
    except User.DoesNotExist:
        user = User.objects.create(
            username=username,
            email=email,
            password=make_password(password),
            is_staff=is_staff
        )

    if is_staff:
        user.is_staff = True

    if permissions:
        if isinstance(permissions, str):
            permissions = [permissions]

        for perm in permissions:
            try:
                permission = Permission.objects.get(codename=perm)
                user.user_permissions.add(permission)
            except Permission.DoesNotExist:
                continue

    user.save()
    return user

def compile_template(template_str):
    import re

    def pop_token(tokens):
        if not tokens:
            return None
        return tokens.pop(0)

    def parse_tokens(tokens):
        result = []
        while tokens:
            token = pop_token(tokens)
            if token is None:
                break

            if token == '{{':
                expr = []
                while tokens:
                    t = pop_token(tokens)
                    if t == '}}':
                        break
                    expr.append(t)
                if expr:
                    result.append(f"str({' '.join(expr)})")
            else:
                result.append(f"'{token}'")

        return ' + '.join(result)

    syntax_rules = {
        r'\{\{': '{{',
        r'\}\}': '}}',
        r'\s+': ' ',
        r'([^{}\s]+)': r'\1'
    }

    tokens = []
    pos = 0
    while pos < len(template_str):
        matched = False
        for pattern, replacement in syntax_rules.items():
            match = re.match(pattern, template_str[pos:])
            if match:
                token = match.group(0)
                if token.strip():
                    if re.match(r'\{\{|\}\}', replacement):
                        tokens.append(replacement)
                    else:
                        tokens.append(token)
                pos += len(token)
                matched = True
                break
        if not matched:
            pos += 1

    parsed_expr = parse_tokens(tokens)
    lambda_str = f"lambda _n: {parsed_expr}"
    return eval(lambda_str)

