def configure_environment(env_id, num_envs=4, custom_reward_params=None, use_gpu=True):
    import tensorflow as tf
    import gym
    from stable_baselines3.common.vec_env import DummyVecEnv, VecFrameStack
    from stable_baselines3.common.monitor import Monitor

    if use_gpu:
        physical_devices = tf.config.list_physical_devices('GPU')
        if physical_devices:
            try:
                for device in physical_devices:
                    tf.config.experimental.set_memory_growth(device, True)
            except RuntimeError as e:
                print(f"GPU memory growth configuration failed: {e}")

    def make_env(env_id, rank):
        def _init():
            env = gym.make(env_id)
            if custom_reward_params:
                env = CustomRewardWrapper(env, **custom_reward_params)
            env = Monitor(env)
            return env
        return _init

    env_fns = [make_env(env_id, i) for i in range(num_envs)]
    vec_env = DummyVecEnv(env_fns)
    vec_env = VecFrameStack(vec_env, n_stack=4)

    return vec_env

class CustomRewardWrapper(gym.Wrapper):
    def __init__(self, env, reward_scale=1.0, bonus_reward=0, penalty_threshold=None):
        super().__init__(env)
        self.reward_scale = reward_scale
        self.bonus_reward = bonus_reward
        self.penalty_threshold = penalty_threshold

    def step(self, action):
        observation, reward, done, info = self.env.step(action)

        # Apply reward scaling
        modified_reward = reward * self.reward_scale

        # Add bonus reward if specified
        if self.bonus_reward != 0:
            modified_reward += self.bonus_reward

        # Apply penalty if threshold is specified and reward is below it
        if self.penalty_threshold is not None and reward < self.penalty_threshold:
            modified_reward -= abs(self.penalty_threshold - reward)

        return observation, modified_reward, done, info
