import sqlite3
from sqlite3 import Error

def create_connection(db_file):
    conn = None
    try:
        conn = sqlite3.connect(db_file)
        return conn
    except Error as e:
        print(e)
    return conn

def create_table(conn, table_name, columns):
    try:
        c = conn.cursor()
        create_table_sql = f"CREATE TABLE IF NOT EXISTS {table_name} ({columns})"
        c.execute(create_table_sql)
    except Error as e:
        print(e)

def insert_record(conn, table_name, values):
    try:
        c = conn.cursor()
        placeholders = ','.join(['?' for _ in range(len(values.split(',')))])
        sql = f"INSERT INTO {table_name} VALUES({placeholders})"
        c.execute(sql, tuple(values.split(',')))
        conn.commit()
    except Error as e:
        print(e)

def main():
    while True:
        print("\n1. Create new database and table")
        print("2. Insert record into existing table")
        print("3. Exit")
        choice = input("Enter your choice (1-3): ")

        if choice == '1':
            db_name = input("Enter database name (with .db extension): ")
            table_name = input("Enter table name: ")
            columns = input("Enter column definitions (e.g., 'id INTEGER, name TEXT'): ")

            conn = create_connection(db_name)
            if conn is not None:
                create_table(conn, table_name, columns)
                print(f"Table {table_name} created successfully")
                conn.close()
            else:
                print("Error creating database connection")

        elif choice == '2':
            db_name = input("Enter database name (with .db extension): ")
            table_name = input("Enter table name: ")
            values = input("Enter values separated by commas: ")

            conn = create_connection(db_name)
            if conn is not None:
                insert_record(conn, table_name, values)
                print("Record inserted successfully")
                conn.close()
            else:
                print("Error creating database connection")

        elif choice == '3':
            print("Exiting program")
            break

        else:
            print("Invalid choice. Please try again")

if __name__ == '__main__':
    main()
