class DMAController
  attr_accessor :mandatory_queue, :request_queue, :response_queue, :sequencer, :network

  def initialize(network)
    @mandatory_queue = Queue.new
    @request_queue = Queue.new
    @response_queue = Queue.new
    @network = network
    @sequencer = DMASequencer.new(self)
  end

  def send_directory_request(request)
    @request_queue.push(request)
    @network.transmit_request(request)
  end

  def receive_directory_response(response)
    @response_queue.push(response)
    process_response(response)
  end

  def process_mandatory_queue
    while !@mandatory_queue.empty?
      request = @mandatory_queue.pop
      handle_mandatory_request(request)
    end
  end

  private

  def handle_mandatory_request(request)
    @sequencer.sequence_request(request)
  end

  def process_response(response)
    @sequencer.handle_response(response)
  end
end

class DMASequencer
  attr_reader :controller

  def initialize(controller)
    @controller = controller
    @pending_requests = {}
    @current_sequence = 0
  end

  def sequence_request(request)
    sequence_number = generate_sequence_number
    @pending_requests[sequence_number] = request
    request.sequence_number = sequence_number
    @controller.send_directory_request(request)
  end

  def handle_response(response)
    request = @pending_requests.delete(response.sequence_number)
    if request
      complete_request(request, response)
    end
  end

  private

  def generate_sequence_number
    @current_sequence += 1
  end

  def complete_request(request, response)
    # Handle completion of DMA request
  end
end

class Network
  def initialize
    @directory_controllers = []
    @dma_controllers = []
  end

  def add_directory_controller(controller)
    @directory_controllers << controller
  end

  def add_dma_controller(controller)
    @dma_controllers << controller
  end

  def transmit_request(request)
    target_directory = find_directory_for_request(request)
    target_directory.handle_request(request) if target_directory
  end

  def transmit_response(response, target_controller)
    target_controller.receive_directory_response(response)
  end

  private

  def find_directory_for_request(request)
    # Logic to determine which directory controller should handle the request
    @directory_controllers.first
  end
end

class DirectoryController
  def initialize(network)
    @network = network
    @memory_map = {}
  end

  def handle_request(request)
    response = process_request(request)
    @network.transmit_response(response, request.source_controller)
  end

  private

  def process_request(request)
    # Process the directory request and generate response
    Response.new(request.sequence_number)
  end
end

class Request
  attr_accessor :sequence_number, :source_controller

  def initialize(source_controller)
    @source_controller = source_controller
  end
end

class Response
  attr_reader :sequence_number

  def initialize(sequence_number)
    @sequence_number = sequence_number
  end
end

# Usage example
network = Network.new
dma_controller = DMAController.new(network)
directory_controller = DirectoryController.new(network)

network.add_dma_controller(dma_controller)
network.add_directory_controller(directory_controller)

request = Request.new(dma_controller)
dma_controller.mandatory_queue.push(request)
dma_controller.process_mandatory_queue
```

