def modify_object_attributes(obj):
    import inspect
    import re

    class_methods = inspect.getmembers(obj.__class__, predicate=inspect.isfunction)
    get_methods = {name: method for name, method in class_methods if name.startswith('Get')}
    set_methods = {name: method for name, method in class_methods if name.startswith('Set')}

    modified_methods = {}

    for set_name, set_method in set_methods.items():
        # Find matching get method by removing 'Set' and adding 'Get'
        get_name = 'Get' + set_name[3:]
        if get_name in get_methods:
            # Create new set method that uses get method
            def create_modified_setter(get_method, original_set):
                def modified_set(self, *args, **kwargs):
                    # Get current value
                    current = get_method(self)

                    # Call original setter
                    result = original_set(self, *args, **kwargs)

                    # Update configuration if needed
                    if hasattr(self, '_config'):
                        # Extract attribute name from method name
                        attr_name = set_name[3:].lower()
                        self._config[attr_name] = args[0]

                    return result
                return modified_set

            # Create and store modified method
            modified_methods[set_name] = create_modified_setter(
                get_methods[get_name], set_method)

    # Replace original methods with modified versions
    for name, method in modified_methods.items():
        setattr(obj.__class__, name, method)

    # Initialize config if not exists
    if not hasattr(obj, '_config'):
        obj._config = {}

    # Populate initial config
    for get_name, get_method in get_methods.items():
        attr_name = get_name[3:].lower()
        obj._config[attr_name] = get_method(obj)

    return obj
