import argparse
import configparser
import logging
import uuid
from typing import Any
from collections import defaultdict

class ConfigurationManager:
    def __init__(self):
        self.config_dict = {}
        self.handlers = []
        self.logger = logging.getLogger(__name__)
        self._load_configs()

    def _load_configs(self):
        # Load command line args
        parser = argparse.ArgumentParser()
        parser.add_argument('--config-file', help='Path to config file')
        args, _ = parser.parse_known_args()

        # Load config file if specified
        if args.config_file:
            config = configparser.ConfigParser()
            config.read(args.config_file)
            for section in config.sections():
                for key, value in config[section].items():
                    self.config_dict[f"{section}.{key}"] = {
                        'value': value,
                        'source': 'config_file',
                        'id': str(uuid.uuid4())
                    }

        # Load command line overrides
        for arg in vars(args):
            value = getattr(args, arg)
            if value is not None:
                self.config_dict[arg] = {
                    'value': value,
                    'source': 'command_line',
                    'id': str(uuid.uuid4())
                }

    def register_handler(self, handler):
        self.handlers.append(handler)

    def broadcast_config(self, config_name: str, config_item: dict):
        for handler in self.handlers:
            handler(config_name, config_item)

    def get_config(self, name: str) -> Any:
        if name not in self.config_dict:
            raise KeyError(f"Configuration '{name}' not found")

        config_item = self.config_dict[name]

        self.logger.warning(
            f"Accessing configuration '{name}' from {config_item['source']} "
            f"(id: {config_item['id']})"
        )

        self.broadcast_config(name, config_item)

        return config_item['value']
