import mysql.connector
import json
import hashlib
import secrets
import string
import os
from typing import Dict

def generate_password(length: int = 12) -> str:
    alphabet = string.ascii_letters + string.digits + string.punctuation
    return ''.join(secrets.choice(alphabet) for _ in range(length))

def hash_password(password: str) -> str:
    return hashlib.sha256(password.encode()).hexdigest()

def read_sql_file(filename: str) -> str:
    with open(filename, 'r') as f:
        return f.read()

def save_sql_file(filename: str, content: str) -> None:
    with open(filename, 'w') as f:
        f.write(content)

def generate_user_passwords() -> Dict[str, str]:
    users = {}
    with open('init_db.sql', 'r') as f:
        for line in f:
            if 'CREATE USER' in line.upper():
                username = line.split("'")[1]
                users[username] = generate_password()
    return users

def modify_sql_file(users: Dict[str, str]) -> str:
    sql_content = read_sql_file('init_db.sql')
    modified_content = sql_content

    for username, password in users.items():
        # Add password setup statements
        password_hash = hash_password(password)
        set_password = f"ALTER USER '{username}'@'%' IDENTIFIED BY '{password}';\n"
        modified_content += set_password

    return modified_content

def save_credentials(users: Dict[str, str]) -> None:
    credentials = {
        'users': users,
        'admin': {
            'username': 'root',
            'password': os.environ.get('MYSQL_ROOT_PASSWORD', 'root_password')
        }
    }

    with open('db-credentials-file', 'w') as f:
        json.dump(credentials, f, indent=2)

def execute_sql_file(filename: str, host: str, user: str, password: str) -> None:
    try:
        conn = mysql.connector.connect(
            host=host,
            user=user,
            password=password
        )

        cursor = conn.cursor()

        sql_content = read_sql_file(filename)
        statements = sql_content.split(';')

        for statement in statements:
            if statement.strip():
                cursor.execute(statement)

        conn.commit()
        cursor.close()
        conn.close()

    except mysql.connector.Error as err:
        print(f"Error: {err}")
        raise

def main():
    # Generate passwords for users
    users = generate_user_passwords()

    # Modify SQL file with password statements
    modified_sql = modify_sql_file(users)
    save_sql_file('init_db_with_passwords.sql', modified_sql)

    # Save credentials
    save_credentials(users)

    # Execute the modified SQL file
    with open('db-credentials-file', 'r') as f:
        credentials = json.load(f)

    execute_sql_file(
        'init_db_with_passwords.sql',
        'localhost',
        credentials['admin']['username'],
        credentials['admin']['password']
    )

if __name__ == '__main__':
    main()
