def parse_lock_definition(lock_def_str):
    warnings = []

    try:
        # Remove whitespace and validate basic syntax
        lock_def_str = lock_def_str.strip()
        if not lock_def_str:
            raise SyntaxError("Empty lock definition")

        # Check for balanced parentheses
        if lock_def_str.count('(') != lock_def_str.count(')'):
            raise SyntaxError("Unbalanced parentheses in lock definition")

        # Parse into list of tuples
        try:
            lock_def = eval(lock_def_str)
            if not isinstance(lock_def, list):
                raise SyntaxError("Lock definition must evaluate to a list")
        except:
            raise SyntaxError("Invalid lock definition syntax")

        # Validate each tuple
        for item in lock_def:
            if not isinstance(item, tuple):
                raise SyntaxError("Lock definition items must be tuples")
            if len(item) != 3:
                raise SyntaxError("Lock definition tuples must have 3 elements")
            if not isinstance(item[0], str):
                raise SyntaxError("First element must be function name string")
            if not isinstance(item[1], list):
                raise SyntaxError("Second element must be args list")
            if not isinstance(item[2], dict):
                raise SyntaxError("Third element must be kwargs dict")

        # Check for deprecated features
        for item in lock_def:
            func_name = item[0]
            if func_name.startswith('deprecated_'):
                warnings.append(f"Warning: {func_name} is deprecated")

        return lock_def, warnings

    except SyntaxError as e:
        raise
    except Exception as e:
        raise SyntaxError(f"Error parsing lock definition: {str(e)}")
