def adjust_volume(command):
    import subprocess
    import re

    def get_volume():
        try:
            output = subprocess.check_output(['osascript', '-e', 'output volume of (get volume settings)']).decode().strip()
            return output
        except:
            try:
                output = subprocess.check_output(['amixer', 'get', 'Master']).decode()
                volume = re.search(r'\[(\d+)%\]', output).group(1)
                return volume
            except:
                return "Unable to get volume"

    try:
        if command.lower() == 'up':
            try:
                subprocess.run(['osascript', '-e', 'set volume output volume (output volume of (get volume settings) + 10)'])
            except:
                subprocess.run(['amixer', '-q', 'sset', 'Master', '10%+'])
        elif command.lower() == 'down':
            try:
                subprocess.run(['osascript', '-e', 'set volume output volume (output volume of (get volume settings) - 10)'])
            except:
                subprocess.run(['amixer', '-q', 'sset', 'Master', '10%-'])
        else:
            return "Invalid command"

        return get_volume()

    except Exception as e:
        return f"Error adjusting volume: {str(e)}"
