class Controller
  attr_accessor :id, :version, :cache, :io_bus, :sequencers

  def initialize(id, version, cache, io_bus)
    @id = id
    @version = version
    @cache = cache
    @io_bus = io_bus
    @sequencers = []
  end

  def add_sequencer(sequencer)
    @sequencers << sequencer
  end
end

class Sequencer
  attr_accessor :id, :controller

  def initialize(id)
    @id = id
    @controller = nil
  end

  def assign_controller(controller)
    @controller = controller
    controller.add_sequencer(self)
  end
end

class SystemConfiguration
  attr_reader :controllers, :sequencers

  def initialize
    @controllers = []
    @sequencers = []
  end

  def create_controller(id, version, cache, io_bus)
    controller = Controller.new(id, version, cache, io_bus)
    @controllers << controller
    controller
  end

  def create_sequencer(id)
    sequencer = Sequencer.new(id)
    @sequencers << sequencer
    sequencer
  end

  def configure_system(version, cache, io_bus, num_controllers, sequencers_per_controller)
    num_controllers.times do |i|
      controller = create_controller(i, version, cache, io_bus)

      sequencers_per_controller.times do |j|
        sequencer_id = i * sequencers_per_controller + j
        sequencer = create_sequencer(sequencer_id)
        sequencer.assign_controller(controller)
      end
    end
  end
end

# Example usage
system = SystemConfiguration.new
system.configure_system(
  version: "1.0",
  cache: "256MB",
  io_bus: "PCIe 4.0",
  num_controllers: 2,
  sequencers_per_controller: 3
)
