def get_switch_port_tags(device_id):
    import hashlib

    # Create a hash of the device ID to generate VM ID
    hash_object = hashlib.md5(str(device_id).encode())
    vm_id = hash_object.hexdigest()[:8]  # Take first 8 characters of hash

    # Create fake switch and port data
    switch = {
        'id': 'switch_' + str(hash_object.hexdigest()[:4]),
        'name': 'switch_' + str(hash_object.hexdigest()[:4]),
        'ports': {}
    }

    port = {
        'id': 'port_' + str(hash_object.hexdigest()[-4:]),
        'name': 'port_' + str(hash_object.hexdigest()[-4:]),
        'tags': {
            'vm_id': vm_id,
            'device_id': device_id,
            'port_type': 'access',
            'vlan': '100'
        }
    }

    switch['ports'][port['id']] = port

    # Get port tags
    port_tags = switch['ports'][port['id']]['tags']

    return {
        'switch': switch,
        'port': port,
        'tags': port_tags,
        'vm_id': vm_id
    }

