def execute_command(command, expected_result='success'):
    """
    Execute command and verify result matches expected outcome
    command: string or list of command and arguments
    expected_result: 'success' or 'failure'
    """
    try:
        process = subprocess.Popen(command, stdout=subprocess.PIPE, stderr=subprocess.PIPE, shell=True)
        stdout, stderr = process.communicate()
        return_code = process.returncode

        if expected_result == 'success':
            assert return_code == 0, f"Command failed with return code {return_code}\nstderr: {stderr.decode()}"
        elif expected_result == 'failure':
            assert return_code != 0, f"Command succeeded but failure was expected\nstdout: {stdout.decode()}"
        else:
            raise ValueError(f"Invalid expected_result: {expected_result}")

        return {
            'stdout': stdout.decode(),
            'stderr': stderr.decode(),
            'return_code': return_code
        }

    except subprocess.SubprocessError as e:
        raise RuntimeError(f"Failed to execute command: {str(e)}")
