def find_bundle_images(bundle_symbolic_name, image_types, bundle_context):
    import os
    import json

    CACHE_FILE = 'bundle_images_cache.json'
    ALL_IMAGE_TYPES = ['.png', '.jpg', '.jpeg', '.gif', '.bmp', '.ico']

    # Load or create cache
    if os.path.exists(CACHE_FILE):
        with open(CACHE_FILE, 'r') as f:
            bundle_cache = json.load(f)
    else:
        bundle_cache = {bundle_symbolic_name: ALL_IMAGE_TYPES}
        with open(CACHE_FILE, 'w') as f:
            json.dump(bundle_cache, f)

    # Get bundle
    bundle = None
    for b in bundle_context.get_bundles():
        if b.get_symbolic_name() == bundle_symbolic_name:
            bundle = b
            break

    if not bundle:
        return []

    # Find images in bundle
    images = []
    bundle_root = bundle.get_entry('/')
    if bundle_root:
        for entry in bundle_root.list():
            entry_path = entry.get_name()
            ext = os.path.splitext(entry_path)[1].lower()
            if ext in image_types and ext in bundle_cache.get(bundle_symbolic_name, []):
                images.append(entry)

    return images
