def execute_code(code_str, local_vars=None, global_vars=None):
    if local_vars is None:
        local_vars = {}
    if global_vars is None:
        global_vars = {}

    sandbox = {'__builtins__': {
        'abs': abs,
        'bool': bool,
        'int': int,
        'float': float,
        'str': str,
        'len': len,
        'max': max,
        'min': min,
        'print': print,
        'range': range,
        'sum': sum
    }}

    sandbox.update(global_vars)

    try:
        exec(f"__result__ = {code_str}", sandbox, local_vars)
        result = local_vars.get('__result__')
        return bool(result) if result is not None else False
    except Exception as e:
        print(f"Error executing code: {str(e)}")
        return False
