def mock_function(func, mock_enabled=True):
    def wrapper(*args, **kwargs):
        wrapper.call_count += 1
        wrapper.call_args.append(args)
        wrapper.call_kwargs.append(kwargs)

        if not mock_enabled:
            return func(*args, **kwargs)

        if wrapper.return_value is not None:
            return wrapper.return_value
        elif wrapper.side_effect is not None:
            if callable(wrapper.side_effect):
                return wrapper.side_effect(*args, **kwargs)
            elif isinstance(wrapper.side_effect, Exception):
                raise wrapper.side_effect
            elif isinstance(wrapper.side_effect, list):
                if wrapper.call_count <= len(wrapper.side_effect):
                    return wrapper.side_effect[wrapper.call_count - 1]
                raise IndexError("No more side effects available")
            return wrapper.side_effect
        return None

    wrapper.original_func = func
    wrapper.call_count = 0
    wrapper.call_args = []
    wrapper.call_kwargs = []
    wrapper.return_value = None
    wrapper.side_effect = None
    wrapper.reset_mock = lambda: setattr(wrapper, 'call_count', 0) or \
                                setattr(wrapper, 'call_args', []) or \
                                setattr(wrapper, 'call_kwargs', [])

    return wrapper
