import subprocess
import re

def svn_checkout(repo_url, local_path):
    try:
        # Run svn checkout command
        result = subprocess.run(['svn', 'checkout', repo_url, local_path], 
                              capture_output=True,
                              text=True,
                              check=True)

        # Extract revision number from output using regex
        match = re.search(r'Checked out revision (\d+)', result.stdout)
        if match:
            return int(match.group(1))
        else:
            raise ValueError("Could not find revision number in SVN output")

    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"SVN checkout failed: {e.stderr}")
    except Exception as e:
        raise RuntimeError(f"Checkout failed: {str(e)}")
