class Transformation:
    def __init__(self, name=None, params=None):
        self.name = name
        self.params = params if params else {}

    def to_dict(self):
        return {
            'class': self.__class__.__name__,
            'module': self.__class__.__module__,
            'name': self.name,
            'params': self.params
        }

    @staticmethod
    def from_dict(d):
        if not isinstance(d, dict):
            raise ValueError("Input must be a dictionary")

        if 'class' not in d or 'module' not in d:
            raise ValueError("Dictionary must contain 'class' and 'module' keys")

        class_path = f"{d['module']}.{d['class']}"
        cls = eval(class_path)

        if not issubclass(cls, Transformation):
            raise ValueError(f"Class {class_path} is not a subclass of Transformation")

        return cls(name=d.get('name'), params=d.get('params'))
