import subprocess
import re
from collections import defaultdict

def get_commit_history():
    cmd = ['hg', 'log', '--template', '{node}\\t{parents}\\n']
    result = subprocess.run(cmd, capture_output=True, text=True)
    return result.stdout.strip().split('\n')

def parse_parents(parents_str):
    # Extract commit hashes from parents string
    matches = re.findall(r'[0-9a-f]{40}', parents_str)
    return matches

def build_commit_graph(history):
    # Build graph of commits and their parents
    commit_graph = defaultdict(list)
    commits_in_order = []

    for line in history:
        if not line:
            continue
        commit, parents = line.split('\t')
        parent_hashes = parse_parents(parents)
        commit_graph[commit].extend(parent_hashes)
        commits_in_order.append(commit)

    return commit_graph, commits_in_order

def count_branches(commit, graph, visited=None):
    if visited is None:
        visited = set()

    if commit in visited:
        return 0

    visited.add(commit)

    # Base case - no parents means this is the initial commit
    if not graph[commit]:
        return 1

    # Recursively count branches from parents
    branch_count = 0
    for parent in graph[commit]:
        branch_count += count_branches(parent, graph, visited)

    return max(1, branch_count)

def analyze_branches():
    history = get_commit_history()
    commit_graph, commits_in_order = build_commit_graph(history)

    branch_counts = {}
    for commit in commits_in_order:
        branch_counts[commit] = count_branches(commit, commit_graph)

    # Print results
    for commit in commits_in_order:
        short_hash = commit[:12]
        print(f"Commit {short_hash}: {branch_counts[commit]} branch(es)")

if __name__ == '__main__':
    analyze_branches()
