def function_updater(func, update_dict):
    def updated_function(*args, **kwargs):
        local_dict = func.__globals__.copy()
        local_dict.update(update_dict)

        code = compile(func.__code__, func.__code__.co_filename, 'exec')
        exec(code, local_dict)

        return local_dict[func.__name__](*args, **kwargs)

    updated_function.__name__ = func.__name__
    updated_function.__doc__ = func.__doc__

    def __repr__(self):
        return f"Updated version of {func.__name__} with {update_dict}"

    updated_function.__repr__ = __repr__
    return updated_function

import hashlib
from datetime import datetime
from typing import Optional

def hash_request_params(request, delta: Optional[float] = None) -> str:
    params = []
    for key, value in request.GET.items():
        if not key.startswith('_'):
            params.append(f"{key}={value}")

    params.sort()
    param_string = ','.join(params)

    if delta is not None:
        current_time = datetime.now().timestamp()
        param_string = f"{param_string},{current_time - delta}"

    return hashlib.md5(param_string.encode('utf-8')).hexdigest()

