from io import TextIOWrapper

def execute_command_as_file(command, mode='r'):
    if mode not in ('r', 'w'):
        raise ValueError("Mode must be 'r' or 'w'")

    if mode == 'r':
        process = Popen(command, stdout=PIPE, shell=True)
        return TextIOWrapper(process.stdout, encoding='utf-8')
    else:
        process = Popen(command, stdin=PIPE, shell=True)
        return TextIOWrapper(process.stdin, encoding='utf-8')

import hashlib

def calculate_sha1(file_path, max_bytes=None):
    sha1 = hashlib.sha1()
    with open(file_path, 'rb') as f:
        if max_bytes:
            data = f.read(max_bytes)
            sha1.update(data)
        else:
            while True:
                data = f.read(65536)
                if not data:
                    break
                sha1.update(data)
    return sha1.hexdigest()

from django.shortcuts import render, redirect
from django.contrib.auth import get_user_model
from django.contrib import messages
from django.urls import reverse
from django.template.loader import render_to_string
from django.core.exceptions import ValidationError
from .forms import PasswordResetForm

def password_reset_confirm(request, user_id, token):
    User = get_user_model()
    try:
        user = User.objects.get(pk=user_id)
    except User.DoesNotExist:
        messages.error(request, 'Invalid password reset link.')
        return redirect('login')

    if request.method == 'POST':
        form = PasswordResetForm(request.POST)
        if form.is_valid():
            try:
                # Verify token
                if user.password_reset_token_valid(token):
                    # Update password
                    new_password = form.cleaned_data['new_password']
                    user.set_password(new_password)
                    user.reset_token = None
                    user.save()

                    messages.success(request, 'Password successfully reset.')
                    return redirect('login')
                else:
                    messages.error(request, 'Invalid or expired reset token.')
                    return redirect('password_reset')
            except ValidationError as e:
                messages.error(request, str(e))
                return redirect('password_reset')
    else:
        form = PasswordResetForm()

    context = {
        'form': form,
        'user_id': user_id,
        'token': token,
        'post_reset_redirect': reverse('login'),
    }

    return render(
        request,
        'registration/password_reset_confirm.html',
        context
    )

