import json
import boto3
from typing import Iterator, Union, Optional
from pathlib import Path

class DataReader:
    def __init__(self, source: Union[str, Path], fail_on_missing: bool = True):
        self.source = str(source)
        self.fail_on_missing = fail_on_missing
        self._iterator = None

    def __iter__(self) -> Iterator[str]:
        if self._iterator is None:
            if self.source.startswith('s3://'):
                self._iterator = self._read_from_s3()
            else:
                self._iterator = self._read_from_file()
        return self._iterator

    def _read_from_file(self) -> Iterator[str]:
        try:
            with open(self.source, 'r') as f:
                for line in f:
                    yield line.strip()
        except FileNotFoundError:
            if self.fail_on_missing:
                raise
            return iter([])

    def _read_from_s3(self) -> Iterator[str]:
        try:
            s3 = boto3.client('s3')
            bucket, key = self._parse_s3_path()
            obj = s3.get_object(Bucket=bucket, Key=key)
            content = obj['Body'].read().decode('utf-8')
            return iter(content.splitlines())
        except:
            if self.fail_on_missing:
                raise
            return iter([])

    def _parse_s3_path(self) -> tuple[str, str]:
        path = self.source.replace('s3://', '')
        bucket = path.split('/')[0]
        key = '/'.join(path.split('/')[1:])
        return bucket, key

    @classmethod
    def from_json(cls, json_str: str) -> 'DataReader':
        data = json.loads(json_str)
        return cls(
            source=data['source'],
            fail_on_missing=data.get('fail_on_missing', True)
        )

    def to_json(self) -> str:
        return json.dumps({
            'source': self.source,
            'fail_on_missing': self.fail_on_missing
        })
