import hashlib
import hmac

def hash_string(input_str: str, compare: bool = False, reference_hash: str = None) -> Union[str, bool]:
    hash_obj = hashlib.sha256()
    hash_obj.update(input_str.encode('utf-8'))
    hashed = hash_obj.hexdigest()

    if compare:
        if reference_hash is None:
            raise ValueError("Reference hash must be provided when compare is True")
        return hmac.compare_digest(hashed, reference_hash)

    return hashed

import os
import pickle
from typing import Any, Optional

def manage_state(file_path: str, initial_state: Any = None) -> Any:
    state = initial_state

    try:
        if os.path.exists(file_path):
            with open(file_path, 'rb') as f:
                state = pickle.load(f)
    except (IOError, pickle.PickleError) as e:
        print(f"Error loading state: {e}")

    try:
        yield state
    finally:
        try:
            with open(file_path, 'wb') as f:
                pickle.dump(state, f)
        except (IOError, pickle.PickleError) as e:
            print(f"Error saving state: {e}")

def load_state(file_path: str, default_state: Any = None) -> Any:
    try:
        if os.path.exists(file_path):
            with open(file_path, 'rb') as f:
                return pickle.load(f)
    except (IOError, pickle.PickleError) as e:
        print(f"Error loading state: {e}")
    return default_state

def save_state(file_path: str, state: Any) -> bool:
    try:
        with open(file_path, 'wb') as f:
            pickle.dump(state, f)
        return True
    except (IOError, pickle.PickleError) as e:
        print(f"Error saving state: {e}")
        return False

def check_code_format(input_str, expected_lines, expected_endings):
    if not input_str.strip():
        return False

    lines = input_str.strip().split('\n')

    if len(lines) != expected_lines:
        return False

    for i, line in enumerate(lines):
        if not line.strip().endswith(expected_endings[i]):
            return False

    return True

def gb_to_kib(gb):
    kib = gb * 1024 * 1024
    return f"{kib:,.0f} KiB"

