def load_skip_filter():
    import os
    import pickle
    import base64
    import zlib

    skip_filter = {}
    skip_env = os.environ.get('PYDEV_PYTEST_SKIP')

    if skip_env:
        try:
            compressed = base64.b64decode(skip_env)
            pickled = zlib.decompress(compressed)
            skip_filter = pickle.loads(pickled)

            # Resolve symlinks in paths
            resolved_filter = {}
            for path in skip_filter:
                try:
                    real_path = os.path.realpath(path)
                    resolved_filter[real_path] = skip_filter[path]
                except:
                    resolved_filter[path] = skip_filter[path]
            skip_filter = resolved_filter

        except (base64.binascii.Error, zlib.error, pickle.UnpicklingError):
            skip_filter = {}

    return skip_filter
