def authenticate_env_vars(env_vars):
    auth_version = None
    authenticated_vars = env_vars.copy()

    # Check for v2.0 authentication
    if all(key in env_vars for key in ['OS_AUTH_URL', 'OS_USERNAME', 'OS_PASSWORD']):
        if 'v2.0' in env_vars.get('OS_AUTH_URL', ''):
            auth_version = '2.0'
        elif 'v3' in env_vars.get('OS_AUTH_URL', ''):
            auth_version = '3.0'
        else:
            auth_version = '2.0'  # Default to 2.0 if version not specified

        authenticated_vars.update({
            'auth_version': auth_version,
            'auth_url': env_vars['OS_AUTH_URL'],
            'username': env_vars['OS_USERNAME'],
            'password': env_vars['OS_PASSWORD']
        })

        if 'OS_TENANT_NAME' in env_vars:
            authenticated_vars['tenant_name'] = env_vars['OS_TENANT_NAME']
        if 'OS_PROJECT_NAME' in env_vars:
            authenticated_vars['project_name'] = env_vars['OS_PROJECT_NAME']
        if 'OS_PROJECT_DOMAIN_NAME' in env_vars:
            authenticated_vars['project_domain_name'] = env_vars['OS_PROJECT_DOMAIN_NAME']
        if 'OS_USER_DOMAIN_NAME' in env_vars:
            authenticated_vars['user_domain_name'] = env_vars['OS_USER_DOMAIN_NAME']

    # Check for v1.0 authentication
    elif all(key in env_vars for key in ['ST_AUTH', 'ST_USER', 'ST_KEY']):
        auth_version = '1.0'
        authenticated_vars.update({
            'auth_version': auth_version,
            'auth_url': env_vars['ST_AUTH'],
            'username': env_vars['ST_USER'],
            'password': env_vars['ST_KEY']
        })

    else:
        raise ValueError("Insufficient authentication credentials provided")

    return authenticated_vars, auth_version

