def extract_version_metadata(file_path, metadata_name):
    version = None
    metadata = {
        'name': metadata_name,
        'version': None,
        'description': 'Software package metadata',
        'author': 'Unknown',
        'date_created': None
    }

    try:
        with open(file_path, 'r') as file:
            for line in file:
                if 'version' in line.lower():
                    # Extract version using regex pattern
                    import re
                    version_pattern = r'version[:\s]*([0-9]+(?:\.[0-9]+)*)'
                    match = re.search(version_pattern, line, re.IGNORECASE)
                    if match:
                        version = match.group(1)
                        break

        if version:
            metadata['version'] = version
            from datetime import datetime
            metadata['date_created'] = datetime.now().strftime('%Y-%m-%d')

        return metadata

    except FileNotFoundError:
        print(f"Error: File {file_path} not found")
        return metadata
    except Exception as e:
        print(f"Error reading file: {str(e)}")
        return metadata

def setup_tower_managed_default(credential_type_name, description=None, kind='ssh'):
    try:
        created_count = 0
        defaults = {
            'name': credential_type_name,
            'description': description or f'Default {credential_type_name} credential type',
            'kind': kind,
            'managed': True,
            'inputs': {
                'fields': [
                    {
                        'id': 'username',
                        'label': 'Username',
                        'type': 'string',
                        'required': True
                    },
                    {
                        'id': 'password',
                        'label': 'Password',
                        'type': 'string',
                        'secret': True,
                        'required': False
                    }
                ]
            },
            'injectors': {
                'env': {
                    'USERNAME': '{{ username }}',
                    'PASSWORD': '{{ password }}'
                }
            }
        }

        credential_type, created = CredentialType.objects.get_or_create(
            name=credential_type_name,
            defaults=defaults
        )

        if created:
            created_count += 1
        else:
            for key, value in defaults.items():
                setattr(credential_type, key, value)
            credential_type.save()
            created_count += 1

        return created_count

    except Exception as e:
        raise Exception(f"Failed to setup tower managed default: {str(e)}")

def calculate_file_hash(file_path, hash_function):
    try:
        with open(file_path, 'rb') as file:
            while chunk := file.read(8192):
                hash_function.update(chunk)
        return hash_function.hexdigest()
    except (IOError, OSError):
        return None

def get_file_md5(filename):
    import hashlib

    md5_hash = hashlib.md5()

    try:
        with open(filename, 'rb') as file:
            while True:
                chunk = file.read(4096)
                if not chunk:
                    break
                md5_hash.update(chunk)
        return md5_hash.hexdigest()
    except IOError:
        return None

import subprocess

def check_job_status(cmd):
    try:
        result = subprocess.run(cmd, shell=True, capture_output=True, text=True)

        output = result.stdout.lower()
        error = result.stderr.lower()

        if result.returncode == 0:
            if any(x in output for x in ['completed', 'success', 'done']):
                return 0
            elif any(x in output for x in ['failed', 'error', 'terminated']):
                return 1
        else:
            if any(x in error for x in ['failed', 'error', 'terminated']):
                return 1

        return None

    except subprocess.SubprocessError:
        return 1
    except Exception:
        return None

using System;
using System.CodeDom.Compiler;
using System.Reflection;
using Microsoft.CSharp;

class DynamicCompiler
{
    static void Main(string[] args)
    {
        string sourceCode = @"
            using System;
            namespace DynamicCode
            {
                public class Program
                {
                    public static void Main(string[] args)
                    {
                        Console.WriteLine(""Dynamic code executed with arguments:"");
                        foreach(string arg in args)
                        {
                            Console.WriteLine(arg);
                        }
                    }
                }
            }";

        CSharpCodeProvider provider = new CSharpCodeProvider();
        CompilerParameters parameters = new CompilerParameters();

        parameters.GenerateExecutable = true;
        parameters.OutputAssembly = "DynamicCode.exe";
        parameters.ReferencedAssemblies.Add("System.dll");
        parameters.GenerateInMemory = true;

        CompilerResults results = provider.CompileAssemblyFromSource(parameters, sourceCode);

        if (results.Errors.HasErrors)
        {
            foreach (CompilerError error in results.Errors)
            {
                Console.WriteLine($"Error: {error.ErrorText}");
            }
            return;
        }

        Assembly assembly = results.CompiledAssembly;
        Type program = assembly.GetType("DynamicCode.Program");
        MethodInfo mainMethod = program.GetMethod("Main");

        mainMethod.Invoke(null, new object[] { args });
    }
}

import requests
from bs4 import BeautifulSoup

def test_registration_form(base_url):
    registration_url = f"{base_url}/register"
    test_cases = [
        {
            "username": "testuser",
            "email": "existing@email.com",
            "password": "password123",
            "confirm_password": "password123",
            "expected_error": "Email already registered"
        },
        {
            "username": "testuser",
            "email": "new@email.com",
            "password": "password123",
            "confirm_password": "different_password",
            "expected_error": "Passwords do not match"
        },
        {
            "username": "",
            "email": "test@email.com",
            "password": "password123",
            "confirm_password": "password123",
            "expected_error": "Username is required"
        }
    ]

    results = []

    for test_case in test_cases:
        form_data = {
            "username": test_case["username"],
            "email": test_case["email"],
            "password": test_case["password"],
            "confirm_password": test_case["confirm_password"]
        }

        try:
            response = requests.post(registration_url, data=form_data)
            soup = BeautifulSoup(response.text, 'html.parser')
            error_message = soup.find(class_='error-message')

            if error_message and test_case["expected_error"] in error_message.text:
                results.append({
                    "test_case": test_case,
                    "status": "PASS",
                    "actual_error": error_message.text
                })
            else:
                results.append({
                    "test_case": test_case,
                    "status": "FAIL",
                    "actual_error": error_message.text if error_message else "No error message found"
                })

        except requests.RequestException as e:
            results.append({
                "test_case": test_case,
                "status": "ERROR",
                "message": str(e)
            })

    return results

def print_test_results(results):
    for result in results:
        print(f"\nTest Case: {result['test_case']['expected_error']}")
        print(f"Status: {result['status']}")
        if result['status'] == 'ERROR':
            print(f"Error: {result['message']}")
        else:
            print(f"Actual Error: {result['actual_error']}")

if __name__ == "__main__":
    base_url = "http://example.com"
    results = test_registration_form(base_url)
    print_test_results(results)

