CREATE OR REPLACE FUNCTION create_trigger_for_rows()
RETURNS void AS $$
DECLARE
    r record;
BEGIN
    -- Install plpgsql if not exists
    CREATE OR REPLACE LANGUAGE plpgsql;

    -- Drop existing triggers matching naming pattern
    FOR r IN 
        SELECT tgname 
        FROM pg_trigger 
        WHERE tgname LIKE 'row_trigger_%'
    LOOP
        EXECUTE 'DROP TRIGGER IF EXISTS ' || r.tgname || ' ON mytable';
    END LOOP;

    -- Create new trigger for each row
    FOR r IN 
        SELECT id, name 
        FROM mytable
    LOOP
        EXECUTE 'CREATE TRIGGER row_trigger_' || r.id || 
                ' AFTER INSERT OR UPDATE ON mytable' ||
                ' FOR EACH ROW' ||
                ' WHEN (NEW.id = ' || r.id || ')' ||
                ' EXECUTE PROCEDURE process_row()';
    END LOOP;
END;
$$ LANGUAGE plpgsql;

-- Function that will be called by triggers
CREATE OR REPLACE FUNCTION process_row() 
RETURNS trigger AS $$
BEGIN
    -- Add trigger logic here
    RAISE NOTICE 'Processing row with id: %', NEW.id;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;
