import argparse

def test():
    """Run test suite"""
    os.system('py.test')

def register(test=False):
    """Register package on PyPI or test repo"""
    if test:
        os.system('python setup.py register -r pypitest')
    else:
        os.system('python setup.py register -r pypi')

def upload(test=False):
    """Upload wheel file to PyPI or test repo"""
    if test:
        os.system('python setup.py bdist_wheel upload -r pypitest')
    else:
        os.system('python setup.py bdist_wheel upload -r pypi')

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--test', action='store_true',
                      help='Use test PyPI repository')
    parser.add_argument('command', choices=['test', 'register', 'upload'],
                      help='Command to run')

    args = parser.parse_args()

    if args.command == 'test':
        test()
    elif args.command == 'register':
        register(args.test)
    elif args.command == 'upload':
        upload(args.test)

if __name__ == '__main__':
