from django.db import models
from django.template.loader import render_to_string
from django.utils import timezone
from django.contrib.auth.hashers import check_password

class EventPage(models.Model):
    AUDIENCE_CHOICES = [
        ('PUB', 'Public'),
        ('PRI', 'Private'),
        ('INV', 'Invite Only')
    ]

    title = models.CharField(max_length=200)
    date = models.DateField()
    time = models.TimeField()
    location = models.CharField(max_length=200)
    description = models.TextField()
    audience = models.CharField(max_length=3, choices=AUDIENCE_CHOICES, default='PUB')
    password = models.CharField(max_length=128, blank=True, null=True)
    created_at = models.DateTimeField(auto_now_add=True)
    updated_at = models.DateTimeField(auto_now=True)

    class Meta:
        ordering = ['date', 'time']

    def __str__(self):
        return self.title

    @classmethod
    def filter_events(cls, location=None, audience=None):
        queryset = cls.objects.all()

        if location:
            queryset = queryset.filter(location__icontains=location)

        if audience:
            queryset = queryset.filter(audience=audience)

        return queryset.filter(date__gte=timezone.now().date())

    def render_page(self, password_attempt=None):
        context = {
            'event': self,
            'requires_password': bool(self.password),
            'password_valid': True
        }

        if self.password:
            if not password_attempt:
                context['password_valid'] = False
            else:
                context['password_valid'] = check_password(password_attempt, self.password)

        return render_to_string('events/event_page.html', context)

    def save(self, *args, **kwargs):
        if not self.id:
            self.created_at = timezone.now()
        self.updated_at = timezone.now()
        return super().save(*args, **kwargs)
