import subprocess
import os

def modify_kickstart(input_file, output_file, params, password):
    if not os.path.exists(input_file):
        raise FileNotFoundError(f"Input file {input_file} not found")

    # Copy input file to output file
    try:
        subprocess.run(['cp', input_file, output_file], check=True)
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"Failed to copy input file: {e}")

    # Replace each placeholder with its value
    for key, value in params.items():
        placeholder = f"__{key.upper()}__"
        try:
            subprocess.run([
                'sed', '-i', f's|{placeholder}|{value}|g', output_file
            ], check=True)
        except subprocess.CalledProcessError as e:
            raise RuntimeError(f"Failed to replace {placeholder}: {e}")

    # Add encrypted password
    try:
        with open(output_file, 'a') as f:
            f.write(f"\nrootpw --iscrypted {password}\n")
    except IOError as e:
        raise RuntimeError(f"Failed to add password: {e}")

def generate_encrypted_password(plain_password):
    try:
        result = subprocess.run(
            ['openssl', 'passwd', '-6', plain_password],
            capture_output=True,
            text=True,
            check=True
        )
        return result.stdout.strip()
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"Failed to generate encrypted password: {e}")

if __name__ == "__main__":
    # Example usage
    params = {
        'hostname': 'server1.example.com',
        'ip': '192.168.1.100',
        'netmask': '255.255.255.0',
        'gateway': '192.168.1.1',
        'nameserver': '8.8.8.8'
    }

    try:
        encrypted_pw = generate_encrypted_password("mypassword123")
        modify_kickstart(
            "template.ks",
            "output.ks",
            params,
            encrypted_pw
        )
    except Exception as e:
        print(f"Error: {e}")
        exit(1)
