import pickle
import os
from zipfile import ZipFile
import numpy as np

class DataLoader:
    def __init__(self, train_path, val_path, test_path):
        self.train_data = self._load_pickle(train_path)
        self.val_data = self._load_pickle(val_path)
        self.test_data = self._load_pickle(test_path)

    def _load_pickle(self, file_path):
        if not os.path.exists(file_path):
            raise FileNotFoundError(f"File not found: {file_path}")

        with open(file_path, 'rb') as f:
            data = pickle.load(f)
        return data

    def render_data(self, data_type='train', batch_size=32, shuffle=True):
        if data_type == 'train':
            data = self.train_data
        elif data_type == 'val':
            data = self.val_data
        elif data_type == 'test':
            data = self.test_data
        else:
            raise ValueError("data_type must be 'train', 'val', or 'test'")

        images = data['images']
        labels = data['labels']

        indices = np.arange(len(images))
        if shuffle:
            np.random.shuffle(indices)

        for start_idx in range(0, len(images), batch_size):
            batch_indices = indices[start_idx:start_idx + batch_size]
            batch_images = images[batch_indices]
            batch_labels = labels[batch_indices]

            yield batch_images, batch_labels

    def get_data_size(self, data_type='train'):
        if data_type == 'train':
            return len(self.train_data['images'])
        elif data_type == 'val':
            return len(self.val_data['images'])
        elif data_type == 'test':
            return len(self.test_data['images'])
        else:
            raise ValueError("data_type must be 'train', 'val', or 'test'")

    def save_to_zip(self, output_path, data_type='train'):
        if data_type == 'train':
            data = self.train_data
        elif data_type == 'val':
            data = self.val_data
        elif data_type == 'test':
            data = self.test_data
        else:
            raise ValueError("data_type must be 'train', 'val', or 'test'")

        with ZipFile(output_path, 'w') as zip_file:
            np.save('images.npy', data['images'])
            np.save('labels.npy', data['labels'])
            zip_file.write('images.npy')
            zip_file.write('labels.npy')
            os.remove('images.npy')
            os.remove('labels.npy')

