def get_package_changelogs(packages):
    import subprocess
    changelogs = []

    for package in packages:
        try:
            # Run rpm -q --changelog for the package
            result = subprocess.run(['rpm', '-q', '--changelog', package], 
                                 capture_output=True, 
                                 text=True,
                                 check=True)

            # Add package name and changelog to list
            changelog_entry = {
                'package': package,
                'changelog': result.stdout
            }
            changelogs.append(changelog_entry)

        except subprocess.CalledProcessError as e:
            # Handle errors when package not found
            changelog_entry = {
                'package': package,
                'changelog': f"Error retrieving changelog: {e.stderr}"
            }
            changelogs.append(changelog_entry)

        except Exception as e:
            # Handle other errors
            changelog_entry = {
                'package': package,
                'changelog': f"Unexpected error: {str(e)}"
            }
            changelogs.append(changelog_entry)

    return changelogs
