from sqlalchemy import create_engine
from contextlib import contextmanager
from typing import Dict, List

class MultiDBConnection:
    def __init__(self, db_urls: Dict[str, str]):
        self.db_urls = db_urls
        self.engines = {}
        self.connections = {}

    def connect(self):
        try:
            for db_name, url in self.db_urls.items():
                engine = create_engine(url)
                self.engines[db_name] = engine
                self.connections[db_name] = engine.connect()
        except Exception as e:
            self.close()
            raise e

    def close(self):
        for conn in self.connections.values():
            conn.close()
        for engine in self.engines.values():
            engine.dispose()
        self.connections.clear()
        self.engines.clear()

    def get_connection(self, db_name: str):
        return self.connections.get(db_name)

    @contextmanager
    def session(self):
        self.connect()
        try:
            yield self
        finally:
            self.close()

def connect_databases(db_configs: Dict[str, str]) -> MultiDBConnection:
    """
    Connect to multiple databases and return connection manager

    Args:
        db_configs: Dictionary of database name to connection URL
    Returns:
        MultiDBConnection instance
    """
    return MultiDBConnection(db_configs)

# Usage example:
if __name__ == "__main__":
    db_urls = {
        "db1": "postgresql://user:pass@localhost:5432/db1",
        "db2": "mysql://user:pass@localhost:3306/db2"
    }

    with connect_databases(db_urls).session() as dbs:
        conn1 = dbs.get_connection("db1")
        conn2 = dbs.get_connection("db2")

        # Execute queries
        result1 = conn1.execute("SELECT * FROM table1")
        result2 = conn2.execute("SELECT * FROM table2")
