import hashlib

def calculate_md5(input_data):
    md5_hash = hashlib.md5()

    if isinstance(input_data, str):
        # Check if input is a file path
        try:
            with open(input_data, 'rb') as file:
                for chunk in iter(lambda: file.read(4096), b''):
                    md5_hash.update(chunk)
        except IOError:
            # If not a file path, treat as string content
            md5_hash.update(input_data.encode('utf-8'))
    elif isinstance(input_data, bytes):
        md5_hash.update(input_data)
    else:
        raise ValueError("Input must be a file path string, text string, or bytes")

    return md5_hash.hexdigest()

class DirectoryController
  attr_accessor :version, :size, :map_levels, :buffer, :system

  def initialize(version, size, map_levels)
    @version = version
    @size = size
    @map_levels = map_levels
    @buffer = MemoryBuffer.new(size)
    @dma = DMASequencer.new(self)
  end

  def assign_to_system(system)
    @system = system
    system.register_controller(self)
  end

  def process_request(address)
    @dma.sequence(address)
  end
end

class DMASequencer
  def initialize(controller)
    @controller = controller
    @current_sequence = 0
  end

  def sequence(address)
    @current_sequence += 1
    map_address(address)
  end

  private

  def map_address(address)
    mapped = address
    @controller.map_levels.times do |level|
      mapped = perform_mapping(mapped, level)
    end
    mapped
  end

  def perform_mapping(address, level)
    # Simple mapping algorithm for demonstration
    (address + level) % @controller.size
  end
end

class MemoryBuffer
  attr_reader :size, :data

  def initialize(size)
    @size = size
    @data = Array.new(size, 0)
  end

  def read(address)
    @data[address % @size]
  end

  def write(address, value)
    @data[address % @size] = value
  end
end

class System
  attr_reader :controllers

  def initialize
    @controllers = []
  end

  def register_controller(controller)
    @controllers << controller
  end
end

