from dataclasses import dataclass
from typing import List, Dict, Any
from abc import ABC, abstractmethod
import uuid

@dataclass
class Sequencer:
    sequence_id: str
    steps: List[str]

@dataclass 
class System:
    system_id: str
    name: str
    status: str

class Controller(ABC):
    def __init__(self, sequencer: Sequencer, system: System):
        self.controller_id = str(uuid.uuid4())
        self.sequencer = sequencer
        self.system = system

    @abstractmethod
    def execute(self):
        pass

    @abstractmethod
    def stop(self):
        pass

class BasicController(Controller):
    def execute(self):
        return f"Executing basic controller {self.controller_id}"

    def stop(self):
        return f"Stopping basic controller {self.controller_id}"

class AdvancedController(Controller):
    def execute(self):
        return f"Executing advanced controller {self.controller_id}"

    def stop(self):
        return f"Stopping advanced controller {self.controller_id}"

def create_controllers(controller_specs: List[Dict[str, Any]]) -> List[Controller]:
    controllers = []

    for spec in controller_specs:
        controller_type = spec["type"]
        count = spec["count"]

        for _ in range(count):
            sequencer = Sequencer(
                sequence_id=str(uuid.uuid4()),
                steps=["step1", "step2", "step3"]
            )

            system = System(
                system_id=str(uuid.uuid4()),
                name=f"System_{uuid.uuid4().hex[:6]}",
                status="ready"
            )

            if controller_type == "basic":
                controller = BasicController(sequencer, system)
            elif controller_type == "advanced":
                controller = AdvancedController(sequencer, system)
            else:
                raise ValueError(f"Unknown controller type: {controller_type}")

            controllers.append(controller)

    return controllers
