class CodeBlock:
    def __init__(self):
        self.lines = []
        self.indent = 0

    def append(self, line):
        if line.strip() == '':
            self.lines.append('')
            return

        if line.rstrip()[-1] == ':':
            self.lines.append('    ' * self.indent + line)
            self.indent += 1
        elif line.strip() == 'end':
            self.indent = max(0, self.indent - 1)
        else:
            self.lines.append('    ' * self.indent + line)

    def get_code(self):
        return '\n'.join(self.lines)

    def run(self):
        code = self.get_code()
        print('-' * 40)
        print('Executing code:')
        print('-' * 40)
        print(code)
        print('-' * 40)
        exec(code)

if __name__ == '__main__':
    code = CodeBlock()
    print("Enter code (empty line to execute, 'quit' to exit):")

    while True:
        line = input('> ')
        if line.strip() == '':
            code.run()
            code = CodeBlock()
            print("\nEnter code (empty line to execute, 'quit' to exit):")
        elif line.strip().lower() == 'quit':
            break
        else:
            code.append(line)
