@contextmanager
def save_file(path: str, content: Optional[str] = None) -> None:
    try:
        save_obj = save.Save()
        save_obj.configure(path=path)
        yield save_obj
        if content:
            save_obj.execute(content)
    except Exception as e:
        raise CommandError(f"Failed to save file: {str(e)}")
    finally:
        save_obj.cleanup()

