import json
from typing import Any, Optional


def deserialize(input_str: str, decode_keys: bool = False) -> Any:
    def key_hook(pairs):
        if not decode_keys:
            return dict(pairs)
        return {
            json.loads(k) if isinstance(k, str) and k.startswith('"') and k.endswith('"') else k: v
            for k, v in pairs
        }

    try:
        return json.loads(input_str, object_pairs_hook=key_hook)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON string")

