import sys
import traceback
from functools import wraps

def handle_import(module_name, alt_module_name=None):
    try:
        if sys.version_info[0] >= 3:
            return __import__(module_name)
        else:
            return __import__(alt_module_name or module_name)
    except ImportError as e:
        raise ImportError(f"Failed to import {module_name}: {str(e)}")

def custom_exception_handler(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        try:
            return func(*args, **kwargs)
        except Exception as e:
            exc_type, exc_value, exc_traceback = sys.exc_info()
            stack_trace = ''.join(traceback.format_tb(exc_traceback))

            error_msg = (
                f"Error in {func.__name__}:\n"
                f"Type: {exc_type.__name__}\n"
                f"Message: {str(e)}\n"
                f"Stack trace:\n{stack_trace}"
            )

            raise type(e)(error_msg).with_traceback(exc_traceback)
    return wrapper

def version_specific_code():
    if sys.version_info[0] >= 3:
        try:
            import urllib.request as urllib
        except ImportError:
            import urllib as urllib
    else:
        import urllib2 as urllib
    return urllib

@custom_exception_handler
def example_function():
    # Example usage
    urllib = version_specific_code()
    json = handle_import('json')

    try:
        # Some operation that might fail
        result = 1 / 0
    except ZeroDivisionError:
        raise ValueError("Custom error message for division by zero")

    return result

import os
import types
import sys

def load_config(filename, silent=False):
    try:
        if not os.path.exists(filename):
            if not silent:
                print(f"Error: Configuration file '{filename}' not found.", file=sys.stderr)
            return False

        config_globals = {}
        with open(filename, 'r') as f:
            config_code = f.read()

        code_object = compile(config_code, filename, 'exec')
        exec(code_object, config_globals)

        module = types.ModuleType('config')
        for key, value in config_globals.items():
            if not key.startswith('__'):
                setattr(module, key, value)

        globals()['config'] = module
        return True

    except (SyntaxError, PermissionError) as e:
        if not silent:
            print(f"Error loading configuration: {str(e)}", file=sys.stderr)
        return False
    except Exception as e:
        if not silent:
            print(f"Unexpected error loading configuration: {str(e)}", file=sys.stderr)
        return False

