from hashlib import md5, sha1, sha256, sha512
from typing import List, Optional

def get_hash_value(strings: List[str], hash_func: str = 'md5', unit: Optional[str] = None) -> str:
    valid_units = {'hex', 'base64', 'bytes', None}
    valid_hashes = {
        'md5': md5,
        'sha1': sha1,
        'sha256': sha256,
        'sha512': sha512
    }

    if unit not in valid_units:
        raise ValueError(f"Invalid unit. Must be one of {valid_units}")

    if hash_func not in valid_hashes:
        raise ValueError(f"Invalid hash function. Must be one of {list(valid_hashes.keys())}")

    hasher = valid_hashes[hash_func]()
    for s in strings:
        hasher.update(s.encode('utf-8'))

    if unit == 'hex':
        return hasher.hexdigest()
    elif unit == 'base64':
        return hasher.digest().hex()
    elif unit == 'bytes':
        return hasher.digest()
    else:
        return hasher.hexdigest()
