import os
import subprocess
import re

def process_files():
    file_versions = []

    try:
        with open('files.txt', 'r') as f:
            content = f.read()

        # Delete directory if it exists
        if os.path.exists('temp_dir'):
            subprocess.run(['rm', '-rf', 'temp_dir'], check=True)

        # Parse filenames and versions
        pattern = r'(\w+)_v(\d+\.\d+)'
        matches = re.finditer(pattern, content)

        for match in matches:
            filename = match.group(1)
            version = float(match.group(2))
            file_versions.append((filename, version))

        return sorted(file_versions, key=lambda x: x[1], reverse=True)

    except FileNotFoundError:
        return []
    except subprocess.CalledProcessError:
        print("Error deleting directory")
        return []
    except Exception as e:
        print(f"Error: {str(e)}")
        return []

if __name__ == '__main__':
    results = process_files()
    for filename, version in results:
        print(f"{filename}: v{version}")
