#!/usr/bin/env python3

import os
import shutil
import urllib.request
import zipfile
import tarfile
import tempfile
from pathlib import Path

def setup_folders(build_dir):
    """Create required folder structure"""
    staging = os.path.join(build_dir, 'staging')
    final = os.path.join(build_dir, 'final')

    for folder in [staging, final]:
        if os.path.exists(folder):
            shutil.rmtree(folder)
        os.makedirs(folder)

    return staging, final

def download_package(url, dest_path):
    """Download package from URL to destination path"""
    try:
        urllib.request.urlretrieve(url, dest_path)
    except Exception as e:
        print(f"Failed to download {url}: {e}")
        return False
    return True

def extract_package(package_path, extract_path):
    """Extract zip/tar package to specified path"""
    try:
        if package_path.endswith('.zip'):
            with zipfile.ZipFile(package_path, 'r') as zip_ref:
                zip_ref.extractall(extract_path)
        elif package_path.endswith(('.tar.gz', '.tgz')):
            with tarfile.open(package_path, 'r:gz') as tar_ref:
                tar_ref.extractall(extract_path)
        else:
            print(f"Unsupported package format: {package_path}")
            return False
    except Exception as e:
        print(f"Failed to extract {package_path}: {e}")
        return False
    return True

def process_products(products, build_dir):
    """Process products dictionary and create final build"""
    staging_dir, final_dir = setup_folders(build_dir)

    for product, packages in products.items():
        # Create product staging folder
        product_staging = os.path.join(staging_dir, product)
        os.makedirs(product_staging)

        # Process each package
        for package_url in packages:
            # Create temp file for download
            with tempfile.NamedTemporaryFile(delete=False) as tmp_file:
                package_path = tmp_file.name

            # Download and extract
            if download_package(package_url, package_path):
                if extract_package(package_path, product_staging):
                    # Move extracted contents to final
                    product_final = os.path.join(final_dir, product)
                    os.makedirs(product_final, exist_ok=True)

                    # Move all items from staging to final
                    for item in os.listdir(product_staging):
                        src = os.path.join(product_staging, item)
                        dst = os.path.join(product_final, item)
                        if os.path.exists(dst):
                            if os.path.isdir(dst):
                                shutil.rmtree(dst)
                            else:
                                os.remove(dst)
                        shutil.move(src, dst)

            # Cleanup temp file
            os.unlink(package_path)

    # Create zip of final folder
    shutil.make_archive(
        os.path.join(build_dir, 'final_build'),
        'zip',
        final_dir
    )

def main():
    # Example usage
    products = {
        'product1': [
            'http://example.com/package1.zip',
            'http://example.com/package2.tar.gz'
        ],
        'product2': [
            'http://example.com/package3.zip'
        ]
    }

    build_dir = '/path/to/build/directory'
    process_products(products, build_dir)

if __name__ == '__main__':
    main()
```

