import hashlib
from urllib.parse import urlencode

def get_gravatar_url(email, params=None):
    email_hash = hashlib.md5(email.lower().strip().encode('utf-8')).hexdigest()

    base_url = f'https://www.gravatar.com/avatar/{email_hash}'

    if not params:
        return base_url

    # Remove None values and convert bools to strings
    clean_params = {}
    for key, value in params.items():
        if value is not None:
            if isinstance(value, bool):
                clean_params[key] = str(value).lower()
            else:
                clean_params[key] = value

    # Sort parameters alphabetically
    sorted_params = dict(sorted(clean_params.items()))

    # Build query string
    query_string = urlencode(sorted_params)

    return f'{base_url}?{query_string}'
