        if (args.length < 2) {
            System.err.println("Usage: AntlrRunner <directory> <file> [options...]");
            System.exit(1);
        }

        String directory = args[0];
        String file = args[1];

        List<String> command = new ArrayList<>();
        command.add("java");
        command.add("-jar");
        command.add("antlr-4.9.2-complete.jar");
        command.add(file);

        // Add additional options
        for (int i = 2; i < args.length; i++) {
            command.add(args[i]);
        }

        ProcessBuilder processBuilder = new ProcessBuilder(command);
        processBuilder.directory(new File(directory));
        processBuilder.redirectErrorStream(true);

        try {
            Process process = processBuilder.start();

            // Read the output
            BufferedReader reader = new BufferedReader(
                new InputStreamReader(process.getInputStream())
            );

            String line;
            StringBuilder output = new StringBuilder();
            while ((line = reader.readLine()) != null) {
                output.append(line).append("\n");
            }

            // Wait for the process to complete
            int exitCode = process.waitFor();

            // Print the output
            System.out.print(output.toString());

            // Check for errors
            if (exitCode != 0) {
                System.err.println("ANTLR process failed with exit code: " + exitCode);
                System.exit(exitCode);
            }

        } catch (IOException e) {
            System.err.println("Error executing ANTLR: " + e.getMessage());
            e.printStackTrace();
            System.exit(1);
        } catch (InterruptedException e) {
            System.err.println("Process interrupted: " + e.getMessage());
            Thread.currentThread().interrupt();
            System.exit(1);
        }
    }
}

