from hashlib import sha1

@lru_cache(maxsize=128)
def make_hash_function(attributes):
    def hash_function(instance):
        values = tuple(getattr(instance, attr) for attr in attributes)
        hash_str = ''.join(repr(v) for v in values)
        return sha1(hash_str.encode()).hexdigest()
    return hash_function

