import requests
from typing import List, Dict, Any
from dataclasses import dataclass
import json

@dataclass
class ResponseItem:
    id: int
    name: str
    status: str

def fetch_and_validate_api_data(url: str) -> List[ResponseItem]:
    try:
        response = requests.get(url)
        response.raise_for_status()

        data = response.json()

        if not isinstance(data, list):
            raise ValueError("API response is not a list")

        validated_items = []
        for item in data:
            if not isinstance(item, dict):
                raise ValueError("List item is not an object")

            if not all(key in item for key in ['id', 'name', 'status']):
                raise ValueError("Object missing required fields")

            if not isinstance(item['id'], int):
                raise ValueError("ID field must be an integer")

            if not isinstance(item['name'], str):
                raise ValueError("Name field must be a string")

            if not isinstance(item['status'], str):
                raise ValueError("Status field must be a string")

            validated_items.append(ResponseItem(
                id=item['id'],
                name=item['name'],
                status=item['status']
            ))

        return validated_items

    except requests.exceptions.RequestException as e:
        raise RuntimeError(f"API request failed: {str(e)}")
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON response")
