def update_asset_type(base_url, asset_type_id, updated_data):
    endpoint = f"{base_url}/api/asset-types/{asset_type_id}"

    headers = {
        'Content-Type': 'application/json'
    }

    try:
        response = requests.put(endpoint, headers=headers, data=json.dumps(updated_data))
        response.raise_for_status()

        response_data = response.json()

        if 'message' not in response_data or 'success' not in response_data['message'].lower():
            raise ValueError('Update was not successful')

        return response_data

    except requests.exceptions.RequestException as e:
        raise Exception(f"Failed to update asset type: {str(e)}")
    except ValueError as e:
        raise Exception(f"Invalid response: {str(e)}")
    except json.JSONDecodeError:
        raise Exception("Failed to parse response JSON")
