function generateIdentifier(input = '', length = 16, base = 16) {
    const charset = '0123456789abcdef'.slice(0, base);
    let seed = 0;

    if (input) {
        for (let i = 0; i < input.length; i++) {
            seed = ((seed << 5) - seed) + input.charCodeAt(i);
            seed = seed & seed;
        }
    } else {
        seed = Date.now();
    }

    const random = function() {
        const x = Math.sin(seed++) * 10000;
        return x - Math.floor(x);
    };

    let result = '';
    for (let i = 0; i < length; i++) {
        result += charset[Math.floor(random() * charset.length)];
    }

    return result;
}

const axios = require('axios');
const FormData = require('form-data');
const fs = require('fs');
const path = require('path');

async function uploadFileFromUrl(sourceUrl) {
  try {
    // Download file from URL
    const response = await axios({
      method: 'get',
      url: sourceUrl,
      responseType: 'stream'
    });

    // Create temp file name
    const tempFile = path.join(__dirname, 'temp_' + Date.now() + path.extname(sourceUrl));

    // Save file locally
    await new Promise((resolve, reject) => {
      const writer = fs.createWriteStream(tempFile);
      response.data.pipe(writer);
      writer.on('finish', resolve);
      writer.on('error', reject);
    });

    // Prepare form data for upload
    const formData = new FormData();
    formData.append('file', fs.createReadStream(tempFile));

    // Upload to destination server
    const uploadResponse = await axios.post('https://your-upload-server.com/upload', formData, {
      headers: {
        ...formData.getHeaders(),
        'Authorization': 'Bearer YOUR_API_KEY'
      }
    });

    // Clean up temp file
    fs.unlinkSync(tempFile);

    // Return uploaded file URL
    return uploadResponse.data.fileUrl;

  } catch (error) {
    throw new Error(`File upload failed: ${error.message}`);
  }
}

module.exports = uploadFileFromUrl;

