const stylus = require('stylus');
const fs = require('fs');
const path = require('path');

function processStylusFiles(sourcePath, destPath) {
  return new Promise((resolve, reject) => {
    const stylusContent = [];

    // Read all .styl files recursively
    function readStylusFiles(dir) {
      const files = fs.readdirSync(dir);

      files.forEach(file => {
        const filePath = path.join(dir, file);
        const stat = fs.statSync(filePath);

        if (stat.isDirectory()) {
          readStylusFiles(filePath);
        } else if (path.extname(file) === '.styl') {
          stylusContent.push(fs.readFileSync(filePath, 'utf8'));
        }
      });
    }

    try {
      readStylusFiles(sourcePath);

      // Concatenate all Stylus content
      const combinedStylus = stylusContent.join('\n');

      // Process Stylus to CSS
      stylus(combinedStylus)
        .set('filename', 'combined.css')
        .set('compress', true)
        .render((err, css) => {
          if (err) {
            reject(err);
            return;
          }

          // Create destination directory if it doesn't exist
          if (!fs.existsSync(destPath)) {
            fs.mkdirSync(destPath, { recursive: true });
          }

          // Write the processed CSS to destination
          const outputPath = path.join(destPath, 'combined.css');
          fs.writeFileSync(outputPath, css);
          resolve(outputPath);
        });

    } catch (error) {
      reject(error);
    }
  });
}

module.exports = processStylusFiles;
