function shuffleHosts(hosts, useHttps) {
    const protocol = useHttps ? 'https://' : 'http://';
    const dsnHosts = hosts.filter(host => host.includes('dsn'));
    const nonDsnHosts = hosts.filter(host => !host.includes('dsn'));

    for (let i = nonDsnHosts.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [nonDsnHosts[i], nonDsnHosts[j]] = [nonDsnHosts[j], nonDsnHosts[i]];
    }

    const shuffledHosts = dsnHosts.length > 0 
        ? [...dsnHosts, ...nonDsnHosts]
        : nonDsnHosts;

    return shuffledHosts.map(host => {
        if (host.startsWith('http://') || host.startsWith('https://')) {
            return host;
        }
        return `${protocol}${host}`;
    });
}

const findMatch = (patterns, userAgent) => {
  return patterns.reduce((match, pattern) => {
    if (match) return match;

    const hasQualifier = pattern.qualifier && userAgent.indexOf(pattern.qualifier) === 0;
    const matchesPattern = pattern.pattern.test(userAgent);

    return (pattern.qualifier ? hasQualifier && matchesPattern : matchesPattern) ? pattern : null;
  }, null);
};

