const handleFileRequest = (req, res, filePath) => {
  const fs = require('fs');
  const path = require('path');

  console.log(`${new Date().toISOString()} - ${req.method} ${req.url}`);

  if (req.method !== 'GET') {
    res.writeHead(405, { 'Content-Type': 'text/plain' });
    res.end('Method Not Allowed');
    return;
  }

  if (req.url.endsWith('/')) {
    const redirectUrl = req.url.slice(0, -1);
    res.writeHead(301, { 'Location': redirectUrl });
    res.end();
    return;
  }

  fs.stat(filePath, (err, stats) => {
    if (err || !stats.isFile()) {
      res.writeHead(404, { 'Content-Type': 'text/plain' });
      res.end('Not Found');
      return;
    }

    const fileStream = fs.createReadStream(filePath);
    const ext = path.extname(filePath);
    const contentType = {
      '.html': 'text/html',
      '.css': 'text/css',
      '.js': 'text/javascript',
      '.json': 'application/json',
      '.png': 'image/png',
      '.jpg': 'image/jpeg',
      '.gif': 'image/gif'
    }[ext] || 'application/octet-stream';

    res.writeHead(200, { 'Content-Type': contentType });
    fileStream.pipe(res);

    fileStream.on('error', (error) => {
      console.error(`Error streaming file: ${error}`);
      res.writeHead(500, { 'Content-Type': 'text/plain' });
      res.end('Internal Server Error');
    });
  });
};

function createFormatFunctions(format) {
    const parts = format.split(',').map(part => part.trim());
    const [xPart, yPart] = parts;

    const comparisonCode = `
        return function(a, b) {
            const aX = ${xPart.replace(/\$/g, 'a')};
            const bX = ${xPart.replace(/\$/g, 'b')};
            if (aX !== bX) return aX - bX;

            const aY = ${yPart.replace(/\$/g, 'a')};
            const bY = ${yPart.replace(/\$/g, 'b')};
            return aY - bY;
        }
    `;

    const formattingCode = `
        return function(data) {
            if (!data || data.length === 0) {
                return { minX: 0, minY: 0, maxX: 0, maxY: 0 };
            }

            let minX = ${xPart.replace(/\$/g, 'data[0]')};
            let maxX = minX;
            let minY = ${yPart.replace(/\$/g, 'data[0]')};
            let maxY = minY;

            for (let i = 1; i < data.length; i++) {
                const x = ${xPart.replace(/\$/g, 'data[i]')};
                const y = ${yPart.replace(/\$/g, 'data[i]')};

                minX = Math.min(minX, x);
                maxX = Math.max(maxX, x);
                minY = Math.min(minY, y);
                maxY = Math.max(maxY, y);
            }

            return { minX, minY, maxX, maxY };
        }
    `;

    return {
        compare: new Function(comparisonCode)(),
        format: new Function(formattingCode)()
    };
}

const fs = require('fs');
const path = require('path');

function checkFilesAndDirectories() {
    const requiredFiles = [
        'package.json',
        'README.md',
        'src/index.js',
        'config/settings.json'
    ];

    const requiredDirectories = [
        'src',
        'config',
        'test',
        'docs'
    ];

    function traverseDirectory(currentPath) {
        let allExist = true;

        for (const file of requiredFiles) {
            const filePath = path.join(currentPath, file);
            if (!fs.existsSync(filePath)) {
                allExist = false;
                break;
            }
        }

        for (const dir of requiredDirectories) {
            const dirPath = path.join(currentPath, dir);
            if (!fs.existsSync(dirPath) || !fs.statSync(dirPath).isDirectory()) {
                allExist = false;
                break;
            }
        }

        if (!allExist) {
            const parentDir = path.dirname(currentPath);
            if (parentDir !== currentPath) {
                return traverseDirectory(parentDir);
            }
            return false;
        }

        return true;
    }

    return traverseDirectory(process.cwd());
}

module.exports = checkFilesAndDirectories;

