const fs = require('fs');
const path = require('path');

function validateDirectoryTree(fsObject, dirPath, options = {}) {
    const {
        createMissing = true,
        validateFiles = true,
        validateDirs = true
    } = options;

    try {
        if (!fs.existsSync(dirPath)) {
            if (createMissing) {
                fs.mkdirSync(dirPath, { recursive: true });
            } else {
                return false;
            }
        }

        let isValid = true;

        for (const [name, item] of Object.entries(fsObject)) {
            const fullPath = path.join(dirPath, name);

            if (typeof item === 'object') {
                if (validateDirs) {
                    const stats = fs.existsSync(fullPath) && fs.statSync(fullPath);
                    if (!stats || !stats.isDirectory()) {
                        if (createMissing) {
                            fs.mkdirSync(fullPath, { recursive: true });
                        } else {
                            isValid = false;
                            continue;
                        }
                    }
                }
                isValid = validateDirectoryTree(item, fullPath, options) && isValid;
            } else if (validateFiles) {
                const exists = fs.existsSync(fullPath);
                if (!exists) {
                    isValid = false;
                }
            }
        }

        return isValid;
    } catch (error) {
        return false;
    }
}

