#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

#define OFP_ACTION_OUTPUT 0
#define OFP_ACTION_SET_VLAN_VID 1  
#define OFP_ACTION_SET_VLAN_PCP 2
#define OFP_ACTION_STRIP_VLAN 3
#define OFP_ACTION_SET_DL_SRC 4
#define OFP_ACTION_SET_DL_DST 5

struct action_result {
    int success;
    char error_msg[256];
    int error_code;
    int offset;
    struct ofp_action *action;
};

struct action_result parse_action(uint8_t *buffer, int offset) {
    struct action_result result = {0};

    // Get action header
    uint16_t type = ntohs(*(uint16_t*)(buffer + offset));
    uint16_t len = ntohs(*(uint16_t*)(buffer + offset + 2));

    // Validate length
    if (len < 8) {
        result.success = 0;
        result.error_code = -1;
        strcpy(result.error_msg, "Action length too small");
        return result;
    }

    // Allocate action struct
    struct ofp_action *action = malloc(len);
    if (!action) {
        result.success = 0; 
        result.error_code = -2;
        strcpy(result.error_msg, "Memory allocation failed");
        return result;
    }

    // Copy header
    memcpy(action, buffer + offset, len);

    // Validate action type and parse fields
    switch(type) {
        case OFP_ACTION_OUTPUT:
            if (len != 8) {
                free(action);
                result.success = 0;
                result.error_code = -3; 
                strcpy(result.error_msg, "Invalid length for output action");
                return result;
            }
            break;

        case OFP_ACTION_SET_VLAN_VID:
            if (len != 8) {
                free(action);
                result.success = 0;
                result.error_code = -3;
                strcpy(result.error_msg, "Invalid length for set VLAN VID action");
                return result;
            }
            break;

        case OFP_ACTION_SET_VLAN_PCP:
            if (len != 8) {
                free(action);
                result.success = 0;
                result.error_code = -3;
                strcpy(result.error_msg, "Invalid length for set VLAN PCP action");
                return result;
            }
            break;

        case OFP_ACTION_STRIP_VLAN:
            if (len != 8) {
                free(action);
                result.success = 0;
                result.error_code = -3;
                strcpy(result.error_msg, "Invalid length for strip VLAN action");
                return result;
            }
            break;

        case OFP_ACTION_SET_DL_SRC:
        case OFP_ACTION_SET_DL_DST:
            if (len != 16) {
                free(action);
                result.success = 0;
                result.error_code = -3;
                strcpy(result.error_msg, "Invalid length for set datalink action");
                return result;
            }
            break;

        default:
            free(action);
            result.success = 0;
            result.error_code = -4;
            strcpy(result.error_msg, "Unknown action type");
            return result;
    }

    // Success
    result.success = 1;
    result.action = action;
    result.offset = offset + len;
    return result;
}
