const fs = require('fs');
const path = require('path');

function getConfigValue(config, key) {
    if (config[key] !== undefined) {
        return config[key];
    }

    // Check for JS file in current and parent directories
    let currentDir = process.cwd();
    while (currentDir !== path.parse(currentDir).root) {
        const jsFilePath = path.join(currentDir, `${key}.js`);
        if (fs.existsSync(jsFilePath)) {
            try {
                const value = require(jsFilePath);
                config[key] = value;
                return value;
            } catch (error) {
                // Continue searching if file can't be required
            }
        }
        currentDir = path.dirname(currentDir);
    }

    // Check package.json
    try {
        const packageJsonPath = path.join(process.cwd(), 'package.json');
        if (fs.existsSync(packageJsonPath)) {
            const packageJson = require(packageJsonPath);
            if (packageJson[key] !== undefined) {
                config[key] = packageJson[key];
                return packageJson[key];
            }

            // Check dependencies and devDependencies
            const allDependencies = {
                ...packageJson.dependencies,
                ...packageJson.devDependencies
            };

            if (allDependencies && allDependencies[key]) {
                config[key] = allDependencies[key];
                return allDependencies[key];
            }
        }
    } catch (error) {
        // Return undefined if package.json can't be read
    }

    return undefined;
}

function getBufferLength(buffer, repeat, opts) {
    let escapedGroupSeparator = escapeRegex(opts.groupSeparator);
    let groupSepWithGlobalFlag = new RegExp(escapedGroupSeparator, "g");
    let escapedRadixPoint = escapeRegex(opts.radixPoint);
    let radixPointWithGlobalFlag = new RegExp(escapedRadixPoint, "g");

    let initialLength = buffer.length;
    let valueLength = 0;
    let groupOffset = 0;

    if (repeat > 1) {
        valueLength = (initialLength * repeat);
        let groupSepMatches = (buffer.join("").match(groupSepWithGlobalFlag) || []).length;
        let radixMatches = (buffer.join("").match(radixPointWithGlobalFlag) || []).length;

        valueLength += (groupSepMatches * (repeat - 1));
        valueLength -= (radixMatches * (repeat - 1));
        groupOffset = groupSepMatches * (repeat - 1);
    } else {
        valueLength = initialLength;
        let matches = (buffer.join("").match(groupSepWithGlobalFlag) || []).length;
        groupOffset = matches;
    }

    return {
        length: valueLength,
        groupOffset: groupOffset
    };
}

const fs = require('fs');
const path = require('path');
const less = require('less');

async function compileLessFiles(directory) {
    const result = {};

    async function processDirectory(dir) {
        const files = fs.readdirSync(dir);

        for (const file of files) {
            const filePath = path.join(dir, file);
            const stat = fs.statSync(filePath);

            if (stat.isDirectory()) {
                await processDirectory(filePath);
                continue;
            }

            if (path.extname(file) === '.less') {
                try {
                    const lessContent = fs.readFileSync(filePath, 'utf8');
                    const cssOutput = await less.render(lessContent, {
                        filename: filePath,
                        compress: false
                    });

                    const cssFilePath = filePath.replace('.less', '.css');
                    fs.writeFileSync(cssFilePath, cssOutput.css);
                    result[cssFilePath] = filePath;

                } catch (error) {
                    console.error(`Error processing ${filePath}:`, error);
                }
            }
        }
    }

    await processDirectory(directory);
    return result;
}

module.exports = compileLessFiles;

function searchAlerts(duration, searchString) {
  const configPath = 'path/to/config.json';
  let matches = 0;
  let firstMatch = null;

  try {
    const config = JSON.parse(fs.readFileSync(configPath, 'utf8'));
    const alerts = config.alerts || [];

    for (let i = 0; i < alerts.length; i++) {
      const alert = alerts[i];

      if (alert.duration === duration) {
        const alertString = JSON.stringify(alert).toLowerCase();

        if (alertString.includes(searchString.toLowerCase())) {
          matches++;

          if (firstMatch === null) {
            firstMatch = {
              lineNumber: i + 1,
              offset: alertString.indexOf(searchString.toLowerCase())
            };
          }
        }
      }
    }

    return {
      matchCount: matches,
      jumpTarget: firstMatch ? `${configPath}:${firstMatch.lineNumber}:${firstMatch.offset}` : null
    };
  } catch (error) {
    throw new Error(`Error searching alerts: ${error.message}`);
  }
}

