function matchesSelector(element, selector, operator = '=', value = null) {
  const selectorParts = selector.match(/([^\[\]]+)(?:\[([^\]=]+)([=!]+)["']?([^"'\]]*)?["']?\])?/);

  if (!selectorParts) {
    return false;
  }

  const [, tagName, attribute, selectorOperator, selectorValue] = selectorParts;

  if (tagName && element.tagName.toLowerCase() !== tagName.toLowerCase()) {
    return false;
  }

  if (attribute) {
    const attributeValue = Sizzle.attr(element, attribute);

    switch (selectorOperator) {
      case '=':
        return attributeValue === selectorValue;
      case '!=':
        return attributeValue !== selectorValue;
      case '^=':
        return attributeValue.startsWith(selectorValue);
      case '$=':
        return attributeValue.endsWith(selectorValue);
      case '*=':
        return attributeValue.includes(selectorValue);
      case '~=':
        return attributeValue.split(/\s+/).includes(selectorValue);
      case '|=':
        return attributeValue === selectorValue || 
               attributeValue.startsWith(selectorValue + '-');
      default:
        return false;
    }
  }

  if (value !== null) {
    const elementValue = Sizzle.attr(element, selector);

    switch (operator) {
      case '=':
        return elementValue === value;
      case '!=':
        return elementValue !== value;
      case '^=':
        return elementValue.startsWith(value);
      case '$=':
        return elementValue.endsWith(value);
      case '*=':
        return elementValue.includes(value);
      case '~=':
        return elementValue.split(/\s+/).includes(value);
      case '|=':
        return elementValue === value || 
               elementValue.startsWith(value + '-');
      default:
        return false;
    }
  }

  return true;
}

const fs = require('fs');
const path = require('path');

function traverseDirectory(dirPath, targetFiles) {
    try {
        const files = fs.readdirSync(dirPath);
        const results = [];

        files.forEach(file => {
            const fullPath = path.join(dirPath, file);
            const stats = fs.statSync(fullPath);

            if (stats.isDirectory()) {
                results.push(...traverseDirectory(fullPath, targetFiles));
            } else if (targetFiles.includes(file)) {
                results.push({
                    file: file,
                    path: fullPath,
                    found: true
                });
            }
        });

        targetFiles.forEach(targetFile => {
            if (!files.includes(targetFile)) {
                results.push({
                    file: targetFile,
                    path: path.join(dirPath, targetFile),
                    found: false
                });
            }
        });

        return results;
    } catch (error) {
        console.error(`Error accessing directory ${dirPath}: ${error.message}`);
        return [];
    }
}

function createStar(ctx, canvasWidth, canvasHeight) {
    return {
        x: Math.random() * canvasWidth,
        y: Math.random() * canvasHeight,
        radius: Math.random() * 2 + 0.5,
        vx: (Math.random() - 0.5) * 2,
        vy: (Math.random() - 0.5) * 2,
        draw: function() {
            ctx.beginPath();
            ctx.arc(this.x, this.y, this.radius, 0, Math.PI * 2);
            ctx.fillStyle = 'white';
            ctx.fill();
        },
        update: function() {
            this.x += this.vx;
            this.y += this.vy;

            if (this.x < 0) this.x = canvasWidth;
            if (this.x > canvasWidth) this.x = 0;
            if (this.y < 0) this.y = canvasHeight;
            if (this.y > canvasHeight) this.y = 0;
        }
    };
}

function depthFirstSearch(grid, x, y, visited = new Set()) {
    if (x < 0 || x >= grid.length || y < 0 || y >= grid[0].length) return;

    const key = `${x},${y}`;
    if (visited.has(key) || grid[x][y].state === 'visited') return;

    grid[x][y].state = 'visited';
    visited.add(key);

    const directions = [[-1, 0], [1, 0], [0, -1], [0, 1]];
    for (const [dx, dy] of directions) {
        depthFirstSearch(grid, x + dx, y + dy, visited);
    }
}

function plantNodesInGrid(grid, maxNodes, startX, startY) {
    let nodesPlanted = 0;

    function getRandomPosition() {
        const x = Math.floor(Math.random() * grid.length);
        const y = Math.floor(Math.random() * grid[0].length);
        return [x, y];
    }

    function plantNode() {
        if (nodesPlanted >= maxNodes) return;

        const [x, y] = getRandomPosition();
        if (grid[x][y].state !== 'visited') {
            grid[x][y].value = Math.floor(Math.random() * 100);
            depthFirstSearch(grid, startX, startY);
            nodesPlanted++;
            plantNode();
        } else {
            plantNode();
        }
    }

    plantNode();
    return grid;
}

