const fs = require('fs');

function loadFiles(fileList, callback) {
    let result = {};
    let completed = 0;

    fileList.forEach(file => {
        fs.readFile(file, 'utf8', (err, data) => {
            if (err) {
                return callback(err);
            }

            try {
                result[file] = JSON.parse(data);
            } catch (parseError) {
                result[file] = data;
            }

            completed++;
            if (completed === fileList.length) {
                callback(null, result);
            }
        });
    });
}

