function validateField(field, regexString, errorMessage) {
    const regex = new RegExp(regexString);
    const isValid = regex.test(field.value);

    if (!isValid) {
        field.classList.add('invalid');

        let errorDiv = field.nextElementSibling;
        if (!errorDiv || !errorDiv.classList.contains('error-message')) {
            errorDiv = document.createElement('div');
            errorDiv.classList.add('error-message');
            field.parentNode.insertBefore(errorDiv, field.nextSibling);
        }
        errorDiv.textContent = errorMessage;
        return false;
    } else {
        field.classList.remove('invalid');

        const errorDiv = field.nextElementSibling;
        if (errorDiv && errorDiv.classList.contains('error-message')) {
            errorDiv.remove();
        }
        return true;
    }
}

function reformatString(input, groupSize = 3, separator = '-') {
  if (!input) return '';

  const cleanInput = input.replace(/\D/g, '');
  const pattern = new RegExp(`(\\d{${groupSize}})`, 'g');

  let formatted = cleanInput.replace(pattern, `$1${separator}`);

  if (formatted.endsWith(separator)) {
    formatted = formatted.slice(0, -1);
  }

  const remainderPattern = new RegExp(`^\\d{1,${groupSize-1}}${separator}`);
  if (remainderPattern.test(formatted)) {
    formatted = formatted.replace(separator, '');
  }

  return formatted;
}

const { exec } = require('child_process');
const fs = require('fs');
const path = require('path');

async function cloneAndLink(repoUrl, targetDir, executablePath, linkPath) {
    return new Promise((resolve, reject) => {
        // Create target directory if it doesn't exist
        if (!fs.existsSync(targetDir)) {
            fs.mkdirSync(targetDir, { recursive: true });
        }

        // Clone the repository
        exec(`git clone ${repoUrl} ${targetDir}`, (error, stdout, stderr) => {
            if (error) {
                reject(new Error(`Git clone failed: ${error.message}`));
                return;
            }

            // Create symbolic link
            const fullExecPath = path.join(targetDir, executablePath);
            const fullLinkPath = path.join(linkPath);

            if (!fs.existsSync(fullExecPath)) {
                reject(new Error(`Executable not found at ${fullExecPath}`));
                return;
            }

            // Remove existing symlink if it exists
            if (fs.existsSync(fullLinkPath)) {
                fs.unlinkSync(fullLinkPath);
            }

            // Create new symlink
            fs.symlink(fullExecPath, fullLinkPath, 'file', (err) => {
                if (err) {
                    reject(new Error(`Failed to create symlink: ${err.message}`));
                    return;
                }
                resolve();
            });
        });
    });
}

