function createClientTransaction(requestSender, sipRequest, transport) {
    const transactionId = Math.random().toString(36).substring(2, 15);

    const logger = {
        debug: (msg) => console.debug(`[Transaction ${transactionId}] ${msg}`),
        info: (msg) => console.info(`[Transaction ${transactionId}] ${msg}`),
        warn: (msg) => console.warn(`[Transaction ${transactionId}] ${msg}`),
        error: (msg) => console.error(`[Transaction ${transactionId}] ${msg}`)
    };

    const transaction = {
        id: transactionId,
        request: sipRequest,
        sender: requestSender,
        transport: transport,
        logger: logger,
        state: 'TRYING',

        send: function() {
            this.logger.debug('Sending request...');
            try {
                this.transport.send(this.request);
                this.state = 'PROCEEDING';
                this.logger.info('Request sent successfully');
            } catch (error) {
                this.state = 'FAILED';
                this.logger.error(`Failed to send request: ${error.message}`);
                throw error;
            }
        },

        receive: function(response) {
            this.logger.debug(`Received response with status ${response.status}`);
            if (response.status >= 200) {
                this.state = 'COMPLETED';
            }
            this.sender.onResponse(response);
        },

        cancel: function() {
            this.logger.info('Cancelling transaction');
            this.state = 'CANCELLED';
            if (this.transport.isConnected()) {
                this.transport.close();
            }
        },

        getState: function() {
            return this.state;
        },

        isActive: function() {
            return ['TRYING', 'PROCEEDING'].includes(this.state);
        }
    };

    transport.onData = (data) => {
        transaction.receive(data);
    };

    transport.onError = (error) => {
        transaction.logger.error(`Transport error: ${error.message}`);
        transaction.state = 'FAILED';
        transaction.sender.onError(error);
    };

    return transaction;
}

