const fs = require('fs');
const path = require('path');

function validateDirectoryStructure(directoryPath, options = {}) {
  const {
    requiredFiles = [],
    requiredDirectories = [],
    generateEmptyFile = true,
    throwOnMissing = true
  } = options;

  if (!fs.existsSync(directoryPath)) {
    if (throwOnMissing) {
      throw new Error(`Base directory does not exist: ${directoryPath}`);
    }
    fs.mkdirSync(directoryPath, { recursive: true });
  }

  const missingFiles = [];
  const missingDirectories = [];

  // Validate directories
  for (const dir of requiredDirectories) {
    const fullPath = path.join(directoryPath, dir);
    if (!fs.existsSync(fullPath)) {
      if (throwOnMissing) {
        missingDirectories.push(dir);
      } else {
        fs.mkdirSync(fullPath, { recursive: true });
      }
    }
  }

  // Validate files
  for (const file of requiredFiles) {
    const fullPath = path.join(directoryPath, file);
    if (!fs.existsSync(fullPath)) {
      if (throwOnMissing) {
        missingFiles.push(file);
      } else if (generateEmptyFile) {
        fs.writeFileSync(fullPath, '', 'utf8');
      }
    }
  }

  if (throwOnMissing && (missingFiles.length > 0 || missingDirectories.length > 0)) {
    throw new Error(
      `Validation failed:\n` +
      `Missing files: ${missingFiles.join(', ')}\n` +
      `Missing directories: ${missingDirectories.join(', ')}`
    );
  }

  return {
    success: true,
    missingFiles,
    missingDirectories,
    basePath: directoryPath
  };
}

