    y: canvas.height / 2,
    size: 10,
    speed: 5,
    dx: 0,
    dy: 0
};

let keys = {
    ArrowUp: false,
    ArrowDown: false,
    ArrowLeft: false,
    ArrowRight: false
};

function updateParticle() {
    // Add random movement
    particle.dx += (Math.random() - 0.5) * 0.5;
    particle.dy += (Math.random() - 0.5) * 0.5;

    // Handle user input
    if (keys.ArrowUp) particle.dy -= 0.5;
    if (keys.ArrowDown) particle.dy += 0.5;
    if (keys.ArrowLeft) particle.dx -= 0.5;
    if (keys.ArrowRight) particle.dx += 0.5;

    // Apply friction
    particle.dx *= 0.98;
    particle.dy *= 0.98;

    // Update position
    particle.x += particle.dx;
    particle.y += particle.dy;

    // Keep particle within bounds
    if (particle.x < 0) particle.x = canvas.width;
    if (particle.x > canvas.width) particle.x = 0;
    if (particle.y < 0) particle.y = canvas.height;
    if (particle.y > canvas.height) particle.y = 0;
}

function drawParticle() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.beginPath();
    ctx.arc(particle.x, particle.y, particle.size, 0, Math.PI * 2);
    ctx.fillStyle = 'blue';
    ctx.fill();
    ctx.closePath();
}

function animate() {
    updateParticle();
    drawParticle();
    requestAnimationFrame(animate);
}

