function calculateTotalAfter2001(dataset, options) {
    var total = _.chain(dataset)
        .filter(function(item) {
            return parseInt(item.year) > 2001;
        })
        .reduce(function(memo, item) {
            return memo + parseFloat(item[options.fieldToSum]);
        }, 0)
        .value();

    $('#totalValue').html('Total: ' + total.toFixed(2));

    var years = _.chain(dataset)
        .filter(function(item) {
            return parseInt(item.year) > 2001;
        })
        .pluck('year')
        .uniq()
        .sort()
        .value();

    $('#years').html('Years included: ' + years.join(', '));

    return total;
}

const keyStore = new Map();

function generateUniqueId(key) {
    if (keyStore.has(key)) {
        return keyStore.get(key);
    }

    const randomPostfix = Math.random().toString(36).substring(2, 8);
    const uniqueSymbol = Symbol(`${key}_${randomPostfix}`);
    const identifier = {
        id: uniqueSymbol,
        key: key,
        timestamp: Date.now(),
        postfix: randomPostfix
    };

    keyStore.set(key, identifier);
    return identifier;
}

function getStoredIds() {
    return Array.from(keyStore.values());
}

function clearStore() {
    keyStore.clear();
}

function removeId(key) {
    return keyStore.delete(key);
}

function hasId(key) {
    return keyStore.has(key);
}

function animateElements(title, button, mines, callback) {
    const duration = Math.random() * 5000 + 5000;

    const titleTween = this.add.tween(title)
        .to({ angle: 360 }, duration, Phaser.Easing.Linear.None, true);

    const buttonTween = this.add.tween(button)
        .to({ angle: -360 }, duration, Phaser.Easing.Linear.None, true);

    const minesTween = this.add.tween(mines)
        .to({ angle: 720 }, duration, Phaser.Easing.Linear.None, true);

    minesTween.onComplete.add(() => {
        if (callback && typeof callback === 'function') {
            callback();
        }
    });
}

