    req.log.info({ res: res }, 'END');
});

server.get('/ping', (req, res, next) => {
    async.waterfall([
        (callback) => {
            _.attempt(() => {
                callback(null, {
                    status: 'success',
                    message: 'pong',
                    timestamp: new Date().toISOString()
                });
            });
        }
    ], (err, result) => {
        if (err) {
            logger.error(err);
            res.send(500, {
                status: 'error',
                message: 'Internal Server Error'
            });
            return next(err);
        }

        res.send(200, result);
        return next();
    });
});

