function escapeString(input, escapeMap, unescape = false) {
  const regexEscape = new RegExp(
    Object.keys(escapeMap).map(char => `\\${char}`).join('|'),
    'g'
  );

  const regexUnescape = new RegExp(
    Object.values(escapeMap).map(char => char.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')).join('|'),
    'g'
  );

  if (!unescape) {
    return input.replace(regexEscape, match => escapeMap[match]);
  }

  const unescapeMap = Object.fromEntries(
    Object.entries(escapeMap).map(([key, value]) => [value, key])
  );

  return input.replace(regexUnescape, match => unescapeMap[match]);
}
