function decodeWBXML(wbxml) {
    const ActiveSyncCodePages = {
        0: 'AirSync',
        1: 'Contacts',
        2: 'Email',
        3: 'Calendar',
        4: 'Move',
        5: 'ItemEstimate',
        6: 'FolderHierarchy',
        7: 'MeetingResponse',
        8: 'Tasks',
        9: 'Notes',
        10: 'Provision',
        11: 'Search',
        12: 'GAL',
        13: 'AirSyncBase',
        14: 'Settings',
        15: 'DocumentLibrary',
        16: 'ItemOperations'
    };

    const CodePageTokens = {
        AirSync: {
            5: 'Sync',
            6: 'Responses',
            7: 'Add',
            8: 'Change',
            9: 'Delete',
            10: 'Fetch',
            11: 'SyncKey',
            12: 'ClientId',
            13: 'ServerId',
            14: 'Status',
            15: 'Collection'
        },
        Contacts: {
            5: 'Anniversary',
            6: 'AssistantName',
            7: 'AssistantPhoneNumber',
            8: 'Birthday',
            9: 'Body',
            10: 'BusinessAddressCity',
            11: 'BusinessAddressCountry',
            12: 'BusinessAddressPostalCode',
            13: 'BusinessAddressState',
            14: 'BusinessAddressStreet',
            15: 'BusinessFaxNumber'
        }
    };

    let position = 0;
    const buffer = new Uint8Array(wbxml.length);
    for (let i = 0; i < wbxml.length; i++) {
        buffer[i] = wbxml.charCodeAt(i);
    }

    function readByte() {
        return buffer[position++];
    }

    function readString() {
        let result = '';
        let byte;
        while ((byte = readByte()) !== 0) {
            result += String.fromCharCode(byte);
        }
        return result;
    }

    function parseElement() {
        const byte = readByte();
        const hasContent = (byte & 0x40) !== 0;
        const token = byte & 0x3F;

        if (token === 0) {
            const str = readString();
            return hasContent ? { [str]: parseContent() } : str;
        }

        const codePage = ActiveSyncCodePages[currentCodePage];
        const tokenName = CodePageTokens[codePage]?.[token] || `unknown-${token}`;

        return hasContent ? { [tokenName]: parseContent() } : tokenName;
    }

    function parseContent() {
        const result = {};
        let elements = [];

        while (position < buffer.length) {
            const byte = buffer[position];

            if (byte === 0x01) { // Switch page
                position++;
                currentCodePage = readByte();
                continue;
            }

            if (byte === 0x15) { // End tag
                position++;
                break;
            }

            const element = parseElement();
            if (typeof element === 'object') {
                Object.assign(result, element);
            } else {
                elements.push(element);
            }
        }

        return elements.length ? elements : result;
    }

    let currentCodePage = 0;
    position = 0;

    // Skip WBXML header
    const version = readByte();
    const publicId = readByte();
    const charsetId = readByte();
    const stringTableLength = readByte();

    return parseContent();
}

