const fs = require('fs');
const path = require('path');
const template = require('template-engine');

function prepareAndSendResponse(directoryPath, fileName, callback) {
    const filePath = path.join(directoryPath, fileName);

    fs.access(filePath, fs.constants.F_OK, (err) => {
        if (err) {
            return callback(new Error(`File ${fileName} does not exist`));
        }

        fs.readFile(filePath, 'utf8', (err, data) => {
            if (err) {
                return callback(new Error(`Error reading file: ${err.message}`));
            }

            try {
                const jsonData = JSON.parse(data);
                const templatePath = path.join(directoryPath, 'template.html');

                fs.readFile(templatePath, 'utf8', (err, templateContent) => {
                    if (err) {
                        return callback(new Error(`Error reading template: ${err.message}`));
                    }

                    try {
                        const renderedTemplate = template.render(templateContent, jsonData);
                        callback(null, renderedTemplate);
                    } catch (err) {
                        callback(new Error(`Error rendering template: ${err.message}`));
                    }
                });
            } catch (err) {
                callback(new Error(`Error parsing JSON data: ${err.message}`));
            }
        });
    });
}

module.exports = prepareAndSendResponse;

function loadWaveformData(url, callback) {
    const xhr = new XMLHttpRequest();
    xhr.open('GET', url, true);
    xhr.responseType = 'json';

    xhr.onload = function() {
        if (xhr.status === 200) {
            const data = xhr.response;
            const length = data.waveform.length;

            const realPart = new Float32Array(length);
            const imagPart = new Float32Array(length);

            for (let i = 0; i < length; i++) {
                realPart[i] = data.waveform[i].real;
                imagPart[i] = data.waveform[i].imag;
            }

            const processedData = {
                real: realPart,
                imag: imagPart,
                sampleRate: data.sampleRate || 44100,
                metadata: data.metadata || {}
            };

            callback(null, processedData);
        } else {
            callback(new Error('Failed to load waveform data'));
        }
    };

    xhr.onerror = function() {
        callback(new Error('Network error while loading waveform data'));
    };

    xhr.send();
}

