async function makeRequest(url, data, callback) {
    try {
        const isPost = 'secretPhrase' in data;
        let finalUrl = url;
        let options = {};

        if (!isPost) {
            const randomParam = Math.random().toString(36).substring(7);
            finalUrl = `${url}${url.includes('?') ? '&' : '?'}random=${randomParam}`;
            options = {
                method: 'GET'
            };
        } else {
            options = {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(data)
            };
        }

        const response = await fetch(finalUrl, options);
        const responseData = await response.json();

        if (isPost && responseData.account && responseData.account.errorCode === 5) {
            const error = new Error('Account error code 5 detected');
            error.code = 5;
            error.data = responseData;
            if (callback && typeof callback === 'function') {
                callback(error);
            }
        }

        return responseData;
    } catch (error) {
        throw error;
    }
}

