class PackageBuilder {
    constructor(packageName, version, description) {
        this.packageName = packageName;
        this.version = version;
        this.description = description;
        this.debianDir = `${packageName}-${version}`;
    }

    createDebianStructure() {
        // Create directory structure
        const dirs = [
            `${this.debianDir}/DEBIAN`,
            `${this.debianDir}/usr/local/bin`,
            `${this.debianDir}/usr/share/doc/${this.packageName}`
        ];

        dirs.forEach(dir => {
            fs.mkdirSync(dir, { recursive: true });
        });

        // Create control file
        const controlContent = `Package: ${this.packageName}
Version: ${this.version}
Section: base
Priority: optional
Architecture: all
Depends: 
Maintainer: Package Maintainer <maintainer@example.com>
Description: ${this.description}
`;

        fs.writeFileSync(`${this.debianDir}/DEBIAN/control`, controlContent);
    }

    buildDebianPackage() {
        try {
            execSync(`dpkg-deb --build ${this.debianDir}`);
            console.log(`Debian package created: ${this.debianDir}.deb`);
            return true;
        } catch (error) {
            console.error('Error creating Debian package:', error.message);
            return false;
        }
    }

    createRpmSpec() {
        const specContent = `Name: ${this.packageName}
Version: ${this.version}
Release: 1
Summary: ${this.description}
License: MIT
BuildArch: noarch

%description
${this.description}

%files
`;

        fs.writeFileSync(`${this.packageName}.spec`, specContent);
    }

    buildRpmPackage() {
        try {
            // Check if rpmbuild is available
            execSync('which rpmbuild');

            // Create RPM build directory structure
            const rpmDirs = [
                'rpmbuild/BUILD',
                'rpmbuild/RPMS',
