function createParticleSystem(m) {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    document.body.appendChild(canvas);
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const particles = [];
    const fontSize = 100;

    ctx.font = `${fontSize}px Arial`;
    const textWidth = ctx.measureText(m).width;
    const textX = (canvas.width - textWidth) / 2;
    const textY = canvas.height / 2;

    ctx.fillStyle = 'black';
    ctx.fillText(m, textX, textY);

    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const pixels = imageData.data;

    for (let y = 0; y < canvas.height; y += 4) {
        for (let x = 0; x < canvas.width; x += 4) {
            const index = (y * canvas.width + x) * 4;
            if (pixels[index + 3] > 0) {
                particles.push({
                    x: x,
                    y: y,
                    originalX: x,
                    originalY: y,
                    vx: 0,
                    vy: 0
                });
            }
        }
    }

    function explode() {
        particles.forEach(p => {
            p.vx = (Math.random() - 0.5) * 20;
            p.vy = (Math.random() - 0.5) * 20;
        });
    }

    function reset() {
        particles.forEach(p => {
            p.x = p.originalX;
            p.y = p.originalY;
            p.vx = 0;
            p.vy = 0;
        });
    }

    function animate() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        particles.forEach(p => {
            p.x += p.vx;
            p.y += p.vy;

            p.vy += 0.1;

            ctx.fillStyle = 'black';
            ctx.fillRect(p.x, p.y, 2, 2);
        });

        requestAnimationFrame(animate);
    }

    animate();

    canvas.addEventListener('click', explode);
    document.addEventListener('keypress', reset);

    return {
        explode,
        reset,
        particles
    };
}

function shuffleSlides(slides) {
  const shuffled = [...slides];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const randomIndex = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[randomIndex]] = [shuffled[randomIndex], shuffled[i]];
  }
  return shuffled;
}

const evaluateFunctions = (() => {
  const memoCache = new Map();

  const memoKey = (fn, args) => {
    const fnString = fn.toString();
    const argsString = JSON.stringify(args);
    return `${fnString}-${argsString}`;
  };

  return (functionsList) => {
    const results = [];

    for (const { fn, args } of functionsList) {
      try {
        const key = memoKey(fn, args);

        if (memoCache.has(key)) {
          results.push(memoCache.get(key));
          continue;
        }

        const result = fn(...args);
        memoCache.set(key, result);
        results.push(result);
      } catch (error) {
        console.error(`Error executing function: ${error.message}`);
        results.push(null);
      }
    }

    return results;
  };
})();

