const fs = require('fs');

function getProjectPaths(projectPath, options = {}) {
  const {
    appDirName = 'app',
    indexFileName = 'index.js',
    configFileName = 'config.js',
    publicDirName = 'public',
    srcDirName = 'src'
  } = options;

  const resolvedPath = path.resolve(projectPath);
  const appPath = path.join(resolvedPath, appDirName);
  const srcPath = path.join(resolvedPath, srcDirName);
  const publicPath = path.join(resolvedPath, publicDirName);
  const indexFilePath = path.join(appPath, indexFileName);
  const configFilePath = path.join(resolvedPath, configFileName);

  const paths = {
    root: resolvedPath,
    app: appPath,
    src: srcPath,
    public: publicPath,
    index: indexFilePath,
    config: configFilePath,
    exists: {
      root: fs.existsSync(resolvedPath),
      app: fs.existsSync(appPath),
      src: fs.existsSync(srcPath),
      public: fs.existsSync(publicPath),
      index: fs.existsSync(indexFilePath),
      config: fs.existsSync(configFilePath)
    },
    relative: {
      app: path.relative(resolvedPath, appPath),
      src: path.relative(resolvedPath, srcPath),
      public: path.relative(resolvedPath, publicPath),
      index: path.relative(resolvedPath, indexFilePath),
      config: path.relative(resolvedPath, configFilePath)
    }
  };

  return paths;
}

module.exports = getProjectPaths;

function modifyJsonObjects(jsonData, targetObject) {
    if (!jsonData || !jsonData.length || !targetObject) {
        return jsonData;
    }

    return jsonData.map(obj => {
        const newPath = `${targetObject.path}/${obj.path}`.replace(/\/+/g, '/');
        return {
            ...obj,
            path: newPath,
            sort: `${targetObject.sort}-${obj.sort}`
        };
