}

function generateUniqueId(length, charSet, existingIds) {
    const chars = charSet || 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    let id;
    let isUnique = false;

    while (!isUnique) {
        id = '';
        for (let i = 0; i < length; i++) {
            const randomIndex = Math.floor(Math.random() * chars.length);
            id += chars[randomIndex];
        }

        isUnique = !existingIds.includes(id);
    }

    return id;
}

import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls';

let scene, camera, renderer, controls;

function init() {
    scene = new THREE.Scene();
    camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
    renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    document.body.appendChild(renderer.domElement);

    // Lighting
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.5);
    scene.add(ambientLight);
    const pointLight = new THREE.PointLight(0xffffff, 0.8);
    pointLight.position.set(5, 5, 5);
    scene.add(pointLight);

    // Controls
    controls = new OrbitControls(camera, renderer.domElement);
    camera.position.z = 5;

    createHuman();
    animate();
}

function createHuman() {
    // Head
    const headGeometry = new THREE.SphereGeometry(0.4, 32, 32);
    const headMaterial = new THREE.MeshPhongMaterial({ color: 0xf1c27d });
    const head = new THREE.Mesh(headGeometry, headMaterial);
    head.position.y = 1.6;

    // Body
    const bodyGeometry = new THREE.CylinderGeometry(0.5, 0.5, 1.5, 32);
    const bodyTexture = new THREE.TextureLoader().load('body_texture.jpg');
    const bodyMaterial = new THREE.MeshPhongMaterial({ 
        map: bodyTexture,
        color: 0xf1c27d 
    });
    const body = new THREE.Mesh(bodyGeometry, bodyMaterial);
    body.position.y = 0.5;

    // Arms
    const armGeometry = new THREE.CylinderGeometry(0.15, 0.15, 1, 32);
    const armMaterial = new THREE.MeshPhongMaterial({ color: 0xf1c27d });

    const leftArm = new THREE.Mesh(armGeometry, armMaterial);
    leftArm.position.set(-0.7, 0.8, 0);
    leftArm.rotation.z = Math.PI / 3;

    const rightArm = new THREE.Mesh(armGeometry, armMaterial);
    rightArm.position.set(0.7, 0.8, 0);
    rightArm.rotation.z = -Math.PI / 3;

    // Legs
    const legGeometry = new THREE.CylinderGeometry(0.2, 0.2, 1.2, 32);
    const legMaterial = new THREE.MeshPhongMaterial({ color: 0xf1c27d });

    const leftLeg = new THREE.Mesh(legGeometry, legMaterial);
    leftLeg.position.set(-0.3, -0.4, 0);

    const rightLeg = new THREE.Mesh(legGeometry, legMaterial);
    rightLeg.position.set(0.3, -0.4, 0);

    // Group all parts
    const human = new THREE.Group();
    human.add(head);
    human.add(body);
    human.add(leftArm);
    human.add(rightArm);
    human.add(leftLeg);
    human.add(rightLeg);

    scene.add(human);
}

function animate() {
    requestAnimationFrame(animate);
    controls.update();
    renderer.render(scene, camera);
}

function onWindowResize() {
    camera.aspect = window.innerWidth / window.innerHeight;
    camera.updateProjectionMatrix();
    renderer.setSize(window.innerWidth, window.innerHeight);
}

window.addEventListener('resize', onWindowResize, false);

