function createTimeZoneRegex(pattern, timeZone) {
  try {
    if (!pattern || !timeZone) {
      throw new Error('Invalid input parameters');
    }

    const timeZonePatterns = {
      'named': /^[A-Z][a-z]+(?:\s[A-Z][a-z]+)*\sTime$/,
      'region': /^[A-Z][a-z]+\/[A-Z][a-z_]+$/
    };

    if (!timeZonePatterns.named.test(pattern) && !timeZonePatterns.region.test(pattern)) {
      throw new Error('Invalid time zone pattern format');
    }

    const escapedTimeZone = timeZone.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const regexPattern = new RegExp(`^${escapedTimeZone}$`);

    return regexPattern;
  } catch (error) {
    return {
      error: true,
      message: error.message
    };
  }
}

function createAndValidateElement(tagName, content, pattern) {
    const element = document.createElement(tagName);
    element.innerHTML = content;
    const regex = new RegExp(pattern);
    return {
        element: element,
        isValid: regex.test(element.innerHTML),
        content: element.innerHTML
    };
}

function extractNames(text) {
  const namePatterns = [
    /(?:Mr\.|Mrs\.|Ms\.|Dr\.|Prof\.) [A-Z][a-z]+ [A-Z][a-z]+/g,
    /[A-Z][a-z]+ [A-Z][a-z]+/g,
    /[A-Z]\. [A-Z][a-z]+/g,
    /[A-Z][a-z]+ [A-Z]\. [A-Z][a-z]+/g
  ];

  let names = new Set();
  let references = {};

  namePatterns.forEach(pattern => {
    let matches = text.match(pattern);
    if (matches) {
      matches.forEach(match => {
        names.add(match);
        if (!references[match]) {
          references[match] = [];
        }
        let index = text.indexOf(match);
        while (index !== -1) {
          references[match].push({
            position: index,
            context: text.substr(Math.max(0, index - 30), 60)
          });
          index = text.indexOf(match, index + 1);
        }
      });
    }
  });

  return {
    uniqueNames: Array.from(names),
    references: references
  };
}

function formatResults(results) {
  let output = "Found Names:\n";
  results.uniqueNames.forEach(name => {
    output += `\n${name}:\n`;
    results.references[name].forEach(ref => {
      output += `  Position: ${ref.position}\n`;
      output += `  Context: ...${ref.context}...\n`;
    });
  });
  return output;
}

function processText(text) {
  const results = extractNames(text);
  return formatResults(results);
}

module.exports = {
  extractNames,
  formatResults,
  processText
};

