const CookieManager = {
    setCookie: function(name, value, days = 7, path = '/') {
        const expires = new Date(Date.now() + days * 864e5).toUTCString();
        document.cookie = `${encodeURIComponent(name)}=${encodeURIComponent(value)}; expires=${expires}; path=${path}`;
    },

    getCookie: function(name) {
        const nameEQ = encodeURIComponent(name) + '=';
        const cookies = document.cookie.split(';');

        for (let cookie of cookies) {
            cookie = cookie.trim();
            if (cookie.indexOf(nameEQ) === 0) {
                return decodeURIComponent(cookie.substring(nameEQ.length));
            }
        }
        return null;
    },

    deleteCookie: function(name, path = '/') {
        document.cookie = `${encodeURIComponent(name)}=; expires=Thu, 01 Jan 1970 00:00:00 GMT; path=${path}`;
    },

    getAllCookies: function() {
        const cookies = {};
        const cookieList = document.cookie.split(';');

        for (let cookie of cookieList) {
            if (cookie.trim()) {
                const [name, value] = cookie.trim().split('=');
                cookies[decodeURIComponent(name)] = decodeURIComponent(value);
            }
        }
        return cookies;
    },

    clearAllCookies: function(path = '/') {
        const cookies = document.cookie.split(';');

        for (let cookie of cookies) {
            const name = cookie.split('=')[0].trim();
            this.deleteCookie(name, path);
        }
    },

    hasCookie: function(name) {
        return this.getCookie(name) !== null;
    },

    updateCookie: function(name, value, days = 7, path = '/') {
        this.setCookie(name, value, days, path);
    }
};

