function fixEvent(event, element) {
    event = event || window.event;

    if (!event.namespace) {
        event.namespace = '';
    }

    if (!event.nsRegex) {
        event.nsRegex = /.*/;
    }

    if (!event.target) {
        event.target = event.srcElement || element;
    }

    if (!event.relatedTarget && event.fromElement) {
        event.relatedTarget = event.fromElement === event.target ? event.toElement : event.fromElement;
    }

    if (event.pageX == null && event.clientX != null) {
        var eventDocument = event.target.ownerDocument || document;
        var doc = eventDocument.documentElement;
        var body = eventDocument.body;

        event.pageX = event.clientX + (doc && doc.scrollLeft || body && body.scrollLeft || 0) - (doc && doc.clientLeft || body && body.clientLeft || 0);
        event.pageY = event.clientY + (doc && doc.scrollTop || body && body.scrollTop || 0) - (doc && doc.clientTop || body && body.clientTop || 0);
    }

    if (event.which == null) {
        event.which = event.charCode != null ? event.charCode : event.keyCode;
    }

    if (!event.metaKey && event.ctrlKey) {
        event.metaKey = event.ctrlKey;
    }

    if (!event.preventDefault) {
        event.preventDefault = function() {
            event.returnValue = false;
        };
    }

    if (!event.stopPropagation) {
        event.stopPropagation = function() {
            event.cancelBubble = true;
        };
    }

    return event;
}

const generateUniqueId = (() => {
  const cache = new Map();
  let counter = 0;

  const generateRandomPostfix = () => {
    return Math.random().toString(36).substring(2, 8);
  };

  return (key) => {
    if (cache.has(key)) {
      return cache.get(key);
    }

    counter++;
    const id = `${key}_${counter}_${generateRandomPostfix()}`;
    cache.set(key, id);
    return id;
  };
})();

const Promise = require('bluebird');
const FileUploader = require('file-uploader');
const Logger = require('logger');
const axios = require('axios');

async function uploadFileFromUrl(sourceUrl) {
    const logger = new Logger('FileUploadService');
    const uploader = new FileUploader({
        maxFileSize: 50 * 1024 * 1024, // 50MB
        allowedFileTypes: ['image/*', 'application/pdf', 'text/*']
    });

    try {
        // Download the file from the URL
        const response = await axios({
            method: 'GET',
            url: sourceUrl,
            responseType: 'stream'
        });

        const fileName = sourceUrl.split('/').pop();
        const fileType = response.headers['content-type'];

        // Create a temporary file object
        const fileObject = {
            name: fileName,
            type: fileType,
            data: response.data
        };

        // Upload the file
        const uploadResult = await Promise.try(() => {
            return uploader.upload(fileObject);
        }).catch(error => {
            logger.error(`Failed to upload file from URL: ${sourceUrl}`, error);
            throw new Error('File upload failed');
        });

        logger.info(`Successfully uploaded file from URL: ${sourceUrl}`);
        return uploadResult.url;

    } catch (error) {
        logger.error(`Error processing file from URL: ${sourceUrl}`, error);
        throw error;
    }
}

module.exports = uploadFileFromUrl;

function getTimeBasedGreeting() {
    const greetings = {
        morning: [
            "Rise and shine!",
            "Good morning!",
            "Have a great morning!",
            "Top of the morning to you!",
            "Morning sunshine!"
        ],
        afternoon: [
            "Good afternoon!",
            "Having a good day?",
            "Hope your day is going well!",
            "Afternoon greetings!",
            "Hello there!"
        ],
        evening: [
            "Good evening!",
            "Hope you had a great day!",
            "Evening greetings!",
            "Winding down for the day?",
            "Pleasant evening!"
        ],
        default: [
            "Hello!",
            "Hi there!",
            "Greetings!",
            "Welcome!",
            "Nice to see you!"
        ]
    };

    const currentHour = new Date().getHours();
    let timeOfDay;

    if (currentHour >= 5 && currentHour < 12) {
        timeOfDay = 'morning';
    } else if (currentHour >= 12 && currentHour < 17) {
        timeOfDay = 'afternoon';
    } else if (currentHour >= 17 && currentHour < 22) {
        timeOfDay = 'evening';
    } else {
        timeOfDay = 'default';
    }

    const messages = greetings[timeOfDay];
    const randomIndex = Math.floor(Math.random() * messages.length);

    return messages[randomIndex];
}

function updateNavigationMenu() {
    const currentUrl = window.location.pathname;
    const menuItems = document.querySelectorAll('.nav-item');

    // Remove active class from all items
    menuItems.forEach(item => {
        item.classList.remove('active');
    });

    // Add active class to matching items
    menuItems.forEach(item => {
        const link = item.querySelector('a');
        if (!link) return;

        const href = link.getAttribute('href');
        if (!href) return;

        // Convert both URLs to comparable formats
        const itemPath = new URL(href, window.location.origin).pathname;

        // Check if current URL starts with menu item URL (for parent items)
        if (currentUrl === itemPath || currentUrl.startsWith(itemPath + '/')) {
            item.classList.add('active');

            // Handle nested menus by marking parent items as active
            let parent = item.parentElement.closest('.nav-item');
            while (parent) {
                parent.classList.add('active');
                parent = parent.parentElement.closest('.nav-item');
            }
        }
    });
}

