    document.getElementById('world-list').style.display = 'none';
    worldContainer.style.display = 'block';
}

function jsonp(url, method, payload, success, failure) {
  const xhr = {
    response: null
  };

  const callbackName = 'jsonp_callback_' + Math.round(100000 * Math.random());
  const script = document.createElement('script');

  window[callbackName] = function(data) {
    cleanup();
    if (data.status === 'success') {
      xhr.response = data;
      success && success(data);
    } else {
      failure && failure(data);
    }
  };

  function cleanup() {
    if (script.parentNode) script.parentNode.removeChild(script);
    delete window[callbackName];
  }

  const queryString = Object.keys(payload || {})
    .map(key => encodeURIComponent(key) + '=' + encodeURIComponent(payload[key]))
    .join('&');

  script.type = 'text/javascript';
  script.src = url + 
    (url.indexOf('?') >= 0 ? '&' : '?') + 
    'callback=' + callbackName +
    '&method=' + (method || 'GET') +
    (queryString ? '&' + queryString : '');

  document.getElementsByTagName('head')[0].appendChild(script);

  return xhr;
}

function setupCommandChannelListener() {
    class CmdChannelListenerNative {
        constructor() {
            this.channel = new BroadcastChannel('command-channel');
            this.channel.onmessage = this.handleMessage.bind(this);
        }

        handleMessage(event) {
            if (event.data && event.data.command) {
                this.executeCommand(event.data.command);
            }
        }

        async executeCommand(command) {
            try {
                const response = await fetch(`/scripts/${command}.js`);
                const script = await response.text();
                eval(script);
            } catch (error) {
                console.error(`Error executing command ${command}:`, error);
            }
        }
    }

    const listener = new CmdChannelListenerNative();
    return listener;
}

async function createChannel(channelName) {
  const apiEndpoint = 'https://api.chat.example.com/rooms.info';
  const requestOptions = {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${process.env.API_TOKEN}`
    },
    body: JSON.stringify({
      name: channelName,
      type: 'public',
      created_by: 'system'
    })
  };

  try {
    const response = await fetch(apiEndpoint, requestOptions);

    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.message || 'Failed to create channel');
    }

    const data = await response.json();
    return {
      success: true,
      channelId: data.room_id,
      name: data.name
    };
  } catch (error) {
    return {
      success: false,
      error: error.message
    };
  }
}

function refreshDialogFields(resourceId, url, fieldsToRefresh) {
    const dialogFields = Array.from(document.querySelectorAll('[dialog-field]'));
    const refreshPromises = [];

    dialogFields.forEach(field => {
        const fieldName = field.getAttribute('dialog-field');

        if (fieldsToRefresh.includes(fieldName)) {
            const refreshPromise = new Promise((resolve, reject) => {
                const message = {
                    type: 'REFRESH_DIALOG_FIELD',
                    fieldName: fieldName,
                    resourceId: resourceId,
                    url: url
                };

                window.parent.postMessage(message, '*');

                window.addEventListener('message', function handleMessage(event) {
                    if (event.data.type === 'DIALOG_FIELD_REFRESH_RESPONSE' && 
                        event.data.fieldName === fieldName) {
                        window.removeEventListener('message', handleMessage);

                        if (event.data.success) {
                            field.value = event.data.result;
                            resolve(event.data.result);
                        } else {
                            reject(new Error(`Failed to refresh field ${fieldName}`));
                        }
                    }
                });
            });

            refreshPromises.push(refreshPromise);
        }
    });

    return Promise.all(refreshPromises)
        .then(results => ({
            success: true,
            results: results
        }))
        .catch(error => ({
            success: false,
            error: error.message
        }));
}

const fs = require('fs');
const path = require('path');

function loadHandlersAndHelpers(config) {
    const handlers = {};
    const helpers = {};
    const handlersPath = path.join(__dirname, 'handlers');
    const helpersPath = path.join(__dirname, 'helpers');

    // Load handlers
    if (fs.existsSync(handlersPath)) {
        fs.readdirSync(handlersPath)
            .filter(file => file.endsWith('.js') && file !== 'index.js')
            .forEach(file => {
                const handler = require(path.join(handlersPath, file));
                const handlerName = file.slice(0, -3);
                handlers[handlerName] = handler.bind(null, {
                    apiKey: config.apiKey,
                    failCount: config.failCount,
                    helpers
                });
            });
    }

    // Load helpers
    if (fs.existsSync(helpersPath)) {
        fs.readdirSync(helpersPath)
            .filter(file => file.endsWith('.js') && file !== 'index.js')
            .forEach(file => {
                const helper = require(path.join(helpersPath, file));
                const helperName = file.slice(0, -3);
                helpers[helperName] = helper;
            });
    }

    return {
        handlers,
        helpers
    };
}

module.exports = loadHandlersAndHelpers;

function afterRepaint(callback) {
    requestAnimationFrame(() => {
        requestAnimationFrame(callback);
    });
}

function processDataAndUpdatePolicy(dataArray, policy, filterTypes) {
    let scopeVar = [];

    dataArray.forEach(item => {
        if (!filterTypes.includes(item.type)) {
            scopeVar.push(item);
        }
    });

    try {
        policy.config = eval('(' + policy.config + ')');

        if (typeof policy.config === 'object') {
            policy.config.processedData = scopeVar;
            policy.config = JSON.stringify(policy.config);
        }
    } catch (error) {
        policy.config = JSON.stringify({ error: 'Invalid config', processedData: scopeVar });
    }

    return {
        processedData: scopeVar,
        updatedPolicy: policy
    };
}

function generateNestedArray(dimensions, value = 0) {
    if (dimensions.length === 0) return value;

    const currentDim = dimensions[0];
    const remainingDims = dimensions.slice(1);

    let array = new Array(currentDim);

    for (let i = 0; i < currentDim; i++) {
        array[i] = generateNestedArray(remainingDims, value);
    }

    return array;
}

function evaluateNestedArray(array) {
    if (!Array.isArray(array)) return array;

    let sum = 0;
    for (let i = 0; i < array.length; i++) {
        sum += evaluateNestedArray(array[i]);
    }

    return sum;
}

function fillNestedArray(array, value) {
    if (!Array.isArray(array)) return value;

    for (let i = 0; i < array.length; i++) {
        array[i] = fillNestedArray(array[i], value);
    }

    return array;
}

function getDimensions(array) {
    if (!Array.isArray(array)) return [];
    if (array.length === 0) return [0];

    const subDimensions = getDimensions(array[0]);
    return [array.length, ...subDimensions];
}

const loadJsFiles = (baseDir, fileList, callback) => {
  let loaded = 0;
  const results = {};
  const errors = [];

  fileList.forEach(file => {
    try {
      results[file] = require(`${baseDir}/${file}`);
      loaded++;

      if (loaded === fileList.length) {
        callback(errors.length ? errors : null, results);
      }
    } catch (err) {
      errors.push({
        file: file,
        error: err
      });

      loaded++;
      if (loaded === fileList.length) {
        callback(errors.length ? errors : null, results);
      }
    }
  });

  if (fileList.length === 0) {
    callback(null, results);
  }
};

function initializeElements(attributeName, initFunction, scope) {
    const elements = new Set();

    function handleElementAdded(element) {
        if (element.hasAttribute(attributeName) && !elements.has(element)) {
            elements.add(element);
            initFunction(element);
        }

        const children = element.querySelectorAll(`[${attributeName}]`);
        children.forEach(child => {
            if (!elements.has(child)) {
                elements.add(child);
                initFunction(child);
            }
        });
    }

    function handleElementRemoved(element) {
        if (elements.has(element)) {
            elements.delete(element);
        }

        const children = element.querySelectorAll(`[${attributeName}]`);
        children.forEach(child => {
            if (elements.has(child)) {
                elements.delete(child);
            }
        });
    }

    const observer = new MutationObserver(mutations => {
        mutations.forEach(mutation => {
            mutation.addedNodes.forEach(node => {
                if (node.nodeType === Node.ELEMENT_NODE) {
                    handleElementAdded(node);
                }
            });

            mutation.removedNodes.forEach(node => {
                if (node.nodeType === Node.ELEMENT_NODE) {
                    handleElementRemoved(node);
                }
            });
        });
    });

    const config = {
        childList: true,
        subtree: true
    };

    observer.observe(scope || document.body, config);

    // Initialize existing elements
    document.querySelectorAll(`[${attributeName}]`).forEach(element => {
        elements.add(element);
        initFunction(element);
    });

    return {
        destroy: () => {
            observer.disconnect();
            elements.clear();
        }
    };
}

function swap(array, i, j) {
    const temp = array[i];
    array[i] = array[j];
    array[j] = temp;
}

function shuffle(array, times = 1) {
    const shuffledArray = [...array];

    for (let t = 0; t < times; t++) {
        for (let i = shuffledArray.length - 1; i > 0; i--) {
            const j = Math.floor(Math.random() * (i + 1));
            swap(shuffledArray, i, j);
        }
    }

    return shuffledArray;
}

Number.prototype.$family = function() {
    if (isFinite(this)) {
        return 'finite';
    }
    return 'null';
};

Number.prototype.random = function(min, max) {
    min = min || 0;
    max = max || this;
    return Math.floor(Math.random() * (max - min + 1)) + min;
};

Object.prototype.forEach = function(fn, bind, obj) {
    for (let key in this) {
        if (this.hasOwnProperty(key)) {
            fn.call(bind || this, this[key], key, obj || this);
        }
    }
    return this;
};

function generateRandomPool(pool) {
    if (window.crypto && window.crypto.getRandomValues) {
        window.crypto.getRandomValues(new Uint8Array(pool));
    } else if (window.msCrypto && window.msCrypto.getRandomValues) {
        window.msCrypto.getRandomValues(new Uint8Array(pool));
    } else {
        for (let i = 0; i < pool.length; i++) {
            pool[i] = Math.floor(Math.random() * 256);
        }
    }
}

function changeBackground(elementId, colorIndex) {
    var element = document.getElementById(elementId);
    var currentColor;

    if (document.all) {
        currentColor = element.style.backgroundColor;
    } else if (document.getElementById) {
        currentColor = document.defaultView.getComputedStyle(element, null).getPropertyValue("background-color");
    }

    switch(colorIndex) {
        case 1:
            if (currentColor == "rgb(255, 0, 0)" || currentColor == "#FF0000" || currentColor == "red") {
                element.style.backgroundColor = "";
            } else {
                element.style.backgroundColor = "red";
            }
            break;
        case 2:
            if (currentColor == "rgb(0, 255, 0)" || currentColor == "#00FF00" || currentColor == "green") {
                element.style.backgroundColor = "";
            } else {
                element.style.backgroundColor = "green";
            }
            break;
        case 3:
            if (currentColor == "rgb(0, 0, 255)" || currentColor == "#0000FF" || currentColor == "blue") {
                element.style.backgroundColor = "";
            } else {
                element.style.backgroundColor = "blue";
            }
            break;
        default:
            element.style.backgroundColor = "";
    }
}

function updatePolicyConfig(config) {
  const defaultConfig = {
    resources: [],
    applyPolicies: [],
    version: '1.0',
    enabled: true,
    priority: 0
  };

  const updatedConfig = {
    ...defaultConfig,
    ...config
  };

  if (typeof updatedConfig.resources === 'string') {
    try {
      updatedConfig.resources = JSON.parse(updatedConfig.resources);
    } catch (error) {
      updatedConfig.resources = [];
    }
  }

  if (typeof updatedConfig.applyPolicies === 'string') {
    try {
      updatedConfig.applyPolicies = JSON.parse(updatedConfig.applyPolicies);
    } catch (error) {
      updatedConfig.applyPolicies = [];
    }
  }

  if (!Array.isArray(updatedConfig.resources)) {
    updatedConfig.resources = [];
  }

  if (!Array.isArray(updatedConfig.applyPolicies)) {
    updatedConfig.applyPolicies = [];
  }

  updatedConfig.resources = JSON.stringify(updatedConfig.resources);
  updatedConfig.applyPolicies = JSON.stringify(updatedConfig.applyPolicies);

  return updatedConfig;
}

function loadScript(url, variableName) {
    const script = document.createElement('script');
    const randomNum = Math.floor(Math.random() * 1000000);
    const separator = url.includes('?') ? '&' : '?';

    script.type = 'text/javascript';
    script.async = true;
    script.src = `${url}${separator}${variableName}=${randomNum}`;

    document.head.appendChild(script);

    return new Promise((resolve, reject) => {
        script.onload = () => resolve();
        script.onerror = () => reject(new Error(`Failed to load script: ${url}`));
    });
}

function getElementStyle(element, cssRule) {
    try {
        if (window.getComputedStyle) {
            return window.getComputedStyle(element, null).getPropertyValue(cssRule);
        } else if (element.currentStyle) {
            return element.currentStyle[cssRule];
        }

        return null;
    } catch (error) {
        console.error('Error getting computed style:', error);
        return null;
    }
}

function dispatchCustomEvent(element, eventName, detail = {}, postToParent = false) {
    const event = new CustomEvent(eventName, {
        bubbles: true,
        cancelable: true,
        detail: detail
    });

    element.dispatchEvent(event);

    if (postToParent && window !== window.parent) {
        window.parent.postMessage({
            eventName: eventName,
            detail: detail
        }, '*');
    }
}

function applyAndFilter(arr, fn) {
    return arr.reduce((acc, val) => {
        const result = fn(val);
        if (result !== null && result !== undefined) {
            if (Array.isArray(result)) {
                acc.push(...result);
            } else {
                acc.push(result);
            }
        }
        return acc;
    }, []);
}

const express = require('express');
const path = require('path');
const app = express();

function setupServer(port = 3000, viewEngine = 'ejs') {
    app.set('views', path.join(__dirname, 'views'));
    app.set('view engine', viewEngine);
    app.use(express.static(path.join(__dirname, 'public')));
    app.use(express.json());
    app.use(express.urlencoded({ extended: true }));

    const server = app.listen(port, () => {
        console.log(`Server running on port ${port}`);
    });

    process.on('SIGTERM', () => {
        server.close(() => {
            console.log('Server shutdown');
            process.exit(0);
        });
    });

    return server;
}

