function generateUUID() {
    let dt = new Date().getTime();
    const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        const r = (dt + Math.random()*16)%16 | 0;
        dt = Math.floor(dt/16);
        return (c=='x' ? r :(r&0x3|0x8)).toString(16);
    });
    return uuid;
}

function reloadCommand(command) {
    const commandName = command.toLowerCase();
    const cmd = client.commands.get(commandName)
        || client.commands.find(c => c.aliases && c.aliases.includes(commandName));

    if (!cmd) {
        return false;
    }

    // Delete cached command from require cache
    delete require.cache[require.resolve(`./commands/${commandName}.js`)];

    // Remove old command and its aliases
    client.commands.delete(commandName);
    if (cmd.aliases) {
        cmd.aliases.forEach(alias => client.commands.delete(alias));
    }

    try {
        // Load new command
        const newCommand = require(`./commands/${commandName}.js`);

        // Set new command
        client.commands.set(newCommand.name, newCommand);

        // Set new aliases
        if (newCommand.aliases) {
            newCommand.aliases.forEach(alias => {
                client.commands.set(alias, newCommand);
            });
        }

        return true;
    } catch (error) {
        console.error(error);
        return false;
    }
}

/** Used to lookup built-in constructors */
var ctorByClass = {};

/** Used to map method names to their aliases */
var methodNames = {
  'forEach': ['each'],
  'map': ['collect'],
  'reduce': ['foldl', 'inject'],
  'reduceRight': ['foldr'],
  'filter': ['select'],
  'find': ['detect'],
  'includes': ['contains', 'include'],
  'some': ['any'],
  'every': ['all']
};

/** Used to identify object classifications */
var objectTypes = {
  'arguments': 'Arguments',
  'array': 'Array',
  'boolean': 'Boolean',
  'date': 'Date',
  'function': 'Function',
  'math': 'Math',
  'number': 'Number',
  'object': 'Object',
  'regexp': 'RegExp',
  'string': 'String'
};

for (var className in objectTypes) {
  var type = objectTypes[className];
  ctorByClass['[object ' + type + ']'] = global[type];
}

function defineAliases(object) {
  for (var methodName in methodNames) {
    var aliases = methodNames[methodName];
    var method = object[methodName];

    for (var i = 0; i < aliases.length; i++) {
      object[aliases[i]] = method;
    }
  }
  return object;
}

