function printDependencyTree(tree, dependencyNames, maxLines = 100, depth = 0, linesPrinted = { count: 0 }) {
    if (!tree || linesPrinted.count >= maxLines) {
        if (linesPrinted.count === maxLines) {
            console.log("... more dependencies not shown");
            linesPrinted.count++;
        }
        return;
    }

    for (const [dependency, children] of Object.entries(tree)) {
        if (linesPrinted.count >= maxLines) {
            break;
        }

        if (dependencyNames.includes(dependency)) {
            console.log(`${' '.repeat(depth * 2)}${dependency}`);
            linesPrinted.count++;

            if (children && typeof children === 'object') {
                printDependencyTree(children, dependencyNames, maxLines, depth + 1, linesPrinted);
            }
        }
    }
}

function shuffleArray(array) {
    let currentIndex = array.length;
    let temporaryValue, randomIndex;

    while (currentIndex !== 0) {
        randomIndex = Math.floor(Math.random() * currentIndex);
        currentIndex--;

        temporaryValue = array[currentIndex];
        array[currentIndex] = array[randomIndex];
        array[randomIndex] = temporaryValue;
    }

    return array;
}

class LiveStreamSimulator {
    constructor() {
        this.activeKeys = new Set();
        this.startCleanupInterval();
    }

    generateKey() {
        const key = Math.random().toString(36).substring(2, 15);
        return key;
    }

    addKey(key) {
        if (this.activeKeys.has(key)) {
            this.activeKeys.delete(key);
            return false;
        } else {
            this.activeKeys.add(key);
            return true;
        }
    }

    removeRandomKey() {
        if (this.activeKeys.size === 0) return null;
        const keys = Array.from(this.activeKeys);
        const randomIndex = Math.floor(Math.random() * keys.length);
        const keyToRemove = keys[randomIndex];
        this.activeKeys.delete(keyToRemove);
        return keyToRemove;
    }

    startCleanupInterval() {
        setInterval(() => {
            const removedKey = this.removeRandomKey();
            if (removedKey) {
                console.log(`Removed key: ${removedKey}`);
            }
        }, 5000);
    }

    getActiveKeys() {
        return Array.from(this.activeKeys);
    }

    simulateStream() {
        const key = this.generateKey();
        const added = this.addKey(key);
        console.log(`Key ${key} ${added ? 'added' : 'removed'}`);
        console.log('Active keys:', this.getActiveKeys());
    }
}

const simulator = new LiveStreamSimulator();
setInterval(() => {
    simulator.simulateStream();
}, 2000);

