function filterBadAirQuality(deviceId, command, controllers, configuration) {
    const maxLevel = configuration.maxLevel || 100;
    const filter = configuration.filter || ((data) => data);

    if (!controllers || !controllers.length) {
        return [];
    }

    return controllers
        .filter(controller => controller.deviceId === deviceId)
        .map(controller => {
            const data = command(controller);
            if (!data || !data.airQuality) {
                return null;
            }
            return {
                deviceId: controller.deviceId,
                airQuality: data.airQuality,
                timestamp: data.timestamp,
                location: controller.location
            };
        })
        .filter(data => data !== null)
        .filter(data => data.airQuality > maxLevel)
        .map(filter);
}

function startIframe(iframe) {
    const iframeSrc = iframe.getAttribute('src');
    const targetOrigin = '*';

    if (iframeSrc.includes('youtube')) {
        iframe.contentWindow.postMessage({
            'event': 'command',
            'func': 'playVideo',
            'args': []
        }, targetOrigin);
    } else if (iframeSrc.includes('vimeo')) {
        iframe.contentWindow.postMessage({
            'method': 'play'
        }, targetOrigin);
    } else {
        iframe.contentWindow.postMessage({
            'event': 'slide',
            'value': 'start'
        }, targetOrigin);
    }
}

const util = require('util');
const debug = util.debuglog('cache-tags');

function listDocumentCacheTags(configPath) {
    try {
        const config = require(configPath);
        const cache = config.cache || {};
        const tags = new Set();

        if (!cache.documents) {
            debug('No documents found in cache configuration');
            return [];
        }

        Object.values(cache.documents).forEach(doc => {
            if (doc.tags && Array.isArray(doc.tags)) {
                doc.tags.forEach(tag => tags.add(tag));
            }
        });

        debug('Found %d unique tags', tags.size);
        return Array.from(tags);
    } catch (error) {
        debug('Error loading configuration: %O', error);
        throw new Error(`Failed to load cache configuration: ${error.message}`);
    }
}

module.exports = listDocumentCacheTags;

const gulp = require('gulp');
const sass = require('gulp-sass')(require('sass'));
const typescript = require('gulp-typescript');
const concat = require('gulp-concat');
const uglify = require('gulp-uglify');
const cleanCSS = require('gulp-clean-css');
const htmlmin = require('gulp-htmlmin');
const del = require('del');
const browserSync = require('browser-sync').create();

// Configuration object
const config = {
    paths: {
        src: {
            base: 'src',
            sass: 'src/styles/**/*.scss',
            typescript: 'src/scripts/**/*.ts',
            html: 'src/**/*.html'
        },
        dist: {
            base: 'dist',
            styles: 'dist/css',
            scripts: 'dist/js',
            html: 'dist'
        }
    },
    fileNames: {
        cssBundle: 'styles.min.css',
        jsBundle: 'scripts.min.js'
    }
};

// Clean dist directory
function clean() {
    return del([config.paths.dist.base]);
}

// Process SASS files
function styles() {
    return gulp.src(config.paths.src.sass)
        .pipe(sass().on('error', sass.logError))
        .pipe(concat(config.fileNames.cssBundle))
        .pipe(cleanCSS())
        .pipe(gulp.dest(config.paths.dist.styles))
        .pipe(browserSync.stream());
}

// Process TypeScript files
function scripts() {
    const tsProject = typescript.createProject('tsconfig.json');
    return gulp.src(config.paths.src.typescript)
        .pipe(tsProject())
        .pipe(concat(config.fileNames.jsBundle))
        .pipe(uglify())
        .pipe(gulp.dest(config.paths.dist.scripts))
        .pipe(browserSync.stream());
}

// Process HTML files
function html() {
    return gulp.src(config.paths.src.html)
        .pipe(htmlmin({ collapseWhitespace: true }))
        .pipe(gulp.dest(config.paths.dist.html))
        .pipe(browserSync.stream());
}

// Start development server
function serve() {
    browserSync.init({
        server: {
            baseDir: config.paths.dist.base
        }
    });

    // Watch for file changes
    gulp.watch(config.paths.src.sass, styles);
    gulp.watch(config.paths.src.typescript, scripts);
    gulp.watch(config.paths.src.html, html);
}

// Export tasks
exports.clean = clean;
exports.styles = styles;
exports.scripts = scripts;
exports.html = html;
exports.serve = serve;

// Default task
exports.default = gulp.series(
    clean,
    gulp.parallel(styles, scripts, html),
    serve
);

// Build task
exports.build = gulp.series(
    clean,
    gulp.parallel(styles, scripts, html)
);

// Custom configuration function
exports.configure = function(customConfig) {
    Object.assign(config, customConfig);
};

function createAccessors(obj) {
    const cache = new Map();
    const propertyPattern = /^[a-zA-Z][a-zA-Z0-9]*$/;

    function createGetter(prop) {
        if (!propertyPattern.test(prop)) {
            return () => undefined;
        }

        if (cache.has(`get${prop}`)) {
            return cache.get(`get${prop}`);
        }

        const getter = new Function('obj', `return obj['${prop}'];`).bind(null, obj);
        cache.set(`get${prop}`, getter);
        return getter;
    }

    function createSetter(prop) {
        if (!propertyPattern.test(prop)) {
            return () => undefined;
        }

        if (cache.has(`set${prop}`)) {
            return cache.get(`set${prop}`);
        }

        const setter = new Function('obj', 'value', `obj['${prop}'] = value;`).bind(null, obj);
        cache.set(`set${prop}`, setter);
        return setter;
    }

    return new Proxy({}, {
        get(target, prop) {
            if (prop.startsWith('get')) {
                const propertyName = prop.slice(3);
                return createGetter(propertyName);
            } else if (prop.startsWith('set')) {
                const propertyName = prop.slice(3);
                return createSetter(propertyName);
            }
            return undefined;
        }
    });
}

