    const appPath = './Passphrases.app';
    const packagePath = './Passphrases.pkg';
    const installLocation = '/Applications';

    const signCommand = `codesign --force --deep --sign "${signingIdentity}" "${appPath}"`;
    const buildCommand = `productbuild --component "${appPath}" "${installLocation}" "${packagePath}"`;

    exec(signCommand, (error, stdout, stderr) => {
        if (error) {
