const fs = require('fs');
const path = require('path');
const { exec } = require('child_process');
const { promisify } = require('util');

const execAsync = promisify(exec);
const copyFileAsync = promisify(fs.copyFile);
const mkdirAsync = promisify(fs.mkdir);
const readdirAsync = promisify(fs.readdir);
const statAsync = promisify(fs.stat);

class PackageBuilder {
    constructor(options) {
        this.sourceFolder = options.sourceFolder;
        this.destFolder = options.destFolder;
        this.signingIdentity = options.signingIdentity;
        this.packageIdentity = options.packageIdentity;
    }

    async copyFolder(src, dest) {
        try {
            await mkdirAsync(dest, { recursive: true });
            const entries = await readdirAsync(src);

            for (const entry of entries) {
                const srcPath = path.join(src, entry);
                const destPath = path.join(dest, entry);
                const stats = await statAsync(srcPath);

                if (stats.isDirectory()) {
                    await this.copyFolder(srcPath, destPath);
                } else {
                    await copyFileAsync(srcPath, destPath);
                }
            }
        } catch (error) {
            console.error(`Error copying folder: ${error.message}`);
            throw error;
        }
    }

    async codesignFile(filePath) {
        try {
            const command = `codesign --force --sign "${this.signingIdentity}" "${filePath}"`;
            await execAsync(command);
            console.log(`Successfully codesigned: ${filePath}`);
        } catch (error) {
            console.error(`Error codesigning file: ${error.message}`);
            throw error;
        }
    }

    async buildPackage() {
        try {
            const command = `pkgbuild --root "${this.destFolder}" --identifier "${this.packageIdentity}" --sign "${this.signingIdentity}" "${this.destFolder}.pkg"`;
            await execAsync(command);
            console.log(`Successfully built package: ${this.destFolder}.pkg`);
        } catch (error) {
            console.error(`Error building package: ${error.message}`);
            throw error;
        }
    }

    async build() {
        try {
            console.log('Starting build process...');
            await this.copyFolder(this.sourceFolder, this.destFolder);
            console.log('Folder copied successfully');

            await this.codesignFile(this.destFolder);
            console.log('Codesigning completed');

            await this.buildPackage();
            console.log('Build process completed successfully');
        } catch (error) {
            console.error('Build process failed:', error);
            process.exit(1);
        }
    }
}

