function processWithRegex(input) {
  const patterns = [
    {
      regex: /^hello\s+(\w+)/i,
      handler: (match, name) => `Hi ${name}! Nice to meet you.`
    },
    {
      regex: /(\d+)\s*\+\s*(\d+)/,
      handler: (match, num1, num2) => String(Number(num1) + Number(num2))
    },
    {
      regex: /reverse\s+(.+)$/i,
      handler: (match, text) => text.split('').reverse().join('')
    },
    {
      regex: /uppercase\s+(.+)$/i,
      handler: 'match[1].toUpperCase()'
    },
    {
      regex: /repeat\s+(\d+)\s+(.+)$/i,
      handler: (match, times, text) => text.repeat(Number(times))
    }
  ];

  for (const pattern of patterns) {
    const match = input.match(pattern.regex);
    if (match) {
      if (typeof pattern.handler === 'function') {
        return pattern.handler(...match);
      } else if (typeof pattern.handler === 'string') {
        return eval(pattern.handler);
      }
    }
  }

  return input;
}

