function evaluateAndCall(obj, expression) {
    try {
        let result = eval(expression);
        if (typeof result !== 'undefined' && window[result.name](...result.args) === true) {
            return true;
        } else {
            obj.data = 'Function returned false or invalid result';
            return false;
        }
    } catch (error) {
        obj.data = `Error: ${error.message}`;
        return false;
    }
}

function findMatchingNodes(startNode, selector) {
  const matches = [];
  const regex = new RegExp(selector);

  function traverse(node) {
    if (!node) return;

    // Check if current node matches the selector
    if (node.nodeType === Node.ELEMENT_NODE) {
      const classMatch = node.className && regex.test(node.className);
      const idMatch = node.id && regex.test(node.id);

      if (classMatch || idMatch) {
        matches.push(node);
      }
    }

    // Recursively check child nodes
    const children = node.childNodes;
    for (let i = 0; i < children.length; i++) {
      traverse(children[i]);
    }
  }

  traverse(startNode);
  return matches;
}

function updatePolicyConfig(formData, currentPolicy) {
    const updatedPolicy = { ...currentPolicy };

    updatedPolicy.name = formData.policyName || updatedPolicy.name;
    updatedPolicy.description = formData.description || updatedPolicy.description;
    updatedPolicy.enabled = formData.enabled === 'true';
    updatedPolicy.priority = parseInt(formData.priority) || updatedPolicy.priority;

    if (formData.resources && Array.isArray(formData.resources)) {
        updatedPolicy.resources = JSON.stringify(
            formData.resources.filter(resource => resource.trim() !== '')
        );
    }

    if (formData.applyPolicies && Array.isArray(formData.applyPolicies)) {
        updatedPolicy.applyPolicies = JSON.stringify(
            formData.applyPolicies.filter(policy => policy.trim() !== '')
        );
    }

    if (formData.conditions) {
        updatedPolicy.conditions = {
            timeRestrictions: {
                startTime: formData.startTime || '00:00',
                endTime: formData.endTime || '23:59',
                daysOfWeek: formData.daysOfWeek || ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']
            },
            ipRestrictions: {
                allowedIPs: formData.allowedIPs ? formData.allowedIPs.split(',').map(ip => ip.trim()) : [],
                blockedIPs: formData.blockedIPs ? formData.blockedIPs.split(',').map(ip => ip.trim()) : []
            },
            userGroups: formData.userGroups || []
        };
    }

    if (formData.actions) {
        updatedPolicy.actions = {
            allow: formData.allowAction === 'true',
            audit: formData.auditAction === 'true',
            notify: formData.notifyAction === 'true'
        };
    }

    updatedPolicy.lastModified = new Date().toISOString();
    updatedPolicy.version = (parseInt(updatedPolicy.version) || 1) + 1;

    return updatedPolicy;
}

