                '-i', filePath,
                '-f', 'image2pipe',
                '-pix_fmt', 'rgb24',
                '-vcodec', 'rawvideo',
                '-'
            ]);

            ffmpegProcess.stdout.on('data', (data) => {
                frames.push(data);
            });

            ffmpegProcess.on('close', (code) => {
                if (code === 0) {
                    resolve(frames);
                } else {
                    reject(new Error(`FFmpeg process exited with code ${code}`));
                }
            });

            ffmpegProcess.on('error', (err) => {
                reject(err);
            });
        });
    }

