                '-s', '1920x1080',
                '-r', fps.toString(),
                '-i', '-',
                '-c:v', 'libx264',
                '-pix_fmt', 'yuv420p',
                outputPath
            ]);

            frames.forEach(frame => {
                ffmpegProcess.stdin.write(frame);
            });

            ffmpegProcess.stdin.end();

            ffmpegProcess.on('close', (code) => {
                if (code === 0) {
                    resolve();
                } else {
                    reject(new Error(`FFmpeg process exited with code ${code}`));
                }
            });

            ffmpegProcess.on('error', (err) => {
                reject(err);
            });
