import React, { useState, useEffect } from 'react';

const VersionSelector = ({ repositoryUrl, versionsDataUrl }) => {
  const [versions, setVersions] = useState([]);
  const [selectedVersion, setSelectedVersion] = useState(null);
  const [latestStable, setLatestStable] = useState(null);

  useEffect(() => {
    const fetchVersions = async () => {
      try {
        const response = await fetch(versionsDataUrl);
        const data = await response.json();

        const sortedVersions = data.versions.sort((a, b) => {
          return b.releaseDate.localeCompare(a.releaseDate);
        });

        const stable = sortedVersions.find(v => !v.prerelease);

        setVersions(sortedVersions);
        setLatestStable(stable);
        setSelectedVersion(stable);
      } catch (error) {
        console.error('Error fetching versions:', error);
      }
    };

    fetchVersions();
  }, [versionsDataUrl]);

  const handleVersionChange = (event) => {
    const selected = versions.find(v => v.version === event.target.value);
    setSelectedVersion(selected);
  };

  if (!versions.length || !selectedVersion) {
    return <div>Loading versions...</div>;
  }

  return (
    <div className="version-selector">
      <div className="current-version">
        <h3>Latest Stable Version: {latestStable.version}</h3>
        <p>Released: {new Date(latestStable.releaseDate).toLocaleDateString()}</p>
      </div>

      <div className="version-select">
        <label htmlFor="version-select">Select Version: </label>
        <select
          id="version-select"
          value={selectedVersion.version}
          onChange={handleVersionChange}
        >
          {versions.map(version => (
            <option 
              key={version.version} 
              value={version.version}
            >
              {version.version} 
              {version.prerelease ? ' (Pre-release)' : ''}
            </option>
          ))}
        </select>
      </div>

      <div className="version-details">
        <h4>Selected Version Details</h4>
        <p>Version: {selectedVersion.version}</p>
        <p>Release Date: {new Date(selectedVersion.releaseDate).toLocaleDateString()}</p>
        <p>Type: {selectedVersion.prerelease ? 'Pre-release' : 'Stable'}</p>
        <a 
          href={`${repositoryUrl}/releases/tag/${selectedVersion.version}`}
          target="_blank"
          rel="noopener noreferrer"
        >
          View Release Notes
        </a>
      </div>
    </div>
  );
};

export default VersionSelector;
