const zlib = require('zlib');

function processEncodedData(base64Data, callback) {
  const buffer = Buffer.from(base64Data, 'base64');

  zlib.inflate(buffer, (err, decompressed) => {
    if (err) {
      callback(err);
      return;
    }

    const decodedString = decompressed.toString('ascii');
    const fragments = [];
    const timeOffsets = [];

    const pairs = decodedString.match(/.{1,2}/g) || [];
    let currentFragment = '';
    let index = 0;

    pairs.forEach((pair, i) => {
      const hexValue = parseInt(pair, 16);

      if (hexValue === 0) {
        if (currentFragment) {
          fragments.push(currentFragment);
          timeOffsets.push(index);
          currentFragment = '';
        }
        index = i;
      } else {
        currentFragment += String.fromCharCode(hexValue);
      }
    });

    if (currentFragment) {
      fragments.push(currentFragment);
      timeOffsets.push(index);
    }

    callback(null, {
      fragments: fragments,
      timeOffsets: timeOffsets
    });
  });
}

function createConfigObject(options = {}) {
  const defaultConfig = {
    prefix: 'app:',
    ssl: false,
    port: 6379,
    host: 'localhost',
    onClose: () => {},
    redis: {
      host: 'localhost',
      port: 6379,
      options: {
        retryStrategy: (times) => Math.min(times * 50, 2000),
        maxRetriesPerRequest: 3,
        enableReadyCheck: true
      }
    }
  };

  const config = {
    ...defaultConfig,
    ...options,
    redis: {
      ...defaultConfig.redis,
      ...options.redis,
      options: {
        ...defaultConfig.redis.options,
        ...(options.redis?.options || {})
      }
    }
  };

  return {
    getPrefix: () => config.prefix,
    setPrefix: (newPrefix) => {
      config.prefix = newPrefix;
      return config.prefix;
    },
    isSSL: () => config.ssl,
    toggleSSL: () => {
      config.ssl = !config.ssl;
      return config.ssl;
    },
    getPort: () => config.port,
    setPort: (newPort) => {
      if (typeof newPort === 'number' && newPort > 0) {
        config.port = newPort;
      }
      return config.port;
    },
    getHost: () => config.host,
    setHost: (newHost) => {
      config.host = newHost;
      return config.host;
    },
    getRedisConfig: () => ({ ...config.redis }),
    setRedisConfig: (redisConfig) => {
      config.redis = {
        ...config.redis,
        ...redisConfig,
        options: {
          ...config.redis.options,
          ...(redisConfig.options || {})
        }
      };
      return config.redis;
    },
    onConnectionClose: (callback) => {
      if (typeof callback === 'function') {
        config.onClose = callback;
      }
      return config.onClose;
    },
    getFullConfig: () => ({ ...config }),
    reset: () => {
      Object.assign(config, defaultConfig);
      return config;
    }
  };
}

function evaluate(expression, environment) {
  const tokens = tokenize(expression);
  let index = 0;

  function parseExpression() {
    const token = tokens[index];
    if (!token) throw new Error('Unexpected end of expression');

    if (token.match(/^[a-zA-Z_][a-zA-Z0-9_]*$/)) {
      index++;
      if (!(token in environment)) {
        throw new Error(`Undefined variable: ${token} at index ${index}`);
      }
      return environment[token];
    }

    if (token.match(/^-?\d+(\.\d+)?$/)) {
      index++;
      return parseFloat(token);
    }

    if (token === '(') {
      index++;
      const operator = tokens[index];
      index++;

      const args = [];
      while (index < tokens.length && tokens[index] !== ')') {
        args.push(parseExpression());
      }

      if (tokens[index] !== ')') {
        throw new Error(`Missing closing parenthesis at index ${index}`);
      }
      index++;

      switch (operator) {
        case '+':
          return args.reduce((a, b) => a + b);
        case '-':
          return args.reduce((a, b) => a - b);
        case '*':
          return args.reduce((a, b) => a * b);
        case '/':
          return args.reduce((a, b) => a / b);
        default:
          throw new Error(`Unknown operator: ${operator} at index ${index}`);
      }
    }

    throw new Error(`Invalid token: ${token} at index ${index}`);
  }

  function tokenize(expr) {
    return expr
      .replace(/\(/g, ' ( ')
      .replace(/\)/g, ' ) ')
      .trim()
      .split(/\s+/);
  }

  try {
    const result = parseExpression();
    if (index < tokens.length) {
      throw new Error(`Unexpected token: ${tokens[index]} at index ${index}`);
    }
    return result;
  } catch (error) {
    throw error;
  }
}

function findUniqueElements(arr1, arr2) {
    let uniqueElements = [];

    for (let i = 0; i < arr1.length; i++) {
        let isUnique = true;

        for (let j = 0; j < arr2.length; j++) {
            if (arr1[i] === arr2[j]) {
                isUnique = false;
                continue;
            }
        }

        if (isUnique) {
            uniqueElements.push(arr1[i]);
        }
    }

    return uniqueElements;
}

function compile(c, rlo, rhi, ram) {
    const lines = c.split('\n');
    const body = [];
    body.push('return function(ram) {');

    for (let i = rlo; i < rhi; i++) {
        if (lines[i] && lines[i].trim()) {
            body.push(`  ${lines[i].trim()}`);
        }
    }

    body.push('};');

    const compiledFunction = new Function(body.join('\n'))();

    const fragment = {
        function: compiledFunction,
        range: [rlo, rhi],
        code: c,
        memory: ram
    };

    return {
        compiledFunction,
        fragment
    };
}

const MessageBus = (function() {
  let subscribers = new Map();
  let browserSupport;

  function detectSupport() {
    if (typeof MessageChannel !== 'undefined') {
      return 'MESSAGE_CHANNEL';
    } else if (typeof window.postMessage !== 'undefined') {
      return 'POST_MESSAGE';
    } else {
      return 'IE_LEGACY';
    }
  }

  function createMessageChannel() {
    const channel = new MessageChannel();
    channel.port1.onmessage = (event) => {
      dispatch(event.data.type, event.data.payload);
    };
    return channel;
  }

  function setupPostMessage() {
    window.addEventListener('message', (event) => {
      if (event.source === window) {
        dispatch(event.data.type, event.data.payload);
      }
    });
  }

  function setupIELegacy() {
    const storageItem = document.createElement('script');
    storageItem.setAttribute('id', 'ie-message-bus');
    document.body.appendChild(storageItem);

    storageItem.onreadystatechange = () => {
      if (storageItem.readyState === 'complete') {
        try {
          const data = JSON.parse(storageItem.getAttribute('data-message'));
          dispatch(data.type, data.payload);
        } catch (e) {}
      }
    };
  }

  function dispatch(type, payload) {
    if (subscribers.has(type)) {
      subscribers.get(type).forEach(callback => callback(payload));
    }
  }

  browserSupport = detectSupport();
  const messageChannel = browserSupport === 'MESSAGE_CHANNEL' ? createMessageChannel() : null;

  if (browserSupport === 'POST_MESSAGE') {
    setupPostMessage();
  } else if (browserSupport === 'IE_LEGACY') {
    setupIELegacy();
  }

  return {
    subscribe: function(type, callback) {
      if (!subscribers.has(type)) {
        subscribers.set(type, new Set());
      }
      subscribers.get(type).add(callback);

      return () => {
        subscribers.get(type).delete(callback);
        if (subscribers.get(type).size === 0) {
          subscribers.delete(type);
        }
      };
    },

    publish: function(type, payload) {
      const message = { type, payload };

      switch (browserSupport) {
        case 'MESSAGE_CHANNEL':
          messageChannel.port2.postMessage(message);
          break;
        case 'POST_MESSAGE':
          window.postMessage(message, '*');
          break;
        case 'IE_LEGACY':
          const storageItem = document.getElementById('ie-message-bus');
          storageItem.setAttribute('data-message', JSON.stringify(message));
          storageItem.readyState = 'complete';
          break;
      }
    }
  };
})();

function findElements(root, matchFunc) {
  let results = [];

  if (!root) {
    return results;
  }

  if (matchFunc(root)) {
    results.push(root);
  }

  if (root.children && root.children.length > 0) {
    for (let child of root.children) {
      results = results.concat(findElements(child, matchFunc));
    }
  }

  return results;
}

