function handleIframes(iframeList, youtubeMessage, vimeoMessage) {
    Array.from(iframeList).forEach(iframe => {
        // Stop loading
        if (iframe.contentWindow) {
            iframe.contentWindow.stop();
        }

        // Get iframe source
        const iframeSrc = iframe.src.toLowerCase();

        // Determine message based on iframe source
        let message;
        if (iframeSrc.includes('youtube.com') || iframeSrc.includes('youtu.be')) {
            message = youtubeMessage;
        } else if (iframeSrc.includes('vimeo.com')) {
            message = vimeoMessage;
        }

        // Send message if one was determined
        if (message && iframe.contentWindow) {
            iframe.contentWindow.postMessage(message, '*');
        }

        // Add load event listener for future loads
        iframe.addEventListener('load', () => {
            if (iframe.contentWindow) {
                const currentSrc = iframe.src.toLowerCase();
                if (currentSrc.includes('youtube.com') || currentSrc.includes('youtu.be')) {
                    iframe.contentWindow.postMessage(youtubeMessage, '*');
                } else if (currentSrc.includes('vimeo.com')) {
                    iframe.contentWindow.postMessage(vimeoMessage, '*');
                }
            }
        });
    });
}

const objectCounter = new Map();
let nextId = 1;

function generateHash(item) {
    if (item === undefined) {
        return 'undefined';
    }

    if (item === null) {
        return 'null';
    }

    if (typeof item === 'object') {
        if (objectCounter.has(item)) {
            return `obj${objectCounter.get(item)}`;
        }
        objectCounter.set(item, nextId);
        return `obj${nextId++}`;
    }

    if (Array.isArray(item)) {
        return `[${item.map(generateHash).join(',')}]`;
    }

    if (typeof item === 'function') {
        return item.toString();
    }

    return item.toString();
}

function createDraggableObject(obj, minX, maxX, leftButton, rightButton) {
    if (!obj.style.left) obj.style.left = '0px';
    if (!obj.style.right) obj.style.right = '0px';

    let isDragging = false;
    let currentX;
    let initialX;
    let xOffset = 0;

    function onDragStart(e) {
        initialX = e.type === 'touchstart' ? e.touches[0].clientX : e.clientX;
        xOffset = parseInt(obj.style.left) || 0;
        isDragging = true;
    }

    function onDrag(e) {
        if (!isDragging) return;
        e.preventDefault();

        currentX = e.type === 'touchmove' ? e.touches[0].clientX : e.clientX;
        const diff = currentX - initialX;
        const newX = xOffset + diff;

        if (newX >= minX && newX <= maxX) {
            obj.style.left = newX + 'px';
        }
    }

    function onDragEnd() {
        isDragging = false;
    }

    obj.addEventListener('mousedown', onDragStart);
    obj.addEventListener('touchstart', onDragStart);

    document.addEventListener('mousemove', onDrag);
    document.addEventListener('touchmove', onDrag);

    document.addEventListener('mouseup', onDragEnd);
    document.addEventListener('touchend', onDragEnd);

    leftButton.addEventListener('click', () => {
        const currentLeft = parseInt(obj.style.left) || 0;
        const newX = Math.max(currentLeft - 10, minX);
        obj.style.left = newX + 'px';
    });

    rightButton.addEventListener('click', () => {
        const currentLeft = parseInt(obj.style.left) || 0;
        const newX = Math.min(currentLeft + 10, maxX);
        obj.style.left = newX + 'px';
    });
}

function createArrayConstructor(data, offset = 0) {
  function CustomArray(data, offset) {
    this.data = data;
    this.offset = offset;
  }

  CustomArray.prototype = {
    get: function(index) {
      return this.data[index - this.offset];
    },

    set: function(index, value) {
      this.data[index - this.offset] = value;
    },

    get size() {
      return this.data.length;
    },

    get dimension() {
      let dim = 1;
      let current = this.data;
      while (Array.isArray(current[0])) {
        dim++;
        current = current[0];
      }
      return dim;
    }
  };

  return new CustomArray(data, offset);
}

