function createFunction(expression, ...args) {
  if (typeof expression !== 'string') {
    throw new TypeError('Expression must be a string');
  }

  try {
    if (expression.includes('=>')) {
      const arrowFunc = expression.trim();
      const paramStart = arrowFunc.indexOf('(');
      const paramEnd = arrowFunc.indexOf(')');
      const params = arrowFunc.slice(paramStart + 1, paramEnd).split(',').map(p => p.trim());
      const body = arrowFunc.slice(arrowFunc.indexOf('=>') + 2).trim();

      return new Function(...params, `return ${body}`);
    }

    if (args.length === 0) {
      return new Function(`return ${expression}`);
    }

    return new Function(...args, `return ${expression}`);
  } catch (error) {
    throw new SyntaxError('Invalid expression');
  }
}

function testColumnToggleTable(tableClass, expectedText, targetHash) {
    return new Promise((resolve, reject) => {
        const startTest = () => {
            const cells = document.getElementsByClassName(tableClass);

            if (cells.length === 0) {
                reject(new Error(`No cells found with class ${tableClass}`));
                return;
            }

            const firstCellText = cells[0].textContent.trim();

            if (firstCellText !== expectedText) {
                reject(new Error(`Expected "${expectedText}" but found "${firstCellText}"`));
                return;
            }

            if (window.location.hash !== targetHash) {
                window.location.hash = targetHash;
                window.addEventListener('hashchange', () => {
                    setTimeout(startTest, 100);
                }, { once: true });
                return;
            }

            resolve(true);
        };

        if (document.readyState === 'complete') {
            startTest();
        } else {
            window.addEventListener('load', startTest);
        }
    });
}

const compile = (code) => {
  let cache;
  let fn;

  return async (s = {}, k = {}) => {
    if (!fn) {
      const args = Object.keys(k);
      const values = Object.values(k);
      const scope = Object.entries(s)
        .map(([key, value]) => `const ${key} = ${JSON.stringify(value)};`)
        .join('\n');

      fn = new Function(...args, `
        ${scope}
        return (async () => {
          ${code}
        })();
      `);
    }

    if (cache) {
      return cache;
    }

    try {
      const result = await fn(...Object.values(k));
      cache = result;
      return result;
    } catch (error) {
      throw error;
    }
  };
};

