class ScriptLoader {
    constructor() {
        this.loadedScripts = new Set();
        this.pendingScripts = new Map();
        this.dependencies = new Map();
    }

    addDependency(scriptUrl, dependsOn = []) {
        this.dependencies.set(scriptUrl, dependsOn);
    }

    async loadScript(url) {
        if (this.loadedScripts.has(url)) {
            return Promise.resolve();
        }

        if (this.pendingScripts.has(url)) {
            return this.pendingScripts.get(url);
        }

        const loadPromise = new Promise((resolve, reject) => {
            const script = document.createElement('script');
            script.type = 'text/javascript';
            script.src = url;

            script.onload = () => {
                this.loadedScripts.add(url);
                this.pendingScripts.delete(url);
                resolve();
            };

            script.onerror = () => {
                this.pendingScripts.delete(url);
                reject(new Error(`Failed to load script: ${url}`));
            };

            document.head.appendChild(script);
        });

        this.pendingScripts.set(url, loadPromise);
        return loadPromise;
    }

    async loadScripts(scripts) {
        const loaded = new Set();
        const loading = new Set();

        async function loadWithDependencies(url, loader) {
            if (loaded.has(url)) return;
            if (loading.has(url)) {
                throw new Error(`Circular dependency detected for ${url}`);
            }

            loading.add(url);

            const dependencies = loader.dependencies.get(url) || [];
            for (const dep of dependencies) {
                await loadWithDependencies(dep, loader);
            }

            await loader.loadScript(url);
            loading.delete(url);
            loaded.add(url);
        }

        try {
            await Promise.all(
                scripts.map(script => loadWithDependencies(script, this))
            );
        } catch (error) {
            console.error('Error loading scripts:', error);
            throw error;
        }
    }
}

