import warning from 'warning';
import ReactComponentTreeHook from 'react-dom/lib/ReactComponentTreeHook';
import EventPluginRegistry from 'react-dom/lib/EventPluginRegistry';

function validateComponentProps(component, props) {
  if (!component || !props) {
    return;
  }

  const componentName = component.getName() || 'Unknown';
  const componentId = component._debugID;

  // Check for dangerous props
  const dangerousProps = ['dangerouslySetInnerHTML', 'innerHTML', '__html'];
  dangerousProps.forEach(prop => {
    warning(
      !props[prop],
      `Warning: ${prop} prop used in ${componentName} (#${componentId}). ` +
      'This is discouraged and may lead to security vulnerabilities.'
    );
  });

  // Validate event handlers
  Object.keys(props).forEach(propName => {
    if (propName.startsWith('on') && typeof props[propName] === 'function') {
      warning(
        EventPluginRegistry.registrationNameModules[propName],
        `Warning: Unknown event handler property '${propName}' in ${componentName} (#${componentId}). ` + 
        'This will not work as expected.'
      );
    }
  });

  // Check for refs on stateless components
  warning(
    !(component.statelessFunctionalComponent && props.ref),
    `Warning: Stateless function components cannot have refs in ${componentName} (#${componentId}).`
  );

  // Validate children
  if (props.children) {
    warning(
      typeof props.children !== 'function',
      `Warning: Children as functions are not supported in ${componentName} (#${componentId}).`
    );
  }

  // Validate style prop
  if (props.style) {
    warning(
      typeof props.style === 'object',
      `Warning: Style prop value must be an object in ${componentName} (#${componentId}).`
    );
  }

  // Check for deprecated lifecycle methods
  const deprecatedMethods = [
    'componentWillMount',
    'componentWillReceiveProps',
    'componentWillUpdate'
  ];

  deprecatedMethods.forEach(method => {
    warning(
      !props[method],
      `Warning: ${method} is deprecated in ${componentName} (#${componentId}). ` +
      'Use newer lifecycle methods instead.'
    );
  });

  // Validate key prop on elements in arrays
  if (Array.isArray(props.children)) {
    const hasKeys = props.children.every(child => 
      child && child.key != null
    );

    warning(
      hasKeys,
      `Warning: Each child in a list should have a unique "key" prop in ${componentName} (#${componentId}).`
    );
  }

  return true;
}

export default validateComponentProps;
