function concatenateBuffers(head) {
    let totalLength = 0;
    let current = head;

    while (current) {
        totalLength += current.data.length;
        current = current.next;
    }

    const result = new Uint8Array(totalLength);
    let offset = 0;
    current = head;

    while (current) {
        result.set(current.data, offset);
        offset += current.data.length;
        current = current.next;
    }

    return result;
}

const createMessageChannel = (id, callback) => {
  const isMessageChannelSupported = typeof MessageChannel !== 'undefined';
  const isPostMessageSupported = typeof window.postMessage !== 'undefined';

  let messageHandler = null;
  let pollingInterval = null;
  const messageQueue = [];

  const handleMessage = (message) => {
    if (message.id === id) {
      callback(message.data);
    }
  };

  if (isMessageChannelSupported) {
    const channel = new MessageChannel();
    channel.port1.onmessage = (event) => handleMessage(event.data);
    messageHandler = (data) => channel.port2.postMessage({ id, data });
  } else if (isPostMessageSupported) {
    window.addEventListener('message', (event) => handleMessage(event.data));
    messageHandler = (data) => window.postMessage({ id, data }, '*');
  } else {
    pollingInterval = setInterval(() => {
      if (messageQueue.length > 0) {
        const message = messageQueue.shift();
        handleMessage(message);
      }
    }, 100);
    messageHandler = (data) => messageQueue.push({ id, data });
  }

  return {
    send: (data) => messageHandler(data),
    cleanup: () => {
      if (pollingInterval) {
        clearInterval(pollingInterval);
      }
      messageQueue.length = 0;
    }
  };
};

function createWriteStream(name, encoding, callback) {
  const chunks = [];
  const headers = { [name.toLowerCase()]: encoding };

  return {
    headers,
    write: function(data, encoding) {
      chunks.push(data);
    },
    end: function(data, encoding) {
      if (data) {
        chunks.push(data);
      }
      callback(chunks);
      return chunks;
    }
  };
}

function loginUser(userName, password) {
    const users = {
        'john': { password: 'pass123', passwordExpiry: '2024-01-01' },
        'jane': { password: 'pass456', passwordExpiry: '2023-12-31' }
    };

    let result = {
        isLoggedIn: false,
        alertMessage: ''
    };

    if (!users[userName]) {
        result.alertMessage = 'User not found';
        return result;
    }

    if (users[userName].password !== password) {
        result.alertMessage = 'Incorrect password';
        alert('Incorrect password');
        return result;
    }

    const today = new Date();
    const expiryDate = new Date(users[userName].passwordExpiry);

    if (today > expiryDate) {
        result.alertMessage = 'Password has expired. Please reset your password.';
        alert(result.alertMessage);
        return result;
    }

    document.cookie = `loggedIn=${userName}; path=/; max-age=3600`;
    result.isLoggedIn = true;
    result.alertMessage = 'Login successful';

    return result;
}

function parseActionLength(buffer, offset) {
  try {
    if (offset + 3 > buffer.length) {
      return {
        error: 'Buffer too short',
        code: 'ERR_BUFFER_UNDERFLOW'
      };
    }

    const actionType = buffer[offset];
    const length = (buffer[offset + 1] << 8) | buffer[offset + 2];

    if (offset + length > buffer.length) {
      return {
        error: 'Invalid length field',
        code: 'ERR_INVALID_LENGTH'
      };
    }

    return {
      actionType,
      length
    };
  } catch (err) {
    return {
      error: 'Failed to parse buffer',
      code: 'ERR_PARSE_FAILED'
    };
  }
}

