function evaluateExpression(expression, context = {}) {
  try {
    const contextKeys = Object.keys(context);
    const contextValues = Object.values(context);
    const fn = new Function(...contextKeys, `return ${expression}`);
    return fn(...contextValues);
  } catch (error) {
    throw new Error('Expression evaluation failed: ' + error.message);
  }
}

function iterateExpression(expression, collection) {
  const fn = createExpressionFunction(expression);
  const results = [];

  if (Array.isArray(collection)) {
    for (let item of collection) {
      results.push(fn.call(item));
    }
  } else if (typeof collection === 'object' && collection !== null) {
    for (let key in collection) {
      if (collection.hasOwnProperty(key)) {
        results.push(fn.call(collection[key]));
      }
    }
  }

  return results;
}

class DataCollector {
  constructor() {
    this.data = [];
    this.isCollecting = false;
    this.stream = null;
  }

  startCollecting(stream) {
    if (this.isCollecting) return;

    this.stream = stream;
    this.isCollecting = true;

    this.stream.on('data', (chunk) => {
      if (this.isCollecting) {
        this.data.push(chunk);
      }
    });

    this.stream.on('end', () => {
      this.isCollecting = false;
      this.stream = null;
    });

    this.stream.on('error', (error) => {
      console.error('Stream error:', error);
      this.isCollecting = false;
      this.stream = null;
    });
  }

  pause() {
    if (this.isCollecting && this.stream) {
      this.isCollecting = false;
      this.stream.pause();
    }
  }

  resume() {
    if (!this.isCollecting && this.stream) {
      this.isCollecting = true;
      this.stream.resume();
    }
  }

  getData() {
    return this.data;
  }

  clear() {
    this.data = [];
  }
}

function copyBuffer(buffer) {
    const newBuffer = Buffer.alloc(buffer.length);
    buffer.copy(newBuffer);
    return newBuffer;
}

function createDraggable(element, minX, minY, maxX, maxY) {
    let isDragging = false;
    let currentX;
    let currentY;
    let initialX;
    let initialY;

    const startButton = document.createElement('button');
    startButton.textContent = 'Start Dragging';
    const stopButton = document.createElement('button');
    stopButton.textContent = 'Stop Dragging';

    startButton.addEventListener('click', () => {
        isDragging = true;
    });

    stopButton.addEventListener('click', () => {
        isDragging = false;
    });

    function onDragStart(e) {
        if (!isDragging) return;
        initialX = e.clientX - currentX;
        initialY = e.clientY - currentY;
        element.style.cursor = 'grabbing';
    }

    function onDrag(e) {
        if (!isDragging) return;
        e.preventDefault();

        currentX = e.clientX - initialX;
        currentY = e.clientY - initialY;

        currentX = Math.min(Math.max(currentX, minX), maxX);
        currentY = Math.min(Math.max(currentY, minY), maxY);

        element.style.left = `${currentX}px`;
        element.style.top = `${currentY}px`;
    }

    function onDragEnd() {
        if (!isDragging) return;
        initialX = currentX;
        initialY = currentY;
        element.style.cursor = 'grab';
    }

    element.addEventListener('mousedown', onDragStart);
    document.addEventListener('mousemove', onDrag);
    document.addEventListener('mouseup', onDragEnd);
    element.style.position = 'absolute';
    element.style.cursor = 'grab';

    document.body.appendChild(startButton);
    document.body.appendChild(stopButton);

    return {
        onDragStart,
        onDrag,
        onDragEnd,
        startButton,
        stopButton
    };
}

