function concatenateBuffers(bufferList, maxSize = Number.MAX_SAFE_INTEGER) {
    const totalLength = bufferList.reduce((sum, buf) => sum + buf.length, 0);

    if (totalLength > maxSize) {
        throw new Error('Resulting buffer would exceed maximum size');
    }

    const result = Buffer.alloc(totalLength);
    let offset = 0;

    for (const buffer of bufferList) {
        buffer.copy(result, offset);
        offset += buffer.length;
    }

    return result;
}

