interface PropTypeCache {
  [key: string]: {
    props: any;
    valid: boolean;
  };
}

const propTypeCache: PropTypeCache = {};

function createPropTypeValidator<P extends object>(
  validator: (props: P) => boolean,
  componentName: string
) {
  return (props: P): void => {
    const cacheKey = `${componentName}-${JSON.stringify(props)}`;

    if (propTypeCache[cacheKey]) {
      if (!propTypeCache[cacheKey].valid) {
        throw new Error(
          `Invalid prop types for component ${componentName}`
        );
      }
      return;
    }

    try {
      const isValid = validator(props);
      propTypeCache[cacheKey] = {
        props,
        valid: isValid
      };

      if (!isValid) {
        throw new Error(
          `Invalid prop types for component ${componentName}`
        );
      }
    } catch (error) {
      propTypeCache[cacheKey] = {
        props,
        valid: false
      };
      throw error;
    }
  };
}

function clearPropTypeCache(): void {
  Object.keys(propTypeCache).forEach(key => {
    delete propTypeCache[key];
  });
}

function getPropTypeCache(): PropTypeCache {
  return { ...propTypeCache };
}

export {
  createPropTypeValidator,
  clearPropTypeCache,
  getPropTypeCache
};
