        'buffer',
        'depthBuffer',
        'offset',
        'depth',
        'color1',
        'color2',
        'material',
        `
        if (depthBuffer[offset] < depth) {
            depthBuffer[offset] = depth;

            let blendFactor = (depth + 1.0) / 2.0;
            let inverseBlendFactor = 1.0 - blendFactor;

            buffer[offset * 4] = Math.floor(color1.r * blendFactor + color2.r * inverseBlendFactor);
            buffer[offset * 4 + 1] = Math.floor(color1.g * blendFactor + color2.g * inverseBlendFactor);
            buffer[offset * 4 + 2] = Math.floor(color1.b * blendFactor + color2.b * inverseBlendFactor);
            buffer[offset * 4 + 3] = Math.floor(material.opacity * 255);

            return {
                buffer: buffer,
                depthBuffer: depthBuffer
            };
        }

        return {
            buffer: buffer,
            depthBuffer: depthBuffer
        };
        `
    );
}

