function makeDraggableResizable(element) {
    let isDragging = false;
    let isResizing = false;
    let currentX;
    let currentY;
    let initialX;
    let initialY;
    let xOffset = 0;
    let yOffset = 0;

    // Create control buttons
    const controlsDiv = document.createElement('div');
    controlsDiv.style.position = 'absolute';
    controlsDiv.style.top = '-25px';
    controlsDiv.style.width = '100%';
    controlsDiv.style.display = 'flex';
    controlsDiv.style.justifyContent = 'space-between';

    const leftAlignBtn = document.createElement('button');
    leftAlignBtn.textContent = 'Left';
    const rightAlignBtn = document.createElement('button');
    rightAlignBtn.textContent = 'Right';

    controlsDiv.appendChild(leftAlignBtn);
    controlsDiv.appendChild(rightAlignBtn);
    element.appendChild(controlsDiv);

    // Create resize handle
    const resizeHandle = document.createElement('div');
    resizeHandle.style.width = '10px';
    resizeHandle.style.height = '10px';
    resizeHandle.style.background = 'gray';
    resizeHandle.style.position = 'absolute';
    resizeHandle.style.right = '0';
    resizeHandle.style.bottom = '0';
    resizeHandle.style.cursor = 'se-resize';
    element.appendChild(resizeHandle);

    // Set initial styles
    element.style.position = 'absolute';
    element.style.cursor = 'move';

    function dragStart(e) {
        if (e.target === resizeHandle) {
            isResizing = true;
        } else {
            isDragging = true;
            initialX = e.clientX - xOffset;
            initialY = e.clientY - yOffset;
        }
    }

    function dragEnd() {
        isDragging = false;
        isResizing = false;
        initialX = currentX;
        initialY = currentY;
    }

    function drag(e) {
        if (isDragging) {
            e.preventDefault();
            currentX = e.clientX - initialX;
            currentY = e.clientY - initialY;
            xOffset = currentX;
            yOffset = currentY;
            element.style.transform = `translate(${currentX}px, ${currentY}px)`;
        } else if (isResizing) {
            e.preventDefault();
            const width = e.clientX - element.offsetLeft;
            const height = e.clientY - element.offsetTop;
            element.style.width = width + 'px';
            element.style.height = height + 'px';
        }
    }

    leftAlignBtn.addEventListener('click', () => {
        element.style.transform = 'translate(0, ' + yOffset + 'px)';
        xOffset = 0;
        currentX = 0;
        initialX = 0;
    });

    rightAlignBtn.addEventListener('click', () => {
        const rightPosition = window.innerWidth - element.offsetWidth;
        element.style.transform = 'translate(' + rightPosition + 'px, ' + yOffset + 'px)';
        xOffset = rightPosition;
        currentX = rightPosition;
        initialX = rightPosition;
    });

    element.addEventListener('mousedown', dragStart);
    document.addEventListener('mousemove', drag);
    document.addEventListener('mouseup', dragEnd);
    document.addEventListener('mouseleave', dragEnd);
}

