const createPropTypesValidator = (expectedPropTypes) => {
  const validationCache = new WeakMap();
  const warnedProps = new Set();

  return (props, componentName) => {
    if (process.env.NODE_ENV === 'production') {
      return null;
    }

    if (validationCache.has(props)) {
      return validationCache.get(props);
    }

    const errors = [];
    const propKeys = Object.keys(props);

    // Check for unknown props
    propKeys.forEach(key => {
      if (!expectedPropTypes.hasOwnProperty(key) && !warnedProps.has(`${componentName}-${key}`)) {
        console.warn(`Unknown prop '${key}' supplied to '${componentName}'`);
        warnedProps.add(`${componentName}-${key}`);
      }
    });

    // Validate prop types
    Object.entries(expectedPropTypes).forEach(([propName, validator]) => {
      if (props.hasOwnProperty(propName)) {
        const value = props[propName];

        try {
          const isValid = validator(value, propName, componentName);
          if (!isValid) {
            errors.push(
              new Error(`Invalid prop '${propName}' supplied to '${componentName}'`)
            );
          }
        } catch (error) {
          errors.push(error);
        }
      } else if (validator.isRequired) {
        errors.push(
          new Error(`Required prop '${propName}' was not supplied to '${componentName}'`)
        );
      }
    });

    const result = errors.length ? errors : null;
    validationCache.set(props, result);
    return result;
  };
};

// Validator helpers
const PropTypes = {
  string: (value, propName, componentName) => {
    return typeof value === 'string' || value instanceof String;
  },
  number: (value, propName, componentName) => {
    return typeof value === 'number' && !isNaN(value);
  },
  bool: (value, propName, componentName) => {
    return typeof value === 'boolean';
  },
  func: (value, propName, componentName) => {
    return typeof value === 'function';
  },
  array: (value, propName, componentName) => {
    return Array.isArray(value);
  },
  object: (value, propName, componentName) => {
    return value !== null && typeof value === 'object' && !Array.isArray(value);
  },
  oneOf: (allowedValues) => {
    return (value, propName, componentName) => {
      return allowedValues.includes(value);
    };
  },
  shape: (shape) => {
    return (value, propName, componentName) => {
      if (typeof value !== 'object' || value === null) return false;
      return Object.entries(shape).every(([key, validator]) => {
        return validator(value[key], key, componentName);
      });
    };
  }
};

// Add isRequired to all validators
Object.keys(PropTypes).forEach(key => {
  const validator = PropTypes[key];
  if (typeof validator === 'function') {
    validator.isRequired = function(value, propName, componentName) {
      return value != null && validator(value, propName, componentName);
    };
  }
});

const { exec } = require('child_process');
const fs = require('fs');

function executeWithWatch(command, inputFiles, options = {}) {
  return new Promise((resolve, reject) => {
    if (options.watch) {
      const missingFiles = inputFiles.filter(file => !fs.existsSync(file));

      if (missingFiles.length > 0) {
        reject(new Error(`Missing input files: ${missingFiles.join(', ')}`));
        return;
      }

      let lastRun = 0;
      const watchFiles = inputFiles.map(file => {
        fs.watch(file, (eventType) => {
          const now = Date.now();
          if (now - lastRun > 1000) {
            lastRun = now;
            runCommand();
          }
        });
      });
    }

    function runCommand() {
      exec(command, (error, stdout, stderr) => {
        if (error) {
          reject(error);
          return;
        }

        resolve({
          stdout: stdout.trim(),
          stderr: stderr.trim()
        });
      });
    }

    runCommand();
  });
}

module.exports = executeWithWatch;

function normalizeURL(url) {
  const urlObj = new URL(url);
  const pathSegments = urlObj.pathname.split('/').filter(Boolean);
  const normalizedPath = [];

  for (const segment of pathSegments) {
    if (segment === '.') {
      continue;
    } else if (segment === '..') {
      normalizedPath.pop();
    } else {
      normalizedPath.push(segment);
    }
  }

  urlObj.pathname = '/' + normalizedPath.join('/');
  return urlObj.toString();
}

