const admin = require('firebase-admin');
const serviceAccount = require('./serviceAccountKey.json');
const fs = require('fs');
const express = require('express');
const app = express();
const http = require('http').createServer(app);
const io = require('socket.io')(http);

// Initialize Firebase
admin.initializeApp({
  credential: admin.credential.cert(serviceAccount),
  databaseURL: 'https://your-project.firebaseio.com'
});

const db = admin.database();
const ledRef = db.ref('led');

// LED device path
const LED_DEVICE = '/dev/led0';

// Initialize LED state
let ledState = false;

// Write to LED device
function writeLED(state) {
  try {
    fs.writeFileSync(LED_DEVICE, state ? '1' : '0');
    return true;
  } catch (error) {
    console.error('Error writing to LED:', error);
    return false;
  }
}

// Socket.io connection handler
io.on('connection', (socket) => {
  console.log('Client connected');

  // Send current LED state to new clients
  ledRef.once('value')
    .then((snapshot) => {
      socket.emit('ledState', snapshot.val());
    })
    .catch((error) => {
      console.error('Error reading LED state:', error);
    });

  // Handle LED control messages
  socket.on('setLED', (data) => {
    try {
      const message = JSON.parse(data);
      ledState = message.state;

      // Write to LED device
      if (writeLED(ledState)) {
        // Update Firebase
        ledRef.set({
          state: ledState,
          timestamp: admin.database.ServerValue.TIMESTAMP
        })
        .then(() => {
          // Broadcast new state to all clients
          io.emit('ledState', { state: ledState });
        })
        .catch((error) => {
          console.error('Error updating Firebase:', error);
        });
      }
    } catch (error) {
      console.error('Error processing message:', error);
    }
  });

  socket.on('disconnect', () => {
    console.log('Client disconnected');
  });
});

// Listen for Firebase changes
ledRef.on('value', (snapshot) => {
  const data = snapshot.val();
  if (data && data.state !== undefined) {
    ledState = data.state;
    writeLED(ledState);
  }
});

// Serve static files
app.use(express.static('public'));

// Start server
const PORT = process.env.PORT || 3000;
http.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// Handle process termination
process.on('SIGINT', () => {
  writeLED(false);
  process.exit();
});
