};

function readI2cBuffer(address, register, length, callback) {
    const i2c = require('i2c-bus');
    const i2c1 = i2c.openSync(1);

    if (typeof register === 'function') {
        callback = register;
        register = undefined;
        length = callback;
    }

    if (typeof length === 'function') {
        callback = length;
        length = register;
        register = undefined;
    }

    const buffer = Buffer.alloc(length);

    try {
        if (register === undefined) {
            if (callback) {
                i2c1.i2cRead(address, length, buffer, (err, bytesRead, buffer) => {
                    i2c1.closeSync();
                    callback(err, buffer);
                });
            } else {
                const bytesRead = i2c1.i2cReadSync(address, length, buffer);
                i2c1.closeSync();
                return buffer;
            }
        } else {
            if (callback) {
                i2c1.readI2cBlock(address, register, length, buffer, (err, bytesRead, buffer) => {
                    i2c1.closeSync();
                    callback(err, buffer);
                });
            } else {
                const bytesRead = i2c1.readI2cBlockSync(address, register, length, buffer);
                i2c1.closeSync();
                return buffer;
            }
        }
    } catch (err) {
        i2c1.closeSync();
        if (callback) {
            callback(err);
        } else {
            throw err;
        }
    }
}

function splitString(str, delimiter) {
    const result = [];
    const regex = new RegExp(delimiter);
    let startIndex = 0;
    let match;

    while ((match = regex.exec(str)) !== null) {
        result.push(str.substr(startIndex, match.index - startIndex));
        startIndex = match.index + delimiter.length;
        regex.lastIndex = startIndex;
    }

    result.push(str.substr(startIndex));
    return result;
}

