URL.prototype.updateUrl = function(hash) {
  if (!hash || Object.keys(hash).length === 0) {
    this.hash = '';
    return this;
  }

  const hashString = Object.entries(hash)
    .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(value)}`)
    .join('&');

  this.hash = `#${hashString}`;
  return this;
};

async function registerUser(username, password, firstName, lastName) {
  try {
    // Input validation
    if (!username || !password || !firstName || !lastName) {
      throw new Error('All fields are required');
    }

    if (username.length < 3 || username.length > 20) {
      throw new Error('Username must be between 3 and 20 characters');
    }

    if (password.length < 8) {
      throw new Error('Password must be at least 8 characters long');
    }

    if (!/^[a-zA-Z]+$/.test(firstName) || !/^[a-zA-Z]+$/.test(lastName)) {
      throw new Error('Name can only contain letters');
    }

    // Hash the password
    const hashedPassword = await bcrypt.hash(password, 10);

    // Register user with service
    const newUser = await UserService.create({
      username: username.toLowerCase(),
      password: hashedPassword,
      firstName: firstName.trim(),
      lastName: lastName.trim(),
      createdAt: new Date(),
      active: true
    });

    // Create session
    const session = await SessionService.create({
      userId: newUser.id,
      timestamp: new Date()
    });

    // Save session token in cookies
    document.cookie = `sessionToken=${session.token}; path=/; max-age=86400; secure; samesite=strict`;

    return {
      success: true,
      user: {
        id: newUser.id,
        username: newUser.username,
        firstName: newUser.firstName,
        lastName: newUser.lastName
      }
    };

  } catch (error) {
    return {
      success: false,
      error: error.message
    };
  }
}

