function executeCoroutines(coroutines, token) {
  const queue = [...coroutines];

  while (queue.length > 0) {
    const current = queue.shift();
    const result = current.next();

    if (result.done) {
      if (result.value === token) {
        queue.push(current);
      } else {
        return {
          done: false,
          value: result.value
        };
      }
    } else {
      queue.push(current);
    }
  }

  return {
    done: true
  };
}

function* createCoroutine() {
  while(true) {
    yield token;
  }
}
