function createMessageHandler() {
    const callbackQueue = [];
    let isProcessing = false;

    window.addEventListener('message', function(event) {
        if (event.data === 'SENTINEL') {
            isProcessing = true;
            while (callbackQueue.length > 0) {
                const callback = callbackQueue.shift();
                callback();
            }
            isProcessing = false;
