function decodeBuffer(buffer) {
  if (!buffer || buffer.length === 0) {
    return '';
  }

  try {
    const decoder = new TextDecoder('utf-8');
    return decoder.decode(buffer);
  } catch (error) {
    try {
      return buffer.toString('utf-8');
    } catch (fallbackError) {
      let result = '';
      for (let i = 0; i < buffer.length; i++) {
        if (buffer[i] >= 32 && buffer[i] <= 126) {
          result += String.fromCharCode(buffer[i]);
        }
      }
      return result;
    }
  }
}

function isContentComponent(component) {
  if (!component) {
    return 'not-content';
  }

  // Check if component is a string or number (direct content)
  if (typeof component === 'string' || typeof component === 'number') {
    return 'content';
  }

  // Check if it's a React element
  if (component.$$typeof === Symbol.for('react.element')) {
    const { type, props } = component;

    // Check HTML elements
    if (typeof type === 'string') {
      const contentTags = ['p', 'span', 'div', 'article', 'section', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6'];
      if (contentTags.includes(type)) {
        return 'content';
      }
    }

    // Check custom components
    if (typeof type === 'function') {
      // Check component name
      const componentName = type.displayName || type.name;
      if (componentName && /Content|Text|Article|Post/i.test(componentName)) {
        return 'content';
      }

      // Check for content-related props
      const contentProps = ['text', 'content', 'children', 'dangerouslySetInnerHTML'];
      if (contentProps.some(prop => props.hasOwnProperty(prop))) {
        return 'content';
      }
    }
  }

  // Check for React fragments
  if (component.type === Symbol.for('react.fragment')) {
    return 'content';
  }

  // Check arrays of components
  if (Array.isArray(component)) {
    const hasContentChildren = component.some(child => isContentComponent(child) === 'content');
    return hasContentChildren ? 'content' : 'not-content';
  }

  return 'not-content';
}

function parseTokens(inputString, patterns) {
    const results = [];
    let remainingString = inputString;

    while (remainingString.length > 0) {
        let matched = false;

        for (const pattern of patterns) {
            const regex = new RegExp(`^${pattern}`);
            const match = remainingString.match(regex);

            if (match) {
                results.push(match[0]);
                remainingString = remainingString.slice(match[0].length).trim();
                matched = true;
                break;
            }
        }

        if (!matched) {
            const nextSpace = remainingString.indexOf(' ');
            if (nextSpace === -1) {
                break;
            }
            remainingString = remainingString.slice(nextSpace + 1).trim();
        }
    }

    return results;
}

