function concatenateBuffers(bufferArray) {
  if (!Array.isArray(bufferArray)) {
    throw new TypeError('Input must be an array');
  }

  const validBuffers = bufferArray.map(buf => {
    if (buf instanceof Uint8Array) {
      return Buffer.from(buf);
    } else if (Buffer.isBuffer(buf)) {
      return buf;
    } else {
      throw new TypeError('Array elements must be Buffer or Uint8Array objects');
    }
  });

  return Buffer.concat(validBuffers);
}

