function getWorldImageInfo(worldUrl) {
  return new Promise((resolve, reject) => {
    const iframe = document.createElement('iframe');
    iframe.style.display = 'none';
    document.body.appendChild(iframe);

    const timeout = setTimeout(() => {
      cleanup();
      reject(new Error('Timeout waiting for world image info'));
    }, 10000);

    function cleanup() {
      window.removeEventListener('message', messageHandler);
      document.body.removeChild(iframe);
      clearTimeout(timeout);
    }

    function messageHandler(event) {
      if (event.origin !== new URL(worldUrl).origin) return;

      try {
        const data = JSON.parse(event.data);
        if (data.type === 'worldImageInfo') {
          cleanup();
          resolve({
            entryImage: data.entryImage,
            posterImage: data.posterImage
          });
        }
      } catch (error) {
        // Ignore invalid JSON messages
      }
    }

    window.addEventListener('message', messageHandler);

    iframe.src = worldUrl;
    iframe.addEventListener('load', () => {
      iframe.contentWindow.postMessage(JSON.stringify({
        type: 'requestWorldImageInfo'
      }), '*');
    });
  });
}

function copyBytes(chunks, start, length) {
  const result = Buffer.allocUnsafe(length);
  let offset = 0;
  let pos = start;
  let remaining = length;

  for (const chunk of chunks) {
    const chunkLength = chunk.length;
    if (pos >= chunkLength) {
      pos -= chunkLength;
      continue;
    }

    const copyLength = Math.min(chunkLength - pos, remaining);
    chunk.copy(result, offset, pos, pos + copyLength);
    offset += copyLength;
    remaining -= copyLength;
    if (remaining === 0) break;
    pos = 0;
  }

  return result;
}

function decodeBuffer(buffer) {
  if (!buffer || buffer.length === 0) {
    return '';
  }

  let result = '';
  let tempBuffer = Buffer.alloc(4);
  let tempLength = 0;

  for (let i = 0; i < buffer.length; i++) {
    const byte = buffer[i];
    tempBuffer[tempLength++] = byte;

    if ((byte & 0x80) === 0x00) {
      result += tempBuffer.toString('utf8', 0, 1);
      tempLength = 0;
    } else if ((byte & 0xE0) === 0xC0) {
      if (tempLength >= 2) {
        result += tempBuffer.toString('utf8', 0, 2);
        tempLength = 0;
      }
    } else if ((byte & 0xF0) === 0xE0) {
      if (tempLength >= 3) {
        result += tempBuffer.toString('utf8', 0, 3);
        tempLength = 0;
      }
    } else if ((byte & 0xF8) === 0xF0) {
      if (tempLength >= 4) {
        result += tempBuffer.toString('utf8', 0, 4);
        tempLength = 0;
      }
    }
  }

  if (tempLength > 0) {
    try {
      result += tempBuffer.toString('utf8', 0, tempLength);
    } catch (e) {
      // Ignore incomplete character
    }
  }

  return result;
}

