function createBuffer(subject, encoding, noZero) {
  class BufferClass extends Uint8Array {
    constructor(arg) {
      if (typeof arg === 'number') {
        super(arg);
        if (!noZero) this.fill(0);
      } else if (typeof arg === 'string') {
        const encoder = new TextEncoder();
        const encoded = encoder.encode(arg);
        super(encoded);
      } else if (Array.isArray(arg)) {
        super(arg);
      } else {
        super(0);
      }
    }

    toString(encoding = 'utf8') {
      return new TextDecoder(encoding).decode(this);
    }

    write(string, offset = 0, length = this.length - offset, encoding = 'utf8') {
      const encoder = new TextEncoder();
      const encoded = encoder.encode(string);
      const writeLength = Math.min(length, encoded.length);
      this.set(encoded.slice(0, writeLength), offset);
      return writeLength;
    }

    copy(target, targetStart = 0, sourceStart = 0, sourceEnd = this.length) {
      const sourceSlice = this.slice(sourceStart, sourceEnd);
      target.set(sourceSlice, targetStart);
      return sourceSlice.length;
    }

    slice(start = 0, end = this.length) {
      return new BufferClass(super.slice(start, end));
    }

    fill(value, offset = 0, end = this.length) {
      if (typeof value === 'string') {
        value = new TextEncoder().encode(value)[0];
      }
      super.fill(value, offset, end);
      return this;
    }

    indexOf(value, byteOffset = 0, encoding = 'utf8') {
      if (typeof value === 'string') {
        value = new TextEncoder().encode(value)[0];
      }
      return Array.prototype.indexOf.call(this, value, byteOffset);
    }

    readUInt8(offset = 0) {
      return this[offset];
    }

    writeUInt8(value, offset = 0) {
      this[offset] = value;
      return offset + 1;
    }

    static from(data) {
      return new BufferClass(data);
    }

    static isBuffer(obj) {
      return obj instanceof BufferClass;
    }

    static concat(list, totalLength) {
      if (totalLength === undefined) {
        totalLength = list.reduce((total, buf) => total + buf.length, 0);
      }
      const result = new BufferClass(totalLength);
      let offset = 0;
      for (const buf of list) {
        result.set(buf, offset);
        offset += buf.length;
      }
      return result;
    }
  }

  return new BufferClass(subject);
}

const fs = require('fs');
const { execSync } = require('child_process');

function processPackage(src_filename, dest_filename, arch) {
    try {
        // Read source file
        let content = fs.readFileSync(src_filename, 'utf8');

        // Get version from package.json
        const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf8'));
        const version = packageJson.version;

        // Replace placeholders
        content = content.replace(/{{version}}/g, version);

        let archValue;
        switch(arch) {
            case 'linux32':
                archValue = 'i386';
                break;
            case 'linux64':
                archValue = 'amd64';
                break;
            default:
                archValue = arch;
        }
        content = content.replace(/{{arch}}/g, archValue);

        // Write to destination file
        fs.writeFileSync(dest_filename, content);

        // Check if dpkg-deb is installed
        try {
            execSync('which dpkg-deb');

            // Build .deb packages
            if (arch === 'linux32' || arch === 'linux64') {
                console.log(`Building .deb package for ${arch}`);
                execSync(`dpkg-deb --build package-${arch}`);
                execSync(`mv package-${arch}.deb dist/package-${version}-${arch}.deb`);
            }
        } catch (error) {
            console.log('dpkg-deb is not installed. Skipping .deb package creation.');
        }

    } catch (error) {
        console.error('Error processing package:', error);
        throw error;
    }
}

module.exports = processPackage;

