function parseMetaEvent(stream) {
    const eventType = stream.readUInt8();
    const length = stream.readUInt8();

    let event = {};

    switch(eventType) {
        case 0x58: // Time Signature
            if (length !== 4) {
                throw new Error('Expected length of 4 for time signature event');
            }
            event.subtype = 'timeSignature';
            event.numerator = stream.readUInt8();
            event.denominator = Math.pow(2, stream.readUInt8());
            event.metronome = stream.readUInt8();
            event.thirtyseconds = stream.readUInt8();
            break;

        case 0x59: // Key Signature
            if (length !== 2) {
                throw new Error('Expected length of 2 for key signature event');
            }
            event.subtype = 'keySignature';
            event.key = stream.readInt8();
            event.scale = stream.readUInt8();
            break;

        case 0x7F: // Sequencer Specific
            event.subtype = 'sequencerSpecific';
            event.data = [];
            for (let i = 0; i < length; i++) {
                event.data.push(stream.readUInt8());
            }
            break;

        default:
            event.subtype = 'unknown';
            console.error(`Unknown meta event type: ${eventType}`);
            // Skip unknown data
            for (let i = 0; i < length; i++) {
                stream.readUInt8();
            }
    }

    return event;
}
