function findUniqueTokens(str1, str2) {
    const tokens1 = str1.split(' ');
    const tokens2 = str2.split(' ');
    let uniqueTokens = [];

    for (let i = 0; i < tokens1.length; i++) {
        let isUnique = true;
        for (let j = 0; j < tokens2.length; j++) {
            if (tokens1[i] === tokens2[j]) {
                isUnique = false;
                continue;
            }
        }
        if (isUnique) {
            uniqueTokens.push(tokens1[i]);
        }
    }

    return uniqueTokens.join(' ');
}

function copyBuffer(n, list) {
  const buffer = Buffer.allocUnsafe(n);
  let offset = 0;
  let source = list;
  let length = n;

  while (length > 0 && source) {
    const chunk = source.data;
    const copied = Math.min(chunk.length, length);
    chunk.copy(buffer, offset, 0, copied);
    offset += copied;
    length -= copied;
    source = source.next;
  }

  return buffer;
}

public void generateRandomGraph() {
    Random random = new Random();
    int numVertices = random.nextInt(20) + 5;  // 5-25 vertices
    int numEdges = random.nextInt(numVertices * 2) + numVertices;  // At least one edge per vertex

    // Add vertices
    for (int i = 0; i < numVertices; i++) {
        Vertex v = graph.addVertex();
        v.property("id", i);
        v.property("value", random.nextInt(100));
        v.property("name", "vertex" + i);
        v.property("active", random.nextBoolean());
        v.property("weight", random.nextDouble());
    }

    // Add edges
    List<Vertex> vertices = new ArrayList<>(graph.traversal().V().toList());
    for (int i = 0; i < numEdges; i++) {
        Vertex v1 = vertices.get(random.nextInt(vertices.size()));
        Vertex v2 = vertices.get(random.nextInt(vertices.size()));

        if (v1 != v2) {
            Edge e = v1.addEdge("connects", v2);
            e.property("weight", random.nextDouble());
            e.property("timestamp", System.currentTimeMillis());
            e.property("strength", random.nextInt(10));
            e.property("active", random.nextBoolean());
        }
    }
}

import org.apache.mina.core.service.IoHandlerAdapter;
import org.apache.mina.core.session.IoSession;
import org.apache.mina.core.future.WriteFuture;
import org.apache.mina.core.future.IoFutureListener;
import java.net.InetSocketAddress;
import java.net.SocketAddress;

public class CustomIoHandler extends IoHandlerAdapter {

    @Override
    public void messageSent(IoSession session, Object message) {
        WriteFuture future = session.write(message);
        future.addListener(new IoFutureListener<WriteFuture>() {
            @Override
            public void operationComplete(WriteFuture future) {
                if (future.isWritten()) {
                    System.out.println("Message sent successfully");
                } else {
                    System.out.println("Failed to send message: " + future.getException());
                }
            }
        });
    }

    public SocketAddress setSocketAddress(String protocol, String host, int port) {
        if ("tcp".equalsIgnoreCase(protocol) || "udp".equalsIgnoreCase(protocol)) {
            return new InetSocketAddress(host, port);
        } else {
            throw new IllegalArgumentException("Unsupported protocol: " + protocol);
        }
    }
}

public static double[] mutateValue(Random random, double value, double stdDevFactor) {
    double stdDev = Math.abs(value * stdDevFactor);
    double mutatedValue = random.nextGaussian() * stdDev + value;

    int numDiscreteValues = 10;
    double[] discreteValues = new double[numDiscreteValues];
    double range = 4 * stdDev;
    double step = range / (numDiscreteValues - 1);

    for (int i = 0; i < numDiscreteValues; i++) {
        discreteValues[i] = value - (2 * stdDev) + (i * step);
    }

    double[] result = new double[numDiscreteValues + 1];
    result[0] = mutatedValue;
    System.arraycopy(discreteValues, 0, result, 1, numDiscreteValues);

    return result;
}

