                Float f = (Float) element;
                System.out.println("Float value: " + f);
                System.out.println("isFinite: " + Float.isFinite(f));
                System.out.println("isInfinite: " + Float.isInfinite(f));
                System.out.println("isNaN: " + Float.isNaN(f));
                System.out.println("Hex string: " + Float.toHexString(f));
            } else if (element instanceof Double) {
                Double d = (Double) element;
                System.out.println("Double value: " + d);
                System.out.println("isFinite: " + Double.isFinite(d));
                System.out.println("isInfinite: " + Double.isInfinite(d));
                System.out.println("isNaN: " + Double.isNaN(d));
                System.out.println("Hex string: " + Double.toHexString(d));
            } else if (element instanceof Long) {
                Long l = (Long) element;
                System.out.println("Long value: " + l);
                System.out.println("Hex string: " + Long.toHexString(l));
                System.out.println("Binary string: " + Long.toBinaryString(l));
                System.out.println("Octal string: " + Long.toOctalString(l));
            } else if (element instanceof Integer) {
                Integer i = (Integer) element;
                System.out.println("Integer value: " + i);
                System.out.println("Hex string: " + Integer.toHexString(i));
                System.out.println("Binary string: " + Integer.toBinaryString(i));
                System.out.println("Octal string: " + Integer.toOctalString(i));
                System.out.println("Unsigned int: " + Integer.toUnsignedString(i));
            }
            System.out.println("-------------------");
        }
    }
}

@SuppressWarnings("unchecked")
public static <T> T getRandomValue(Class<T> type, Random random) {
    switch (type.getSimpleName()) {
        case "Integer":
            return (T) Integer.valueOf(random.nextInt(100));
        case "Double":
            return (T) Double.valueOf(random.nextDouble() * 100);
        case "Boolean":
            return (T) Boolean.valueOf(random.nextBoolean());
        case "String":
            String chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
            StringBuilder sb = new StringBuilder();
            for (int i = 0; i < 10; i++) {
                sb.append(chars.charAt(random.nextInt(chars.length())));
            }
            return (T) sb.toString();
        case "Long":
            return (T) Long.valueOf(random.nextLong());
        case "Float":
            return (T) Float.valueOf(random.nextFloat() * 100);
        default:
            throw new IllegalArgumentException("Unsupported type: " + type.getSimpleName());
    }
}

public class JsonGenerator {
    public enum Type {
        OBJECT,
        GEO_POINT,
        GEO_SHAPE
    }

    public static String generateJson(Object obj, Type type) {
        StringBuilder json = new StringBuilder();

        switch (type) {
            case OBJECT:
                json.append("{")
                    .append("\"first_name\":\"John\",")
                    .append("\"last_name\":\"Doe\",")
                    .append("\"ssn\":\"123-45-6789\"")
                    .append("}");
                break;

            case GEO_POINT:
                json.append("{")
                    .append("\"lat\":40.7128,")
                    .append("\"lon\":-74.0060")
                    .append("}");
                break;

            case GEO_SHAPE:
                json.append("{")
                    .append("\"type\":\"polygon\",")
                    .append("\"coordinates\":[")
                    .append("[[-77.0,38.8],")
                    .append("[-77.1,38.9],")
                    .append("[-77.0,39.0],")
                    .append("[-77.0,38.8]]")
                    .append("]")
                    .append("}");
                break;

            default:
                json.append("{}");
                break;
        }

        return json.toString();
    }
}

public String generatePassword(int length) {
    if (length < 4) {
        throw new IllegalArgumentException("Password length must be at least 4 characters");
    }

    String upperChars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    String lowerChars = "abcdefghijklmnopqrstuvwxyz";
    String numbers = "0123456789";
    String specialChars = "!@#$%^&*()_+-=[]{}|;:,.<>?";
    String allChars = upperChars + lowerChars + numbers + specialChars;

    Random random = new Random();
    StringBuilder password = new StringBuilder();

    // Ensure password starts with a letter
    password.append(lowerChars.charAt(random.nextInt(lowerChars.length())));

    // Generate middle part of password
    for (int i = 1; i < length - 2; i++) {
        password.append(allChars.charAt(random.nextInt(allChars.length())));
    }

    // Ensure second-to-last character is a number
    password.append(numbers.charAt(random.nextInt(numbers.length())));

    // Ensure last character is a special character
    password.append(specialChars.charAt(random.nextInt(specialChars.length())));

    return password.toString();
}

@SuppressWarnings("unchecked")
public static <T> T generateRandomValue(Random random, Class<T> type) {
    if (type == Byte.class || type == byte.class) {
        return (T) Byte.valueOf((byte) random.nextInt(Byte.MAX_VALUE + 1));
    } else if (type == Short.class || type == short.class) {
        return (T) Short.valueOf((short) random.nextInt(Short.MAX_VALUE + 1));
    } else if (type == Integer.class || type == int.class) {
        return (T) Integer.valueOf(random.nextInt());
    } else if (type == Long.class || type == long.class) {
        return (T) Long.valueOf(random.nextLong());
    } else if (type == Float.class || type == float.class) {
        return (T) Float.valueOf(random.nextFloat());
    } else if (type == Double.class || type == double.class) {
        return (T) Double.valueOf(random.nextDouble());
    } else if (type == Character.class || type == char.class) {
        return (T) Character.valueOf((char) random.nextInt(Character.MAX_VALUE + 1));
    } else if (type == String.class) {
        int length = random.nextInt(20) + 1;
        StringBuilder sb = new StringBuilder(length);
        for (int i = 0; i < length; i++) {
            sb.append((char) (random.nextInt(26) + 'a'));
        }
        return (T) sb.toString();
    } else if (type == BigDecimal.class) {
        return (T) BigDecimal.valueOf(random.nextDouble() * random.nextInt(1000));
    } else {
        throw new IllegalArgumentException("Unsupported type: " + type.getName());
    }
}

public class UnsignedConverter {
    public static long[] convertToUnsigned(int[] input) {
        if (input == null) {
            return null;
        }

        long[] result = new long[input.length];
        for (int i = 0; i < input.length; i++) {
            result[i] = Integer.toUnsignedLong(input[i]);
        }
        return result;
    }

    public static BigInteger[] convertToUnsigned(long[] input) {
        if (input == null) {
            return null;
        }

        BigInteger[] result = new BigInteger[input.length];
        for (int i = 0; i < input.length; i++) {
            result[i] = Long.toUnsignedBigInteger(input[i]);
        }
        return result;
    }

    public static int[] convertToUnsignedByte(byte[] input) {
        if (input == null) {
            return null;
        }

        int[] result = new int[input.length];
        for (int i = 0; i < input.length; i++) {
            result[i] = Byte.toUnsignedInt(input[i]);
        }
        return result;
    }

    public static int[] convertToUnsignedShort(short[] input) {
        if (input == null) {
            return null;
        }

        int[] result = new int[input.length];
        for (int i = 0; i < input.length; i++) {
            result[i] = Short.toUnsignedInt(input[i]);
        }
        return result;
    }
}

public void processListOfPairs(List<Pair<Integer, Boolean>> pairs, double percentageToProcess) {
    Random random = new Random();
    int totalIterations = (int) (pairs.size() * (percentageToProcess / 100.0));
    int currentIteration = 0;

    for (int i = 0; i < pairs.size() && currentIteration < totalIterations; i++) {
        Pair<Integer, Boolean> currentPair = pairs.get(i);
        boolean isLastPair = (i == pairs.size() - 1);

        System.out.println("Processing pair at position " + i + 
                          " (Last pair: " + isLastPair + ")");

        if (!isLastPair) {
            int randomPreviousPosition = random.nextInt(i + 1);
            if (randomPreviousPosition != i) {
                pairs.remove(i);
                pairs.add(randomPreviousPosition, currentPair);
                System.out.println("Moved pair from position " + i + 
                                 " to position " + randomPreviousPosition);
            }
        }

        currentIteration++;
    }
}

private void performRandomOperations(Node node) {
    Random random = new Random();
    int expectedHeartbeats = 0;
    int expectedClears = 0;
    int actualHeartbeats = 0;
    int actualClears = 0;

    for (int i = 0; i < 100; i++) {
        boolean isHeartbeat = random.nextBoolean();

        if (isHeartbeat) {
            expectedHeartbeats++;
            try {
                node.reportHeartbeat();
                actualHeartbeats++;
            } catch (Exception e) {
                logger.error("Failed to report heartbeat", e);
            }
        } else {
            expectedClears++;
            try {
                node.clearPrimary();
                actualClears++;
            } catch (Exception e) {
                logger.error("Failed to clear primary", e);
            }
        }
    }

    int heartbeatDiff = expectedHeartbeats - actualHeartbeats;
    int clearDiff = expectedClears - actualClears;

    logger.info("Operation differences - Heartbeats: {} (expected: {}, actual: {}), Clears: {} (expected: {}, actual: {})",
        heartbeatDiff, expectedHeartbeats, actualHeartbeats,
        clearDiff, expectedClears, actualClears);
}

private void generateRandomFields(String[] availableTypes) {
    Random random = new Random();
    int numFields = random.nextInt(9) + 1;
    String[] selectedTypes = new String[numFields];
    boolean includeNulls = random.nextBoolean();
    boolean ascending = random.nextBoolean();

    Set<Integer> usedIndices = new HashSet<>();
    for (int i = 0; i < numFields; i++) {
        int index;
        do {
            index = random.nextInt(availableTypes.length);
        } while (usedIndices.contains(index));
        usedIndices.add(index);
        selectedTypes[i] = availableTypes[index];
    }

    if (includeNulls) {
        int nullCount = random.nextInt(numFields + 1);
        String[] withNulls = Arrays.copyOf(selectedTypes, numFields + nullCount);
        for (int i = numFields; i < withNulls.length; i++) {
            withNulls[i] = null;
        }
        selectedTypes = withNulls;
    }

    processFields(selectedTypes, ascending);
}

import com.codahale.metrics.Gauge;
import com.codahale.metrics.MetricRegistry;
import com.codahale.metrics.graphite.Graphite;
import com.codahale.metrics.graphite.GraphiteReporter;

import java.net.InetSocketAddress;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.TimeUnit;

public class MetricNotificationService {
    private static MetricNotificationService instance;
    private final GraphiteReporter graphiteReporter;
    private final MetricRegistry metricRegistry;
    private Map<String, MetricGauge> metricMap;

    public static MetricNotificationService get() {
        if (instance == null) {
            instance = new MetricNotificationService();
        }
        return instance;
    }

    private MetricNotificationService() {
        final Graphite graphite = new Graphite(new InetSocketAddress("localhost", 2003));
        this.metricRegistry = new MetricRegistry();
        this.metricMap = new HashMap<>();

        this.graphiteReporter = GraphiteReporter.forRegistry(metricRegistry)
                .convertDurationsTo(TimeUnit.SECONDS)
                .build(graphite);

        graphiteReporter.start(1, TimeUnit.MINUTES);
    }

    public void registerMetric(String name, MetricGauge gauge) {
        if (!metricMap.containsKey(name)) {
            metricMap.put(name, gauge);
            metricRegistry.register(name, new Gauge<Long>() {
                @Override
                public Long getValue() {
                    return gauge.getValue();
                }
            });
        }
    }
}

