public List<InetSocketAddress> createAddresses(List<String> hostsAndPorts, String username, 
        String password, String serverId, boolean createEnrichmentConnection, 
        String driverLocation, String driverName, int connectionTimeout) 
        throws ArrayIndexOutOfBoundsException {

    List<InetSocketAddress> addresses = new ArrayList<>();

    for (String hostAndPort : hostsAndPorts) {
        String[] parts = hostAndPort.split(":");
        if (parts.length != 2) {
            throw new ArrayIndexOutOfBoundsException(
                "Invalid host:port format: " + hostAndPort);
        }

        String host = parts[0].trim();
        int port;

        try {
            port = Integer.parseInt(parts[1].trim());
        } catch (NumberFormatException e) {
            throw new IllegalArgumentException(
                "Invalid port number: " + parts[1]);
        }

        if (port < 0 || port > 65535) {
            throw new IllegalArgumentException(
                "Port number out of range (0-65535): " + port);
        }

        addresses.add(new InetSocketAddress(host, port));
    }

    return addresses;
}

