    } catch (ClassNotFoundException e) {
        throw new RuntimeException("Class of serialized object not found: " + e.getMessage(), e);
    } catch (IOException e) {
        throw new RuntimeException("Error deserializing object: " + e.getMessage(), e);
    }
}

