public void processNumericArray(double[] numbers) {
    BigDecimal[] decimals = new BigDecimal[numbers.length];
    Float[] floats = new Float[numbers.length];
    Double[] doubles = new Double[numbers.length];

    for (int i = 0; i < numbers.length; i++) {
        decimals[i] = BigDecimal.valueOf(numbers[i]);
        floats[i] = Float.valueOf((float) numbers[i]);
        doubles[i] = Double.valueOf(numbers[i]);
    }

    testBatch(decimals, BigDecimal.class);
    testBatch(floats, Float.class);
    testBatch(doubles, Double.class);
}

private <T extends Number> void testBatch(T[] values, Class<T> type) {
    for (T value : values) {
        if (type == BigDecimal.class) {
            BigDecimal bd = (BigDecimal) value;
            bd = bd.add(BigDecimal.ONE);
            bd = bd.multiply(BigDecimal.valueOf(2));
        } else if (type == Float.class) {
            float f = value.floatValue();
            f = Math.nextUp(f);
            f = f * 2.0f;
        } else if (type == Double.class) {
            double d = value.doubleValue();
            d = Math.nextUp(d);
            d = d * 2.0;
        }
    }
}

private Path writeRandomBinaryData(FileSystem fs, Path folder, String fileName, long length) throws IOException {
    Path file = folder.resolve(fileName);
    Random random = new Random();
    byte[] buffer = new byte[4096];
    long remaining = length;

    try (OutputStream out = fs.newOutputStream(file, StandardOpenOption.CREATE, 
            StandardOpenOption.WRITE)) {
        while (remaining > 0) {
            if (random.nextBoolean() && remaining > 1) {
                // Write multiple bytes
                int bytesToWrite = (int) Math.min(remaining, buffer.length);
                random.nextBytes(buffer);
                out.write(buffer, 0, bytesToWrite);
                remaining -= bytesToWrite;
            } else {
                // Write single byte
                out.write(random.nextInt(256));
                remaining--;
            }
        }
        out.flush();
    }

    return file;
}

public class ArrayTransformer {
    public static <T, R> R[] transformArray(T[] inputArray, Function<T, R> transformer, Class<R> outputType) {
        if (inputArray == null || inputArray.length == 0) {
            @SuppressWarnings("unchecked")
            R[] emptyArray = (R[]) Array.newInstance(outputType, 0);
            return emptyArray;
        }

        @SuppressWarnings("unchecked")
        R[] resultArray = (R[]) Array.newInstance(outputType, inputArray.length);

        for (int i = 0; i < inputArray.length; i++) {
            resultArray[i] = transformer.apply(inputArray[i]);
        }

        return resultArray;
    }
}

