import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import java.io.File;
import java.util.HashMap;
import java.util.Map;

public class ThemeCacheManager {
    private static final String DEFAULT_THEME_DIR = "/data/themes/default/";
    private String themeDirectory;
    private Bitmap themeBitmap;
    private Map<String, Bitmap> themeCache;

    public ThemeCacheManager() {
        themeCache = new HashMap<>();
    }

    public void cleanupThemeBitmap() {
        if (themeBitmap != null && !themeBitmap.isRecycled()) {
            themeBitmap.recycle();
            themeBitmap = null;
        }
    }

    public void setDefaultThemeDirectory() {
        if (themeDirectory == null || themeDirectory.isEmpty()) {
            themeDirectory = DEFAULT_THEME_DIR;
        }
    }

    public void loadThemeFromCache(String cacheRoot, String themeName) {
        try {
            File themeFile = new File(cacheRoot + File.separator + themeName + ".png");
            if (themeFile.exists()) {
                cleanupThemeBitmap();
                themeBitmap = BitmapFactory.decodeFile(themeFile.getAbsolutePath());
                if (themeBitmap != null) {
                    themeCache.put(themeName, themeBitmap);
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    public Bitmap getThemeFromCache(String themeName) {
        return themeCache.get(themeName);
    }

    public void clearThemeCache() {
        for (Bitmap bitmap : themeCache.values()) {
            if (bitmap != null && !bitmap.isRecycled()) {
                bitmap.recycle();
            }
        }
        themeCache.clear();
    }

    public String getThemeDirectory() {
        return themeDirectory;
    }

    public void setThemeDirectory(String directory) {
        this.themeDirectory = directory;
    }

    public boolean isThemeCached(String themeName) {
        return themeCache.containsKey(themeName) && 
               themeCache.get(themeName) != null && 
               !themeCache.get(themeName).isRecycled();
    }
}
