public SortedBinaryDocValues compareFieldData(Random random, LeafReaderContext context, 
        IndexFieldData<?> firstField, IndexFieldData<?> secondField, Preprocessor preprocessor) {

    SortedBinaryDocValues firstValues = firstField.load(context).getBytesValues();
    SortedBinaryDocValues secondValues = secondField.load(context).getBytesValues();

    int maxDoc = context.reader().maxDoc();
    BitSet matchedDocs = new BitSet(maxDoc);

    for (int docId = 0; docId < maxDoc; docId++) {
        if (firstValues.advanceExact(docId) && secondValues.advanceExact(docId)) {
            BytesRef firstRef = firstValues.nextValue();
            BytesRef secondRef = secondValues.nextValue();

            byte[] firstBytes = Arrays.copyOf(firstRef.bytes, firstRef.length);
            byte[] secondBytes = Arrays.copyOf(secondRef.bytes, secondRef.length);

            preprocessor.process(firstBytes);
            preprocessor.process(secondBytes);

            int comparison = Arrays.binarySearch(firstBytes, secondBytes[0]);
            if (comparison >= 0) {
                matchedDocs.set(docId);
            }
        }
    }

    return new SortedBinaryDocValues() {
        private int currentDoc = -1;

        @Override
        public boolean advanceExact(int target) {
            currentDoc = target;
            return matchedDocs.get(target);
        }

        @Override
        public int docID() {
            return currentDoc;
        }

        @Override
        public int nextDoc() {
            return currentDoc = matchedDocs.nextSetBit(currentDoc + 1);
        }

        @Override
        public BytesRef nextValue() {
            return new BytesRef(String.valueOf(currentDoc));
        }

        @Override
        public int valueCount() {
            return 1;
        }
    };
}

