                iterationRandom.nextInt(65535),
                iterationRandom.nextInt(65535)
            );

            DatanodeRegistration registration = new DatanodeRegistration(
                datanodeId,
                new StorageInfo(
                    HdfsConstants.LAYOUT_VERSION,
                    HdfsConstants.NAMESPACE_ID,
                    HdfsConstants.CLUSTER_ID,
                    HdfsConstants.BLOCK_POOL_ID
                ),
                ExportedBlockKeys.DUMMY_KEYS,
                "Test"
            );

            storageMap.put(storageId, registration);
        }

        try {
            datanodeManager.registerDatanode(storageMap.values().iterator().next());

            for (Map.Entry<String, DatanodeRegistration> entry : storageMap.entrySet()) {
                DatanodeDescriptor descriptor = 
                    datanodeManager.getDatanode(entry.getValue());
                if (descriptor != null) {
                    datanodeManager.handleHeartbeat(
                        descriptor,
                        0L,
                        0L,
                        0L,
                        0L,
                        0,
                        0,
                        0,
                        null,
                        true
                    );
                }
            }
        } catch (IOException e) {
            LOG.error("Error processing datanode registration", e);
        }

        try {
            Thread.sleep(100);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            break;
        }
    }
}
