public static InputStream getResourceAsStream(String resourceUrl) throws IOException {
    try {
        if (resourceUrl.startsWith("http://") || resourceUrl.startsWith("https://")) {
            URL url = new URL(resourceUrl);
            return url.openStream();
        } else {
            ClassLoader classLoader = Thread.currentThread().getContextClassLoader();
            InputStream inputStream = classLoader.getResourceAsStream(resourceUrl);

            if (inputStream == null) {
                File file = new File(resourceUrl);
                if (file.exists()) {
                    return new FileInputStream(file);
                } else {
                    throw new FileNotFoundException("Resource not found: " + resourceUrl);
                }
            }

            return inputStream;
        }
    } catch (MalformedURLException e) {
        throw new IOException("Invalid URL format: " + resourceUrl, e);
    }
}

