import java.util.*;
import java.util.concurrent.atomic.AtomicInteger;

class Graph {
    private int vertices;
    private List<List<Integer>> adjacencyList;
    private Set<Integer> visited;
    private AtomicInteger vertexCount;
    private AtomicInteger edgeCount;
    private AtomicInteger completedThreads;

    public Graph(int vertices) {
        this.vertices = vertices;
        adjacencyList = new ArrayList<>(vertices);
        visited = Collections.synchronizedSet(new HashSet<>());
        vertexCount = new AtomicInteger(vertices);
        edgeCount = new AtomicInteger(0);
        completedThreads = new AtomicInteger(0);

        for (int i = 0; i < vertices; i++) {
            adjacencyList.add(new ArrayList<>());
        }
    }

    public synchronized void addEdge(int source, int destination) {
        adjacencyList.get(source).add(destination);
        adjacencyList.get(destination).add(source);
        edgeCount.incrementAndGet();
    }

    public void traverseGraph(int startVertex) {
        if (!visited.contains(startVertex)) {
            visited.add(startVertex);
            System.out.println("Thread " + Thread.currentThread().getName() + " visited vertex " + startVertex);

            List<Integer> neighbors = adjacencyList.get(startVertex);
            for (Integer neighbor : neighbors) {
                traverseGraph(neighbor);
            }
        }
    }

    public AtomicInteger getVertexCount() {
        return vertexCount;
    }

    public AtomicInteger getEdgeCount() {
        return edgeCount;
    }

    public AtomicInteger getCompletedThreads() {
        return completedThreads;
    }
}

class GraphTraverser extends Thread {
    private Graph graph;
    private int startVertex;

    public GraphTraverser(Graph graph, int startVertex, String name) {
        super(name);
        this.graph = graph;
        this.startVertex = startVertex;
    }

    @Override
    public void run() {
        graph.traverseGraph(startVertex);
        graph.getCompletedThreads().incrementAndGet();
    }
}

public class ConcurrentGraphTraversal {
    public static void main(String[] args) {
        Graph graph = new Graph(6);

        graph.addEdge(0, 1);
        graph.addEdge(0, 2);
        graph.addEdge(1, 3);
        graph.addEdge(2, 3);
        graph.addEdge(3, 4);
        graph.addEdge(4, 5);

        List<GraphTraverser> traversers = new ArrayList<>();
        traversers.add(new GraphTraverser(graph, 0, "Thread-1"));
        traversers.add(new GraphTraverser(graph, 3, "Thread-2"));
        traversers.add(new GraphTraverser(graph, 5, "Thread-3"));

        for (GraphTraverser traverser : traversers) {
            traverser.start();
        }

        for (GraphTraverser traverser : traversers) {
            try {
                traverser.join();
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }

        System.out.println("\nGraph Statistics:");
        System.out.println("Number of vertices: " + graph.getVertexCount());
        System.out.println("Number of edges: " + graph.getEdgeCount());
        System.out.println("Completed threads: " + graph.getCompletedThreads());
    }
}
