import java.io.*;

public class CommandExecutor {
    public static void main(String[] args) {
        String command = "ls -l";
        String[] envp = {"PATH=/usr/bin:/bin"};
        File workingDir = new File("/tmp");
        File fileToDelete = new File("/tmp/test.txt");

        try {
            if (fileToDelete.exists()) {
                fileToDelete.delete();
            }

            Process process = Runtime.getRuntime().exec(command, envp, workingDir);

            BufferedReader stdInput = new BufferedReader(new InputStreamReader(process.getInputStream()));
            BufferedReader stdError = new BufferedReader(new InputStreamReader(process.getErrorStream()));

            String line;
            System.out.println("Standard output:");
            while ((line = stdInput.readLine()) != null) {
                System.out.println(line);
            }

            System.out.println("\nStandard error:");
            while ((line = stdError.readLine()) != null) {
                System.out.println(line);
            }

            int exitCode = process.waitFor();
            System.out.println("\nProcess exited with code: " + exitCode);

            stdInput.close();
            stdError.close();
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }
}
