public class JsonGenerator {
    public static String toJson(Object obj) {
        if (obj == null) {
            return "null";
        }

        if (obj instanceof String) {
            return "\"" + escapeString((String) obj) + "\"";
        }

        if (obj instanceof Number || obj instanceof Boolean) {
            return obj.toString();
        }

        if (obj instanceof Object[]) {
            return arrayToJson((Object[]) obj);
        }

        if (obj instanceof Iterable<?>) {
            return iterableToJson((Iterable<?>) obj);
        }

        return objectToJson(obj);
    }

    private static String escapeString(String str) {
        StringBuilder sb = new StringBuilder();
        for (char c : str.toCharArray()) {
            switch (c) {
                case '"':
                    sb.append("\\\"");
                    break;
                case '\\':
                    sb.append("\\\\");
                    break;
                case '\b':
                    sb.append("\\b");
                    break;
                case '\f':
                    sb.append("\\f");
                    break;
                case '\n':
                    sb.append("\\n");
                    break;
                case '\r':
                    sb.append("\\r");
                    break;
                case '\t':
                    sb.append("\\t");
                    break;
                default:
                    if (c < ' ') {
                        sb.append(String.format("\\u%04x", (int) c));
                    } else {
                        sb.append(c);
                    }
            }
        }
        return sb.toString();
    }

    private static String arrayToJson(Object[] array) {
        StringBuilder sb = new StringBuilder();
        sb.append("[");
        for (int i = 0; i < array.length; i++) {
            if (i > 0) {
                sb.append(",");
            }
            sb.append(toJson(array[i]));
        }
        sb.append("]");
        return sb.toString();
    }

    private static String iterableToJson(Iterable<?> iterable) {
        StringBuilder sb = new StringBuilder();
        sb.append("[");
        boolean first = true;
        for (Object item : iterable) {
            if (!first) {
                sb.append(",");
            }
            sb.append(toJson(item));
            first = false;
        }
        sb.append("]");
        return sb.toString();
    }

    private static String objectToJson(Object obj) {
        StringBuilder sb = new StringBuilder();
        sb.append("{");
        boolean first = true;

        for (java.lang.reflect.Field field : obj.getClass().getDeclaredFields()) {
            try {
                field.setAccessible(true);
                if (!first) {
                    sb.append(",");
                }
                sb.append("\"").append(field.getName()).append("\":");
                sb.append(toJson(field.get(obj)));
                first = false;
            } catch (IllegalAccessException e) {
                // Skip inaccessible fields
            }
        }

        sb.append("}");
        return sb.toString();
    }
}

import java.util.*;
import java.util.function.Function;

public class WeightNormalizer<T> {
    public Map<T, Double> normalizeWeights(List<T> items, Function<T, Double> weightFunction) {
        if (items == null || items.isEmpty()) {
            return Collections.emptyMap();
        }

        Map<T, Double> weights = new HashMap<>();
        double totalWeight = 0.0;

        // Calculate raw weights and sum
        for (T item : items) {
            double weight = weightFunction.apply(item);
            if (weight < 0) {
                throw new IllegalArgumentException("Weights must be non-negative");
            }
            weights.put(item, weight);
            totalWeight += weight;
        }

        // Normalize weights
        if (totalWeight > 0) {
            for (Map.Entry<T, Double> entry : weights.entrySet()) {
                weights.put(entry.getKey(), entry.getValue() / totalWeight);
            }
        } else {
            // If total weight is 0, assign equal probabilities
            double equalWeight = 1.0 / items.size();
            for (T item : items) {
                weights.put(item, equalWeight);
            }
        }

        return weights;
    }
}

