public class DisjointPairsFinder {
    private static class UnionFind {
        private int[] parent;
        private int[] rank;

        public UnionFind(int size) {
            parent = new int[size];
            rank = new int[size];
            for (int i = 0; i < size; i++) {
                parent[i] = i;
            }
        }

        public int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public void union(int x, int y) {
            int rootX = find(x);
            int rootY = find(y);

            if (rootX != rootY) {
                if (rank[rootX] < rank[rootY]) {
                    parent[rootX] = rootY;
                } else if (rank[rootX] > rank[rootY]) {
                    parent[rootY] = rootX;
                } else {
                    parent[rootY] = rootX;
                    rank[rootX]++;
                }
            }
        }

        public boolean isDisjoint(int x, int y) {
            return find(x) != find(y);
        }
    }

    public static int countDisjointPairs(int[] arr) {
        int n = arr.length;
        UnionFind uf = new UnionFind(n);
        int disjointPairsCount = 0;

        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                long startTime = System.nanoTime();

                if (uf.isDisjoint(i, j)) {
                    disjointPairsCount++;
                    uf.union(i, j);
                }

                long endTime = System.nanoTime();
                System.out.printf("Checking pair (%d, %d) took %.3f ms%n", 
                    arr[i], arr[j], (endTime - startTime) / 1_000_000.0);
            }
        }

        return disjointPairsCount;
    }
}
