public static String generateSHA1Hash(String input) throws NoSuchAlgorithmException {
    MessageDigest digest = MessageDigest.getInstance("SHA-1");
    byte[] hash = digest.digest(input.getBytes(StandardCharsets.UTF_8));

    StringBuilder hexString = new StringBuilder();
    for (byte b : hash) {
        String hex = Integer.toHexString(0xff & b);
        if (hex.length() == 1) {
            hexString.append('0');
        }
        hexString.append(hex);
    }

    return hexString.toString();
}

private RectF calculateRandomCropRect(RectF drawableBounds, RectF viewport) {
    float drawableAspect = drawableBounds.width() / drawableBounds.height();
    float viewportAspect = viewport.width() / viewport.height();

    float cropWidth, cropHeight;
    if (drawableAspect > viewportAspect) {
        cropHeight = drawableBounds.height();
        cropWidth = cropHeight * viewportAspect;
    } else {
        cropWidth = drawableBounds.width();
        cropHeight = cropWidth / viewportAspect;
    }

    float minScale = 0.3f;
    float randomScale = minScale + (float) Math.random() * (1.0f - minScale);

    cropWidth *= randomScale;
    cropHeight *= randomScale;

    float maxOffsetX = drawableBounds.width() - cropWidth;
    float maxOffsetY = drawableBounds.height() - cropHeight;

    float randomOffsetX = (float) Math.random() * maxOffsetX;
    float randomOffsetY = (float) Math.random() * maxOffsetY;

    return new RectF(
        drawableBounds.left + randomOffsetX,
        drawableBounds.top + randomOffsetY,
        drawableBounds.left + randomOffsetX + cropWidth,
        drawableBounds.top + randomOffsetY + cropHeight
    );
}

