private void connectToServer(String host, int port) {
    try {
        InetSocketAddress serverAddress = new InetSocketAddress(host, port);
        SocketChannel socketChannel = SocketChannel.open();
        socketChannel.configureBlocking(false);

        socketChannel.connect(serverAddress);
        Selector selector = Selector.open();
        socketChannel.register(selector, SelectionKey.OP_CONNECT);

        while (true) {
            selector.select();
            Iterator<SelectionKey> keys = selector.selectedKeys().iterator();

            while (keys.hasNext()) {
                SelectionKey key = keys.next();
                keys.remove();

                if (!key.isValid()) {
                    continue;
                }

                if (key.isConnectable()) {
                    SocketChannel channel = (SocketChannel) key.channel();

                    if (channel.isConnectionPending()) {
                        try {
                            channel.finishConnect();
                        } catch (IOException e) {
                            key.cancel();
                            channel.close();
                            throw new RuntimeException("Connection failed", e);
                        }
                    }

                    channel.register(selector, SelectionKey.OP_READ | SelectionKey.OP_WRITE);
                    System.out.println("Connected to: " + channel.getRemoteAddress());
                }

                if (key.isReadable()) {
                    handleRead(key);
                }

                if (key.isWritable()) {
                    handleWrite(key);
                }
            }
        }
    } catch (IOException e) {
        throw new RuntimeException("Error establishing connection", e);
    }
}

private void handleRead(SelectionKey key) throws IOException {
    SocketChannel channel = (SocketChannel) key.channel();
    ByteBuffer buffer = ByteBuffer.allocate(1024);
    int bytesRead = channel.read(buffer);

    if (bytesRead == -1) {
        key.cancel();
        channel.close();
        return;
    }

    buffer.flip();
    byte[] data = new byte[buffer.remaining()];
    buffer.get(data);
    processReceivedData(data);
}

private void handleWrite(SelectionKey key) throws IOException {
    SocketChannel channel = (SocketChannel) key.channel();
    ByteBuffer buffer = (ByteBuffer) key.attachment();

    if (buffer != null && buffer.hasRemaining()) {
        channel.write(buffer);
    }
}

private void processReceivedData(byte[] data) {
    // Process received data here
    String message = new String(data, StandardCharsets.UTF_8);
    System.out.println("Received: " + message);
}

private void configureOpenAPIWithKeycloak(OpenAPI openAPI) {
    Components components = new Components();
    SecurityScheme securityScheme = new SecurityScheme()
        .type(SecurityScheme.Type.OPENIDCONNECT)
        .openIdConnectUrl("${keycloak.auth-server-url}/realms/${keycloak.realm}/.well-known/openid-configuration")
        .flows(new OAuthFlows()
            .authorizationCode(new OAuthFlow()
                .authorizationUrl("${keycloak.auth-server-url}/realms/${keycloak.realm}/protocol/openid-connect/auth")
                .tokenUrl("${keycloak.auth-server-url}/realms/${keycloak.realm}/protocol/openid-connect/token")
                .addExtension("nonce", UUID.randomUUID().toString())
                .scopes(new Scopes()
                    .addString("openid", "OpenID Connect scope")
                    .addString("profile", "Profile information")
                    .addString("email", "Email information"))));

    components.addSecuritySchemes("keycloak", securityScheme);
    openAPI.components(components);

    SecurityRequirement securityRequirement = new SecurityRequirement()
        .addList("keycloak", Arrays.asList("openid", "profile", "email"));
    openAPI.addSecurityItem(securityRequirement);

    Info info = new Info()
        .title("API secured with Keycloak")
        .version("1.0")
        .description("This API is secured using Keycloak authentication");
    openAPI.info(info);
}

private void configureSecuritySchemes(OpenAPI openAPI, String keycloakRealmPath) {
    Components components = openAPI.getComponents();
    if (components == null) {
        components = new Components();
        openAPI.setComponents(components);
    }

    // Configure OIDC security scheme
    SecurityScheme oidcScheme = new SecurityScheme()
        .type(SecurityScheme.Type.OPENIDCONNECT)
        .openIdConnectUrl(keycloakRealmPath + "/.well-known/openid-configuration")
        .description("OpenID Connect Authentication");

    // Configure OAuth2 security scheme with authorization code flow
    OAuthFlow authorizationCodeFlow = new OAuthFlow()
        .authorizationUrl(keycloakRealmPath + "/protocol/openid-connect/auth")
        .tokenUrl(keycloakRealmPath + "/protocol/openid-connect/token")
        .refreshUrl(keycloakRealmPath + "/protocol/openid-connect/token")
        .addParametersItem("nonce", new Parameter().required(true))
        .scopes(new Scopes()
            .addString("openid", "OpenID Connect scope")
            .addString("profile", "Profile information")
            .addString("email", "Email information"));

    SecurityScheme oauth2Scheme = new SecurityScheme()
        .type(SecurityScheme.Type.OAUTH2)
        .flows(new OAuthFlows().authorizationCode(authorizationCodeFlow))
        .description("OAuth2 Authentication");

    // Add security schemes to components
    components.addSecuritySchemes("oidc", oidcScheme);
    components.addSecuritySchemes("oauth2", oauth2Scheme);

    // Add global security requirement
    SecurityRequirement securityRequirement = new SecurityRequirement()
        .addList("oidc")
        .addList("oauth2");

    if (openAPI.getSecurity() == null) {
        openAPI.setSecurity(new ArrayList<>());
    }
    openAPI.getSecurity().add(securityRequirement);
}

