public void comparePointSets(List<List<Double>> set1, List<List<Double>> set2, double tolerance) {
    if (set1.size() != set2.size()) {
        throw new AssertionError("Sets have different number of documents: " + 
            set1.size() + " vs " + set2.size());
    }

    for (int i = 0; i < set1.size(); i++) {
        List<Double> points1 = set1.get(i);
        List<Double> points2 = set2.get(i);

        if (points1.size() != points2.size()) {
            throw new AssertionError("Document " + i + " has different number of points: " + 
                points1.size() + " vs " + points2.size());
        }

        if (points1.size() > 0) {
            // Check values are in increasing order
            for (int j = 1; j < points1.size(); j++) {
                if (points1.get(j) <= points1.get(j-1)) {
                    throw new AssertionError("Values in set 1 document " + i + 
                        " are not in increasing order at index " + j);
                }
            }

            for (int j = 1; j < points2.size(); j++) {
                if (points2.get(j) <= points2.get(j-1)) {
                    throw new AssertionError("Values in set 2 document " + i + 
                        " are not in increasing order at index " + j);
                }
            }

            // Compare points within tolerance
            for (int j = 0; j < points1.size(); j++) {
                double diff = Math.abs(points1.get(j) - points2.get(j));
                if (diff > tolerance) {
                    throw new AssertionError("Points differ by more than tolerance at document " + 
                        i + " index " + j + ": " + points1.get(j) + " vs " + points2.get(j));
                }
            }
        }
    }
}
