public Long registrarEvento(String tipo, String descricao) {
    Evento evento = new Evento();
    evento.setTipo(tipo);
    evento.setDescricao(descricao);
    evento.setDataCriacao(new Date());

    Session session = HibernateUtil.getSessionFactory().openSession();
    Transaction tx = null;
    Long eventoId = null;

    try {
        tx = session.beginTransaction();
        eventoId = (Long) session.save(evento);
        tx.commit();

        FacesContext context = FacesContext.getCurrentInstance();
        context.getResponseWriter().write("Evento registrado com sucesso!");

    } catch (Exception e) {
        if (tx != null) {
            tx.rollback();
        }
        throw new RuntimeException("Erro ao registrar evento: " + e.getMessage());
    } finally {
        session.close();
    }

    return eventoId;
}

private void sendEmail(boolean success, Activity activity, String subject) {
    WeakReference<Activity> activityRef = new WeakReference<>(activity);

    activityRef.get().runOnUiThread(() -> {
        Activity currentActivity = activityRef.get();
        if (currentActivity != null) {
            Intent emailIntent = new Intent(Intent.ACTION_SEND);
            emailIntent.setType("message/rfc822");
            emailIntent.putExtra(Intent.EXTRA_SUBJECT, subject);
            try {
                currentActivity.startActivity(Intent.createChooser(emailIntent, "Send email..."));
            } catch (ActivityNotFoundException e) {
                // Handle the case where no email app is available
            }
        }
    });
