public class DelegationTokenManager {
    private DelegationTokenManagerService tokenService;

    public String createDelegationToken(String username, String password, String tokenId) {
        try {
            UserCredentials credentials = new UserCredentials(username, password);
            DelegationToken token = tokenService.createToken(credentials, tokenId);
            return token.getTokenValue();
        } catch (TokenException e) {
            throw new RuntimeException("Failed to create delegation token", e);
        }
    }

    public boolean verifyDelegationToken(String tokenValue) {
        try {
            return tokenService.verifyToken(tokenValue);
        } catch (TokenException e) {
            return false;
        }
    }

    public boolean renewDelegationToken(String tokenValue) {
        try {
            DelegationToken renewedToken = tokenService.renewToken(tokenValue);
            return renewedToken != null;
        } catch (TokenException e) {
            return false;
        }
    }

    public void cancelDelegationToken(String tokenValue) {
        try {
            tokenService.cancelToken(tokenValue);
        } catch (TokenException e) {
            throw new RuntimeException("Failed to cancel delegation token", e);
        }
    }

    private static class UserCredentials {
        private String username;
        private String password;

        public UserCredentials(String username, String password) {
            this.username = username;
            this.password = password;
        }

        public String getUsername() {
            return username;
        }

        public String getPassword() {
            return password;
        }
    }

    private static class DelegationToken {
        private String tokenValue;
        private String tokenId;
        private long expirationTime;

        public String getTokenValue() {
            return tokenValue;
        }

        public String getTokenId() {
            return tokenId;
        }

        public long getExpirationTime() {
            return expirationTime;
        }
    }

    private static class TokenException extends Exception {
        public TokenException(String message) {
            super(message);
        }
    }
}
