public void savePulseToDatabase(Pulse pulse, int tableIndex) throws SQLException {
    String sql = "INSERT INTO pulse_table (table_index, timestamp, pulse_data) VALUES (?, ?, ?)";

    try (Connection connection = DriverManager.getConnection("jdbc:mysql://localhost:3306/pulsedb", "username", "password");
         PreparedStatement statement = connection.prepareStatement(sql)) {

        byte[] pulseData = serializePulse(pulse);
        Blob blob = connection.createBlob();
        blob.setBytes(1, pulseData);

        statement.setInt(1, tableIndex);
        statement.setTimestamp(2, new Timestamp(System.currentTimeMillis()));
        statement.setBlob(3, blob);

        statement.executeUpdate();
        blob.free();

    } catch (SQLException e) {
        throw new SQLException("Failed to save pulse to database: " + e.getMessage(), e);
    }
}

private byte[] serializePulse(Pulse pulse) throws SQLException {
    try (ByteArrayOutputStream baos = new ByteArrayOutputStream();
         ObjectOutputStream oos = new ObjectOutputStream(baos)) {

        oos.writeObject(pulse);
        return baos.toByteArray();

    } catch (IOException e) {
        throw new SQLException("Failed to serialize pulse: " + e.getMessage(), e);
    }
}

