import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.IOException;

public class CommandExecutor {
    private String command;
    private String pattern;
    private long sleepTime;

    public CommandExecutor(String command, String pattern, long sleepTime) {
        this.command = command;
        this.pattern = pattern;
        this.sleepTime = sleepTime;
    }

    public boolean executeAndCheck() throws IOException, InterruptedException {
        boolean patternFound = false;
        boolean shouldContinue = true;

        while (shouldContinue) {
            Process process = Runtime.getRuntime().exec(command);
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            boolean currentIterationFound = false;

            while ((line = reader.readLine()) != null) {
                if (line.contains(pattern)) {
                    currentIterationFound = true;
                    patternFound = true;
                    break;
                }
            }

            reader.close();
            process.waitFor();

            if (currentIterationFound) {
                Thread.sleep(sleepTime);
            } else {
                shouldContinue = false;
            }
        }

        return patternFound;
    }

    public static void main(String[] args) {
        try {
            CommandExecutor executor = new CommandExecutor("ps -ef", "java", 5000);
            boolean result = executor.executeAndCheck();
            System.out.println("Pattern was found: " + result);
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }
}
