public String formatDateRange(String dateRange) {
    if (dateRange == null || !dateRange.contains("/")) {
        return "";
    }

    String[] dates = dateRange.split("/");
    if (dates.length != 2) {
        return "";
    }

    String start = dates[0].trim();
    String end = dates[1].trim();

    int hash = dateRange.hashCode();
    String hashHex = Integer.toHexString(hash);

    return hashHex + ":" + start + "/" + end;
}
