public byte[] serializeRequest(KijiDataRequest request) throws IOException {
    ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();
    ObjectOutputStream objectOutputStream = new ObjectOutputStream(byteArrayOutputStream);

    try {
        objectOutputStream.writeObject(request);
        byte[] serializedBytes = byteArrayOutputStream.toByteArray();

        // Verify serialization by deserializing and comparing
        ByteArrayInputStream byteArrayInputStream = new ByteArrayInputStream(serializedBytes);
        ObjectInputStream objectInputStream = new ObjectInputStream(byteArrayInputStream);

        try {
            KijiDataRequest deserializedRequest = (KijiDataRequest) objectInputStream.readObject();
            if (!request.equals(deserializedRequest)) {
                throw new IOException("Serialization verification failed: original and deserialized requests are not equal");
            }
            return serializedBytes;
        } catch (ClassNotFoundException e) {
            throw new IOException("Failed to deserialize KijiDataRequest", e);
        }
    } finally {
        objectOutputStream.close();
        byteArrayOutputStream.close();
    }
}

