public URI downloadFile(String fileUrl, String destinationPath) {
    try {
        URL url = new URL(fileUrl);
        HttpURLConnection connection = (HttpURLConnection) url.openConnection();
        connection.setConnectTimeout(5000);
        connection.setReadTimeout(5000);

        int responseCode = connection.getResponseCode();
        if (responseCode != HttpURLConnection.HTTP_OK) {
            return null;
        }

        Path destination = Paths.get(destinationPath);
        Files.createDirectories(destination.getParent());

        try (InputStream in = connection.getInputStream();
             OutputStream out = Files.newOutputStream(destination)) {

            byte[] buffer = new byte[8192];
            int bytesRead;
            while ((bytesRead = in.read(buffer)) != -1) {
                out.write(buffer, 0, bytesRead);
            }
        }

        return destination.toUri();

    } catch (IOException e) {
        return null;
    } finally {
        connection.disconnect();
    }
}

import java.io.*;

public class ObjectSerializer {

    public static <T extends Serializable> ByteArrayOutputStream serializeObject(T object) throws IOException {
        ByteArrayOutputStream byteStream = new ByteArrayOutputStream();
        ObjectOutputStream objectStream = new ObjectOutputStream(byteStream);
        objectStream.writeObject(object);
        objectStream.close();
        return byteStream;
    }

    @SuppressWarnings("unchecked")
    public static <T extends Serializable> T deserializeObject(ByteArrayOutputStream byteStream) 
            throws IOException, ClassNotFoundException {
        byte[] bytes = byteStream.toByteArray();
        ByteArrayInputStream byteInputStream = new ByteArrayInputStream(bytes);
        ObjectInputStream objectInputStream = new ObjectInputStream(byteInputStream);
        T object = (T) objectInputStream.readObject();
        objectInputStream.close();
        return object;
    }
}

