import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;

public class CommandExecutor {
    private static final String ERROR_MESSAGE = "fatal error";

    public static void main(String[] args) {
        try {
            Process process = Runtime.getRuntime().exec("ping localhost");

            StreamReader outputReader = new StreamReader(process.getInputStream(), "OUTPUT");
            StreamReader errorReader = new StreamReader(process.getErrorStream(), "ERROR");

            outputReader.start();
            errorReader.start();

            int exitCode = process.waitFor();
            System.out.println("Process exited with code: " + exitCode);

        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }

    static class StreamReader extends Thread {
        private InputStream is;
        private String type;

        StreamReader(InputStream is, String type) {
            this.is = is;
            this.type = type;
        }

        public void run() {
            try {
                BufferedReader br = new BufferedReader(new InputStreamReader(is));
                String line;
                while ((line = br.readLine()) != null) {
                    System.out.println(type + "> " + line);
                    if (type.equals("ERROR") && line.toLowerCase().contains(ERROR_MESSAGE)) {
                        System.err.println("Fatal error detected. Exiting program.");
                        System.exit(1);
                    }
                }
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
    }
}
