public static String getMD5Hash(String input) throws NoSuchAlgorithmException {
    MessageDigest md = MessageDigest.getInstance("MD5");
    byte[] messageDigest = md.digest(input.getBytes());
    StringBuilder hexString = new StringBuilder();

    for (byte b : messageDigest) {
        String hex = Integer.toHexString(0xFF & b);
        if (hex.length() == 1) {
            hexString.append('0');
        }
        hexString.append(hex);
    }

    return hexString.toString();
}

private void loadFromFile() {
    JFileChooser fileChooser = new JFileChooser();
    fileChooser.setDialogTitle("Load Serialized Object");

    if (fileChooser.showOpenDialog(this) == JFileChooser.APPROVE_OPTION) {
        File selectedFile = fileChooser.getSelectedFile();

        try (ObjectInputStream ois = new ObjectInputStream(
                new BufferedInputStream(
                new FileInputStream(selectedFile)))) {

            Object deserializedObject = ois.readObject();

            if (deserializedObject instanceof SerializableData) {
                SerializableData data = (SerializableData) deserializedObject;

                // Update GUI components with deserialized data
                nameTextField.setText(data.getName());
                descriptionTextArea.setText(data.getDescription());
                dateChooser.setDate(data.getDate());
                statusComboBox.setSelectedItem(data.getStatus());
                prioritySpinner.setValue(data.getPriority());

                // Refresh the display
                revalidate();
                repaint();
            } else {
                JOptionPane.showMessageDialog(this,
                    "Invalid file format",
                    "Error",
                    JOptionPane.ERROR_MESSAGE);
            }

        } catch (IOException ex) {
            JOptionPane.showMessageDialog(this,
                "Error reading file: " + ex.getMessage(),
                "Error",
                JOptionPane.ERROR_MESSAGE);
        } catch (ClassNotFoundException ex) {
            JOptionPane.showMessageDialog(this,
                "Error: Class not found - " + ex.getMessage(),
                "Error",
                JOptionPane.ERROR_MESSAGE);
        }
    }
}

