import java.io.*;
import java.util.*;

public class FileDataFilter {
    private Hashtable<String, Object> dataStore;
    private String targetDataType;
    private List<File> matchingFiles;

    public FileDataFilter(String dataType) {
        this.targetDataType = dataType;
        this.dataStore = new Hashtable<>();
        this.matchingFiles = new ArrayList<>();
    }

    public void processDirectory(String directoryPath) {
        File directory = new File(directoryPath);
        if (!directory.isDirectory()) {
            throw new IllegalArgumentException("Invalid directory path");
        }

        File[] files = directory.listFiles();
        if (files != null) {
            for (File file : files) {
                if (file.isFile()) {
                    processFile(file);
                }
            }
        }
    }

    private void processFile(File file) {
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(file))) {
            Object obj = ois.readObject();
            if (obj != null && obj.getClass().getName().equals(targetDataType)) {
                dataStore.put(file.getPath(), obj);
                matchingFiles.add(file);
            }
        } catch (FileNotFoundException e) {
            System.err.println("File not found: " + file.getPath());
        } catch (ClassNotFoundException e) {
            System.err.println("Class not found for file: " + file.getPath());
        } catch (IOException e) {
            System.err.println("Error reading file: " + file.getPath());
        }
    }

    public List<File> getMatchingFiles() {
        return Collections.unmodifiableList(matchingFiles);
    }

    public Object getDataFromFile(String filePath) {
        return dataStore.get(filePath);
    }

    public static void main(String[] args) {
        FileDataFilter filter = new FileDataFilter("java.lang.String");

        try {
            filter.processDirectory("./data");

            System.out.println("Files containing specified data type:");
            for (File file : filter.getMatchingFiles()) {
                System.out.println(file.getPath());
                System.out.println("Data: " + filter.getDataFromFile(file.getPath()));
            }
        } catch (IllegalArgumentException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}
