@Configuration
@EnableWebSecurity
public class SecurityConfig extends WebSecurityConfigurerAdapter {

    @Autowired
    private UserDetailsService userDetailsService;

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
            .authorizeRequests()
                .antMatchers("/", "/home", "/public/**").permitAll()
                .antMatchers("/admin/**").hasRole("ADMIN")
                .antMatchers("/user/**").hasAnyRole("USER", "ADMIN")
                .anyRequest().authenticated()
            .and()
            .formLogin()
                .loginPage("/login")
                .permitAll()
                .defaultSuccessUrl("/dashboard")
            .and()
            .logout()
                .permitAll()
                .logoutSuccessUrl("/")
            .and()
            .rememberMe()
                .key("uniqueAndSecret")
                .tokenValiditySeconds(86400)
            .and()
            .requestCache()
                .requestCache(new CustomRequestCache())
            .and()
            .csrf()
                .csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse());
    }

    @Override
    protected void configure(AuthenticationManagerBuilder auth) throws Exception {
        auth
            .userDetailsService(userDetailsService)
            .passwordEncoder(passwordEncoder());
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }

    private static class CustomRequestCache extends HttpSessionRequestCache {
        @Override
        public void saveRequest(HttpServletRequest request, HttpServletResponse response) {
            if (!SecurityUtils.isStaticResourceRequest(request)) {
                super.saveRequest(request, response);
            }
        }
    }

    private static class SecurityUtils {
        private static final String[] STATIC_RESOURCES = {
            "/css/**", "/js/**", "/images/**", "/webjars/**", "/favicon.ico"
        };

        public static boolean isStaticResourceRequest(HttpServletRequest request) {
            String path = request.getRequestURI();
            return Arrays.stream(STATIC_RESOURCES)
                .map(pattern -> new AntPathMatcher().match(pattern, path))
                .anyMatch(match -> match);
        }
    }
}

public static Map<String, Object> serializeAndDeserializeMap(Map<String, Object> originalMap) throws IOException, ClassNotFoundException {
    ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();

    try (ObjectOutputStream objectOutputStream = new ObjectOutputStream(byteArrayOutputStream)) {
        objectOutputStream.writeObject(originalMap);
    }

    byte[] serializedBytes = byteArrayOutputStream.toByteArray();
    ByteArrayInputStream byteArrayInputStream = new ByteArrayInputStream(serializedBytes);

    try (ObjectInputStream objectInputStream = new ObjectInputStream(byteArrayInputStream)) {
        @SuppressWarnings("unchecked")
        Map<String, Object> deserializedMap = (Map<String, Object>) objectInputStream.readObject();
        return deserializedMap;
    }
}

