    String createdBy = "Created by: John Doe";
    String modifiedBy = "Modified by: Jane Smith";

    int createdWidth = metrics.stringWidth(createdBy);
    int modifiedWidth = metrics.stringWidth(modifiedBy);

    g.drawString(createdBy, 10, 20);
    g.drawString(modifiedBy, 10, 40);

    if (!isRunning) {
        String pausedText = "Game Paused";
        int pausedWidth = metrics.stringWidth(pausedText);
        g.drawString(pausedText, (800 - pausedWidth) / 2, 300);
    }

    g.drawLine(400, 0, 400, 600);
}

