import org.apache.zookeeper.server.ServerCnxnFactory;
import org.apache.zookeeper.server.ZooKeeperServer;
import java.io.File;
import java.net.BindException;
import java.net.InetSocketAddress;

public class ZookeeperServerSetup {
    private static final int MIN_PORT = 2181;
    private static final int MAX_PORT = 2191;
    private static final int TICK_TIME = 2000;
    private static final int MIN_SESSION_TIMEOUT = TICK_TIME * 2;
    private static final int MAX_SESSION_TIMEOUT = TICK_TIME * 20;

    public static void main(String[] args) {
        try {
            String dataDir = "zookeeper/data";
            File dir = new File(dataDir);
            if (!dir.exists()) {
                dir.mkdirs();
            }

            ZooKeeperServer server = new ZooKeeperServer(dir, dir, TICK_TIME);
            server.setMinSessionTimeout(MIN_SESSION_TIMEOUT);
            server.setMaxSessionTimeout(MAX_SESSION_TIMEOUT);

            ServerCnxnFactory cnxnFactory = null;

            for (int port = MIN_PORT; port <= MAX_PORT; port++) {
                try {
                    InetSocketAddress addr = new InetSocketAddress(port);
                    cnxnFactory = ServerCnxnFactory.createFactory(addr, -1);
                    break;
                } catch (BindException e) {
                    if (port == MAX_PORT) {
                        throw new RuntimeException("Could not find available port in range", e);
                    }
                    continue;
                }
            }

            if (cnxnFactory != null) {
                cnxnFactory.startup(server);
                System.out.println("ZooKeeper server started");
            }

        } catch (Exception e) {
            System.err.println("Failed to start ZooKeeper server: " + e.getMessage());
            e.printStackTrace();
            System.exit(1);
        }
    }
}
