private IoConnector setupSocketConnection(URI uri) throws IOException {
    NioSocketConnector connector = new NioSocketConnector();

    DefaultIoFilterChainBuilder chain = connector.getFilterChain();
    chain.addLast("logger", new LoggingFilter());
    chain.addLast("codec", new ProtocolCodecFilter(new TextLineCodecFactory(Charset.forName("UTF-8"))));

    connector.setHandler(new IoHandlerAdapter());
    connector.getSessionConfig().setReadBufferSize(2048);
    connector.getSessionConfig().setIdleTime(IdleStatus.BOTH_IDLE, 10);

    int processorCount = Runtime.getRuntime().availableProcessors() + 1;
    ExecutorService executor = Executors.newFixedThreadPool(processorCount);
    connector.setWorkerPool(executor);

    InetSocketAddress address = new InetSocketAddress(uri.getHost(), uri.getPort());
    ConnectFuture future = connector.connect(address);
    future.awaitUninterruptibly();

    if (!future.isConnected()) {
        throw new IOException("Failed to connect to: " + uri.toString());
    }

    return connector;
}

