import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;

public class KeystoreGenerator {
    private static final String KEY_ALGORITHM = "RSA";
    private static final int KEY_SIZE = 2048;
    private static final int VALIDITY_DAYS = 365;
    private static final String KEY_ALIAS = "mykey";
    private static final String STORE_PASSWORD = "changeit";

    public static File generateKeystore(String hostname) throws IOException, InterruptedException {
        Path tempDir = Files.createTempDirectory("keystore_");
        File keystoreFile = new File(tempDir.toFile(), "keystore.jks");

        ProcessBuilder pb = new ProcessBuilder(
            "keytool",
            "-genkeypair",
            "-alias", KEY_ALIAS,
            "-keyalg", KEY_ALGORITHM,
            "-keysize", String.valueOf(KEY_SIZE),
            "-validity", String.valueOf(VALIDITY_DAYS),
            "-keystore", keystoreFile.getAbsolutePath(),
            "-storepass", STORE_PASSWORD,
            "-keypass", STORE_PASSWORD,
            "-dname", "CN=" + hostname + ", OU=None, O=None, L=None, ST=None, C=None",
            "-ext", "SAN=dns:" + hostname
        );

        pb.redirectErrorStream(true);
        Process process = pb.start();

        int exitCode = process.waitFor();
        if (exitCode != 0) {
            throw new IOException("Keytool command failed with exit code: " + exitCode);
        }

        return keystoreFile;
    }

    public static void main(String[] args) {
        try {
            if (args.length != 1) {
                System.err.println("Usage: KeystoreGenerator <hostname>");
                System.exit(1);
            }

            File keystoreFile = generateKeystore(args[0]);
            System.out.println("Keystore generated successfully at: " + keystoreFile.getAbsolutePath());
        } catch (Exception e) {
            System.err.println("Error generating keystore: " + e.getMessage());
            System.exit(1);
        }
    }
}
