public class HMMTagger {
    private Map<String, Map<String, Double>> transitionProb;
    private Map<String, Map<String, Double>> emissionProb;
    private Set<String> states;
    private Map<String, Double> initialProb;

    public HMMTagger(String modelFile) {
        transitionProb = new HashMap<>();
        emissionProb = new HashMap<>();
        states = new HashSet<>();
        initialProb = new HashMap<>();
        loadModel(modelFile);
    }

    private void loadModel(String filename) {
        try (BufferedReader br = new BufferedReader(new FileReader(filename))) {
            String line;
            String section = "";

            while ((line = br.readLine()) != null) {
                if (line.startsWith("###")) {
                    section = line.substring(3).trim();
                    continue;
                }

                String[] parts = line.split("\t");
                if (parts.length < 3) continue;

                switch(section) {
                    case "TRANSITIONS":
                        states.add(parts[0]);
                        transitionProb.putIfAbsent(parts[0], new HashMap<>());
                        transitionProb.get(parts[0]).put(parts[1], Double.parseDouble(parts[2]));
                        break;
                    case "EMISSIONS":
                        emissionProb.putIfAbsent(parts[0], new HashMap<>());
                        emissionProb.get(parts[0]).put(parts[1], Double.parseDouble(parts[2]));
                        break;
                    case "INITIAL":
                        initialProb.put(parts[0], Double.parseDouble(parts[1]));
                        break;
                }
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

