public void updateAndVerifySocketAddress(Configuration config) {
    InetSocketAddress newAddress = new InetSocketAddress("localhost", 8080);
    config.setSocketAddress("test.socket", newAddress);

    InetSocketAddress retrievedAddress = config.getSocketAddress("test.socket");

    if (!newAddress.equals(retrievedAddress)) {
        throw new IllegalStateException("Socket address not properly updated");
    }

    if (newAddress.getPort() != retrievedAddress.getPort() || 
        !newAddress.getHostName().equals(retrievedAddress.getHostName())) {
        throw new IllegalStateException("Socket address details do not match");
    }
}

private Socket bindSocket(Properties config) throws IOException {
    Socket socket = new Socket();
    int port = Integer.parseInt(config.getProperty("port"));
    InetSocketAddress endpoint = new InetSocketAddress(port);
    socket.bind(endpoint);
    return socket;
}

