import javax.swing.*;
import java.awt.*;
import java.awt.image.BufferedImage;
import java.io.File;
import java.io.IOException;
import javax.imageio.ImageIO;

public class ImageRotator extends JFrame {
    private String inputPath;
    private int angle;
    private JLabel imageLabel;

    public ImageRotator(String inputPath, int angle) {
        this.inputPath = inputPath;
        this.angle = angle;

        setTitle("Rotated Image");
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

        imageLabel = new JLabel();
        add(imageLabel);

        rotateAndDisplayImage();
    }

    private void rotateAndDisplayImage() {
        try {
            // Create output filename
            String outputPath = "rotated_" + new File(inputPath).getName();

            // Build ImageMagick convert command
            ProcessBuilder pb = new ProcessBuilder(
                "convert",
                inputPath,
                "-rotate",
                String.valueOf(angle),
                outputPath
            );

            // Execute command and wait for completion
            Process process = pb.start();
            int exitCode = process.waitFor();

            if (exitCode != 0) {
                throw new IOException("Image rotation failed with exit code: " + exitCode);
            }

            // Load and display rotated image
            BufferedImage rotatedImage = ImageIO.read(new File(outputPath));
            imageLabel.setIcon(new ImageIcon(rotatedImage));
            pack();
            setLocationRelativeTo(null);

        } catch (IOException | InterruptedException e) {
            JOptionPane.showMessageDialog(this,
                "Error rotating image: " + e.getMessage(),
                "Error",
                JOptionPane.ERROR_MESSAGE);
        }
    }

    public static void main(String[] args) {
        if (args.length != 2) {
            System.err.println("Usage: java ImageRotator <image_path> <rotation_angle>");
            System.exit(1);
        }

        String imagePath = args[0];
        int angle;

        try {
            angle = Integer.parseInt(args[1]);
        } catch (NumberFormatException e) {
            System.err.println("Error: Rotation angle must be an integer");
            System.exit(1);
            return;
        }

        SwingUtilities.invokeLater(() -> {
            ImageRotator rotator = new ImageRotator(imagePath, angle);
            rotator.setVisible(true);
        });
    }
}
