import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.ArrayList;
import java.util.List;

public class MacAddressRetriever {
    public List<String> getMacAddresses() {
        List<String> macAddresses = new ArrayList<>();
        String os = System.getProperty("os.name").toLowerCase();

        try {
            Process process;
            if (os.contains("win")) {
                process = Runtime.getRuntime().exec("getmac /fo csv /nh");
            } else if (os.contains("nix") || os.contains("nux") || os.contains("mac")) {
                process = Runtime.getRuntime().exec("ifconfig -a");
            } else {
                throw new UnsupportedOperationException("Unsupported operating system");
            }

            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;

            while ((line = reader.readLine()) != null) {
                if (os.contains("win")) {
                    if (line.contains(",")) {
                        String[] parts = line.split(",");
                        if (parts.length >= 2) {
                            String mac = parts[1].replace("\"", "").trim();
                            if (isValidMacAddress(mac)) {
                                macAddresses.add(mac);
                            }
                        }
                    }
                } else {
                    if (line.contains("ether")) {
                        String[] parts = line.trim().split("\\s+");
                        for (int i = 0; i < parts.length; i++) {
                            if (parts[i].equals("ether") && i + 1 < parts.length) {
                                String mac = parts[i + 1].trim();
                                if (isValidMacAddress(mac)) {
                                    macAddresses.add(mac);
                                }
                            }
                        }
                    }
                }
            }

            reader.close();
            process.waitFor();

        } catch (Exception e) {
            e.printStackTrace();
        }

        return macAddresses;
    }

    private boolean isValidMacAddress(String mac) {
        return mac.matches("([0-9A-Fa-f]{2}[:-]){5}([0-9A-Fa-f]{2})");
    }

    public static void main(String[] args) {
        MacAddressRetriever retriever = new MacAddressRetriever();
        List<String> macAddresses = retriever.getMacAddresses();
        for (String mac : macAddresses) {
            System.out.println("MAC Address: " + mac);
        }
    }
}

import java.io.*;
import java.net.URL;
import java.nio.channels.Channels;
import java.nio.channels.ReadableByteChannel;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.StandardCopyOption;

public class DictionaryDownloader {
    private static final String DICTIONARY_FILE = "dictionary.txt";

    public void downloadDictionary(String dictionaryUrl) throws IOException {
        File tempFile = null;
        try {
            // Create temporary file
            tempFile = File.createTempFile("dictionary", ".tmp");

            // Download dictionary to temp file
            URL url = new URL(dictionaryUrl);
            ReadableByteChannel rbc = Channels.newChannel(url.openStream());
            FileOutputStream fos = new FileOutputStream(tempFile);
            fos.getChannel().transferFrom(rbc, 0, Long.MAX_VALUE);
            fos.close();

            // Replace existing dictionary with downloaded content
            File dictionaryFile = new File(DICTIONARY_FILE);
            Files.move(tempFile.toPath(), 
                      dictionaryFile.toPath(), 
                      StandardCopyOption.REPLACE_EXISTING);

        } catch (IOException e) {
            if (tempFile != null && tempFile.exists()) {
                tempFile.delete();
            }
            throw e;
        }
    }

    public static void main(String[] args) {
        try {
            DictionaryDownloader downloader = new DictionaryDownloader();
            downloader.downloadDictionary("https://example.com/dictionary.txt");
            System.out.println("Dictionary successfully updated");
        } catch (IOException e) {
            System.err.println("Error downloading dictionary: " + e.getMessage());
        }
    }
}

