private Response sendPostRequest(String endpoint, String requestBody, String token, Integer maxRate) throws IOException {
    OkHttpClient.Builder clientBuilder = new OkHttpClient.Builder()
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS);

    if (maxRate != null) {
        clientBuilder.addInterceptor(new RateLimitInterceptor(maxRate));
    }

    OkHttpClient client = clientBuilder.build();

    RequestBody body;
    if (requestBody.length() > 1024) { // Gzip if body is larger than 1KB
        ByteArrayOutputStream byteStream = new ByteArrayOutputStream();
        try (GZIPOutputStream gzipStream = new GZIPOutputStream(byteStream)) {
            gzipStream.write(requestBody.getBytes(StandardCharsets.UTF_8));
        }
        body = RequestBody.create(MediaType.parse("application/json"), byteStream.toByteArray());
    } else {
        body = RequestBody.create(MediaType.parse("application/json"), requestBody);
    }

    Request request = new Request.Builder()
            .url(endpoint)
            .addHeader("Authorization", "Bearer " + token)
            .addHeader("Content-Type", "application/json")
            .post(body)
            .build();

    return client.newCall(request).execute();
}

private static class RateLimitInterceptor implements Interceptor {
    private final RateLimiter rateLimiter;

    public RateLimitInterceptor(int maxRequestsPerSecond) {
        this.rateLimiter = RateLimiter.create(maxRequestsPerSecond);
    }

    @Override
    public Response intercept(Chain chain) throws IOException {
        rateLimiter.acquire();
        return chain.proceed(chain.request());
    }
}
