import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public class HashGenerator {
    public static String generateHash(String input, String algorithm) throws NoSuchAlgorithmException {
        String normalizedAlgorithm = normalizeAlgorithm(algorithm);

        MessageDigest digest = MessageDigest.getInstance(normalizedAlgorithm);
        byte[] hash = digest.digest(input.getBytes());

        return bytesToHex(hash);
    }

    private static String normalizeAlgorithm(String algorithm) throws NoSuchAlgorithmException {
        String normalized = algorithm.toUpperCase();
        switch(normalized) {
            case "MD5":
            case "SHA1":
            case "SHA-1":
            case "SHA256":
            case "SHA-256":
            case "SHA384":
            case "SHA-384":
            case "SHA512":
            case "SHA-512":
                return normalized;
            default:
                throw new NoSuchAlgorithmException("Unsupported hash algorithm: " + algorithm);
        }
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder result = new StringBuilder();
        for (byte b : bytes) {
            result.append(String.format("%02x", b));
        }
        return result.toString();
    }

    public static void main(String[] args) {
        try {
            String input = "Hello, World!";
            String[] algorithms = {"MD5", "SHA-1", "SHA-256", "SHA-384", "SHA-512"};

            for (String algorithm : algorithms) {
                String hash = generateHash(input, algorithm);
                System.out.println(algorithm + ": " + hash);
            }

            // Test invalid algorithm
            generateHash(input, "INVALID");

        } catch (NoSuchAlgorithmException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}
