private void startListening(String address, int port) throws IOException {
    final ServerSocketChannel serverChannel = ServerSocketChannel.open();
    final ServerSocket serverSocket = serverChannel.socket();

    serverSocket.setReuseAddress(true);
    serverSocket.bind(new InetSocketAddress(address, port));

    final CountDownLatch listeningLatch = new CountDownLatch(1);

    Thread acceptThread = new Thread(() -> {
        try {
            listeningLatch.countDown();
            while (!Thread.currentThread().isInterrupted()) {
                try {
                    SocketChannel clientChannel = serverChannel.accept();
                    handleNewConnection(clientChannel);
                } catch (IOException e) {
                    if (!serverSocket.isClosed()) {
                        e.printStackTrace();
                    }
                }
            }
        } finally {
            try {
                serverChannel.close();
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
    });

    acceptThread.setDaemon(true);
    acceptThread.start();

    try {
        listeningLatch.await();
    } catch (InterruptedException e) {
        Thread.currentThread().interrupt();
        throw new IOException("Interrupted while waiting for server to start", e);
    }
}

