import java.io.*;
import java.math.BigInteger;
import java.nio.file.*;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public static void generateMD5Hash(String filePath) {
    try {
        File inputFile = new File(filePath);
        System.out.println("Reading file: " + inputFile.getName());

        MessageDigest md = MessageDigest.getInstance("MD5");
        byte[] fileBytes = Files.readAllBytes(inputFile.toPath());
        byte[] hashBytes = md.digest(fileBytes);

        String hashString = new BigInteger(1, hashBytes).toString(16);
        while (hashString.length() < 32) {
            hashString = "0" + hashString;
        }

        String md5FilePath = filePath + ".md5";
        Files.write(Paths.get(md5FilePath), hashString.getBytes());

        System.out.println("MD5 hash generated: " + hashString);
        System.out.println("Hash written to: " + md5FilePath);

    } catch (NoSuchAlgorithmException e) {
        System.err.println("MD5 algorithm not found: " + e.getMessage());
    } catch (IOException e) {
        System.err.println("Error processing file: " + e.getMessage());
    }
}

