public class CommandExecutor {
    public static int executeAndReadError(String command) throws Exception {
        Process process = Runtime.getRuntime().exec(command);

        byte[] buffer = new byte[4096];
        int totalBytesRead = 0;
        int bytesRead;

        try (InputStream errorStream = process.getErrorStream()) {
            while ((bytesRead = errorStream.read(buffer)) != -1) {
                totalBytesRead += bytesRead;
            }
        }

        process.waitFor();
        return totalBytesRead;
    }

    public static void main(String[] args) {
        try {
            String command = args.length > 0 ? args[0] : "ls -l";
            int bytesRead = executeAndReadError(command);
            System.out.println("Bytes read from error stream: " + bytesRead);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

public Object remoteMethodCall(String methodName, Object[] params, String serverHost, int serverPort) throws IOException, ClassNotFoundException {
    try (Socket socket = new Socket(serverHost, serverPort)) {
        ObjectOutputStream out = new ObjectOutputStream(socket.getOutputStream());
        ObjectInputStream in = new ObjectInputStream(socket.getInputStream());

        // Create request object
        RemoteRequest request = new RemoteRequest(methodName, params);

        // Send request
        out.writeObject(request);
        out.flush();

        // Receive response
        Object result = in.readObject();

        return result;
    }
}

class RemoteRequest implements Serializable {
    private static final long serialVersionUID = 1L;
    private String methodName;
    private Object[] params;

    public RemoteRequest(String methodName, Object[] params) {
        this.methodName = methodName;
        this.params = params;
    }

    public String getMethodName() {
        return methodName;
    }

    public Object[] getParams() {
        return params;
    }
}

