private String calculateETag(Change change) {
    try {
        MessageDigest md = MessageDigest.getInstance("MD5");

        // Add last updated timestamp
        md.update(Long.toString(change.getLastUpdatedOn()).getBytes());

        // Add row version
        md.update(Long.toString(change.getRowVersion()).getBytes());

        // Add current user's account ID
        md.update(getCurrentUser().getAccountId().toString().getBytes());

        // Get project state and iterate through revisions
        ProjectState projectState = change.getProject();
        for (RevisionInfo revision : projectState.getRevisions()) {
            md.update(revision.getId().getBytes());
        }

        // Convert byte array to hex string
        byte[] digest = md.digest();
        StringBuilder sb = new StringBuilder();
        for (byte b : digest) {
            sb.append(String.format("%02x", b));
        }

        return "\"" + sb.toString() + "\"";

    } catch (NoSuchAlgorithmException e) {
        throw new RuntimeException("MD5 algorithm not available", e);
    }
}
