public boolean sendMessageToHost(String hostName, int port, byte[] messageBuffer, boolean flush) {
    try (Socket socket = new Socket()) {
        socket.setKeepAlive(true);
        socket.connect(new InetSocketAddress(hostName, port), 5000);

        OutputStream outputStream = socket.getOutputStream();
        outputStream.write(messageBuffer);
        outputStream.flush();

        if (flush) {
            outputStream.write(messageBuffer);
            outputStream.flush();
        }

        return true;
    } catch (IOException e) {
        return false;
    }
}

import com.sun.net.httpserver.HttpServer;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpExchange;
import java.io.IOException;
import java.io.OutputStream;
import java.net.InetSocketAddress;

public class NotificationServer {
    private static int completedJobs = 0;
    private static int failedJobs = 0;

    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/notify", new NotifyHandler());
        server.setExecutor(null);
        server.start();
        System.out.println("Server started on port 8080");
    }

    static class NotifyHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if ("GET".equals(exchange.getRequestMethod())) {
                String response = String.format("Jobs completed: %d, Jobs failed: %d", completedJobs, failedJobs);
                exchange.sendResponseHeaders(200, response.length());
                try (OutputStream os = exchange.getResponseBody()) {
                    os.write(response.getBytes());
                }
            } else {
                String response = "Method not allowed";
                exchange.sendResponseHeaders(405, response.length());
                try (OutputStream os = exchange.getResponseBody()) {
                    os.write(response.getBytes());
                }
            }
        }
    }

    public static void incrementCompletedJobs() {
        completedJobs++;
    }

    public static void incrementFailedJobs() {
        failedJobs++;
    }
}

private Socket createSocket(String host, int port, boolean useSSL, int connectTimeout, int readTimeout, String pattern) throws Exception {
    Socket socket;

    if (useSSL) {
        SSLSocketFactory sslSocketFactory = (SSLSocketFactory) SSLSocketFactory.getDefault();
        socket = sslSocketFactory.createSocket();
    } else {
        socket = new Socket();
    }

    socket.setSoTimeout(readTimeout);
    socket.setKeepAlive(true);
    socket.setTcpNoDelay(true);

    InetSocketAddress endpoint = new InetSocketAddress(host, port);
    socket.connect(endpoint, connectTimeout);

    if (pattern != null && !pattern.isEmpty()) {
        BufferedWriter writer = new BufferedWriter(new OutputStreamWriter(socket.getOutputStream()));
        writer.write(pattern);
        writer.flush();
    }

    return socket;
}

private DatagramConnector setupDatagramConnector(String uri) throws IOException {
    DatagramConnector datagramConnector = new DatagramConnector();

    URI connectionUri = URI.create(uri);
    InetSocketAddress socketAddress = new InetSocketAddress(
        connectionUri.getHost(), 
        connectionUri.getPort()
    );

    DatagramEndpoint endpoint = new DatagramEndpoint(socketAddress);
    datagramConnector.setEndpoint(endpoint);

    int processorCount = Runtime.getRuntime().availableProcessors();
    datagramConnector.setProcessorCount(processorCount);

    ThreadPoolExecutor executor = new ThreadPoolExecutor(
        processorCount,
        processorCount * 2,
        60L,
        TimeUnit.SECONDS,
        new LinkedBlockingQueue<>(),
        new ThreadFactoryBuilder().setNameFormat("datagram-pool-%d").build()
    );
    datagramConnector.setExecutor(executor);

    if (datagramConnector.isTransferExchange()) {
        throw new IllegalArgumentException("Transfer exchange must be disabled");
    }

    datagramConnector.setReuseAddress(true);
    datagramConnector.setReceiveBufferSize(65536);
    datagramConnector.setSendBufferSize(65536);

    return datagramConnector;
}

private void loadApplicationState() {
    try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream("appstate.dat"))) {
        Rectangle bounds = (Rectangle) ois.readObject();
        int extendedState = ois.readInt();
        @SuppressWarnings("unchecked")
        List<TreePath> treePaths = (List<TreePath>) ois.readObject();
        int sourceComboIndex = ois.readInt();
        int targetComboIndex = ois.readInt();
        int encodingComboIndex = ois.readInt();
        int threadCount = ois.readInt();
        int parallelism = ois.readInt();

        mainFrame.setBounds(bounds);
        mainFrame.setExtendedState(extendedState);

        for (TreePath path : treePaths) {
            fileTree.addSelectionPath(path);
        }

        sourceComboBox.setSelectedIndex(sourceComboIndex);
        targetComboBox.setSelectedIndex(targetComboIndex);
        encodingComboBox.setSelectedIndex(encodingComboIndex);

        threadCountSpinner.setValue(threadCount);
        parallelismSlider.setValue(parallelism);

    } catch (IOException | ClassNotFoundException e) {
        logger.log(Level.WARNING, "Failed to load application state", e);
        // Use default values if loading fails
        mainFrame.setLocationRelativeTo(null);
        mainFrame.setExtendedState(Frame.NORMAL);
    }
}

private Source createSource(InputStream inputStream) {
    if (inputStream == null) {
        throw new HttpMessageNotReadableException("Empty input stream");
    }

    try {
        XMLInputFactory inputFactory = XMLInputFactory.newInstance();
        inputFactory.setProperty(XMLInputFactory.IS_SUPPORTING_EXTERNAL_ENTITIES, false);
        inputFactory.setProperty(XMLInputFactory.SUPPORT_DTD, false);
        XMLStreamReader xmlStreamReader = inputFactory.createXMLStreamReader(inputStream);
        return new StAXSource(xmlStreamReader);
    } catch (XMLStreamException ex) {
        throw new HttpMessageNotReadableException("Failed to parse XML document", ex);
    }
}

