public static String compressFileWithLZO(String filePath, int compressionLevel) throws IOException, NoSuchAlgorithmException {
    byte[] buffer = new byte[8192];
    String compressedPath = filePath + ".lzo";
    MessageDigest md = MessageDigest.getInstance("MD5");

    try (FileInputStream fis = new FileInputStream(filePath);
         FileOutputStream fos = new FileOutputStream(compressedPath)) {

        LzoCompressor compressor = LzoAlgorithm.LZO1X.newCompressor();
        LzoOutputStream lzos = new LzoOutputStream(fos, compressor, compressionLevel);

        int bytesRead;
        while ((bytesRead = fis.read(buffer)) != -1) {
            lzos.write(buffer, 0, bytesRead);
            md.update(buffer, 0, bytesRead);
        }

        lzos.close();
    }

    byte[] digest = md.digest();
    StringBuilder sb = new StringBuilder();
    for (byte b : digest) {
        sb.append(String.format("%02x", b));
    }

    return sb.toString();
}
