import akka.actor.AbstractActor;
import akka.actor.ActorRef;
import akka.actor.ActorSystem;
import akka.actor.Props;
import akka.io.Tcp;
import akka.io.TcpMessage;
import akka.util.ByteString;

import java.net.InetSocketAddress;

public class DiscoveryActor extends AbstractActor {

    private final InetSocketAddress remoteAddress;
    private final ActorRef tcpManager;

    public DiscoveryActor(String host, int port) {
        this.remoteAddress = new InetSocketAddress(host, port);
        this.tcpManager = Tcp.get(getContext().getSystem()).manager();
    }

    public static Props props(String host, int port) {
        return Props.create(DiscoveryActor.class, host, port);
    }

    @Override
    public Receive createReceive() {
        return receiveBuilder()
                .match(String.class, msg -> {
                    if (msg.equals("discover")) {
                        tcpManager.tell(TcpMessage.connect(remoteAddress), getSelf());
                    }
                })
                .match(Tcp.Connected.class, conn -> {
                    getSender().tell(TcpMessage.register(getSelf()), getSelf());
                    ByteString discoveryMessage = ByteString.fromString("DISCOVERY");
                    getSender().tell(TcpMessage.write(discoveryMessage), getSelf());
                })
                .match(Tcp.CommandFailed.class, failed -> {
                    getContext().stop(getSelf());
                })
                .match(Tcp.Received.class, received -> {
                    // Handle received data
                    String response = received.data().utf8String();
                    System.out.println("Received: " + response);
                })
                .match(Tcp.ConnectionClosed.class, closed -> {
                    getContext().stop(getSelf());
                })
                .build();
    }

    public static void main(String[] args) {
        ActorSystem system = ActorSystem.create("DiscoverySystem");
        ActorRef discoveryActor = system.actorOf(DiscoveryActor.props("localhost", 8080));
        discoveryActor.tell("discover", ActorRef.noSender());
    }
}
