import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public byte[] getCombinedHash(byte[] input) throws NoSuchAlgorithmException {
    MessageDigest md5Digest = MessageDigest.getInstance("MD5");
    MessageDigest md2Digest = MessageDigest.getInstance("MD2");

    byte[] md5Hash = md5Digest.digest(input);
    byte[] md2Hash = md2Digest.digest(input);

    byte[] combinedHash = new byte[md5Hash.length + md2Hash.length];
    System.arraycopy(md5Hash, 0, combinedHash, 0, md5Hash.length);
    System.arraycopy(md2Hash, 0, combinedHash, md5Hash.length, md2Hash.length);

    return combinedHash;
}

private void handleClientRequest(Socket clientSocket) throws IOException {
    try (
        BufferedReader in = new BufferedReader(new InputStreamReader(clientSocket.getInputStream()));
        PrintWriter out = new PrintWriter(clientSocket.getOutputStream(), true)
    ) {
        String request = in.readLine();
        String[] parts = request.split("\\|");

        if (parts.length < 2) {
            out.println("Invalid request format");
            return;
        }

        String className = parts[0];
        String methodName = parts[1];
        Object[] args = new Object[parts.length - 2];

        for (int i = 2; i < parts.length; i++) {
            args[i-2] = parts[i];
        }

        try {
            Class<?> clazz = Class.forName(className);
            Object instance = clazz.getDeclaredConstructor().newInstance();

            Method[] methods = clazz.getMethods();
            Method targetMethod = null;

            for (Method method : methods) {
                if (method.getName().equals(methodName) && 
                    method.getParameterCount() == args.length) {
                    targetMethod = method;
                    break;
                }
            }

            if (targetMethod != null) {
                Object result = targetMethod.invoke(instance, args);
                out.println(result != null ? result.toString() : "null");
            } else {
                out.println("Method not found");
            }

        } catch (ClassNotFoundException e) {
            out.println("Class not found: " + className);
        } catch (Exception e) {
            out.println("Error: " + e.getMessage());
        }
    }
}

@SuppressWarnings("unchecked")
public Socket establishKerberosConnection(String remoteHost, int port, int timeout, int pingInterval) 
    throws IOException, SecurityException, GSSException {

    System.setProperty("javax.security.auth.useSubjectCredsOnly", "false");
    System.setProperty("java.security.krb5.conf", "/etc/krb5.conf");

    Socket socket = new Socket();
    InetAddress localAddr = null;

    try {
        localAddr = InetAddress.getByName(remoteHost);
        if (localAddr.isAnyLocalAddress() || localAddr.isLoopbackAddress()) {
            socket.bind(new InetSocketAddress(localAddr, 0));
        }
    } catch (UnknownHostException e) {
        // Proceed without binding if host is not local
    }

    SocketAddress remoteAddr = new InetSocketAddress(remoteHost, port);
    socket.connect(remoteAddr, timeout);
    socket.setKeepAlive(true);
    socket.setSoTimeout(timeout);

    GSSManager manager = GSSManager.getInstance();
    GSSName serverName = manager.createName("host@" + remoteHost, GSSName.NT_HOSTBASED_SERVICE);
    GSSContext context = manager.createContext(serverName,
            GSSConstants.KERBEROS_V5_OID,
            null,
            GSSContext.DEFAULT_LIFETIME);

    context.requestMutualAuth(true);
    context.requestConf(true);
    context.requestInteg(true);

    byte[] token = new byte[0];
    token = context.initSecContext(token, 0, token.length);

    DataOutputStream outStream = new DataOutputStream(socket.getOutputStream());
    outStream.writeInt(token.length);
    outStream.write(token);
    outStream.flush();

    DataInputStream inStream = new DataInputStream(socket.getInputStream());
    int length = inStream.readInt();
    token = new byte[length];
    inStream.readFully(token);

    context.initSecContext(token, 0, token.length);

    if (!context.isEstablished()) {
        throw new SecurityException("Failed to establish Kerberos context");
    }

    return socket;
}

public ProcessInstance serializeAndDeserialize(ProcessInstance originalInstance) throws IOException, ClassNotFoundException {
    // Serialize
    ByteArrayOutputStream baos = new ByteArrayOutputStream();
    ObjectOutputStream oos = new ObjectOutputStream(baos);
    oos.writeObject(originalInstance);
    oos.close();

    // Deserialize
    ByteArrayInputStream bais = new ByteArrayInputStream(baos.toByteArray());
    ObjectInputStream ois = new ObjectInputStream(bais);
    ProcessInstance deserializedInstance = (ProcessInstance) ois.readObject();
    ois.close();

    // Verify ID matches
    if (!deserializedInstance.getId().equals(originalInstance.getId())) {
        throw new IllegalStateException("Deserialized instance ID does not match original ID");
    }

    return deserializedInstance;
}

