private boolean executeProcess(List<String> commandArgs, long timeoutMillis) {
    try {
        // Build command array
        String[] commandArray = commandArgs.toArray(new String[0]);

        // Start process
        Process process = Runtime.getRuntime().exec(commandArray);

        // Create watchdog thread
        Thread watchdog = new Thread(() -> {
            try {
                Thread.sleep(timeoutMillis);
                if (process.isAlive()) {
                    process.destroy();
                    LOGGER.warn("Process timed out after {} ms and was terminated", timeoutMillis);
                }
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        });
        watchdog.setDaemon(true);
        watchdog.start();

        // Log process details
        LOGGER.info("Started process: {}", String.join(" ", commandArgs));

        // Read process output streams
        BufferedReader stdInput = new BufferedReader(new InputStreamReader(process.getInputStream()));
        BufferedReader stdError = new BufferedReader(new InputStreamReader(process.getErrorStream()));

        // Log stdout
        String line;
        while ((line = stdInput.readLine()) != null) {
            LOGGER.debug("Process stdout: {}", line);
        }

        // Log stderr
        while ((line = stdError.readLine()) != null) {
            LOGGER.error("Process stderr: {}", line);
        }

        // Wait for process completion
        int exitCode = process.waitFor();
        LOGGER.info("Process completed with exit code: {}", exitCode);

        return true;

    } catch (IOException e) {
        LOGGER.error("Failed to start process: {}", e.getMessage());
        return false;
    } catch (InterruptedException e) {
        Thread.currentThread().interrupt();
        LOGGER.error("Process execution interrupted: {}", e.getMessage());
        return false;
    }
}
