import java.io.BufferedReader;
import java.io.File;
import java.io.InputStreamReader;
import java.util.ArrayList;
import java.util.List;

public class CodeSigner {
    private String keystore;
    private String alias;
    private String password;
    private String sourceFile;

    public CodeSigner(String keystore, String alias, String sourceFile) {
        this(keystore, alias, "", sourceFile);
    }

    public CodeSigner(String keystore, String alias, String password, String sourceFile) {
        this.keystore = keystore;
        this.alias = alias;
        this.password = password;
        this.sourceFile = sourceFile;
    }

    public boolean signCode() {
        try {
            List<String> command = new ArrayList<>();
            command.add("jarsigner");
            command.add("-keystore");
            command.add(keystore);

            if (!password.isEmpty()) {
                command.add("-storepass");
                command.add(password);
            }

            command.add(sourceFile);
            command.add(alias);

            ProcessBuilder processBuilder = new ProcessBuilder(command);
            processBuilder.redirectErrorStream(true);
            Process process = processBuilder.start();

            BufferedReader reader = new BufferedReader(
                new InputStreamReader(process.getInputStream())
            );

            String line;
            StringBuilder output = new StringBuilder();
            while ((line = reader.readLine()) != null) {
                output.append(line).append("\n");
            }

            int exitCode = process.waitFor();
            return exitCode == 0;
        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }

    public boolean verifySignature() {
        try {
            List<String> command = new ArrayList<>();
            command.add("jarsigner");
            command.add("-verify");
            command.add("-verbose");
            command.add("-certs");
            command.add(sourceFile);

            ProcessBuilder processBuilder = new ProcessBuilder(command);
            processBuilder.redirectErrorStream(true);
            Process process = processBuilder.start();

            BufferedReader reader = new BufferedReader(
                new InputStreamReader(process.getInputStream())
            );

            String line;
            StringBuilder output = new StringBuilder();
            while ((line = reader.readLine()) != null) {
                output.append(line).append("\n");
            }

            int exitCode = process.waitFor();
            return exitCode == 0;
        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }

    public static void main(String[] args) {
        if (args.length < 3) {
            System.out.println("Usage: CodeSigner <keystore> <alias> <sourceFile> [password]");
            System.exit(1);
        }

        String keystore = args[0];
        String alias = args[1];
        String sourceFile = args[2];
        String password = args.length > 3 ? args[3] : "";

        CodeSigner signer = new CodeSigner(keystore, alias, password, sourceFile);

        if (signer.signCode()) {
            System.out.println("Code signing successful");
            if (signer.verifySignature()) {
                System.out.println("Signature verification successful");
            } else {
                System.out.println("Signature verification failed");
            }
        } else {
            System.out.println("Code signing failed");
        }
    }
}

