import java.io.*;

class SerializableObject implements Serializable {
    private static final long serialVersionUID = 1L;
    private String data;
    private int number;

    public SerializableObject(String data, int number) {
        this.data = data;
        this.number = number;
    }
}

public class SerializationBenchmark {
    public static void main(String[] args) {
        SerializableObject obj = new SerializableObject("Test data", 42);

        long totalSerializationTime = 0;
        long totalDeserializationTime = 0;
        long totalSize = 0;

        for (int i = 0; i < 500; i++) {
            try {
                // Serialization
                long startSerialize = System.nanoTime();
                byte[] serializedData = serialize(obj);
                long endSerialize = System.nanoTime();
                totalSerializationTime += (endSerialize - startSerialize);
                totalSize += serializedData.length;

                // Deserialization
                long startDeserialize = System.nanoTime();
                deserialize(serializedData);
                long endDeserialize = System.nanoTime();
                totalDeserializationTime += (endDeserialize - startDeserialize);

            } catch (Exception e) {
                e.printStackTrace();
            }
        }

        System.out.println("Average serialization time: " + (totalSerializationTime / 500 / 1000.0) + " microseconds");
        System.out.println("Average deserialization time: " + (totalDeserializationTime / 500 / 1000.0) + " microseconds");
        System.out.println("Average serialized size: " + (totalSize / 500) + " bytes");
    }

    private static byte[] serialize(Object obj) throws IOException {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        ObjectOutputStream oos = new ObjectOutputStream(baos);
        oos.writeObject(obj);
        oos.close();
        return baos.toByteArray();
    }

    private static Object deserialize(byte[] data) throws IOException, ClassNotFoundException {
        ByteArrayInputStream bais = new ByteArrayInputStream(data);
        ObjectInputStream ois = new ObjectInputStream(bais);
        Object obj = ois.readObject();
        ois.close();
        return obj;
    }
}
