public Map<String, Byte> mergeStringAndBinaryMaps(Map<String, String> stringMap, InputStream binaryStream) throws IOException {
    Map<String, Byte> result = new HashMap<>();

    // Convert string map values to bytes
    for (Map.Entry<String, String> entry : stringMap.entrySet()) {
        try {
            byte value = Byte.parseByte(entry.getValue());
            result.put(entry.getKey(), value);
        } catch (NumberFormatException e) {
            // Skip invalid number strings
            continue;
        }
    }

    // Read binary stream into map
    try (DataInputStream dis = new DataInputStream(binaryStream)) {
        int numEntries = dis.readInt();
        for (int i = 0; i < numEntries; i++) {
            int keyLength = dis.readInt();
            byte[] keyBytes = new byte[keyLength];
            dis.readFully(keyBytes);
            String key = new String(keyBytes, StandardCharsets.UTF_8);
            byte value = dis.readByte();
            result.put(key, value);
        }
    }

    return result;
}
