public static String executeCommand(String command, boolean waitForCompletion) throws IOException, InterruptedException {
    StringBuilder output = new StringBuilder();
    Process process = Runtime.getRuntime().exec(command);

    BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
    String line;
    while ((line = reader.readLine()) != null) {
        output.append(line).append("\n");
    }

    BufferedReader errorReader = new BufferedReader(new InputStreamReader(process.getErrorStream()));
    while ((line = errorReader.readLine()) != null) {
        output.append(line).append("\n");
    }

    if (waitForCompletion) {
        process.waitFor();
    }

    reader.close();
    errorReader.close();
    process.destroy();

    return output.toString().trim();
}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.ArrayList;
import java.util.List;

public class PackageManager {
    public List<String> getInstalledPackages() throws IOException {
        List<String> packages = new ArrayList<>();
        Process process = null;
        BufferedReader reader = null;

        try {
            String osName = System.getProperty("os.name").toLowerCase();
            String[] command;

            if (osName.contains("win")) {
                command = new String[]{"wmic", "product", "get", "name"};
            } else if (osName.contains("mac")) {
                command = new String[]{"pkgutil", "--pkgs"};
            } else {
                command = new String[]{"dpkg", "-l"};
            }

            process = Runtime.getRuntime().exec(command);
            reader = new BufferedReader(new InputStreamReader(process.getInputStream()));

            String line;
            while ((line = reader.readLine()) != null) {
                if (!line.trim().isEmpty()) {
                    packages.add(line.trim());
                }
            }

            process.waitFor();

            if (process.exitValue() != 0) {
                throw new IOException("Command execution failed with exit code: " + process.exitValue());
            }

        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new IOException("Command execution interrupted", e);
        } finally {
            if (reader != null) {
                try {
                    reader.close();
                } catch (IOException e) {
                    // Ignore close exception
                }
            }
            if (process != null) {
                process.destroy();
            }
        }

        return packages;
    }
}

import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.DESKeySpec;
import javax.crypto.SecretKeyFactory;
import java.security.SecureRandom;

public SecretKey generateDESKey(String seed) throws Exception {
    byte[] seedBytes = seed.getBytes("UTF-8");
    SecureRandom secureRandom = new SecureRandom(seedBytes);

    KeyGenerator keyGen = KeyGenerator.getInstance("DES");
    keyGen.init(56, secureRandom);

    SecretKey secretKey = keyGen.generateKey();

    // Ensure the key is valid for DES
    DESKeySpec desKeySpec = new DESKeySpec(secretKey.getEncoded());
    SecretKeyFactory keyFactory = SecretKeyFactory.getInstance("DES");
    return keyFactory.generateSecret(desKeySpec);
}

public class HashGenerator {
    public static final int HASH_FUNCTION_SIMPLE = 1;
    public static final int HASH_FUNCTION_DJB2 = 2;
    public static final int HASH_FUNCTION_SDBM = 3;
    public static final int HASH_FUNCTION_JAVA = 4;

    public static long generateHash(String input, int hashFunction) {
        if (input == null) {
            return 0;
        }

        switch (hashFunction) {
            case HASH_FUNCTION_SIMPLE:
                return simpleHash(input);
            case HASH_FUNCTION_DJB2:
                return djb2Hash(input);
            case HASH_FUNCTION_SDBM:
                return sdbmHash(input);
            case HASH_FUNCTION_JAVA:
                return input.hashCode();
            default:
                throw new IllegalArgumentException("Invalid hash function selected");
        }
    }

    private static long simpleHash(String input) {
        long hash = 0;
        for (int i = 0; i < input.length(); i++) {
            hash = 31 * hash + input.charAt(i);
        }
        return hash;
    }

    private static long djb2Hash(String input) {
        long hash = 5381;
        for (int i = 0; i < input.length(); i++) {
            hash = ((hash << 5) + hash) + input.charAt(i);
        }
        return hash;
    }

    private static long sdbmHash(String input) {
        long hash = 0;
        for (int i = 0; i < input.length(); i++) {
            hash = input.charAt(i) + (hash << 6) + (hash << 16) - hash;
        }
        return hash;
    }
}

import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.math.BigInteger;

public String getMD5Hash(String input) {
    try {
        MessageDigest md = MessageDigest.getInstance("MD5");
        byte[] messageDigest = md.digest(input.getBytes());
        BigInteger no = new BigInteger(1, messageDigest);
        String hashtext = no.toString(16);
        while (hashtext.length() < 32) {
            hashtext = "0" + hashtext;
        }
        return hashtext;
    } catch (NoSuchAlgorithmException e) {
        throw new RuntimeException(e);
    }
}

public String getMD5Hash(String input) {
    try {
        MessageDigest md = MessageDigest.getInstance("MD5");
        byte[] messageDigest = md.digest(input.getBytes());
        StringBuilder hexString = new StringBuilder();

        for (byte b : messageDigest) {
            String hex = Integer.toHexString(0xFF & b);
            if (hex.length() == 1) {
                hexString.append('0');
            }
            hexString.append(hex);
        }

        return hexString.toString();
    } catch (NoSuchAlgorithmException e) {
        return null;
    }
}

public static WalkMap readWalkMap(String filePath) throws IOException, ClassNotFoundException {
    File file = new File(filePath);
    if (!file.exists()) {
        throw new FileNotFoundException("File not found: " + filePath);
    }

    String extension = filePath.substring(filePath.lastIndexOf(".")).toLowerCase();

    switch (extension) {
        case ".objv":
            try (BufferedReader reader = new BufferedReader(new FileReader(file))) {
                return new ViewMap(reader);
            }

        case ".objp":
            try (BufferedReader reader = new BufferedReader(new FileReader(file))) {
                return new PathsMap(reader);
            }

        case ".jrd3m":
            try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(file))) {
                Object obj = ois.readObject();
                if (obj instanceof WalkMap) {
                    return (WalkMap) obj;
                } else {
                    throw new IOException("Invalid file format: Object is not a WalkMap");
                }
            }

        default:
            throw new IOException("Unsupported file extension: " + extension);
    }
}

