        List<ExtractedData> allData = new ArrayList<>();

        for (String filePath : args) {
            try {
                if (filePath.toLowerCase().endsWith(XML_FILE_EXTENSION)) {
                    allData.addAll(extractor.parseXMLFile(filePath));
                } else if (filePath.toLowerCase().endsWith(SQL_FILE_EXTENSION)) {
                    allData.addAll(extractor.parseSQLFile(filePath));
                } else {
                    System.err.println("Unsupported file format: " + filePath);
                }
            } catch (Exception e) {
                System.err.println("Error processing file " + filePath + ": " + e.getMessage());
                e.printStackTrace();
            }
