    private List<ExtractedData> parseXMLFile(String filePath) throws Exception {
        List<ExtractedData> data = new ArrayList<>();
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(new File(filePath));

        NodeList records = document.getElementsByTagName("record");
        for (int i = 0; i < records.getLength(); i++) {
            Node record = records.item(i);
            if (record.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) record;
                ExtractedData extractedData = new ExtractedData();
                extractedData.setId(element.getAttribute("id"));
                extractedData.setName(getElementValue(element, "name"));
                extractedData.setValue(getElementValue(element, "value"));
                data.add(extractedData);
            }
        }
        return data;
    }

    private String getElementValue(Element parent, String elementName) {
        NodeList nodeList = parent.getElementsByTagName(elementName);
        if (nodeList.getLength() > 0) {
            return nodeList.item(0).getTextContent();
        }
        return "";
    }

