import org.xml.sax.Attributes;
import org.xml.sax.SAXException;
import org.xml.sax.helpers.DefaultHandler;
import javax.xml.parsers.SAXParser;
import javax.xml.parsers.SAXParserFactory;
import java.io.File;
import java.util.HashMap;
import java.util.Map;

public class XMLPrefixAnalyzer {
    public static void main(String[] args) {
        if (args.length == 0) {
            System.out.println("Please provide XML file paths as arguments");
            return;
        }

        FrequencyHandler handler = new FrequencyHandler();
        SAXParserFactory factory = SAXParserFactory.newInstance();
        factory.setNamespaceAware(true);

        try {
            SAXParser parser = factory.newSAXParser();

            for (String filePath : args) {
                File xmlFile = new File(filePath);
                parser.parse(xmlFile, handler);
            }

            handler.printPrefixFrequencies();

        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

class FrequencyHandler extends DefaultHandler {
    private Map<String, Integer> prefixFrequencies = new HashMap<>();

    @Override
    public void startElement(String uri, String localName, String qName, Attributes attributes) throws SAXException {
        // Process element name
        addPrefix(qName);

        // Process attributes
        for (int i = 0; i < attributes.getLength(); i++) {
            addPrefix(attributes.getQName(i));
        }
    }

    private void addPrefix(String qName) {
        if (qName.contains(":")) {
            String prefix = qName.substring(0, qName.indexOf(":"));
            prefixFrequencies.merge(prefix, 1, Integer::sum);
        }
    }

    public void printPrefixFrequencies() {
        System.out.println("Prefix frequencies:");
        prefixFrequencies.entrySet().stream()
            .sorted(Map.Entry.<String, Integer>comparingByValue().reversed())
            .forEach(entry -> System.out.printf("%s: %d%n", entry.getKey(), entry.getValue()));
    }
}
