import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.Map;
import java.util.TreeMap;

private static int calculateHashCode(Map<String, String> paths, String moduleName, boolean createSymlinks, boolean createHeaderMap) {
    try {
        MessageDigest digest = MessageDigest.getInstance("SHA-1");

        // Sort paths to ensure consistent hash
        TreeMap<String, String> sortedPaths = new TreeMap<>(paths);

        // Add module name to hash
        digest.update(moduleName.getBytes());

        // Add symlink state
        digest.update((byte) (createSymlinks ? 1 : 0));

        // Add header map state
        digest.update((byte) (createHeaderMap ? 1 : 0));

        // Add all paths
        for (Map.Entry<String, String> entry : sortedPaths.entrySet()) {
            digest.update(entry.getKey().getBytes());
            if (entry.getValue() != null) {
                digest.update(entry.getValue().getBytes());
            }
        }

        byte[] hashBytes = digest.digest();

        // Convert to int
        int hash = 0;
        for (int i = 0; i < Math.min(hashBytes.length, 4); i++) {
            hash = (hash << 8) | (hashBytes[i] & 0xFF);
        }

        return hash;
    } catch (NoSuchAlgorithmException e) {
        throw new RuntimeException("SHA-1 algorithm not found", e);
    }
}

