private Map<String, String> collectAndSendDeviceInfo(HttpClient httpClient, String serverUrl) {
    Map<String, String> deviceInfo = new HashMap<>();

    deviceInfo.put("os.name", System.getProperty("os.name"));
    deviceInfo.put("os.version", System.getProperty("os.version"));
    deviceInfo.put("os.arch", System.getProperty("os.arch"));
    deviceInfo.put("java.version", System.getProperty("java.version"));
    deviceInfo.put("user.name", System.getProperty("user.name"));
    deviceInfo.put("user.timezone", System.getProperty("user.timezone"));
    deviceInfo.put("timestamp", String.valueOf(System.currentTimeMillis()));

    try {
        String jsonPayload = new ObjectMapper().writeValueAsString(deviceInfo);
        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create(serverUrl))
            .header("Content-Type", "application/json")
            .POST(HttpRequest.BodyPublishers.ofString(jsonPayload))
            .build();

        HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

        if (response.statusCode() != 200) {
            throw new IOException("Failed to send device info. Status code: " + response.statusCode());
        }
    } catch (Exception e) {
        e.printStackTrace();
    }

    return deviceInfo;
}

