private Object serializeAndDeserialize(Object objectToSerialize, Object parentObject) throws IOException, ClassNotFoundException {
    ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();
    ObjectOutputStream objectOutputStream = null;
    ObjectInputStream objectInputStream = null;
    Object deserializedObject = null;

    try {
        objectOutputStream = new ObjectOutputStream(byteArrayOutputStream);
        objectOutputStream.writeObject(objectToSerialize);
        objectOutputStream.reset();

        byte[] serializedData = byteArrayOutputStream.toByteArray();
        ByteArrayInputStream byteArrayInputStream = new ByteArrayInputStream(serializedData);
        objectInputStream = new ObjectInputStream(byteArrayInputStream);

        deserializedObject = objectInputStream.readObject();

        if (deserializedObject != null && parentObject != null) {
            Field[] fields = parentObject.getClass().getDeclaredFields();
            for (Field field : fields) {
                if (field.get(parentObject) == objectToSerialize) {
                    field.setAccessible(true);
                    field.set(parentObject, deserializedObject);
                    break;
                }
            }
        }
    } finally {
        if (objectOutputStream != null) {
            objectOutputStream.close();
        }
        if (objectInputStream != null) {
            objectInputStream.close();
        }
        byteArrayOutputStream.close();
    }

    return deserializedObject;
}

