public static int executeCommand(String[] commands, InputStream input, OutputStream output, Optional<Long> timeout) throws IOException, InterruptedException {
    Process process = Runtime.getRuntime().exec(commands);

    // Handle input stream if provided
    if (input != null) {
        try (OutputStream processInput = process.getOutputStream()) {
            byte[] buffer = new byte[1024];
            int length;
            while ((length = input.read(buffer)) != -1) {
                processInput.write(buffer, 0, length);
            }
        }
    }

    // Handle output stream if provided
    if (output != null) {
        try (InputStream processOutput = process.getInputStream()) {
            byte[] buffer = new byte[1024];
            int length;
            while ((length = processOutput.read(buffer)) != -1) {
                output.write(buffer, 0, length);
            }
        }
    }

    if (timeout.isPresent()) {
        if (!process.waitFor(timeout.get(), TimeUnit.MILLISECONDS)) {
            process.destroy();
            throw new InterruptedException("Process timed out after " + timeout.get() + " milliseconds");
        }
    } else {
        process.waitFor();
    }

    return process.exitValue();
}

public static int executeCommand(String command, InputStream input, OutputStream output, Optional<Long> timeout) throws IOException, InterruptedException {
    return executeCommand(new String[]{command}, input, output, timeout);
}
