import java.io.*;
import java.util.*;

public class NFASerializationTest {
    static class State implements Serializable {
        private static final long serialVersionUID = 1L;
        int id;
        boolean accepting;
        Map<Character, Set<State>> transitions;

        public State(int id) {
            this.id = id;
            this.accepting = false;
            this.transitions = new HashMap<>();
        }

        public void addTransition(char symbol, State target) {
            transitions.computeIfAbsent(symbol, k -> new HashSet<>()).add(target);
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (!(o instanceof State)) return false;
            State state = (State) o;
            return id == state.id && accepting == state.accepting;
        }

        @Override
        public int hashCode() {
            return Objects.hash(id, accepting);
        }
    }

    static class NFA implements Serializable {
        private static final long serialVersionUID = 1L;
        State startState;
        Set<State> states;

        public NFA() {
            this.states = new HashSet<>();
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (!(o instanceof NFA)) return false;
            NFA nfa = (NFA) o;
            return Objects.equals(startState, nfa.startState) && 
                   Objects.equals(states, nfa.states);
        }

        @Override
        public int hashCode() {
            return Objects.hash(startState, states);
        }
    }

    public static NFA createNFA(int windowLength) {
        NFA nfa = new NFA();
        State[] states = new State[windowLength + 1];

        for (int i = 0; i <= windowLength; i++) {
            states[i] = new State(i);
            nfa.states.add(states[i]);
        }

        nfa.startState = states[0];
        states[windowLength].accepting = true;

        for (int i = 0; i < windowLength; i++) {
            states[i].addTransition('0', states[i + 1]);
            states[i].addTransition('1', states[i + 1]);
        }

        return nfa;
    }

    public static NFA serializeAndDeserialize(NFA original) throws IOException, ClassNotFoundException {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        ObjectOutputStream oos = new ObjectOutputStream(baos);
        oos.writeObject(original);
        oos.close();

        ByteArrayInputStream bais = new ByteArrayInputStream(baos.toByteArray());
        ObjectInputStream ois = new ObjectInputStream(bais);
        NFA deserialized = (NFA) ois.readObject();
        ois.close();

        return deserialized;
    }

    public static boolean testNFASerialization(int windowLength) {
        try {
            NFA original = createNFA(windowLength);
            NFA deserialized = serializeAndDeserialize(original);
            return original.equals(deserialized);
        } catch (IOException | ClassNotFoundException e) {
            return false;
        }
    }
}
