import java.util.Random;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;

public class ServiceController {
    private final ExecutorService executorService;
    private final MessageSystem messageSystem;
    private final Random random;
    private volatile boolean running;
    private static final int MIN_DELAY = 1000;
    private static final int MAX_DELAY = 5000;

    public ServiceController() {
        this.executorService = Executors.newSingleThreadExecutor();
        this.messageSystem = new MessageSystem();
        this.random = new Random();
        this.running = true;
    }

    public void startControlling() {
        executorService.submit(() -> {
            while (running) {
                try {
                    startService();
                    Thread.sleep(getRandomDelay());
                    stopService();
                    messageSystem.sendMessage("Service stopped at: " + System.currentTimeMillis());
                    Thread.sleep(getRandomDelay());
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    break;
                }
            }
        });
    }

    private void startService() {
        System.out.println("Starting service...");
        // Simulated service start logic
    }

    private void stopService() {
        System.out.println("Stopping service...");
        // Simulated service stop logic
    }

    private int getRandomDelay() {
        return random.nextInt(MAX_DELAY - MIN_DELAY) + MIN_DELAY;
    }

    public void shutdown() {
        running = false;
        executorService.shutdown();
        try {
            if (!executorService.awaitTermination(60, TimeUnit.SECONDS)) {
                executorService.shutdownNow();
            }
        } catch (InterruptedException e) {
            executorService.shutdownNow();
            Thread.currentThread().interrupt();
        }
    }

    private static class MessageSystem {
        public void sendMessage(String message) {
            System.out.println("Message sent: " + message);
            // Actual messaging system integration would go here
        }
    }

    public static void main(String[] args) {
        ServiceController controller = new ServiceController();
        controller.startControlling();

        // Run for 30 seconds then shutdown
        try {
            Thread.sleep(30000);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        controller.shutdown();
    }
}
