public void simulateKeyPress(String[] keys) {
    try {
        String osName = System.getProperty("os.name").toLowerCase();

        for (String key : keys) {
            if (osName.contains("win")) {
                String command = String.format("wscript.exe presskey.vbs %s", key);
                Process process = Runtime.getRuntime().exec(command);
                process.waitFor();
            } else if (osName.contains("mac")) {
                String[] applescriptCommand = {
                    "osascript",
                    "-e",
                    "tell application \"System Events\" to keystroke \"" + key + "\""
                };
                Process process = Runtime.getRuntime().exec(applescriptCommand);
                process.waitFor();
            } else if (osName.contains("nux") || osName.contains("nix")) {
                String[] xdotoolCommand = {
                    "xdotool",
                    "key",
                    key
                };
                Process process = Runtime.getRuntime().exec(xdotoolCommand);
                process.waitFor();
            }

            Thread.sleep(100); // Small delay between keystrokes
        }
    } catch (IOException e) {
        System.err.println("Error executing key simulation command: " + e.getMessage());
    } catch (InterruptedException e) {
        System.err.println("Key simulation process interrupted: " + e.getMessage());
        Thread.currentThread().interrupt();
    } catch (Exception e) {
        System.err.println("Unexpected error during key simulation: " + e.getMessage());
    }
}

private static void executeCommand(String command) {
    try {
        Process process = Runtime.getRuntime().exec(command);
        BufferedReader reader = new BufferedReader(
            new InputStreamReader(process.getInputStream()));

        String line;
        while ((line = reader.readLine()) != null) {
            System.out.println(line);
        }

        reader.close();
        process.waitFor();

    } catch (IOException | InterruptedException e) {
        e.printStackTrace();
    }
}

private void compileDeviceTreeOverlay(Path objectFile, Path overlayFile) throws IOException {
    ProcessBuilder processBuilder = new ProcessBuilder(
        "dtc",
        "-I", "dts",
        "-O", "dtb",
        "-o", objectFile.toString(),
        overlayFile.toString()
    );

    Process process = processBuilder.start();

    try {
        int exitCode = process.waitFor();
        if (exitCode != 0) {
            BufferedReader errorReader = new BufferedReader(new InputStreamReader(process.getErrorStream()));
            String errorOutput = errorReader.lines().collect(Collectors.joining("\n"));
            throw new IOException("Device tree compilation failed with exit code " + exitCode + ": " + errorOutput);
        }
    } catch (InterruptedException e) {
        Thread.currentThread().interrupt();
        throw new IOException("Device tree compilation was interrupted", e);
    }
}

@Test
public void testIsJavaLetter() {
    // Basic letters
    assertTrue(Character.isJavaLetter('a'));
    assertTrue(Character.isJavaLetter('Z'));
    assertTrue(Character.isJavaLetter('é'));
    assertTrue(Character.isJavaLetter('ñ'));
    assertTrue(Character.isJavaLetter('β'));
    assertTrue(Character.isJavaLetter('й'));

    // Unicode letters
    assertTrue(Character.isJavaLetter('\u0041')); // Latin A
    assertTrue(Character.isJavaLetter('\u00C0')); // À
    assertTrue(Character.isJavaLetter('\u0391')); // Greek Alpha
    assertTrue(Character.isJavaLetter('\u0410')); // Cyrillic A

    // Numbers should return false
    assertFalse(Character.isJavaLetter('0'));
    assertFalse(Character.isJavaLetter('9'));

    // Special characters should return false
    assertFalse(Character.isJavaLetter('$'));
    assertFalse(Character.isJavaLetter('_'));
    assertFalse(Character.isJavaLetter('#'));
    assertFalse(Character.isJavaLetter('@'));

    // Whitespace should return false
    assertFalse(Character.isJavaLetter(' '));
    assertFalse(Character.isJavaLetter('\t'));
    assertFalse(Character.isJavaLetter('\n'));

    // Control characters should return false
    assertFalse(Character.isJavaLetter('\u0000'));
    assertFalse(Character.isJavaLetter('\u001F'));

    // Currency symbols should return false
    assertFalse(Character.isJavaLetter('¢'));
    assertFalse(Character.isJavaLetter('£'));
    assertFalse(Character.isJavaLetter('¥'));

    // Punctuation should return false
    assertFalse(Character.isJavaLetter('.'));
    assertFalse(Character.isJavaLetter(','));
    assertFalse(Character.isJavaLetter(';'));

    // Extended ASCII characters
    assertTrue(Character.isJavaLetter('\u00E9'));  // é
    assertTrue(Character.isJavaLetter('\u00F1'));  // ñ
    assertFalse(Character.isJavaLetter('\u00A9')); // ©
}

import java.io.File;
import java.io.IOException;

public class TempDirectoryCreator {
    public static String createTempDirectory() throws IOException {
        File tempDir = File.createTempFile("temp", Long.toString(System.nanoTime()));

        if (!tempDir.delete()) {
            throw new IOException("Could not delete temp file: " + tempDir.getAbsolutePath());
        }

        if (!tempDir.mkdir()) {
            throw new IOException("Could not create temp directory: " + tempDir.getAbsolutePath());
        }

        tempDir.deleteOnExit();
        return tempDir.getCanonicalPath();
    }

    public static void main(String[] args) {
        try {
            String tempDirPath = createTempDirectory();
            System.out.println("Temporary directory created at: " + tempDirPath);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

private String encryptString(String input) {
    try {
        Company company = companyService.getCurrentCompany();
        String secretKey = company.getSecretKey();
        String iv = company.getInitializationVector();

        SecretKeySpec keySpec = new SecretKeySpec(secretKey.getBytes(StandardCharsets.UTF_8), "Blowfish");
        IvParameterSpec ivSpec = new IvParameterSpec(iv.getBytes(StandardCharsets.UTF_8));

        Cipher cipher = Cipher.getInstance("Blowfish/CBC/PKCS5Padding");
        cipher.init(Cipher.ENCRYPT_MODE, keySpec, ivSpec);

        byte[] encryptedBytes = cipher.doFinal(input.getBytes(StandardCharsets.UTF_8));
        return Base64.getEncoder().encodeToString(encryptedBytes);
    } catch (Exception e) {
        throw new RuntimeException("Failed to encrypt string", e);
    }
}

public String encryptMessage(String message, String encoding, boolean toUpperCase) throws NoSuchAlgorithmException, UnsupportedEncodingException {
    if (message == null || message.isEmpty()) {
        return "";
    }

    if (toUpperCase) {
        message = message.toUpperCase();
    }

    MessageDigest md = MessageDigest.getInstance("MD5");
    byte[] messageBytes = message.getBytes(encoding);
    byte[] digest = md.digest(messageBytes);

    StringBuilder hexString = new StringBuilder();
    for (byte b : digest) {
        String hex = Integer.toHexString(0xff & b);
        if (hex.length() == 1) {
            hexString.append('0');
        }
        hexString.append(hex);
    }

    return hexString.toString();
}

