import java.io.BufferedReader;
import java.io.File;
import java.io.InputStreamReader;
import java.util.ArrayList;
import java.util.List;

public class QueryGenerator {
    private String toolPath;
    private String templateDir;

    public QueryGenerator(String toolPath, String templateDir) {
        this.toolPath = toolPath;
        this.templateDir = templateDir;
    }

    public List<String> generateQueries(String templateName, String[] params) throws Exception {
        List<String> generatedQueries = new ArrayList<>();

        ProcessBuilder pb = new ProcessBuilder(
            toolPath,
            "--template", templateDir + File.separator + templateName,
            "--params", String.join(",", params)
        );

        pb.redirectErrorStream(true);
        Process process = pb.start();

        try (BufferedReader reader = new BufferedReader(
                new InputStreamReader(process.getInputStream()))) {

            String line;
            while ((line = reader.readLine()) != null) {
                if (!line.trim().isEmpty()) {
                    generatedQueries.add(line);
                }
            }
        }

        int exitCode = process.waitFor();
        if (exitCode != 0) {
            throw new RuntimeException("Query generation failed with exit code: " + exitCode);
        }

        return generatedQueries;
    }

    public static void main(String[] args) {
        try {
            QueryGenerator generator = new QueryGenerator(
                "/usr/local/bin/query-gen",
                "/path/to/templates"
            );

            String[] params = {"param1=value1", "param2=value2"};
            List<String> queries = generator.generateQueries("sample.template", params);

            for (String query : queries) {
                System.out.println("Generated query: " + query);
            }

        } catch (Exception e) {
            System.err.println("Error generating queries: " + e.getMessage());
            e.printStackTrace();
        }
    }
}
