import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public class MD5Filter implements Filter {
    private final int frequency;
    private MessageDigest md;

    public MD5Filter(int frequency) {
        this.frequency = frequency;
        try {
            this.md = MessageDigest.getInstance("MD5");
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("MD5 algorithm not available", e);
        }
    }

    @Override
    public byte[] filter(byte[] input) {
        md.reset();
        md.update(input);
        byte[] hash = md.digest();

        int firstByte = hash[0] & 0xFF;
        if (firstByte % frequency == 0) {
            return hash;
        }

        return new byte[0];
    }
}

interface Filter {
    byte[] filter(byte[] input);
}

private void configureWebView(WebView webView) throws NullPointerException {
    if (webView == null) {
        throw new NullPointerException("WebView cannot be null");
    }

    try {
        WebSettings settings = webView.getSettings();
        settings.setJavaScriptEnabled(true);
        settings.setUserAgentString("Mozilla/5.0 (Linux; Android 10; Mobile)");
        settings.setAllowFileAccess(true);
        settings.setCacheMode(WebSettings.LOAD_DEFAULT);
        settings.setDomStorageEnabled(true);
        settings.setDatabaseEnabled(true);

        String cachePath = webView.getContext().getCacheDir().getAbsolutePath();
        settings.setAppCachePath(cachePath);
        settings.setAppCacheEnabled(true);

        settings.setSupportZoom(true);
        settings.setBuiltInZoomControls(true);
        settings.setDisplayZoomControls(false);

        settings.setLoadWithOverviewMode(true);
        settings.setUseWideViewPort(true);

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
            settings.setMixedContentMode(WebSettings.MIXED_CONTENT_ALWAYS_ALLOW);
        }
    } catch (Exception e) {
        throw new RuntimeException("Error configuring WebView: " + e.getMessage());
    }
}

import javax.swing.*;
import java.awt.Desktop;
import java.io.File;
import java.io.IOException;

public void openFileOrDirectory() {
    JFileChooser fileChooser = new JFileChooser();
    fileChooser.setFileSelectionMode(JFileChooser.FILES_AND_DIRECTORIES);

    int result = fileChooser.showOpenDialog(null);

    if (result == JFileChooser.APPROVE_OPTION) {
        File selectedFile = fileChooser.getSelectedFile();

        try {
            if (Desktop.isDesktopSupported()) {
                Desktop desktop = Desktop.getDesktop();
                desktop.open(selectedFile);
            } else {
                String os = System.getProperty("os.name").toLowerCase();
                ProcessBuilder processBuilder = null;

                if (os.contains("win")) {
                    processBuilder = new ProcessBuilder("cmd", "/c", "start", selectedFile.getAbsolutePath());
                } else if (os.contains("mac")) {
                    processBuilder = new ProcessBuilder("open", selectedFile.getAbsolutePath());
                } else if (os.contains("nix") || os.contains("nux")) {
                    processBuilder = new ProcessBuilder("xdg-open", selectedFile.getAbsolutePath());
                }

                if (processBuilder != null) {
                    processBuilder.start();
                } else {
                    JOptionPane.showMessageDialog(null,
                        "Unsupported operating system",
                        "Error",
                        JOptionPane.ERROR_MESSAGE);
                }
            }
        } catch (IOException e) {
            JOptionPane.showMessageDialog(null,
                "Error opening file: " + e.getMessage(),
                "Error",
                JOptionPane.ERROR_MESSAGE);
        }
    }
}

import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public class MD5Digest {
    private MessageDigest md;

    public MD5Digest() {
        try {
            md = MessageDigest.getInstance("MD5");
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("MD5 algorithm not available", e);
        }
    }

    public String digest(String input) {
        md.reset();
        byte[] hash = md.digest(input.getBytes());
        StringBuilder hexString = new StringBuilder();

        for (byte b : hash) {
            String hex = Integer.toHexString(0xff & b);
            if (hex.length() == 1) {
                hexString.append('0');
            }
            hexString.append(hex);
        }

        return hexString.toString();
    }

    @Override
    public String toString() {
        return "MD5 Message-Digest Algorithm";
    }
}

public static long getHashValue(String input) throws NoSuchAlgorithmException {
    byte[] asciiBytes = input.getBytes(StandardCharsets.US_ASCII);
    MessageDigest md = MessageDigest.getInstance("SHA-1");
    byte[] hashBytes = md.digest(asciiBytes);

    long hashValue = 0;
    for (int i = 0; i < 8 && i < hashBytes.length; i++) {
        hashValue = (hashValue << 8) | (hashBytes[i] & 0xFF);
    }

    return hashValue & 0xFFFFFFFFFFFFFFFFL;
}

import javax.tools.*;
import java.io.*;
import java.net.URI;
import java.util.*;

public class RuntimeCompiler {
    public static void compileSource(String sourceCode, String className, String outputPath) throws IOException {
        JavaCompiler compiler = ToolProvider.getSystemJavaCompiler();
        DiagnosticCollector<JavaFileObject> diagnostics = new DiagnosticCollector<>();
        StandardJavaFileManager fileManager = compiler.getStandardFileManager(diagnostics, null, null);

        JavaFileObject javaFile = new JavaSourceFromString(className, sourceCode);
        Iterable<? extends JavaFileObject> compilationUnits = Arrays.asList(javaFile);

        String classPath = System.getProperty("java.class.path");
        List<String> options = Arrays.asList("-d", outputPath, "-classpath", classPath);

        JavaCompiler.CompilationTask task = compiler.getTask(
            null,
            fileManager,
            diagnostics,
            options,
            null,
            compilationUnits
        );

        boolean success = task.call();

        if (!success) {
            for (Diagnostic<? extends JavaFileObject> diagnostic : diagnostics.getDiagnostics()) {
                System.err.format("Error on line %d: %s%n",
                    diagnostic.getLineNumber(),
                    diagnostic.getMessage(null));
            }
            throw new IOException("Compilation failed");
        }

        fileManager.close();
    }
}

