public static String executeCommand(String command) throws IOException {
    Process process = Runtime.getRuntime().exec(command);
    BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
    StringBuilder output = new StringBuilder();
    String line;

    while ((line = reader.readLine()) != null) {
        output.append(line).append("\n");
    }

    reader.close();
    return output.toString();
}

private boolean uploadFileWithRetry(String fileUrl, File file) throws IOException {
    int maxRetries = 3;
    int retryCount = 0;
    boolean success = false;

    while (!success && retryCount < maxRetries) {
        HttpURLConnection connection = null;
        try {
            URL url = new URL(fileUrl);
            connection = (HttpURLConnection) url.openConnection();
            connection.setDoOutput(true);
            connection.setRequestMethod("POST");
            connection.setRequestProperty("Content-Type", "multipart/form-data");

            try (OutputStream os = connection.getOutputStream();
                 FileInputStream fis = new FileInputStream(file)) {
                byte[] buffer = new byte[4096];
                int bytesRead;
                while ((bytesRead = fis.read(buffer)) != -1) {
                    os.write(buffer, 0, bytesRead);
                }
                os.flush();
            }

            int responseCode = connection.getResponseCode();
            success = (responseCode >= 200 && responseCode < 300);

            if (!success) {
                retryCount++;
                Thread.sleep(1000 * retryCount); // Exponential backoff
            }
        } catch (Exception e) {
            retryCount++;
            if (retryCount == maxRetries) {
                throw new IOException("Failed to upload file after " + maxRetries + " attempts", e);
            }
            try {
                Thread.sleep(1000 * retryCount); // Exponential backoff
            } catch (InterruptedException ie) {
                Thread.currentThread().interrupt();
                throw new IOException("Upload interrupted", ie);
            }
        } finally {
            if (connection != null) {
                connection.disconnect();
            }
        }
    }
    return success;
}

private void openImageEditor(String imagePath) {
    String editorPath = getConfiguredEditorPath();

    if (editorPath != null && !editorPath.isEmpty()) {
        try {
            Process process = Runtime.getRuntime().exec(new String[]{editorPath, imagePath});
            process.waitFor();

            if (process.exitValue() != 0) {
                showNotification("Editor Error", "Image editor failed to open properly");
                openImageGallery(imagePath);
            }
        } catch (IOException | InterruptedException e) {
            showNotification("Editor Error", "Failed to launch image editor");
            openImageGallery(imagePath);
        }
    } else {
        showNotification("Editor Not Configured", "No image editor is configured");
        openImageGallery(imagePath);
    }
}

private String getConfiguredEditorPath() {
    // This could read from configuration file or settings
    return System.getProperty("image.editor.path");
}

private void showNotification(String title, String message) {
    // Implementation for showing system notification
    SystemTray tray = SystemTray.getSystemTray();
    try {
        TrayIcon trayIcon = new TrayIcon(createDefaultImage());
        tray.add(trayIcon);
        trayIcon.displayMessage(title, message, TrayIcon.MessageType.INFO);
        tray.remove(trayIcon);
    } catch (AWTException e) {
        e.printStackTrace();
    }
}

private void openImageGallery(String imagePath) {
    try {
        Desktop.getDesktop().open(new File(imagePath));
    } catch (IOException e) {
        e.printStackTrace();
    }
}

private Image createDefaultImage() {
    BufferedImage image = new BufferedImage(16, 16, BufferedImage.TYPE_INT_RGB);
    Graphics2D g = image.createGraphics();
    g.setColor(Color.WHITE);
    g.fillRect(0, 0, 16, 16);
    g.dispose();
    return image;
}

import javax.crypto.Cipher;
import javax.crypto.spec.IvParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.nio.charset.StandardCharsets;
import java.util.Base64;

public String encrypt(String key, String target) throws Exception {
    byte[] keyBytes = new byte[16];
    byte[] ivBytes = new byte[16];
    byte[] keyData = key.getBytes(StandardCharsets.UTF_8);

    System.arraycopy(keyData, 0, keyBytes, 0, Math.min(keyData.length, 16));
    System.arraycopy(keyData, 0, ivBytes, 0, Math.min(keyData.length, 16));

    SecretKeySpec secretKey = new SecretKeySpec(keyBytes, "AES");
    IvParameterSpec iv = new IvParameterSpec(ivBytes);

    Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
    cipher.init(Cipher.ENCRYPT_MODE, secretKey, iv);

    byte[] encrypted = cipher.doFinal(target.getBytes(StandardCharsets.UTF_8));
    return Base64.getEncoder().encodeToString(encrypted);
}

public static String calculateMD5(String filePath) throws IOException, NoSuchAlgorithmException {
    MessageDigest md = MessageDigest.getInstance("MD5");
    try (FileInputStream fis = new FileInputStream(filePath)) {
        byte[] buffer = new byte[8192];
        int bytesRead;
        while ((bytesRead = fis.read(buffer)) != -1) {
            md.update(buffer, 0, bytesRead);
        }
    }

    byte[] digest = md.digest();
    StringBuilder sb = new StringBuilder();
    for (byte b : digest) {
        sb.append(String.format("%02x", b));
    }
    return sb.toString();
}

