public boolean modifyXmlProperty(String propertyGroup, String propertyName, String newValue) {
    try {
        DocumentBuilderFactory docFactory = DocumentBuilderFactory.newInstance();
        DocumentBuilder docBuilder = docFactory.newDocumentBuilder();
        Document doc = docBuilder.parse("config.xml");

        XPathFactory xPathFactory = XPathFactory.newInstance();
        XPath xpath = xPathFactory.newXPath();

        String xpathExpression = String.format("//group[@name='%s']/property[@name='%s']", 
            propertyGroup, propertyName);

        XPathExpression expr = xpath.compile(xpathExpression);
        Node node = (Node) expr.evaluate(doc, XPathConstants.NODE);

        if (node != null) {
            node.setTextContent(newValue);

            TransformerFactory transformerFactory = TransformerFactory.newInstance();
            Transformer transformer = transformerFactory.newTransformer();
            DOMSource source = new DOMSource(doc);
            StreamResult result = new StreamResult(new File("config.xml"));
            transformer.transform(source, result);

            return true;
        }

        return false;

    } catch (Exception e) {
        e.printStackTrace();
        return false;
    }
}
