private Map<String, Edge> createEdges(List<VertexBuilder> vertexBuilders) {
    Map<String, Edge> edgeMap = new HashMap<>();

    for (VertexBuilder builder : vertexBuilders) {
        Vertex sourceVertex = builder.getSourceVertex();
        List<Vertex> targetVertices = builder.getTargetVertices();
        String edgeLabel = builder.getEdgeLabel();
        Map<String, Object> properties = builder.getEdgeProperties();

        for (Vertex targetVertex : targetVertices) {
            String edgeHash = generateEdgeHash(sourceVertex.id(), targetVertex.id(), edgeLabel);

            if (!edgeMap.containsKey(edgeHash)) {
                Edge edge = sourceVertex.addEdge(edgeLabel, targetVertex);
                properties.forEach(edge::property);
                edgeMap.put(edgeHash, edge);
            }
        }
    }

    return edgeMap;
}

private String generateEdgeHash(Object sourceId, Object targetId, String label) {
    return String.format("%s_%s_%s", sourceId.toString(), targetId.toString(), label);
}

