        String[] command = new String[]{
            filePath,
            url,
            outputPath,
            fileType,
            String.valueOf(compress)
        };

        Process process = Runtime.getRuntime().exec(command);
        process.waitFor();
    } catch (IOException e) {
        logger.error("Error executing command: " + e.getMessage(), e);
