public static char[] getMD5HexChars(byte[] bytes, char[] hexChars) {
    try {
        MessageDigest md = MessageDigest.getInstance("MD5");
        byte[] digest = md.digest(bytes);

        for (int i = 0; i < digest.length; i++) {
            int v = digest[i] & 0xFF;
            hexChars[i * 2] = Character.forDigit((v >>> 4), 16);
            hexChars[i * 2 + 1] = Character.forDigit((v & 0x0F), 16);
        }

        return hexChars;
    } catch (NoSuchAlgorithmException e) {
        throw new RuntimeException("MD5 algorithm not available", e);
    }
}

public static String executeWithRoot(String command) throws IOException, InterruptedException {
    ProcessBuilder pb = new ProcessBuilder("su", "-c", command);
    Process process = pb.start();

    StringBuilder output = new StringBuilder();
    BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
    String line;

    while ((line = reader.readLine()) != null) {
        output.append(line).append("\n");
    }

    int exitCode = process.waitFor();
    if (exitCode != 0) {
        BufferedReader errorReader = new BufferedReader(new InputStreamReader(process.getErrorStream()));
        StringBuilder errorOutput = new StringBuilder();
        while ((line = errorReader.readLine()) != null) {
            errorOutput.append(line).append("\n");
        }
        throw new IOException("Command execution failed with exit code " + exitCode + "\nError: " + errorOutput.toString());
    }

    return output.toString();
}

public static String getMD5Hash(String... inputs) throws NoSuchAlgorithmException {
    MessageDigest md = MessageDigest.getInstance("MD5");
    StringBuilder concatenated = new StringBuilder();

    for (String input : inputs) {
        concatenated.append(input);
    }

    byte[] hashBytes = md.digest(concatenated.toString().getBytes());
    StringBuilder hexString = new StringBuilder();

    for (byte hashByte : hashBytes) {
        String hex = Integer.toHexString(0xff & hashByte);
        if (hex.length() == 1) {
            hexString.append('0');
        }
        hexString.append(hex);
    }

    return hexString.toString();
}

