import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.HashMap;
import java.util.Map;
import java.util.function.Function;

public class HashGenerator {
    private static final Map<String, Function<String, String>> hashFunctions = new HashMap<>();

    static {
        hashFunctions.put("MD5", input -> hash(input, "MD5"));
        hashFunctions.put("SHA-1", input -> hash(input, "SHA-1"));
        hashFunctions.put("SHA-256", input -> hash(input, "SHA-256"));
        hashFunctions.put("SHA-384", input -> hash(input, "SHA-384")); 
        hashFunctions.put("SHA-512", input -> hash(input, "SHA-512"));
    }

    private static String hash(String input, String algorithm) {
        try {
            MessageDigest digest = MessageDigest.getInstance(algorithm);
            byte[] hash = digest.digest(input.getBytes());
            StringBuilder hexString = new StringBuilder();

            for (byte b : hash) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) {
                    hexString.append('0');
                }
                hexString.append(hex);
            }

            return hexString.toString();
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("Hash algorithm not found", e);
        }
    }

    public static String generateHash(String input, String algorithm) {
        Function<String, String> hashFunction = hashFunctions.get(algorithm.toUpperCase());
        if (hashFunction == null) {
            throw new IllegalArgumentException("Unsupported hash algorithm: " + algorithm);
        }
        return hashFunction.apply(input);
    }

    public static void main(String[] args) {
        String input = "Hello, World!";
        String[] algorithms = {"MD5", "SHA-1", "SHA-256", "SHA-384", "SHA-512"};

        for (String algorithm : algorithms) {
            String hash = generateHash(input, algorithm);
            System.out.printf("%s: %s%n", algorithm, hash);
        }
    }
}
