private String generateMD5AndCreateGroup(List<String> strings, List<ServerGroup> serverGroups) {
    String concatenatedString = String.join("", strings);
    String md5Hash = DigestUtils.md5Hex(concatenatedString);

    boolean groupExists = serverGroups.stream()
        .anyMatch(group -> group.getGroupId().equals(md5Hash));

    if (!groupExists) {
        ServerGroup newGroup = new ServerGroup();
        newGroup.setGroupId(md5Hash);
        newGroup.setBackendServers(new ArrayList<>());
        serverGroups.add(newGroup);
    }

    return md5Hash;
}

private void debugStep(String expression) {
    try {
        setDebugMode("step");
        boolean result = evaluateExpression(expression);
        if (result) {
            String currentLocation = getCurrentLocation();
            System.out.println("Breakpoint hit at: " + currentLocation);
            System.out.println("Expression evaluation successful");
        }
    } catch (Exception e) {
        System.err.println("Debug step failed: " + e.getMessage());
    } finally {
        resetDebugMode();
    }
}

