public void registerUser(String username, String password, HttpSession session) {
    try {
        if (username == null || username.trim().isEmpty() || 
            password == null || password.trim().isEmpty()) {
            logger.warn("Username or password is empty");
            session.setAttribute("error", "Username and password are required");
            return;
        }

        String hashedPassword = hashPassword(password);

        Connection conn = null;
        PreparedStatement ps = null;

        try {
            conn = dataSource.getConnection();
            ps = conn.prepareStatement(
                "INSERT INTO users (username, password) VALUES (?, ?)");
            ps.setString(1, username);
            ps.setString(2, hashedPassword);
            ps.executeUpdate();

        } catch (SQLException e) {
            logger.error("Error registering new user", e);
            session.setAttribute("error", "Database error occurred");
            throw new RuntimeException(e);
        } finally {
            if (ps != null) {
                ps.close();
            }
            if (conn != null) {
                conn.close(); 
            }
        }

    } catch (Exception e) {
        logger.error("Unexpected error during registration", e);
        session.setAttribute("error", "An unexpected error occurred");
    }
}

