public String generateRandomString(double seed) {
    try {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        String seedString = String.valueOf(seed);
        byte[] hashBytes = digest.digest(seedString.getBytes(StandardCharsets.UTF_8));

        StringBuilder hexString = new StringBuilder();
        for (byte b : hashBytes) {
            String hex = Integer.toHexString(0xff & b);
            if (hex.length() == 1) {
                hexString.append('0');
            }
            hexString.append(hex);
        }

        return hexString.substring(0, Math.min(32, hexString.length()));
    } catch (NoSuchAlgorithmException e) {
        return null;
    }
}

