public String mergeIntervals(List<DataSegment> segments) {
    if (segments == null || segments.isEmpty()) {
        return "";
    }

    // Sort segments by start time
    Collections.sort(segments, (a, b) -> a.getStart().compareTo(b.getStart()));

    DateTime start = segments.get(0).getStart();
    DateTime end = segments.get(0).getEnd();

    // Merge overlapping intervals
    for (int i = 1; i < segments.size(); i++) {
        DataSegment current = segments.get(i);

        if (current.getStart().isBefore(end) || current.getStart().isEqual(end)) {
            end = end.isAfter(current.getEnd()) ? end : current.getEnd();
        } else {
            start = current.getStart();
            end = current.getEnd();
        }
    }

    return start.toString() + "-" + end.toString();
}
