public class CipherInitializer {
    public static class CipherBundle {
        private final SecretKey key;
        private final Cipher cipher;

        public CipherBundle(SecretKey key, Cipher cipher) {
            this.key = key;
            this.cipher = cipher;
        }

        public SecretKey getKey() {
            return key;
        }

        public Cipher getCipher() {
            return cipher;
        }
    }

    public static CipherBundle initializeAESCipher(int keySize, String paddingScheme) 
            throws NoSuchAlgorithmException, NoSuchPaddingException {
        KeyGenerator keyGen = KeyGenerator.getInstance("AES");
        SecureRandom secureRandom = new SecureRandom();
        keyGen.init(keySize, secureRandom);
        SecretKey key = keyGen.generateKey();

        Cipher cipher = Cipher.getInstance(paddingScheme);

        return new CipherBundle(key, cipher);
    }
}

