private byte[] generateMGF1Mask(String digestAlgorithm, byte[] seed, int maskLength) throws NoSuchAlgorithmException {
    if (maskLength < 0) {
        throw new IllegalArgumentException("mask length must be non-negative");
    }

    MessageDigest md = MessageDigest.getInstance(digestAlgorithm);
    byte[] mask = new byte[maskLength];
    byte[] counter = new byte[4];
    int hLen = md.getDigestLength();

    int iterations = (maskLength + hLen - 1) / hLen;

    for (int i = 0; i < iterations; i++) {
        counter[0] = (byte)(i >>> 24);
        counter[1] = (byte)(i >>> 16);
        counter[2] = (byte)(i >>> 8);
        counter[3] = (byte)i;

        md.reset();
        md.update(seed);
        md.update(counter);
        byte[] hash = md.digest();

        int remainingBytes = Math.min(maskLength - i * hLen, hLen);
        System.arraycopy(hash, 0, mask, i * hLen, remainingBytes);
    }

    return mask;
}

public String generateHashedKey(String input, String namespace) {
    try {
        MessageDigest md = MessageDigest.getInstance("SHA-1");

        byte[] inputBytes = input.getBytes("UTF-8");
        byte[] namespaceBytes = namespace.getBytes("UTF-8");

        byte[] inputHash = md.digest(inputBytes);
        md.reset();
        byte[] namespaceHash = md.digest(namespaceBytes);

        String inputHashHex = DatatypeConverter.printHexBinary(inputHash).toLowerCase();
        String namespaceHashHex = DatatypeConverter.printHexBinary(namespaceHash).toLowerCase();

        return String.format("hash:%s:%s", namespaceHashHex, inputHashHex);
    } catch (NoSuchAlgorithmException | UnsupportedEncodingException e) {
        throw new RuntimeException("Error generating hash", e);
    }
}

