public void parseXMLConfiguration(InputStream xmlInput, String schemaLocation) throws Exception {
    SAXParserFactory factory = SAXParserFactory.newInstance();
    factory.setValidating(true);
    factory.setNamespaceAware(true);

    SchemaFactory schemaFactory = SchemaFactory.newInstance(XMLConstants.W3C_XML_SCHEMA_NS_URI);
    Schema schema = schemaFactory.newSchema(new File(schemaLocation));
    factory.setSchema(schema);

    SAXParser parser = factory.newSAXParser();
    CustomConfigurationHandler handler = new CustomConfigurationHandler();

    parser.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
    parser.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

    try {
        XMLReader reader = parser.getXMLReader();
        reader.setErrorHandler(new ErrorHandler() {
            @Override
            public void warning(SAXParseException e) throws SAXException {
                throw e;
            }

            @Override
            public void error(SAXParseException e) throws SAXException {
                throw e;
            }

            @Override
            public void fatalError(SAXParseException e) throws SAXException {
                throw e;
            }
        });

        parser.parse(xmlInput, handler);

    } catch (SAXException | IOException e) {
        throw new ConfigurationParseException("Failed to parse XML configuration", e);
    } finally {
        try {
            xmlInput.close();
        } catch (IOException e) {
            // Log error but don't throw
        }
    }
}

class CustomConfigurationHandler extends DefaultHandler {
    private StringBuilder currentValue = new StringBuilder();
    private Configuration config = new Configuration();

    @Override
    public void startElement(String uri, String localName, String qName, Attributes attributes) {
        currentValue.setLength(0);

        if (qName.equals("node")) {
            String id = attributes.getValue("id");
            String address = attributes.getValue("address");
            config.addNode(id, address);
        }
    }

    @Override
    public void characters(char[] ch, int start, int length) {
        currentValue.append(ch, start, length);
    }

    @Override
    public void endElement(String uri, String localName, String qName) {
        if (qName.equals("property")) {
            config.setProperty(currentValue.toString().trim());
        }
    }

    public Configuration getConfiguration() {
        return config;
    }
}

class ConfigurationParseException extends Exception {
    public ConfigurationParseException(String message, Throwable cause) {
        super(message, cause);
    }
}
