import os

def generate_candidates(generator_func, max_size, size=None, filename='candidates.txt'):
    if size is None:
        size = max_size

    candidates = set()

    while len(candidates) < max_size:
        candidate = generator_func()
        if len(candidate) == size:
            candidates.add(candidate)

    assert len(candidates) == max_size, "Candidate set size does not equal maximum size"

    with open(filename, 'w') as f:
        for candidate in candidates:
            f.write(f"{candidate}\n")

    return candidates
