import json

class JsonObject:
    registry = {}

    def to_json(self):
        return json.dumps(self.__dict__)

    @classmethod
    def from_json(cls, json_string):
        data = json.loads(json_string)
        return cls(**data)

    @classmethod
    def register_factory(cls, id, factory_func):
        cls.registry[id] = factory_func

    @classmethod
    def create_instance(cls, id, *args, **kwargs):
        if id in cls.registry:
            return cls.registry[id](*args, **kwargs)
        raise ValueError(f"No factory registered for ID: {id}")

# Example subclass
class ExampleObject(JsonObject):
    def __init__(self, name, value):
        self.name = name
        self.value = value

# Registering factory function
JsonObject.register_factory('example', ExampleObject)

# Example usage:
# Creating an instance of ExampleObject
example_instance = JsonObject.create_instance('example', name='test', value=42)
json_string = example_instance.to_json()
new_instance = JsonObject.from_json(json_string)
