```python
import random
import sys

def random_sample(population, num_samples=1, with_replacement=False, std_devs=1):
    if num_samples < 0:
        raise ValueError("Number of samples must be non-negative.")
    if not population:
        return []

    max_samples = int(sys.maxsize * std_devs)
    if num_samples > max_samples:
        raise ValueError(f"Number of samples cannot exceed {max_samples}.")

    if with_replacement:
        return [random.choice(population) for _ in range(num_samples)]
    else:
        random.shuffle(population)
        return population[:num_samples]
