import torch

def set_layer_weights_and_save_model(model, layer_weights_dict, layer_names, file_path, file_format='pt'):
    for layer_name in layer_names:
        if layer_name in layer_weights_dict:
            layer = dict(model.named_modules()).get(layer_name)
            if layer is not None:
                layer.load_state_dict(layer_weights_dict[layer_name])

    if file_format == 'pt':
        torch.save(model.state_dict(), file_path)
    elif file_format == 'onnx':
        dummy_input = torch.randn(1, *next(model.parameters()).size()[1:])  # Assuming the model takes a tensor input
        torch.onnx.export(model, dummy_input, file_path)
    else:
        raise ValueError("Unsupported file format. Use 'pt' or 'onnx'.")
