        return json.dumps({
            'amount': self.amount,
            'unit': self.unit,
            'error_bounds': self.error_bounds
        })

    def __str__(self):
        return f"{self.amount} {self.unit} ± {self.error_bounds}"

    def __eq__(self, other):
