import random
import string

def generate_random(prefix='', maxlen=10, domen=''):
    if domen:
        length = maxlen - len(prefix) - len(domen) - 1
        if length < 1:
            return prefix + '@' + domen
        random_part = ''.join(random.choices(string.ascii_letters + string.digits, k=length))
        return prefix + random_part + '@' + domen
    else:
        length = maxlen - len(prefix)
        if length < 1:
            return prefix
        return prefix + ''.join(random.choices(string.ascii_letters + string.digits, k=length))
