def process_file(filename):
    try:
        with open(filename, 'r') as file:
            lines = file.readlines()

        lines.sort()

        if lines:
            last_line = lines[-1].strip()
            sequence_number = int(last_line.split()[-1])  # Assuming the sequence number is the last item on the last line
            return sequence_number
        else:
            return None  # No lines to process

    except FileNotFoundError:
        print(f"Error: The file '{filename}' was not found.")
    except ValueError:
        print("Error: Could not convert the sequence number to an integer.")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")

    return None
