import os
import difflib

def read_file(file_path):
    with open(file_path, 'r') as file:
        return set(file.read().splitlines())

def compute_differences(file1_lines, file2_lines):
    diff = difflib.unified_diff(file1_lines, file2_lines, lineterm='')
    return list(diff)

def remove_files_based_on_criteria(files, criteria):
    return [file for file in files if criteria not in file]

def create_directory(directory):
    if not os.path.exists(directory):
        os.makedirs(directory)

def main(file1_path, file2_path, criteria, output_directory):
    file1_lines = read_file(file1_path)
    file2_lines = read_file(file2_path)

    differences = compute_differences(file1_lines, file2_lines)
    print("Differences between files:")
    for line in differences:
        print(line)

    files_to_check = [file1_path, file2_path]
    remaining_files = remove_files_based_on_criteria(files_to_check, criteria)

    create_directory(output_directory)

    for file in remaining_files:
        print(f"Processing file: {file}")
        # Additional operations can be performed here

if __name__ == "__main__":
    main('file1.txt', 'file2.txt', 'remove_criteria', 'output_directory')
