        "-d",          # With -d option
        "input.txt",   # With an input file
    ]

    for args in arguments_list:
        print(f"Running script with arguments: {args}")
        return_code = run_script(script_name, args)

        if return_code == 0:
            print("Script executed successfully.")
            # Check for the existence of certain files based on expected outcomes
            if args == "-d":
                assert check_file_existence("output_directory"), "Output directory should exist."
            elif args == "input.txt":
