import gzip

def gff3_to_gtf(input_file, output_file, dialect='default'):
    def parse_gff3_line(line):
        fields = line.strip().split('\t')
        if len(fields) < 9:
            return None
        attributes = fields[8]
        # Process attributes based on dialect
        if dialect == 'default':
            attributes = attributes.replace(';', ' ')
        return '\t'.join(fields[:8]) + '\t' + attributes

    with (gzip.open(input_file, 'rt') if input_file.endswith('.gz') else open(input_file, 'r')) as infile, \
         open(output_file, 'w') as outfile:
        for line in infile:
            if line.startswith('#'):
                outfile.write(line)  # Copy comments directly
            else:
                gtf_line = parse_gff3_line(line)
                if gtf_line:
                    outfile.write(gtf_line + '\n')
