```python
def run_tests(test_cases):
    passed = 0
    failed = 0

    for test_func, expected in test_cases:
        try:
            output = eval(test_func)()
            if output == expected:
                passed += 1
            else:
                failed += 1
                print(f"Test {test_func} failed: expected '{expected}', got '{output}'")
        except Exception as e:
            failed += 1
            print(f"Test {test_func} failed with exception: {e}")

    if failed == 0:
        print(f"All tests passed: {passed} test(s) passed.")
    else:
        print(f"{failed} test(s) failed, {passed} test(s) passed.")
