import os

def read_settings(file_path, defaults):
    settings = {}
    if not os.path.exists(file_path):
        return defaults

    try:
        with open(file_path, 'r') as file:
            for line in file:
                key, value = line.strip().split('=')
                settings[key] = value
    except Exception:
        return defaults

    for key in defaults:
        settings.setdefault(key, defaults[key])

    return settings
