```python
import hashlib

class HashGenerator:
    def __init__(self, algorithm='sha256'):
        self.algorithm = algorithm
        self.hash_obj = self.create_hash_object()

    def create_hash_object(self):
        if self.algorithm == 'md5':
            return hashlib.md5()
        elif self.algorithm == 'sha256':
            return hashlib.sha256()
        else:
            raise ValueError("Unsupported hash algorithm")

    def update(self, string):
        self.hash_obj.update(string.encode('utf-8'))

    def digest(self):
        return self.hash_obj.hexdigest()

    def clone(self):
        new_hash_gen = HashGenerator(self.algorithm)
        new_hash_gen.hash_obj = self.hash_obj.copy()
        return new_hash_gen

def hash_string(string, algorithm='sha256'):
    hash_gen = HashGenerator(algorithm)
    hash_gen.update(string)
    return hash_gen.digest()
```

