import json
import subprocess

def retrieve_etcd_data(ip_address, path, use_ssl=False, cert_path=None, key_path=None):
    url = f'https://{ip_address}{path}' if use_ssl else f'http://{ip_address}{path}'
    curl_command = ['curl', '-s', url]

    if use_ssl:
        curl_command.extend(['--cert', cert_path, '--key', key_path])

    try:
        response = subprocess.check_output(curl_command)
        return json.loads(response)
    except subprocess.CalledProcessError as e:
        print(f"Error retrieving data: {e}")
        return None
    except json.JSONDecodeError as e:
        print(f"Error decoding JSON response: {e}")
        return None
