import hashlib

def read_file(file_path):
    with open(file_path, 'r') as file:
        return file.read()

def get_file_hash(contents):
    return hashlib.sha256(contents.encode()).hexdigest()

def update_version(file_path, new_contents):
    with open(file_path, 'w') as file:
        file.write(new_contents)

def main(file_path, stored_hash):
    contents = read_file(file_path)
    current_hash = get_file_hash(contents)

    if current_hash != stored_hash:
        print("Contents have changed, updating version...")
        update_version(file_path, contents)
        new_hash = get_file_hash(contents)
        print(f"Updated hash: {new_hash}")
    else:
        print("Contents match the stored version.")

# Example usage
file_path = 'example.txt'
stored_hash = 'your_stored_hash_here'
main(file_path, stored_hash)
