import shelve

def create_data_filter(storage_file):
    def record_data(data):
        with shelve.open(storage_file) as db:
            data_type = type(data).__name__
            if data_type not in db:
                db[data_type] = []
            db[data_type].append(data)

    def playback_data(data_type):
        with shelve.open(storage_file) as db:
            return db.get(data_type, [])

    return record_data, playback_data
