```python
import warnings

def deprecate_attribute(old_name, new_name, version):
    def decorator(cls):
        private_old_name = f"_{old_name}"

        @property
        def deprecated_property(self):
            warnings.warn(
                f"{old_name} is deprecated and will be removed in version {version}. Use {new_name} instead.",
                DeprecationWarning,
                stacklevel=2
            )
            return getattr(self, private_old_name)

        @deprecated_property.setter
        def deprecated_property(self, value):
            warnings.warn(
                f"{old_name} is deprecated and will be removed in version {version}. Use {new_name} instead.",
                DeprecationWarning,
                stacklevel=2
            )
            setattr(self, private_old_name, value)

        setattr(cls, old_name, deprecated_property)
        return cls
    return decorator

@deprecate_attribute('old_name', 'new_name', '1.0.0')
class MyClass:
    def __init__(self, value):
        self._old_name = value

    @property
    def new_name(self):
        return self._old_name

    @new_name.setter
    def new_name(self, value):
        self._old_name = value
