class PythonHandler:
    def __init__(self, library_mock, method_name):
        self.library_mock = library_mock
        self.method_name = method_name

    def call_method(self, *args):
        method = getattr(self.library_mock, self.method_name)
        return method(*args)

def test_library_method(library_mock, method_name, expected_results, arg_limits):
    handler = PythonHandler(library_mock, method_name)

    # Test expected results
    for args, expected in expected_results.items():
        result = handler.call_method(*args)
        assert result == expected, f"Expected {expected} but got {result} for args {args}"

    # Test argument limits
    min_args, max_args = arg_limits
    try:
        handler.call_method(*([None] * (min_args - 1)))
        assert False, f"Method should not accept less than {min_args} arguments"
    except TypeError:
        pass  # Expected behavior

    try:
        handler.call_method(*([None] * (max_args + 1)))
        assert False, f"Method should not accept more than {max_args} arguments"
    except TypeError:
        pass  # Expected behavior
