CREATE OR REPLACE FUNCTION manage_table() RETURNS INTEGER AS $$
DECLARE
    rows_affected INTEGER;
BEGIN
    -- Create the table with an auto-incrementing primary key
    CREATE TABLE IF NOT EXISTS my_table (
        id SERIAL PRIMARY KEY,
        name TEXT UNIQUE
    );

    -- Insert two unique names
    INSERT INTO my_table (name) VALUES ('Alice'), ('Bob');

    -- Acquire a write lock on the table
    LOCK TABLE my_table IN ACCESS EXCLUSIVE MODE;

    -- Insert a third row with a non-unique name
    BEGIN
        INSERT INTO my_table (name) VALUES ('Alice');
    EXCEPTION
        WHEN unique_violation THEN
            RAISE EXCEPTION 'Cannot insert non-unique name without lock';
    END;

    -- Release the lock (automatically released at the end of the transaction)

    -- Get the number of rows affected
    GET DIAGNOSTICS rows_affected = ROW_COUNT;

    RETURN rows_affected;
END;
$$ LANGUAGE plpgsql;
```

