```python
import sqlite3

def crud_operations(db_name, table_name, operation, data=None, condition=None):
    conn = sqlite3.connect(db_name)
    cursor = conn.cursor()

    if operation == "create":
        placeholders = ', '.join(['?'] * len(data))
        columns = ', '.join(data.keys())
        sql = f'INSERT INTO {table_name} ({columns}) VALUES ({placeholders})'
        cursor.execute(sql, tuple(data.values()))

    elif operation == "read":
        sql = f'SELECT * FROM {table_name}'
        if condition:
            sql += f' WHERE {condition}'
        cursor.execute(sql)
        return cursor.fetchall()

    elif operation == "update":
        if not condition:
            raise ValueError("Condition must be provided for update operation.")
        set_clause = ', '.join([f"{key} = ?" for key in data.keys()])
        sql = f'UPDATE {table_name} SET {set_clause} WHERE {condition}'
        cursor.execute(sql, tuple(data.values()))

    elif operation == "delete":
        if not condition:
            raise ValueError("Condition must be provided for delete operation.")
        sql = f'DELETE FROM {table_name} WHERE {condition}'
        cursor.execute(sql)

    conn.commit()
    conn.close()
