import re

def compile_template(template):
    tokens = re.findall(r'\{(.*?)\}', template)

    syntax_rules = {
        'add': '+',
        'sub': '-',
        'mul': '*',
        'div': '/',
    }

    def parse_tokens(tokens):
        parsed = []
        for token in tokens:
            if token in syntax_rules:
                parsed.append(syntax_rules[token])
            else:
                parsed.append(token)
        return ''.join(parsed)

    parsed_expression = parse_tokens(tokens)
    lambda_function = f"lambda _n: {parsed_expression}"
    return eval(lambda_function)

# Example usage:
# compiled_lambda = compile_template("{add} 1 {sub} 2")
# result = compiled_lambda(5)  # This would evaluate to 5 + 1 - 2
