class Controller
  attr_accessor :id, :sequencers

  def initialize(id)
    @id = id
    @sequencers = []
  end

  def add_sequencer(sequencer)
    @sequencers << sequencer
  end
end

class Sequencer
  attr_accessor :id

  def initialize(id)
    @id = id
  end
end

class SystemConfiguration
  attr_accessor :version, :cache, :io_bus, :controllers, :sequencers

  def initialize(version, cache, io_bus)
    @version = version
    @cache = cache
    @io_bus = io_bus
    @controllers = []
    @sequencers = []
  end

  def create_controllers_and_sequencers(num_controllers, num_sequencers_per_controller)
    num_controllers.times do |c|
      controller = Controller.new("Controller_#{c + 1}")
      @controllers << controller

      num_sequencers_per_controller.times do |s|
        sequencer = Sequencer.new("Sequencer_#{c + 1}_#{s + 1}")
        controller.add_sequencer(sequencer)
        @sequencers << sequencer
      end
    end
  end
end

# Example usage:
system_config = SystemConfiguration.new('1.0.0', 'default_cache', 'default_io_bus')
