import sys
import contextlib
import io

def execute_code_in_sandbox(code: str, local_vars: dict, global_vars: dict) -> any:
    # Capture the output
    output = io.StringIO()
    with contextlib.redirect_stdout(output):
        try:
            exec(code, global_vars, local_vars)
            result = local_vars.get('result', None)
            if result:
                return result
            else:
                return bool(eval(code, global_vars, local_vars))
        except Exception as e:
            return str(e)
        finally:
            output.close()
