import os
import hashlib
import base64
import secrets

class UserAccount:
    def __init__(self, username, phone_number, emergency_contact):
        self.username = username
        self.password_hash = None
        self.salt = None
        self.phone_number = phone_number
        self.emergency_contact = emergency_contact
        self.secret_key = self.generate_secret_key()

    def generate_secret_key(self):
        return base64.urlsafe_b64encode(secrets.token_bytes(32)).decode('utf-8')

    def set_password(self, password):
        self.salt = os.urandom(16)
        self.password_hash = self.hash_password(password)

    def hash_password(self, password):
        return hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), self.salt, 100000)

    def verify_password(self, password):
        hashed_input = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), self.salt, 100000)
        return hashed_input == self.password_hash
