import subprocess
import json
from collections import defaultdict

def get_commit_history():
    result = subprocess.run(['hg', 'log', '--template', '{node}\n'], capture_output=True, text=True)
    return result.stdout.strip().splitlines()

def get_parents(commit):
    result = subprocess.run(['hg', 'log', '--template', '{parents}\n', commit], capture_output=True, text=True)
    return result.stdout.strip().splitlines()

def analyze_branches(commit_history):
    commit_parents = defaultdict(list)
    for commit in commit_history:
        parents = get_parents(commit)
        commit_parents[commit] = parents

    branch_count_at_commit = {}
    for commit, parents in commit_parents.items():
        branch_count_at_commit[commit] = len(parents) + 1  # +1 for the commit itself

    return branch_count_at_commit

if __name__ == "__main__":
    commit_history = get_commit_history()
    branch_counts = analyze_branches(commit_history)
    print(json.dumps(branch_counts, indent=4))
