    minuit = Minuit()

    for key, value in params_dict.items():
        exec(f'minuit.{key} = value')

    minuit.values = {exclusion: centroid for exclusion, centroid in zip(exclusions, centroids)}

    return minuit
```

```python
def update_function(params_dict, func):
    def updated_function(*args, **kwargs):
        new_kwargs = {**kwargs, **params_dict}
        return func(*args, **new_kwargs)

    updated_function.__name__ = func.__name__
    updated_function.__signature__ = func.__signature__

    def __repr__():
        return f"<function {func.__name__} at {id(updated_function)}>"

    updated_function.__repr__ = __repr__

    return updated_function
```

