import hashlib

def calculate_sha1(file_path, max_bytes=None):
    sha1 = hashlib.sha1()
    with open(file_path, 'rb') as f:
        if max_bytes:
            data = f.read(max_bytes)
            sha1.update(data)
        else:
            while chunk := f.read(8192):
                sha1.update(chunk)
    return sha1.hexdigest()
