import json
import os

class FileBucketReader:
    def __init__(self, source, fail_on_missing=False):
        self.source = source
        self.fail_on_missing = fail_on_missing
        self._validate_source()

    def _validate_source(self):
        if self.fail_on_missing and not self._source_exists():
            raise FileNotFoundError(f"Source '{self.source}' does not exist.")

    def _source_exists(self):
        return os.path.isfile(self.source) or self._is_bucket_available()

    def _is_bucket_available(self):
        # Placeholder for actual bucket availability check
        return False

    def __iter__(self):
        if os.path.isfile(self.source):
            with open(self.source, 'r') as file:
                for line in file:
                    yield line.strip()
        else:
            raise ValueError("Source is not a valid file or bucket.")

    def load_from_json(self, json_str):
        data = json.loads(json_str)
        self.source = data.get('source', self.source)
        self.fail_on_missing = data.get('fail_on_missing', self.fail_on_missing)
        self._validate_source()

    def to_json(self):
        return json.dumps({
            'source': self.source,
            'fail_on_missing': self.fail_on_missing
        })
