import requests
import base64

def basic_authenticate(url, username, password):
    auth = f"{username}:{password}"
    b64_auth = base64.b64encode(auth.encode()).decode()
    headers = {'Authorization': f'Basic {b64_auth}'}

    response = requests.get(url, headers=headers)

