def execute_function(func_name, *args, **kwargs):
    local_vars = {}
    try:
        exec(f'result = {func_name}(*args, **kwargs)', {}, local_vars)
        return local_vars['result']
    except Exception as e:
        return f'Error: {str(e)}'
    finally:
        for var in local_vars:
            del local_vars[var]
