import hashlib
import sqlite3

class User:
    def __init__(self, username, password):
        self.username = username
        self.password = self.hash_password(password)

    def hash_password(self, password):
        return hashlib.sha256(password.encode()).hexdigest()

class Coach:
    def __init__(self, name):
        self.name = name

def save_to_database(coaches):
    conn = sqlite3.connect('coaches.db')
    cursor = conn.cursor()

    cursor.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY,
            username TEXT UNIQUE,
            password TEXT
        )
    ''')
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS coaches (
            id INTEGER PRIMARY KEY,
            name TEXT
        )
    ''')

    for coach in coaches:
        user = User(coach['username'], coach['password'])
        cursor.execute('INSERT INTO users (username, password) VALUES (?, ?)', (user.username, user.password))
        cursor.execute('INSERT INTO coaches (name) VALUES (?)', (coach['name'],))

    conn.commit()
    conn.close()

def create_and_save_coaches():
    coaches_data = [
        {'name': 'Coach A', 'username': 'coach_a', 'password': 'password123'},
        {'name': 'Coach B', 'username': 'coach_b', 'password': 'password456'}
    ]
    save_to_database(coaches_data)

create_and_save_coaches()
