from django.db import models, transaction

class CredentialType(models.Model):
    name = models.CharField(max_length=255)
    is_default = models.BooleanField(default=False)

def setup_default_credential_type(name):
    with transaction.atomic():
        # Create a default credential type if it doesn't exist
        default_credential, created = CredentialType.objects.get_or_create(
            name=name,
            defaults={'is_default': True}
        )

        # If a new default was created, ensure no other types are default
        if created:
            CredentialType.objects.filter(is_default=True).exclude(id=default_credential.id).update(is_default=False)

    return CredentialType.objects.count()
