CREATE OR REPLACE FUNCTION manage_triggers_and_language() RETURNS void AS $$
DECLARE
    r RECORD;
BEGIN
    -- Check and install the language if it does not exist
    IF NOT EXISTS (SELECT 1 FROM pg_language WHERE lanname = 'plpgsql') THEN
        EXECUTE 'CREATE LANGUAGE plpgsql';
    END IF;

    -- Drop existing triggers with a specific naming convention
    FOR r IN SELECT tgname FROM pg_trigger WHERE tgname LIKE 'my_trigger_%' LOOP
        EXECUTE format('DROP TRIGGER IF EXISTS %I ON my_table', r.tgname);
    END LOOP;

    -- Create triggers for each row in a SELECT statement
    FOR r IN SELECT * FROM my_table LOOP
        EXECUTE format('CREATE TRIGGER my_trigger_%s AFTER INSERT ON my_table FOR EACH ROW EXECUTE FUNCTION my_function()', r.id);
    END LOOP;
END;
$$ LANGUAGE plpgsql;
