import sys
import hashlib
from Crypto.Cipher import AES
from Crypto.Protocol.KDF import PBKDF2
import os

def hash_data(data, algorithm):
    if algorithm == 'sha256':
        return hashlib.sha256(data.encode()).hexdigest()
    elif algorithm == 'sha512':
        return hashlib.sha512(data.encode()).hexdigest()
    else:
        raise ValueError("Unsupported algorithm")

def derive_key(password, salt, iterations=100000):
    return PBKDF2(password, salt, dkLen=32, count=iterations)

def decrypt_data(encrypted_data, key):
    cipher = AES.new(key, AES.MODE_GCM)
    nonce = encrypted_data[:16]
    ciphertext = encrypted_data[16:]
    decrypted_data = cipher.decrypt_and_verify(ciphertext, nonce)
    return decrypted_data.decode()

def main():
    if len(sys.argv) != 5:
        print("Usage: python script.py <input_data> <algorithm> <password> <salt>")
        sys.exit(1)

    input_data = sys.argv[1]
    algorithm = sys.argv[2]
    password = sys.argv[3].encode()
    salt = bytes.fromhex(sys.argv[4])

    # Generate hash
    hash_value = hash_data(input_data, algorithm)
    print(f"Hash Value: {hash_value}")

    # Simulate encrypted data (for demonstration purposes only; use actual encrypted data in practice)
    encrypted_data = os.urandom(16) + os.urandom(16)  # Placeholder for actual encrypted content

    # Derive decryption key
    decryption_key = derive_key(password, salt)

    # Decrypt data
    try:
        decrypted_data = decrypt_data(encrypted_data, decryption_key)
        print(f"Decrypted Data: {decrypted_data}")
    except Exception as e:
        print(f"Decryption failed: {str(e)}")

if __name__ == "__main__":
    main()
```

