import subprocess

def get_changelog(packages):
    changelog_entries = []
    for package in packages:
        try:
            result = subprocess.run(['rpm', '-q', '--changelog', package], capture_output=True, text=True, check=True)
            changelog_entries.append(f"Changelog for {package}:\n{result.stdout}\n")
