class Controller:
    def __init__(self, controller_id, sequencer, system):
        self.controller_id = controller_id
        self.sequencer = sequencer
        self.system = system

    def start(self):
        print(f"Controller {self.controller_id} starting.")

    def stop(self):
        print(f"Controller {self.controller_id} stopping.")

def create_controllers(controller_types):
    controllers = []
    controller_id = 1

    for controller_type, count in controller_types.items():
        for _ in range(count):
            sequencer = f"Sequencer_{controller_id}"
            system = f"System_{controller_id}"
            controller = Controller(controller_id, sequencer, system)
            controllers.append(controller)
            controller_id += 1

    return controllers
