```python
import importlib.util
import os
import sys

class PythonPath:
    def __init__(self):
        self.extensions = []

    def add_extension(self, extension):
        self.extensions.append(extension)

def load_and_execute_extension(file_path, base_python_path, root_directory):
    try:
        if not os.path.exists(file_path):
            raise FileNotFoundError(f"Extension file not found: {file_path}")

        spec = importlib.util.spec_from_file_location("extension_module", file_path)
        extension_module = importlib.util.module_from_spec(spec)
        sys.modules["extension_module"] = extension_module
        spec.loader.exec_module(extension_module)

        if not hasattr(extension_module, 'Extend'):
            raise AttributeError("The module does not define an 'Extend' function.")

        extended_python_path = extension_module.Extend(base_python_path, root_directory)
        return extended_python_path

    except Exception as e:
        print(f"An error occurred while loading the extension: {e}")
        return None
