```python
import hashlib

def hash_strings(strings, hash_function='sha256', unit='bytes'):
    hash_func_map = {
        'sha256': hashlib.sha256,
        'sha512': hashlib.sha512,
        'md5': hashlib.md5
    }

    if hash_function not in hash_func_map:
        raise ValueError("Unrecognized hash function")

    hasher = hash_func_map[hash_function]()
    for string in strings:
        hasher.update(string.encode('utf-8'))

    hash_value = hasher.digest()

    if unit == 'bytes':
        return hash_value
    elif unit == 'hex':
        return hasher.hexdigest()
    else:
        raise ValueError("Unrecognized unit")
```

