import os
import shutil
import requests
import zipfile

def download_and_extract(url, dest_folder):
    response = requests.get(url)
    if response.status_code == 200:
        package_path = os.path.join(dest_folder, url.split('/')[-1])
        with open(package_path, 'wb') as f:
            f.write(response.content)
        if package_path.endswith('.zip'):
            with zipfile.ZipFile(package_path, 'r') as zip_ref:
                zip_ref.extractall(dest_folder)
        os.remove(package_path)

def create_staging_and_final_folders(products, build_folder, final_folder):
    os.makedirs(final_folder, exist_ok=True)

    for product, packages in products.items():
        staging_folder = os.path.join(build_folder, product)
        os.makedirs(staging_folder, exist_ok=True)

        for package in packages:
            download_and_extract(package, staging_folder)

        for item in os.listdir(staging_folder):
            item_path = os.path.join(staging_folder, item)
            if os.path.isdir(item_path):
                shutil.move(item_path, final_folder)
            else:
                shutil.move(item_path, final_folder)

        shutil.rmtree(staging_folder)

def zip_final_folder(final_folder):
    zip_file_path = final_folder + '.zip'
    with zipfile.ZipFile(zip_file_path, 'w') as zipf:
        for root, _, files in os.walk(final_folder):
            for file in files:
                zipf.write(os.path.join(root, file), os.path.relpath(os.path.join(root, file), final_folder))

products = {
    'product1': ['http://example.com/package1.zip', 'http://example.com/package2.zip'],
    'product2': ['http://example.com/package3.zip']
}

build_folder = '/path/to/build_folder'
final_folder = '/path/to/final_folder'

create_staging_and_final_folders(products, build_folder, final_folder)
zip_final_folder(final_folder)
