import hashlib
import urllib.parse

def generate_gravatar_url(email, params=None):
    # Normalize and hash the email address
    email_hash = hashlib.md5(email.strip().lower().encode('utf-8')).hexdigest()

    # Canonicalize parameters
    if params:
        canonical_params = {k: v for k, v in sorted(params.items())}
    else:
        canonical_params = {}

    # Build the query string from parameters
    query_string = urllib.parse.urlencode(canonical_params)

    # Construct the Gravatar URL
    gravatar_url = f"https://www.gravatar.com/avatar/{email_hash}"
    if query_string:
        gravatar_url += f"?{query_string}"

    return gravatar_url
