```java
import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class AntlrRunner {
    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: java AntlrRunner <directory> <file> [options]");
            System.exit(1);
        }

        String directory = args[0];
        String file = args[1];
        String[] options = new String[args.length - 2];
        System.arraycopy(args, 2, options, 0, options.length);

        ProcessBuilder processBuilder = new ProcessBuilder();
        processBuilder.command(buildCommand(directory, file, options));
        processBuilder.redirectErrorStream(true);

        try {
            Process process = processBuilder.start();
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

            int exitCode = process.waitFor();
            if (exitCode != 0) {
                System.err.println("ANTLR tool encountered an error. Exit code: " + exitCode);
            }
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }

    private static String[] buildCommand(String directory, String file, String[] options) {
        String[] command = new String[options.length + 2];
        command[0] = "antlr4"; // Replace with the actual ANTLR command if different
        command[1] = file;
        System.arraycopy(options, 0, command, 2, options.length);
        return command;
    }
}
