import hashlib

class RFPDupeFilter:
    def __init__(self):
        self.seen_requests = set()

class CaseInsensitiveDupeFilter(RFPDupeFilter):
    def request_fingerprint(self, request):
        url = request.url.lower()
        fingerprint = hashlib.sha1(url.encode('utf-8')).hexdigest()
        return fingerprint

    def is_duplicate(self, request):
        fingerprint = self.request_fingerprint(request)
        if fingerprint in self.seen_requests:
            return True
        self.seen_requests.add(fingerprint)
        return False
