import hashlib
import os

def hash_message(message, hash_function='sha256', salt=None):
    if salt is None:
        salt = os.urandom(16)
    else:
        salt = salt.encode()

    if hash_function == 'md5':
        hasher = hashlib.md5()
    elif hash_function == 'sha1':
        hasher = hashlib.sha1()
    elif hash_function == 'sha256':
        hasher = hashlib.sha256()
    else:
        raise ValueError("Unsupported hash function. Use 'md5', 'sha1', or 'sha256'.")

    hasher.update(salt + message.encode())
    return hasher.hexdigest()
