const fs = require('fs');
const path = require('path');

const moduleCache = {};

function loadModule(filename, options) {
    const resolvedPath = path.resolve(filename);

    if (moduleCache[resolvedPath]) {
        return moduleCache[resolvedPath];
    }

    try {
        const fileContent = fs.readFileSync(resolvedPath, 'utf8');
        const moduleFunction = new Function('exports', 'require', 'module', '__filename', '__dirname', fileContent);
        const module = { exports: {} };

        moduleFunction(module.exports, require, module, resolvedPath, path.dirname(resolvedPath));
        moduleCache[resolvedPath] = module.exports;

        return module.exports;
    } catch (error) {
        throw new Error(`Cannot load module: ${error.message}`);
    }
}
