```javascript
function asyncReduce(array, initialValue, callback) {
    return new Promise((resolve, reject) => {
        let accumulator = initialValue;

        const reduceStep = (index) => {
            if (index >= array.length) {
                return resolve(accumulator);
            }

            const currentValue = array[index];

            Promise.resolve(callback(accumulator, currentValue))
                .then(result => {
                    accumulator = result;
                    reduceStep(index + 1);
                })
                .catch(error => reject(error));
        };

        reduceStep(0);
    });
}

