```javascript
function generateUniqueId(input = '', length = 8, base = 16) {
    const seed = input ? Array.from(input).reduce((acc, char) => acc + char.charCodeAt(0), 0) : Math.random();
    const random = (seed * 9301 + 49297) % 233280;
    const uniqueId = [];

    for (let i = 0; i < length; i++) {
        uniqueId.push((random + i) % Math.pow(base, 1).toString(base).padStart(1, '0'));
    }

    return uniqueId.join('');
}
