function modifyHosts(hosts, useHttps) {
    const distributedSearchNetworkHost = "dsn.example.com"; // Example DSN host
    const protocol = useHttps ? "https://" : "http://";

    // Shuffle the hosts array
    for (let i = hosts.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [hosts[i], hosts[j]] = [hosts[j], hosts[i]];
    }

    // Add DSN host if it exists
