```javascript
function matchUserAgent(patterns) {
    const userAgent = navigator.userAgent;

    return patterns.reduce((acc, { pattern, qualifier }) => {
        if (acc) return acc;

        const regex = new RegExp(pattern);
        const matches = regex.test(userAgent);
        const startsWithQualifier = qualifier ? userAgent.startsWith(qualifier) : true;

        return matches && startsWithQualifier ? { pattern, qualifier } : null;
    }, null);
}
