function createComparisonAndFormattingFunctions(formatString) {
    const comparisonFunction = new Function('a', 'b', `
        const format = ${JSON.stringify(formatString)};
        return a[format] < b[format] ? -1 : (a[format] > b[format] ? 1 : 0);
    `);

    const formattingFunction = new Function('data', `
        const compare = ${comparisonFunction.toString()};
        const minX = Math.min(...data.map(d => d[formatString]));
        const maxX = Math.max(...data.map(d => d[formatString]));
        const minY = Math.min(...data.map(d => d[formatString]);
        const maxY = Math.max(...data.map(d => d[formatString]));
        return { minX, minY, maxX, maxY };
    `);

    return { comparisonFunction, formattingFunction };
}
