```javascript
const fs = require('fs');
const path = require('path');

function validateAndCreateDirTree(fsObject, dirPath, options) {
    let isValid = true;

    if (!fsObject.existsSync(dirPath)) {
        if (options.createDirs) {
            fsObject.mkdirSync(dirPath, { recursive: true });
        } else {
            return false;
        }
    }

    const entries = fsObject.readdirSync(dirPath);
    for (const entry of entries) {
        const fullPath = path.join(dirPath, entry);
        if (fsObject.statSync(fullPath).isDirectory()) {
            isValid = validateAndCreateDirTree(fsObject, fullPath, options) && isValid;
        } else if (!options.validateFiles || !fsObject.existsSync(fullPath)) {
            isValid = false;
        }
    }

    return isValid;
}
