```c
#include <stdint.h>
#include <string.h>
#include <stdio.h>
#include <stdlib.h>

#define OFP_ACTION_MAX_LENGTH 16

typedef struct {
    char *error;
    int code;
    void *data;
} Result;

Result parse_openflow_action(const uint8_t *buffer, size_t offset) {
    Result result;
    if (offset + 4 > sizeof(buffer)) {
        result.error = "Buffer overflow";
        result.code = -1;
        result.data = NULL;
        return result;
    }

    uint16_t type = (buffer[offset] << 8) | buffer[offset + 1];
    uint16_t length = (buffer[offset + 2] << 8) | buffer[offset + 3];

    if (length < 4 || length > OFP_ACTION_MAX_LENGTH) {
        result.error = "Invalid action length";
        result.code = -2;
        result.data = NULL;
        return result;
    }

    // Allocate memory for action data
    void *action_data = malloc(length);
    if (action_data == NULL) {
        result.error = "Memory allocation failed";
        result.code = -3;
        result.data = NULL;
        return result;
    }

    memcpy(action_data, buffer + offset, length);

    result.error = NULL;
    result.code = 0;
    result.data = action_data;

    // Return updated offset
    result.data = (void *)((uintptr_t)action_data + length);

    return result;
}
