```javascript
const fs = require('fs');
const path = require('path');

const config = {};

function getConfigValue(key) {
    if (key in config) {
        return config[key];
    }

    let value = config[key];

    // Check if the value is not found in the config object
    if (value === undefined) {
        const currentDir = process.cwd();
        const parentDir = path.resolve(currentDir, '..');
        const filesToCheck = [
            path.join(currentDir, 'config.js'),
            path.join(parentDir, 'config.js')
        ];

        for (const file of filesToCheck) {
            if (fs.existsSync(file)) {
                const requiredConfig = require(file);
                if (key in requiredConfig) {
                    value = requiredConfig[key];
                    break;
                }
            }
        }
    }

    // Check if the value is still not found and if the key might be a package name
    if (value === undefined) {
        try {
            const packageJsonPath = path.join(currentDir, 'package.json');
            const packageJson = require(packageJsonPath);
            if (packageJson[key]) {
                value = packageJson[key];
            }
        } catch (error) {
            // Ignore errors if package.json doesn't exist
        }
    }

    // Set the value in the config object for future reference
    if (value !== undefined) {
        config[key] = value;
    }

    return value;
}
