const fs = require('fs');
const path = require('path');
const less = require('less');

async function compileLessFiles(dir) {
    const result = {};

    async function searchDirectory(directory) {
        const files = fs.readdirSync(directory);

        for (const file of files) {
            const filePath = path.join(directory, file);
            const stat = fs.statSync(filePath);

            if (stat.isDirectory()) {
                await searchDirectory(filePath);
            } else if (filePath.endsWith('.less')) {
                const cssFilePath = filePath.replace(/\.less$/, '.css');
                const lessContent = fs.readFileSync(filePath, 'utf-8');

                const output = await less.render(lessContent);
                fs.writeFileSync(cssFilePath, output.css);
                result[cssFilePath] = filePath;
            }
        }
    }

    await searchDirectory(dir);
    return result;
}
