```javascript
const fs = require('fs');
const path = require('path');
const sass = require('node-sass');
const ts = require('typescript');
const _ = require('lodash');
const concat = require('concat');

const deleteFile = (filePath) => {
    fs.unlink(filePath, (err) => {
        if (err) throw err;
        console.log(`${filePath} was deleted`);
    });
};

const insertTextIntoFile = (filePath, text) => {
    fs.appendFile(filePath, text, (err) => {
        if (err) throw err;
        console.log(`Text inserted into ${filePath}`);
    });
};

const compileSass = (inputFile, outputFile) => {
    sass.render({ file: inputFile }, (err, result) => {
        if (err) throw err;
        fs.writeFileSync(outputFile, result.css);
        console.log(`${outputFile} has been compiled from ${inputFile}`);
    });
};

const compileTypeScript = (inputFile, outputFile) => {
    const tsConfig = {
        compilerOptions: {
            module: 'commonjs',
            target: 'es5',
        },
    };
    const source = fs.readFileSync(inputFile, 'utf8');
    const result = ts.transpileModule(source, tsConfig);
    fs.writeFileSync(outputFile, result.outputText);
    console.log(`${outputFile} has been compiled from ${inputFile}`);
};

const concatenateFiles = (inputFiles, outputFile) => {
    concat(inputFiles, outputFile).then(() => {
        console.log(`${outputFile} has been created by concatenating files`);
    });
};

// Example usage
deleteFile('path/to/file.txt');
insertTextIntoFile('path/to/file.txt', 'New text\n');
compileSass('path/to/style.scss', 'path/to/style.css');
compileTypeScript('path/to/script.ts', 'path/to/script.js');
concatenateFiles(['file1.txt', 'file2.txt'], 'output.txt');
