```javascript
function doesElementMatchSelector(element, selector, operator = '=', value = null) {
    const attrValue = Sizzle.attr(element, selector);

    if (value === null) {
        return !!attrValue;
    }

    switch (operator) {
        case '=':
            return attrValue === value;
        case '!=':
            return attrValue !== value;
        case '<':
            return attrValue < value;
        case '>':
            return attrValue > value;
        case '<=':
            return attrValue <= value;
        case '>=':
            return attrValue >= value;
        default:
            return false;
    }
}
