const fs = require('fs');
const path = require('path');

function checkFilesInDirectory(dirPath, filesToCheck) {
    if (!fs.existsSync(dirPath)) {
        return;
    }

    const items = fs.readdirSync(dirPath);
    const foundFiles = [];

    items.forEach(item => {
        const itemPath = path.join(dirPath, item);
        if (fs.statSync(itemPath).isDirectory()) {
            checkFilesInDirectory(itemPath, filesToCheck);
        } else if (filesToCheck.includes(item)) {
            foundFiles.push(itemPath);
        }
    });

    if (foundFiles.length > 0) {
        console.log(`Found files in ${dirPath}:`, foundFiles);
    }
}

// Example usage:
// checkFilesInDirectory('/path/to/start', ['file1.txt', 'file2.txt']);
