function generateRandomStar(ctx, canvasWidth, canvasHeight) {
    const radius = Math.random() * 5 + 2; // Random radius between 2 and 7
    const x = Math.random() * canvasWidth; // Random x position
    const y = Math.random() * canvasHeight; // Random y position
    const velocityX = (Math.random() - 0.5) * 2; // Random x velocity
    const velocityY = (Math.random() - 0.5) * 2; // Random y velocity

    ctx.beginPath();
    ctx.arc(x, y, radius, 0, Math.PI * 2, false);
    ctx.fillStyle = "white"; // Star color
    ctx.fill();
    ctx.closePath();

    return { x, y, velocityX, velocityY, radius };
}
