```javascript
function plantNodes(grid, startX, startY, maxNodes) {
    const rows = grid.length;
    const cols = grid[0].length;
    let nodesPlanted = 0;

    function dfs(x, y) {
        if (x < 0 || x >= rows || y < 0 || y >= cols || grid[x][y].state === 'visited') {
            return;
        }

        grid[x][y].state = 'visited';

        // Plant a new node if we haven't reached the max limit
        if (nodesPlanted < maxNodes) {
            let newX, newY;
            do {
                newX = Math.floor(Math.random() * rows);
                newY = Math.floor(Math.random() * cols);
            } while (grid[newX][newY].state === 'visited');
            grid[newX][newY] = { x: newX, y: newY, value: Math.random(), state: 'planted' };
            nodesPlanted++;
        }

        // Explore neighbors
        dfs(x + 1, y); // down
        dfs(x - 1, y); // up
        dfs(x, y + 1); // right
        dfs(x, y - 1); // left
    }

    dfs(startX, startY);
}
