const fs = require('fs');

function loadFiles(filePaths, callback) {
    let results = {};
    let filesToLoad = filePaths.length;

    filePaths.forEach((filePath) => {
        fs.readFile(filePath, 'utf8', (err, data) => {
            if (err) {
                return callback(err);
            }
            results[filePath] = data;
            filesToLoad--;
            if (filesToLoad === 0) {
                callback(null, results);
            }
        });
    });
}
