function validateField(field, regexString) {
    const regex = new RegExp(regexString);
    const value = field.value;
    let isValid = true;
    let errorMessage = '';

    if (!regex.test(value)) {
        isValid = false;
        errorMessage = 'Invalid input. Please match the required format.';
        field.classList.add('error');
    } else {
        field.classList.remove('error');
    }

    if (errorMessage) {
        field.setCustomValidity(errorMessage);
    } else {
        field.setCustomValidity('');
    }

    return isValid;
}
