    fs.symlink(binExecutable, symlinkPath, 'file', (err) => {
        if (err) {
            console.error(`Error creating symlink: ${err.message}`);
        } else {
            console.log(`Symlink created: ${symlinkPath} -> ${binExecutable}`);
        }
    });
});
