```javascript
function generateUniqueId() {
    return 'id-' + Math.random().toString(36).substr(2, 9);
}

function encryptMessage(message, key) {
    let encrypted = '';
    for (let i = 0; i < message.length; i++) {
        encrypted += String.fromCharCode(message.charCodeAt(i) ^ key.charCodeAt(i % key.length));
    }
    return encrypted;
}

function sendMessage(message, connection) {
    const uniqueId = generateUniqueId();
    const key = uniqueId; // Using uniqueId as the encryption key
    const encryptedMessage = encryptMessage(message, key);

    connection.send(JSON.stringify({ id: uniqueId, message: encryptedMessage }));
}
```

