```javascript
const fs = require('fs');
const path = require('path');

function validateAndCreate(dirPath, options) {
    if (!fs.existsSync(dirPath)) {
        throw new Error(`Directory does not exist: ${dirPath}`);
    }

    for (const [key, value] of Object.entries(options)) {
        const fullPath = path.join(dirPath, key);

        if (value === true) {
            // Check if it's a directory
            if (!fs.existsSync(fullPath)) {
                fs.mkdirSync(fullPath);
            } else if (!fs.statSync(fullPath).isDirectory()) {
                throw new Error(`Expected a directory but found a file: ${fullPath}`);
            }
        } else if (value === 'file') {
            // Check if it's a file
            if (!fs.existsSync(fullPath)) {
                fs.writeFileSync(fullPath, '', 'utf8');
            } else if (!fs.statSync(fullPath).isFile()) {
                throw new Error(`Expected a file but found a directory: ${fullPath}`);
            }
        }
    }
}
