const canvas = document.getElementById('canvas');
const ctx = canvas.getContext('2d');

let particle = {
    x: canvas.width / 2,
    y: canvas.height / 2,
    size: 5
};

function updateParticle() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.beginPath();
    ctx.arc(particle.x, particle.y, particle.size, 0, Math.PI * 2);
    ctx.fillStyle = 'blue';
    ctx.fill();
}

function moveParticle(event) {
    const { key } = event;
    const randomOffset = Math.random() * 5;

    switch (key) {
        case 'ArrowUp':
            particle.y -= 5 + randomOffset;
            break;
        case 'ArrowDown':
            particle.y += 5 + randomOffset;
            break;
        case 'ArrowLeft':
            particle.x -= 5 + randomOffset;
            break;
        case 'ArrowRight':
            particle.x += 5 + randomOffset;
            break;
    }
    updateParticle();
}

document.addEventListener('keydown', moveParticle);
updateParticle();
