function sendMessageToIframe(iframe, eventName, data, callback) {
    const message = JSON.stringify({ event: eventName, data: data });
    const uniqueCallbackName = `callback_${Date.now()}`;

    if (callback) {
        window[uniqueCallbackName] = function(event) {
            if (event.data && event.data.event === eventName) {
                callback(event.data.data);
                delete window[uniqueCallbackName];
            }
        };
        window.addEventListener('message', window[uniqueCallbackName]);
    }

    iframe.contentWindow.postMessage(message, '*');
}
