```javascript
function generateUUID() {
    let randomBytes = new Uint8Array(16);
    window.crypto.getRandomValues(randomBytes);
    randomBytes[6] = (randomBytes[6] & 0x0f) | 0x40; // Set the version to 0100
    randomBytes[8] = (randomBytes[8] & 0x3f) | 0x80; // Set the variant to 10

    const hexArray = Array.from(randomBytes, byte => ('00' + byte.toString(16)).slice(-2));
    return `${hexArray.slice(0, 4).join('')}-${hexArray.slice(4, 6).join('')}-${hexArray.slice(6, 8).join('')}-${hexArray.slice(8, 10).join('')}-${hexArray.slice(10).join('')}`;
}
