// HTML structure for suggestions
const suggestionTemplate = Handlebars.compile(`
  <ul class="suggestions">
    {{#each products}}
      <li data-id="{{id}}" data-upc="{{upc}}" class="suggestion-item">
        <span class="product-name">{{name}}</span> - 
        <span class="product-price">${{price}}</span> - 
        <span class="product-stock">{{stock}} in stock</span>
      </li>
    {{/each}}
  </ul>
`);

function autocompleteSearch(inputElement) {
  inputElement.addEventListener('input', function() {
    const query = this.value;

    if (query.length < 2) {
      clearSuggestions();
      return;
    }

    fetch(`search.php?query=${encodeURIComponent(query)}`)
      .then(response => response.json())
      .then(data => {
        const html = suggestionTemplate({ products: data });
        displaySuggestions(html);
      })
      .catch(error => console.error('Error fetching data:', error));
  });

  function displaySuggestions(html) {
    clearSuggestions();
    const suggestionsContainer = document.createElement('div');
    suggestionsContainer.classList.add('suggestions-container');
    suggestionsContainer.innerHTML = html;
    document.body.appendChild(suggestionsContainer);

    suggestionsContainer.addEventListener('click', function(e) {
      if (e.target.classList.contains('suggestion-item')) {
        const selectedItem = e.target;
        inputElement.value = `${selectedItem.dataset.id} - ${selectedItem.dataset.upc}`;
        clearSuggestions();
      }
    });
  }

  function clearSuggestions() {
    const existingSuggestions = document.querySelector('.suggestions-container');
    if (existingSuggestions) {
      existingSuggestions.remove();
    }
  }
}
