const tls = require('tls');
const fs = require('fs');

const options = {
  key: fs.readFileSync('server-key.pem'),
  cert: fs.readFileSync('server-cert.pem'),
  ca: fs.readFileSync('client-cert.pem'), // Self-signed client cert for verification
  requestCert: true,
  rejectUnauthorized: true
};

const server = tls.createServer(options, (socket) => {
  console.log('Client connected:', socket.remoteAddress);
  socket.write('Welcome to the TLS server!\n');
  socket.setEncoding('utf8');

  socket.on('data', (data) => {
    console.log('Received data:', data);
  });

  socket.on('end', () => {
    console.log('Client disconnected');
  });
});

server.on('error', (err) => {
  console.error('Server error:', err);
});

server.on('secureConnection', (tlsSocket) => {
  console.log('Secure connection established with:', tlsSocket.remoteAddress);
});

server.on('clientError', (err, socket) => {
  console.error('Client error:', err);
  socket.destroy();
});

server.listen(8000, () => {
  console.log('TLS server listening on port 8000');
});
