function escapeUnescapeString(input, map, unescape = false) {
    const regex = new RegExp(unescape ? Object.keys(map).map(key => escapeRegExp(key)).join('|') : Object.values(map).map(value => escapeRegExp(value)).join('|'), 'g');

    return input.replace(regex, (match) => {
        return unescape ? Object.keys(map).find(key => map[key] === match) : map[match];
    });
}

