```javascript
function decodeWBXML(wbxml) {
    const codepageMap = {
        // Add codepage mapping here
        // Example: 0x01: 'SomeValue',
    };

    let pos = 0;
    const length = wbxml.length;
    const result = {};

    function readByte() {
        return wbxml.charCodeAt(pos++);
    }

    function readString() {
        let str = '';
        let byte;
        while ((byte = readByte()) !== 0) {
            str += String.fromCharCode(byte);
        }
        return str;
    }

    function readElement() {
        const tag = readByte();
        const name = codepageMap[tag] || `UnknownTag_${tag}`;
        const value = readString();
        result[name] = value;
    }

    while (pos < length) {
        readElement();
    }

    return result;
}
