const fs = require('fs');
const path = require('path');

function sendResponse(directory, fileName, callback) {
    const filePath = path.join(directory, fileName);

    fs.access(filePath, fs.constants.F_OK, (err) => {
        if (err) {
            return callback(`File not found: ${fileName}`);
        }

        fs.readFile(filePath, 'utf8', (err, data) => {
            if (err) {
                return callback(`Error reading file: ${err.message}`);
            }

            // Assuming a simple template engine that replaces {{data}} with the content
            const responseTemplate = `<html><body><h1>Response</h1><div>{{data}}</div></body></html>`;
            const responseContent = responseTemplate.replace('{{data}}', data);
            callback(null, responseContent);
        });
    });
}
