function loadWaveformData(url, callback) {
    const xhr = new XMLHttpRequest();
    xhr.open("GET", url, true);
    xhr.responseType = "json";

    xhr.onload = function() {
        if (xhr.status === 200) {
            const data = xhr.response;
            const realParts = new Float32Array(data.length);
            const imaginaryParts = new Float32Array(data.length);

            for (let i = 0; i < data.length; i++) {
                realParts[i] = data[i].real;
                imaginaryParts[i] = data[i].imaginary;
            }

            callback({ real: realParts, imaginary: imaginaryParts });
        } else {
            console.error('Failed to load data:', xhr.statusText);
        }
    };

    xhr.onerror = function() {
        console.error('Request error');
    };

    xhr.send();
}
