```javascript
async function makeRequest(url, data, callback) {
    const method = data.secretPhrase ? 'POST' : 'GET';
    let queryString = '';

    if (method === 'GET') {
        const randomParam = `random=${Math.random()}`;
        queryString = url.includes('?') ? `&${randomParam}` : `?${randomParam}`;
        url += queryString;
    }

    const options = {
        method: method,
        headers: {
            'Content-Type': 'application/json',
        },
        body: method === 'POST' ? JSON.stringify(data) : undefined,
    };

    try {
        const response = await fetch(url, options);
        const responseData = await response.json();

        if (method === 'POST' && responseData.errorCode === 5) {
            callback(new Error('Error code 5 received'));
            return;
        }

        return responseData;
    } catch (error) {
        console.error('Request failed:', error);
    }
}
