function createTimeZoneRegex(pattern, timeZone) {
    const validTimeZoneFormats = [
        /^(Pacific Time|Eastern Time|Central Time|Mountain Time|[A-Za-z]+\/[A-Za-z_]+)$/,
        /^(America\/[A-Za-z_]+)$/,
        /^(GMT[+-]\d{1,2}:?\d{0,2})$/
    ];

    const isValid = validTimeZoneFormats.some(regex => regex.test(pattern));

    if (!isValid) {
        return { error: 'Invalid time zone format' };
    }

    return new RegExp(pattern);
}
