function extractUniqueNames(text) {
    const namePattern = /\b([A-Z][a-z]+(?:\s[A-Z][a-z]+)?(?:\s[A-Z]\.)?)\b/g;
    const matches = text.match(namePattern);
    const uniqueNames = [...new Set(matches)];
    const nameReferences = uniqueNames.map(name => ({
        name: name,
        occurrences: text.match(new RegExp(name, 'g')).length
    }));
    return nameReferences;
}

