```javascript
function packOctetArray(format, values) {
    const formatSpecifiers = {
        'i': 4, // Integer - 4 bytes
        'f': 4, // Float - 4 bytes
        'd': 8, // Double - 8 bytes
        'c': 1  // Char - 1 byte
    };

    const formatRegex = /([ifdc])/g;
    let byteLength = 0;

    // Calculate total byte length based on format string
    let match;
    while ((match = formatRegex.exec(format)) !== null) {
        byteLength += formatSpecifiers[match[1]];
    }

    const octetArray = new Uint8Array(byteLength);
    let offset = 0;

    // Pack values into the octet array
    values.forEach((value, index) => {
        const specifier = format[index];
        if (specifier === 'i') {
            const view = new DataView(octetArray.buffer, offset);
            view.setInt32(0, value);
            offset += 4;
        } else if (specifier === 'f') {
            const view = new DataView(octetArray.buffer, offset);
            view.setFloat32(0, value);
            offset += 4;
        } else if (specifier === 'd') {
            const view = new DataView(octetArray.buffer, offset);
            view.setFloat64(0, value);
            offset += 8;
        } else if (specifier === 'c') {
            octetArray[offset] = value.charCodeAt(0);
            offset += 1;
        }
    });

    return octetArray;
}
