function modifyEvent(event, element) {
    event.namespace = 'customNamespace';
    event.regexNamespace = new RegExp(`^${event.namespace}\\..*`);

    // Clean up the event object
    const cleanedEvent = {
        type: event.type,
        target: event.target,
        currentTarget: event.currentTarget,
        preventDefault: event.preventDefault.bind(event),
        stopPropagation: event.stopPropagation.bind(event),
        namespace: event.namespace,
        regexNamespace: event.regexNamespace
    };

    // Set up the handler argument list
    const handlerArgs = [cleanedEvent, element];

