```javascript
function parseCSSSelector(selector) {
    const result = {
        combinators: [],
        simpleSelectors: [],
        attributeTests: []
    };

    // Remove leading and trailing whitespace
    selector = selector.trim();

    // Regex patterns
    const combinatorPattern = /[>\s+~]/g;
    const simpleSelectorPattern = /([.#]?[a-zA-Z_][\w-]*)|(\*|:not\((?:[^()]+|\([^()]*\))*\))/g;
    const attributePattern = /\[([^\]]+)\]/g;

    // Split selector by combinators
    const components = selector.split(combinatorPattern);

    components.forEach((component, index) => {
        component = component.trim();
        if (component) {
            // Check for attribute tests
            const attributes = [...component.matchAll(attributePattern)];
            attributes.forEach(attr => {
                result.attributeTests.push(attr[0]);
                component = component.replace(attr[0], '').trim();
            });
            // Add remaining simple selector
            if (component) {
                result.simpleSelectors.push(component);
            }
            // Add combinator if not the last component
            if (index < components.length - 1) {
                const combinatorMatch = selector.match(combinatorPattern);
                if (combinatorMatch) {
                    result.combinators.push(combinatorMatch[index]);
                }
            }
        }
    });

    return result;
}
