```javascript
import React, { useEffect, useState } from 'react';

const ProjectInfo = () => {
    const [latestVersion, setLatestVersion] = useState(null);
    const [allVersions, setAllVersions] = useState([]);
    const [selectedVersion, setSelectedVersion] = useState(null);
    const [versionDetails, setVersionDetails] = useState(null);

    useEffect(() => {
        const fetchData = async () => {
            try {
                const response = await fetch('/path/to/versions.json');
                const data = await response.json();
                setLatestVersion(data.latest);
                setAllVersions(data.versions);
            } catch (error) {
                console.error('Error fetching version data:', error);
            }
        };
        fetchData();
    }, []);

    const handleVersionSelect = async (version) => {
        setSelectedVersion(version);
        try {
            const response = await fetch(`/path/to/version/details/${version}.json`);
            const details = await response.json();
            setVersionDetails(details);
        } catch (error) {
            console.error('Error fetching version details:', error);
        }
    };

    return (
        <div>
            <h1>Project Name</h1>
            {latestVersion && (
                <div>
                    <h2>Latest Stable Version: {latestVersion}</h2>
                    <a href="https://github.com/username/repo" target="_blank" rel="noopener noreferrer">GitHub Repository</a>
                </div>
            )}
            <h2>All Versions:</h2>
            <ul>
                {allVersions.map((version) => (
                    <li key={version} onClick={() => handleVersionSelect(version)}>
                        {version}
                    </li>
                ))}
            </ul>
            {selectedVersion && versionDetails && (
                <div>
                    <h3>Details for Version: {selectedVersion}</h3>
                    <pre>{JSON.stringify(versionDetails, null, 2)}</pre>
                </div>
            )}
        </div>
    );
};

export default ProjectInfo;
