function modifyModuleExport(module, func, errorLibrary) {
    const originalExport = module.exports;

    module.exports = function(...args) {
        const randomArg = Math.random(); // or any other logic for random argument
        try {
            return func(randomArg, ...args);
        } catch (error) {
            errorLibrary.displayError(error);
        }
    };

    if (module.hot) {
        module.hot.accept(() => {
            module.exports = originalExport; // Restore original behavior on hot reload
            modifyModuleExport(module, func, errorLibrary); // Reapply the modified behavior
        });
    }
}
