class SimpleWeakMap {
    constructor() {
        this.map = new WeakMap();
    }

    set(key, value) {
        if (typeof key !== 'object' || key === null) {
            throw new TypeError('Key must be an object.');
        }
        this.map.set(key, value);
    }

    get(key) {
        if (typeof key !== 'object' || key === null) {
            throw new TypeError('Key must be an object.');
        }
        return this.map.get(key);
    }

    delete(key) {
        if (typeof key !== 'object' || key === null) {
            throw new TypeError('Key must be an object.');
        }
        return this.map.delete(key);
    }

    has(key) {
        if (typeof key !== 'object' || key === null) {
            throw new TypeError('Key must be an object.');
        }
        return this.map.has(key);
    }
}
