function traverseTree(nodes, currentNodeId, relativePath = '') {
    const currentNode = nodes.find(node => node.id === currentNodeId);

    if (!currentNode) {
        console.error('Node not found:', currentNodeId);
        return;
    }

    console.log('Current Node:', currentNodeId, 'Relative Path:', relativePath);

    if (currentNode.subIndices && currentNode.subIndices.length > 0) {
        currentNode.subIndices.forEach(subIndex => {
            traverseTree(nodes, subIndex, `${relativePath}/${currentNodeId}`);
        });
    } else {
        loadSubIndices(currentNodeId).then(subIndices => {
            currentNode.subIndices = subIndices;
            subIndices.forEach(subIndex => {
                traverseTree(nodes, subIndex, `${relativePath}/${currentNodeId}`);
            });
        }).catch(error => {
            console.error('Error loading sub-indices for:', currentNodeId, error);
        });
    }
}

