```javascript
const fs = require('fs');
const path = require('path');

function loadHandlersAndHelpers(config) {
    const { apiKey, failCount } = config;
    const handlers = {};
    const helpers = {};

    const loadFiles = (dir, target) => {
        const files = fs.readdirSync(dir);

        files.forEach(file => {
            const filePath = path.join(dir, file);
            const stat = fs.statSync(filePath);

            if (stat.isDirectory()) {
                loadFiles(filePath, target);
            } else if (file.endsWith('.js') && file !== 'index.js') {
                const module = require(filePath);
                const fileName = path.basename(file, '.js');
                target[fileName] = module;
            }
        });
    };

    loadFiles('./handlers', handlers);
    loadFiles('./helpers', helpers);

    return { handlers, helpers, apiKey, failCount };
}
