```javascript
function updatePolicyConfiguration(policy) {
    const defaultConfig = {
        resources: [],
        applyPolicies: [],
    };

    // Set default values
    policy.configuration = { ...defaultConfig, ...policy.configuration };

    // Parse resources
    if (Array.isArray(policy.configuration.resources)) {
        policy.configuration.resources = policy.configuration.resources.map(resource => {
            return typeof resource === 'string' ? { name: resource } : resource;
        });
    }

    // Parse applyPolicies
    if (Array.isArray(policy.configuration.applyPolicies)) {
        policy.configuration.applyPolicies = policy.configuration.applyPolicies.map(policy => {
            return typeof policy === 'string' ? { name: policy } : policy;
        });
    }

    // Stringify resources
    policy.configuration.resources = JSON.stringify(policy.configuration.resources);

    // Stringify applyPolicies
    policy.configuration.applyPolicies = JSON.stringify(policy.configuration.applyPolicies);
}
