function printDependencies(tree, dependencies, maxLines, currentDepth = 0, printedLines = 0) {
    if (printedLines >= maxLines) {
        console.log("There are more dependencies beyond the limit.");
        return printedLines;
    }

    for (const dependency of dependencies) {
        if (printedLines >= maxLines) {
            console.log("There are more dependencies beyond the limit.");
            return printedLines;
        }
        console.log(' '.repeat(currentDepth * 2) + dependency);
        printedLines++;
    }

    for (const child of tree.children) {
        printedLines = printDependencies(child, child.dependencies, maxLines, currentDepth + 1, printedLines);
    }

    return printedLines;
}
