```javascript
class LiveStream {
    constructor() {
        this.keys = new Set();
        this.interval = setInterval(() => this.removeRandomKey(), 5000);
    }

    generateKey() {
        const key = this.generateRandomKey();
        if (this.keys.has(key)) {
            this.keys.delete(key);
        } else {
            this.keys.add(key);
        }
        console.log(`Current keys: ${Array.from(this.keys)}`);
    }

    generateRandomKey() {
        return Math.random().toString(36).substring(2, 10);
    }

    removeRandomKey() {
        const keysArray = Array.from(this.keys);
        if (keysArray.length > 0) {
            const randomIndex = Math.floor(Math.random() * keysArray.length);
            const keyToRemove = keysArray[randomIndex];
            this.keys.delete(keyToRemove);
            console.log(`Removed key: ${keyToRemove}`);
        }
    }

    stop() {
        clearInterval(this.interval);
    }
}

// Usage
const liveStream = new LiveStream();
setInterval(() => liveStream.generateKey(), 2000);
