```javascript
function createPropertyFunctions(obj, namingConvention) {
    const functions = {};

    function isValidPropertyName(name) {
        return namingConvention.test(name);
    }

    return function(property) {
        if (!isValidPropertyName(property)) {
            return function() {};
        }

        if (functions[property]) {
            return functions[property];
        }

        if (property in obj) {
            functions[property] = function(value) {
                if (value !== undefined) {
                    obj[property] = value;
                }
                return obj[property];
            };
        } else {
            functions[property] = function(value) {
                if (value !== undefined) {
                    obj[property] = value;
                }
                return obj[property];
            };
        }

        return functions[property];
    };
}
