function evaluateAndCall(obj, expr) {
    try {
        const result = eval(expr);
        if (typeof window[result] === 'function') {
            const callResult = window[result]();
            if (callResult === true) {
                return true;
            } else {
                obj.data = 'Function call did not return true';
                return false;
            }
        } else {
            obj.data = 'No such function in window object';
            return false;
        }
    } catch (error) {
        obj.data = 'Error evaluating expression: ' + error.message;
        return false;
    }
}
