```javascript
function traverseDOM(node, selector, regex) {
    let matches = [];

    if (node.matches(selector) && (regex.test(node.className) || regex.test(node.id))) {
        matches.push(node);
    }

    node.childNodes.forEach(child => {
        matches = matches.concat(traverseDOM(child, selector, regex));
    });

    return matches;
}
