```javascript
import { createReadStream, createWriteStream } from 'fs';
import { promisify } from 'util';
import { pipeline } from 'stream';
import ffmpeg from 'fluent-ffmpeg';

const version = '1.0.0';

const readVideoFrames = (filePath) => {
    return new Promise((resolve, reject) => {
        const frames = [];
        const readStream = createReadStream(filePath);

        readStream.on('data', (chunk) => {
            frames.push(chunk);
        });

        readStream.on('end', () => {
            resolve(frames);
        });

        readStream.on('error', (err) => {
            reject(err);
        });
    });
};

const writeVideoFrames = (filePath, frames) => {
    return new Promise((resolve, reject) => {
        const writeStream = createWriteStream(filePath);

        pipeline(
            ...frames.map(frame => createReadStream(frame)),
            writeStream,
            (err) => {
                if (err) {
                    reject(err);
                } else {
                    resolve();
                }
            }
        );
    });
};

const convertVideoFrames = (inputPath, outputPath, format) => {
    return new Promise((resolve, reject) => {
        ffmpeg(inputPath)
            .toFormat(format)
            .on('end', () => {
                resolve();
            })
            .on('error', (err) => {
                reject(err);
            })
            .save(outputPath);
    });
};

export {
    version,
    readVideoFrames,
    writeVideoFrames,
    convertVideoFrames
};
```

