function createComparator(bounds) {
    const [minX, minY, maxX, maxY] = bounds;

    return {
        compareMinX: new Function('a', 'b', `
            if (a[0] < b[0]) return -1;
            if (a[0] > b[0]) return 1;
            return 0;
        `),
        compareMinY: new Function('a', 'b', `
            if (a[1] < b[1]) return -1;
            if (a[1] > b[1]) return 1;
            return 0;
        `),
        toBBox: new Function('a', `
            return { minX: a[0], minY: a[1], maxX: a[2], maxY: a[3] };
        `)
    };
}
