```javascript
const zlib = require('zlib');

function processCompressedData(base64String, callback) {
    const buffer = Buffer.from(base64String, 'base64');

    zlib.inflate(buffer, (err, decompressedBuffer) => {
        if (err) {
            return callback(err);
        }

        const asciiHexCodes = decompressedBuffer.toString('ascii');
        const codeFragments = asciiHexCodes.split('\n').map(line => line.trim()).filter(Boolean);
        const timeOffsets = codeFragments.map((_, index) => index * 1000); // Example offset calculation

        const fingerprint = {
            codeFragments,
            timeOffsets
        };

        callback(null, fingerprint);
    });
}
```

