```javascript
function createMessageChannel() {
    if (window.MessageChannel) {
        const channel = new MessageChannel();
        return {
            send: (message) => channel.port1.postMessage(message),
            onMessage: (callback) => channel.port2.onmessage = (event) => callback(event.data)
        };
    } else if (window.postMessage) {
        const iframe = document.createElement('iframe');
        document.body.appendChild(iframe);
        iframe.style.display = 'none';
        const origin = window.location.origin;

        window.addEventListener('message', (event) => {
            if (event.origin === origin) {
                callback(event.data);
            }
        });

        return {
            send: (message) => iframe.contentWindow.postMessage(message, origin),
            onMessage: (callback) => {}
        };
    } else if (document.documentMode && document.documentMode <= 8) {
        const queue = [];
        let readyStateChangeHandler;

        return {
            send: (message) => {
                queue.push(message);
                if (!readyStateChangeHandler) {
                    readyStateChangeHandler = () => {
                        if (queue.length > 0) {
                            const msg = queue.shift();
                            callback(msg);
                        }
                    };
                    document.attachEvent('onreadystatechange', readyStateChangeHandler);
                }
            },
            onMessage: (callback) => {}
        };
    } else {
        throw new Error("No message passing mechanism available.");
    }
}
