```javascript
function traverseDOM(element, selector, testFunc) {
    let matches = [];

    if (element.matches(selector) && testFunc(element)) {
        matches.push(element);
    }

    for (let child of element.children) {
        matches = matches.concat(traverseDOM(child, selector, testFunc));
    }

    return matches;
}
