    if (event.origin !== window.location.origin) return; // Check origin for security

    const message = event.data;
    switch (message.type) {
        case 'requestWorlds':
            // Send the list of loaded worlds
            const worlds = ['Earth', 'Mars', 'Venus']; // Example worlds
            popup.postMessage({ type: 'worldsList', worlds }, '*');
