```javascript
let objectCounter = 0;
const objectMap = new WeakMap();

function hashItem(item) {
    if (item === undefined) {
        return 'undefined';
    }

    if (item === null) {
        return 'null';
    }

    if (typeof item === 'object') {
        if (objectMap.has(item)) {
            return objectMap.get(item);
        } else {
            objectCounter++;
            const hash = `object_${objectCounter}`;
            objectMap.set(item, hash);
            return hash;
        }
    }

    return String(item);
}
