```javascript
function createDraggable(object, minX, maxX, leftButton, rightButton) {
    let offsetX = 0;
    let isDragging = false;

    const onDragStart = (event) => {
        isDragging = true;
        offsetX = event.clientX - object.getBoundingClientRect().left;
        document.addEventListener('mousemove', onDrag);
        document.addEventListener('mouseup', onDragEnd);
    };

    const onDrag = (event) => {
        if (isDragging) {
            let newX = event.clientX - offsetX;
            if (newX < minX) newX = minX;
            if (newX > maxX) newX = maxX;
            object.style.left = `${newX}px`;
            object.style.right = '0px';
        }
    };

    const onDragEnd = () => {
        isDragging = false;
        document.removeEventListener('mousemove', onDrag);
        document.removeEventListener('mouseup', onDragEnd);
    };

    object.style.left = object.style.left || '0px';
    object.style.right = object.style.right || '0px';

    object.addEventListener('mousedown', onDragStart);
    leftButton.addEventListener('click', () => {
        let newX = parseInt(object.style.left) - 10;
        if (newX < minX) newX = minX;
        object.style.left = `${newX}px`;
    });

    rightButton.addEventListener('click', () => {
        let newX = parseInt(object.style.left) + 10;
        if (newX > maxX) newX = maxX;
        object.style.left = `${newX}px`;
    });
}
