function createScopedFunction(code) {
    return async function(s, k) {
        const fn = new Function(...Object.keys(k), 'with(this) { return (' + code + '); }').bind(s);
        const cache = new Map();
        const key = JSON.stringify({ scope: s, locals: k });

        if (cache.has(key)) {
            return cache.get(key);
        }

        const result = await fn(...Object.values(k));
        cache.set(key, result);
        return result;
    };
}
