```javascript
function concatenateBuffers(head) {
    let totalLength = 0;
    let currentNode = head;

    // First pass to calculate total length
    while (currentNode) {
        totalLength += currentNode.data.length;
        currentNode = currentNode.next;
    }

    // Create a new buffer with the total length
    const concatenatedBuffer = Buffer.alloc(totalLength);
    let offset = 0;
    currentNode = head;

    // Second pass to copy data into the new buffer
    while (currentNode) {
        concatenatedBuffer.copy(concatenatedBuffer, offset, 0, currentNode.data.length);
        offset += currentNode.data.length;
        currentNode = currentNode.next;
    }

    return concatenatedBuffer;
}
