```javascript
function parseAction(buffer, offset) {
    const ACTION_TYPE = 0; // Assuming action type is at offset 0
    const LENGTH_OFFSET = 2; // Assuming length is at offset 2

    if (offset + LENGTH_OFFSET + 2 > buffer.length) {
        return { error: 'Buffer overflow', code: 'BUFFER_OVERFLOW' };
    }

    const actionType = buffer.readUInt8(offset + ACTION_TYPE);
    const length = buffer.readUInt16BE(offset + LENGTH_OFFSET);

    if (length <= 0 || offset + LENGTH_OFFSET + length > buffer.length) {
        return { error: 'Invalid length field', code: 'INVALID_LENGTH' };
    }

    const actionData = buffer.slice(offset + LENGTH_OFFSET + 2, offset + LENGTH_OFFSET + 2 + length);

    return { action: actionData, length: length };
}
