function createDraggableObject(minX, maxX, minY, maxY) {
    const draggable = document.createElement('div');
    draggable.style.width = '100px';
    draggable.style.height = '100px';
    draggable.style.backgroundColor = 'blue';
    draggable.style.position = 'absolute';
    document.body.appendChild(draggable);

    let isDragging = false;

    function onDragStart(e) {
        isDragging = true;
    }

    function onDrag(e) {
        if (isDragging) {
            const newX = Math.min(maxX, Math.max(minX, e.clientX - 50));
            const newY = Math.min(maxY, Math.max(minY, e.clientY - 50));
            draggable.style.left = newX + 'px';
            draggable.style.top = newY + 'px';
        }
    }

    function onDragEnd() {
        isDragging = false;
    }

    draggable.addEventListener('mousedown', onDragStart);
    document.addEventListener('mousemove', onDrag);
    document.addEventListener('mouseup', onDragEnd);

    const startButton = document.createElement('button');
    startButton.textContent = 'Start Dragging';
    document.body.appendChild(startButton);

    const stopButton = document.createElement('button');
    stopButton.textContent = 'Stop Dragging';
    document.body.appendChild(stopButton);

    startButton.addEventListener('click', () => {
        draggable.addEventListener('mousedown', onDragStart);
