import PropTypes from 'prop-types';

type ValidationFunction = (props: any, propName: string, componentName: string) => Error | null;

function createValidatedComponent(validationFn: ValidationFunction, componentName: string) {
    const cache: { [key: string]: boolean } = {};

    return (props: any) => {
        for (const prop in props) {
            if (props.hasOwnProperty(prop)) {
                if (!cache[prop]) {
                    const error = validationFn(props, prop, componentName);
                    if (error) {
                        throw new Error(`Invalid prop \`${prop}\` supplied to \`${componentName}\`. ${error.message}`);
                    }
                    cache[prop] = true;
                }
            }
        }
    };
}

// Example usage
const MyComponentPropTypes = {
    name: PropTypes.string.isRequired,
    age: PropTypes.number,
};

const validateMyComponent = createValidatedComponent(PropTypes.checkPropTypes.bind(null, MyComponentPropTypes), 'MyComponent');

// To validate props
const props = { name: 'John', age: 30 };
validateMyComponent(props);
