```javascript
function makeResizableDraggable(element) {
    let isResizing = false;
    let isDragging = false;
    let lastDownX = 0;
    let lastDownY = 0;

    const resizer = document.createElement('div');
    resizer.style.width = '10px';
    resizer.style.height = '10px';
    resizer.style.background = 'blue';
    resizer.style.position = 'absolute';
    resizer.style.right = '0';
    resizer.style.bottom = '0';
    resizer.style.cursor = 'nwse-resize';
    element.appendChild(resizer);

    resizer.addEventListener('mousedown', (event) => {
        isResizing = true;
        event.preventDefault();
    });

    document.addEventListener('mousemove', (event) => {
        if (isResizing) {
            element.style.width = `${event.clientX - element.getBoundingClientRect().left}px`;
            element.style.height = `${event.clientY - element.getBoundingClientRect().top}px`;
        }
        if (isDragging) {
            element.style.left = `${event.clientX - lastDownX}px`;
            element.style.top = `${event.clientY - lastDownY}px`;
        }
    });

    document.addEventListener('mouseup', () => {
        isResizing = false;
        isDragging = false;
    });

    element.addEventListener('mousedown', (event) => {
        if (event.target !== resizer) {
            isDragging = true;
            lastDownX = event.clientX - element.getBoundingClientRect().left;
            lastDownY = event.clientY - element.getBoundingClientRect().top;
        }
    });

    const leftAlignButton = document.createElement('button');
    leftAlignButton.innerText = 'Align Left';
    leftAlignButton.addEventListener('click', () => {
        element.style.left = '0';
    });
    document.body.appendChild(leftAlignButton);

    const rightAlignButton = document.createElement('button');
    rightAlignButton.innerText = 'Align Right';
    rightAlignButton.addEventListener('click', () => {
        element.style.left = `${window.innerWidth - element.offsetWidth}px`;
    });
    document.body.appendChild(rightAlignButton);
}
