```javascript
import PropTypes from 'prop-types';

const propTypesCache = new WeakMap();

export function validateProps(Component, propTypes) {
    if (process.env.NODE_ENV !== 'production') {
        if (!propTypesCache.has(Component)) {
            propTypesCache.set(Component, propTypes);
            Component.propTypes = propTypes;

            const originalRender = Component.prototype.render;

            Component.prototype.render = function() {
                const propKeys = Object.keys(this.props);
                const propTypesKeys = Object.keys(propTypes);

                for (const key of propKeys) {
                    if (!propTypesKeys.includes(key)) {
                        console.warn(`Unknown prop '${key}' passed to ${Component.name}`);
                    }
                }

                return originalRender.call(this);
            };
        }
    }
}
