```javascript
function normalizeURL(url) {
    const urlObj = new URL(url, 'http://dummybase.com'); // Use a base URL to handle relative paths correctly
    const segments = urlObj.pathname.split('/').filter(seg => seg && seg !== '.');
    const stack = [];

    for (const seg of segments) {
        if (seg === '..') {
            stack.pop();
        } else {
            stack.push(seg);
        }
    }

    urlObj.pathname = '/' + stack.join('/');
    return urlObj.href.replace('http://dummybase.com', '').replace(/\/$/, '');
}
