function setupMobileTableTest(testName, testFunction) {
    var testHash = hashTestName(testName);

    $(document).on("pagechange", function(event, ui) {
        if (ui.toPage[0].id === testHash) {
            QUnit.start();
            testFunction();
        }
    });

