const i2c = require('i2c-bus');

function readI2CData(address, register, callback) {
    const i2c1 = i2c.openSync(1); // Open I2C bus 1
    const buffer = Buffer.alloc(2); // Allocate a buffer of size 2 (adjust as needed)

    if (typeof register === 'undefined') {
        i2c1.readI2cBlockSync(address, 0, buffer.length, buffer);
    } else {
        i2c1.readI2cBlockSync(address, register, buffer.length, buffer);
    }

    i2c1.closeSync();

    if (typeof callback === 'function') {
        callback(null, buffer);
    } else {
        return buffer;
    }
}
