function splitStringByDelimiter(inputString, delimiter) {
    const regex = new RegExp(`([^${delimiter}]+)(${delimiter})?`);
    let result = [];
    let match;

    while ((match = regex.exec(inputString)) !== null) {
        if (match[1]) {
            result.push(match[1]);
        }
        inputString = inputString.slice(match[0].length);
    }

    return result.filter(Boolean);
}
