```javascript
function* coroutineSystem(coroutines, token) {
    const iterator = coroutines[Symbol.iterator]();

    while (true) {
        const { value: coroutine, done } = iterator.next();

        if (done) {
            return 'done';
        }

        const result = coroutine.next();

        if (result.done) {
            return result.value;
        }

        if (result.value === token) {
            // Put the coroutine back in the iterable
            coroutines.push(coroutine);
        } else {
            coroutine.next(result.value);
        }
    }
}
