function decodeBuffer(buffer) {
    if (!buffer || buffer.length === 0) {
        return '';
    }

    const decoder = new TextDecoder('utf-8', { fatal: true });
    let decodedString = '';

    try {
        decodedString = decoder.decode(buffer, { stream: true });
    } catch (error) {
        // If an error occurs, return the string decoded so far
        return decodedString;
    }

    // Finalize decoding to handle any remaining bytes
    decodedString += decoder.decode(); 
    return decodedString;
}
