function canBeContent(component) {
    const isFunctionComponent = typeof component.type === 'function';
    const isClassComponent = typeof component.type === 'object' && component.type !== null && component.type.prototype && component.type.prototype.isReactComponent;
    const isDOMElement = typeof component.type === 'string';

    const hasContentProps = component.props && (component.props.children || component.props.dangerouslySetInnerHTML);

    if (isFunctionComponent || isClassComponent || isDOMElement) {
        if (hasContentProps) {
            return 'This component can be treated as content.';
        }
    }

    return 'This component cannot be treated as content.';
}
