```javascript
function parseTokens(input, patterns) {
    const results = [];
    const tokens = input.split(/\s+/);

    for (let token of tokens) {
        for (let pattern of patterns) {
            const regex = new RegExp(pattern);
            if (regex.test(token)) {
                results.push(token);
                input = input.replace(token, '').trim();
                break;
            }
        }
    }

    return results;
}
