```javascript
function copyBytesFromChunks(chunks, byteCount) {
    const totalBytes = chunks.reduce((sum, chunk) => sum + chunk.length, 0);
    const bufferSize = Math.min(totalBytes, byteCount);
    const newBuffer = Buffer.allocUnsafe(bufferSize);

    let offset = 0;
    for (const chunk of chunks) {
        const bytesToCopy = Math.min(chunk.length, bufferSize - offset);
        chunk.copy(newBuffer, offset, 0, bytesToCopy);
        offset += bytesToCopy;
        if (offset >= bufferSize) break;
    }

    return newBuffer;
}
