function decodeBuffer(buffer) {
    if (!buffer || buffer.length === 0) {
        return '';
    }

    const decoder = new TextDecoder('utf-8', { fatal: true });
    let decodedString = '';
    let incompleteBuffer = new Uint8Array();

    try {
        decodedString = decoder.decode(buffer, { stream: true });
    } catch (e) {
        if (e instanceof TypeError) {
            incompleteBuffer = buffer.slice(-decoder.encoding.length);
            decodedString = decoder.decode(incompleteBuffer, { stream: false });
        }
    }

    return decodedString;
}
