            const packageName32 = dest_filename.replace('.deb', '-linux32.deb');
            const packageName64 = dest_filename.replace('.deb', '-linux64.deb');

            execSync(`dpkg-deb --build ${dest_filename} ${packageName32}`);
            execSync(`dpkg-deb --build ${dest_filename} ${packageName64}`);
        } catch (error) {
