```javascript
function parseMidiMetaEvent(dataStream) {
    const event = {};

    const metaType = dataStream.readUInt8();
    const length = dataStream.readUInt8();

    switch (metaType) {
        case 0x58: // Time Signature
            if (length !== 4) throw new Error('Invalid Time Signature length');
            const numerator = dataStream.readUInt8();
            const denominator = Math.pow(2, dataStream.readUInt8());
            const metronome = dataStream.readUInt8();
            const thirtyseconds = dataStream.readUInt8();
            event.subtype = 'timeSignature';
            event.numerator = numerator;
            event.denominator = denominator;
            event.metronome = metronome;
            event.thirtyseconds = thirtyseconds;
            break;

        case 0x01: // Key Signature
            if (length !== 2) throw new Error('Invalid Key Signature length');
            const key = dataStream.readInt8();
            const scale = dataStream.readUInt8();
            event.subtype = 'keySignature';
            event.key = key;
            event.scale = scale;
            break;

        case 0x7F: // Sequencer Specific
            if (length < 1) throw new Error('Invalid Sequencer Specific length');
            const data = new Uint8Array(length);
            dataStream.read(data);
            event.subtype = 'sequencerSpecific';
            event.data = data;
            break;

        default:
            event.subtype = 'unknown';
            console.error(`Unknown meta event type: ${metaType}`);
            break;
    }

    return event;
}
