```c
#include <stdlib.h>
#include <string.h>

typedef struct Chunk {
    char *data;
    size_t size;
    struct Chunk *next;
} Chunk;

inline char* copy_chunks(size_t *n, Chunk *list) {
    size_t total_bytes = 0;
    Chunk *current = list;

    while (current != NULL && total_bytes < *n) {
        total_bytes += current->size;
        current = current->next;
    }

    if (total_bytes > *n) {
        total_bytes = *n;
    }

    char *buffer = (char *)malloc(total_bytes);
    if (buffer == NULL) {
        return NULL;
    }

    size_t bytes_copied = 0;
    current = list;

    while (current != NULL && bytes_copied < total_bytes) {
        size_t to_copy = current->size;
        if (bytes_copied + to_copy > total_bytes) {
            to_copy = total_bytes - bytes_copied;
        }

        memcpy(buffer + bytes_copied, current->data, to_copy);
        bytes_copied += to_copy;
        current = current->next;
    }

    *n = bytes_copied;
    return buffer;
}
