import java.util.Random;
import java.util.HashMap;
import java.util.Map;

public class GraphDatabase {
    private final Map<Integer, Map<String, String>> vertices = new HashMap<>();
    private final Map<Integer, Map<String, String>> edges = new HashMap<>();
    private final Random random = new Random();
    private int vertexCount = 0;
    private int edgeCount = 0;

    public void addRandomVerticesAndEdges() {
        int numVertices = random.nextInt(10) + 1; // Random number of vertices between 1 and 10
        int numEdges = random.nextInt(10) + 1; // Random number of edges between 1 and 10

        for (int i = 0; i < numVertices; i++) {
            Map<String, String> properties = new HashMap<>();
            properties.put("property" + random.nextInt(100), "value" + random.nextInt(100));
            vertices.put(vertexCount++, properties);
        }

        for (int i = 0; i < numEdges; i++) {
            Map<String, String> properties = new HashMap<>();
            properties.put("property" + random.nextInt(100), "value" + random.nextInt(100));
            edges.put(edgeCount++, properties);
