import java.util.ArrayList;
import java.util.List;
import java.util.Random;

public class MutationUtil {
    public static Pair<Double, List<Double>> mutateValue(Random random, double value, double stdDevFactor, double range) {
        double mean = value;
        double stdDev = stdDevFactor * range;
        double mutatedValue = mean + random.nextGaussian() * stdDev;

        List<Double> discreteValues = new ArrayList<>();
        for (double i = mean - range; i <= mean + range; i++) {
            discreteValues.add(i);
        }

        return new Pair<>(mutatedValue, discreteValues);
    }

    public static class Pair<T, U> {
        public final T first;
        public final U second;

        public Pair(T first, U second) {
            this.first = first;
            this.second = second;
        }
    }
}
