import java.math.BigDecimal;
import java.math.MathContext;
import java.security.SecureRandom;
import java.util.Random;

public class RandomValueGenerator {

    private static final Random random = new SecureRandom();

    public static <T> T generateRandomValue(Class<T> type) {
        if (type == byte.class) {
            return type.cast((byte) random.nextInt(Byte.MAX_VALUE + 1));
        } else if (type == short.class) {
            return type.cast((short) random.nextInt(Short.MAX_VALUE + 1));
        } else if (type == int.class) {
            return type.cast(random.nextInt());
        } else if (type == long.class) {
            return type.cast(random.nextLong());
        } else if (type == float.class) {
            return type.cast(random.nextFloat());
        } else if (type == double.class) {
            return type.cast(random.nextDouble());
        } else if (type == char.class) {
            return type.cast((char) (random.nextInt(26) + 'a'));
        } else if (type == String.class) {
            int length = random.nextInt(10) + 1; // Random length between 1 and 10
            StringBuilder sb = new StringBuilder(length);
            for (int i = 0; i < length; i++) {
                sb.append((char) (random.nextInt(26) + 'a'));
            }
            return type.cast(sb.toString());
        } else if (type == BigDecimal.class) {
            return type.cast(BigDecimal.valueOf(random.nextDouble()).round(new MathContext(2)));
        } else {
            throw new IllegalArgumentException("Type not supported");
        }
    }
}
