import org.apache.lucene.index.IndexReader;
import org.apache.lucene.index.LeafReaderContext;
import org.apache.lucene.index.NumericDocValues;
import org.hamcrest.MatcherAssert;
import org.hamcrest.Matchers;

public void compareNumericFields(IndexReader reader, int docId1, int docId2, String fieldName) throws Exception {
    NumericDocValues values1 = reader.getNumericDocValues(fieldName);
    NumericDocValues values2 = reader.getNumericDocValues(fieldName);

    if (values1 == null || values2 == null) {
        throw new IllegalArgumentException("Field not found in one or both documents.");
    }

    values1.advanceExact(docId1);
    values2.advanceExact(docId2);

    long value1 = values1.longValue();
    long value2 = values2.longValue();

    MatcherAssert.assertThat("Values are not equal", value1, Matchers.is(value2));

    int count1 = (int) values1.getValueCount();
    int count2 = (int) values2.getValueCount();

    MatcherAssert.assertThat("Number of values in fields are not the same", count1, Matchers.is(count2));
}
