import java.util.Arrays;

public class UnsignedConverter {

    public static long[] convertToUnsigned(int[] input) {
        long[] result = new long[input.length];
        for (int i = 0; i < input.length; i++) {
            if (input[i] < 0) {
                result[i] = 0; // Treat negative as 0
            } else {
                result[i] = input[i] & 0xFFFFFFFFL; // Convert to unsigned long
            }
        }
        return result;
    }

    public static void main(String[] args) {
        int[] testArray = {0, 1, -1, Integer.MAX_VALUE, Integer.MIN_VALUE, 100, -100};
        long[] unsignedResults = convertToUnsigned(testArray);
        System.out.println(Arrays.toString(unsignedResults));
    }
}
