public class PairMover {
    private static final Random random = new Random();

    public static void processPairs(List<Pair> pairs, double percentage) {
        int totalPairs = pairs.size();
        int pairsToProcess = (int) (totalPairs * percentage);

        for (int i = 0; i < pairsToProcess; i++) {
            Pair currentPair = pairs.get(i);
            if (i == totalPairs - 1) {
                System.out.println("Current pair is the last one: " + currentPair);
            } else {
                System.out.println("Current pair is not the last one: " + currentPair);
                int randomIndex = random.nextInt(i);
                Pair previousPair = pairs.get(randomIndex);
                // Move currentPair to the position of previousPair (simulated)
                System.out.println("Moving current pair to position of previous pair: " + previousPair);
            }
        }
    }

    public static class Pair {
        private final int number;
        private final boolean flag;

        public Pair(int number, boolean flag) {
            this.number = number;
            this.flag = flag;
        }

        @Override
        public String toString() {
            return "Pair{" + "number=" + number + ", flag=" + flag + '}';
        }
    }
}
