    public void performRandomOperation(int expectedHeartbeats, int expectedClears) {
        for (int i = 0; i < 100; i++) {
            if (random.nextBoolean()) {
                reportHeartbeat();
            } else {
                clearPrimary();
            }
        }
        logOperationDifference(expectedHeartbeats, expectedClears);
    }

    private void reportHeartbeat() {
        heartbeatCount++;
    }

    private void clearPrimary() {
        clearPrimaryCount++;
    }

    private void logOperationDifference(int expectedHeartbeats, int expectedClears) {
        int heartbeatDifference = expectedHeartbeats - heartbeatCount;
        int clearPrimaryDifference = expectedClears - clearPrimaryCount;
        logger.info("Heartbeat count difference: " + heartbeatDifference);
        logger.info("Clear primary count difference: " + clearPrimaryDifference);
    }
