        int numberOfFields = random.nextInt(9) + 1;
        List<String> fields = new ArrayList<>();

        for (int i = 0; i < numberOfFields; i++) {
            fields.add(types[random.nextInt(types.length)]);
        }

        boolean ascendingOrder = random.nextBoolean();
        boolean includeNullsAtEnd = random.nextBoolean();

        if (includeNullsAtEnd) {
            fields.add(null);
        }

        if (ascendingOrder) {
            Collections.sort(fields, (a, b) -> {
                if (a == null) return 1;
                if (b == null) return -1;
                return a.compareTo(b);
            });
        } else {
            Collections.sort(fields, (a, b) -> {
                if (a == null) return 1;
                if (b == null) return -1;
                return b.compareTo(a);
            });
        }

        callOtherMethod(fields, ascendingOrder);
    }

    private static void callOtherMethod(List<String> fields, boolean ascendingOrder) {
