import com.codahale.metrics.Graphite;
import com.codahale.metrics.GraphiteReporter;
import com.codahale.metrics.MetricRegistry;
import com.codahale.metrics.Gauge;

import java.net.InetSocketAddress;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.TimeUnit;

public class MetricNotificationService {

    private final GraphiteReporter graphiteReporter;
    private final MetricRegistry metricRegistry;
    private final Map<String, Gauge> metricMap;

    private static MetricNotificationService instance;

    private MetricNotificationService(String hostname, int port) {
        this.metricRegistry = new MetricRegistry();
        this.graphiteReporter = GraphiteReporter.forRegistry(metricRegistry)
                .prefixedWith("myapp")
                .convertDurationsTo(TimeUnit.SECONDS)
                .build(new Graphite(new InetSocketAddress(hostname, port)));
        this.metricMap = new HashMap<>();
        this.graphiteReporter.start(1, TimeUnit.MINUTES);
    }

    public static MetricNotificationService get(String hostname, int port) {
        if (instance == null) {
            instance = new MetricNotificationService(hostname, port);
        }
        return instance;
    }

    public void registerMetric(String name, Gauge<?> gauge) {
        metricRegistry.register(name, gauge);
        metricMap.put(name, gauge);
    }
}
