import java.net.InetSocketAddress;
import java.util.ArrayList;
import java.util.List;

public class ConnectionUtils {

    public static List<InetSocketAddress> createSocketAddresses(List<String> hostnames, String username, String password, 
                                                                String serverId, boolean createEnrichmentConnection, 
                                                                String driverLocation, String driverName, 
                                                                int connectionTimeout) {
        List<InetSocketAddress> socketAddresses = new ArrayList<>();

        for (String hostname : hostnames) {
            String[] parts = hostname.split(":");
            if (parts.length != 2) {
                throw new ArrayIndexOutOfBoundsException("Input must be in the format host:port");
            }

            String host = parts[0];
            int port;
            try {
                port = Integer.parseInt(parts[1]);
            } catch (NumberFormatException e) {
                throw new IllegalArgumentException("Invalid port number: " + parts[1]);
            }

            socketAddresses.add(new InetSocketAddress(host, port));
        }

        return socketAddresses;
    }
}
