import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.ObjectInputStream;
import java.io.Serializable;

public class Deserializer {

    public <T extends Serializable> T deserialize(byte[] byteArray, Class<T> clazz) {
        try (ByteArrayInputStream bais = new ByteArrayInputStream(byteArray);
             ObjectInputStream ois = new ObjectInputStream(bais)) {
            Object obj = ois.readObject();
            if (!clazz.isInstance(obj)) {
                throw new RuntimeException("Deserialized object is not of type " + clazz.getName());
            }
            return clazz.cast(obj);
        } catch (IOException e) {
            throw new RuntimeException("Deserialization failed due to I/O error: " + e.getMessage(), e);
        } catch (ClassNotFoundException e) {
            throw new RuntimeException("Deserialization failed: Class not found - " + e.getMessage(), e);
        } catch (ClassCastException e) {
            throw new RuntimeException("Deserialized object cannot be cast to " + clazz.getName(), e);
        }
    }
}
