import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.nio.file.FileSystem;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Random;

public class RandomBinaryFileGenerator {

    public static File generateRandomBinaryFile(FileSystem fileSystem, String folder, String fileName, int length) throws IOException {
        Path folderPath = fileSystem.getPath(folder);
        if (!Files.exists(folderPath)) {
            Files.createDirectories(folderPath);
        }

        File file = new File(folderPath.toFile(), fileName);
        try (FileOutputStream fos = new FileOutputStream(file)) {
            Random random = new Random();
            int bytesWritten = 0;

            while (bytesWritten < length) {
                int bytesToWrite = random.nextBoolean() ? 1 : Math.min(random.nextInt(1024) + 1, length - bytesWritten);
                byte[] data = new byte[bytesToWrite];
                random.nextBytes(data);
                fos.write(data);
                bytesWritten += bytesToWrite;
            }
        }

        return file;
    }
}
