import javax.crypto.Cipher;
import javax.crypto.SecretKeyFactory;
import javax.crypto.spec.PBEKeySpec;
import javax.crypto.spec.SecretKeySpec;
import javax.crypto.spec.IvParameterSpec;
import java.security.spec.KeySpec;
import java.util.Base64;
import javax.crypto.spec.SecretKeySpec;

public class AESCryptography {
    private static final String ALGORITHM = "AES";
    private static final String CIPHER_TRANSFORMATION = "AES/CBC/NoPadding";

    public static byte[] generateKey(String password, byte[] salt) throws Exception {
        KeySpec spec = new PBEKeySpec(password.toCharArray(), salt, 65536, 128);
        SecretKeyFactory factory = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA1");
        byte[] key = factory.generateSecret(spec).getEncoded();
        return key;
    }

    public static byte[] encrypt(String password, byte[] salt, byte[] data, byte[] iv) throws Exception {
        byte[] key = generateKey(password, salt);
        SecretKeySpec secretKey = new SecretKeySpec(key, ALGORITHM);
        Cipher cipher = Cipher.getInstance(CIPHER_TRANSFORMATION);
        IvParameterSpec ivParams = new IvParameterSpec(iv);
        cipher.init(Cipher.ENCRYPT_MODE, secretKey, ivParams);
        return cipher.doFinal(data);
    }

    public static byte[] decrypt(String password, byte[] salt, byte[] encryptedData, byte[] iv) throws Exception {
        byte[] key = generateKey(password, salt);
        SecretKeySpec secretKey = new SecretKeySpec(key, ALGORITHM);
        Cipher cipher = Cipher.getInstance(CIPHER_TRANSFORMATION);
        IvParameterSpec ivParams = new IvParameterSpec(iv);
        cipher.init(Cipher.DECRYPT_MODE, secretKey, ivParams);
        return cipher.doFinal(encryptedData);
    }

    public static void main(String[] args) {
        try {
            String password = "mysecretpassword";
            byte[] salt = "randomsalt".getBytes();
            byte[] iv = new byte[16]; // Initialization Vector (must be 16 bytes for AES)
            byte[] data = "Hello, World!".getBytes();

            byte[] encryptedData = encrypt(password, salt, data, iv);
            System.out.println("Encrypted: " + Base64.getEncoder().encodeToString(encryptedData));

            byte[] decryptedData = decrypt(password, salt, encryptedData, iv);
            System.out.println("Decrypted: " + new String(decryptedData));
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
