import java.util.ArrayList;
import java.util.List;
import java.util.Random;
import java.util.HashSet;

public class ObjectModifier {
    private Random random = new Random();

    public List<Double> modifyList(List<Object> originalList) {
        int size = originalList.size();
        double mean = 0;
        double stdDev = 0.2 * size;
        List<Object> modifiedList = new ArrayList<>(originalList);
        HashSet<Double> discreteValues = new HashSet<>();

        for (int i = 0; i < size; i++) {
            if (random.nextBoolean()) {
                double newValue = mean + random.nextGaussian() * stdDev;
                modifiedList.set(i, newValue);
                discreteValues.add(newValue);
            }
        }

        // You can return the modified list or the discrete values based on your requirement
        return new ArrayList<>(discreteValues);
    }
}
