import java.io.InputStream;
import java.net.HttpURLConnection;
import java.net.URL;

public class ResourceLoader {

    public InputStream loadResource(String resourceUrl) throws Exception {
        InputStream inputStream = null;

        if (resourceUrl.startsWith("http://") || resourceUrl.startsWith("https://")) {
            URL url = new URL(resourceUrl);
            HttpURLConnection connection = (HttpURLConnection) url.openConnection();
            connection.setRequestMethod("GET");
            connection.connect();

            if (connection.getResponseCode() == HttpURLConnection.HTTP_OK) {
                inputStream = connection.getInputStream();
            } else {
                throw new Exception("Failed to connect to remote resource: " + connection.getResponseMessage());
            }
        } else {
            inputStream = getClass().getResourceAsStream(resourceUrl);
            if (inputStream == null) {
                throw new Exception("Resource not found: " + resourceUrl);
            }
        }

        return inputStream;
    }
}
