```java
import java.util.*;
import java.util.concurrent.atomic.AtomicInteger;

class Graph {
    private final Map<Integer, List<Integer>> adjacencyList = new HashMap<>();
    private final AtomicInteger vertexCount = new AtomicInteger(0);
    private final AtomicInteger edgeCount = new AtomicInteger(0);
    private final AtomicInteger completedThreads = new AtomicInteger(0);

    public void addVertex(int vertex) {
        adjacencyList.putIfAbsent(vertex, new ArrayList<>());
        vertexCount.incrementAndGet();
    }

    public void addEdge(int source, int destination) {
        adjacencyList.get(source).add(destination);
        adjacencyList.get(destination).add(source); // For undirected graph
        edgeCount.incrementAndGet();
    }

    public void traverse(int startVertex) {
        Set<Integer> visited = new HashSet<>();
        traverseHelper(startVertex, visited);
        completedThreads.incrementAndGet();
    }

    private void traverseHelper(int vertex, Set<Integer> visited) {
        if (visited.contains(vertex)) return;
        visited.add(vertex);
        System.out.println("Visited: " + vertex);
        for (int neighbor : adjacencyList.get(vertex)) {
            traverseHelper(neighbor, visited);
        }
    }

    public int getVertexCount() {
        return vertexCount.get();
    }

    public int getEdgeCount() {
        return edgeCount.get();
    }

    public int getCompletedThreads() {
        return completedThreads.get();
    }
}

class GraphTraversalThread extends Thread {
    private final Graph graph;
    private final int startVertex;

    public GraphTraversalThread(Graph graph, int startVertex) {
        this.graph = graph;
        this.startVertex = startVertex;
    }

    @Override
    public void run() {
        graph.traverse(startVertex);
    }
}

public class ConcurrentGraphTraversal {
    public static void main(String[] args) throws InterruptedException {
        Graph graph = new Graph();
        graph.addVertex(1);
        graph.addVertex(2);
        graph.addVertex(3);
        graph.addVertex(4);
        graph.addEdge(1, 2);
        graph.addEdge(1, 3);
        graph.addEdge(2, 4);

        Thread thread1 = new GraphTraversalThread(graph, 1);
        Thread thread2 = new GraphTraversalThread(graph, 2);
        Thread thread3 = new GraphTraversalThread(graph, 3);

        thread1.start();
        thread2.start();
        thread3.start();

        thread1.join();
        thread2.join();
        thread3.join();

        System.out.println("Number of vertices: " + graph.getVertexCount());
        System.out.println("Number of edges: " + graph.getEdgeCount());
        System.out.println("Number of completed threads: " + graph.getCompletedThreads());
    }
}
