import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

class ProcessReturnInfo {
    private final int exitCode;
    private final String stdout;
    private final String stderr;

    public ProcessReturnInfo(int exitCode, String stdout, String stderr) {
        this.exitCode = exitCode;
        this.stdout = stdout;
        this.stderr = stderr;
    }

    public int getExitCode() {
        return exitCode;
    }

    public String getStdout() {
        return stdout;
    }

    public String getStderr() {
        return stderr;
    }
}

public class CommandExecutor {

    public ProcessReturnInfo executeCommand(String command) throws IOException, InterruptedException {
        Process process = Runtime.getRuntime().exec(command);
        StringBuilder output = new StringBuilder();
        StringBuilder error = new StringBuilder();

        try (BufferedReader stdInput = new BufferedReader(new InputStreamReader(process.getInputStream()));
             BufferedReader stdError = new BufferedReader(new InputStreamReader(process.getErrorStream()))) {

            String s;
            while ((s = stdInput.readLine()) != null) {
                output.append(s).append(System.lineSeparator());
            }

            while ((s = stdError.readLine()) != null) {
                error.append(s).append(System.lineSeparator());
            }
        }

        int exitCode = process.waitFor();
        return new ProcessReturnInfo(exitCode, output.toString(), error.toString());
    }
}
