```java
import java.lang.reflect.Array;
import java.lang.reflect.Field;
import java.util.Collection;
import java.util.Map;

public class JsonGenerator {
    public static String toJson(Object obj) {
        if (obj == null) {
            return "null";
        }
        if (obj instanceof String) {
            return "\"" + escapeString((String) obj) + "\"";
        }
        if (obj instanceof Number || obj instanceof Boolean) {
            return obj.toString();
        }
        if (obj.getClass().isArray()) {
            return arrayToJson(obj);
        }
        if (obj instanceof Collection) {
            return collectionToJson((Collection<?>) obj);
        }
        if (obj instanceof Map) {
            return mapToJson((Map<?, ?>) obj);
        }
        return objectToJson(obj);
    }

    private static String arrayToJson(Object array) {
        StringBuilder json = new StringBuilder("[");
        int length = Array.getLength(array);
        for (int i = 0; i < length; i++) {
            json.append(toJson(Array.get(array, i)));
            if (i < length - 1) {
                json.append(",");
            }
        }
        json.append("]");
        return json.toString();
    }

    private static String collectionToJson(Collection<?> collection) {
        StringBuilder json = new StringBuilder("[");
        int size = collection.size();
        int i = 0;
        for (Object item : collection) {
            json.append(toJson(item));
            if (i < size - 1) {
                json.append(",");
            }
            i++;
        }
        json.append("]");
        return json.toString();
    }

    private static String mapToJson(Map<?, ?> map) {
        StringBuilder json = new StringBuilder("{");
        int size = map.size();
        int i = 0;
        for (Map.Entry<?, ?> entry : map.entrySet()) {
            json.append("\"").append(escapeString(entry.getKey().toString())).append("\":");
            json.append(toJson(entry.getValue()));
            if (i < size - 1) {
                json.append(",");
            }
            i++;
        }
        json.append("}");
        return json.toString();
    }

    private static String objectToJson(Object obj) {
        StringBuilder json = new StringBuilder("{");
        Field[] fields = obj.getClass().getDeclaredFields();
        int length = fields.length;
        for (int i = 0; i < length; i++) {
            Field field = fields[i];
            field.setAccessible(true);
            try {
                json.append("\"").append(escapeString(field.getName())).append("\":");
                json.append(toJson(field.get(obj)));
                if (i < length - 1) {
                    json.append(",");
                }
            } catch (IllegalAccessException e) {
                e.printStackTrace();
            }
        }
        json.append("}");
        return json.toString();
    }

    private static String escapeString(String str) {
        return str.replace("\\", "\\\\")
                  .replace("\"", "\\\"")
                  .replace("\b", "\\b")
                  .replace("\f", "\\f")
                  .replace("\n", "\\n")
                  .replace("\r", "\\r")
                  .replace("\t", "\\t");
    }
}
