import java.util.*;
import java.util.function.Function;

public class WeightNormalizer {

    public static <T> Map<T, Double> normalizeWeights(List<WeightedItem<T>> items, Function<WeightedItem<T>, Double> weightFunction) {
        Map<T, Double> normalizedWeights = new HashMap<>();
        double totalWeight = 0.0;

        for (WeightedItem<T> item : items) {
            totalWeight += weightFunction.apply(item);
        }

        for (WeightedItem<T> item : items) {
            double normalizedWeight = totalWeight > 0 ? weightFunction.apply(item) / totalWeight : 0.0;
            normalizedWeights.put(item.getItem(), normalizedWeight);
        }

        return normalizedWeights;
    }

    public static class WeightedItem<T> {
        private final T item;
        private final double weight;

        public WeightedItem(T item, double weight) {
            this.item = item;
            this.weight = weight;
        }

        public T getItem() {
            return item;
        }

        public double getWeight() {
            return weight;
        }
    }
}
