```java
import java.util.HashMap;

public class DisjointPairs {

    public static int countDisjointPairs(int[] arr) {
        long startTime = System.currentTimeMillis();

        int n = arr.length;
        UnionFind uf = new UnionFind(n);
        HashMap<Integer, Integer> indexMap = new HashMap<>();

        for (int i = 0; i < n; i++) {
            indexMap.put(arr[i], i);
        }

        int disjointPairsCount = 0;

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (uf.find(i) != uf.find(j)) {
                    disjointPairsCount++;
                    uf.union(i, j);
                }
            }
        }

        long endTime = System.currentTimeMillis();
        System.out.println("Time taken (ms): " + (endTime - startTime));

        return disjointPairsCount;
    }

    static class UnionFind {
        private int[] parent;
        private int[] rank;

        public UnionFind(int size) {
            parent = new int[size];
            rank = new int[size];
            for (int i = 0; i < size; i++) {
                parent[i] = i;
                rank[i] = 1;
            }
        }

        public int find(int p) {
            if (parent[p] != p) {
                parent[p] = find(parent[p]);
            }
            return parent[p];
        }

        public void union(int p, int q) {
            int rootP = find(p);
            int rootQ = find(q);
            if (rootP != rootQ) {
                if (rank[rootP] > rank[rootQ]) {
                    parent[rootQ] = rootP;
                } else if (rank[rootP] < rank[rootQ]) {
                    parent[rootP] = rootQ;
                } else {
                    parent[rootQ] = rootP;
                    rank[rootP]++;
                }
            }
        }
    }

    public static void main(String[] args) {
        int[] array = {1, 2, 3, 4, 5}; // Example input
        int result = countDisjointPairs(array);
        System.out.println("Number of disjoint pairs: " + result);
    }
}
