import android.graphics.RectF;
import java.util.Random;

public class DrawableCropper {

    private static final Random random = new Random();

    public static RectF getCroppedDrawable(RectF drawableBounds, RectF viewport) {
        float drawableAspect = drawableBounds.width() / drawableBounds.height();
        float viewportAspect = viewport.width() / viewport.height();

        float cropWidth, cropHeight;

        if (drawableAspect > viewportAspect) {
            cropWidth = Math.min(drawableBounds.width(), viewport.width());
            cropHeight = cropWidth / drawableAspect;
        } else {
            cropHeight = Math.min(drawableBounds.height(), viewport.height());
            cropWidth = cropHeight * drawableAspect;
        }

        float scaleFactor = random.nextFloat();
        float minSize = 50; // Minimum size constraint
        cropWidth = Math.max(cropWidth * scaleFactor, minSize);
        cropHeight = Math.max(cropHeight * scaleFactor, minSize);

        float offsetX = random.nextFloat() * (drawableBounds.width() - cropWidth);
        float offsetY = random.nextFloat() * (drawableBounds.height() - cropHeight);

        return new RectF(drawableBounds.left + offsetX, drawableBounds.top + offsetY, 
                         drawableBounds.left + offsetX + cropWidth, 
                         drawableBounds.top + offsetY + cropHeight);
    }
}
