public class OpenAPIConfig {

    public OpenAPI configureOpenApiWithKeycloak(OpenAPI openApi) {
        SecurityScheme securityScheme = new SecurityScheme()
            .name("keycloak")
            .type(Type.OAUTH2)
            .in(In.HEADER)
            .flows(new OAuthFlows()
                .authorizationCode(new OAuthFlow()
                    .authorizationUrl("https://your-keycloak-url/auth/realms/your-realm/protocol/openid-connect/auth")
                    .tokenUrl("https://your-keycloak-url/auth/realms/your-realm/protocol/openid-connect/token")
                    .scopes(new HashMap<>())
                    .addExtension("nonce", "true"))); // Add nonce parameter

        openApi.getComponents().addSecuritySchemes("keycloak", securityScheme);
        openApi.addSecurityItem(new SecurityRequirement().addList("keycloak"));

        return openApi;
    }
