import io.swagger.v3.oas.models.OpenAPI;
import io.swagger.v3.oas.models.security.SecurityScheme;
import io.swagger.v3.oas.models.security.SecurityScheme.Type;
import io.swagger.v3.oas.models.security.SecurityScheme.In;
import io.swagger.v3.oas.models.security.OAuthFlow;
import io.swagger.v3.oas.models.security.OAuthFlows;

public void configureOpenAPISecurity(OpenAPI openAPI, String keycloakRealmPath) {
    SecurityScheme oidcScheme = new SecurityScheme()
            .type(Type.OPENIDCONNECT)
            .name("oidc")
            .openIdConnectUrl(keycloakRealmPath + "/protocol/openid-connect/certs");

    SecurityScheme oauth2Scheme = new SecurityScheme()
            .type(Type.OAUTH2)
            .name("oauth2")
            .flows(new OAuthFlows()
                .authorizationCode(new OAuthFlow()
                    .authorizationUrl(keycloakRealmPath + "/protocol/openid-connect/auth")
                    .tokenUrl(keycloakRealmPath + "/protocol/openid-connect/token")
                    .addExtension("nonce", true)));

    openAPI.addSecurityItem(new io.swagger.v3.oas.models.security.SecurityRequirement().addList("oauth2"));
    openAPI.components(new io.swagger.v3.oas.models.Components()
            .addSecuritySchemes("oidc", oidcScheme)
            .addSecuritySchemes("oauth2", oauth2Scheme));
}
