```java
import java.util.List;
import java.util.Collections;

public class GeoPointComparator {

    public static void compareGeoPoints(List<List<Double>> setA, List<List<Double>> setB, double tolerance) throws Exception {
        if (setA.size() != setB.size()) {
            throw new Exception("The number of documents in the sets do not match.");
        }

        for (int i = 0; i < setA.size(); i++) {
            List<Double> pointsA = setA.get(i);
            List<Double> pointsB = setB.get(i);

            if (pointsA.size() != pointsB.size()) {
                throw new Exception("The number of values in document " + i + " do not match.");
            }

            if (pointsA.size() > 0) {
                List<Double> sortedA = pointsA.stream().sorted().toList();
                List<Double> sortedB = pointsB.stream().sorted().toList();

                for (int j = 0; j < sortedA.size(); j++) {
                    if (Math.abs(sortedA.get(j) - sortedB.get(j)) > tolerance) {
                        throw new Exception("Values in document " + i + " at index " + j + " are not within the tolerance.");
                    }
                }
            }
        }
    }
}
