public class TokenManager {

    private DelegationTokenManagerService tokenService;

    public TokenManager(DelegationTokenManagerService tokenService) {
        this.tokenService = tokenService;
    }

    public Object manageDelegationToken(String userCredentials, String tokenId, String action) {
        switch (action.toLowerCase()) {
            case "create":
                return tokenService.createToken(userCredentials);
            case "verify":
                return tokenService.verifyToken(tokenId);
            case "renew":
                return tokenService.renewToken(tokenId);
            case "cancel":
                return tokenService.cancelToken(tokenId);
            default:
                throw new IllegalArgumentException("Invalid action: " + action);
        }
    }
