public class WeatherFetcher {
    private static final String API_KEY = "YOUR_API_KEY";
    private static final String API_URL = "http://api.openweathermap.org/data/2.5/weather?q=";

    public static String getWeatherData(String location) {
        StringBuilder response = new StringBuilder();
        try {
            String urlString = API_URL + location + "&appid=" + API_KEY;
            URL url = new URL(urlString);
            HttpURLConnection conn = (HttpURLConnection) url.openConnection();
            conn.setRequestMethod("GET");

            int responseCode = conn.getResponseCode();
            if (responseCode == HttpURLConnection.HTTP_OK) {
                BufferedReader in = new BufferedReader(new InputStreamReader(conn.getInputStream()));
                String inputLine;
                while ((inputLine = in.readLine()) != null) {
                    response.append(inputLine);
                }
                in.close();
            } else {
                return "Error: Unable to fetch weather data. Response code: " + responseCode;
            }
        } catch (Exception e) {
            return "Exception occurred: " + e.getMessage();
        }
        return response.toString();
    }
}
