import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.net.HttpURLConnection;
import java.net.InetSocketAddress;
import java.net.Proxy;
import java.net.URL;

public class ProxyExample {

    public static void main(String[] args) {
        try {
            String targetUrl = "http://example.com";
            String proxy1Host = "proxy1.example.com";
            int proxy1Port = 8080;
            String proxy2Host = "proxy2.example.com";
            int proxy2Port = 8081;

            // Set up first proxy
            Proxy proxy1 = new Proxy(Proxy.Type.HTTP, new InetSocketAddress(proxy1Host, proxy1Port));
            HttpURLConnection connection1 = (HttpURLConnection) new URL(targetUrl).openConnection(proxy1);
            printResponse(connection1);

            // Set up second proxy
            Proxy proxy2 = new Proxy(Proxy.Type.HTTP, new InetSocketAddress(proxy2Host, proxy2Port));
            HttpURLConnection connection2 = (HttpURLConnection) new URL(targetUrl).openConnection(proxy2);
            printResponse(connection2);

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static void printResponse(HttpURLConnection connection) throws Exception {
        BufferedReader in = new BufferedReader(new InputStreamReader(connection.getInputStream()));
        String inputLine;
        StringBuilder response = new StringBuilder();
        while ((inputLine = in.readLine()) != null) {
            response.append(inputLine);
        }
        in.close();
        System.out.println("Response: " + response.toString());
    }
}
