import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.regex.Pattern;

public class CommandPatternChecker {
    public static void main(String[] args) {
        String command = "your_command_here"; // Replace with your command
        String patternToFind = "your_pattern_here"; // Replace with the pattern to find
        int sleepTime = 5000; // Time in milliseconds to sleep before checking again

        boolean found = checkPatternInCommandOutput(command, patternToFind, sleepTime);
        System.out.println("Pattern found: " + found);
    }

    public static boolean checkPatternInCommandOutput(String command, String patternToFind, int sleepTime) {
        boolean patternFound = false;
        Pattern pattern = Pattern.compile(patternToFind);

        try {
            while (true) {
                Process process = Runtime.getRuntime().exec(command);
                BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
                String line;
                boolean matchFound = false;

                while ((line = reader.readLine()) != null) {
                    if (pattern.matcher(line).find()) {
                        matchFound = true;
                        break;
                    }
                }

                reader.close();
                process.waitFor();

                if (matchFound) {
                    patternFound = true;
                    Thread.sleep(sleepTime);
                } else {
                    break;
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }

        return patternFound;
    }
}
