        this.y = y;
        this.z = z;
    }

    @Override
    public String toString() {
        return "CustomObject{" +
                "d=" + d +
                ", x=" + x +
                ", y=" + y +
                ", z=" + z +
                '}';
    }
}

public class SerializationExample {
    public static void main(String[] args) {
        CustomObject originalObject = new CustomObject(10, 20.5, 30.5f, true);

        // Serialize the object
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream("object.ser"))) {
            oos.writeObject(originalObject);
        } catch (IOException e) {
            e.printStackTrace();
        }

        // Deserialize the object
        CustomObject deserializedObject = null;
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream("object.ser"))) {
            deserializedObject = (CustomObject) ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }

        // Output the deserialized object
        System.out.println("Deserialized Object: " + deserializedObject);
    }
}
