```java
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public class DateRangeHasher {
    public static String getIntervalWithHash(String dateRange) {
        String[] dates = dateRange.split("/");
        if (dates.length != 2) {
            throw new IllegalArgumentException("Invalid date range format. Expected 'startDate/endDate'.");
        }

        String startDate = dates[0];
        String endDate = dates[1];
        String interval = startDate + "/" + endDate;

        String hash = hashString(dateRange);
        return hash + interval;
    }

    private static String hashString(String input) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] hashBytes = md.digest(input.getBytes());
            StringBuilder hashString = new StringBuilder();
            for (byte b : hashBytes) {
                hashString.append(String.format("%02x", b));
            }
            return hashString.toString();
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("Hashing algorithm not found", e);
        }
    }
