public class KijiDataRequestSerializer {

    public byte[] serializeKijiDataRequest(KijiDataRequest request) throws IOException {
        // Serialize the KijiDataRequest
        ByteArrayOutputStream byteOut = new ByteArrayOutputStream();
        try (ObjectOutputStream out = new ObjectOutputStream(byteOut)) {
            out.writeObject(request);
        }
        return byteOut.toByteArray();
    }

    public KijiDataRequest deserializeKijiDataRequest(byte[] data) throws IOException, ClassNotFoundException {
        // Deserialize the KijiDataRequest
        ByteArrayInputStream byteIn = new ByteArrayInputStream(data);
        try (ObjectInputStream in = new ObjectInputStream(byteIn)) {
            return (KijiDataRequest) in.readObject();
        }
    }

    public boolean compareRequests(KijiDataRequest originalRequest) throws IOException, ClassNotFoundException {
        byte[] serializedData = serializeKijiDataRequest(originalRequest);
        KijiDataRequest deserializedRequest = deserializeKijiDataRequest(serializedData);
        return originalRequest.equals(deserializedRequest);
    }
}
