public class PokemonWeaknesses {
    public static String getWeaknesses(Pokemon pokemon) {
        String type = pokemon.getType();
        String weaknesses;

        switch (type.toLowerCase()) {
            case "fire":
                weaknesses = "Water, Ground, Rock";
                break;
            case "water":
                weaknesses = "Electric, Grass";
                break;
            case "grass":
                weaknesses = "Fire, Ice, Bug, Flying, Poison";
                break;
            case "electric":
                weaknesses = "Ground";
                break;
            case "ground":
                weaknesses = "Water, Ice, Grass";
                break;
            case "rock":
                weaknesses = "Water, Grass, Fighting, Steel, Ground";
                break;
            case "fighting":
                weaknesses = "Flying, Psychic, Fairy";
                break;
            case "psychic":
                weaknesses = "Bug, Ghost, Dark";
                break;
            case "bug":
                weaknesses = "Fire, Flying, Rock, Fairy, Ice";
                break;
            case "ghost":
                weaknesses = "Ghost, Dark";
                break;
            case "fairy":
                weaknesses = "Poison, Steel";
                break;
            default:
                weaknesses = "No weaknesses found.";
                break;
        }

        return pokemon.getName() + " is weak against: " + weaknesses;
    }
}
