import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.io.ObjectInputStream;
import java.util.Hashtable;
import java.util.ArrayList;
import java.util.List;

public class FileFilter {
    public static void main(String[] args) {
        String directoryPath = "path/to/directory";
        String dataType = "specificDataType"; // Replace with your specific data type
        List<File> filteredFiles = new ArrayList<>();

        File directory = new File(directoryPath);
        if (directory.isDirectory()) {
            File[] files = directory.listFiles();
            if (files != null) {
                for (File file : files) {
                    if (file.isFile()) {
                        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(file))) {
                            Hashtable<String, Object> data = (Hashtable<String, Object>) ois.readObject();
                            if (data.containsKey(dataType)) {
                                filteredFiles.add(file);
                            }
                        } catch (FileNotFoundException e) {
                            System.err.println("File not found: " + file.getName());
                        } catch (IOException e) {
                            System.err.println("IOException while reading file: " + file.getName());
                        } catch (ClassNotFoundException e) {
                            System.err.println("Class not found while reading file: " + file.getName());
                        }
                    }
                }
            }
        }

        System.out.println("Filtered files containing " + dataType + ":");
        for (File filteredFile : filteredFiles) {
            System.out.println(filteredFile.getName());
        }
    }
}
