import java.net.InetSocketAddress;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.ArrayList;
import java.util.List;

public class UrlToInetSocketAddress {

    public static List<InetSocketAddress> convertUrlsToInetSocketAddresses(List<String> urls) {
        List<InetSocketAddress> addresses = new ArrayList<>();

        for (String url : urls) {
            try {
                URI uri = new URI(url);
                String host = uri.getHost();
                int port = uri.getPort() != -1 ? uri.getPort() : (uri.getScheme().equalsIgnoreCase("https") ? 443 : 80);

                if (host != null) {
                    InetSocketAddress address = new InetSocketAddress(host, port);
                    addresses.add(address);
                }
            } catch (URISyntaxException e) {
                // Invalid URL, skip it
            } catch (Exception e) {
                // Handle DNS resolution failures or other exceptions if needed
            }
        }

        return addresses;
    }
}
