import org.apache.zookeeper.server.ZooKeeperServer;
import org.apache.zookeeper.server.ServerCnxnFactory;
import org.apache.zookeeper.server.NIOServerCnxnFactory;

import java.io.File;
import java.io.IOException;
import java.net.InetSocketAddress;
import java.net.BindException;

public class ZooKeeperServerSetup {
    public static void main(String[] args) {
        String txnLogDir = "path/to/txnLog"; // Specify your transaction log directory
        int minPort = 2181; // Specify the starting port
        int maxPort = 2191; // Specify the ending port
        int tickTime = 2000; // Specify tick time
        int sessionTimeout = 60000; // Specify session timeout

        File logDir = new File(txnLogDir);
        if (!logDir.exists()) {
            logDir.mkdirs();
        }

        ZooKeeperServer zkServer = new ZooKeeperServer(logDir, logDir, tickTime);
        ServerCnxnFactory factory = null;

        for (int port = minPort; port <= maxPort; port++) {
            try {
                factory = NIOServerCnxnFactory.createFactory(new InetSocketAddress(port), 1024);
                factory.startup(zkServer);
                System.out.println("ZooKeeper server started on port: " + port);
                break; // Exit the loop if server started successfully
            } catch (BindException e) {
                // Ignored, continue to the next port
            } catch (IOException e) {
                e.printStackTrace();
                break; // Exit on other IO exceptions
            }
        }

        if (factory == null) {
            System.err.println("Failed to start ZooKeeper server on the specified port range.");
        }
    }
}
