import org.apache.mina.transport.socket.nio.NioSocketConnector;
import org.apache.mina.core.filterchain.DefaultFilterChainBuilder;
import org.apache.mina.core.session.IoSession;
import org.apache.mina.core.session.IoHandlerAdapter;
import org.apache.mina.core.future.ConnectFuture;

import java.net.URI;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;

public class MinaSocketConnector {

    public IoSession connect(URI uri, int timeout, List<Object> filters, int maxPoolSize) throws Exception {
        NioSocketConnector connector = new NioSocketConnector();
        connector.setConnectTimeout(timeout);

        DefaultFilterChainBuilder filterChain = connector.getFilterChain();
        for (Object filter : filters) {
            filterChain.addLast(filter.getClass().getSimpleName(), filter);
        }

        connector.setHandler(new IoHandlerAdapter());

        ExecutorService executorService = Executors.newFixedThreadPool(maxPoolSize);
        connector.setWorkerPool(executorService);

        ConnectFuture future = connector.connect(uri);
        future.awaitUninterruptibly();

        if (!future.isConnected()) {
            throw new Exception("Failed to connect to " + uri);
        }

        return future.getSession();
    }
}
