import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Arrays;

public class KeystoreGenerator {

    public static void main(String[] args) {
        if (args.length != 5) {
            System.err.println("Usage: java KeystoreGenerator <hostname> <keystore-password> <alias> <key-algorithm> <validity>");
            return;
        }

        String hostname = args[0];
        String keystorePassword = args[1];
        String alias = args[2];
        String keyAlgorithm = args[3];
        String validity = args[4];

        try {
            // Create a temporary directory
            Path tempDir = Files.createTempDirectory("keystore");
            File keystoreFile = new File(tempDir.toFile(), "keystore.jks");

            // Build the keytool command
            String[] command = {
                    "keytool",
                    "-genkeypair",
                    "-alias", alias,
                    "-keyalg", keyAlgorithm,
                    "-keystore", keystoreFile.getAbsolutePath(),
                    "-storepass", keystorePassword,
                    "-keypass", keystorePassword,
                    "-dname", "CN=" + hostname,
                    "-validity", validity
            };

            // Execute the command
            ProcessBuilder processBuilder = new ProcessBuilder(command);
            Process process = processBuilder.inheritIO().start();
            int exitCode = process.waitFor();

            if (exitCode == 0) {
                System.out.println("Keystore created successfully at: " + keystoreFile.getAbsolutePath());
            } else {
                System.err.println("Error occurred while generating keystore. Exit code: " + exitCode);
            }

        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }
}
