import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class HMMPOSTagger {
    private Map<String, Map<String, Double>> transitionProbabilities = new HashMap<>();
    private Map<String, Map<String, Double>> emissionProbabilities = new HashMap<>();
    private List<String> states;

    public void loadModel(String modelFilePath) throws IOException {
        try (BufferedReader br = new BufferedReader(new FileReader(modelFilePath))) {
            String line;
            boolean readingTransitions = false;
            boolean readingEmissions = false;

            while ((line = br.readLine()) != null) {
                if (line.trim().equals("TRANSITIONS")) {
                    readingTransitions = true;
                    readingEmissions = false;
                    continue;
                } else if (line.trim().equals("EMISSIONS")) {
                    readingTransitions = false;
                    readingEmissions = true;
                    continue;
                }

                if (readingTransitions) {
                    String[] parts = line.split("\\s+");
                    String fromState = parts[0];
                    String toState = parts[1];
                    double probability = Double.parseDouble(parts[2]);
                    transitionProbabilities.putIfAbsent(fromState, new HashMap<>());
                    transitionProbabilities.get(fromState).put(toState, probability);
                } else if (readingEmissions) {
                    String[] parts = line.split("\\s+");
                    String state = parts[0];
                    String observation = parts[1];
                    double probability = Double.parseDouble(parts[2]);
                    emissionProbabilities.putIfAbsent(state, new HashMap<>());
                    emissionProbabilities.get(state).put(observation, probability);
                }
            }
        }
    }

    public Map<String, String> tag(String[] words) {
        Map<String, String> taggedWords = new HashMap<>();
        for (String word : words) {
            String bestTag = null;
            double bestProbability = Double.NEGATIVE_INFINITY;

            for (String state : states) {
                double emissionProb = emissionProbabilities.getOrDefault(state, new HashMap<>()).getOrDefault(word, 0.0);
                double transitionProb = transitionProbabilities.getOrDefault("START", new HashMap<>()).getOrDefault(state, 0.0);
                double probability = Math.log(transitionProb) + Math.log(emissionProb);

                if (probability > bestProbability) {
                    bestProbability = probability;
                    bestTag = state;
                }
            }
            taggedWords.put(word, bestTag);
        }
        return taggedWords;
    }

    public void setStates(List<String> states) {
        this.states = states;
    }

    public static void main(String[] args) {
        HMMPOSTagger tagger = new HMMPOSTagger();
        try {
            tagger.loadModel("hmm_model.txt");
            tagger.setStates(List.of("NN", "VB", "JJ", "RB")); // Example states
            String[] inputText = {"The", "cat", "sits", "on", "the", "mat"};
            Map<String, String> taggedResult = tagger.tag(inputText);

            for (Map.Entry<String, String> entry : taggedResult.entrySet()) {
                System.out.println(entry.getKey() + " => " + entry.getValue());
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}
