import com.alibaba.otter.canal.protocol.CanalEntry;
import com.alibaba.otter.canal.protocol.Message;
import com.alibaba.otter.canal.client.CanalConnector;
import com.alibaba.otter.canal.client.CanalConnectors;

import java.net.InetSocketAddress;
import java.util.List;

public class CanalClient {
    public static void main(String[] args) {
        CanalConnector connector = CanalConnectors.newSingleConnector(
                new InetSocketAddress("localhost", 11111),
                "example",
                "", 
                "");

        try {
            connector.connect();
            connector.subscribe("empty_topic");
            connector.rollback();

            int batchSize = 10; // specify the number of messages to receive
            while (true) {
                Message message = connector.getWithoutAck(batchSize); // fetch messages
                long batchId = message.getId();
                try {
                    List<CanalEntry.Entry> entries = message.getEntries();
                    if (entries.isEmpty()) {
                        System.out.println("No messages found.");
                    } else {
                        for (CanalEntry.Entry entry : entries) {
                            // Process each entry
                            System.out.println("Received entry: " + entry.toString());
                        }
                    }
                } finally {
                    connector.ack(batchId); // acknowledge the received messages
                }
            }
        } finally {
            connector.disconnect();
        }
    }
}
