import javax.imageio.ImageIO;
import javax.swing.*;
import java.awt.*;
import java.awt.image.BufferedImage;
import java.io.File;
import java.io.IOException;

public class ImageRotator {

    public static void main(String[] args) {
        String filePath = "path/to/your/image.jpg"; // replace with your image path
        int angle = 90; // replace with your desired rotation angle

        try {
            rotateImage(filePath, angle);
            displayImage(filePath);
        } catch (IOException | InterruptedException e) {
            JOptionPane.showMessageDialog(null, "Error: " + e.getMessage());
        }
    }

    private static void rotateImage(String filePath, int angle) throws IOException, InterruptedException {
        String command = String.format("convert %s -rotate %d %s", filePath, angle, filePath);
        Process process = Runtime.getRuntime().exec(command);
        int exitCode = process.waitFor();
        if (exitCode != 0) {
            throw new IOException("Failed to rotate image. Command exited with code: " + exitCode);
        }
    }

    private static void displayImage(String filePath) throws IOException {
        BufferedImage img = ImageIO.read(new File(filePath));
        ImageIcon icon = new ImageIcon(img);
        JLabel label = new JLabel(icon);
        JFrame frame = new JFrame();
        frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        frame.getContentPane().add(label);
        frame.pack();
        frame.setVisible(true);
    }
}
