import com.google.android.youtube.player.YouTubeBaseActivity;
import com.google.android.youtube.player.YouTubeInitializationResult;
import com.google.android.youtube.player.YouTubePlayer;
import com.google.android.youtube.player.YouTubePlayerView;
import android.os.Bundle;
import android.view.MotionEvent;
import android.view.View;
import android.widget.ImageView;
import com.squareup.picasso.Picasso;

public class YouTubePlayerActivity extends YouTubeBaseActivity {

    private static final String API_KEY = "YOUR_API_KEY";
    private static final String VIDEO_ID = "YOUR_VIDEO_ID";
    private YouTubePlayer youtubePlayer;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_youtube_player);

        ImageView thumbnail = findViewById(R.id.thumbnail);
        YouTubePlayerView youTubePlayerView = findViewById(R.id.youtube_player_view);

        Picasso.get().load("https://img.youtube.com/vi/" + VIDEO_ID + "/0.jpg").into(thumbnail);

        youTubePlayerView.initialize(API_KEY, new YouTubePlayer.OnInitializedListener() {
            @Override
            public void onInitializationSuccess(YouTubePlayer.Provider provider, YouTubePlayer player, boolean wasRestored) {
                youtubePlayer = player;
                if (!wasRestored) {
                    youtubePlayer.loadVideo(VIDEO_ID);
                }
                thumbnail.setOnClickListener(v -> youtubePlayer.play());
            }

            @Override
            public void onInitializationFailure(YouTubePlayer.Provider provider, YouTubeInitializationResult error) {
                // Handle error
            }
        });

        // Make the activity draggable
        findViewById(R.id.youtube_player_container).setOnTouchListener(new View.OnTouchListener() {
            private float dX, dY;

            @Override
            public boolean onTouch(View view, MotionEvent event) {
                switch (event.getAction()) {
                    case MotionEvent.ACTION_DOWN:
                        dX = view.getX() - event.getRawX();
                        dY = view.getY() - event.getRawY();
                        break;
                    case MotionEvent.ACTION_MOVE:
                        view.animate()
                            .x(event.getRawX() + dX)
                            .y(event.getRawY() + dY)
                            .setDuration(0)
                            .start();
                        break;
                    default:
                        break;
                }
                return true;
            }
        });
    }
}
