import java.io.BufferedInputStream;
import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.net.HttpURLConnection;
import java.net.URL;
import java.nio.file.Files;

public class DictionaryDownloader {

    public static void main(String[] args) {
        String dictionaryUrl = "http://example.com/dictionary.txt"; // Replace with actual URL
        String existingDictionaryPath = "path/to/existing/dictionary.txt"; // Replace with actual path

        try {
            File tempFile = downloadDictionary(dictionaryUrl);
            replaceExistingDictionary(tempFile, existingDictionaryPath);
            System.out.println("Dictionary updated successfully.");
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }

    private static File downloadDictionary(String urlString) throws IOException {
        URL url = new URL(urlString);
        HttpURLConnection connection = (HttpURLConnection) url.openConnection();
        connection.setRequestMethod("GET");

        try (InputStream in = new BufferedInputStream(connection.getInputStream());
             FileOutputStream out = new FileOutputStream(File.createTempFile("downloaded_dict", ".txt"))) {
            byte[] buffer = new byte[1024];
            int bytesRead;
            while ((bytesRead = in.read(buffer, 0, buffer.length)) != -1) {
                out.write(buffer, 0, bytesRead);
            }
        }

        return new File("downloaded_dict.txt");
    }

    private static void replaceExistingDictionary(File tempFile, String existingDictionaryPath) throws IOException {
        Files.move(tempFile.toPath(), new File(existingDictionaryPath).toPath(), java.nio.file.StandardCopyOption.REPLACE_EXISTING);
    }
}
