import java.io.*;
import java.net.HttpURLConnection;
import java.net.URL;
import java.util.concurrent.TimeUnit;
import com.google.common.util.concurrent.RateLimiter;

public class HttpClient {

    public static String sendPostRequest(String endpoint, String requestBody, String token, boolean gzip, Integer maxRate) throws IOException, InterruptedException {
        if (maxRate != null) {
            RateLimiter rateLimiter = RateLimiter.create(maxRate);
            rateLimiter.acquire();
        }

        HttpURLConnection connection = (HttpURLConnection) new URL(endpoint).openConnection();
        connection.setRequestMethod("POST");
        connection.setRequestProperty("Authorization", "Bearer " + token);
        connection.setRequestProperty("Content-Type", "application/json");
        if (gzip) {
            connection.setRequestProperty("Content-Encoding", "gzip");
            requestBody = gzipRequestBody(requestBody);
        }
        connection.setDoOutput(true);

        try (OutputStream os = connection.getOutputStream()) {
            os.write(requestBody.getBytes("UTF-8"));
            os.flush();
        }

        BufferedReader in = new BufferedReader(new InputStreamReader(connection.getInputStream()));
        StringBuilder response = new StringBuilder();
        String inputLine;
        while ((inputLine = in.readLine()) != null) {
            response.append(inputLine);
        }
        in.close();

        return response.toString();
    }

    private static String gzipRequestBody(String requestBody) throws IOException {
        ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();
        try (GZIPOutputStream gzipOutputStream = new GZIPOutputStream(byteArrayOutputStream)) {
            gzipOutputStream.write(requestBody.getBytes("UTF-8"));
        }
        return byteArrayOutputStream.toString("ISO-8859-1");
    }
}
