import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.Scanner;

public class HashGenerator {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter the string to hash: ");
        String input = scanner.nextLine();

        System.out.print("Enter the hashing algorithm (MD5, SHA-1, SHA-256, SHA-384, SHA-512): ");
        String algorithm = scanner.nextLine().toUpperCase();

        try {
            String hashValue = generateHash(input, algorithm);
            System.out.println("Hash value: " + hashValue);
        } catch (NoSuchAlgorithmException e) {
            System.out.println("Invalid algorithm name.");
        }

        scanner.close();
    }

    public static String generateHash(String input, String algorithm) throws NoSuchAlgorithmException {
        MessageDigest digest = MessageDigest.getInstance(algorithm);
        byte[] hashBytes = digest.digest(input.getBytes());
        StringBuilder hexString = new StringBuilder();

        for (byte b : hashBytes) {
            String hex = Integer.toHexString(0xff & b);
            if (hex.length() == 1) hexString.append('0');
            hexString.append(hex);
        }

        return hexString.toString();
    }
}
