import java.io.File;
import java.io.FileInputStream;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public class MD5Hasher {

    public static void generateMD5Hash(String filePath) {
        File file = new File(filePath);
        String md5FilePath = filePath + ".md5";

        try (InputStream fis = new FileInputStream(file);
             FileOutputStream fos = new FileOutputStream(md5FilePath)) {

            MessageDigest md = MessageDigest.getInstance("MD5");
            byte[] dataBytes = new byte[1024];
            int bytesRead;

            System.out.println("Generating MD5 hash for: " + file.getName());

            while ((bytesRead = fis.read(dataBytes)) != -1) {
                md.update(dataBytes, 0, bytesRead);
            }

            byte[] mdBytes = md.digest();
            StringBuilder sb = new StringBuilder();

            for (byte b : mdBytes) {
                sb.append(String.format("%02x", b));
            }

            fos.write(sb.toString().getBytes());
            System.out.println("MD5 hash written to: " + md5FilePath);

        } catch (IOException | NoSuchAlgorithmException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}
