import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.sql.SQLException;

public class DatabaseService {
    private Dao dao; // Assume Dao is a predefined data access object

    public DatabaseService(Dao dao) {
        this.dao = dao;
    }

    public void createOrUpdateObject(String userName, String url, boolean someFlag, String algorithm) throws NoSuchAlgorithmException, SQLException {
        String uniqueIdentifier = generateUniqueIdentifier(userName, url, algorithm);
        // Create or update the object in the database using the DAO
        dao.createOrUpdate(uniqueIdentifier, someFlag);
    }

    private String generateUniqueIdentifier(String userName, String url, String algorithm) throws NoSuchAlgorithmException {
        MessageDigest messageDigest = MessageDigest.getInstance(algorithm);
        String input = userName + url;
        byte[] digest = messageDigest.digest(input.getBytes());
        return bytesToHex(digest);
    }

    private String bytesToHex(byte[] bytes) {
        StringBuilder hexString = new StringBuilder();
        for (byte b : bytes) {
            String hex = Integer.toHexString(0xff & b);
            if (hex.length() == 1) hexString.append('0');
            hexString.append(hex);
        }
        return hexString.toString();
    }
}
