import java.io.*;
import java.net.Socket;

public class RemoteMethodCaller {

    public Object callRemoteMethod(String host, int port, String methodName, Object... params) throws IOException, ClassNotFoundException {
        try (Socket socket = new Socket(host, port);
             ObjectOutputStream out = new ObjectOutputStream(socket.getOutputStream());
             ObjectInputStream in = new ObjectInputStream(socket.getInputStream())) {

            // Create a request object
            Request request = new Request(methodName, params);
            // Send the request
            out.writeObject(request);
            out.flush();

            // Receive the response
            Object response = in.readObject();
            return response;
        }
    }

    private static class Request implements Serializable {
        private final String methodName;
        private final Object[] params;

        public Request(String methodName, Object[] params) {
            this.methodName = methodName;
            this.params = params;
        }

        public String getMethodName() {
            return methodName;
        }

        public Object[] getParams() {
            return params;
        }
    }
}
