import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.List;

public class Change {
    private final String accountId;
    private final long lastUpdated;
    private final int rowVersion;
    private final List<Revision> revisions;

    // Getters for accountId, lastUpdated, rowVersion, and revisions

    public String getAccountId() {
        return accountId;
    }

    public long getLastUpdated() {
        return lastUpdated;
    }

    public int getRowVersion() {
        return rowVersion;
    }

    public List<Revision> getRevisions() {
        return revisions;
    }
}

class Revision {
    private final String revisionId;

    public Revision(String revisionId) {
        this.revisionId = revisionId;
    }

    public String getRevisionId() {
        return revisionId;
    }
}

public class ETagGenerator {

    public static String generateETag(Change change) {
        try {
            MessageDigest md = MessageDigest.getInstance("MD5");
            StringBuilder stringBuilder = new StringBuilder();

            stringBuilder.append(change.getLastUpdated());
            stringBuilder.append(change.getRowVersion());
            stringBuilder.append(change.getAccountId());

            for (Revision revision : change.getRevisions()) {
                stringBuilder.append(revision.getRevisionId());
            }

            byte[] hashBytes = md.digest(stringBuilder.toString().getBytes());
            StringBuilder hashString = new StringBuilder();

            for (byte b : hashBytes) {
                hashString.append(String.format("%02x", b));
            }

            return hashString.toString();
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("MD5 algorithm not found", e);
        }
    }
}
