import com.sun.net.httpserver.HttpExchange;
import java.io.IOException;
import java.io.OutputStream;
import java.net.InetSocketAddress;

public class SimpleHttpServer {
    private static int jobsCompleted = 10; // Example data
    private static int jobsFailed = 2; // Example data

    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/notify", new NotifyHandler());
        server.setExecutor(null); // creates a default executor
        server.start();
    }

    static class NotifyHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            String response = "Jobs completed: " + jobsCompleted + ", Jobs failed: " + jobsFailed;
            exchange.sendResponseHeaders(200, response.length());
            OutputStream os = exchange.getResponseBody();
            os.write(response.getBytes());
            os.close();
        }
    }
}
