public class SocketConnection {

    public static Socket createSocketConnection(String host, int port, boolean useSSL, int connectionTimeout, int readTimeout) throws IOException {
        Socket socket;

        if (useSSL) {
            SSLSocketFactory factory = (SSLSocketFactory) SSLSocketFactory.getDefault();
            socket = factory.createSocket();
        } else {
