import java.net.InetSocketAddress;
import java.net.URI;
import java.nio.channels.DatagramChannel;
import java.nio.channels.Selector;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class DatagramConnector {
    private DatagramChannel channel;
    private Selector selector;
    private ExecutorService executorService;

    public DatagramConnector(DatagramChannel channel, Selector selector, ExecutorService executorService) {
        this.channel = channel;
        this.selector = selector;
        this.executorService = executorService;
    }

    public static DatagramConnector setupConnection(String uri) {
        if (uri == null || uri.isEmpty()) {
            throw new IllegalArgumentException("URI cannot be null or empty");
        }

        try {
            URI connectionURI = new URI(uri);
            InetSocketAddress socketAddress = new InetSocketAddress(connectionURI.getHost(), connectionURI.getPort());

            DatagramChannel channel = DatagramChannel.open();
            channel.configureBlocking(false);
            channel.bind(socketAddress);

            Selector selector = Selector.open();
            channel.register(selector, SelectionKey.OP_READ);

            int processorCount = Runtime.getRuntime().availableProcessors();
            ExecutorService executorService = Executors.newFixedThreadPool(processorCount);

            return new DatagramConnector(channel, selector, executorService);
        } catch (Exception e) {
            throw new IllegalArgumentException("Error setting up connection: " + e.getMessage(), e);
        }
    }
}
