import javax.xml.stream.XMLInputFactory;
import javax.xml.stream.XMLStreamReader;
import org.springframework.http.HttpStatus;
import org.springframework.web.server.ResponseStatusException;
import java.io.InputStream;

public class XmlParser {

    public Source parseXml(InputStream inputStream) {
        if (inputStream == null || inputStream.available() == 0) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "Input stream is empty or null");
        }

        try {
            XMLInputFactory factory = XMLInputFactory.newInstance();
            XMLStreamReader reader = factory.createXMLStreamReader(inputStream);
            return new StreamSource(reader);
        } catch (Exception e) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "Failed to read XML", e);
        }
    }
}
