import java.io.*;

class Person implements Serializable {
    private String name;
    private int age;

    public Person(String name, int age) {
        this.name = name;
        this.age = age;
    }

    public String getName() {
        return name;
    }

    public int getAge() {
        return age;
    }
}

public class SerializationExample {

    public static void main(String[] args) {
        try {
            // Create an object to serialize
            Person originalPerson = new Person("Alice", 30);

            // Serialize the object to a byte array
            ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();
            ObjectOutputStream objectOutputStream = new ObjectOutputStream(byteArrayOutputStream);
            objectOutputStream.writeObject(originalPerson);
            objectOutputStream.flush();
            byte[] byteArray = byteArrayOutputStream.toByteArray();
            objectOutputStream.close();
            byteArrayOutputStream.close();

            // Deserialize the byte array back to an object
            ByteArrayInputStream byteArrayInputStream = new ByteArrayInputStream(byteArray);
            ObjectInputStream objectInputStream = new ObjectInputStream(byteArrayInputStream);
            Person deserializedPerson = (Person) objectInputStream.readObject();
            objectInputStream.close();
            byteArrayInputStream.close();

            // Verify that the deserialized object has the same properties as the original object
            System.out.println("Original Name: " + originalPerson.getName());
            System.out.println("Deserialized Name: " + deserializedPerson.getName());
            System.out.println("Original Age: " + originalPerson.getAge());
            System.out.println("Deserialized Age: " + deserializedPerson.getAge());
            System.out.println("Properties match: " + 
                originalPerson.getName().equals(deserializedPerson.getName()) && 
                originalPerson.getAge() == deserializedPerson.getAge());

        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}
