    }
}

public class SerializationExample {
    public static void main(String[] args) {
        MyObject originalObject = new MyObject("Test", 42);

        byte[] serializedObject = serialize(originalObject);
        MyObject deserializedObject = deserialize(serializedObject);

        System.out.println("Original Object: " + originalObject);
        System.out.println("Deserialized Object: " + deserializedObject);
    }

    public static byte[] serialize(MyObject obj) {
        try (ByteArrayOutputStream bos = new ByteArrayOutputStream();
             ObjectOutputStream oos = new ObjectOutputStream(bos)) {
            oos.writeObject(obj);
            return bos.toByteArray();
        } catch (IOException e) {
            e.printStackTrace();
            return null;
        }
    }

    public static MyObject deserialize(byte[] data) {
        try (ByteArrayInputStream bis = new ByteArrayInputStream(data);
             ObjectInputStream ois = new ObjectInputStream(bis)) {
            return (MyObject) ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
            return null;
        }
    }
}
