import java.io.File;
import java.io.FileInputStream;
import java.io.FileOutputStream;
import java.io.IOException;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.zip.Deflater;

import org.apache.hadoop.io.compress.CompressionCodec;
import org.apache.hadoop.io.compress.CompressionCodecFactory;
import org.apache.hadoop.conf.Configuration;

public class FileCompressor {

    public static String compressFile(String filePath, int compressionLevel) throws IOException, NoSuchAlgorithmException {
        Configuration conf = new Configuration();
        CompressionCodecFactory factory = new CompressionCodecFactory(conf);
        CompressionCodec codec = factory.getCodec(new File(filePath));

        if (codec == null) {
            throw new IOException("No codec found for file: " + filePath);
        }

        String compressedFilePath = filePath + ".lzo";
        try (FileInputStream fis = new FileInputStream(filePath);
             FileOutputStream fos = new FileOutputStream(compressedFilePath);
             Deflater deflater = new Deflater(compressionLevel)) {

            byte[] buffer = new byte[1024];
            int bytesRead;

            while ((bytesRead = fis.read(buffer)) != -1) {
                deflater.setInput(buffer, 0, bytesRead);
            }
            deflater.finish();
            byte[] compressedData = new byte[1024];
            while (!deflater.finished()) {
                int count = deflater.deflate(compressedData);
                fos.write(compressedData, 0, count);
            }
        }

        return getMD5Hash(compressedFilePath);
    }

    private static String getMD5Hash(String filePath) throws IOException, NoSuchAlgorithmException {
        MessageDigest md = MessageDigest.getInstance("MD5");
        try (FileInputStream fis = new FileInputStream(new File(filePath))) {
            byte[] dataBytes = new byte[1024];
            int nRead;

            while ((nRead = fis.read(dataBytes)) != -1) {
                md.update(dataBytes, 0, nRead);
            }
        }
        byte[] mdBytes = md.digest();
        StringBuilder sb = new StringBuilder();
        for (byte b : mdBytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }
}
