import akka.actor.ActorSystem;
import akka.actor.AbstractActor;
import akka.actor.Props;
import akka.io.Tcp;
import akka.io.TcpMessage;
import scala.concurrent.duration.Duration;

import java.net.InetSocketAddress;
import java.util.concurrent.TimeUnit;

public class TcpDiscoveryActor extends AbstractActor {

    private final String remoteAddress;
    private final int remotePort;

    public TcpDiscoveryActor(String remoteAddress, int remotePort) {
        this.remoteAddress = remoteAddress;
        this.remotePort = remotePort;
    }

    @Override
    public Receive createReceive() {
        return receiveBuilder()
                .match(Tcp.CommandFailed.class, msg -> {
                    // Handle command failure
                })
                .match(Tcp.Connected.class, msg -> {
                    // Send discovery message
                    getSender().tell(TcpMessage.write(TcpMessage.register(getSelf())), getSelf());
                    String discoveryMessage = "DISCOVERY_MESSAGE";
                    getSender().tell(TcpMessage.write(discoveryMessage), getSelf());
                })
                .build();
    }

    @Override
    public void preStart() {
        getContext().getSystem().actorOf(Props.create(TcpListener.class, getSelf(), remoteAddress, remotePort));
    }

    public static class TcpListener extends AbstractActor {

        private final ActorRef sender;
        private final String remoteAddress;
        private final int remotePort;

        public TcpListener(ActorRef sender, String remoteAddress, int remotePort) {
            this.sender = sender;
            this.remoteAddress = remoteAddress;
            this.remotePort = remotePort;
        }

        @Override
        public Receive createReceive() {
            return receiveBuilder()
                    .match(Tcp.Bound.class, msg -> {
                        // Listening successfully
                    })
                    .match(Tcp.CommandFailed.class, msg -> {
                        // Handle command failure
                    })
                    .build();
        }

        @Override
        public void preStart() {
            // Bind to the listening address
            getContext().getSystem().getIoT().tcp().bind(getSelf(), new InetSocketAddress(remoteAddress, remotePort));
        }
    }

    public static void main(String[] args) {
        ActorSystem system = ActorSystem.create("TcpDiscoverySystem");
        String remoteAddress = "127.0.0.1"; // Example remote address
        int remotePort = 8888; // Example remote port
        system.actorOf(Props.create(TcpDiscoveryActor.class, remoteAddress, remotePort), "TcpDiscoveryActor");
    }
}
