import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public class HashConcatenator {
    public static byte[] concatenateHashes(byte[] input) throws NoSuchAlgorithmException {
        MessageDigest md5Digest = MessageDigest.getInstance("MD5");
        MessageDigest md2Digest = MessageDigest.getInstance("MD2");

        byte[] md5Hash = md5Digest.digest(input);
        byte[] md2Hash = md2Digest.digest(input);

        byte[] concatenatedHashes = new byte[md5Hash.length + md2Hash.length];
        System.arraycopy(md5Hash, 0, concatenatedHashes, 0, md5Hash.length);
        System.arraycopy(md2Hash, 0, concatenatedHashes, md5Hash.length, md2Hash.length);

        return concatenatedHashes;
    }
}
