import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.Scanner;
import java.util.concurrent.ProcessBuilder;

public class CodeSigner {

    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java CodeSigner <file_to_sign> [<password>]");
            System.exit(1);
        }

        String fileToSign = args[0];
        String password = args.length > 1 ? args[1] : "";

        try {
            boolean result = signCode(fileToSign, password);
            System.out.println("Signing result: " + (result ? "Success" : "Failure"));
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }

    private static boolean signCode(String fileToSign, String password) throws IOException, InterruptedException {
        String jarSignerPath = "jarsigner"; // Adjust this if jarsigner is not in the PATH
        String keystorePath = "keystore.jks"; // Path to your keystore
        String alias = "alias"; // Your keystore alias

        ProcessBuilder processBuilder = new ProcessBuilder(jarSignerPath, "-keystore", keystorePath, "-storepass", password, fileToSign, alias);
        Process process = processBuilder.start();
        int exitCode = process.waitFor();

        // Optionally read the output/error streams
        String output = new String(Files.readAllBytes(Paths.get("output.txt")));
        String error = new String(Files.readAllBytes(Paths.get("error.txt")));

        if (exitCode != 0) {
            System.err.println("Error: " + error);
            return false;
        }
        return true;
    }
}
