public class SerializeDeserializeTest {
    public static void main(String[] args) {
        SampleObject obj = new SampleObject("Test", 123);
        long totalSerializationTime = 0;
        long totalDeserializationTime = 0;
        int totalSize = 0;

        for (int i = 0; i < 500; i++) {
            long startTime = System.nanoTime();
            byte[] serializedData = serialize(obj);
            long endTime = System.nanoTime();
            totalSerializationTime += (endTime - startTime);
            totalSize += serializedData.length;

            startTime = System.nanoTime();
            deserialize(serializedData);
            endTime = System.nanoTime();
            totalDeserializationTime += (endTime - startTime);
        }

        System.out.println("Total Serialization Time (ms): " + (totalSerializationTime / 1_000_000));
        System.out.println("Total Deserialization Time (ms): " + (totalDeserializationTime / 1_000_000));
        System.out.println("Average Serialized Size (bytes): " + (totalSize / 500));
    }

    private static byte[] serialize(SampleObject obj) {
        try (ByteArrayOutputStream bos = new ByteArrayOutputStream();
             ObjectOutputStream oos = new ObjectOutputStream(bos)) {
            oos.writeObject(obj);
            return bos.toByteArray();
        } catch (IOException e) {
            e.printStackTrace();
            return null;
        }
    }

    private static SampleObject deserialize(byte[] data) {
        try (ByteArrayInputStream bis = new ByteArrayInputStream(data);
             ObjectInputStream ois = new ObjectInputStream(bis)) {
            return (SampleObject) ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
            return null;
        }
    }
}
