import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.ObjectInputStream;
import java.io.ObjectOutputStream;
import java.util.HashMap;
import java.util.Map;

public class MapMerger {

    public static Map<String, Byte> mergeMaps(Map<String, String> stringMap, byte[] binaryData) throws IOException, ClassNotFoundException {
        Map<String, Byte> byteMap = deserializeBinaryData(binaryData);
        Map<String, Byte> mergedMap = new HashMap<>(byteMap);

        for (Map.Entry<String, String> entry : stringMap.entrySet()) {
            mergedMap.put(entry.getKey(), entry.getValue().getBytes()[0]); // Assuming single byte value
        }

        return mergedMap;
    }

    private static Map<String, Byte> deserializeBinaryData(byte[] data) throws IOException, ClassNotFoundException {
        try (ByteArrayInputStream bis = new ByteArrayInputStream(data);
             ObjectInputStream ois = new ObjectInputStream(bis)) {
            return (Map<String, Byte>) ois.readObject();
        }
    }
}
