```java
public class HashUtil {

    public static long getHashValue(String input, String hashFunction) {
        switch (hashFunction.toLowerCase()) {
            case "simple":
                return simpleHash(input);
            case "murmur":
                return murmurHash(input);
            default:
                throw new IllegalArgumentException("Unsupported hash function: " + hashFunction);
        }
    }

    private static long simpleHash(String input) {
        long hash = 0;
        for (char c : input.toCharArray()) {
            hash = (hash * 31) + c;
        }
        return hash;
    }

    private static long murmurHash(String input) {
        int len = input.length();
        long h = 0;
        for (int i = 0; i < len; i++) {
            h ^= (long) input.charAt(i);
            h *= 0x5bd1e995;
            h ^= h >>> 15;
            h *= 0x5bd1e995;
        }
        return h;
    }
}
