import java.io.File;
import java.io.FileInputStream;
import java.io.FileNotFoundException;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.List;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import javax.xml.transform.Source;
import javax.xml.transform.stream.StreamSource;
import javax.xml.transform.stream.StreamResult;
import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.TransformerException;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;
import org.xml.sax.SAXException;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;

public class DataExtractor {

    public static void main(String[] args) {
        if (args.length == 0) {
            System.out.println("No files provided.");
            return;
        }

        for (String filePath : args) {
            try {
                File file = new File(filePath);
                if (filePath.endsWith(".xml")) {
                    extractFromXML(file);
                } else if (filePath.endsWith(".sql")) {
                    extractFromSQL(file);
                } else {
                    System.out.println("Unsupported file format: " + filePath);
                }
            } catch (Exception e) {
                System.err.println("Error processing file: " + filePath + " - " + e.getMessage());
            }
        }
    }

    private static void extractFromXML(File file) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(file);
            NodeList nodes = document.getElementsByTagName("data");

            for (int i = 0; i < nodes.getLength(); i++) {
                System.out.println(nodes.item(i).getTextContent());
            }
        } catch (ParserConfigurationException | SAXException | IOException e) {
            System.err.println("Error parsing XML file: " + file.getName() + " - " + e.getMessage());
        }
    }

    private static void extractFromSQL(File file) {
        String url = "jdbc:sqlite:sample.db"; // Adjust database URL as needed
        try (Connection conn = DriverManager.getConnection(url);
             Statement stmt = conn.createStatement()) {

            List<String> sqlCommands = Files.readAllLines(Paths.get(file.getPath()));

            for (String sql : sqlCommands) {
                ResultSet rs = stmt.executeQuery(sql);
                while (rs.next()) {
                    // Assuming we are interested in the first column of the result set
                    System.out.println(rs.getString(1));
                }
                rs.close();
            }
        } catch (SQLException | IOException e) {
            System.err.println("Error processing SQL file: " + file.getName() + " - " + e.getMessage());
        }
    }
}
