import org.xml.sax.Attributes;
import org.xml.sax.SAXException;
import org.xml.sax.helpers.DefaultHandler;

import javax.xml.parsers.SAXParser;
import javax.xml.parsers.SAXParserFactory;
import java.io.File;
import java.util.HashMap;
import java.util.Map;

public class UniquePrefixExtractor {

    public static void main(String[] args) {
        String[] xmlFiles = {"file1.xml", "file2.xml", "file3.xml"}; // Add your XML file paths here
        FrequencyHandler frequencyHandler = new FrequencyHandler();

        try {
            SAXParserFactory factory = SAXParserFactory.newInstance();
            SAXParser saxParser = factory.newSAXParser();

            for (String xmlFile : xmlFiles) {
                saxParser.parse(new File(xmlFile), frequencyHandler);
            }

            frequencyHandler.printFrequencies();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    static class FrequencyHandler extends DefaultHandler {
        private final Map<String, Integer> prefixFrequency = new HashMap<>();

        @Override
        public void startElement(String uri, String localName, String qName, Attributes attributes) throws SAXException {
            String prefix = getPrefix(qName);
            if (prefix != null) {
                prefixFrequency.put(prefix, prefixFrequency.getOrDefault(prefix, 0) + 1);
            }
        }

        private String getPrefix(String qName) {
            int colonIndex = qName.indexOf(':');
            return (colonIndex != -1) ? qName.substring(0, colonIndex) : null;
        }

        public void printFrequencies() {
            System.out.println("Unique Prefix Frequencies:");
            for (Map.Entry<String, Integer> entry : prefixFrequency.entrySet()) {
                System.out.println(entry.getKey() + ": " + entry.getValue());
            }
        }
    }
}
