import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.Map;

public class HashGenerator {

    public static String generateHash(Map<String, String> paths, String moduleName, boolean createSymlinks, boolean createHeaderMap) {
        StringBuilder inputBuilder = new StringBuilder();
        inputBuilder.append(moduleName)
                    .append(createSymlinks)
                    .append(createHeaderMap);

        for (Map.Entry<String, String> entry : paths.entrySet()) {
            inputBuilder.append(entry.getKey()).append(entry.getValue());
        }

        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-1");
            byte[] hashBytes = digest.digest(inputBuilder.toString().getBytes(StandardCharsets.UTF_8));
            StringBuilder hashString = new StringBuilder();
            for (byte b : hashBytes) {
                hashString.append(String.format("%02x", b));
            }
            return hashString.toString();
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("SHA-1 algorithm not found", e);
        }
    }
}
