        if (parts.length != 2) {
            throw new IllegalArgumentException("Invalid number of coordinates");
        }

        double x = Double.parseDouble(parts[0].trim());
        double y = Double.parseDouble(parts[1].trim());

        assert Double.compare(x, expectedX) == 0 : "Expected X: " + expectedX + ", but got: " + x;
        assert Double.compare(y, expectedY) == 0 : "Expected Y: " + expectedY + ", but got: " + y;
