import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;

public class TokenGenerator {

    public String generateToken() {
        SecureRandom secureRandom = new SecureRandom();
        byte[] randomBytes = new byte[20]; // 20 bytes will produce a 40-character hex string
        secureRandom.nextBytes(randomBytes);

        try {
            MessageDigest messageDigest = MessageDigest.getInstance("SHA-1");
            byte[] hashedBytes = messageDigest.digest(randomBytes);
            StringBuilder token = new StringBuilder(8);
            for (int i = 0; i < 4; i++) {
                int byteValue = hashedBytes[i] & 0xFF; // Convert byte to int
                token.append(String.format("%02x", byteValue)); // Convert to hex
            }
            return token.toString();
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("SHA-1 algorithm not found", e);
        }
    }
}
