import java.io.InputStream;
import java.io.OutputStream;
import java.io.IOException;
import java.util.Optional;

public class CommandExecutor {

    public static int executeCommand(String[] commands, InputStream inputStream, OutputStream outputStream, Optional<Long> timeout) {
        ProcessBuilder processBuilder = new ProcessBuilder(commands);
        processBuilder.redirectInput(inputStream);
        processBuilder.redirectOutput(outputStream);
        Process process = null;
        try {
            process = processBuilder.start();
            if (timeout.isPresent()) {
                return process.waitFor(timeout.get(), java.util.concurrent.TimeUnit.MILLISECONDS) ? process.exitValue() : -1;
            } else {
                process.waitFor();
                return process.exitValue();
            }
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
            return -1;
        } finally {
            if (process != null) {
                process.destroy();
            }
        }
    }
}
