import java.io.*;
import java.util.*;

class State implements Serializable {
    private static final long serialVersionUID = 1L;
    private final String name;
    private final Map<Character, List<State>> transitions = new HashMap<>();

    public State(String name) {
        this.name = name;
    }

    public String getName() {
        return name;
    }

    public void addTransition(char input, State state) {
        transitions.computeIfAbsent(input, k -> new ArrayList<>()).add(state);
    }

    public List<State> getTransitions(char input) {
        return transitions.getOrDefault(input, new ArrayList<>());
    }
}

class NFA implements Serializable {
    private static final long serialVersionUID = 1L;
    private final State startState;
    private final Set<State> acceptStates = new HashSet<>();

    public NFA(int windowLength) {
        startState = new State("start");
        State currentState = startState;

        for (int i = 0; i < windowLength; i++) {
            State newState = new State("state" + (i + 1));
            currentState.addTransition('a', newState);
            currentState = newState;
        }

        acceptStates.add(currentState);
    }

    public State getStartState() {
        return startState;
    }

    public Set<State> getAcceptStates() {
        return acceptStates;
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (!(obj instanceof NFA)) return false;
        NFA other = (NFA) obj;
        return Objects.equals(startState, other.startState) && Objects.equals(acceptStates, other.acceptStates);
    }
}

public class NFASerialization {
    public static NFA createNFA(int windowLength) {
        return new NFA(windowLength);
    }

    public static byte[] serializeNFA(NFA nfa) throws IOException {
        try (ByteArrayOutputStream bos = new ByteArrayOutputStream(); ObjectOutputStream out = new ObjectOutputStream(bos)) {
            out.writeObject(nfa);
            return bos.toByteArray();
        }
    }

    public static NFA deserializeNFA(byte[] data) throws IOException, ClassNotFoundException {
        try (ByteArrayInputStream bis = new ByteArrayInputStream(data); ObjectInputStream in = new ObjectInputStream(bis)) {
            return (NFA) in.readObject();
        }
    }

    public static void main(String[] args) {
        try {
            int windowLength = 5;
            NFA originalNFA = createNFA(windowLength);
            byte[] serializedNFA = serializeNFA(originalNFA);
            NFA deserializedNFA = deserializeNFA(serializedNFA);

            System.out.println("Original NFA equals Deserialized NFA: " + originalNFA.equals(deserializedNFA));
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}
