import static org.junit.Assert.assertTrue;
import static org.junit.Assert.assertFalse;

public class CharacterTest {

    public boolean testIsJavaLetter(char ch) {
        boolean result = Character.isJavaLetter(ch);

        if (Character.isLetter(ch)) {
            assertTrue("Expected " + ch + " to be a Java letter", result);
        } else {
            assertFalse("Expected " + ch + " not to be a Java letter", result);
        }

        return result;
    }

    public void runTests() {
        testIsJavaLetter('a'); // true
        testIsJavaLetter('Z'); // true
        testIsJavaLetter('1'); // false
        testIsJavaLetter('$'); // false
        testIsJavaLetter('_'); // true
        testIsJavaLetter('\u200C'); // true (Zero Width Non-Joiner)
        testIsJavaLetter('\u200D'); // false (Zero Width Joiner)
        testIsJavaLetter(' '); // false
        testIsJavaLetter('\n'); // false
    }
}
