import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public class MessageEncryptor {

    public static String encryptMessage(String message, String encodingScheme, boolean toUpperCase) {
        try {
            MessageDigest md = MessageDigest.getInstance("MD5");
            byte[] messageBytes = message.getBytes(encodingScheme);
            byte[] digest = md.digest(messageBytes);
            StringBuilder hexString = new StringBuilder();

            for (byte b : digest) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) hexString.append('0');
                hexString.append(hex);
            }

            String encryptedMessage = hexString.toString();
            return toUpperCase ? encryptedMessage.toUpperCase() : encryptedMessage;
        } catch (NoSuchAlgorithmException | java.io.UnsupportedEncodingException e) {
            throw new RuntimeException(e);
        }
    }
}
