import javax.swing.*;
import java.awt.event.ActionEvent;
import java.awt.event.ActionListener;
import java.io.File;
import java.io.IOException;

public class OpenFileOrDirectory {

    public static void main(String[] args) {
        JButton button = new JButton("Open File/Directory");
        button.addActionListener(new ActionListener() {
            @Override
            public void actionPerformed(ActionEvent e) {
                openFileOrDirectory();
            }
        });

        JFrame frame = new JFrame("Open File/Directory");
        frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        frame.getContentPane().add(button);
        frame.setSize(300, 200);
        frame.setVisible(true);
    }

    public static void openFileOrDirectory() {
        JFileChooser fileChooser = new JFileChooser();
        fileChooser.setDialogTitle("Select a file or directory");
        fileChooser.setFileSelectionMode(JFileChooser.FILES_AND_DIRECTORIES);
        int userSelection = fileChooser.showOpenDialog(null);

        if (userSelection == JFileChooser.APPROVE_OPTION) {
            File fileToOpen = fileChooser.getSelectedFile();
            try {
                if (System.getProperty("os.name").toLowerCase().contains("win")) {
                    // Windows
                    new ProcessBuilder("cmd", "/c", "start", "\"\"", fileToOpen.getAbsolutePath()).start();
                } else {
                    // macOS or Linux
                    String command = (System.getProperty("os.name").toLowerCase().contains("mac")) ? "open" : "xdg-open";
                    new ProcessBuilder(command, fileToOpen.getAbsolutePath()).start();
                }
            } catch (IOException ex) {
                JOptionPane.showMessageDialog(null, "Error opening file: " + ex.getMessage());
            }
        }
    }
}
