import org.apache.http.HttpResponse;
import org.apache.http.client.methods.HttpGet;
import org.apache.http.impl.client.BasicCredentialsProvider;
import org.apache.http.impl.client.CloseableHttpClient;
import org.apache.http.impl.client.HttpClientBuilder;
import org.apache.http.conn.ssl.SSLConnectionSocketFactory;
import org.apache.http.conn.socket.PlainConnectionSocketFactory;
import org.apache.http.conn.ssl.NoopHostnameVerifier;
import org.apache.http.impl.conn.PoolingHttpClientConnectionManager;
import org.apache.http.conn.ssl.SSLContexts;
import org.apache.http.config.Registry;
import org.apache.http.config.RegistryBuilder;
import org.apache.http.util.EntityUtils;
import org.apache.http.auth.UsernamePasswordCredentials;
import org.apache.http.auth.AuthScope;
import org.apache.http.client.config.RequestConfig;
import org.apache.http.HttpHost;

import javax.net.ssl.SSLContext;

public class HttpClientExample {

    public static void main(String[] args) throws Exception {
        // Proxy configuration
        HttpHost proxy = new HttpHost("proxy.example.com", 8080);

        // Credentials provider
        BasicCredentialsProvider credsProvider = new BasicCredentialsProvider();
        credsProvider.setCredentials(
            new AuthScope(proxy),
            new UsernamePasswordCredentials("username", "password")
        );

        // SSL context
        SSLContext sslContext = SSLContexts.custom().loadTrustMaterial((chain, authType) -> true).build();
        SSLConnectionSocketFactory sslSocketFactory = new SSLConnectionSocketFactory(sslContext, NoopHostnameVerifier.INSTANCE);
        PlainConnectionSocketFactory plainSocketFactory = new PlainConnectionSocketFactory();

        // Registry for socket factories
        Registry<org.apache.http.conn.socket.ConnectionSocketFactory> socketFactoryRegistry = RegistryBuilder.<org.apache.http.conn.socket.ConnectionSocketFactory>create()
                .register("http", plainSocketFactory)
                .register("https", sslSocketFactory)
                .build();

        // Connection manager
        PoolingHttpClientConnectionManager connectionManager = new PoolingHttpClientConnectionManager(socketFactoryRegistry);

        // Request configuration
        RequestConfig requestConfig = RequestConfig.custom()
                .setProxy(proxy)
                .build();

        // Create CloseableHttpClient
        CloseableHttpClient httpClient = HttpClientBuilder.create()
                .setDefaultCredentialsProvider(credsProvider)
                .setDefaultRequestConfig(requestConfig)
                .setConnectionManager(connectionManager)
                .build();

        // Execute GET request
        HttpGet httpGet = new HttpGet("https://example.com");
        HttpResponse response = httpClient.execute(httpGet);
        String responseString = EntityUtils.toString(response.getEntity());

        // Print the response
        System.out.println(responseString);

        // Close the client
        httpClient.close();
    }
}
