import java.util.HashSet;
import java.util.List;
import java.util.Set;

public class GraphDatabase {

    private Set<String> existingEdges = new HashSet<>();

    public void createEdges(List<VertexBuilder> vertexBuilders) {
        for (int i = 0; i < vertexBuilders.size(); i++) {
            for (int j = i + 1; j < vertexBuilders.size(); j++) {
                String edge = createEdgeHash(vertexBuilders.get(i), vertexBuilders.get(j));
                if (!existingEdges.contains(edge)) {
                    // Logic to create edge in the graph database
                    existingEdges.add(edge);
                }
            }
        }
    }

    private String createEdgeHash(VertexBuilder vertex1, VertexBuilder vertex2) {
        return vertex1.getId() + "-" + vertex2.getId();
    }

    public static class VertexBuilder {
        private String id;

        public VertexBuilder(String id) {
            this.id = id;
        }

        public String getId() {
            return id;
        }
    }
}
