import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.HashMap;
import java.util.Map;

public class HashGenerator {
    private static final Map<String, String> algorithms = new HashMap<>();

    static {
        algorithms.put("MD5", "MD5");
        algorithms.put("SHA-1", "SHA-1");
        algorithms.put("SHA-256", "SHA-256");
        algorithms.put("SHA-384", "SHA-384");
        algorithms.put("SHA-512", "SHA-512");
    }

    public static String generateHash(String input, String algorithm) throws NoSuchAlgorithmException {
        if (!algorithms.containsKey(algorithm)) {
            throw new IllegalArgumentException("Unsupported algorithm: " + algorithm);
        }
        MessageDigest digest = MessageDigest.getInstance(algorithms.get(algorithm));
        byte[] hashBytes = digest.digest(input.getBytes());
        StringBuilder hashString = new StringBuilder();
        for (byte b : hashBytes) {
            hashString.append(String.format("%02x", b));
        }
        return hashString.toString();
    }

    public static void main(String[] args) {
        try {
            String input = "Hello, World!";
            String algorithm = "SHA-256";
            String hashValue = generateHash(input, algorithm);
            System.out.println("Hash value: " + hashValue);
        } catch (NoSuchAlgorithmException e) {
            e.printStackTrace();
        } catch (IllegalArgumentException e) {
            System.out.println(e.getMessage());
        }
    }
}
