import org.apache.commons.codec.digest.DigestUtils;
import java.util.ArrayList;
import java.util.List;

class ServerGroup {
    private String id;
    private List<String> backendServers;

    public ServerGroup(String id) {
        this.id = id;
        this.backendServers = new ArrayList<>();
    }

    public String getId() {
        return id;
    }

    public List<String> getBackendServers() {
        return backendServers;
    }
}

public class ServerGroupManager {
    private List<ServerGroup> serverGroups;

    public ServerGroupManager() {
        this.serverGroups = new ArrayList<>();
    }

    public String createServerGroup(List<String> strings) {
        String concatenatedString = String.join("", strings);
        String md5Hash = DigestUtils.md5Hex(concatenatedString);

        for (ServerGroup group : serverGroups) {
            if (group.getId().equals(md5Hash)) {
                return md5Hash; // Server group already exists
            }
        }

        ServerGroup newGroup = new ServerGroup(md5Hash);
        serverGroups.add(newGroup);
        return md5Hash;
    }
}
