import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

class DataSegment {
    LocalDateTime start;
    LocalDateTime end;

    public DataSegment(LocalDateTime start, LocalDateTime end) {
        this.start = start;
        this.end = end;
    }
}

public class IntervalMerger {

    public static String mergeIntervals(List<DataSegment> segments) {
        if (segments.isEmpty()) {
            return "";
        }

        // Sort segments by start time
        segments.sort((a, b) -> a.start.compareTo(b.start));

        LocalDateTime mergedStart = segments.get(0).start;
        LocalDateTime mergedEnd = segments.get(0).end;

        for (DataSegment segment : segments) {
            if (segment.start.isBefore(mergedEnd) || segment.start.isEqual(mergedEnd)) {
                mergedEnd = segment.end.isAfter(mergedEnd) ? segment.end : mergedEnd;
            } else {
                mergedStart = segment.start;
                mergedEnd = segment.end;
            }
        }

        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd'T'HH:mm:ss");
        return mergedStart.format(formatter) + "-" + mergedEnd.format(formatter);
    }
}
