import java.net.InetAddress;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public class NodeIdentifier {

    public static long generateNodeId() {
        try {
            // Get the local host's address
            InetAddress localHost = InetAddress.getLocalHost();
            byte[] addressBytes = localHost.getAddress();

            // Create MD5 hash of the address
            MessageDigest md = MessageDigest.getInstance("MD5");
            byte[] hash = md.digest(addressBytes);

            // Combine the lower 8 bytes of the hash into a long
            long nodeId = 0;
            for (int i = 0; i < 8; i++) {
                nodeId <<= 8;
                nodeId |= (hash[i] & 0xFF);
            }

            // Ensure upper 8 bits are set to 0
            return nodeId & 0xFFFFFFFFFFFFFF00L;
        } catch (Exception e) {
            throw new RuntimeException("Failed to generate node ID", e);
        }
    }
}
