import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;

public class AesKeyGenerator {

    public static Object[] generateAesKeyAndCipher(int keySize, String paddingScheme) throws NoSuchAlgorithmException, Exception {
        KeyGenerator keyGenerator = KeyGenerator.getInstance("AES");
        keyGenerator.init(keySize, new SecureRandom());
        SecretKey secretKey = keyGenerator.generateKey();

        Cipher cipher = Cipher.getInstance("AES/" + paddingScheme);
        cipher.init(Cipher.ENCRYPT_MODE, secretKey);

        return new Object[]{secretKey, cipher};
    }
}
