import java.nio.file.Files;
import java.util.Random;
import java.util.Scanner;

public class Main {
    private static final int BYTE_ARRAY_SIZE = 8192; // 8KB

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter the flag (true/false):");
        boolean flag = Boolean.parseBoolean(scanner.nextLine());

        if (flag) {
            printFakeStackTrace();
            printRandomBytes();
        } else {
            System.out.println("Work is being done...");
            File file = new File("example.txt");
            performWork(file);
        }
    }

    private static void printFakeStackTrace() {
        System.out.println("Exception in thread \"main\" java.lang.RuntimeException: Fake stack trace");
        System.out.println("\tat Main.main(Main.java:10)");
        System.out.println("\tat java.base/jdk.internal.reflect.NativeMethodAccessorImpl.invoke0(Native Method)");
        System.out.println("\tat java.base/jdk.internal.reflect.NativeMethodAccessorImpl.invoke(NativeMethodAccessorImpl.java:62)");
        System.out.println("\tat java.base/jdk.internal.reflect.DelegatingMethodAccessorImpl.invoke(DelegatingMethodAccessorImpl.java:43)");
        System.out.println("\tat java.base/java.lang.reflect.Method.invoke(Method.java:566)");
        System.out.println("\tat java.base/java.util.concurrent.ForkJoinTask$AdaptedRunnableAction.exec(ForkJoinTask.java:1431)");
        System.out.println("\tat java.base/java.util.concurrent.ForkJoinTask.doExec(ForkJoinTask.java:295)");
        System.out.println("\tat java.base/java.util.concurrent.ForkJoinPool$WorkQueue.topLevelExec(ForkJoinPool.java:1005)");
        System.out.println("\tat java.base/java.util.concurrent.ForkJoinPool.scan(ForkJoinPool.java:1656)");
    }

    private static void printRandomBytes() {
        byte[] randomBytes = new byte[BYTE_ARRAY_SIZE];
        new Random().nextBytes(randomBytes);
        System.out.println("Random bytes: " + java.util.Base64.getEncoder().encodeToString(randomBytes));
    }

    private static void performWork(File file) {
        try {
            if (!file.exists()) {
                file.createNewFile();
            }
            Files.writeString(file.toPath(), "Work completed successfully!");
            System.out.println("File written: " + file.getAbsolutePath());
        } catch (IOException e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }
}
