```java
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.Arrays;

public class MGF1 {

    public static byte[] generateMask(int maskLen, byte[] seed, String digestAlgorithm) throws NoSuchAlgorithmException {
        MessageDigest digest = MessageDigest.getInstance(digestAlgorithm);
        int hLen = digest.getDigestLength();
        int numOfHashes = (int) Math.ceil((double) maskLen / hLen);
        byte[] mask = new byte[maskLen];
        byte[] C = new byte[4];

        for (int i = 0; i < numOfHashes; i++) {
            C[0] = (byte) (i >> 24);
            C[1] = (byte) (i >> 16);
            C[2] = (byte) (i >> 8);
            C[3] = (byte) (i);

            digest.update(seed);
            digest.update(C);
            byte[] hash = digest.digest();

            int offset = i * hLen;
            int length = Math.min(hLen, maskLen - offset);
            System.arraycopy(hash, 0, mask, offset, length);
        }

        return mask;
    }
}
