public class HashUtil {
    private static final String PREFIX = "prefix:";

    public static String generateHashedString(String input, String namespace) {
        try {
            String key = sha1Hash(input);
            String nsHash = sha1Hash(namespace);
            return PREFIX + nsHash + ":" + key;
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("SHA-1 algorithm not found", e);
        }
    }

    private static String sha1Hash(String value) throws NoSuchAlgorithmException {
        MessageDigest digest = MessageDigest.getInstance("SHA-1");
        byte[] hashBytes = digest.digest(value.getBytes());
        StringBuilder hexString = new StringBuilder();
        for (byte b : hashBytes) {
            String hex = Integer.toHexString(0xff & b);
            if (hex.length() == 1) hexString.append('0');
            hexString.append(hex);
        }
        return hexString.toString();
    }
}
