import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class ConfigDisplayServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String configFilePath = request.getParameter("configPath");
        response.setContentType("text/plain");

        try (BufferedReader reader = new BufferedReader(new FileReader(configFilePath))) {
            String line;
            StringBuilder fileContents = new StringBuilder();
            while ((line = reader.readLine()) != null) {
                fileContents.append(line).append("\n");
            }
            response.getWriter().write(fileContents.toString());
        } catch (IOException e) {
            response.getWriter().write("Error reading configuration file.");
            e.printStackTrace(); // Log the error details
        }
    }
}
