const idStore = new Map();

/**
 * Generates a unique identifier for a given key using a combination of a
 * random postfix and a Symbol. It maintains a shared store of keys
 * and their corresponding identifiers.
 *
 * @param {any} key - The key for which to generate or retrieve an identifier.
 * @returns {Symbol} The unique identifier for the given key.
 */
function getUniqueId(key) {
  if (idStore.has(key)) {
    return idStore.get(key);
  }

  const randomPostfix = Math.random().toString(36).substring(2, 9);
  const uniqueIdentifier = Symbol(`${String(key)}_${randomPostfix}`);

  idStore.set(key, uniqueIdentifier);

  return uniqueIdentifier;
}
