}

/**
 * Generates a random position within a defined rectangular area.
 * @param {number} minX - The minimum x-coordinate of the area.
 * @param {number} minY - The minimum y-coordinate of the area.
 * @param {number} maxX - The maximum x-coordinate of the area.
 * @param {number} maxY - The maximum y-coordinate of the area.
 * @returns {Vector} A new Vector object with random x and y coordinates.
 */
function generateRandomPosition(minX, minY, maxX, maxY) {
    if (minX > maxX || minY > maxY) {
        throw new Error("Minimum coordinates cannot be greater than maximum coordinates.");
    }

    const randomX = Math.random() * (maxX - minX) + minX;
    const randomY = Math.random() * (maxY - minY) + minY;

    return new Vector(randomX, randomY);
}
