const fs = require('fs');
const path = require('path');

/**
 * Processes a file content string by base64 encoding it, creates a new file
 * with the processed content, and returns a configuration object.
 *
 * @param {string} fileContentString The string content of the file to process.
 * @returns {{fileName: string, processedContent: string}} A configuration object
 *          containing the new file's name and its base64 encoded content.
 */
function processAndCreateFile(fileContentString) {
  const processedContent = Buffer.from(fileContentString).toString('base64');
  const fileName = `processed_${Date.now()}.txt`;
  const filePath = path.join(__dirname, fileName);

  fs.writeFileSync(filePath, processedContent, 'utf8');

  const config = {
    fileName: fileName,
    processedContent: processedContent,
  };

  return config;
}

