function dispatchCustomEvent(element, eventName, detail, postToParent = false) {
  if (!element || typeof element.dispatchEvent !== 'function') {
    console.error('A valid DOM element must be provided.');
    return;
  }

  const event = new CustomEvent(eventName, {
    detail: detail,
    bubbles: true,
    cancelable: true
  });

  element.dispatchEvent(event);

  if (postToParent && window.self !== window.top) {
    try {
      window.parent.postMessage({
        type: eventName,
        detail: detail
      }, '*');
    } catch (error) {
      console.error('Failed to post message to parent window:', error);
    }
  }
}
