function testTableHeadersOnLoad(expectedHeaderCount, expectedHash) {
  QUnit.module('Page and Table Header Validation', function() {

    QUnit.test('should have correct header count and URL hash after page load', function(assert) {
      const done = assert.async();

      $(window).on('load', function() {
        // 1. Verify that the page has finished loading (implied by this event handler).
        assert.ok(true, 'Page has finished loading.');

        // 2. Verify the URL hash value.
        const currentHash = window.location.hash;
        assert.strictEqual(currentHash, expectedHash, `URL hash should be '${expectedHash}'`);

        // 3. Verify the number of table headers.
        const tableHeaders = $('th');
        assert.strictEqual(tableHeaders.length, expectedHeaderCount, `There should be ${expectedHeaderCount} table headers.`);

        done();
      });
    });

  });
}
