        credentials.get('access_key_id'),
        credentials.get('access_key_secret'),
        config.get('region_id')
    )

    self.vpc_id = config.get('vpc_id')
    self.vswitch_ids = config.get('vswitch_ids', [])
    self.instance_type = config.get('instance_type')
    self.security_group_id = config.get('security_group_id')
    self.key_pair_name = config.get('key_pair_name')

    # Random offset for trying availability zones round-robin
    self.vswitch_offset = random.randint(0, max(len(self.vswitch_ids) - 1, 0))

    # Cache for tags
    self._instance_tags_cache = {}
    self._pending_instance_tags = {}
    self._pending_instance_names = {}

    # Batch update tracking
    self._batch_start = None
    self._batch_vpc_tags = {}
    self._batch_instance_tags = {}

    # Default tags
    self.default_tags = config.get('tags', {})
    if not isinstance(self.default_tags, dict):
        self.default_tags = {}

    # Subnet info
    self.subnets = {}
    self.subnet_azs = {}
    if self.vswitch_ids:
        for vswitch_id in self.vswitch_ids:
            self.subnets[vswitch_id] = None
            self.subnet_azs[vswitch_id] = None
