private void compareNumericFields(Document doc1, Document doc2, String fieldName) throws IOException {
    NumericDocValues values1 = doc1.getNumericField(fieldName).load();
    NumericDocValues values2 = doc2.getNumericField(fieldName).load();

    // Check number of values matches
    long valueCount1 = values1.count();
    long valueCount2 = values2.count();
    assertThat("Number of values in " + fieldName + " should match", 
               valueCount1, equalTo(valueCount2));

    // Compare each value
    for (int i = 0; i < valueCount1; i++) {
        long value1 = values1.nextValue();
        long value2 = values2.nextValue();
        assertThat("Values at position " + i + " in " + fieldName + " should match",
                   value1, equalTo(value2));
    }
}
