import com.alibaba.otter.canal.client.CanalConnector;
import com.alibaba.otter.canal.client.CanalConnectors;
import com.alibaba.otter.canal.protocol.Message;
import com.alibaba.otter.canal.protocol.CanalEntry.Entry;
import com.alibaba.otter.canal.protocol.CanalEntry.EntryType;
import com.alibaba.otter.canal.protocol.CanalEntry.RowChange;

public class CanalClient {
    private CanalConnector connector;
    private String hostname;
    private int port;
    private String destination;
    private String username;
    private String password;
    private int batchSize;

    public CanalClient(String hostname, int port, String destination, String username, String password, int batchSize) {
        this.hostname = hostname;
        this.port = port;
        this.destination = destination;
        this.username = username;
        this.password = password;
        this.batchSize = batchSize;
    }

    public void connect() {
        connector = CanalConnectors.newSingleConnector(
            new InetSocketAddress(hostname, port),
            destination,
            username,
            password
        );
        connector.connect();
        connector.subscribe("");
        connector.rollback();
    }

    public void process() {
        try {
            while (true) {
                Message message = connector.getWithoutAck(batchSize);
                long batchId = message.getId();
                int size = message.getEntries().size();

                if (batchId == -1 || size == 0) {
                    try {
                        Thread.sleep(1000);
                    } catch (InterruptedException e) {
                        break;
                    }
                } else {
                    processEntries(message.getEntries());
                    connector.ack(batchId);
                }
            }
        } finally {
            disconnect();
        }
    }

    private void processEntries(List<Entry> entries) {
        for (Entry entry : entries) {
            if (entry.getEntryType() == EntryType.TRANSACTIONBEGIN ||
                entry.getEntryType() == EntryType.TRANSACTIONEND) {
                continue;
            }

            try {
                RowChange rowChange = RowChange.parseFrom(entry.getStoreValue());
                // Process row change here
                System.out.println("Change Type: " + rowChange.getEventType());
                System.out.println("Schema: " + entry.getHeader().getSchemaName());
                System.out.println("Table: " + entry.getHeader().getTableName());
            } catch (Exception e) {
                throw new RuntimeException("Error parsing entry", e);
            }
        }
    }

    public void disconnect() {
        if (connector != null) {
            connector.disconnect();
        }
    }

    public static void main(String[] args) {
        CanalClient client = new CanalClient(
            "localhost",
            11111,
            "example",
            "",
            "",
            1000
        );
        client.connect();
        client.process();
    }
}
