def conditional_import(module_name):
    if sys.version_info < (3, 0):
        try:
            return __import__(module_name)
        except Exception as e:
            custom_exception_handler(e)
    else:
        try:
            return __import__(module_name)
        except Exception as e:
            custom_exception_handler(e)
