 import zmq
import threading
import os

def start_zmq_server(bind_address="tcp://127.0.0.1:0"):
    context = zmq.Context()
    socket = context.socket(zmq.REP)
    socket.bind(bind_address)
    server_address = socket.last_endpoint
    if isinstance(server_address, bytes):
        server_address = server_address.decode('utf-8')

    shared_data = {}
    data_condition = threading.Condition()

    def server_loop():
        while True:
            try:
                message = socket.recv_json()
                with data_condition:
                    if isinstance(message, dict):
                        shared_data.update(message)
                    else:
                        shared_data['last_message'] = message
                    data_condition.notify_all()
                socket.send_json({"status": "received"})
            except zmq.ZMQError:
                break
            except Exception:
                socket.send_json({"status": "error"})

    server_thread = threading.Thread(target=server_loop, daemon=True)
    server_thread.start()
    os.environ["ZMQ_SERVER_ADDRESS"] = server_address

    return context, socket, shared_data, data_condition, server_thread

