import json
from typing import Dict, Callable, Any

class JSONBase:
    _factories: Dict[str, Callable[..., 'JSONBase']] = {}

    def __init__(self, **kwargs):
        for key, value in kwargs.items():
            setattr(self, key, value)
        self._type_id: str = None

    def to_json(self) -> str:
        data = {k: v for k, v in self.__dict__.items() if not k.startswith('_')}
        if self._type_id is not None:
            data['__type__'] = self._type_id
        return json.dumps(data)

    @classmethod
    def from_json(cls, json_str: str) -> 'JSONBase':
        data = json.loads(json_str)
        type_id = data.pop('__type__', None)

        if type_id and type_id in cls._factories:
            instance = cls._factories[type_id](**data)
            instance._type_id = type_id
            return instance

        instance = cls(**data)
        return instance

    @classmethod
    def register_factory(cls, id: str, factory: Callable[..., 'JSONBase']) -> None:
        cls._factories[id] = factory

    @classmethod
    def create_instance(cls, id: str, *args, **kwargs) -> 'JSONBase':
        if id not in cls._factories:
            raise KeyError(f"No factory registered for ID: {id}")
        instance = cls._factories[id](*args, **kwargs)
        instance._type_id = id
        return instance

def add_factory(id: str, factory: Callable[..., JSONBase]) -> None:
    JSONBase.register_factory(id, factory)

def create_instance(id: str, *args, **kwargs) -> JSONBase:
    return JSONBase.create_instance(id, *args, **kwargs)
