import random
import sys
import math

def random_sample(population, n_samples=1, with_replacement=False, num_std_devs=3):
    if n_samples < 0:
        raise ValueError("Number of samples cannot be negative")

    if not population:
        return []

    max_samples = int(sys.maxsize + num_std_devs * math.sqrt(sys.maxsize))
    if n_samples > max_samples:
        raise ValueError("Number of samples exceeds calculated maximum")

    if with_replacement:
        return [random.choice(population) for _ in range(n_samples)]
    else:
        if n_samples > len(population):
            raise ValueError("Sample size exceeds population size")
        temp_pop = list(population)
        random.shuffle(temp_pop)
        return temp_pop[:n_samples]
