 ```python
import threading
import time
import json
from http.server import HTTPServer, BaseHTTPRequestHandler
from urllib.parse import urlparse
from typing import Dict, Any, Optional, Tuple


class MockHandler(BaseHTTPRequestHandler):
    def __init__(self, routes: Dict, *args, **kwargs):
        self.routes = routes
        super().__init__(*args, **kwargs)

    def do_GET(self):
        self._handle('GET')

    def do_POST(self):
        self._handle('POST')

    def do_PUT(self):
        self._handle('PUT')

    def do_DELETE(self):
        self._handle('DELETE')

    def _handle(self, method: str):
        parsed = urlparse(self.path)
        key = (method, parsed.path)

        if key in self.routes:
            config = self.routes[key]
            status = config.get('status', 200)
            body = config.get('body', '')
            headers = config.get('headers', {})

            self.send_response(status)
            for k, v in headers.items():
                self.send_header(k, v)

            if isinstance(body, dict):
                self.send_header('Content-Type', 'application/json')
                body = json.dumps(body).encode('utf-8')
            else:
                body = str(body).encode('utf-8')

            self.send_header('Content-Length', len(body))
            self.end_headers()
            self.wfile.write(body)
        else:
            self.send_response(404)
            self.end_headers()
            self.wfile.write(b'Not Found')

    def log_message(self, format, *args):
        pass


class MockServer:
    def __init__(self, port: int = 0, host: str = '127.0.0.1'):
        self.port = port
        self.host = host
        self.routes: Dict[Tuple[str, str], Dict[str, Any]] = {}
        self._server: Optional[HTTPServer] = None
        self._thread: Optional[threading.Thread] = None
        self._running = False

    def add_route(self, method: str, path: str, status: int = 200, body: Any = '', headers: Optional[Dict] = None):
        self.routes[(method.upper(), path)] = {
            'status': status,
            'body': body,
            'headers': headers or {}
        }

    def start(self):
        def handler_factory(*args, **kwargs):
            return MockHandler(self.routes, *args, **kwargs)

        self._server = HTTPServer((self.host, self.port), handler_factory)
        if self.port == 0:
            self.port = self._server.server_address[1]

        self._thread = threading.Thread(target=self._server.serve_forever, daemon=True)
        self._thread.start()
        self._running = True
        time.sleep(0.1)

    def stop(self):
        if self._server:
            self._server.shutdown()
            self._server.server_close()
            self._running = False

    def url(self) -> str:
        return f"http://{self.host}:{self.port}"

    def is_running(self) -> bool:
        return self._running

    def __enter__(self):
        self.start()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.stop()


def create_mock_server(port: int = 0, routes: Optional[Dict] = None) -> MockServer:
    """
    Creates and starts a live mock HTTP server for testing.

    Args:
        port: Port to listen on (0 for auto-assign)
        routes: Dict mapping (method, path) tuples to response dicts with 
                'status', 'body', and optional 'headers'

    Returns:
        MockServer instance that can be controlled via start/stop or context manager
    """
    server = MockServer(port=port)

    if routes:
        for (method, path), response in routes.items():
            server.add_route(method, path, **response)

    server.start()
    return server
```

