import networkx as nx
import numpy as np
import matplotlib.pyplot as plt
from hiveplot import HivePlot

def generate_random_hive_graph(n_nodes, edge_density, output_file="hive_plot.pdf", seed=None):
    if seed is not None:
        np.random.seed(seed)

    G = nx.erdos_renyi_graph(n_nodes, edge_density, seed=seed)

    node_types = ['A', 'B', 'C']
    for node in G.nodes():
        G.nodes[node]['type'] = np.random.choice(node_types)

    for u, v in G.edges():
        G.edges[u, v]['weight'] = np.random.uniform(0.1, 1.0)

    nodes = {}
    node_positions = {}
    for nt in node_types:
        nodes[nt] = [n for n, d in G.nodes(data=True) if d['type'] == nt]
        node_positions[nt] = {n: G.degree(n) for n in nodes[nt]}

    edges = {}
    for u, v in G.edges():
        t1 = G.nodes[u]['type']
        t2 = G.nodes[v]['type']
        key = (t1, t2)
        if key not in edges:
            edges[key] = []
        edges[key].append((u, v))

    h = HivePlot(nodes, edges, node_positions, node_size=3)
    h.draw()

    plt.savefig(output_file, format='pdf', bbox_inches='tight')
    plt.close()

if __name__ == "__main__":
    generate_random_hive_graph(30, 0.2, "random_graph.pdf")
