```python
import requests
import math
import os

def download_file_in_parts(url, max_part_size, min_part_size=1024*1024, max_parts=100, output_path=None):
    if output_path is None:
        output_path = url.split('/')[-1] or 'downloaded_file'

    head_resp = requests.head(url, allow_redirects=True)
    head_resp.raise_for_status()

    total_size = int(head_resp.headers.get('content-length', 0))
    accept_ranges = head_resp.headers.get('accept-ranges', 'none')

    if total_size == 0:
        with requests.get(url, stream=True) as r:
            r.raise_for_status()
            with open(output_path, 'wb') as f:
                for chunk in r.iter_content(chunk_size=8192):
                    if chunk:
                        f.write(chunk)
        return {'total_size': None, 'num_parts': 1, 'part_size': None, 'output_path': output_path}

    if accept_ranges != 'bytes':
        with requests.get(url, stream=True) as r:
            r.raise_for_status()
            with open(output_path, 'wb') as f:
                for chunk in r.iter_content(chunk_size=8192):
                    if chunk:
                        f.write(chunk)
        return {'total_size': total_size, 'num_parts': 1, 'part_size': total_size, 'output_path': output_path}

    num_parts = math.ceil(total_size / max_part_size)
    part_size = max_part_size

    if num_parts > max_parts:
        part_size = math.ceil(total_size / max_parts)
        num_parts = max_parts

    if part_size < min_part_size:
        adjusted_num_parts = math.ceil(total_size / min_part_size)
        if adjusted_num_parts > max_parts:
            raise ValueError(f"Cannot satisfy constraints: min_part_size={min_part_size} requires {adjusted_num_parts} parts, but max_parts={max_parts}")
        part_size = min_part_size
        num_parts = adjusted_num_parts

    with open(output_path, 'wb') as f:
        for i in range(num_parts):
            start = i * part_size
            end = min(start + part_size - 1, total_size - 1)

            headers = {'Range': f'bytes={start}-{end}'}
            with requests.get(url, headers=headers, stream=True) as r:
                r.raise_for_status()
                for chunk in r.iter_content(chunk_size=8192):
                    if chunk:
                        f.write(chunk)

    return {
        'total_size': total_size,
        'num_parts': num_parts,
        'part_size': part_size,
        'output_path': output_path
    }
