import random
from unittest import mock

def get_oldest_non_default_policy(storage_policy_index):
    fake_ring = {
        0: {'name': 'legacy', 'default': True, 'timestamp': 1000},
        1: {'name': 'hdd', 'default': False, 'timestamp': 2000},
        2: {'name': 'ssd', 'default': False, 'timestamp': 3000},
    }

    def mock_get_container_policies(*args, **kwargs):
        headers = []
        for idx, policy in fake_ring.items():
            if idx != storage_policy_index:
                headers.append(('X-Storage-Policy', policy['name']))
                headers.append(('X-Backend-Storage-Policy-Index', str(idx)))
        random.shuffle(headers)
        return {'headers': headers}

    with mock.patch('swift.common.ring.Ring.get_nodes', side_effect=mock_get_container_policies):
        from swift.common.ring import Ring
        response = Ring({}).get_nodes()

        policy_indexes = []
        for header, value in response['headers']:
            if header == 'X-Backend-Storage-Policy-Index':
                policy_indexes.append(int(value))

        oldest_idx = None
        oldest_time = float('inf')
        for idx in policy_indexes:
            if not fake_ring[idx]['default'] and fake_ring[idx]['timestamp'] < oldest_time:
                oldest_time = fake_ring[idx]['timestamp']
                oldest_idx = idx

        return oldest_idx
