def create_db_and_user(db_name, username=None, admin_conn_kwargs=None):
    if username is None:
        username = db_name
    if admin_conn_kwargs is None:
        admin_conn_kwargs = {}

    conn = psycopg2.connect(dbname='postgres', **admin_conn_kwargs)
    conn.set_isolation_level(ISOLATION_LEVEL_AUTOCOMMIT)
    cur = conn.cursor()

    try:
        cur.execute(sql.SQL("CREATE USER {}").format(sql.Identifier(username)))
        cur.execute(sql.SQL("CREATE DATABASE {} OWNER {}").format(
            sql.Identifier(db_name),
            sql.Identifier(username)
        ))
    finally:
        cur.close()
        conn.close()

