 import io
import sys
from contextlib import redirect_stdout

def validate_code(code_str, reference_code_str, test_cases=None):
    def execute(code, env_vars):
        restricted_globals = {"__builtins__": {}}
        restricted_globals.update(env_vars)
        output_buffer = io.StringIO()

        try:
            compiled = compile(code, "<sandbox>", "exec")
            with redirect_stdout(output_buffer):
                exec(compiled, restricted_globals)
            return output_buffer.getvalue(), None
        except Exception as e:
            return None, str(e)

    if test_cases is None:
        test_cases = [{}]

    for i, case in enumerate(test_cases):
        candidate_out, cand_err = execute(code_str, case)
        ref_out, ref_err = execute(reference_code_str, case)

        if cand_err:
            return False, f"Test {i}: Candidate error - {cand_err}"
        if ref_err:
            return False, f"Test {i}: Reference error - {ref_err}"
        if candidate_out != ref_out:
            return False, f"Test {i}: Mismatch - expected {repr(ref_out)}, got {repr(candidate_out)}"

    return True, "All tests passed"

