import json
from typing import Union, Dict, Any

class Quantity:
    def __init__(self, amount: float, unit: str, error_lower: float = 0.0, error_upper: float = 0.0):
        self.amount = amount
        self.unit = unit
        self.error_lower = error_lower
        self.error_upper = error_upper

    @classmethod
    def from_json(cls, json_data: Union[str, Dict[str, Any]]) -> 'Quantity':
        if isinstance(json_data, str):
            data = json.loads(json_data)
        else:
            data = json_data

        return cls(
            amount=data['amount'],
            unit=data['unit'],
            error_lower=data.get('error_lower', 0.0),
            error_upper=data.get('error_upper', 0.0)
        )

    def to_json(self) -> str:
        return json.dumps({
            'amount': self.amount,
            'unit': self.unit,
            'error_lower': self.error_lower,
            'error_upper': self.error_upper
        })

    def __str__(self) -> str:
        if self.error_lower == self.error_upper:
            if self.error_lower == 0:
                return f"{self.amount} {self.unit}"
            return f"{self.amount} ± {self.error_lower} {self.unit}"
        return f"{self.amount} +{self.error_upper}/-{self.error_lower} {self.unit}"

    def __eq__(self, other: object) -> bool:
        if not isinstance(other, Quantity):
            return NotImplemented
        return (self.amount == other.amount and 
                self.unit == other.unit and 
                self.error_lower == other.error_lower and 
                self.error_upper == other.error_upper)
