import random

def rearrange_list(input_list):
    if not input_list:
        subset = []
    else:
        subset_size = random.randint(0, len(input_list))
        subset = random.sample(input_list, subset_size)

    faza = random.random() < 0.5

    if faza:
        if subset:
            num_to_remove = random.randint(1, len(subset))
            result = random.sample(subset, len(subset) - num_to_remove)
        else:
            result = []
    else:
        num_to_add = random.randint(1, 10)
        new_elements = [random.randint(1, 50) for _ in range(num_to_add)]
        result = subset + new_elements

    return result
