 import os
import inspect
import importlib.util
from distutils.core import run_setup

def get_modules(package_dir):
    modules = []
    if not os.path.exists(package_dir):
        return modules
    for root, dirs, files in os.walk(package_dir):
        for file in files:
            if file.endswith('.py') and not file.startswith('__'):
                module_path = os.path.join(root, file)
                module_name = file[:-3]
                try:
                    spec = importlib.util.spec_from_file_location(module_name, module_path)
                    module = importlib.util.module_from_spec(spec)
                    spec.loader.exec_module(module)
                    if inspect.ismodule(module):
                        modules.append(module_name)
                except Exception:
                    modules.append(module_name)
    return modules

def generate_readme(template_path, output_path, placeholder='{{MODULES}}'):
    package_name = 'package'
    if os.path.exists('setup.py'):
        try:
            setup = run_setup('setup.py', stop_after='config')
            package_name = setup.get_name() or package_name
        except Exception:
            pass

    package_dir = package_name.replace('.', os.sep)
    modules = get_modules(package_dir)
    module_list = '\n'.join(f'- {m}' for m in modules)

    with open(template_path, 'r') as f:
        template_content = f.read()

    readme_content = template_content.replace(placeholder, module_list)

    with open(output_path, 'w') as f:
        f.write(readme_content)

if __name__ == '__main__':
    generate_readme('README.template', 'README.md')

 import re

def extract_sequence_number(filepath):
    try:
        with open(filepath, 'r') as file:
            lines = file.readlines()
        if not lines:
            return None
        lines.sort()
        last_line = lines[-1]
        match = re.search(r'\d+', last_line)
        return int(match.group()) if match else None
    except (FileNotFoundError, PermissionError, ValueError):
        return None
    except Exception:
        return None

