 ```python
import subprocess
import threading
import time
import os
import re
import sys
from datetime import datetime

class AndroidDeviceMonitor:
    def __init__(self, screenshot_interval=5, output_dir="android_capture"):
        self.screenshot_interval = screenshot_interval
        self.output_dir = output_dir
        self.running = False
        self.device_serial = None

        if not os.path.exists(output_dir):
            os.makedirs(output_dir)

    def get_connected_device(self):
        try:
            result = subprocess.run(['adb', 'devices'], capture_output=True, text=True, timeout=5)
            lines = result.stdout.strip().split('\n')[1:]
            for line in lines:
                parts = line.split()
                if len(parts) >= 2 and parts[1] == 'device':
                    return parts[0]
            return None
        except:
            return None

    def capture_screenshots(self):
        while self.running:
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S_%f")[:-3]
            filepath = os.path.join(self.output_dir, f"screen_{timestamp}.png")

            try:
                proc = subprocess.Popen(
                    ['adb', 'shell', 'screencap', '-p'],
                    stdout=subprocess.PIPE,
                    stderr=subprocess.PIPE
                )
                stdout, stderr = proc.communicate(timeout=10)

                if proc.returncode != 0:
                    if not self.get_connected_device():
                        self.running = False
                        break
                    continue

                if sys.platform == 'win32':
                    stdout = stdout.replace(b'\r\n', b'\n')

                with open(filepath, 'wb') as f:
                    f.write(stdout)

            except Exception:
                if not self.get_connected_device():
                    self.running = False
                    break

            time.sleep(self.screenshot_interval)

    def parse_log_line(self, line):
        if not line:
            return None

        pattern = r'^(\d{2}-\d{2})\s+(\d{2}:\d{2}:\d{2}\.\d{3})\s+(\d+)\s+(\d+)\s+([VDIWEF])\s+([^:]+):\s*(.*)$'
        match = re.match(pattern, line)

        if match:
            date, time, pid, tid, level, tag, message = match.groups()
            return {
                'date': date,
                'time': time,
                'pid': pid,
                'tid': tid,
                'level': level,
                'tag': tag.strip(),
                'message': message.strip()
            }
        return {'raw': line}

    def capture_logcat(self):
        logfile_path = os.path.join(self.output_dir, f"logcat_{datetime.now().strftime('%Y%m%d_%H%M%S')}.txt")

        try:
            proc = subprocess.Popen(
                ['adb', 'logcat'],
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                encoding='utf-8',
                errors='ignore'
            )

            with open(logfile_path, 'w', encoding='utf-8') as logfile:
                while self.running:
                    try:
                        line = proc.stdout.readline()
                        if not line and proc.poll() is not None:
                            break

                        if not line:
                            continue

                        line = line.rstrip('\n\r')
                        parsed = self.parse_log_line(line)

                        if 'raw' in parsed:
                            logfile.write(f"{line}\n")
                        else:
                            logfile.write(f"[{parsed['date']} {parsed['time']}] [{parsed['level']}] {parsed['tag']}: {parsed['message']}\n")

                        logfile.flush()

                    except Exception:
                        break

        except Exception:
            pass

        self.running = False

    def monitor_connection(self):
        while self.running:
            time.sleep(2)
            if self.get_connected_device() is None:
                self.running = False
                break

    def run(self):
        if not self.get_connected_device():
            sys.exit(1)

        self.running = True

        threads = [
            threading.Thread(target=self.capture_screenshots),
            threading.Thread(target=self.capture_logcat),
            threading.Thread(target=self.monitor_connection)
        ]

        for t in threads:
            t.daemon = True
            t.start()

        try:
            while self.running:
                time.sleep(0.5)
        except KeyboardInterrupt:
            pass

        self.running = False

        for t in threads:
            t.join(timeout=3)

if __name__ == "__main__":
    monitor = AndroidDeviceMonitor(screenshot_interval=5)
    monitor.run()
