import tensorflow as tf
import numpy as np
import pandas as pd
from sklearn.preprocessing import StandardScaler, LabelEncoder, MinMaxScaler
from sklearn.model_selection import train_test_split
import json

def compile_ml_model(config):
    data_path = config.get('data_path')
    file_type = config.get('file_type', 'csv')

    if file_type == 'csv':
        df = pd.read_csv(data_path)
    elif file_type == 'parquet':
        df = pd.read_parquet(data_path)
    elif file_type == 'numpy':
        data = np.load(data_path)
        if isinstance(data, np.lib.npyio.NpzFile):
            X, y = data['X'], data['y']
        else:
            X, y = data[:, :-1], data[:, -1]
        df = None
    else:
        raise ValueError(f"Unsupported file type: {file_type}")

    if df is not None:
        target_col = config.get('target_column')
        feature_cols = config.get('feature_columns')

        if target_col:
            y = df[target_col].values
            X = df[feature_cols].values if feature_cols else df.drop(columns=[target_col]).values
        else:
            X = df.iloc[:, :-1].values
            y = df.iloc[:, -1].values

    preprocessing = config.get('preprocessing', {})

    if preprocessing.get('scale') == 'standard':
        scaler = StandardScaler()
        X = scaler.fit_transform(X)
    elif preprocessing.get('scale') == 'minmax':
        scaler = MinMaxScaler()
        X = scaler.fit_transform(X)

    if preprocessing.get('encode_labels'):
        encoder = LabelEncoder()
        y = encoder.fit_transform(y)

    if preprocessing.get('reshape'):
        X = X.reshape(preprocessing['reshape'])

    validation_split = config.get('validation_split', 0.2)
    if validation_split > 0:
        X_train, X_val, y_train, y_val = train_test_split(
            X, y, test_size=validation_split, random_state=42
        )

    input_shape = config.get('input_shape', X.shape[1:])
    num_classes = config.get('num_classes', len(np.unique(y)))

    model_config = config.get('model', {})
    layers = model_config.get('layers', [
        {'type': 'dense', 'units': 128, 'activation': 'relu'},
        {'type': 'dropout', 'rate': 0.2},
        {'type': 'dense', 'units': 64, 'activation': 'relu'},
        {'type': 'dense', 'units': num_classes, 'activation': 'softmax'}
    ])

    model = tf.keras.Sequential()
    model.add(tf.keras.layers.Input(shape=input_shape))

    for layer in layers:
        layer_type = layer.get('type', 'dense')
        if layer_type == 'dense':
            model.add(tf.keras.layers.Dense(
                units=layer['units'],
                activation=layer.get('activation', 'relu'),
                kernel_regularizer=tf.keras.regularizers.l2(layer.get('l2', 0.0))
            ))
        elif layer_type == 'dropout':
            model.add(tf.keras.layers.Dropout(layer.get('rate', 0.5)))
        elif layer_type == 'batch_norm':
            model.add(tf.keras.layers.BatchNormalization())
        elif layer_type == 'flatten':
            model.add(tf.keras.layers.Flatten())

    optimizer_config = config.get('optimizer', 'adam')
    if isinstance(optimizer_config, dict):
        optimizer_name = optimizer_config.get('name', 'adam')
        lr = optimizer_config.get('learning_rate', 0.001)
        if optimizer_name == 'adam':
            optimizer = tf.keras.optimizers.Adam(learning_rate=lr)
        elif optimizer_name == 'sgd':
            optimizer = tf.keras.optimizers.SGD(learning_rate=lr)
        elif optimizer_name == 'rmsprop':
            optimizer = tf.keras.optimizers.RMSprop(learning_rate=lr)
        else:
            optimizer = optimizer_name
    else:
        optimizer = optimizer_config

    loss = config.get('loss', 'sparse_categorical_crossentropy')
    metrics = config.get('metrics', ['accuracy'])

    model.compile(
        optimizer=optimizer,
        loss=loss,
        metrics=metrics
    )

    model.config = config
    model.preprocessor = {
        'scaler': scaler if preprocessing.get('scale') else None,
        'encoder': encoder if preprocessing.get('encode_labels') else None
    }

    return model
