 ```python
import gzip
import re
from typing import Dict, Optional, TextIO
import sys

def convert_gff3_to_gtf(input_file: str, output_file: Optional[str] = None, 
                       dialect: Optional[Dict[str, str]] = None) -> None:
    """
    Convert GFF3 file to GTF format with specified dialect.

    Args:
        input_file: Path to GFF3 file (gzipped or plain text)
        output_file: Path to output GTF file (None for stdout)
        dialect: Mapping of GFF3 attribute keys to GTF attribute keys.
                Default: {'ID': 'gene_id', 'Parent': 'transcript_id'}
    """

    def open_file(filepath: str):
        """Open file handling gzip compression."""
        with open(filepath, 'rb') as f:
            magic = f.read(2)
        if magic == b'\x1f\x8b':
            return gzip.open(filepath, 'rt')
        return open(filepath, 'r')

    def parse_gff3_attributes(attr_str: str) -> Dict[str, str]:
        """Parse GFF3 attributes (tag=value; format)."""
        attrs = {}
        if attr_str == '.':
            return attrs
        for item in attr_str.split(';'):
            item = item.strip()
            if '=' in item:
                key, value = item.split('=', 1)
                # Take first value if multiple (comma-separated)
                attrs[key] = value.split(',')[0]
        return attrs

    def build_gtf_attributes(attrs: Dict[str, str], feature: str, 
                           mapping: Dict[str, str]) -> str:
        """Convert to GTF format (tag "value";)."""
        gtf_attrs = {}

        # Apply dialect mapping
        for gff_key, gtf_key in mapping.items():
            if gff_key in attrs:
                gtf_attrs[gtf_key] = attrs[gff_key]

        # Ensure gene_id exists
        if 'gene_id' not in gtf_attrs:
            if 'ID' in attrs:
                gtf_attrs['gene_id'] = attrs['ID']
            elif 'Parent' in attrs:
                gtf_attrs['gene_id'] = attrs['Parent']
            else:
                gtf_attrs['gene_id'] = '.'

        # Ensure transcript_id for exon/CDS features
        if feature in ('exon', 'CDS', 'start_codon', 'stop_codon', 'UTR', 
                      'five_prime_UTR', 'three_prime_UTR'):
            if 'transcript_id' not in gtf_attrs:
                if 'ID' in attrs:
                    gtf_attrs['transcript_id'] = attrs['ID']
                elif 'Parent' in attrs:
                    gtf_attrs['transcript_id'] = attrs['Parent']
                else:
                    gtf_attrs['transcript_id'] = gtf_attrs.get('gene_id', '.')

        # Format as GTF: key "value";
        parts = []
        if 'gene_id' in gtf_attrs:
            parts.append(f"gene_id \"{gtf_attrs['gene_id']}\"")
        if 'transcript_id' in gtf_attrs:
            parts.append(f"transcript_id \"{gtf_attrs['transcript_id']}\"")

        for key, value in gtf_attrs.items():
            if key not in ('gene_id', 'transcript_id'):
                # Escape quotes in value
                safe_val = value.replace('"', '\\"')
                parts.append(f'{key} "{safe_val}"')

        return '; '.join(parts) + ';' if parts else ''

    # Default dialect
    if dialect is None:
        dialect = {'ID': 'gene_id', 'Parent': 'transcript_id'}

    out_handle = open(output_file, 'w') if output_file else sys.stdout

    try:
        with open_file(input_file) as in_handle:
            for line in in_handle:
                line = line.rstrip('\n\r')

                # Skip comments and empty lines
                if not line or line.startswith('#'):
                    continue

                cols = line.split('\t')
                if len(cols) != 9:
                    continue

                seqid, source, feature, start, end, score, strand, phase, attrs = cols

                # Parse and convert attributes
                attr_dict = parse_gff3_attributes(attrs)
                gtf_attr_str = build_gtf_attributes(attr_dict, feature, dialect)

                # Write GTF line
                gtf_line = '\t'.join([seqid, source, feature, start, end, 
                                    score, strand, phase, gtf_attr_str])
                out_handle.write(gtf_line + '\n')
    finally:
        if output_file:
            out_handle.close()
```

 ```python
import json
import pickle
import cv2
import numpy as np
from pathlib import Path

class ImageFeatureExtractor:
    def __init__(self, vocab_path):
        with open(vocab_path, 'rb') as f:
            self.vocabulary = pickle.load(f)

        if not isinstance(self.vocabulary, np.ndarray):
            self.vocabulary = np.array(self.vocabulary)

        self.detector = cv2.SIFT_create()

    def extract(self, image_path):
        img = cv2.imread(str(image_path), cv2.IMREAD_GRAYSCALE)
        if img is None:
            return None

        keypoints, descriptors = self.detector.detectAndCompute(img, None)

        if descriptors is None or len(descriptors) == 0:
            return np.zeros(len(self.vocabulary))

        distances = np.linalg.norm(descriptors[:, np.newaxis, :] - self.vocabulary, axis=2)
        assignments = np.argmin(distances, axis=1)

        hist = np.bincount(assignments, minlength=len(self.vocabulary))
        return hist / len(descriptors)

def process_dataset(json_path, vocab_path):
    with open(json_path, 'r') as f:
        annotations = json.load(f)

    extractor = ImageFeatureExtractor(vocab_path)
    features_list = []

    for item in annotations:
        image_path = item.get('image_path') or item.get('file_name') or item.get('path')
        if image_path and Path(image_path).exists():
            features = extractor.extract(image_path)
            if features is not None:
                features_list.append(features)

    return features_list
