import json

class Quantity:
    def __init__(self, data):
        self.amount = data['amount']
        self.unit = data['unit']
        self.upperBound = data['upperBound']
        self.lowerBound = data.get('lowerBound')

    @classmethod
    def fromWikibase(cls, wb_data):
        return cls({
            'amount': wb_data.get('amount'),
            'unit': wb_data.get('unit'),
            'upperBound': wb_data.get('upperBound'),
            'lowerBound': wb_data.get('lowerBound')
        })

    def __str__(self):
        return json.dumps({
            'amount': self.amount,
            'unit': self.unit,
            'upperBound': self.upperBound,
            'lowerBound': self.lowerBound
        })

    def __eq__(self, other):
        if not isinstance(other, Quantity):
            return NotImplemented
        return (self.amount == other.amount and 
                self.unit == other.unit and 
                self.upperBound == other.upperBound and
                self.lowerBound == other.lowerBound)
