 import os
import glob

def generate_report(directory_path, coefficient=1.0, output_file="report.txt"):
    stats = {}
    stat_file = os.path.join(directory_path, "statistics.txt")

    if os.path.exists(stat_file):
        with open(stat_file, 'r') as f:
            for line in f:
                line = line.strip()
                if ':' in line:
                    key, value = line.split(':', 1)
                    stats[key.strip()] = value.strip()

    for key in ['Increase', 'Decrease']:
        if key in stats:
            try:
                stats[key] = str(float(stats[key]) * coefficient)
            except ValueError:
                pass

    alignment_files = []
    for pattern in ['*.fa', '*.fasta', '*.aln', '*.phy', '*.nex']:
        alignment_files.extend(glob.glob(os.path.join(directory_path, pattern)))

    concatenated = ""
    for af in alignment_files:
        with open(af, 'r') as f:
            concatenated += f.read() + "\n"

    with open(output_file, 'w') as f:
        f.write(f"Reticulations: {stats.get('Reticulations', 'N/A')}\n")
        f.write(f"Taxa: {stats.get('Taxa', 'N/A')}\n")
        f.write(f"Increase: {stats.get('Increase', 'N/A')}\n")
        f.write(f"Decrease: {stats.get('Decrease', 'N/A')}\n")
        f.write(f"Outgroup: {stats.get('Outgroup', 'N/A')}\n")
        if concatenated:
            f.write("\n")
            f.write(concatenated)

