import hashlib

class HashComputer:
    def __init__(self, algorithm='sha256', initial_string=''):
        self.algorithm = algorithm
        self._hash_obj = hashlib.new(algorithm)
        if initial_string:
            self._hash_obj.update(initial_string.encode('utf-8'))

    def update(self, string):
        self._hash_obj.update(string.encode('utf-8'))
        return self

    def hexdigest(self):
        return self._hash_obj.hexdigest()

    def clone(self):
        new_instance = HashComputer.__new__(HashComputer)
        new_instance.algorithm = self.algorithm
        new_instance._hash_obj = self._hash_obj.copy()
        return new_instance

def hash_string(input_string, algorithm='sha256'):
    return hashlib.new(algorithm, input_string.encode('utf-8')).hexdigest()
