from subprocess import check_output
import json

def get_etcd_data(ip, path, cert_file=None, key_file=None, ca_file=None):
    protocol = "https" if any([cert_file, key_file, ca_file]) else "http"
    url = f"{protocol}://{ip}:2379/v2/keys/{path}"

    cmd = ["curl", "-s", "-L", url]

    if cert_file:
        cmd.extend(["--cert", cert_file])
    if key_file:
        cmd.extend(["--key", key_file])
    if ca_file:
        cmd.extend(["--cacert", ca_file])

    output = check_output(cmd)
    return json.loads(output)
