        '/reset/<uid>/<token>/',
        view_func=PasswordResetConfirmView.as_view('password_reset_confirm')
    )
    app.add_url_rule(
        '/reset/complete/',
        view_func=PasswordResetCompleteView.as_view('password_reset_complete')
