import hashlib
import hmac

def get_md5_hash(input_string, expected_hash=None):
    computed_hash = hashlib.md5(input_string.encode('utf-8')).hexdigest()
    if expected_hash is not None:
        if not hmac.compare_digest(computed_hash, expected_hash):
            raise ValueError("Hash mismatch")
    return computed_hash
