 ```python
import shelve
from typing import Any, Type, Iterator

class DataFilter:
    def __init__(self, path: str, types: tuple[Type, ...]):
        self.path = path
        self.types = types
        self._db = None

    def start(self):
        self._db = shelve.open(self.path, writeback=True)
        if 'records' not in self._db:
            self._db['records'] = []

    def record(self, item: Any) -> bool:
        if isinstance(item, self.types):
            self._db['records'].append(item)
            self._db.sync()
            return True
        return False

    def playback(self) -> Iterator[Any]:
        if self._db:
            for item in self._db['records']:
                yield item
        else:
            with shelve.open(self.path, 'r') as db:
                for item in db.get('records', []):
                    yield item

    def stop(self):
        if self._db:
            self._db.close()
            self._db = None

def create_filter(storage_path: str, *allowed_types: Type):
    return DataFilter(storage_path, allowed_types)
