 ```python
import warnings

def _warn_deprecation(old_name, new_name, version):
    warnings.warn(
        f"{old_name} is deprecated since version {version}, use {new_name} instead",
        DeprecationWarning,
        stacklevel=4
    )

def _get_deprecated_attribute(self, old_name, new_name, version):
    _warn_deprecation(old_name, new_name, version)
    return getattr(self, new_name)

def _set_deprecated_attribute(self, value, old_name, new_name, version):
    _warn_deprecation(old_name, new_name, version)
    setattr(self, new_name, value)

def deprecated_attribute(old_name, new_name, version):
    def getter(self):
        return _get_deprecated_attribute(self, old_name, new_name, version)

    def setter(self, value):
        _set_deprecated_attribute(self, value, old_name, new_name, version)

    return property(getter, setter)
