def execute_function(func_str, options):
    import collections
    import re

    namespace = {
        '__builtins__': __builtins__,
        'collections': collections,
        'namedtuple': collections.namedtuple
    }

    exec(func_str, namespace)

    func_name = None
    match = re.search(r'def\s+(\w+)\s*\(', func_str)
    if match:
        func_name = match.group(1)
    else:
        match = re.search(r'(\w+)\s*=\s*lambda', func_str)
        if match:
            func_name = match.group(1)

    if func_name and func_name in namespace:
        func = namespace[func_name]
    else:
        func = next((v for k, v in namespace.items() 
                    if callable(v) and not k.startswith('_') and k not in ['collections', 'namedtuple']), None)
        if func is None:
            raise ValueError("No callable found in string")

    return func(**options) if isinstance(options, dict) else func(options)
