 import hashlib
import pickle
import threading
from datetime import datetime, timezone

bounties_list = []
bounties_lock = threading.Lock()

class Bounty:
    def __init__(self, public_key, bounty_amount):
        self.public_key = public_key
        self.bounty_amount = bounty_amount
        self.stored_hash = None

    def calculate_bounty(self, master_public_key):
        current_time = datetime.now(timezone.utc).isoformat()
        data = f"{current_time}{master_public_key}{self.public_key}".encode('utf-8')
        hash_obj = hashlib.sha256(data)
        hash_int = int(hash_obj.hexdigest(), 16)
        calculated_amount = self.bounty_amount + (hash_int % 10000)
        return calculated_amount

    def check_file_hash(self, file_hash):
        return self.stored_hash == file_hash

    def set_stored_hash(self, file_hash):
        self.stored_hash = file_hash

    def serialize(self):
        return pickle.dumps(self)

    @staticmethod
    def deserialize(data):
        return pickle.loads(data)

def add_bounty(public_key, bounty_amount):
    bounty = Bounty(public_key, bounty_amount)
    with bounties_lock:
        bounties_list.append(bounty)
    return bounty

