import random

def random_subset_array(dimensions):
    def create_array(dims):
        if not dims:
            return random.randint(0, 100)
        return [create_array(dims[1:]) for _ in range(dims[0])]

    intervals = []
    for dim in dimensions:
        start = random.randint(0, dim - 1)
        end = random.randint(start + 1, dim)
        intervals.append((start, end))

    def extract_subset(arr, ints):
        if not ints:
            return arr
        start, end = ints[0]
        return [extract_subset(subarr, ints[1:]) for subarr in arr[start:end]]

    original = create_array(dimensions)
    return extract_subset(original, intervals)
