import scipy.stats as stats

def get_ppf(distribution_name, values, **fit_params):
    try:
        dist = getattr(stats, distribution_name)
    except AttributeError:
        return None

    if not hasattr(dist, 'ppf'):
        return None

    try:
        params = dist.fit(values, **fit_params)
        frozen_dist = dist(*params)
        return frozen_dist.ppf
    except Exception:
        return None
