import re

def compile_template(_n):
    tokens = re.findall(r'\S+', _n)
    index = [0]

    def pop():
        if index[0] >= len(tokens):
            raise SyntaxError("Unexpected end of template")
        tok = tokens[index[0]]
        index[0] += 1
        return tok

    syntax = {
        'add': '+',
        'sub': '-',
        'mul': '*',
        'div': '/',
        'pow': '**'
    }

    def parse_expression():
        token = pop()
        if token in syntax:
            left = parse_expression()
            right = parse_expression()
            return f"({left} {syntax[token]} {right})"
        elif token == 'n':
            return '_n'
        else:
            return token

    expr = parse_expression()
    return eval(f"lambda _n: {expr}")
