 import tensorflow as tf
from stable_baselines3.common.vec_env import DummyVecEnv
import gymnasium as gym
from typing import Optional, Dict, Callable, Any, Tuple

class CustomRewardWrapper(gym.Wrapper):
    def __init__(self, env: gym.Env, reward_params: Dict[str, Any]):
        super().__init__(env)
        self.reward_params = reward_params
        self.custom_fn: Optional[Callable] = reward_params.get('custom_fn')

    def step(self, action) -> Tuple[Any, float, bool, bool, Dict]:
        obs, reward, terminated, truncated, info = self.env.step(action)

        if self.custom_fn is not None:
            reward = self.custom_fn(reward, obs, action, info, self.reward_params)
        else:
            if 'scale' in self.reward_params:
                reward *= self.reward_params['scale']
            if 'offset' in self.reward_params:
                reward += self.reward_params['offset']
            if 'clip_range' in self.reward_params:
                low, high = self.reward_params['clip_range']
                reward = max(low, min(reward, high))

        return obs, reward, terminated, truncated, info

def configure_rl_env(
    env_id: str,
    n_envs: int = 1,
    seed: Optional[int] = None,
    reward_params: Optional[Dict[str, Any]] = None,
    env_kwargs: Optional[Dict[str, Any]] = None
) -> DummyVecEnv:
    gpus = tf.config.list_physical_devices('GPU')
    if gpus:
        try:
            for gpu in gpus:
                tf.config.experimental.set_memory_growth(gpu, True)
        except RuntimeError:
            pass

    def make_env(rank: int):
        def _init():
            kwargs = env_kwargs.copy() if env_kwargs else {}
            if seed is not None:
                kwargs['seed'] = seed + rank
            env = gym.make(env_id, **kwargs)
            if reward_params is not None:
                env = CustomRewardWrapper(env, reward_params)
            return env
        return _init

    env_fns = [make_env(i) for i in range(n_envs)]
    return DummyVecEnv(env_fns)

