def execute_command(command, mode='r'):
    if mode == 'r':
        process = subprocess.Popen(command, stdout=subprocess.PIPE, shell=isinstance(command, str))
        return io.TextIOWrapper(process.stdout, encoding='utf-8')
    elif mode == 'w':
        process = subprocess.Popen(command, stdin=subprocess.PIPE, shell=isinstance(command, str))
        return io.TextIOWrapper(process.stdin, encoding='utf-8', write_through=True)
