 import hashlib

def sha1_file(filepath, max_bytes=None):
    sha1 = hashlib.sha1()
    with open(filepath, 'rb') as f:
        if max_bytes is None:
            while True:
                data = f.read(8192)
                if not data:
                    break
                sha1.update(data)
        else:
            remaining = max_bytes
            while remaining > 0:
                chunk = f.read(min(8192, remaining))
                if not chunk:
                    break
                sha1.update(chunk)
                remaining -= len(chunk)
    return sha1.hexdigest()

