import json
import pickle
import base64

def get_user_virtual_machines(user, cache=None, db=None):
    try:
        user_id = getattr(user, 'id', str(user))
        vm_data = None

        if cache is not None:
            vm_data = cache.get(user_id)

        if vm_data is None and db is not None:
            vm_data = db.get_virtual_machines(user)
            if cache is not None and vm_data is not None:
                cache.set(user_id, vm_data)

        if vm_data is None:
            return {}

        if isinstance(vm_data, (str, bytes)):
            try:
                decoded = base64.b64decode(vm_data)
                vms = pickle.loads(decoded)
            except Exception:
                try:
                    if isinstance(vm_data, bytes):
                        vm_data = vm_data.decode('utf-8')
                    vms = json.loads(vm_data)
                except Exception:
                    return {}
        else:
            vms = vm_data

        result = {}
        if isinstance(vms, list):
            for vm in vms:
                if isinstance(vm, dict):
                    vm_id = vm.get('id')
                    if vm_id:
                        result[vm_id] = vm
                elif hasattr(vm, 'id'):
                    result[vm.id] = {'state': getattr(vm, 'state', None), 'data': vm}
        elif isinstance(vms, dict):
            result = vms

        return result

    except Exception:
        return {}
