import pickle
import os
from contextlib import contextmanager

@contextmanager
def load_save_state(filepath):
    if os.path.exists(filepath):
        try:
            with open(filepath, 'rb') as f:
                state = pickle.load(f)
        except Exception:
            state = {}
    else:
        state = {}

    try:
        yield state
    finally:
        try:
            with open(filepath, 'wb') as f:
                pickle.dump(state, f)
        except Exception:
            pass
