 import os
import pickle
import base64
import zlib

def load_skip_filter():
    env_value = os.environ.get('PYDEV_PYTEST_SKIP')
    if not env_value:
        return {}

    try:
        compressed_data = base64.b64decode(env_value)
        pickled_data = zlib.decompress(compressed_data)
        skip_filter = pickle.loads(pickled_data)

        if not isinstance(skip_filter, dict):
            return {}

        resolved_filter = {}
        for path, skip_value in skip_filter.items():
            try:
                resolved_path = os.path.realpath(path)
            except (OSError, IOError):
                resolved_path = path
            resolved_filter[resolved_path] = skip_value

        return resolved_filter
    except Exception:
        return {}

