CREATE OR REPLACE FUNCTION modify_table_structure(
    p_table_name TEXT,
    p_old_column_name TEXT,
    p_new_column_name TEXT,
    p_new_column_def JSONB
) RETURNS VOID AS $$
DECLARE
    v_new_col_name TEXT;
    v_data_type TEXT;
    v_constraints TEXT;
BEGIN
    EXECUTE format('ALTER TABLE %I RENAME COLUMN %I TO %I', 
                   p_table_name, p_old_column_name, p_new_column_name);

    v_new_col_name := p_new_column_def->>'name';
    v_data_type := p_new_column_def->>'data_type';
    v_constraints := COALESCE(p_new_column_def->>'constraints', '');

    EXECUTE format('ALTER TABLE %I ADD COLUMN %I %s %s', 
                   p_table_name, v_new_col_name, v_data_type, v_constraints);
END;
$$ LANGUAGE plpgsql;
