from flask import Flask, request, redirect, session, url_for
import paypalrestsdk

app = Flask(__name__)
app.secret_key = 'your-secret-key-change-this'

HTML_FORM = '''
<!DOCTYPE html>
<html>
<body>
    <h2>PayPal Payment</h2>
    <form method="post" action="/pay">
        <label>Client ID: <input type="text" name="client_id" required></label><br><br>
        <label>Client Secret: <input type="text" name="client_secret" required></label><br><br>
        <label>Amount (USD): <input type="number" name="amount" step="0.01" value="10.00" required></label><br><br>
        <button type="submit">Pay with PayPal</button>
    </form>
</body>
</html>
'''

@app.route('/')
def index():
    return HTML_FORM

@app.route('/pay', methods=['POST'])
def pay():
    client_id = request.form['client_id']
    client_secret = request.form['client_secret']
    amount = request.form['amount']

    session['client_id'] = client_id
    session['client_secret'] = client_secret

    paypalrestsdk.configure({
        "mode": "sandbox",
        "client_id": client_id,
        "client_secret": client_secret
    })

    payment = paypalrestsdk.Payment({
        "intent": "sale",
        "payer": {"payment_method": "paypal"},
        "redirect_urls": {
            "return_url": url_for('success', _external=True),
            "cancel_url": url_for('cancel', _external=True)
        },
        "transactions": [{
            "amount": {
                "total": amount,
                "currency": "USD"
            },
            "description": "Payment transaction"
        }]
    })

    if payment.create():
        for link in payment.links:
            if link.rel == "approval_url":
                return redirect(link.href)
    else:
        return str(payment.error)

@app.route('/success')
def success():
    payment_id = request.args.get('paymentId')
    payer_id = request.args.get('PayerID')

    if not payment_id or not payer_id:
        return "Error: Missing payment information"

    client_id = session.get('client_id')
    client_secret = session.get('client_secret')

    if not client_id or not client_secret:
        return "Error: Session expired"

    paypalrestsdk.configure({
        "mode": "sandbox",
        "client_id": client_id,
        "client_secret": client_secret
    })

    payment = paypalrestsdk.Payment.find(payment_id)

    if payment.execute({"payer_id": payer_id}):
        return f"<h1>Payment Successful!</h1><p>Payment ID: {payment.id}</p><p>State: {payment.state}</p>"
    else:
        return f"<h1>Payment Failed</h1><p>Error: {payment.error}</p>"

@app.route('/cancel')
def cancel():
    return "<h1>Payment Cancelled</h1>"

if __name__ == '__main__':
    app.run(debug=True)

