def execute_function(func_name, args=(), kwargs=None):
    import sys
    if kwargs is None:
        kwargs = {}

    frame = sys._getframe(1)
    exec_globals = frame.f_globals.copy()
    exec_locals = {}
    original_keys = set(exec_globals.keys())

    try:
        exec_globals['__tmp_args'] = args
        exec_globals['__tmp_kwargs'] = kwargs
        exec(f"__tmp_result = {func_name}(*__tmp_args, **__tmp_kwargs)", exec_globals, exec_locals)
        return exec_globals.get('__tmp_result')
    except Exception as e:
        raise RuntimeError(f"Error executing {func_name}: {e}") from e
    finally:
        current_keys = set(exec_globals.keys())
        new_keys = current_keys - original_keys
        for key in list(new_keys) + ['__tmp_args', '__tmp_kwargs', '__tmp_result']:
            if key in exec_globals:
                del exec_globals[key]
        exec_locals.clear()
