def authenticate_env_vars(env_vars):
   authenticated_env = dict(env_vars)
   auth_version = None

   if all(k in authenticated_env for k in ['OS_AUTH_URL', 'OS_USERNAME', 'OS_PASSWORD']):
       url = authenticated_env['OS_AUTH_URL']
       if '/v3' in url:
           auth_version = '3.0'
       elif '/v2.0' in url or '/v2' in url:
           auth_version = '2.0'
       else:
           auth_version = '2.0'
       authenticated_env['OS_AUTH_VERSION'] = auth_version

   elif all(k in authenticated_env for k in ['ST_AUTH', 'ST_USER', 'ST_KEY']):
       auth_version = '1.0'
       authenticated_env['ST_AUTH_VERSION'] = auth_version

   return authenticated_env, auth_version

