import os
import sys
import logging
import csv
from scrapy import Item, Field
from scrapy.spiders import Spider
from scrapy.crawler import CrawlerProcess
from scrapy.exceptions import DropItem
from scrapy.pipelines.images import ImagesPipeline


class DataItem(Item):
    url = Field()
    title = Field()
    text = Field()


class CSVPipeline:
    def __init__(self, output_file):
        self.output_file = output_file
        self.file = None
        self.writer = None

    @classmethod
    def from_crawler(cls, crawler):
        return cls(output_file=crawler.settings.get('OUTPUT_FILE'))

    def open_spider(self, spider):
        self.file = open(self.output_file, 'w', newline='', encoding='utf-8')
        self.writer = csv.DictWriter(self.file, fieldnames=['url', 'title', 'text'])
        self.writer.writeheader()

    def close_spider(self, spider):
        if self.file:
            self.file.close()

    def process_item(self, item, spider):
        self.writer.writerow(dict(item))
        return item


class GenericSpider(Spider):
    name = 'generic_spider'

    def __init__(self, url=None, **kwargs):
        super().__init__(**kwargs)
        self.start_urls = [url] if url else []

    def parse(self, response):
        item = DataItem()
        item['url'] = response.url
        item['title'] = response.css('title::text').get(default='').strip()
        item['text'] = ' '.join(response.css('p::text').getall()).strip()[:500]
        yield item


if __name__ == '__main__':
    if len(sys.argv) != 3:
        print("Usage: python script.py <URL> <output_file.csv>")
        sys.exit(1)

    url = sys.argv[1]
    output_file = sys.argv[2]

    if os.path.exists(output_file):
        os.remove(output_file)

    process = CrawlerProcess(settings={
        'LOG_LEVEL': logging.INFO,
        'ITEM_PIPELINES': {
            '__main__.CSVPipeline': 300,
        },
        'OUTPUT_FILE': output_file,
        'USER_AGENT': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
        'ROBOTSTXT_OBEY': True,
        'DOWNLOAD_DELAY': 1,
    })

    process.crawl(GenericSpider, url=url)
    process.start()
