def calculate_file_hash(filepath, hash_obj):
    try:
        with open(filepath, 'rb') as f:
            while chunk := f.read(8192):
                hash_obj.update(chunk)
        return hash_obj.hexdigest()
    except (FileNotFoundError, PermissionError, OSError):
