import subprocess

def check_job_status(command):
    try:
        result = subprocess.run(
            command,
            shell=True,
            capture_output=True,
            text=True,
            timeout=30
        )

        output = (result.stdout + result.stderr).lower()

        if any(keyword in output for keyword in ["completed", "success", "done", "finished"]):
            return 0
        elif any(keyword in output for keyword in ["failed", "error", "failure", "aborted"]):
            return 1
        else:
            return None

    except (subprocess.TimeoutExpired, subprocess.SubprocessError, Exception):
        return None
