 CREATE OR REPLACE FUNCTION setup_triggers(
    table_query TEXT,
    trigger_name_prefix TEXT DEFAULT 'trg_',
    trigger_function TEXT DEFAULT 'generic_trigger_func'
) RETURNS void AS $$
DECLARE
    rec RECORD;
    tbl_name TEXT;
    sch_name TEXT;
    trg_name TEXT;
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_language WHERE lanname = 'plpgsql') THEN
        CREATE LANGUAGE plpgsql;
    END IF;

    FOR rec IN EXECUTE table_query LOOP
        sch_name := COALESCE(rec.schema_name, 'public');
        tbl_name := rec.table_name;
        trg_name := trigger_name_prefix || tbl_name;

        EXECUTE format('DROP TRIGGER IF EXISTS %I ON %I.%I', 
                      trg_name, sch_name, tbl_name);

        EXECUTE format('CREATE TRIGGER %I 
                       BEFORE INSERT OR UPDATE ON %I.%I 
                       FOR EACH ROW 
                       EXECUTE FUNCTION %I()',
                      trg_name, sch_name, tbl_name, trigger_function);
    END LOOP;
END;
$$ LANGUAGE plpgsql;

