    parser.add_argument("--test", action="store_true", help="Use test PyPI environment")
    parser.add_argument("command", choices=["test", "register", "upload"], help="Command to execute")
    args = parser.parse_args()

    if args.command == "test":
        test()
    elif args.command == "register":
        register(args.test)
    elif args.command == "upload":
        upload(args.test)
