from django.db import models
from django.template.loader import render_to_string
from django.core.exceptions import PermissionDenied
from django.utils.html import escape

class EventPage(models.Model):
    title = models.CharField(max_length=255)
    date = models.DateField()
    time = models.TimeField()
    location = models.CharField(max_length=255)
    audience = models.CharField(max_length=100, default='general')
    view_password = models.CharField(max_length=128, blank=True, null=True)

    class Meta:
        ordering = ['date', 'time']

    @classmethod
    def filter_by_location_and_audience(cls, location=None, audience=None):
        queryset = cls.objects.all()
        if location:
            queryset = queryset.filter(location__icontains=location)
        if audience:
            queryset = queryset.filter(audience__icontains=audience)
        return queryset

    def render_event_page(self, provided_password=None, template_name='event_page.html'):
        if self.view_password:
            if not provided_password or provided_password != self.view_password:
                raise PermissionDenied("Invalid or missing password")

        context = {
            'event': self,
            'title': escape(self.title),
            'date': self.date,
            'time': self.time,
            'location': escape(self.location),
            'audience': self.audience,
        }
        return render_to_string(template_name, context)
