import pickle

class PickleDataLoader:
    def __init__(self, train_path=None, val_path=None, test_path=None):
        self.train_data = None
        self.train_labels = None
        self.val_data = None
        self.val_labels = None
        self.test_data = None
        self.test_labels = None

        if train_path:
            self.train_data, self.train_labels = self._load_pickle(train_path)
        if val_path:
            self.val_data, self.val_labels = self._load_pickle(val_path)
        if test_path:
            self.test_data, self.test_labels = self._load_pickle(test_path)

    def _load_pickle(self, filepath):
        with open(filepath, 'rb') as f:
            data = pickle.load(f)

        if isinstance(data, dict):
            images = data.get('images') or data.get('data') or data.get('x')
            labels = data.get('labels') or data.get('targets') or data.get('y')
            return images, labels
        elif isinstance(data, (list, tuple)) and len(data) >= 2:
            return data[0], data[1]
        else:
            raise ValueError("Pickle file must contain dict or tuple/list of (images, labels)")

    def render_data(self, split='train'):
        if split == 'train':
            if self.train_data is None:
                raise ValueError("Training data not loaded")
            return zip(self.train_data, self.train_labels)
        elif split == 'val':
            if self.val_data is None:
                raise ValueError("Validation data not loaded")
            return zip(self.val_data, self.val_labels)
        elif split == 'test':
            if self.test_data is None:
                raise ValueError("Test data not loaded")
            return zip(self.test_data, self.test_labels)
        else:
            raise ValueError("Split must be 'train', 'val', or 'test'")
