import uuid

def create_controllers(configurations, sequencer, system):
    class Controller:
        def __init__(self, ctrl_type, seq, sys):
            self.unique_id = uuid.uuid4().hex
            self.controller_type = ctrl_type
            self.sequencer = seq
            self.system = sys
            self.state = "idle"

        def activate(self):
            self.state = "active"
            return f"Controller {self.unique_id} activated"

        def deactivate(self):
            self.state = "inactive"
            return f"Controller {self.unique_id} deactivated"

        def execute_command(self, command):
            if self.sequencer:
                return self.sequencer.run(command, self.system)
            return None

        def get_status(self):
            return {
                "id": self.unique_id,
                "type": self.controller_type,
                "state": self.state
            }

    controllers = []
    for config in configurations:
        if isinstance(config, dict):
            ctrl_type = config.get('type', 'default')
            count = config.get('count', 1)
        else:
            ctrl_type, count = config[0], config[1]

        for _ in range(count):
            controllers.append(Controller(ctrl_type, sequencer, system))

    return controllers
