from collections import namedtuple

def get_table_columns(cursor, table_name, columns=None, named_tuples=False):
    try:
        cursor.execute(f"SHOW COLUMNS FROM {table_name}")
        rows = cursor.fetchall()

        result = []
        if named_tuples:
            Column = namedtuple('Column', ['name', 'type'])

        for row in rows:
            col_name = row[0]
            col_type = row[1]

            if columns is None or col_name in columns:
                if named_tuples:
                    result.append(Column(name=col_name, type=col_type))
                else:
                    result.append((col_name, col_type))

        return result
    except Exception as e:
        raise RuntimeError(f"Database error retrieving columns from {table_name}: {e}")
