 import json
import os
import subprocess
import tempfile
from pathlib import Path
from typing import Dict, Any, Optional


class JavaTestEnvironment:
    def __init__(self, expectations_file: str, display_num: int = 99, 
                 java_home: Optional[str] = None, xvfb_args: Optional[list] = None):
        self.expectations_file = Path(expectations_file)
        self.display_num = display_num
        self.java_home = java_home or os.environ.get("JAVA_HOME")
        self.xvfb_args = xvfb_args or ["-screen", "0", "1280x1024x24", "-ac"]
        self.expectations: Dict[str, Any] = {}
        self.xvfb_process: Optional[subprocess.Popen] = None
        self.original_display: Optional[str] = None
        self.temp_dir = tempfile.mkdtemp()

    def load_expectations(self) -> Dict[str, Any]:
        if not self.expectations_file.exists():
            raise FileNotFoundError(f"Expectations file not found: {self.expectations_file}")

        with open(self.expectations_file, 'r') as f:
            self.expectations = json.load(f)
        return self.expectations

    def setup_display(self) -> str:
        self.original_display = os.environ.get("DISPLAY")
        display_str = f":{self.display_num}"

        cmd = ["Xvfb", display_str] + self.xvfb_args
        self.xvfb_process = subprocess.Popen(
            cmd, 
            stdout=subprocess.DEVNULL, 
            stderr=subprocess.DEVNULL
        )

        os.environ["DISPLAY"] = display_str

        # Verify display is ready
        import time
        time.sleep(0.5)

        return display_str

    def setup_java_env(self):
        if self.java_home:
            os.environ["JAVA_HOME"] = self.java_home
            os.environ["PATH"] = f"{self.java_home}/bin:{os.environ.get('PATH', '')}"

        # Set temp directory for Java
        os.environ["JAVA_TMPDIR"] = self.temp_dir

    def setup(self):
        self.load_expectations()
        self.setup_display()
        self.setup_java_env()

    def teardown(self):
        if self.xvfb_process:
            self.xvfb_process.terminate()
            try:
                self.xvfb_process.wait(timeout=5)
            except subprocess.TimeoutExpired:
                self.xvfb_process.kill()

        if self.original_display is not None:
            os.environ["DISPLAY"] = self.original_display
        elif "DISPLAY" in os.environ:
            del os.environ["DISPLAY"]

        # Cleanup temp directory
        import shutil
        if os.path.exists(self.temp_dir):
            shutil.rmtree(self.temp_dir, ignore_errors=True)

    def get_expectation(self, key: str, default: Any = None) -> Any:
        return self.expectations.get(key, default)

    def __enter__(self):
        self.setup()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.teardown()
        return False

