import importlib.util
import os

def load_extension(extension_path, python_path, root_dir):
    try:
        if not os.path.isfile(extension_path):
            raise FileNotFoundError(f"Extension file not found: {extension_path}")

        spec = importlib.util.spec_from_file_location("custom_extension", extension_path)
        if spec is None or spec.loader is None:
            raise ImportError(f"Cannot load extension from {extension_path}")

        module = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(module)

        if not hasattr(module, 'Extend'):
            raise AttributeError("Extension module must define 'Extend' function")

        extend_func = module.Extend
        if not callable(extend_func):
            raise TypeError("'Extend' must be callable")

        result = extend_func(python_path, root_dir)
        return result

    except Exception as e:
        raise RuntimeError(f"Failed to load or execute extension: {e}") from e
