import json
import ast

def deserialize_json(s, decode_keys=False):
    if decode_keys:
        def object_pairs_hook(pairs):
            result = {}
            for k, v in pairs:
                if isinstance(k, str):
                    try:
                        k = ast.literal_eval(k)
                    except (ValueError, SyntaxError):
                        pass
                result[k] = v
            return result
        return json.loads(s, object_pairs_hook=object_pairs_hook)
    return json.loads(s)
