 ```python
import threading
import time
import sqlite3
from typing import Optional, Callable
from dataclasses import dataclass

@dataclass
class Book:
    id: str
    title: str
    duration: int

class Database:
    def __init__(self, db_path: str = "audiobooks.db"):
        self.conn = sqlite3.connect(db_path, check_same_thread=False)
        self.cursor = self.conn.cursor()
        self.cursor.execute("""
            CREATE TABLE IF NOT EXISTS progress (
                book_id TEXT PRIMARY KEY,
                position INTEGER DEFAULT 0,
                completed BOOLEAN DEFAULT 0
            )
        """)
        self.conn.commit()

    def save_progress(self, book_id: str, position: int):
        self.cursor.execute(
            "INSERT OR REPLACE INTO progress (book_id, position, completed) VALUES (?, ?, 0)",
            (book_id, position)
        )
        self.conn.commit()

    def get_progress(self, book_id: str) -> int:
        self.cursor.execute("SELECT position FROM progress WHERE book_id = ?", (book_id,))
        result = self.cursor.fetchone()
        return result[0] if result else 0

    def delete_progress(self, book_id: str):
        self.cursor.execute("DELETE FROM progress WHERE book_id = ?", (book_id,))
        self.conn.commit()

    def mark_completed(self, book_id: str):
        self.cursor.execute("UPDATE progress SET completed = 1 WHERE book_id = ?", (book_id,))
        self.conn.commit()

class AudioPlayer:
    def __init__(self, database: Database, on_finished: Callable[[str], None]):
        self.db = database
        self.on_finished = on_finished
        self.current_book: Optional[Book] = None
        self.is_playing = False
        self.position = 0
        self._stop_event = threading.Event()
        self._thread: Optional[threading.Thread] = None
        self._lock = threading.Lock()

    def _playback_loop(self):
        while not self._stop_event.is_set() and self.current_book:
            time.sleep(0.1)
            with self._lock:
                self.position += 1

                if self.position >= self.current_book.duration:
                    book_id = self.current_book.id
                    self.is_playing = False
                    self.current_book = None
                    self._stop_event.set()
                    self.on_finished(book_id)
                    break

        if self.current_book and not self._stop_event.is_set():
            self.db.save_progress(self.current_book.id, self.position)

    def play(self, book: Book):
        with self._lock:
            if self.is_playing:
                self._stop_playback()

            self.current_book = book
            self.position = self.db.get_progress(book.id)
            self.is_playing = True
            self._stop_event.clear()

            self._thread = threading.Thread(target=self._playback_loop, daemon=True)
            self._thread.start()

    def _stop_playback(self):
        if self.current_book:
            self.db.save_progress(self.current_book.id, self.position)
        self._stop_event.set()
        if self._thread and self._thread.is_alive():
            self._thread.join(timeout=1.0)
        self.is_playing = False

    def stop(self):
        with self._lock:
            self._stop_playback()
            self.current_book = None

class RFIDReader:
    def __init__(self):
        self.last_card: Optional[str] = None
        self._simulated_cards = []
        self._simulation_index = 0

    def simulate_card_detection(self, book_id: str):
        self._simulated_cards.append(book_id)

    def read_card(self) -> Optional[str]:
        if self._simulation_index < len(self._simulated_cards):
            card = self._simulated_cards[self._simulation_index]
            self._simulation_index += 1
            if card != self.last_card:
                self.last_card = card
                return card
        return None

class AudiobookController:
    def __init__(self):
        self.db = Database()
        self.rfid = RFIDReader()
        self.player: Optional[AudioPlayer] = None
        self.books: dict[str, Book] = {}
        self.running = True
        self._lock = threading.Lock()

        self.player = AudioPlayer(self.db, self._on_book_finished)

    def register_book(self, book_id: str, title: str, duration: int):
        self.books[book_id] = Book(id=book_id, title=title, duration=duration)

    def _on_book_finished(self, book_id: str):
        with self._lock:
            self.db.delete_progress(book_id)

    def handle_new_card(self, book_id: str):
        with self._lock:
            if book_id not in self.books:
                return

            book = self.books[book_id]

            if self.player.is_playing and self.player.current_book:
                if self.player.current_book.id == book_id:
                    return
                self.player.stop()

            self.player.play(book)

    def run(self):
        while self.running:
            card_id = self.rfid.read_card()

            if card_id:
                self.handle_new_card(card_id)

            time.sleep(0.1)

if __name__ == "__main__":
    controller = AudiobookController()

    controller.register_book("BOOK001", "The Great Gatsby", 50)
    controller.register_book("BOOK002", "1984", 75)
