```javascript
const fs = require('fs');
const path = require('path');
const vm = require('vm');

const moduleCache = {};

function loadModule(filename, options = {}) {
  const absolutePath = path.resolve(filename);

  if (moduleCache[absolutePath]) {
    return moduleCache[absolutePath];
  }

  try {
    const code = fs.readFileSync(absolutePath, 'utf8');
    const module = { exports: {} };
    const dirname = path.dirname(absolutePath);
    const wrapper = `(function(exports, require, module, __filename, __dirname) { ${code} \n});`;
    const compiled = vm.runInThisContext(wrapper, { filename: absolutePath });

    compiled(module.exports, require, module, absolutePath, dirname);

    if (typeof module.exports !== 'function') {
      throw new Error('Module does not export a function');
    }

    moduleCache[absolutePath] = module.exports;
    return module.exports;
  } catch (error) {
    throw new Error(`Failed to load module ${filename}: ${error.message}`);
  }
}
