 ```javascript
function generateId(length, base, input) {
  const chars = '0123456789abcdefghijklmnopqrstuvwxyz'.slice(0, base);
  let seed;

  if (input && input.length > 0) {
    seed = 0;
    for (let i = 0; i < input.length; i++) {
      seed = ((seed << 5) - seed) + input.charCodeAt(i);
      seed |= 0;
    }
    seed = Math.abs(seed);
  } else {
    seed = Math.floor(Math.random() * 2147483647);
  }

  const a = 1664525;
  const c = 1013904223;
  const m = 4294967296;
  let result = '';

  for (let i = 0; i < length; i++) {
    seed = (a * seed + c) % m;
    result += chars[Math.floor((seed / m) * base)];
  }

  return result;
}
