function findMatchingPattern(patterns, userAgent) {
  return patterns.reduce((match, item) => {
    if (match) return match;
    if (item.qualifier && !userAgent.startsWith(item.qualifier)) return null;
    const regex = item.pattern instanceof RegExp ? item.pattern : new RegExp(item.pattern);
    return regex.test(userAgent) ? item : null;
  }, null);
}
