 const fs = require('fs');
const path = require('path');

function handleStaticFile(req, res, filePath) {
    console.log(`Request: ${req.method} ${req.url} -> ${filePath}`);

    if (req.method !== 'GET' && req.method !== 'HEAD') {
        res.statusCode = 405;
        res.end('Method Not Allowed');
        return;
    }

    fs.stat(filePath, (err, stats) => {
        if (err || !stats.isFile()) {
            if (stats && stats.isDirectory() && !req.url.endsWith('/')) {
                res.statusCode = 301;
                res.setHeader('Location', req.url + '/');
                res.end();
                console.log(`301 Redirect to ${req.url}/`);
            } else {
                res.statusCode = 404;
                res.end('Not Found');
                console.log(`404 Not Found: ${filePath}`);
            }
            return;
        }

        const ext = path.extname(filePath);
        const contentType = {
            '.html': 'text/html',
            '.js': 'application/javascript',
            '.css': 'text/css',
            '.json': 'application/json',
            '.png': 'image/png',
            '.jpg': 'image/jpeg',
            '.gif': 'image/gif',
            '.svg': 'image/svg+xml'
        }[ext] || 'application/octet-stream';

        res.statusCode = 200;
        res.setHeader('Content-Type', contentType);
        res.setHeader('Content-Length', stats.size);

        if (req.method === 'HEAD') {
            res.end();
        } else {
            fs.createReadStream(filePath).pipe(res);
        }

        console.log(`200 OK: ${filePath} (${contentType})`);
    });
}

