function createFunctions(formatString) {
  const compare = new Function('a', 'b', formatString);
  const format = new Function('data', `
    const cmp = ${compare.toString()};
    if (!data || data.length === 0) return {minX: 0, minY: 0, maxX: 0, maxY: 0};
    let minX = data[0].x, maxX = data[0].x, minY = data[0].y, maxY = data[0].y;
    for (let i = 1; i < data.length; i++) {
      const item = data[i];
      if (cmp(item.x, minX) < 0) minX = item.x;
      if (cmp(item.x, maxX) > 0) maxX = item.x;
      if (cmp(item.y, minY) < 0) minY = item.y;
      if (cmp(item.y, maxY) > 0) maxY = item.y;
    }
    return {minX, minY, maxX, maxY};
  `);
  return {compare, format};
}
