 const fs = require('fs');
const path = require('path');

function checkRequiredExistence() {
  const required = ['package.json', 'node_modules', '.gitignore'];
  const found = new Set();

  function traverse(dir) {
    if (found.size === required.length) return;

    let entries;
    try {
      entries = fs.readdirSync(dir, { withFileTypes: true });
    } catch (e) {
      return;
    }

    for (const entry of entries) {
      if (required.includes(entry.name)) {
        found.add(entry.name);
      }

      if (entry.isDirectory()) {
        traverse(path.join(dir, entry.name));
      }
    }
  }

  traverse(process.cwd());
  return found.size === required.length;
}

