function validateFileExtension(fileInput, allowedExtensions, errorElementId) {
    const file = fileInput.files[0];
    if (!file) return false;

    const extPattern = allowedExtensions.map(ext => ext.replace('.', '')).join('|');
    const regex = new RegExp(`\\.(${extPattern})$`, 'i');

    if (!regex.test(file.name)) {
        const errorElement = document.getElementById(errorElementId);
        const message = `Invalid file type. Allowed extensions: ${allowedExtensions.join(', ')}`;

        if (errorElement) {
            errorElement.textContent = message;
            errorElement.style.display = 'block';
        } else {
            alert(message);
        }
        return false;
    }

    const errorElement = document.getElementById(errorElementId);
    if (errorElement) {
        errorElement.textContent = '';
        errorElement.style.display = 'none';
    }
    return true;
}
