 ```c
#include <stdint.h>
#include <stddef.h>

#define OFP_ACTION_HEADER_LEN 4
#define ERR_OK 0
#define ERR_INVALID_LENGTH 1
#define ERR_INVALID_TYPE 2
#define ERR_BUFFER_TOO_SMALL 3

typedef struct {
    int error_code;
    const char *error_message;
    uint16_t action_type;
    uint16_t action_length;
    const uint8_t *action_data;
    size_t action_data_len;
    size_t new_offset;
} action_result_t;

action_result_t parse_openflow_action(const uint8_t *buffer, size_t buf_len, size_t offset) {
    action_result_t result = {0};
    result.new_offset = offset;

    if (offset + OFP_ACTION_HEADER_LEN > buf_len) {
        result.error_code = ERR_BUFFER_TOO_SMALL;
        result.error_message = "Insufficient buffer for action header";
        return result;
    }

    const uint8_t *ptr = buffer + offset;
    uint16_t type = ((uint16_t)ptr[0] << 8) | ptr[1];
    uint16_t len = ((uint16_t)ptr[2] << 8) | ptr[3];

    if (len < OFP_ACTION_HEADER_LEN) {
        result.error_code = ERR_INVALID_LENGTH;
        result.error_message = "Action length smaller than header";
        return result;
    }

    if (offset + len > buf_len) {
        result.error_code = ERR_BUFFER_TOO_SMALL;
        result.error_message = "Action length exceeds buffer";
        return result;
    }

    if (type > 11 && type != 0xFFFF) {
        result.error_code = ERR_INVALID_TYPE;
        result.error_message = "Invalid action type";
        return result;
    }

    result.error_code = ERR_OK;
    result.error_message = NULL;
    result.action_type = type;
    result.action_length = len;
    result.action_data = ptr;
    result.action_data_len = len;
    result.new_offset = offset + len;

    return result;
}
