async function createAndLeaveChannel(apiBaseUrl, authToken, newChannelName, channelIdToLeave) {
  const headers = {
    'Authorization': `Bearer ${authToken}`,
    'Content-Type': 'application/json'
  };

  const createResponse = await fetch(`${apiBaseUrl}/rooms`, {
    method: 'POST',
    headers: headers,
    body: JSON.stringify({ name: newChannelName })
  });

  if (!createResponse.ok) {
    throw new Error(`Failed to create channel: ${createResponse.status}`);
  }

  const newChannel = await createResponse.json();

  const leaveResponse = await fetch(`${apiBaseUrl}/rooms/${channelIdToLeave}/leave`, {
    method: 'POST',
    headers: headers
  });

  if (!leaveResponse.ok) {
    throw new Error(`Failed to leave channel: ${leaveResponse.status}`);
  }

  return {
    newChannel: newChannel,
    leaveResult: await leaveResponse.json()
  };
}

 const fs = require('fs');
const path = require('path');

function getConfigValue(config, key) {
  if (Object.prototype.hasOwnProperty.call(config, key)) {
    return config[key];
  }

  let currentDir = process.cwd();
  const root = path.parse(currentDir).root;

  while (currentDir !== root) {
    const filePath = path.join(currentDir, `${key}.js`);
    if (fs.existsSync(filePath)) {
      try {
        const moduleExports = require(filePath);
        if (moduleExports && typeof moduleExports === 'object' && key in moduleExports) {
          config[key] = moduleExports[key];
          return config[key];
        }
      } catch (err) {
        // Continue searching
      }
    }
    const parentDir = path.dirname(currentDir);
    if (parentDir === currentDir) break;
    currentDir = parentDir;
  }

  currentDir = process.cwd();
  while (currentDir !== root) {
    const packagePath = path.join(currentDir, 'package.json');
    if (fs.existsSync(packagePath)) {
      try {
        const packageJson = JSON.parse(fs.readFileSync(packagePath, 'utf8'));
        if (key in packageJson) {
          config[key] = packageJson[key];
          return config[key];
        }
      } catch (err) {
        // Continue searching
      }
      break;
    }
    const parentDir = path.dirname(currentDir);
    if (parentDir === currentDir) break;
    currentDir = parentDir;
  }

  return undefined;
}

 ```javascript
function calculateLength(buffer, repeat, options) {
  const str = String(buffer);
  const { groupSeparator, radixPoint } = options;

  const escapedGroupSep = escapeRegex(groupSeparator);
  const escapedRadixPoint = escapeRegex(radixPoint);

  const cleanStr = str.replace(new RegExp(escapedGroupSep, 'g'), '');
  const parts = cleanStr.split(new RegExp(escapedRadixPoint));

  const integerPart = parts[0] || '';
  const fractionalPart = parts[1] || '';
  const intLength = integerPart.length;

  const groupCount = (intLength > 0 && repeat > 0) ? Math.floor((intLength - 1) / repeat) : 0;
  const groupOffset = groupCount * groupSeparator.length;

  const length = intLength + groupOffset + 
                 (fractionalPart.length > 0 ? radixPoint.length + fractionalPart.length : 0);

  return { length, groupOffset };
}
