const fs = require('fs').promises;
const path = require('path');
const less = require('less');

async function compileLessFiles(directory) {
  const result = {};

  async function recurse(dir) {
    const entries = await fs.readdir(dir, { withFileTypes: true });

    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);

      if (entry.isDirectory()) {
        await recurse(fullPath);
      } else if (entry.name.endsWith('.less')) {
        const cssPath = fullPath.replace(/\.less$/, '.css');
        const content = await fs.readFile(fullPath, 'utf8');
        const compiled = await less.render(content);
        await fs.writeFile(cssPath, compiled.css);
        result[cssPath] = fullPath;
      }
    }
  }

  await recurse(directory);
  return result;
}
