function findAlerts(duration, searchString) {
  const lines = duration.split('\n');
  let count = 0;
  let firstLine = -1;
  let firstColumn = -1;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const idx = line.indexOf(searchString);
    if (idx !== -1) {
      count++;
      if (firstLine === -1) {
        firstLine = i + 1;
        firstColumn = idx + 1;
      }
    }
  }

  return {
    count: count,
    jumpTarget: firstLine !== -1 ? { line: firstLine, column: firstColumn } : null
  };
}
