 import fs from 'fs/promises';
import path from 'path';
import _ from 'lodash';
import * as sass from 'sass';
import ts from 'typescript';

const fileUtils = {
  async deletePatterns(patterns) {
    const matches = await Promise.all(
      patterns.map(p => fs.glob(p).catch(() => []))
    );
    const files = _.uniq(_.flatten(matches));
    const results = await Promise.allSettled(
      files.map(f => fs.unlink(f))
    );
    return _.zipObject(files, results.map(r => r.status === 'fulfilled'));
  },

  async insertText(filePath, text, position = 'end') {
    let content = await fs.readFile(filePath, 'utf8').catch(() => '');
    const strategies = {
      start: () => text + content,
      end: () => content + text,
      middle: () => {
        const mid = Math.floor(content.length / 2);
        return content.slice(0, mid) + text + content.slice(mid);
      }
    };

    if (_.isNumber(position)) {
      content = content.slice(0, position) + text + content.slice(position);
    } else if (_.isFunction(position)) {
      content = position(content, text);
    } else {
      content = (strategies[position] || strategies.end)();
    }

    await fs.writeFile(filePath, content);
    return content.length;
  },

  async concatenate(sourceFiles, outputFile) {
    const contents = await Promise.all(
      sourceFiles.map(f => fs.readFile(f, 'utf8').catch(() => null))
    );
    const valid = _.compact(contents);
    const categorized = _.groupBy(valid, (c, i) => path.extname(sourceFiles[i]));
    const ordered = _.flatMap(['.css', '.scss', '.ts', '.js'], ext => 
      categorized[ext] || []
    );
    const merged = ordered.join('\n');
    await fs.writeFile(outputFile, merged);
    return { output: outputFile, bytes: merged.length, sources: valid.length };
  }
};

const compilers = {
  sassToCss(input, output, options = {}) {
    const result = sass.compile(input, _.pick(options, ['style', 'loadPaths']));
    return fs.writeFile(output, result.css).then(() => ({
      css: result.css,
      stats: result.stats
    }));
  },

  typescriptToJs(files, outDir) {
    const options = {
      outDir,
      module: ts.ModuleKind.ESNext,
      target: ts.ScriptTarget.ES2020,
      declaration: true,
      strict: true
    };

    const program = ts.createProgram(files, options);
    const emitResult = program.emit();
    const diagnostics = ts.getPreEmitDiagnostics(program).concat(emitResult.diagnostics);

    return {
      success: !emitResult.emitSkipped,
      files: _.map(files, f => path.relative(process.cwd(), f)),
      errors: diagnostics.map(d => ts.flattenDiagnosticMessageText(d.messageText, '\n'))
    };
  }
};

async function executeWorkflow(config) {
  const { cleanup, build, transform, bundle } = _.groupBy(config, 'phase');

  if (cleanup) {
    const toDelete = _.flatMap(cleanup, 'patterns');
    await fileUtils.deletePatterns(toDelete);
  }

  const buildResults = [];

  if (build) {
    const sassTasks = _.filter(build, { type: 'sass' });
    const tsTasks = _.filter(build, { type: 'typescript' });

    await Promise.all(_.map(sassTasks, async task => {
      const res = await compilers.sassToCss(task.input, task.output, task.options);
      buildResults.push({ type: 'sass', ...res });
    }));

    if (tsTasks.length) {
      const files = _.map(tsTasks, 'input');
      const result = compilers.typescriptToJs(files, './dist');
      buildResults.push({ type: 'typescript', ...result });
    }
  }

  if (transform) {
    for (const task of transform) {
      await fileUtils.insertText(
        task.file, 
        task.content, 
        task.position
      );
    }
  }

  if (bundle) {
    for (const task of bundle) {
      await fileUtils.concatenate(task.inputs, task.output);
    }
  }

  const summary = _.mapValues(
    _.groupBy(buildResults, 'type'),
    items => _.map(items, i => _.pick(i, ['output', 'bytes', 'success']))
  );

  return _.merge(summary, {
    processed: _.sumBy(buildResults, r => r.bytes || 0),
    timestamp: new Date().toISOString()
  });
}

const workflow = [
  { phase: 'cleanup', patterns: ['./dist/*', './temp/*.js'] },
  { phase: 'build', type: 'sass', input: './src/theme.scss', output: './dist/theme.css' },
  { phase: 'build', type: 'typescript', input: './src/index.ts' },
  { phase: 'build', type: 'typescript', input: './src/utils.ts' },
  { phase: 'transform', file: './dist/index.js', content: '/* Built */\n', position: 'start' },
  { phase: 'bundle', inputs: ['./dist/theme.css', './dist/index.js'], output: './dist/app.bundle' }
];

executeWorkflow(workflow)
  .then(report => console.log(JSON.stringify(report, null, 2)))
  .catch(console.error);

