const fs = require('fs').promises;
const path = require('path');

async function checkFilesInDirectories(rootPath, targetFiles) {
  const results = [];

  async function traverse(currentPath) {
    try {
      const entries = await fs.readdir(currentPath, { withFileTypes: true });
      const files = entries.filter(e => e.isFile()).map(e => e.name);
      const directories = entries.filter(e => e.isDirectory()).map(e => e.name);

      const foundFiles = targetFiles.filter(file => files.includes(file));

      if (foundFiles.length > 0) {
        results.push({
          directory: currentPath,
          found: foundFiles,
          missing: targetFiles.filter(f => !files.includes(f))
        });
      }

      for (const dir of directories) {
        await traverse(path.join(currentPath, dir));
      }
    } catch (error) {
      // Skip directories that can't be read
    }
  }

  await traverse(rootPath);
  return results;
}
