function dfsAndPlant(grid, startX, startY, maxNodes) {
  if (maxNodes <= 0 || !grid || grid.length === 0) return;

  const rows = grid.length;
  const cols = grid[0].length;

  function dfs(x, y) {
    if (x < 0 || x >= cols || y < 0 || y >= rows) return;
    const node = grid[y][x];
    if (!node || node.state === 'visited') return;

    node.state = 'visited';

    dfs(x + 1, y);
    dfs(x - 1, y);
    dfs(x, y + 1);
    dfs(x, y - 1);
  }

  if (startX >= 0 && startX < cols && startY >= 0 && startY < rows) {
    dfs(startX, startY);
  }

  const randX = Math.floor(Math.random() * cols);
  const randY = Math.floor(Math.random() * rows);

  grid[randY][randX] = {
    x: randX,
    y: randY,
    value: Math.random(),
    state: 'unvisited'
  };

  dfsAndPlant(grid, randX, randY, maxNodes - 1);
}
