        require.js(moduleUrl, function(err, module) {
            firstLoadTime = Date.now() - firstLoadTime;
            firstModule = module;

            strictEqual(err, null, "First load succeeds");
            ok(module, "First load returns module");

            var secondLoadTime = Date.now();
            require.js(moduleUrl, function(err, module) {
                secondLoadTime = Date.now() - secondLoadTime;

                strictEqual(module, firstModule, "Same cached instance returned");
                start();
            });
        });
    });

    asyncTest("Error handling for missing module", function() {
        expect(2);

        require.js("non-existent-module.js", function(err, module) {
            ok(err instanceof Error || err !== null, "Error returned for 404");
            strictEqual(module, undefined, "No module returned on error");
            start();
        });
    });

    asyncTest("Error handling for network failure", function() {
        expect(1);

        require.js("http://invalid-domain-12345.com/module.js", function(err) {
            ok(err, "Network error properly caught");
            start();
        });
    });
