const fs = require('fs');

function loadMultipleFiles(filePaths, callback) {
  const results = {};
  let completed = 0;
  let hasError = false;
  const total = filePaths.length;

  if (total === 0) {
    return callback(null, results);
  }

  filePaths.forEach((filePath) => {
    fs.readFile(filePath, 'utf8', (err, data) => {
      if (hasError) return;

      if (err) {
        hasError = true;
        return callback(err);
      }

      results[filePath] = data;
      completed++;

      if (completed === total) {
        callback(null, results);
      }
    });
  });
}

module.exports = loadMultipleFiles;

