 ```ruby
require 'thread'

class DMAController
  attr_reader :mandatory_queue, :request_queue, :response_queue, :sequencer, :network

  def initialize(network)
    @mandatory_queue = Queue.new
    @request_queue = Queue.new
    @response_queue = Queue.new
    @network = network
    @sequencer = nil
    @directory_controllers = []
    @running = false
  end

  def attach_sequencer(sequencer)
    @sequencer = sequencer
    sequencer.attach_controller(self)
  end

  def connect_directory_controller(controller)
    @directory_controllers << controller
  end

  def start
    @running = true
    @worker_thread = Thread.new { process_queues }
  end

  def stop
    @running = false
    @worker_thread.join if @worker_thread
  end

  def send_request(directory_id, request)
    @request_queue << { type: :request, dir_id: directory_id, data: request }
  end

  def send_response(directory_id, response)
    @response_queue << { type: :response, dir_id: directory_id, data: response }
  end

  def receive_from_network(packet)
    @mandatory_queue << packet
  end

  private

  def process_queues
    while @running
      process_mandatory_queue
      process_request_queue
      process_response_queue
      sleep 0.01
    end
  end

  def process_mandatory_queue
    return if @mandatory_queue.empty?
    packet = @mandatory_queue.pop
    handle_packet(packet)
  end

  def process_request_queue
    return if @request_queue.empty?
    req = @request_queue.pop
    dir_controller = @directory_controllers[req[:dir_id]]
    dir_controller.receive_request(req[:data]) if dir_controller
  end

  def process_response_queue
    return if @response_queue.empty?
    resp = @response_queue.pop
    dir_controller = @directory_controllers[resp[:dir_id]]
    dir_controller.receive_response(resp[:data]) if dir_controller
  end

  def handle_packet(packet)
    case packet[:type]
    when :memory_request
      @sequencer.schedule_transfer(packet) if @sequencer
    when :directory_response
      @response_queue << packet
    end
  end
end

class DMASequencer
  attr_reader :controller

  def initialize
    @controller = nil
    @transfers = []
  end

  def attach_controller(controller)
    @controller = controller
  end

  def schedule_transfer(packet)
    @transfers << packet
    execute_transfer(packet)
  end

  def execute_transfer(packet)
    src = packet[:source]
    dst = packet[:destination]
    size = packet[:size]

    data = read_memory(src, size)
    write_memory(dst, data)

    completion = { type: :completion, source: src, destination: dst }
    @controller.send_response(packet[:dir_id], completion) if packet[:dir_id]
  end

  private

  def read_memory(address, size)
    "data_#{address}_#{size}"
  end

  def write_memory(address, data)
    true
  end
end

class DirectoryController
  attr_reader :id, :name

  def initialize(id, name)
    @id = id
    @name = name
    @request_queue = Queue.new
    @response_queue = Queue.new
  end

  def receive_request(request)
    @request_queue << request
    process_request(request)
  end

  def receive_response(response)
    @response_queue << response
  end

  def send_request_to_dma(dma_controller, request)
    dma_controller.receive_from_network({ type: :directory_request, dir_id: @id, data: request })
  end

  private

  def process_request(request)
    response = { type: :directory_ack, request_id: request.object_id }
    @response_queue << response
  end
end

class Network
  attr_reader :dma_controllers, :directory_controllers

  def initialize
    @dma_controllers = []
    @directory_controllers = []
    @packet_queue = Queue.new
    @running = false
  end

  def register_dma_controller(controller)
    @dma_controllers << controller
  end

  def register_directory_controller(controller)
    @directory_controllers << controller
  end

  def send_packet(from, to, packet)
    @packet_queue << { from: from, to: to, data: packet }
  end

  def start
    @running = true
    @network_thread = Thread.new { route_packets }
  end

  def stop
    @running = false
    @network_thread.join if @network_thread
  end

  private

  def route_packets
    while @running
      unless @packet_queue.empty?
        packet = @packet_queue.pop
        deliver_packet(packet)
      end
      sleep 0.01
    end
  end

  def deliver_packet(packet)
    target = packet[:to]
    if target.is_a?(DMAController)
      target.receive_from_network(packet[:data])
    elsif target.is_a?(DirectoryController)
      target.receive_request(packet[:data])
    end
  end
end

network = Network.new
dma_controller = DMAController.new(network)
network.register_dma_controller(dma_controller)

sequencer = DMASequencer.new
dma_controller.attach_sequencer(sequencer)

dir_controller1 = DirectoryController.new(0, "Directory0")
dir_controller2 = DirectoryController.new(1, "Directory1")

network.register_directory_controller(dir_controller1)
network.register_directory_controller(dir_controller2)

dma_controller.connect_directory_controller(dir_controller1)
dma_controller.connect_directory_controller(dir_controller2)

network.start
dma_controller.start

dma_controller.send_request(0, { address: 0x1000, size: 64, operation: :read })
dma_controller.send_response(0, { status: :ack, data: "result" })

sleep 1

dma_controller.stop
network.stop
