import sqlite3

def get_row_counts(db_path, table_names):
    if not table_names:
        return {}

    conn = sqlite3.connect(db_path)
    try:
        cursor = conn.cursor()

        first_table = table_names[0]
        cursor.execute(f'PRAGMA table_info("{first_table}")')
        first_info = cursor.fetchall()

        if not first_info:
            raise ValueError(f"Table '{first_table}' does not exist")

        first_schema = tuple((row[1], row[2], row[3], row[5]) for row in first_info)
        counts = {}

        for table in table_names:
            cursor.execute(f'PRAGMA table_info("{table}")')
            info = cursor.fetchall()

            if not info:
                raise ValueError(f"Table '{table}' does not exist")

            schema = tuple((row[1], row[2], row[3], row[5]) for row in info)
            if schema != first_schema:
                raise ValueError(f"Schema mismatch between '{first_table}' and '{table}'")

            cursor.execute(f'SELECT COUNT(*) FROM "{table}"')
            count = cursor.fetchone()[0]

            if count == 0:
                raise ValueError(f"Table '{table}' has zero rows")

            counts[table] = count

        return counts
    finally:
        conn.close()
