import subprocess
import re

def adjust_volume(command):
    try:
        if command == 'up':
            subprocess.run(['amixer', 'set', 'Master', '5%+'], check=True, capture_output=True)
        elif command == 'down':
            subprocess.run(['amixer', 'set', 'Master', '5%-'], check=True, capture_output=True)
        else:
            return "Error: Unrecognized command"

        result = subprocess.run(['amixer', 'get', 'Master'], capture_output=True, text=True, check=True)
        match = re.search(r'\[(\d+%)\]', result.stdout)
        if match:
            return match.group(1)
        return "Error: Unable to retrieve volume"
    except subprocess.CalledProcessError:
        return "Error: Volume adjustment failed"
    except Exception:
        return "Error: Unexpected error"
