class Controller
  attr_reader :id, :sequencers, :version, :cache, :io_bus

  def initialize(id, version, cache, io_bus)
    @id = id
    @version = version
    @cache = cache
    @io_bus = io_bus
    @sequencers = []
  end

  def add_sequencer(sequencer)
    @sequencers << sequencer unless @sequencers.include?(sequencer)
    sequencer.controller = self
  end
end

class Sequencer
  attr_reader :id, :version, :cache, :io_bus
  attr_accessor :controller

  def initialize(id, version, cache, io_bus)
    @id = id
    @version = version
    @cache = cache
    @io_bus = io_bus
    @controller = nil
  end
end

class SystemConfigurator
  attr_reader :controllers, :sequencers

  def initialize(version, cache, io_bus)
    @version = version
    @cache = cache
    @io_bus = io_bus
    @controllers = []
    @sequencers = []
  end

  def configure(sequence_count)
    sequence_count.times do |i|
      controller = Controller.new(i, @version, @cache, @io_bus)
      sequencer = Sequencer.new(i, @version, @cache, @io_bus)

      controller.add_sequencer(sequencer)

      @controllers << controller
      @sequencers << sequencer
    end
  end
end
