import subprocess

def execute_command(command, expected_success):
    process = subprocess.Popen(command, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    stdout, stderr = process.communicate()
    return_code = process.returncode

    if expected_success:
        assert return_code == 0, f"Command failed with return code {return_code}: {stderr.decode()}"
