def execute_sandboxed(code, local_vars=None, global_vars=None):
    if not code:
        return None

    safe_globals = {
        "__builtins__": {
            "True": True, "False": False, "None": None,
            "abs": abs, "all": all, "any": any, "bool": bool,
            "chr": chr, "dict": dict, "dir": dir, "enumerate": enumerate,
            "filter": filter, "float": float, "format": format,
            "hasattr": hasattr, "hash": hash, "hex": hex, "id": id,
            "int": int, "isinstance": isinstance, "issubclass": issubclass,
            "iter": iter, "len": len, "list": list, "map": map,
            "max": max, "min": min, "next": next, "oct": oct,
            "ord": ord, "pow": pow, "print": print, "range": range,
            "repr": repr, "reversed": reversed, "round": round,
            "set": set, "slice": slice, "sorted": sorted, "str": str,
            "sum": sum, "tuple": tuple, "type": type, "zip": zip,
        }
    }

    if global_vars:
        safe_globals.update(global_vars)

    exec_locals = dict(local_vars) if local_vars else {}

    try:
        return eval(code, safe_globals, exec_locals)
    except SyntaxError:
        exec(code, safe_globals, exec_locals)
        return None
