def handle_get_request(request, write):
    if request.method != 'GET':
        return

    if_none_match = request.headers.get('If-None-Match')
    if if_none_match and if_none_match == request.response.etag:
        request.response.status_code = 304
        return 304

    content = request.response.content
    if 'Content-Length' not in request.response.headers:
        request.response.headers['Content-Length'] = str(len(content))

    write(content)
