import sys

def custom_reraise(exc_info, context=""):
    exc_type, exc_value, exc_traceback = exc_info
    new_msg = "{}: {}".format(context, exc_value) if context else str(exc_value)

    if sys.version_info >= (3,):
        new_exc = exc_type(new_msg)
        new_exc.__cause__ = exc_value
        raise new_exc.with_traceback(exc_traceback)
    else:
        exec("raise exc_type(new_msg), None, exc_traceback")

def version_compatible_handler(url):
    try:
        if sys.version_info >= (3,):
            from urllib.parse import urlparse
            from io import StringIO
        else:
            from urlparse import urlparse
            from StringIO import StringIO

        parsed = urlparse(url)
        buffer = StringIO()
        buffer.write(str(parsed.path))
        return buffer.getvalue()

    except Exception:
        custom_reraise(sys.exc_info(), "Error processing URL")
