import os
import types

def load_config(filename, silent=False):
    try:
        if not os.path.exists(filename):
            if not silent:
                print(f"Configuration file not found: {filename}")
            return False

        config_module = types.ModuleType('config')
        config_module.__file__ = os.path.abspath(filename)

        with open(filename, 'rb') as f:
            exec(compile(f.read(), filename, 'exec'), config_module.__dict__)

        globals()['config'] = config_module
        return True

    except Exception as e:
        if not silent:
            print(f"Error loading configuration: {e}")
        return False
