 ```python
import os
import hashlib

def calculate_md5_hashes(directory_path):
    file_hashes = {}

    for filename in os.listdir(directory_path):
        file_path = os.path.join(directory_path, filename)
        if os.path.isfile(file_path):
            md5_hash = hashlib.md5()
            with open(file_path, 'rb') as f:
                for chunk in iter(lambda: f.read(4096), b''):
                    md5_hash.update(chunk)
            file_hashes[filename] = md5_hash.hexdigest()

    sorted_hashes = dict(sorted(file_hashes.items(), key=lambda item: item[1]))

    return {
        "number_of_test_cases": len(sorted_hashes),
        "file_hashes": sorted_hashes
    }
```

