```python
import subprocess
import shlex
from typing import Union, Optional

def run_command(
    cmd: Union[str, list], 
    use_sudo: bool = False, 
    password: Optional[str] = None, 
    shell: bool = False
) -> str:
    if isinstance(cmd, str) and not shell:
        cmd = shlex.split(cmd)

    if use_sudo:
        if isinstance(cmd, str):
            if shell:
                cmd = f"sudo {cmd}"
            else:
                cmd = ["sudo"] + shlex.split(cmd)
        else:
            cmd = ["sudo"] + list(cmd)

        if password:
            if isinstance(cmd, list):
                cmd.insert(1, "-S")
            else:
                cmd = cmd.replace("sudo", "sudo -S", 1)

    try:
        kwargs = {
            "shell": shell,
            "capture_output": True,
            "text": True
        }

        if password and use_sudo:
            kwargs["input"] = password + "\n"

        result = subprocess.run(cmd, **kwargs, check=True)
        return result.stdout

    except subprocess.CalledProcessError as e:
        error_msg = f"Command failed with exit code {e.returncode}"
        if e.stderr:
            error_msg += f": {e.stderr.strip()}"
        raise RuntimeError(error_msg) from e
