 ```python
import hashlib
import hmac

def generate_api_message(*parts, secret_key=None, algorithm='sha256'):
    message = ''.join(str(part) for part in parts)
    message_bytes = message.encode('utf-8')

    if secret_key:
        key_bytes = secret_key.encode('utf-8') if isinstance(secret_key, str) else secret_key
        return hmac.new(key_bytes, message_bytes, getattr(hashlib, algorithm)).hexdigest()
    else:
        return hashlib.new(algorithm, message_bytes).hexdigest()
