 import java.io.BufferedReader;
import java.io.File;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class AntlrRunner {
    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: java AntlrRunner <directory> <file> [options...]");
            System.exit(1);
        }

        String directory = args[0];
        String file = args[1];
        List<String> options = Arrays.asList(Arrays.copyOfRange(args, 2, args.length));

        List<String> command = new ArrayList<>();
        command.add("antlr4");
        command.addAll(options);
        command.add(file);

        ProcessBuilder pb = new ProcessBuilder(command);
        pb.directory(new File(directory));
        pb.redirectErrorStream(true);

        try {
            Process process = pb.start();

            try (BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    System.out.println(line);
                }
            }

            int exitCode = process.waitFor();
            if (exitCode != 0) {
                System.err.println("ANTLR tool encountered errors (exit code: " + exitCode + ")");
                System.exit(exitCode);
            }
        } catch (IOException | InterruptedException e) {
            System.err.println("Error executing ANTLR: " + e.getMessage());
            System.exit(1);
        }
    }
}

