import hashlib
from functools import lru_cache

@lru_cache(maxsize=None)
def generate_hash_function(attributes):
    def hash_func(obj):
        values = (getattr(obj, attr) for attr in attributes)
        concatenated = ''.join(repr(v) for v in values)
        return hashlib.sha1(concatenated.encode('utf-8')).hexdigest()
    return hash_func
