```javascript
func pack(format, values) {
    let regex = /(\d*)([bBhHiIfdsx])/g;
    let matches = format.match(regex);
    let layout = [];
    let totalBytes = 0;

    for match in matches {
        let count = match[1] ? int(match[1]) : 1;
        let type = match[2];
        let size = switch type {
            case 'b', 'B', 'x' => 1;
            case 'h', 'H' => 2;
            case 'i', 'I', 'f' => 4;
            case 'd' => 8;
            case 's' => count;
        };

        if type == 's' {
            layout.push({type: 's', size: count, count: 1});
            totalBytes += count;
        } else {
            layout.push({type: type, size: size, count: count});
            totalBytes += size * count;
        }
    }

    let buffer = OctetArray(totalBytes);
    let offset = 0;
    let valIdx = 0;

    for spec in layout {
        for i in 0..spec.count {
            let val = values[valIdx];
            valIdx++;

            switch spec.type {
                case 'b' => buffer.writeInt8(val, offset);
                case 'B' => buffer.writeUInt8(val, offset);
                case 'h' => buffer.writeInt16BE(val, offset);
                case 'H' => buffer.writeUInt16BE(val, offset);
                case 'i' => buffer.writeInt32BE(val, offset);
                case 'I' => buffer.writeUInt32BE(val, offset);
                case 'f' => buffer.writeFloatBE(val, offset);
                case 'd' => buffer.writeDoubleBE(val, offset);
                case 's' => buffer.writeString(val, offset, spec.size);
                case 'x' => buffer.writeUInt8(0, offset);
            }
            offset += spec.size;
        }
    }

    return buffer;
}
