```javascript
function modifyEvent(event, element) {
    var type = event.type || '',
        dot = type.indexOf('.'),
        namespace = '';

    if (dot !== -1) {
        namespace = type.substring(dot + 1);
        type = type.substring(0, dot);
    }

    event.type = type;
    event.namespace = namespace;
    event.namespaceRegex = namespace ? new RegExp('(^|\\.)' + namespace.split('.').join('\\.(?:.*\\.)?') + '(\\.|$)') : null;
    event.target = event.target || element;
    event.delegateTarget = element;
    event.handlerArgs = [event].concat(event.data || []);

    return event;
}
