 const createUniqueIdentifier = (() => {
  const cache = new Map();
  let counter = 0;

  return function(key) {
    if (cache.has(key)) {
      return cache.get(key);
    }

    counter++;
    const random = Math.random().toString(36).substring(2, 8);
    const identifier = `${counter}-${random}`;

    cache.set(key, identifier);
    return identifier;
  };
})();

 const Promise = require('bluebird');
const axios = require('axios');
const fileUploader = require('file-uploader');
const logger = require('logger');

const uploadAsync = Promise.promisify(fileUploader.upload);

module.exports = function uploadFileFromUrl(fileUrl) {
  return Promise.try(() => axios.get(fileUrl, { responseType: 'arraybuffer' }))
    .then(response => {
      if (response.status !== 200) {
        throw new Error(`Failed to download file: ${response.status}`);
      }
      return uploadAsync(Buffer.from(response.data));
    })
    .then(uploadResult => {
      logger.info(`Successfully uploaded file from ${fileUrl} to ${uploadResult.url}`);
      return uploadResult.url;
    })
    .catch(error => {
      logger.error(`Error uploading file from ${fileUrl}: ${error.message}`);
      throw error;
    });
};

