function getRandomGreeting() {
  const greetings = {
    morning: ["Good morning!", "Rise and shine!", "Top of the morning!", "Morning sunshine!"],
    afternoon: ["Good afternoon!", "Hope you're having a great day!", "Afternoon greetings!", "Hello there!"],
    evening: ["Good evening!", "Hope you had a nice day!", "Evening greetings!", "Nice to see you!"]
  };

  const hour = new Date().getHours();
  let selectedGreetings;

  if (hour >= 5 && hour < 12) {
    selectedGreetings = greetings.morning;
  } else if (hour >= 12 && hour < 18) {
    selectedGreetings = greetings.afternoon;
  } else if (hour >= 18 && hour < 22) {
    selectedGreetings = greetings.evening;
  } else {
    return "Hello!";
  }

  return selectedGreetings[Math.floor(Math.random() * selectedGreetings.length)];
}
