 import React, { useState, useEffect } from 'react';

const ProjectInfo = ({ jsonUrl, repoUrl }) => {
  const [versions, setVersions] = useState([]);
  const [latestStable, setLatestStable] = useState(null);
  const [selectedVersion, setSelectedVersion] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch(jsonUrl)
      .then(response => {
        if (!response.ok) throw new Error('Failed to fetch');
        return response.json();
      })
      .then(data => {
        const versionList = data.versions || data;
        setVersions(versionList);
        const stable = versionList.find(v => v.stable) || versionList[0];
        setLatestStable(stable);
        setLoading(false);
      })
      .catch(err => {
        setError(err.message);
        setLoading(false);
      });
  }, [jsonUrl]);

  if (loading) return <div>Loading project information...</div>;
  if (error) return <div>Error loading data: {error}</div>;

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', maxWidth: '900px', margin: '0 auto', padding: '20px' }}>
      <header style={{ marginBottom: '30px', borderBottom: '2px solid #eee', paddingBottom: '20px' }}>
        <h1>Software Project</h1>
        <div style={{ background: '#f0f8ff', padding: '15px', borderRadius: '8px', marginTop: '15px' }}>
          <h2 style={{ margin: '0 0 10px 0', fontSize: '1.2em' }}>Latest Stable Version</h2>
          <p style={{ margin: '5px 0', fontSize: '1.5em', fontWeight: 'bold' }}>
            {latestStable?.version || latestStable?.name || 'Unknown'}
          </p>
          <p style={{ margin: '5px 0', color: '#666' }}>
            Released: {latestStable?.date || 'N/A'}
          </p>
          <a 
            href={repoUrl} 
            target="_blank" 
            rel="noopener noreferrer"
            style={{ color: '#0366d6', textDecoration: 'none', fontWeight: 'bold' }}
          >
            View Repository on GitHub →
          </a>
        </div>
      </header>

      <div style={{ display: 'flex', gap: '30px' }}>
        <aside style={{ flex: '0 0 250px' }}>
          <h3>All Versions</h3>
          <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
            {versions.map((version, index) => (
              <li 
                key={index}
                onClick={() => setSelectedVersion(version)}
                style={{
                  padding: '10px',
                  marginBottom: '5px',
                  cursor: 'pointer',
                  borderRadius: '5px',
                  backgroundColor: selectedVersion === version ? '#e1f5fe' : '#f5f5f5',
                  borderLeft: version.stable ? '4px solid #4caf50' : '4px solid transparent',
                  fontWeight: selectedVersion === version ? 'bold' : 'normal'
                }}
              >
                {version.version || version.name}
                {version.stable && <span style={{ color: '#4caf50', fontSize: '0.8em', marginLeft: '5px' }}>●</span>}
              </li>
            ))}
          </ul>
        </aside>

        <main style={{ flex: 1 }}>
          {selectedVersion ? (
            <div style={{ background: '#fafafa', padding: '20px', borderRadius: '8px' }}>
              <h2 style={{ marginTop: 0 }}>Version Details</h2>
              <div style={{ marginBottom: '15px' }}>
                <strong>Version:</strong> {selectedVersion.version || selectedVersion.name}
              </div>
              <div style={{ marginBottom: '15px' }}>
                <strong>Release Date:</strong> {selectedVersion.date || 'Not specified'}
              </div>
              <div style={{ marginBottom: '15px' }}>
                <strong>Status:</strong> {selectedVersion.stable ? 'Stable Release' : 'Development/Pre-release'}
              </div>
              {selectedVersion.changelog && (
                <div style={{ marginBottom: '15px' }}>
                  <strong>Changelog:</strong>
                  <pre style={{ 
                    background: 'white', 
                    padding: '15px', 
                    borderRadius: '5px', 
                    overflow: 'auto',
                    border: '1px solid #ddd',
                    fontSize: '0.9em'
                  }}>
                    {selectedVersion.changelog}
                  </pre>
                </div>
              )}
              <a 
                href={`${repoUrl}/releases/tag/${selectedVersion.version || selectedVersion.name}`}
                target="_blank"
                rel="noopener noreferrer"
                style={{ color: '#0366d6' }}
              >
                View this release on GitHub
              </a>
            </div>
          ) : (
            <div style={{ color: '#666', fontStyle: 'italic', padding: '40px', textAlign: 'center' }}>
              Select a version from the list to view details
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default ProjectInfo;

