function createListManager(listType) {
  const lists = {
    default: ['item1', 'item2', 'item3'],
    custom: ['customA', 'customB']
  };

  const store = {
    items: [...(lists[listType] || lists.default)]
  };

  store.dispatch = (action) => {
    switch (action?.type) {
      case 'ADD':
        store.items.push(action.payload);
        break;
      case 'REMOVE':
        store.items = store.items.filter(item => item !== action.payload);
        break;
      case 'SET':
        store.items = [...action.payload];
        break;
      case 'CLEAR':
        store.items = [];
        break;
    }
  };

  return store;
}
