function generateSessionId(secretKey, length) {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  let sessionId = '';

  for (let i = 0; i < length; i++) {
    const randomVal = Math.floor(Math.random() * chars.length);
    const secretVal = secretKey.charCodeAt(i % secretKey.length) % chars.length;
    sessionId += chars[(randomVal + secretVal) % chars.length];
  }

  return sessionId;
}
