  const index = this._hash(key);
  const bucket = this.buckets[index];

  for (let i = 0; i < bucket.length; i++) {
    if (bucket[i].key === key) {
      bucket[i].value = value;
      return this;
    }
  }

  bucket.push({ key, value });
  this.size++;

  if (this.size / this.capacity > 0.75) {
    this._resize();
  }

  return this;
