function numberListManager(initialList = []) {
  let list = [...initialList].sort((a, b) => a - b);

  return {
    add(number) {
      list.push(number);
      list.sort((a, b) => a - b);
      return this;
    },
    remove(number) {
      const index = list.indexOf(number);
      if (index !== -1) {
        list.splice(index, 1);
      }
      return this;
    },
    sort() {
      list.sort((a, b) => a - b);
      return this;
    },
    getList() {
      return [...list];
    }
  };
}
