function sortObjects(list, direction) {
    let result = list.slice();
    for (let i = 0; i < result.length; i++) {
        for (let j = 0; j < result.length - 1; j++) {
            let expr = direction === 'asc' ? 
                'result[j].value > result[j + 1].value' : 
                'result[j].value < result[j + 1].value';
            if (eval(expr)) {
                let temp = result[j];
                result[j] = result[j + 1];
                result[j + 1] = temp;
            }
        }
    }
    return result;
}
