async function traverseTree(nodes, currentId, path = '', cache = new Map()) {
  const currentNode = nodes.find(n => n.id === currentId);
  if (!currentNode) return;

  let subIndices = cache.get(currentId) || currentNode.subIndices;

  if (!subIndices) {
    const module = await import(`./subIndices-${currentId}.js`);
    subIndices = module.default || module.subIndices;
    cache.set(currentId, subIndices);
    currentNode.subIndices = subIndices;
  }

  for (const subId of subIndices) {
    const newPath = path ? `${path}/${subId}` : String(subId);
    await traverseTree(nodes, subId, newPath, cache);
  }
}
