 ```javascript
function jsonpRequest(url, method, payload, successCallback, failureCallback) {
    var callbackName = 'jsonp_callback_' + Math.random().toString(36).substr(2, 9);
    var script = document.createElement('script');
    script.type = 'text/javascript';

    var xhr = {
        response: null,
        status: 0,
        readyState: 4
    };

    window[callbackName] = function(data) {
        if (script.parentNode) {
            script.parentNode.removeChild(script);
        }
        delete window[callbackName];

        xhr.response = data;

        if (data && (data.status === 'error' || data.error || (typeof data.status === 'number' && data.status >= 400))) {
            xhr.status = typeof data.status === 'number' ? data.status : 400;
            if (failureCallback) failureCallback(xhr);
        } else {
            xhr.status = 200;
            if (successCallback) successCallback(xhr);
        }
    };

    var queryParams = '';
    if (payload) {
        var params = [];
        for (var key in payload) {
            if (payload.hasOwnProperty(key)) {
                params.push(encodeURIComponent(key) + '=' + encodeURIComponent(payload[key]));
            }
        }
        if (params.length > 0) {
            queryParams = '&' + params.join('&');
        }
    }

    var separator = url.indexOf('?') === -1 ? '?' : '&';
    script.src = url + separator + 'callback=' + callbackName + queryParams;

    document.head.appendChild(script);

    return xhr;
}
