function refreshDialogFields(resourceId, url, fieldNamesToRefresh) {
  var self = this;
  var fields = self.dialogFields || [];

  fields.forEach(function(field) {
    if (fieldNamesToRefresh.indexOf(field.name) !== -1) {
      var messageId = Math.random().toString(36).substr(2, 9);
      var payload = {
        type: 'refreshDialogField',
        resourceId: resourceId,
        url: url,
        fieldName: field.name,
        messageId: messageId
      };

      function onMessage(event) {
        if (event.data && event.data.messageId === messageId) {
          if (event.data.success) {
            field.value = event.data.result;
          }
          window.removeEventListener('message', onMessage);
        }
      }

      window.addEventListener('message', onMessage);
      window.parent.postMessage(payload, '*');
    }
  });
}
