const fs = require('fs');
const path = require('path');

function setupHandlersAndHelpers(config) {
  const handlers = {};
  const helpers = {};

  const loadDirectory = (directory, targetObject) => {
    if (!fs.existsSync(directory)) return;

    const files = fs.readdirSync(directory);

    files.forEach(file => {
      if (file.endsWith('.js') && file !== 'index.js') {
        const name = path.basename(file, '.js');
        const moduleExport = require(path.join(directory, file));

        if (typeof moduleExport === 'function') {
          targetObject[name] = moduleExport.bind(null, config);
        } else {
          targetObject[name] = moduleExport;
        }
      }
    });
  };

  loadDirectory(path.join(__dirname, 'handlers'), handlers);
  loadDirectory(path.join(__dirname, 'helpers'), helpers);

  return { handlers, helpers };
}

module.exports = setupHandlersAndHelpers;

