 ```javascript
function generateAndEvaluate(dimensions, valueFn = () => Math.floor(Math.random() * 100)) {
  const generate = (dims, depth = 0) => {
    if (depth === dims.length) return valueFn();
    return Array.from({ length: dims[depth] }, () => generate(dims, depth + 1));
  };

  const evaluate = (arr) => {
    let sum = 0, count = 0;
    const flatten = [];

    const traverse = (node) => {
      if (Array.isArray(node)) {
        node.forEach(traverse);
      } else {
        sum += node;
        count++;
        flatten.push(node);
      }
    };

    traverse(arr);
    return { sum, count, average: count ? sum / count : 0, flatten };
  };

  const array = generate(dimensions);
  const stats = evaluate(array);

  return { array, ...stats };
}
