 ```javascript
function setupAttributeObserver(attribute, initFn, cleanupFn) {
  var $ = window.jQuery || window.jqLite || window.$;
  if (!$) throw new Error('jQuery or jqLite required');

  var attrSelector = '[' + attribute + ']';

  $(attrSelector).each(function() { initFn($(this)); });

  var observer = new MutationObserver(function(mutations) {
    mutations.forEach(function(mutation) {
      Array.prototype.forEach.call(mutation.addedNodes, function(node) {
        if (node.nodeType === 1) {
          var $node = $(node);
          if ($node.is(attrSelector)) initFn($node);
          $node.find(attrSelector).each(function() { initFn($(this)); });
        }
      });

      if (cleanupFn) {
        Array.prototype.forEach.call(mutation.removedNodes, function(node) {
          if (node.nodeType === 1) {
            var $node = $(node);
            if ($node.is(attrSelector)) cleanupFn($node);
            $node.find(attrSelector).each(function() { cleanupFn($(this)); });
          }
        });
      }
    });
  });

  observer.observe(document.documentElement, { childList: true, subtree: true });

  return { stop: function() { observer.disconnect(); } };
}
