 ```javascript
function shuffleArray(array, times = 1) {
  const result = [...array];

  const swap = (i, j) => {
    [result[i], result[j]] = [result[j], result[i]];
  };

  for (let n = 0; n < times; n++) {
    for (let i = result.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      swap(i, j);
    }
  }

  return result;
}

shuffleArray.swap = (array, i, j) => {
  const result = [...array];
  [result[i], result[j]] = [result[j], result[i]];
  return result;
};
