function generateRandomPool() {
  const pool = new Uint8Array(32);
  if (typeof crypto !== 'undefined' && crypto.getRandomValues) {
    crypto.getRandomValues(pool);
  } else {
    for (let i = 0; i < 32; i++) {
      pool[i] = Math.floor(Math.random() * 256);
    }
  }
  generateRandomPool.pool = pool;
}
