function updatePolicyConfig(config, action = 'parse') {
  const defaults = {
    name: '',
    enabled: false,
    resources: [],
    applyPolicies: []
  };

  const updated = { ...defaults, ...config };

  if (action === 'parse') {
    if (typeof updated.resources === 'string') {
      updated.resources = JSON.parse(updated.resources);
    }
    if (typeof updated.applyPolicies === 'string') {
      updated.applyPolicies = JSON.parse(updated.applyPolicies);
    }
  } else if (action === 'stringify') {
    if (typeof updated.resources !== 'string') {
      updated.resources = JSON.stringify(updated.resources);
    }
    if (typeof updated.applyPolicies !== 'string') {
      updated.applyPolicies = JSON.stringify(updated.applyPolicies);
    }
  }

  return updated;
}
