```javascript
function generateUUID(length) {
  const chars = '0123456789abcdef';
  let uuid = '';

  for (let i = 0; i < 32; i++) {
    let char;
    if (i === 12) {
      char = '4';
    } else if (i === 16) {
      char = (8 + Math.floor(Math.random() * 4)).toString(16);
    } else {
      char = chars[Math.floor(Math.random() * 16)];
    }

    uuid += char;

    if (length === 36 && (i === 7 || i === 11 || i === 15 || i === 19)) {
      uuid += '-';
    }
  }

  return uuid;
}
