 ```javascript
function reloadCommand(client, commandName) {
    const command = client.commands.get(commandName) || client.commands.find(cmd => cmd.aliases && cmd.aliases.includes(commandName));
    if (!command) throw new Error(`Command \`${commandName}\` not found.`);

    const path = require.resolve(`./commands/${command.name}.js`);
    delete require.cache[path];

    client.commands.delete(command.name);
    if (command.aliases) {
        command.aliases.forEach(alias => client.aliases.delete(alias));
    }

    const newCommand = require(path);
    client.commands.set(newCommand.name, newCommand);
    if (newCommand.aliases) {
        newCommand.aliases.forEach(alias => client.aliases.set(alias, newCommand.name));
    }

    return newCommand;
}
