 ```javascript
function printDependencyTree(tree, startNames, maxLines) {
  let lineCount = 0;
  let truncated = false;
  const visited = new Set();

  function traverse(name, depth) {
    if (lineCount >= maxLines) {
      truncated = true;
      return;
    }

    console.log(' '.repeat(depth * 2) + name);
    lineCount++;

    if (lineCount >= maxLines) {
      truncated = true;
      return;
    }

    const children = tree[name] || [];
    for (const child of children) {
      if (!visited.has(child)) {
        visited.add(child);
        traverse(child, depth + 1);
        if (truncated) return;
      }
    }
  }

  for (const name of startNames) {
    if (!visited.has(name)) {
      visited.add(name);
      traverse(name, 0);
      if (truncated) break;
    }
  }

  if (truncated) {
    console.log("... (more dependencies beyond limit)");
  }
}
