function startIframeContent(iframe) {
  if (!iframe || !iframe.contentWindow || !iframe.src) return;

  const src = iframe.src.toLowerCase();
  let message;

  if (src.includes('youtube')) {
    message = JSON.stringify({ event: 'command', func: 'playVideo', args: [] });
  } else if (src.includes('vimeo')) {
    message = JSON.stringify({ method: 'play' });
  } else {
    message = JSON.stringify({ event: 'slide', value: 'start' });
  }

  iframe.contentWindow.postMessage(message, '*');
}

