import gulp from 'gulp';
import sass from 'gulp-sass';
import * as dartSass from 'sass';
import typescript from 'gulp-typescript';
import concat from 'gulp-concat';
import htmlmin from 'gulp-htmlmin';
import sourcemaps from 'gulp-sourcemaps';
import { deleteAsync } from 'del';

const sassCompiler = sass(dartSass);

const config = {
  paths: {
    src: {
      sass: 'src/scss/**/*.scss',
      ts: 'src/ts/**/*.ts',
      html: 'src/templates/**/*.html'
    },
    dest: {
      css: 'dist/css',
      js: 'dist/js',
      html: 'dist/templates',
      build: 'dist/build'
    },
    filenames: {
      css: 'app.min.css',
      js: 'app.min.js',
      html: 'templates.min.html'
    }
  },
  options: {
    sass: { outputStyle: 'compressed' },
    typescript: { target: 'ES6', module: 'commonjs' },
    htmlmin: { collapseWhitespace: true }
  }
};

function clean() {
  return deleteAsync([config.paths.dest.build]);
}

function compileSass() {
  return gulp.src(config.paths.src.sass)
    .pipe(sourcemaps.init())
    .pipe(sassCompiler(config.options.sass).on('error', sassCompiler.logError))
    .pipe(concat(config.paths.filenames.css))
    .pipe(sourcemaps.write('.'))
    .pipe(gulp.dest(config.paths.dest.css))
    .pipe(gulp.dest(config.paths.dest.build));
}

function compileTypeScript() {
  const tsProject = typescript.createProject(config.options.typescript);
  return gulp.src(config.paths.src.ts)
    .pipe(sourcemaps.init())
    .pipe(tsProject())
    .pipe(concat(config.paths.filenames.js))
    .pipe(sourcemaps.write('.'))
    .pipe(gulp.dest(config.paths.dest.js))
    .pipe(gulp.dest(config.paths.dest.build));
}

function compileHtml() {
  return gulp.src(config.paths.src.html)
    .pipe(htmlmin(config.options.htmlmin))
    .pipe(concat(config.paths.filenames.html))
    .pipe(gulp.dest(config.paths.dest.html))
    .pipe(gulp.dest(config.paths.dest.build));
}

function watch() {
  gulp.watch(config.paths.src.sass, compileSass);
  gulp.watch(config.paths.src.ts, compileTypeScript);
  gulp.watch(config.paths.src.html, compileHtml);
}

const build = gulp.series(clean, gulp.parallel(compileSass, compileTypeScript, compileHtml));

export { clean, compileSass, compileTypeScript, compileHtml, watch, build };
export default build;

 ```javascript
function createPropertyAccessors(target, namingConvention) {
  const cache = {};

  return function getAccessor(propertyName) {
    if (!namingConvention.test(propertyName)) {
      return function() {};
    }

    if (cache[propertyName]) {
      return cache[propertyName];
    }

    if (propertyName in target) {
      if (typeof target[propertyName] === 'function') {
        const wrapper = function(...args) {
          return target[propertyName].apply(target, args);
        };
        cache[propertyName] = wrapper;
        return wrapper;
      }

      const accessor = new Function('ctx', 'val', `
        if (arguments.length > 1) {
          ctx['${propertyName}'] = val;
          return val;
        }
        return ctx['${propertyName}'];
      `).bind(null, target);

      cache[propertyName] = accessor;
      return accessor;
    }

    return function() {};
  };
}
