 const fs = require('fs').promises;
const { exec } = require('child_process');
const util = require('util');
const path = require('path');

const execAsync = util.promisify(exec);

function parseArgs() {
  const args = process.argv.slice(2);
  const options = {};
  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--source') options.source = args[++i];
    else if (args[i] === '--dest') options.dest = args[++i];
    else if (args[i] === '--identity') options.identity = args[++i];
    else if (args[i] === '--file-to-sign') options.fileToSign = args[++i];
    else if (args[i] === '--package-output') options.packageOutput = args[++i];
  }
  return options;
}

async function copyFolder(source, dest) {
  await fs.cp(source, dest, { recursive: true, force: true });
}

async function codesignFile(filePath, identity) {
  const cmd = `codesign --force --deep --sign "${identity}" --timestamp --verbose "${filePath}"`;
  await execAsync(cmd);
}

async function buildPackage(source, output, identity) {
  const cmd = `pkgbuild --root "${source}" --sign "${identity}" --install-location /Applications "${output}"`;
  await execAsync(cmd);
}

async function main() {
  const opts = parseArgs();

  if (!opts.source || !opts.dest || !opts.identity || !opts.fileToSign || !opts.packageOutput) {
    console.error('Missing required arguments. Usage:');
    console.error('node script.js --source <src> --dest <dst> --identity <cert> --file-to-sign <relative-path> --package-output <pkg>');
    process.exit(1);
  }

  try {
    console.log(`Copying folder: ${opts.source} -> ${opts.dest}`);
    await copyFolder(opts.source, opts.dest);

    const signPath = path.join(opts.dest, opts.fileToSign);
    console.log(`Codesigning: ${signPath}`);
    await codesignFile(signPath, opts.identity);

    console.log(`Building package: ${opts.packageOutput}`);
    await buildPackage(opts.dest, opts.packageOutput, opts.identity);

    console.log('Success.');
  } catch (err) {
    console.error('Error:', err.message);
    if (err.stderr) console.error('Details:', err.stderr);
    process.exit(1);
  }
}

main();

