 ```javascript
function findMatchingNodes(root, selector, regex) {
  const matches = [];

  (function traverse(node) {
    if (node.nodeType !== Node.ELEMENT_NODE) return;

    let selectorMatch = !selector || node.matches(selector);
    let regexMatch = false;

    if (regex) {
      if (node.id && regex.test(node.id)) regexMatch = true;
      if (!regexMatch && node.classList) {
        for (const cls of node.classList) {
          if (regex.test(cls)) {
            regexMatch = true;
            break;
          }
        }
      }
    } else {
      regexMatch = true;
    }

    if (selectorMatch && regexMatch) {
      matches.push(node);
    }

    for (const child of node.children) {
      traverse(child);
    }
  })(root);

  return matches;
}
