```javascript
function updatePolicyFromForm(policy, formData) {
  policy.name = formData.name || policy.name;
  policy.description = formData.description || policy.description;
  policy.configuration = policy.configuration || {};

  if (formData.effect) {
    policy.configuration.effect = formData.effect;
  }

  if (formData.actions) {
    policy.configuration.actions = Array.isArray(formData.actions) 
      ? formData.actions 
      : formData.actions.split(',').map(a => a.trim());
  }

  if (formData.resources) {
    policy.resources = Array.isArray(formData.resources)
      ? formData.resources
      : formData.resources.split(',').map(r => r.trim());
  }

  if (formData.applyPolicies) {
    policy.applyPolicies = Array.isArray(formData.applyPolicies)
      ? formData.applyPolicies
      : formData.applyPolicies.split(',').map(p => p.trim());
  }

  Object.keys(formData).forEach(key => {
    if (!['name', 'description', 'effect', 'actions', 'resources', 'applyPolicies'].includes(key)) {
      policy.configuration[key] = formData[key];
    }
  });

  policy.resources = JSON.stringify(policy.resources || []);
  policy.applyPolicies = JSON.stringify(policy.applyPolicies || []);

  return policy;
}
