 const fs = require('fs');
const { Transform } = require('stream');
const path = require('path');

const VERSION = '1.0.0';

class VideoFrame {
  constructor(data, width, height, format, timestamp = 0) {
    this.data = data;
    this.width = width;
    this.height = height;
    this.format = format;
    this.timestamp = timestamp;
  }
}

async function readVideoFrames(filePath, options = {}) {
  const stats = await fs.promises.stat(filePath);
  if (!stats.isFile()) throw new Error('Path is not a file');

  const stream = fs.createReadStream(filePath);
  const frames = [];
  let buffer = Buffer.alloc(0);
  const frameSize = options.frameSize || 1024;

  return new Promise((resolve, reject) => {
    stream.on('data', chunk => {
      buffer = Buffer.concat([buffer, chunk]);
      while (buffer.length >= frameSize) {
        frames.push(new VideoFrame(
          buffer.slice(0, frameSize),
          options.width || 1920,
          options.height || 1080,
          options.format || 'raw'
        ));
        buffer = buffer.slice(frameSize);
      }
    });
    stream.on('end', () => resolve(frames));
    stream.on('error', reject);
  });
}

async function writeVideoFrames(filePath, frames, options = {}) {
  const stream = fs.createWriteStream(filePath);
  return new Promise((resolve, reject) => {
    stream.on('error', reject);
    stream.on('finish', resolve);
    frames.forEach(frame => {
      const data = frame instanceof VideoFrame ? frame.data : frame;
      stream.write(data);
    });
    stream.end();
  });
}

function convertFrameFormat(frame, targetFormat, options = {}) {
  if (!(frame instanceof VideoFrame)) throw new Error('Invalid frame type');
  const convertedData = Buffer.from(frame.data);

  if (options.pixelTransform) {
    for (let i = 0; i < convertedData.length; i++) {
      convertedData[i] = options.pixelTransform(convertedData[i], i);
    }
  }

  return new VideoFrame(
    convertedData,
    frame.width,
    frame.height,
    targetFormat,
    frame.timestamp
  );
}

function createFrameConverter(inputFormat, outputFormat) {
  return new Transform({
    objectMode: true,
    transform(chunk, encoding, callback) {
      try {
        const frame = chunk instanceof VideoFrame 
          ? chunk 
          : new VideoFrame(chunk, 0, 0, inputFormat);
        const converted = convertFrameFormat(frame, outputFormat);
        callback(null, converted);
      } catch (err) {
        callback(err);
      }
    }
  });
}

module.exports = {
  VERSION,
  VideoFrame,
  readVideoFrames,
  writeVideoFrames,
  convertFrameFormat,
  createFrameConverter
};

 ```jsx
import React, { useState, useMemo } from 'react';

const VersionList = ({ 
  versions = [], 
  repositoryUrl, 
  onVersionSelect,
  linkGenerator = (repo, ver) => `${repo}/releases/tag/${ver}`
}) => {
  const [selectedVersion, setSelectedVersion] = useState(null);

  const processedVersions = useMemo(() => {
    return versions.map(v => 
      typeof v === 'string' 
        ? { version: v, stable: !v.match(/-(alpha|beta|rc|dev|snapshot)/i) }
        : { ...v, stable: v.stable ?? !v.version?.match(/-(alpha|beta|rc|dev|snapshot)/i) }
    ).sort((a, b) => 
      b.version.localeCompare(a.version, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [versions]);

  const latestStable = useMemo(() => 
    processedVersions.find(v => v.stable) || processedVersions[0]
  , [processedVersions]);

  const handleChange = (e) => {
    const version = e.target.value;
    setSelectedVersion(version);
    onVersionSelect?.(version);
  };

  const displayVersion = selectedVersion || latestStable?.version;

  if (!processedVersions.length) return <div>No versions available</div>;

  return (
    <div className="version-list">
      <div className="latest-stable">
        <span className="label">Latest Stable:</span>
        <span className="version-tag">{latestStable?.version}</span>
        <a 
          href={linkGenerator(repositoryUrl, latestStable?.version)} 
          target="_blank" 
          rel="noopener noreferrer"
        >
          View Release
        </a>
      </div>

      <div className="selector">
        <label htmlFor="version-select">Version: </label>
        <select 
          id="version-select"
          value={displayVersion || ''} 
          onChange={handleChange}
        >
          {processedVersions.map(v => (
            <option key={v.version} value={v.version}>
              {v.version} {v.stable ? '(stable)' : '(pre-release)'}
            </option>
          ))}
        </select>
      </div>

      {selectedVersion && selectedVersion !== latestStable?.version && (
        <div className="selected-info">
          <a 
            href={linkGenerator(repositoryUrl, selectedVersion)} 
            target="_blank" 
            rel="noopener noreferrer"
          >
            View {selectedVersion} on Repository
          </a>
        </div>
      )}
    </div>
  );
};

export default VersionList;
