function createComparator([minX, minY, maxX, maxY]) {
  return {
    compareMinX: new Function('a', 'b', `return a.${minX} < b.${minX} ? -1 : a.${minX} > b.${minX} ? 1 : 0`),
    compareMinY: new Function('a', 'b', `return a.${minY} < b.${minY} ? -1 : a.${minY} > b.${minY} ? 1 : 0`),
    toBBox: new Function('a', `return {${minX}: a.${minX}, ${minY}: a.${minY}, ${maxX}: a.${maxX}, ${maxY}: a.${maxY}}`)
  };
