const zlib = require('zlib');

function decodeFingerprint(base64Data, callback) {
    const compressedBuffer = Buffer.from(base64Data, 'base64');

    zlib.inflate(compressedBuffer, (err, decompressedBuffer) => {
        if (err) {
            return callback(err);
        }

        const hexString = decompressedBuffer.toString('ascii');
        const codes = [];
        const times = [];

        for (let i = 0; i < hexString.length; i += 16) {
            const codeHex = hexString.substring(i, i + 8);
            const timeHex = hexString.substring(i + 8, i + 16);

            if (codeHex.length === 8) {
                codes.push(parseInt(codeHex, 16));
            }

            if (timeHex.length === 8) {
                times.push(parseInt(timeHex, 16));
            }
        }

        const fingerprint = {
            codes: codes,
            times: times
        };

        callback(null, fingerprint);
    });
}
