function findElements(root, selector, testFn) {
  const matches = [];

  function traverse(node) {
    if (node.nodeType === 1) {
      if (testFn(node, selector)) {
        matches.push(node);
      }
      for (let i = 0; i < node.children.length; i++) {
        traverse(node.children[i]);
      }
    }
  }

  traverse(root);
  return matches;
}
