 ```javascript
function createWorldMessenger(targetWindow, targetOrigin = '*') {
  const pendingRequests = new Map();
  let messageHandler = null;

  const generateId = () => Math.random().toString(36).substr(2, 9);

  const sendMessage = (type, payload, requestId = null) => {
    if (!targetWindow) return;
    const message = { type, payload, requestId, timestamp: Date.now() };
    targetWindow.postMessage(message, targetOrigin);
  };

  const setupListener = (handlers = {}) => {
    messageHandler = (event) => {
      if (targetOrigin !== '*' && event.origin !== targetOrigin) return;

      const { type, payload, requestId } = event.data || {};
      if (!type) return;

      if (type.endsWith('_RESPONSE') && pendingRequests.has(requestId)) {
        const { resolve } = pendingRequests.get(requestId);
        resolve(payload);
        pendingRequests.delete(requestId);
        return;
      }

      if (handlers[type]) {
        const response = handlers[type](payload);
        if (requestId && !type.endsWith('_RESPONSE')) {
          sendMessage(`${type}_RESPONSE`, response, requestId);
        }
      }
    };

    window.addEventListener('message', messageHandler);
    return () => window.removeEventListener('message', messageHandler);
  };

  const requestWorlds = () => {
    return new Promise((resolve) => {
      const requestId = generateId();
      pendingRequests.set(requestId, { resolve });
      sendMessage('GET_WORLDS', null, requestId);

      setTimeout(() => {
        if (pendingRequests.has(requestId)) {
          pendingRequests.delete(requestId);
          resolve([]);
        }
      }, 10000);
    });
  };

  const loadWorld = (worldData) => {
    sendMessage('LOAD_WORLD', worldData);
  };

  const navigateWorld = (worldId, options = {}) => {
    sendMessage('NAVIGATE_WORLD', { worldId, options });
  };

  const destroy = () => {
    if (messageHandler) {
      window.removeEventListener('message', messageHandler);
    }
    pendingRequests.clear();
  };

  return {
    setupListener,
    requestWorlds,
    loadWorld,
    navigateWorld,
    destroy,
    sendMessage
  };
}

function initMainWindowMessaging(popupUrl, targetOrigin) {
  const popup = window.open(popupUrl, 'WorldManager', 'width=800,height=600');
  const messenger = createWorldMessenger(popup, targetOrigin);

  messenger.setupListener({
    WORLD_LOADED: (data) => console.log('World loaded:', data),
    NAVIGATION_COMPLETE: (data) => console.log('Navigation complete:', data)
  });

  return messenger;
}

function initPopupMessaging(targetOrigin) {
  const messenger = createWorldMessenger(window.opener, targetOrigin);

  messenger.setupListener({
    GET_WORLDS: () => {
      return Array.from(document.querySelectorAll('[data-world]')).map(el => ({
        id: el.dataset.worldId,
        name: el.dataset.worldName
      }));
    },
    LOAD_WORLD: (data) => {
      if (window.loadWorld && typeof window.loadWorld === 'function') {
        window.loadWorld(data);
      }
      return { success: true };
    },
    NAVIGATE_WORLD: (data) => {
      if (window.navigateToWorld && typeof window.navigateToWorld === 'function') {
        window.navigateToWorld(data.worldId, data.options);
      }
      return { navigated: true };
    }
  });

  return messenger;
}
```

