```javascript
function createDraggable(obj, minX, maxX, leftBtn, rightBtn) {
    if (!obj.style.left) obj.style.left = "0px";
    if (!obj.style.right) obj.style.right = "0px";

    var startX, startLeft, isDragging = false;

    function onDragStart(e) {
        isDragging = true;
        startX = e.clientX;
        startLeft = parseInt(obj.style.left, 10) || 0;
        document.addEventListener("mousemove", onDrag);
        document.addEventListener("mouseup", onDragEnd);
        e.preventDefault();
    }

    function onDrag(e) {
        if (!isDragging) return;
        var dx = e.clientX - startX;
        var newLeft = startLeft + dx;
        if (newLeft < minX) newLeft = minX;
        if (newLeft > maxX) newLeft = maxX;
        obj.style.left = newLeft + "px";
    }

    function onDragEnd(e) {
        isDragging = false;
        document.removeEventListener("mousemove", onDrag);
        document.removeEventListener("mouseup", onDragEnd);
    }

    obj.onmousedown = onDragStart;
    leftBtn.onmousedown = onDragStart;
    rightBtn.onmousedown = onDragStart;
}
