 const ScriptLoader = (function() {
  const loaded = new Map();
  const failed = new Set();

  function loadScript(url, timeout = 10000) {
    if (loaded.has(url)) return Promise.resolve(loaded.get(url));
    if (failed.has(url)) return Promise.reject(new Error(`Previously failed: ${url}`));

    return new Promise((resolve, reject) => {
      const script = document.createElement('script');
      script.type = 'text/javascript';
      script.async = false;
      script.src = url;

      const timer = setTimeout(() => {
        failed.add(url);
        reject(new Error(`Timeout: ${url}`));
      }, timeout);

      script.onload = () => {
        clearTimeout(timer);
        const result = {url, status: 'loaded', timestamp: Date.now()};
        loaded.set(url, result);
        resolve(result);
      };

      script.onerror = () => {
        clearTimeout(timer);
        failed.add(url);
        reject(new Error(`Load failed: ${url}`));
      };

      document.head.appendChild(script);
    });
  }

  return {
    execute: async function(primaryUrl, secondaryUrls = [], options = {}) {
      try {
        const primary = await loadScript(primaryUrl, options.primaryTimeout);

        if (!secondaryUrls.length) return [primary];

        const results = await Promise.allSettled(
          secondaryUrls.map(url => loadScript(url, options.secondaryTimeout))
        );

        return [primary, ...results.map((r, i) => 
          r.status === 'fulfilled' ? r.value : {url: secondaryUrls[i], status: 'failed', error: r.reason.message}
        )];

      } catch (primaryError) {
        console.error(`Primary script execution failed: ${primaryError.message}`);
        throw primaryError;
      }
    },

    reset: function() {
      loaded.clear();
      failed.clear();
    }
  };
})();

ScriptLoader.execute('main.js', ['plugin-a.js', 'plugin-b.js', 'optional.js'], {
  primaryTimeout: 15000,
  secondaryTimeout: 8000
}).then(results => {
  results.forEach(r => {
    if (r.status === 'failed') console.warn(`Script error: ${r.url} - ${r.error}`);
  });
}).catch(err => {
  console.error('Fatal error loading primary script:', err);
});

 var warning = require('warning');
var ReactComponentTreeHook = require('ReactComponentTreeHook');
var EventPluginRegistry = require('EventPluginRegistry');

function validateComponentProperties(props, debugID) {
  var componentName = ReactComponentTreeHook.getDisplayName(debugID) || 'Unknown';

  for (var propKey in props) {
    if (!props.hasOwnProperty(propKey)) {
      continue;
    }

    var propValue = props[propKey];

    if (propKey === 'dangerouslySetInnerHTML') {
      warning(
        propValue == null || (typeof propValue === 'object' && '__html' in propValue),
        'dangerouslySetInnerHTML must be in the form {__html: ...}. ' +
        'Please visit https://fb.me/react-invariant-dangerously-set-inner-html ' +
        'for more information.\n\nComponent: %s',
        componentName
      );
    }

    if (/^on/.test(propKey) && propValue != null) {
      var isRegisteredEvent = EventPluginRegistry.registrationNameModules.hasOwnProperty(propKey);
      warning(
        isRegisteredEvent,
        'Unknown event handler property `%s`. It will be ignored.\n' +
        'Did you mean to register it in the EventPluginRegistry?\n' +
        'Component: %s',
        propKey,
        componentName
      );
    }

    if (propKey === 'innerHTML' || propKey === 'outerHTML') {
      warning(
        false,
        'Directly setting `%s` on a component is dangerous and is not supported. ' +
        'Use dangerouslySetInnerHTML instead.\nComponent: %s',
        propKey,
        componentName
      );
    }

    if (propKey === 'style' && propValue != null && typeof propValue !== 'object') {
      warning(
        false,
        'The `style` prop expects a mapping from style properties to values, ' +
        'not a string. For example, style={{marginRight: spacing + \'em\'}} ' +
        'when using JSX.\n\nComponent: %s',
        componentName
      );
    }
  }
}

module.exports = validateComponentProperties;

