function concatBuffers(head) {
    if (head == null) {
        return createBuffer(0);
    }

    var totalSize = 0;
    var current = head;
    while (current != null) {
        totalSize += size(current.data);
        current = current.next;
    }

    var result = createBuffer(totalSize);
    var offset = 0;

    current = head;
    while (current != null) {
        copy(result, offset, current.data);
        offset += size(current.data);
        current = current.next;
    }

    return result;
}
