function parseAction(buffer, offset) {
  const TYPE_FIELD_SIZE = 1;
  const LENGTH_FIELD_SIZE = 2;
  const HEADER_SIZE = TYPE_FIELD_SIZE + LENGTH_FIELD_SIZE;

  if (!buffer || typeof offset !== 'number') {
    return {
      code: 'ERR_INVALID_ARGUMENTS',
      message: 'Buffer and offset are required'
    };
  }

  if (offset < 0 || offset + HEADER_SIZE > buffer.length) {
    return {
      code: 'ERR_INVALID_OFFSET',
      message: 'Offset out of bounds or insufficient data for action header'
    };
  }

  const length = (buffer[offset + TYPE_FIELD_SIZE] << 8) | buffer[offset + TYPE_FIELD_SIZE + 1];

  if (length < 0 || offset + HEADER_SIZE + length > buffer.length) {
    return {
      code: 'ERR_INVALID_LENGTH',
      message: 'Length field value exceeds buffer bounds'
    };
  }

  const action = buffer.slice(offset + HEADER_SIZE, offset + HEADER_SIZE + length);

  return {
    action: action,
    length: length
  };
}
