function compileExpression(expression) {
  return function(context) {
    context = context || {};
    var GlobalEnumerator = typeof Enumerator !== 'undefined' ? Enumerator : function(obj) {
      this.items = Array.isArray(obj) ? obj : Object.keys(obj).map(function(k) { return [k, obj[k]]; });
      this.index = -1;
    };
    if (!GlobalEnumerator.prototype.atEnd) {
      GlobalEnumerator.prototype.atEnd = function() { return this.index >= this.items.length - 1; };
      GlobalEnumerator.prototype.moveNext = function() { this.index++; };
      GlobalEnumerator.prototype.item = function() { return this.items[this.index]; };
    }
    var keys = Object.keys(context);
    var values = keys.map(function(k) { return context[k]; });
    var fn = new Function('Enumerator', keys.join(','), 'return (' + expression + ');');
    return fn.apply(null, [GlobalEnumerator].concat(values));
  };
}
