 ```javascript
function collectStream(stream) {
  const chunks = [];
  let paused = false;

  const cleanup = () => {
    stream.removeAllListeners('data');
    stream.removeAllListeners('end');
    stream.removeAllListeners('error');
  };

  const promise = new Promise((resolve, reject) => {
    stream.on('data', (chunk) => {
      chunks.push(chunk);
      if (paused) stream.pause();
    });

    stream.on('end', () => {
      cleanup();
      resolve(chunks);
    });

    stream.on('error', (err) => {
      cleanup();
      reject(err);
    });
  });

  return {
    promise,
    pause() {
      paused = true;
      stream.pause();
    },
    resume() {
      paused = false;
      stream.resume();
    }
  };
}
