 const _cache = new WeakMap();
const _isDev = typeof process !== 'undefined' && process?.env?.NODE_ENV !== 'production';

function validateProps(componentName, props, propTypes = {}) {
  const cached = _cache.get(props);
  if (cached && cached.component === componentName && cached.schema === propTypes) {
    return cached.valid;
  }

  let isValid = true;
  const validKeys = new Set(Object.keys(propTypes));

  for (const key of validKeys) {
    const validator = propTypes[key];
    if (typeof validator === 'function') {
      const error = validator(props, key, componentName, 'prop');
      if (error instanceof Error) {
        isValid = false;
        if (_isDev) console.error(`[${componentName}] ${error.message}`);
      }
    }
  }

  if (_isDev) {
    for (const key of Object.keys(props)) {
      if (!validKeys.has(key)) {
        console.warn(`[${componentName}] Unknown prop: ${key}`);
      }
    }
  }

  _cache.set(props, { component: componentName, schema: propTypes, valid: isValid });
  return isValid;
}

 const { exec } = require('child_process');
const fs = require('fs');
const path = require('path');

function executeCommand(command, inputFiles) {
  return new Promise((resolve, reject) => {
    if (command.includes('--watch') && inputFiles) {
      for (const file of inputFiles) {
        if (!fs.existsSync(path.resolve(file))) {
          reject(new Error(`Input file not found: ${file}`));
          return;
        }
      }
    }

    exec(command, (error, stdout, stderr) => {
      if (error) {
        reject(error);
      } else {
        resolve({ stdout, stderr });
      }
    });
  });
}

module.exports = executeCommand;

```javascript
function normalizeURL(url) {
  const protocolMatch = url.match(/^([a-z][a-z0-9+.-]*:\/\/[^\/]*)(\/.*)?$/i);

  let base = '';
  let path = url;

  if (protocolMatch) {
    base = protocolMatch[1];
    path = protocolMatch[2] || '/';
  }

  let query = '';
  let hash = '';

  const hashIndex = path.indexOf('#');
  if (hashIndex !== -1) {
    hash = path.substring(hashIndex);
    path = path.substring(0, hashIndex);
  }

  const queryIndex = path.indexOf('?');
  if (queryIndex !== -1) {
    query = path.substring(queryIndex);
    path = path.substring(0, queryIndex);
  }

  const segments = path.split('/');
  const normalized = [];

  for (const segment of segments) {
    if (segment === '..') {
      if (normalized.length > 0 && normalized[normalized.length - 1] !== '..') {
        normalized.pop();
      } else if (!base) {
        normalized.push('..');
      }
    } else if (segment !== '.' && segment !== '') {
      normalized.push(segment);
    }
  }

  let result = normalized.join('/');

  if (path.startsWith('/') || base) {
    result = '/' + result;
  }

  if (result.length > 1 && result.endsWith('/')) {
    result = result.slice(0, -1);
  }

  return base + result + query + hash;
}
