const admin = require('firebase-admin');
const { Server } = require('socket.io');
const http = require('http');
const serviceAccount = require('./serviceAccountKey.json');

admin.initializeApp({
  credential: admin.credential.cert(serviceAccount),
  databaseURL: 'https://your-project-id.firebaseio.com'
});

const db = admin.database();
const ledDataRef = db.ref('ledDevice');

class LEDDevice {
  constructor() {
    this.state = false;
  }

  writeSync(state) {
    const start = Date.now();
    while (Date.now() - start < 5) {}
    this.state = Boolean(state);
    return this.state;
  }

  readSync() {
    return this.state;
  }
}

const ledDevice = new LEDDevice();
const server = http.createServer();
const io = new Server(server, { cors: { origin: "*" } });

io.on('connection', (socket) => {
  ledDataRef.once('value', (snapshot) => {
    const currentData = snapshot.val();
    socket.emit('initialState', currentData || { state: false });
  });

  socket.on('ledControl', (jsonMessage) => {
    try {
      const data = typeof jsonMessage === 'string' ? JSON.parse(jsonMessage) : jsonMessage;
      const { ledId, state, timestamp } = data;

      const newState = Boolean(state);
      const confirmedState = ledDevice.writeSync(newState);

      const record = {
        ledId: ledId || 'default-led',
        state: confirmedState,
        timestamp: timestamp || Date.now(),
        synced: true
      };

      ledDataRef.set(record, (error) => {
        if (error) {
          socket.emit('updateError', { error: error.message });
        } else {
          ledDataRef.once('value', (snap) => {
            socket.emit('stateConfirmed', {
              deviceState: ledDevice.readSync(),
              databaseState: snap.val()
            });
          });
        }
      });

    } catch (error) {
      socket.emit('parseError', { message: error.message });
    }
  });

  socket.on('disconnect', () => {
    console.log('Client disconnected');
  });
});

server.listen(3000, () => {
  console.log('Server running on port 3000');
});
