function readI2CBuffer(address, register, length, callback) {
  if (typeof register === 'function') {
    callback = register;
    register = undefined;
    length = 1;
  } else if (typeof length === 'function') {
    callback = length;
    length = 1;
  }

  const buffer = Buffer.alloc(length);

  if (callback) {
    const cb = (err, bytesRead, buf) => callback(err, buf);
    if (register !== undefined) {
      i2c.readI2cBlock(address, register, length, buffer, cb);
    } else {
      i2c.i2cRead(address, length, buffer, cb);
    }
  } else {
    if (register !== undefined) {
      i2c.readI2cBlockSync(address, register, length, buffer);
    } else {
      i2c.i2cReadSync(address, length, buffer);
    }
    return buffer;
  }
}
