```javascript
function decodeBuffer(buffer) {
  if (!buffer || buffer.length === 0) return '';

  let length = buffer.length;

  for (let i = 1; i <= 3 && i <= buffer.length; i++) {
    const byte = buffer[buffer.length - i];

    if ((byte & 0x80) === 0) {
      break;
    } else if ((byte & 0xc0) === 0x80) {
      continue;
    } else if ((byte & 0xe0) === 0xc0) {
      if (i !== 2) length = buffer.length - i;
      break;
    } else if ((byte & 0xf0) === 0xe0) {
      if (i !== 3) length = buffer.length - i;
      break;
    } else if ((byte & 0xf8) === 0xf0) {
      length = buffer.length - i;
      break;
    }
  }

  return new TextDecoder('utf-8').decode(buffer.subarray(0, length));
}
