import React from 'react';

function analyzeContentCapability(component) {
  if (!React.isValidElement(component)) {
    return 'cannot be treated as content';
  }

  const { type, props } = component;

  if (typeof type === 'string') {
    const contentElements = ['div', 'span', 'p', 'article', 'section', 'main', 'aside', 'header', 'footer', 'nav', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'li', 'td', 'th', 'label', 'figcaption', 'blockquote', 'pre', 'code', 'em', 'strong', 'a'];
    const voidContentElements = ['img', 'video', 'audio', 'canvas', 'svg', 'picture', 'br', 'hr', 'input', 'iframe'];

    if (contentElements.includes(type) || voidContentElements.includes(type)) {
      return 'can be treated as content';
    }

    if (props.children !== undefined || props.dangerouslySetInnerHTML || props.content || props.text) {
      return 'can be treated as content';
    }
  }

  if (type === React.Fragment) {
    if (props.children !== undefined && props.children !== null) {
      return 'can be treated as content';
    }
    return 'cannot be treated as content';
  }

  if (typeof type === 'function') {
    const componentName = type.displayName || type.name || '';
    const contentPatterns = ['Content', 'Text', 'Body', 'Item', 'Cell', 'Article', 'Post', 'Message', 'Description', 'Label', 'Title', 'Paragraph', 'Caption', 'Headline'];

    const hasContentName = contentPatterns.some(pattern => componentName.includes(pattern));
    const hasContentProps = props.children !== undefined || props.content !== undefined || props.text !== undefined || props.html !== undefined || props.dangerouslySetInnerHTML !== undefined;

    if (hasContentName || hasContentProps) {
      return 'can be treated as content';
    }
  }

  return 'cannot be treated as content';
}

export default analyzeContentCapability;

