function attachIframeListener(iframe, eventType) {
    iframe.addEventListener(eventType, () => {
        if (!iframe.hasAttribute('data-autoplay')) return;

        const src = iframe.src || '';
        let message;
        let isSpecific = true;

        if (src.includes('youtube')) {
            message = JSON.stringify({ event: 'command', func: 'playVideo', args: [] });
        } else if (src.includes('vimeo')) {
            message = JSON.stringify({ method: 'play' });
        } else if (src.includes('slide')) {
            message = 'slide:start';
        } else {
            message = 'play';
            isSpecific = false;
        }

        if (isSpecific) {
            iframe.contentWindow.postMessage(message, '*');
        } else {
            document.querySelectorAll('iframe').forEach(frame => {
                frame.contentWindow.postMessage(message, '*');
            });
        }
    });
}
