 import java.io.IOException;
import java.net.InetSocketAddress;
import java.nio.channels.AsynchronousSocketChannel;
import java.nio.channels.CompletionHandler;

public class RemoteChannelConnector {

    public void establishConnection(String host, int port) {
        try {
            AsynchronousSocketChannel channel = AsynchronousSocketChannel.open();
            InetSocketAddress remoteAddress = new InetSocketAddress(host, port);

            channel.connect(remoteAddress, channel, new CompletionHandler<Void, AsynchronousSocketChannel>() {
                @Override
                public void completed(Void result, AsynchronousSocketChannel ch) {
                    onConnected(ch);
                }

                @Override
                public void failed(Throwable exc, AsynchronousSocketChannel ch) {
                    onConnectionFailed(exc, ch);
                }
            });
        } catch (IOException e) {
            onOpenFailed(e);
        }
    }

    private void onConnected(AsynchronousSocketChannel channel) {
        // Connection established successfully
    }

    private void onConnectionFailed(Throwable exc, AsynchronousSocketChannel channel) {
        try {
            channel.close();
        } catch (IOException ignored) {}
    }

    private void onOpenFailed(IOException e) {
        // Failed to open channel
    }
}

import io.swagger.v3.oas.models.OpenAPI;
import io.swagger.v3.oas.models.Components;
import io.swagger.v3.oas.models.security.OAuthFlow;
import io.swagger.v3.oas.models.security.OAuthFlows;
import io.swagger.v3.oas.models.security.Scopes;
import io.swagger.v3.oas.models.security.SecurityScheme;
import io.swagger.v3.oas.models.security.SecurityRequirement;

public void configureKeycloakSecurity(OpenAPI openApi, String keycloakBaseUrl, String realm) {
    String openIdConfigUrl = keycloakBaseUrl + "/realms/" + realm + "/.well-known/openid-configuration";
    String authorizationUrl = keycloakBaseUrl + "/realms/" + realm + "/protocol/openid-connect/auth";
    String tokenUrl = keycloakBaseUrl + "/realms/" + realm + "/protocol/openid-connect/token";

    if (openApi.getComponents() == null) {
        openApi.setComponents(new Components());
    }

    SecurityScheme oidcScheme = new SecurityScheme()
        .type(SecurityScheme.Type.OPENIDCONNECT)
        .openIdConnectUrl(openIdConfigUrl);

    OAuthFlow authCodeFlow = new OAuthFlow()
        .authorizationUrl(authorizationUrl)
        .tokenUrl(tokenUrl)
        .scopes(new Scopes());

    authCodeFlow.addExtension("x-nonce-parameter", "nonce");
    authCodeFlow.addExtension("x-nonce-required", true);

    OAuthFlows flows = new OAuthFlows()
        .authorizationCode(authCodeFlow);

    SecurityScheme oauth2Scheme = new SecurityScheme()
        .type(SecurityScheme.Type.OAUTH2)
        .flows(flows);

    openApi.getComponents()
        .addSecuritySchemes("openIdConnect", oidcScheme)
        .addSecuritySchemes("oauth2", oauth2Scheme);

    openApi.addSecurityItem(new SecurityRequirement().addList("openIdConnect"));
    openApi.addSecurityItem(new SecurityRequirement().addList("oauth2"));
}

