 ```java
import java.util.List;
import java.util.Objects;

public class GeoDataComparator {

    public static class GeoPoint {
        public final double latitude;
        public final double longitude;

        public GeoPoint(double latitude, double longitude) {
            this.latitude = latitude;
            this.longitude = longitude;
        }
    }

    public static class Document {
        public final List<GeoPoint> points;

        public Document(List<GeoPoint> points) {
            this.points = points;
        }
    }

    public static void compareGeographicalDatasets(
            List<Document> dataset1, 
            List<Document> dataset2, 
            double toleranceMeters) {

        if (dataset1 == null || dataset2 == null) {
            throw new IllegalArgumentException("Datasets cannot be null");
        }

        if (dataset1.size() != dataset2.size()) {
            throw new AssertionError("Dataset sizes do not match: " + 
                dataset1.size() + " vs " + dataset2.size());
        }

        for (int docIndex = 0; docIndex < dataset1.size(); docIndex++) {
            Document doc1 = dataset1.get(docIndex);
            Document doc2 = dataset2.get(docIndex);

            if (doc1 == null || doc2 == null) {
                throw new AssertionError("Document at index " + docIndex + " is null");
            }

            List<GeoPoint> points1 = doc1.points;
            List<GeoPoint> points2 = doc2.points;

            if (points1 == null || points2 == null) {
                throw new AssertionError("Points list is null at document index " + docIndex);
            }

            if (points1.size() != points2.size()) {
                throw new AssertionError("Point count mismatch at document index " + docIndex + 
                    ": " + points1.size() + " vs " + points2.size());
            }

            if (points1.size() > 0) {
                assertIncreasingOrder(points1, docIndex, "dataset1");
                assertIncreasingOrder(points2, docIndex, "dataset2");

                for (int pointIndex = 0; pointIndex < points1.size(); pointIndex++) {
                    GeoPoint p1 = points1.get(pointIndex);
                    GeoPoint p2 = points2.get(pointIndex);

                    if (p1 == null || p2 == null) {
                        throw new AssertionError("Null point at document " + docIndex + ", index " + pointIndex);
                    }

                    double distance = haversineDistance(
                        p1.latitude, p1.longitude, 
                        p2.latitude, p2.longitude
                    );

                    if (distance > toleranceMeters) {
                        throw new AssertionError(String.format(
                            "Distance tolerance exceeded at document %d, point %d: %.2f meters (tolerance: %.2f)",
                            docIndex, pointIndex, distance, toleranceMeters));
                    }
                }
            }
        }
    }

    private static void assertIncreasingOrder(List<GeoPoint> points, int docIndex, String source) {
        for (int i = 1; i < points.size(); i++) {
            GeoPoint prev = points.get(i - 1);
            GeoPoint curr = points.get(i);

            int latCompare = Double.compare(prev.latitude, curr.latitude);
            if (latCompare > 0) {
                throw new AssertionError(String.format(
                    "Points not in increasing order at %s document %d: latitude decreasing at index %d",
                    source, docIndex, i));
            } else if (latCompare == 0) {
                if (Double.compare(prev.longitude, curr.longitude) > 0) {
                    throw new AssertionError(String.format(
                        "Points not in increasing order at %s document %d: longitude decreasing at index %d",
                        source, docIndex, i));
                }
            }
        }
    }

    private static double haversineDistance(double lat1, double lon1, double lat2, double lon2) {
        final double R = 6371000;
        double dLat = Math.toRadians(lat2 - lat1);
        double dLon = Math.toRadians(lon2 - lon1);
        double a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
                   Math.cos(Math.toRadians(lat1)) * Math.cos(Math.toRadians(lat2)) *
                   Math.sin(dLon / 2) * Math.sin(dLon / 2);
        double c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
        return R * c;
    }
}
