 import com.google.gson.Gson;
import java.util.ArrayList;
import java.util.List;
import java.util.Random;

class Event {
    private Header header;
    private Body body;

    public Event(Header header, Body body) {
        this.header = header;
        this.body = body;
    }
}

class Header {
    private int messageNumber;

    public Header(int messageNumber) {
        this.messageNumber = messageNumber;
    }
}

class Body {
    private double gaussianNumber;

    public Body(double gaussianNumber) {
        this.gaussianNumber = gaussianNumber;
    }
}

public class EventGenerator {
    public static void main(String[] args) {
        Gson gson = new Gson();
        Random random = new Random();
        List<Event> events = new ArrayList<>();

        for (int i = 1; i <= 10; i++) {
            Header header = new Header(i);
            Body body = new Body(random.nextGaussian());
            events.add(new Event(header, body));
        }

        String jsonString = gson.toJson(events);
        System.out.println(jsonString);
    }
}

