import java.util.concurrent.CountDownLatch;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.ThreadLocalRandom;
import org.apache.tinkerpop.gremlin.structure.T;
import org.apache.tinkerpop.gremlin.structure.Vertex;
import org.umlg.sqlg.structure.SQLgGraph;

public class GraphPopulator {
    public static void populateGraph(ExecutorService executor, SQLgGraph graph, int iterations) throws InterruptedException {
        CountDownLatch latch = new CountDownLatch(iterations);

        for (int i = 0; i < iterations; i++) {
            executor.submit(() -> {
                try {
                    ThreadLocalRandom random = ThreadLocalRandom.current();

                    synchronized (graph) {
                        Vertex v1 = graph.addVertex(T.label, "Entity", "id", random.nextInt(), "score", random.nextDouble());
                        Vertex v2 = graph.addVertex(T.label, "Entity", "id", random.nextInt(), "score", random.nextDouble());
                        v1.addEdge("link", v2, "weight", random.nextDouble(), "timestamp", System.currentTimeMillis());

                        graph.tx().commit();
                    }
                } finally {
                    latch.countDown();
                }
            });
        }

        latch.await();
    }
}
