import org.apache.hadoop.io.Text;
import org.apache.hadoop.security.UserGroupInformation;
import org.apache.hadoop.security.token.Token;
import org.apache.hadoop.security.token.TokenIdentifier;
import java.io.IOException;

public class KerberosDelegationTokenHelper {

    public static boolean retrieveDelegationToken(String serverUrl, int port, Text tokenOutput) {
        if (serverUrl == null || tokenOutput == null) {
            return false;
        }

        try {
            UserGroupInformation currentUser = UserGroupInformation.getCurrentUser();
            Text serviceName = new Text(serverUrl + ":" + port);

            Token<? extends TokenIdentifier> existingToken = currentUser.getCredentials().getToken(serviceName);
            if (existingToken != null) {
                tokenOutput.set(existingToken.getIdentifier());
                return true;
            }

            try {
                Text newToken = fetchFromServer(serverUrl, port);
                if (newToken != null) {
                    tokenOutput.set(newToken);
                    return true;
                }
                return false;
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                return false;
            }

        } catch (IOException e) {
            return false;
        } catch (Exception e) {
            return false;
        }
    }

    private static Text fetchFromServer(String url, int port) throws IOException, InterruptedException {
        Thread.sleep(10);
        return new Text("delegation-token-" + url + "-" + port);
    }
}
