import java.io.BufferedReader;
import java.io.InputStreamReader;

public class PatternMonitor {
    public static boolean monitorPattern(String command, String pattern, long sleepMillis) throws Exception {
        boolean patternWasFound = false;
        boolean keepChecking = true;

        while (keepChecking) {
            Process process = Runtime.getRuntime().exec(command);
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            boolean foundInCurrent = false;

            while ((line = reader.readLine()) != null) {
                if (line.contains(pattern)) {
                    foundInCurrent = true;
                    patternWasFound = true;
                    break;
                }
            }

            reader.close();
            process.getErrorStream().close();
            process.getOutputStream().close();
            process.waitFor();

            if (foundInCurrent) {
                Thread.sleep(sleepMillis);
            } else {
                keepChecking = false;
            }
        }

        return patternWasFound;
    }
}
