class CustomObject implements Serializable {
    private int d;
    private double x;
    private float y;
    private boolean z;

    public CustomObject(int d, double x, float y, boolean z) {
        this.d = d;
        this.x = x;
        this.y = y;
        this.z = z;
    }

    @Override
    public String toString() {
        return "CustomObject{d=" + d + ", x=" + x + ", y=" + y + ", z=" + z + "}";
    }
}

public class SerializationExample {
    public static void main(String[] args) {
        String filename = "data.ser";
        CustomObject original = new CustomObject(42, 3.14159, 2.718f, true);

        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(filename))) {
            oos.writeObject(original);
        } catch (IOException e) {
            e.printStackTrace();
        }

        CustomObject restored = null;
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(filename))) {
            restored = (CustomObject) ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }

        System.out.println("Original: " + original);
        System.out.println("Restored: " + restored);
    }
}

