import java.io.IOException;
import java.net.InetSocketAddress;
import java.nio.ByteBuffer;
import java.nio.channels.*;
import java.util.Iterator;
import java.util.Scanner;
import java.util.Set;

public class NioServer {
    private static final int BUFFER_SIZE = 1024;
    private volatile boolean running = true;
    private Selector selector;
    private ServerSocketChannel serverChannel;

    public static void main(String[] args) {
        NioServer server = new NioServer();
        server.start("localhost", 8080);
    }

    public void start(String address, int port) {
        try {
            selector = Selector.open();
            serverChannel = ServerSocketChannel.open();
            serverChannel.configureBlocking(false);
            serverChannel.bind(new InetSocketAddress(address, port));
            serverChannel.register(selector, SelectionKey.OP_ACCEPT);

            System.out.println("Server started on " + address + ":" + port);
            System.out.println("Commands: quit, status");

            Thread consoleThread = new Thread(this::handleConsoleCommands);
            consoleThread.setDaemon(true);
            consoleThread.start();

            while (running) {
                selector.select();
                Set<SelectionKey> selectedKeys = selector.selectedKeys();
                Iterator<SelectionKey> iterator = selectedKeys.iterator();

                while (iterator.hasNext()) {
                    SelectionKey key = iterator.next();
                    iterator.remove();

                    if (!key.isValid()) continue;

                    if (key.isAcceptable()) {
                        acceptConnection(key);
                    } else if (key.isReadable()) {
                        readData(key);
                    }
                }
            }
        } catch (IOException e) {
            e.printStackTrace();
        } finally {
            close();
        }
    }

    private void acceptConnection(SelectionKey key) throws IOException {
        ServerSocketChannel server = (ServerSocketChannel) key.channel();
        SocketChannel client = server.accept();
        client.configureBlocking(false);
        client.register(selector, SelectionKey.OP_READ);
        System.out.println("Client connected: " + client.getRemoteAddress());
    }

    private void readData(SelectionKey key) {
        SocketChannel channel = (SocketChannel) key.channel();
        ByteBuffer buffer = ByteBuffer.allocate(BUFFER_SIZE);

        try {
            int bytesRead = channel.read(buffer);
            if (bytesRead == -1) {
                System.out.println("Client disconnected: " + channel.getRemoteAddress());
                key.cancel();
                channel.close();
            } else if (bytesRead > 0) {
                buffer.flip();
                byte[] data = new byte[buffer.remaining()];
                buffer.get(data);
                String message = new String(data);
                System.out.println("Received: " + message.trim());
            }
        } catch (IOException e) {
            try {
                key.cancel();
                channel.close();
            } catch (IOException ex) {
                ex.printStackTrace();
            }
        }
    }

    private void handleConsoleCommands() {
        Scanner scanner = new Scanner(System.in);
        while (running) {
            if (scanner.hasNextLine()) {
                String command = scanner.nextLine().trim().toLowerCase();
                switch (command) {
                    case "quit":
                    case "exit":
                        running = false;
                        selector.wakeup();
                        break;
                    case "status":
                        System.out.println("Server is running");
                        break;
                    default:
                        System.out.println("Unknown command: " + command);
                }
            }
        }
        scanner.close();
    }

    private void close() {
        try {
            if (selector != null) selector.close();
            if (serverChannel != null) serverChannel.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}
