import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.IvParameterSpec;
import java.security.SecureRandom;
import java.nio.charset.StandardCharsets;

public class AESCTREncryption {
    public static void main(String[] args) throws Exception {
        String inputMessage = "This is a secret message for AES CTR encryption.";
        int keySize = 256;

        KeyGenerator keyGenerator = KeyGenerator.getInstance("AES");
        keyGenerator.init(keySize);
        SecretKey secretKey = keyGenerator.generateKey();

        byte[] iv = new byte[16];
        SecureRandom secureRandom = new SecureRandom();
        secureRandom.nextBytes(iv);
        IvParameterSpec ivParameterSpec = new IvParameterSpec(iv);

        Cipher cipher = Cipher.getInstance("AES/CTR/NoPadding");
        cipher.init(Cipher.ENCRYPT_MODE, secretKey, ivParameterSpec);

        byte[] encryptedBytes = cipher.doFinal(inputMessage.getBytes(StandardCharsets.UTF_8));

        StringBuilder hexOutput = new StringBuilder();
        for (byte b : encryptedBytes) {
            hexOutput.append(String.format("%02x", b));
        }

        System.out.println(hexOutput.toString());
    }
}
