import java.io.*;

public byte[] serializeKijiDataRequest(KijiDataRequest request) throws IOException, ClassNotFoundException {
    ByteArrayOutputStream baos = new ByteArrayOutputStream();
    try (ObjectOutputStream oos = new ObjectOutputStream(baos)) {
        oos.writeObject(request);
    }

    byte[] serializedData = baos.toByteArray();

    ByteArrayInputStream bais = new ByteArrayInputStream(serializedData);
    KijiDataRequest deserializedRequest;
    try (ObjectInputStream ois = new ObjectInputStream(bais)) {
        deserializedRequest = (KijiDataRequest) ois.readObject();
    }

    if (!request.equals(deserializedRequest)) {
        throw new IllegalStateException("Deserialized request does not equal original");
    }

    return serializedData;
}
