import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;

public class CommandRunner {
    private static final String FATAL_MESSAGE = "FATAL_ERROR";

    public static void main(String[] args) {
        try {
            String command = args.length > 0 ? args[0] : "echo test";
            Process process = Runtime.getRuntime().exec(command);

            Thread outputThread = new Thread(new StreamReader(process.getInputStream(), false));
            Thread errorThread = new Thread(new StreamReader(process.getErrorStream(), true));

            outputThread.start();
            errorThread.start();

            process.waitFor();
            outputThread.join();
            errorThread.join();

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    static class StreamReader implements Runnable {
        private InputStream inputStream;
        private boolean isError;

        StreamReader(InputStream inputStream, boolean isError) {
            this.inputStream = inputStream;
            this.isError = isError;
        }

        @Override
        public void run() {
            try (BufferedReader reader = new BufferedReader(new InputStreamReader(inputStream))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    if (isError) {
                        System.err.println(line);
                        if (line.contains(FATAL_MESSAGE)) {
                            System.exit(1);
                        }
                    } else {
                        System.out.println(line);
                    }
                }
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
    }
}
