 import java.io.*;
import java.util.*;

public class FileDataFilter {
    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: java FileDataFilter <directory> <className>");
            return;
        }

        String directoryPath = args[0];
        String targetClassName = args[1];
        File directory = new File(directoryPath);
        Hashtable<String, Object> dataStore = new Hashtable<>();
        List<String> validFiles = new ArrayList<>();

        if (!directory.isDirectory()) {
            System.err.println("Not a directory: " + directoryPath);
            return;
        }

        File[] files = directory.listFiles();
        if (files == null) {
            System.err.println("Cannot read directory: " + directoryPath);
            return;
        }

        Class<?> targetClass = null;
        try {
            targetClass = Class.forName(targetClassName);
        } catch (ClassNotFoundException e) {
            System.err.println("Target class not found: " + targetClassName);
            return;
        }

        for (File file : files) {
            if (file.isFile()) {
                try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(file))) {
                    Object obj = ois.readObject();
                    if (targetClass.isInstance(obj)) {
                        dataStore.put(file.getAbsolutePath(), obj);
                        validFiles.add(file.getName());
                    }
                } catch (FileNotFoundException e) {
                    System.err.println("File not found: " + file.getName());
                } catch (ClassNotFoundException e) {
                    System.err.println("Class not found in file " + file.getName() + ": " + e.getMessage());
                } catch (IOException e) {
                    System.err.println("IO error reading " + file.getName() + ": " + e.getMessage());
                }
            }
        }

        System.out.println("Files containing " + targetClassName + ":");
        for (String fileName : validFiles) {
            System.out.println(fileName);
        }
    }
}

