import java.io.File;
import java.io.IOException;
import java.net.BindException;
import java.net.InetSocketAddress;
import org.apache.zookeeper.server.ServerCnxnFactory;
import org.apache.zookeeper.server.ZooKeeperServer;
import org.apache.zookeeper.server.persistence.FileTxnSnapLog;

public class ZooKeeperServerSetup {
    public static void main(String[] args) {
        String dataDir = "/tmp/zookeeper";
        int startPort = 2181;
        int endPort = 2190;
        int tickTime = 3000;
        int minSessionTimeout = 6000;
        int maxSessionTimeout = 60000;

        ZooKeeperServer server = new ZooKeeperServer();
        ServerCnxnFactory cnxnFactory = null;

        try {
            FileTxnSnapLog txnLog = new FileTxnSnapLog(new File(dataDir), new File(dataDir));
            server.setTxnLogFactory(txnLog);
            server.setTickTime(tickTime);
            server.setMinSessionTimeout(minSessionTimeout);
            server.setMaxSessionTimeout(maxSessionTimeout);

            for (int port = startPort; port <= endPort; port++) {
                try {
                    cnxnFactory = ServerCnxnFactory.createFactory();
                    cnxnFactory.configure(new InetSocketAddress(port), 100);
                    server.setServerCnxnFactory(cnxnFactory);
                    cnxnFactory.startup(server);
                    break;
                } catch (BindException e) {
                    if (cnxnFactory != null) {
                        cnxnFactory.shutdown();
                    }
                    continue;
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
