import org.apache.mina.core.filterchain.IoFilter;
import org.apache.mina.core.future.ConnectFuture;
import org.apache.mina.core.service.IoHandlerAdapter;
import org.apache.mina.core.session.IoSession;
import org.apache.mina.filter.executor.ExecutorFilter;
import org.apache.mina.transport.socket.nio.NioSocketConnector;
import java.net.InetSocketAddress;
import java.net.URI;
import java.util.List;
import java.util.concurrent.Executors;
import java.util.concurrent.ExecutorService;

public class MinaSocketFactory {
    public IoSession createConnectedSocket(URI uri, int timeout, int maxPoolSize, List<IoFilter> filters) {
        NioSocketConnector connector = new NioSocketConnector();

        ExecutorService workerPool = Executors.newFixedThreadPool(maxPoolSize);
        connector.getFilterChain().addLast("workerPool", new ExecutorFilter(workerPool));

        if (filters != null) {
            for (int i = 0; i < filters.size(); i++) {
                connector.getFilterChain().addLast("filter-" + i, filters.get(i));
            }
        }

        connector.setConnectTimeoutMillis(timeout);
        connector.setHandler(new IoHandlerAdapter());

        int port = uri.getPort() != -1 ? uri.getPort() : 80;
        ConnectFuture future = connector.connect(new InetSocketAddress(uri.getHost(), port));
        future.awaitUninterruptibly();

        if (!future.isConnected()) {
            throw new RuntimeException("Failed to connect to " + uri);
        }

        return future.getSession();
    }
}

 import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;

public class KeystoreGenerator {

    public static Path generateKeystore(String hostname, String storePassword, String alias, 
                                       String keyAlgorithm, int validityDays) throws IOException, InterruptedException {
        Path tempDir = Files.createTempDirectory("keystore_");
        Path keystoreFile = tempDir.resolve("keystore.jks");

        ProcessBuilder processBuilder = new ProcessBuilder(
            "keytool",
            "-genkeypair",
            "-alias", alias,
            "-keyalg", keyAlgorithm,
            "-validity", String.valueOf(validityDays),
            "-keystore", keystoreFile.toString(),
            "-storepass", storePassword,
            "-keypass", storePassword,
            "-dname", "CN=" + hostname
        );

        processBuilder.inheritIO();
        Process process = processBuilder.start();
        int exitCode = process.waitFor();

        if (exitCode != 0) {
            throw new RuntimeException("Keytool command failed with exit code: " + exitCode);
        }

        return keystoreFile;
    }

    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java KeystoreGenerator <hostname> [storePassword] [alias] [keyAlgorithm] [validityDays]");
            System.exit(1);
        }

        String hostname = args[0];
        String storePassword = args.length > 1 ? args[1] : "changeit";
        String alias = args.length > 2 ? args[2] : hostname;
        String keyAlgorithm = args.length > 3 ? args[3] : "RSA";
        int validityDays = args.length > 4 ? Integer.parseInt(args[4]) : 365;

        try {
            Path keystorePath = generateKeystore(hostname, storePassword, alias, keyAlgorithm, validityDays);
            System.out.println("Keystore generated successfully at: " + keystorePath);
        } catch (Exception e) {
            e.printStackTrace();
            System.exit(1);
        }
    }
}

 ```java
import java.io.*;
import java.util.*;

public class HMMTagger {
    private Set<String> states;
    private Map<String, Double> initialProbabilities;
    private Map<String, Map<String, Double>> transitionProbabilities;
    private Map<String, Map<String, Double>> emissionProbabilities;

    public HMMTagger() {
        this.states = new HashSet<>();
        this.initialProbabilities = new HashMap<>();
        this.transitionProbabilities = new HashMap<>();
        this.emissionProbabilities = new HashMap<>();
    }

    public void loadModel(String filename) throws IOException {
        BufferedReader reader = new BufferedReader(new FileReader(filename));
        String line;

        if ((line = reader.readLine()) != null) {
            String[] stateArray = line.trim().split("\\s+");
            for (String state : stateArray) {
                states.add(state);
                transitionProbabilities.put(state, new HashMap<>());
                emissionProbabilities.put(state, new HashMap<>());
            }
        }

        if ((line = reader.readLine()) != null) {
            String[] probs = line.trim().split("\\s+");
            int i = 0;
            for (String state : states) {
                if (i < probs.length) {
                    initialProbabilities.put(state, Double.parseDouble(probs[i]));
                    i++;
                }
            }
        }

        while ((line = reader.readLine()) != null && !line.trim().isEmpty()) {
            String[] parts = line.trim().split("\\s+");
            if (parts.length == 3) {
                String from = parts[0];
                String to = parts[1];
                double prob = Double.parseDouble(parts[2]);
                transitionProbabilities.get(from).put(to, prob);
            }
        }

        while ((line = reader.readLine()) != null) {
            String[] parts = line.trim().split("\\s+");
            if (parts.length == 3) {
                String state = parts[0];
                String word = parts[1].toLowerCase();
                double prob = Double.parseDouble(parts[2]);
                emissionProbabilities.get(state).put(word, prob);
            }
        }
        reader.close();
    }

    public Map<String, String> tag(String text) {
        String[] words = text.toLowerCase().split("\\s+");
        if (words.length == 0) return new HashMap<>();

        Map<String, Double> viterbi = new HashMap<>();
        Map<Integer, Map<String, String>> backpointers = new HashMap<>();

        for (String state : states) {
            double initProb = initialProbabilities.getOrDefault(state, 0.0);
            double emitProb = emissionProbabilities.get(state).getOrDefault(words[0], 0.0);
            viterbi.put(state, initProb * emitProb);
        }

        for (int t = 1; t < words.length; t++) {
            Map<String, Double> newViterbi = new HashMap<>();
            Map<String, String> currentBackpointers = new HashMap<>();

            for (String state : states) {
                double maxProb = 0.0;
                String bestPrevState = null;

                for (String prevState : states) {
                    double prevProb = viterbi.getOrDefault(prevState, 0.0);
                    double transProb = transitionProbabilities.get(prevState).getOrDefault(state, 0.0);
                    double prob = prevProb * transProb;

                    if (prob > maxProb) {
                        maxProb = prob;
                        bestPrevState = prevState;
                    }
                }

                double emitProb = emissionProbabilities.get(state).getOrDefault(words[t], 0.0);
                newViterbi.put(state, maxProb * emitProb);
                if (bestPrevState != null) {
                    currentBackpointers.put(state, bestPrevState);
                }
            }

            viterbi = newViterbi;
            backpointers.put(t, currentBackpointers);
        }

        double maxProb = 0.0;
        String bestFinalState = null;
        for (String state : states) {
            double prob = viterbi.getOrDefault(state, 0.0);
            if (prob > maxProb) {
                maxProb = prob;
                bestFinalState = state;
            }
        }

        String[] tags = new String[words.length];
        tags[words.length - 1] = bestFinalState;
        for (int t = words.length - 1; t > 0; t--) {
            if (backpointers.containsKey(t) && tags[t] != null) {
                tags[t - 1] = backpointers.get(t).get(tags[t]);
            }
        }

        Map<String, String> result = new LinkedHashMap<>();
        for (int i = 0; i < words.length; i++) {
            if (tags[i] != null) {
                result.put(words[i], tags[i]);
            }
        }

        return result;
    }

    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: java HMMTagger <model-file> <text>");
            System.exit(1);
        }

        try {
            HMMTagger tagger = new HMMTagger();
            tagger.loadModel(args[0]);
            Map<String, String> tagged = tagger.tag(args[1]);

            for (Map.Entry<String, String> entry : tagged.entrySet()) {
                System.out.println(entry.getKey() + "/" + entry.getValue());
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
