import java.net.InetSocketAddress;
import java.util.Objects;

public class ConfigManager {
    public static class Configuration {
        private InetSocketAddress socketAddress;

        public void setSocketAddress(InetSocketAddress address) {
            this.socketAddress = address;
        }

        public InetSocketAddress getSocketAddress() {
            return socketAddress;
        }
    }

    public static void updateAndTestAddress(Configuration config, String host, int port) {
        InetSocketAddress newAddress = new InetSocketAddress(host, port);
        config.setSocketAddress(newAddress);
        InetSocketAddress retrieved = config.getSocketAddress();
        if (!Objects.equals(retrieved, newAddress)) {
            throw new AssertionError("Address mismatch: expected " + newAddress + " but was " + retrieved);
        }
        if (!retrieved.getHostName().equals(host) || retrieved.getPort() != port) {
            throw new AssertionError("Address components do not match expected values");
        }
    }
}
