import javax.swing.*;
import java.awt.*;
import java.io.*;
import java.nio.file.Files;
import java.nio.file.Path;

public class ImageRotator {
    public static void main(String[] args) {
        if (args.length != 2) {
            System.err.println("Usage: java ImageRotator <image-path> <angle>");
            System.exit(1);
        }

        String inputPath = args[0];
        String angle = args[1];
        File inputFile = new File(inputPath);

        if (!inputFile.exists()) {
            System.err.println("Error: File not found: " + inputPath);
            System.exit(1);
        }

        try {
            Path tempOutput = Files.createTempFile("rotated-", ".png");
            String outputPath = tempOutput.toAbsolutePath().toString();

            ProcessBuilder pb = new ProcessBuilder("convert", inputPath, "-rotate", angle, outputPath);
            pb.redirectErrorStream(true);

            Process process = pb.start();

            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            StringBuilder output = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                output.append(line).append(System.lineSeparator());
            }
            reader.close();

            int exitCode = process.waitFor();

            if (exitCode != 0) {
                System.err.println("Error: Image rotation failed (exit code " + exitCode + ")");
                if (output.length() > 0) {
                    System.err.println(output.toString());
                }
                Files.deleteIfExists(tempOutput);
                System.exit(1);
            }

            displayImage(outputPath);
            tempOutput.toFile().deleteOnExit();

        } catch (IOException e) {
            System.err.println("Error: Failed to execute command - " + e.getMessage());
            System.exit(1);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            System.err.println("Error: Process interrupted");
            System.exit(1);
        }
    }

    private static void displayImage(String imagePath) {
        SwingUtilities.invokeLater(() -> {
            JFrame frame = new JFrame("Rotated Image");
            frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

            ImageIcon icon = new ImageIcon(imagePath);
            JLabel label = new JLabel(icon);
            JScrollPane scrollPane = new JScrollPane(label);

            frame.add(scrollPane, BorderLayout.CENTER);
            frame.pack();
            frame.setLocationRelativeTo(null);
            frame.setVisible(true);
        });
    }
}
