import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.concurrent.TimeUnit;
import java.util.zip.GZIPOutputStream;
import com.google.common.util.concurrent.RateLimiter;

public class ApiClient {
    private static RateLimiter rateLimiter;

    public static String sendPostRequest(String endpoint, byte[] body, String token, boolean gzipBody, double maxRatePerSecond) throws IOException, InterruptedException {
        if (maxRatePerSecond > 0) {
            if (rateLimiter == null || rateLimiter.getRate() != maxRatePerSecond) {
                rateLimiter = RateLimiter.create(maxRatePerSecond);
            }
            rateLimiter.acquire();
        }

        HttpClient client = HttpClient.newHttpClient();

        byte[] requestBody = body;
        HttpRequest.Builder requestBuilder = HttpRequest.newBuilder()
            .uri(URI.create(endpoint))
            .header("Authorization", "Bearer " + token)
            .header("Content-Type", "application/json");

        if (gzipBody) {
            requestBody = gzipCompress(body);
            requestBuilder.header("Content-Encoding", "gzip");
        }

        HttpRequest request = requestBuilder
            .POST(HttpRequest.BodyPublishers.ofByteArray(requestBody))
            .build();

        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
        return response.body();
    }

    private static byte[] gzipCompress(byte[] data) throws IOException {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        try (GZIPOutputStream gzipOut = new GZIPOutputStream(baos)) {
            gzipOut.write(data);
        }
        return baos.toByteArray();
    }
}
