 import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;

public class HashFunction {

    public static String hash(String algorithm, String input) throws NoSuchAlgorithmException {
        if (algorithm == null || input == null) {
            throw new IllegalArgumentException("Algorithm and input cannot be null");
        }

        MessageDigest digest = MessageDigest.getInstance(algorithm);
        byte[] hashBytes = digest.digest(input.getBytes(StandardCharsets.UTF_8));

        StringBuilder hexString = new StringBuilder(2 * hashBytes.length);
        for (byte b : hashBytes) {
            String hex = Integer.toHexString(0xff & b);
            if (hex.length() == 1) {
                hexString.append('0');
            }
            hexString.append(hex);
        }
        return hexString.toString();
    }

    public static void main(String[] args) {
        String input = "Hello, World!";
        String[] algorithms = {"MD5", "SHA-1", "SHA-256", "SHA-384", "SHA-512", "md5", "sha-256", "INVALID"};

        for (String algo : algorithms) {
            try {
                String result = hash(algo, input);
                System.out.println(algo + ": " + result);
            } catch (NoSuchAlgorithmException e) {
                System.out.println("Error: '" + algo + "' is not a valid algorithm");
            }
        }
    }
}

 public void startServer(int port, InetAddress address) throws IOException, InterruptedException {
    ServerSocketChannel channel = ServerSocketChannel.open();
    ServerSocket serverSocket = channel.socket();
    serverSocket.setReuseAddress(true);
    serverSocket.bind(new InetSocketAddress(address, port));

    CountDownLatch latch = new CountDownLatch(1);

    new Thread(() -> {
        latch.countDown();
        while (!Thread.currentThread().isInterrupted()) {
            try {
                Socket client = serverSocket.accept();
                client.close();
            } catch (IOException e) {
                break;
            }
        }
    }).start();

    latch.await();
}

import java.io.InputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.security.MessageDigest;

public class FileHashUtil {
    public static void generateMD5(String filePath) {
        try {
            System.out.println("Starting MD5 hash generation for: " + filePath);

            Path inputPath = Paths.get(filePath);
            Path outputPath = Paths.get(filePath + ".md5");

            System.out.println("Initializing MD5 digest...");
            MessageDigest md = MessageDigest.getInstance("MD5");

            System.out.println("Reading file contents...");
            try (InputStream is = Files.newInputStream(inputPath)) {
                byte[] buffer = new byte[8192];
                int bytesRead;
                while ((bytesRead = is.read(buffer)) != -1) {
                    md.update(buffer, 0, bytesRead);
                }
            }

            System.out.println("Computing hash...");
            byte[] digest = md.digest();
            StringBuilder hexString = new StringBuilder();
            for (byte b : digest) {
                hexString.append(String.format("%02x", b & 0xff));
            }
            String hash = hexString.toString();

            System.out.println("Writing hash to: " + outputPath);
            Files.write(outputPath, hash.getBytes());

            System.out.println("MD5 hash generation completed successfully.");
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}

