        String concatenated = userName + url;
        byte[] hash = digest.digest(concatenated.getBytes());
        StringBuilder hexString = new StringBuilder();
        for (byte b : hash) {
            hexString.append(String.format("%02x", b));
        }
        String uniqueId = hexString.toString();

        MyObject entity = new MyObject();
        entity.setUniqueId(uniqueId);
        entity.setUserName(userName);
        entity.setUrl(url);
        entity.setActive(active);

        dao.saveOrUpdate(entity);
    } catch (NoSuchAlgorithmException e) {
        throw new IllegalArgumentException("Invalid algorithm: " + algorithm, e);
    }
