public class ErrorStreamByteCounter {
    public static long countErrorBytes(String command) throws IOException {
        Process process = Runtime.getRuntime().exec(command);
        long byteCount = 0;
        try (InputStream errorStream = process.getErrorStream()) {
            byte[] buffer = new byte[1024];
            int bytesRead;
            while ((bytesRead = errorStream.read(buffer)) != -1) {
                byteCount += bytesRead;
            }
        }
        return byteCount;
    }

