import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;

public String generateETag(Change change) {
    try {
        MessageDigest md = MessageDigest.getInstance("MD5");

        if (change.getLastUpdated() != null) {
            md.update(change.getLastUpdated().toString().getBytes(StandardCharsets.UTF_8));
        }

        md.update(String.valueOf(change.getRowVersion()).getBytes(StandardCharsets.UTF_8));
        md.update(String.valueOf(change.getAccountId()).getBytes(StandardCharsets.UTF_8));

        ProjectState projectState = change.getProjectState();
        if (projectState != null) {
            for (Revision revision : projectState.getRevisions()) {
                md.update(String.valueOf(revision.getId()).getBytes(StandardCharsets.UTF_8));
            }
        }

        byte[] hash = md.digest();
        StringBuilder sb = new StringBuilder();
        for (byte b : hash) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    } catch (NoSuchAlgorithmException e) {
        throw new RuntimeException(e);
    }
}

