import javax.net.ssl.SSLSocketFactory;
import java.io.IOException;
import java.io.OutputStream;
import java.net.InetSocketAddress;
import java.net.Socket;
import javax.net.SocketFactory;

public class SocketConnectionFactory {

    public static Socket createConnection(String host, int port, boolean useSSL, 
                                         int connectTimeout, int readTimeout, 
                                         byte[] initPattern) throws IOException {
        Socket socket = null;
        try {
            SocketFactory factory = useSSL ? SSLSocketFactory.getDefault() : SocketFactory.getDefault();
            socket = factory.createSocket();
            socket.connect(new InetSocketAddress(host, port), connectTimeout);
            socket.setSoTimeout(readTimeout);

            if (initPattern != null && initPattern.length > 0) {
                OutputStream out = socket.getOutputStream();
                out.write(initPattern);
                out.flush();
            }

            return socket;
        } catch (IOException e) {
            if (socket != null) {
                try {
                    socket.close();
                } catch (IOException ignored) {}
            }
            throw e;
        }
    }
}
