import org.springframework.http.converter.HttpMessageNotReadableException;
import javax.xml.transform.Source;
import javax.xml.transform.stax.StAXSource;
import javax.xml.stream.XMLInputFactory;
import javax.xml.stream.XMLStreamException;
import javax.xml.stream.XMLStreamReader;
import java.io.IOException;
import java.io.InputStream;
import java.io.PushbackInputStream;

public class XmlSourceReader {

    public Source createSource(InputStream inputStream) {
        try {
            if (inputStream == null) {
                throw new HttpMessageNotReadableException("Input stream is null");
            }

            PushbackInputStream pushbackStream = new PushbackInputStream(inputStream);
            int firstByte = pushbackStream.read();
            if (firstByte == -1) {
                throw new HttpMessageNotReadableException("Input stream is empty");
            }
            pushbackStream.unread(firstByte);

            XMLInputFactory factory = XMLInputFactory.newInstance();
            XMLStreamReader xmlStreamReader = factory.createXMLStreamReader(pushbackStream);
            return new StAXSource(xmlStreamReader);
        } catch (XMLStreamException | IOException ex) {
            throw new HttpMessageNotReadableException("Failed to parse XML input stream", ex);
        }
    }
}

 import java.io.*;
import java.util.Objects;

public class SerializationDemo implements Serializable {
    private static final long serialVersionUID = 1L;
    private String name;
    private int age;
    private double salary;

    public SerializationDemo(String name, int age, double salary) {
        this.name = name;
        this.age = age;
        this.salary = salary;
    }

    public String getName() { return name; }
    public int getAge() { return age; }
    public double getSalary() { return salary; }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        SerializationDemo that = (SerializationDemo) o;
        return age == that.age && 
               Double.compare(that.salary, salary) == 0 && 
               Objects.equals(name, that.name);
    }

    @Override
    public int hashCode() {
        return Objects.hash(name, age, salary);
    }

    public static void main(String[] args) {
        SerializationDemo original = new SerializationDemo("John Doe", 30, 50000.0);

        byte[] serializedData = serialize(original);
        SerializationDemo deserialized = deserialize(serializedData);

        boolean isEqual = original.equals(deserialized);
        System.out.println("Original: " + original.getName() + ", " + original.getAge() + ", " + original.getSalary());
        System.out.println("Deserialized: " + deserialized.getName() + ", " + deserialized.getAge() + ", " + deserialized.getSalary());
        System.out.println("Objects are equal: " + isEqual);
    }

    public static byte[] serialize(Object obj) {
        try (ByteArrayOutputStream baos = new ByteArrayOutputStream();
             ObjectOutputStream oos = new ObjectOutputStream(baos)) {
            oos.writeObject(obj);
            oos.flush();
            return baos.toByteArray();
        } catch (IOException e) {
            throw new RuntimeException("Serialization failed", e);
        }
    }

    public static SerializationDemo deserialize(byte[] data) {
        try (ByteArrayInputStream bais = new ByteArrayInputStream(data);
             ObjectInputStream ois = new ObjectInputStream(bais)) {
            return (SerializationDemo) ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            throw new RuntimeException("Deserialization failed", e);
        }
    }
}

