 import java.io.*;
import java.nio.file.*;
import java.security.MessageDigest;
import io.airlift.compress.lzo.LzoCompressor;

public class FileCompressor {
    public static String compressAndHash(String filePath, int compressionLevel) throws Exception {
        byte[] input = Files.readAllBytes(Paths.get(filePath));
        LzoCompressor compressor = new LzoCompressor();
        int maxCompressedLength = compressor.maxCompressedLength(input.length);
        byte[] compressed = new byte[maxCompressedLength];
        int compressedSize = compressor.compress(input, 0, input.length, compressed, 0, maxCompressedLength);
        byte[] actualCompressed = new byte[compressedSize];
        System.arraycopy(compressed, 0, actualCompressed, 0, compressedSize);
        MessageDigest md = MessageDigest.getInstance("MD5");
        byte[] digest = md.digest(actualCompressed);
        StringBuilder sb = new StringBuilder();
        for (byte b : digest) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }
}

 import java.io.*;
import java.nio.MappedByteBuffer;
import java.nio.channels.FileChannel;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.StandardOpenOption;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public class FileChecksumUtil {

    public enum ReadType {
        BUFFERED,
        UNBUFFERED,
        MEMORY_MAPPED
    }

    public static String getMD5Checksum(String filePath, ReadType readType) {
        if (filePath == null || readType == null) {
            throw new IllegalArgumentException("File path and read type must not be null");
        }

        try {
            Path path = Paths.get(filePath);
            MessageDigest md = MessageDigest.getInstance("MD5");

            switch (readType) {
                case BUFFERED:
                    try (BufferedInputStream bis = new BufferedInputStream(new FileInputStream(path.toFile()))) {
                        byte[] buffer = new byte[8192];
                        int read;
                        while ((read = bis.read(buffer)) != -1) {
                            md.update(buffer, 0, read);
                        }
                    }
                    break;

                case UNBUFFERED:
                    try (FileInputStream fis = new FileInputStream(path.toFile())) {
                        byte[] buffer = new byte[8192];
                        int read;
                        while ((read = fis.read(buffer)) != -1) {
                            md.update(buffer, 0, read);
                        }
                    }
                    break;

                case MEMORY_MAPPED:
                    try (FileChannel channel = FileChannel.open(path, StandardOpenOption.READ)) {
                        MappedByteBuffer buffer = channel.map(FileChannel.MapMode.READ_ONLY, 0, channel.size());
                        md.update(buffer);
                    }
                    break;
            }

            byte[] digest = md.digest();
            StringBuilder sb = new StringBuilder();
            for (byte b : digest) {
                sb.append(String.format("%02x", b));
            }
            return sb.toString();

        } catch (IOException | NoSuchAlgorithmException e) {
            throw new RuntimeException("Failed to calculate MD5 checksum for file: " + filePath, e);
        }
    }
}

