import akka.actor.*;
import akka.io.Tcp;
import akka.io.TcpMessage;
import akka.util.ByteString;
import java.net.InetSocketAddress;

public class DiscoverySystem {
    public static void main(String[] args) {
        ActorSystem system = ActorSystem.create("DiscoverySystem");
        InetSocketAddress local = new InetSocketAddress("0.0.0.0", 8080);
        InetSocketAddress remote = new InetSocketAddress("127.0.0.1", 9000);
        system.actorOf(Props.create(DiscoveryActor.class, local, remote));
    }

    static class DiscoveryActor extends AbstractActor {
        private final InetSocketAddress local;
        private final InetSocketAddress remote;

        public DiscoveryActor(InetSocketAddress local, InetSocketAddress remote) {
            this.local = local;
            this.remote = remote;
        }

        @Override
        public void preStart() {
            ActorRef manager = Tcp.get(getContext().getSystem()).manager();
            manager.tell(TcpMessage.bind(getSelf(), local, 100), getSelf());
            manager.tell(TcpMessage.connect(remote), getSelf());
        }

        @Override
        public Receive createReceive() {
            return receiveBuilder()
                .match(Tcp.Bound.class, msg -> {})
                .match(Tcp.Connected.class, msg -> {
                    ActorRef connection = getSender();
                    if (msg.remoteAddress().equals(remote)) {
                        connection.tell(TcpMessage.register(getSelf()), getSelf());
                        connection.tell(TcpMessage.write(ByteString.fromString("DISCOVERY")), getSelf());
                    } else {
                        connection.tell(TcpMessage.register(getSelf()), getSelf());
                    }
                })
                .match(Tcp.Received.class, msg -> {})
                .match(Tcp.CommandFailed.class, msg -> getContext().stop(getSelf()))
                .build();
        }
    }
}
