import java.io.*;
import java.lang.reflect.*;
import java.net.Socket;

public void handleClient(Socket socket) {
    try (BufferedReader in = new BufferedReader(new InputStreamReader(socket.getInputStream()));
         PrintWriter out = new PrintWriter(socket.getOutputStream(), true)) {

        String request = in.readLine();
        if (request == null) return;

        String[] parts = request.split("\\|");
        if (parts.length < 2) {
            out.println("ERROR:Invalid format. Expected: ClassName|methodName|arg1|arg2|...");
            return;
        }

        String className = parts[0];
        String methodName = parts[1];
        Object[] args = new String[parts.length - 2];
        System.arraycopy(parts, 2, args, 0, args.length);

        Class<?> clazz = Class.forName(className);
        Method method = null;

        for (Method m : clazz.getMethods()) {
            if (m.getName().equals(methodName) && m.getParameterCount() == args.length) {
                method = m;
                break;
            }
        }

        if (method == null) {
            out.println("ERROR:Method not found: " + methodName);
            return;
        }

        Object instance = null;
        if (!Modifier.isStatic(method.getModifiers())) {
            instance = clazz.getDeclaredConstructor().newInstance();
        }

        Object result = method.invoke(instance, args);
        out.println(result != null ? result.toString() : "null");

    } catch (Exception e) {
        try {
            new PrintWriter(socket.getOutputStream(), true).println("ERROR:" + e.getMessage());
        } catch (IOException ignored) {}
    }
}
