import java.io.IOException;
import java.net.InetAddress;
import java.net.InetSocketAddress;
import java.net.NetworkInterface;
import java.net.Socket;
import java.net.SocketAddress;
import java.security.PrivilegedExceptionAction;
import javax.security.auth.Subject;
import javax.security.auth.login.LoginContext;
import javax.security.auth.login.LoginException;

public class KerberosSocketConnector {

    public Socket connect(
            final String remoteHost,
            final int remotePort,
            final String localHost,
            final int localPort,
            final int connectionTimeoutMillis,
            final int pingIntervalMillis) throws Exception {

        LoginContext loginContext = new LoginContext("KerberosClient");
        loginContext.login();
        final Subject subject = loginContext.getSubject();

        return Subject.doAs(subject, new PrivilegedExceptionAction<Socket>() {
            @Override
            public Socket run() throws Exception {
                Socket socket = new Socket();

                try {
                    if (localHost != null && !localHost.isEmpty()) {
                        InetAddress localAddress = InetAddress.getByName(localHost);
                        if (isLocalAddress(localAddress)) {
                            SocketAddress bindPoint = new InetSocketAddress(localAddress, localPort);
                            socket.bind(bindPoint);
                        }
                    }

                    socket.setKeepAlive(true);
                    setPingInterval(socket, pingIntervalMillis);

                    SocketAddress remoteAddress = new InetSocketAddress(remoteHost, remotePort);
                    socket.connect(remoteAddress, connectionTimeoutMillis);

                    return socket;
                } catch (IOException e) {
                    try {
                        socket.close();
                    } catch (IOException ex) {
                        e.addSuppressed(ex);
                    }
                    throw e;
                }
            }
        });
    }

    private boolean isLocalAddress(InetAddress address) throws IOException {
        if (address.isLoopbackAddress()) {
            return true;
        }
        return NetworkInterface.getByInetAddress(address) != null;
    }

    private void setPingInterval(Socket socket, int intervalMillis) {
        try {
            socket.setOption(java.net.StandardSocketOptions.TCP_KEEPIDLE, intervalMillis / 1000);
        } catch (UnsupportedOperationException | IOException e) {
            // Ignore if not supported on this platform
        }
    }
}
