import java.io.*;

public class ProcessInstanceSerializer {

    public static ProcessInstance serializeAndDeserialize(ProcessInstance original) throws IOException, ClassNotFoundException {
        byte[] serializedData;

        try (ByteArrayOutputStream baos = new ByteArrayOutputStream();
             ObjectOutputStream oos = new ObjectOutputStream(baos)) {
            oos.writeObject(original);
            serializedData = baos.toByteArray();
        }

        ProcessInstance deserialized;
        try (ByteArrayInputStream bais = new ByteArrayInputStream(serializedData);
             ObjectInputStream ois = new ObjectInputStream(bais)) {
            deserialized = (ProcessInstance) ois.readObject();
        }

        if (!original.getId().equals(deserialized.getId())) {
            throw new IllegalStateException("ID mismatch: expected " + original.getId() + " but found " + deserialized.getId());
        }

        return deserialized;
    }
}
