import java.io.IOException;
import java.util.List;
import java.util.logging.Level;
import java.util.logging.Logger;

public class ProcessExecutor {
    private static final Logger LOGGER = Logger.getLogger(ProcessExecutor.class.getName());

    public boolean executeProcess(List<String> commandArgs) {
        if (commandArgs == null || commandArgs.isEmpty()) {
            LOGGER.warning("Command arguments list is null or empty");
            return false;
        }

        try {
            String[] commandArray = commandArgs.toArray(new String[0]);
            LOGGER.info("Executing process with arguments: " + commandArgs);

            Process process = Runtime.getRuntime().exec(commandArray);

            WatchdogThread watchdog = new WatchdogThread(process, commandArgs.get(0));
            watchdog.start();

            LOGGER.info("Process started successfully");
            return true;

        } catch (IOException e) {
            LOGGER.log(Level.SEVERE, "Failed to start process: " + e.getMessage(), e);
            return false;
        }
    }

    private static class WatchdogThread extends Thread {
        private final Process process;
        private final String processName;

        public WatchdogThread(Process process, String processName) {
            this.process = process;
            this.processName = processName;
            setDaemon(true);
            setName("Watchdog-" + processName);
        }

        @Override
        public void run() {
            try {
                int exitCode = process.waitFor();
                LOGGER.info("Process '" + processName + "' terminated with exit code: " + exitCode);
            } catch (InterruptedException e) {
                LOGGER.warning("Watchdog for '" + processName + "' was interrupted");
                Thread.currentThread().interrupt();
            }
        }
    }
}
