import java.io.*;
import java.util.*;

public class CodeSigner {
    public static int signCodeFile(String jarFile, String keystore, String alias, String password) {
        List<String> command = new ArrayList<>();
        command.add("jarsigner");
        command.add("-keystore");
        command.add(keystore);

        if (password != null && !password.isEmpty()) {
            command.add("-storepass");
            command.add(password);
        }

        command.add(jarFile);
        command.add(alias);

        ProcessBuilder pb = new ProcessBuilder(command);
        pb.redirectErrorStream(true);

        try {
            Process process = pb.start();

            try (BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    System.out.println(line);
                }
            }

            return process.waitFor();
        } catch (IOException | InterruptedException e) {
            System.err.println("Error: " + e.getMessage());
            return -1;
        }
    }

    public static void main(String[] args) {
        if (args.length < 3) {
            System.err.println("Usage: java CodeSigner <jar-file> <keystore> <alias> [password]");
            System.exit(1);
        }

        String jarFile = args[0];
        String keystore = args[1];
        String alias = args[2];
        String password = args.length > 3 ? args[3] : "";

        int result = signCodeFile(jarFile, keystore, alias, password);
        System.exit(result);
    }
}
