import java.io.*;
import java.util.*;

public class SerializationTest implements Serializable {
    private static final long serialVersionUID = 1L;
    private String data;
    private int number;
    private List<String> items;

    public SerializationTest() {
        this.data = "Test data for serialization performance testing";
        this.number = 12345;
        this.items = new ArrayList<>();
        for (int i = 0; i < 100; i++) {
            this.items.add("Item " + i);
        }
    }

    public static void main(String[] args) {
        SerializationTest object = new SerializationTest();
        int iterations = 500;

        byte[] serializedData = null;
        long startTime = System.nanoTime();

        for (int i = 0; i < iterations; i++) {
            try {
                ByteArrayOutputStream baos = new ByteArrayOutputStream();
                ObjectOutputStream oos = new ObjectOutputStream(baos);
                oos.writeObject(object);
                oos.close();
                serializedData = baos.toByteArray();
            } catch (IOException e) {
                e.printStackTrace();
            }
        }

        long serializationTime = System.nanoTime() - startTime;
        startTime = System.nanoTime();

        for (int i = 0; i < iterations; i++) {
            try {
                ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(serializedData));
                SerializationTest deserialized = (SerializationTest) ois.readObject();
                ois.close();
            } catch (Exception e) {
                e.printStackTrace();
            }
        }

        long deserializationTime = System.nanoTime() - startTime;

        System.out.println("Iterations: " + iterations);
        System.out.println("Serialized size: " + serializedData.length + " bytes");
        System.out.println("Serialization time: " + (serializationTime / 1_000_000.0) + " ms");
        System.out.println("Deserialization time: " + (deserializationTime / 1_000_000.0) + " ms");
        System.out.println("Total time: " + ((serializationTime + deserializationTime) / 1_000_000.0) + " ms");
    }
}
