import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.ArrayList;
import java.util.List;

public class PackageManager {
    public static List<String> getInstalledPackages() throws IOException {
        List<String> packages = new ArrayList<>();
        String os = System.getProperty("os.name").toLowerCase();
        ProcessBuilder processBuilder;

        if (os.contains("linux")) {
            processBuilder = new ProcessBuilder("dpkg", "-l");
        } else if (os.contains("mac")) {
            processBuilder = new ProcessBuilder("brew", "list");
        } else if (os.contains("win")) {
            processBuilder = new ProcessBuilder("wmic", "product", "get", "name");
        } else {
            throw new IOException("Unsupported operating system: " + os);
        }

        try {
            Process process = processBuilder.start();

            try (BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    line = line.trim();
                    if (!line.isEmpty() && !line.startsWith("=") && !line.toLowerCase().contains("name")) {
                        packages.add(line);
                    }
                }
            }

            int exitCode = process.waitFor();
            if (exitCode != 0) {
                if (os.contains("linux")) {
                    return getInstalledPackagesRpm();
                }
                throw new IOException("Command exited with non-zero code: " + exitCode);
            }

        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new IOException("Process execution was interrupted", e);
        }

        return packages;
    }

    private static List<String> getInstalledPackagesRpm() throws IOException {
        List<String> packages = new ArrayList<>();
        try {
            Process process = new ProcessBuilder("rpm", "-qa").start();

            try (BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    if (!line.trim().isEmpty()) {
                        packages.add(line.trim());
                    }
                }
            }

            process.waitFor();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new IOException("RPM process was interrupted", e);
        }
        return packages;
    }
}
