import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;
import java.util.zip.CRC32;

public class StringHasher {

    public enum HashFunction {
        JAVA_HASH_CODE,
        CRC32,
        MD5_TRUNCATED,
        SHA256_TRUNCATED,
        FNV1A_64
    }

    public static long hash(String input, HashFunction function) {
        if (input == null) {
            throw new IllegalArgumentException("Input string cannot be null");
        }

        switch (function) {
            case JAVA_HASH_CODE:
                return input.hashCode() & 0xFFFFFFFFL;
            case CRC32:
                CRC32 crc32 = new CRC32();
                crc32.update(input.getBytes(StandardCharsets.UTF_8));
                return crc32.getValue();
            case MD5_TRUNCATED:
                return truncateToLong(digest(input, "MD5"));
            case SHA256_TRUNCATED:
                return truncateToLong(digest(input, "SHA-256"));
            case FNV1A_64:
                return fnv1a64(input);
            default:
                throw new IllegalArgumentException("Unsupported hash function");
        }
    }

    private static byte[] digest(String input, String algorithm) {
        try {
            MessageDigest md = MessageDigest.getInstance(algorithm);
            return md.digest(input.getBytes(StandardCharsets.UTF_8));
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("Algorithm not available: " + algorithm, e);
        }
    }

    private static long truncateToLong(byte[] bytes) {
        long result = 0;
        int length = Math.min(bytes.length, 8);
        for (int i = 0; i < length; i++) {
            result = (result << 8) | (bytes[i] & 0xFF);
        }
        return result;
    }

    private static long fnv1a64(String input) {
        final long OFFSET_BASIS = 0xcbf29ce484222325L;
        final long FNV_PRIME = 0x100000001b3L;
        long hash = OFFSET_BASIS;
        for (byte b : input.getBytes(StandardCharsets.UTF_8)) {
            hash ^= (b & 0xFF);
            hash *= FNV_PRIME;
        }
        return hash;
    }
}
