import java.io.*;
import java.nio.file.*;

public static WalkMap loadWalkMap(String filePath) throws IOException, ClassNotFoundException {
    if (filePath == null) {
        throw new IllegalArgumentException("File path cannot be null");
    }

    Path path = Paths.get(filePath);
    if (!Files.exists(path)) {
        throw new FileNotFoundException("File does not exist: " + filePath);
    }

    String fileName = path.getFileName().toString();
    int lastDot = fileName.lastIndexOf('.');
    if (lastDot == -1 || lastDot == fileName.length() - 1) {
        throw new IllegalArgumentException("File has no extension: " + filePath);
    }

    String extension = fileName.substring(lastDot).toLowerCase();

    switch (extension) {
        case ".objv":
            try {
                String content = new String(Files.readAllBytes(path), java.nio.charset.StandardCharsets.UTF_8);
                return new ViewMap(content);
            } catch (Exception e) {
                throw new IOException("Invalid format for .objv file", e);
            }

        case ".objp":
            try {
                String content = new String(Files.readAllBytes(path), java.nio.charset.StandardCharsets.UTF_8);
                return new PathsMap(content);
            } catch (Exception e) {
                throw new IOException("Invalid format for .objp file", e);
            }

        case ".jrd3m":
            try (ObjectInputStream ois = new ObjectInputStream(Files.newInputStream(path))) {
                Object obj = ois.readObject();
                if (obj instanceof WalkMap) {
                    return (WalkMap) obj;
                } else {
                    throw new IOException("Invalid format: file does not contain a WalkMap object");
                }
            } catch (IOException | ClassNotFoundException e) {
                throw e;
            } catch (Exception e) {
                throw new IOException("Error reading serialized WalkMap", e);
            }

        default:
            throw new IllegalArgumentException("Unsupported file extension: " + extension);
    }
}
