import org.w3c.dom.*;
import org.xml.sax.SAXException;

class DataRecord {
    private final String source;
    private final Map<String, Object> fields;
    private final long timestamp;

    public DataRecord(String source) {
        this.source = source;
        this.fields = new LinkedHashMap<>();
        this.timestamp = System.currentTimeMillis();
    }

    public void addField(String key, Object value) {
        fields.put(key, value);
    }

    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder();
        sb.append("{\n");
        sb.append("  \"source\": \"").append(escapeJson(source)).append("\",\n");
        sb.append("  \"timestamp\": ").append(timestamp).append(",\n");
        sb.append("  \"data\": {\n");
        int i = 0;
        for (Map.Entry<String, Object> entry : fields.entrySet()) {
            sb.append("    \"").append(escapeJson(entry.getKey())).append("\": ");
            if (entry.getValue() instanceof Number || entry.getValue() instanceof Boolean) {
                sb.append(entry.getValue());
            } else {
                sb.append("\"").append(escapeJson(String.valueOf(entry.getValue()))).append("\"");
            }
            if (++i < fields.size()) sb.append(",");
            sb.append("\n");
        }
        sb.append("  }\n");
        sb.append("}");
        return sb.toString();
    }

    private String escapeJson(String s) {
        if (s == null) return "null";
        return s.replace("\\", "\\\\").replace("\"", "\\\"").replace("\n", "\\n").replace("\r", "\\r").replace("\t", "\\t");
    }
}

