 import javax.xml.parsers.SAXParser;
import javax.xml.parsers.SAXParserFactory;
import org.xml.sax.helpers.DefaultHandler;
import java.io.File;
import java.util.Map;
import java.util.TreeMap;

public class PrefixFrequencyParser {

    public static void main(String[] args) {
        try {
            SAXParserFactory factory = SAXParserFactory.newInstance();
            factory.setNamespaceAware(true);
            SAXParser saxParser = factory.newSAXParser();

            FrequencyHandler handler = new FrequencyHandler();

            for (String filename : args) {
                saxParser.parse(new File(filename), handler);
            }

            for (Map.Entry<String, Integer> entry : handler.getFrequencies().entrySet()) {
                System.out.println(entry.getKey() + ": " + entry.getValue());
            }

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    static class FrequencyHandler extends DefaultHandler {
        private Map<String, Integer> frequencies = new TreeMap<>();

        @Override
        public void startPrefixMapping(String prefix, String uri) {
            frequencies.put(prefix, frequencies.getOrDefault(prefix, 0) + 1);
        }

        public Map<String, Integer> getFrequencies() {
            return frequencies;
        }
    }
}

