import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.Map;

public class HashUtil {
    public static String generateHash(Map<String, String> pathMap, String moduleName, boolean createSymlinks, boolean createHeaderMap) throws NoSuchAlgorithmException {
        MessageDigest digest = MessageDigest.getInstance("SHA-1");

        digest.update(moduleName.getBytes());
        digest.update(Boolean.toString(createSymlinks).getBytes());
        digest.update(Boolean.toString(createHeaderMap).getBytes());

        for (Map.Entry<String, String> entry : pathMap.entrySet()) {
            digest.update(entry.getKey().getBytes());
            if (entry.getValue() != null) {
                digest.update(entry.getValue().getBytes());
            }
        }

        byte[] hashBytes = digest.digest();
        StringBuilder hexString = new StringBuilder();
        for (byte b : hashBytes) {
            hexString.append(String.format("%02x", b));
        }

        return hexString.toString();
    }
}
