import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.net.URI;
import java.util.Map;
import java.util.HashMap;

public class DeviceDataSender {
    public void sendDeviceInfo(HttpClient httpClient, String serverUrl) throws Exception {
        Map<String, String> deviceMap = new HashMap<>();
        deviceMap.put("os_name", System.getProperty("os.name"));
        deviceMap.put("os_version", System.getProperty("os.version"));
        deviceMap.put("os_architecture", System.getProperty("os.arch"));
        deviceMap.put("java_version", System.getProperty("java.version"));
        deviceMap.put("user_name", System.getProperty("user.name"));
        deviceMap.put("user_timezone", System.getProperty("user.timezone"));

        StringBuilder jsonBuilder = new StringBuilder("{");
        boolean first = true;
        for (Map.Entry<String, String> entry : deviceMap.entrySet()) {
            if (!first) {
                jsonBuilder.append(",");
            }
            first = false;
            jsonBuilder.append("\"").append(entry.getKey()).append("\":");
            String value = entry.getValue() == null ? "" : entry.getValue();
            jsonBuilder.append("\"").append(value.replace("\\", "\\\\").replace("\"", "\\\"")).append("\"");
        }
        jsonBuilder.append("}");

        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create(serverUrl))
            .header("Content-Type", "application/json")
            .POST(HttpRequest.BodyPublishers.ofString(jsonBuilder.toString()))
            .build();

        httpClient.send(request, HttpResponse.BodyHandlers.discarding());
    }
}
