import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.xpath.XPath;
import javax.xml.xpath.XPathConstants;
import javax.xml.xpath.XPathFactory;
import org.w3c.dom.Document;
import org.xml.sax.InputSource;
import java.io.StringReader;

public class XmlValidator {
    public FailureDetail validateXPath(String responseValue, String xpathExpression) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new InputSource(new StringReader(responseValue)));

            XPath xpath = XPathFactory.newInstance().newXPath();
            Boolean result = (Boolean) xpath.evaluate(xpathExpression, document, XPathConstants.BOOLEAN);

            if (Boolean.TRUE.equals(result)) {
                return null;
            } else {
                return new FailureDetail("XPath expression returned false: " + xpathExpression);
            }
        } catch (Exception e) {
            return new FailureDetail("Error processing XML or evaluating XPath: " + e.getMessage());
        }
    }

    public static class FailureDetail {
        private final String message;

        public FailureDetail(String message) {
            this.message = message;
        }

        public String getMessage() {
            return message;
        }
    }
}
