import java.io.*;
import java.util.*;

public class NFASerializationUtil {

    public static class NFA implements Serializable {
        private static final long serialVersionUID = 1L;
        private int windowLength;
        private Set<Integer> states;
        private Map<Integer, Map<Character, Set<Integer>>> transitions;
        private int initialState;
        private Set<Integer> acceptingStates;

        public NFA(int windowLength) {
            this.windowLength = windowLength;
            this.states = new HashSet<>();
            this.transitions = new HashMap<>();
            this.acceptingStates = new HashSet<>();
            initializeFromWindowLength();
        }

        private void initializeFromWindowLength() {
            for (int i = 0; i <= windowLength; i++) {
                states.add(i);
                transitions.put(i, new HashMap<>());
                if (i > 0) {
                    Map<Character, Set<Integer>> trans = new HashMap<>();
                    Set<Integer> nextStates = new HashSet<>();
                    nextStates.add(i);
                    trans.put('0', nextStates);
                    Set<Integer> loopStates = new HashSet<>();
                    loopStates.add(i - 1);
                    trans.put('1', loopStates);
                    transitions.put(i - 1, trans);
                }
            }
            initialState = 0;
            acceptingStates.add(windowLength);
        }

        @Override
        public boolean equals(Object obj) {
            if (this == obj) return true;
            if (obj == null || getClass() != obj.getClass()) return false;
            NFA other = (NFA) obj;
            return windowLength == other.windowLength &&
                   initialState == other.initialState &&
                   Objects.equals(states, other.states) &&
                   Objects.equals(transitions, other.transitions) &&
                   Objects.equals(acceptingStates, other.acceptingStates);
        }

        @Override
        public int hashCode() {
            return Objects.hash(windowLength, states, transitions, initialState, acceptingStates);
        }
    }

    public static boolean createSerializeDeserializeAndCompare(int windowLength) {
        try {
            NFA original = new NFA(windowLength);

            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            ObjectOutputStream oos = new ObjectOutputStream(baos);
            oos.writeObject(original);
            oos.close();

            ByteArrayInputStream bais = new ByteArrayInputStream(baos.toByteArray());
            ObjectInputStream ois = new ObjectInputStream(bais);
            NFA deserialized = (NFA) ois.readObject();
            ois.close();

            return original.equals(deserialized);
        } catch (IOException | ClassNotFoundException e) {
            throw new RuntimeException(e);
        }
    }
}
