 ```java
import java.util.Random;

interface Service {
    void start();
    void stop();
}

interface MessagingSystem {
    void sendMessage(String message);
}

public class ServiceManager {
    private final Service service;
    private final MessagingSystem messagingSystem;
    private final Random random;
    private final long minDelay;
    private final long maxDelay;
    private volatile boolean active = true;

    public ServiceManager(Service service, MessagingSystem messagingSystem, long minDelayMs, long maxDelayMs) {
        this.service = service;
        this.messagingSystem = messagingSystem;
        this.random = new Random();
        this.minDelay = minDelayMs;
        this.maxDelay = maxDelayMs;
    }

    public void execute() {
        while (active && !Thread.currentThread().isInterrupted()) {
            try {
                service.start();

                long runDuration = randomDelay();
                Thread.sleep(runDuration);

                service.stop();
                messagingSystem.sendMessage("Service stopped after running for " + runDuration + "ms");

                Thread.sleep(randomDelay());

            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                break;
            }
        }
    }

    private long randomDelay() {
        return minDelay + (long) (random.nextDouble() * (maxDelay - minDelay));
    }

    public void stop() {
        active = false;
    }

    public static void main(String[] args) {
        Service svc = new Service() {
            public void start() { System.out.println("Starting service"); }
            public void stop() { System.out.println("Stopping service"); }
        };

        MessagingSystem msg = m -> System.out.println("Messaging: " + m);

        ServiceManager manager = new ServiceManager(svc, msg, 1000, 3000);

        Runtime.getRuntime().addShutdownHook(new Thread(manager::stop));

        manager.execute();
    }
}
