import java.io.IOException;

public class KeyboardSimulator {
    public static void simulateKeyboardInput(String... keys) {
        if (keys == null || keys.length == 0) {
            return;
        }

        StringBuilder input = new StringBuilder();
        for (String key : keys) {
            if (key != null) {
                input.append(key);
            }
        }

        String text = input.toString();
        if (text.isEmpty()) {
            return;
        }

        try {
            String os = System.getProperty("os.name").toLowerCase();
            Process process;

            if (os.contains("win")) {
                String escaped = text.replace("'", "''");
                String command = String.format(
                    "Add-Type -AssemblyName System.Windows.Forms; " +
                    "[System.Windows.Forms.SendKeys]::SendWait('%s');", 
                    escaped
                );
                process = Runtime.getRuntime().exec(new String[]{"powershell.exe", "-Command", command});
            } else if (os.contains("mac")) {
                String escaped = text.replace("\"", "\\\"");
                String script = String.format("tell application \"System Events\" to keystroke \"%s\"", escaped);
                process = Runtime.getRuntime().exec(new String[]{"osascript", "-e", script});
            } else {
                process = Runtime.getRuntime().exec(new String[]{"xdotool", "type", text});
            }

            int exitCode = process.waitFor();
            if (exitCode != 0) {
                System.err.println("Keyboard simulation failed with exit code: " + exitCode);
            }
        } catch (IOException e) {
            System.err.println("IO error during keyboard simulation: " + e.getMessage());
        } catch (InterruptedException e) {
            System.err.println("Keyboard simulation interrupted: " + e.getMessage());
            Thread.currentThread().interrupt();
        } catch (Exception e) {
            System.err.println("Unexpected error during keyboard simulation: " + e.getMessage());
        }
    }
}
