public String encrypt(String plaintext) {
    try {
        Company company = companyService.getCompany();
        byte[] keyBytes = company.getSecretKey().getBytes(StandardCharsets.UTF_8);
        byte[] ivBytes = company.getInitializationVector().getBytes(StandardCharsets.UTF_8);

        Cipher cipher = Cipher.getInstance("Blowfish/CBC/PKCS5Padding");
        SecretKeySpec secretKey = new SecretKeySpec(keyBytes, "Blowfish");
        IvParameterSpec iv = new IvParameterSpec(ivBytes);

        cipher.init(Cipher.ENCRYPT_MODE, secretKey, iv);
        byte[] encrypted = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));

        return Base64.getEncoder().encodeToString(encrypted);
    } catch (Exception e) {
        throw new RuntimeException("Encryption failed", e);
    }
}
