import java.security.MessageDigest;

public static String encryptMessage(String message, String encodingScheme, boolean toUpperCase) throws Exception {
    if (toUpperCase) {
        message = message.toUpperCase();
    }
    MessageDigest md = MessageDigest.getInstance("MD5");
    byte[] digest = md.digest(message.getBytes(encodingScheme));
    StringBuilder sb = new StringBuilder();
    for (byte b : digest) {
        sb.append(String.format("%02x", b));
    }
    return sb.toString();
