import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.concurrent.*;

public class TemplateQueryExecutor {

    public String generateQueries(String toolPath, String template) 
            throws IOException, InterruptedException, ExecutionException, TimeoutException {

        ProcessBuilder pb = new ProcessBuilder(toolPath);
        pb.redirectErrorStream(true);

        Process process = pb.start();

        ExecutorService executor = Executors.newSingleThreadExecutor();
        Future<String> outputFuture = executor.submit(() -> {
            StringBuilder sb = new StringBuilder();
            try (BufferedReader reader = new BufferedReader(
                    new InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    sb.append(line).append(System.lineSeparator());
                }
            }
            return sb.toString();
        });

        try (BufferedWriter writer = new BufferedWriter(
                new OutputStreamWriter(process.getOutputStream(), StandardCharsets.UTF_8))) {
            writer.write(template);
        }

        int exitCode = process.waitFor();
        String output = outputFuture.get(30, TimeUnit.SECONDS);
        executor.shutdownNow();

        if (exitCode != 0) {
            throw new RuntimeException("Tool failed with exit code: " + exitCode);
        }

        return output;
    }

    public static void main(String[] args) {
        TemplateQueryExecutor executor = new TemplateQueryExecutor();
        try {
            String template = "SELECT * FROM ${table} WHERE id = ${id}";
            String queries = executor.generateQueries("/usr/local/bin/querygen", template);
            System.out.print(queries);
        } catch (Exception e) {
            e.printStackTrace();
            System.exit(1);
        }
    }
}
