import java.io.File;
import java.io.IOException;
import javax.xml.parsers.ParserConfigurationException;
import javax.xml.parsers.SAXParser;
import javax.xml.parsers.SAXParserFactory;
import org.xml.sax.Attributes;
import org.xml.sax.ErrorHandler;
import org.xml.sax.SAXException;
import org.xml.sax.SAXParseException;
import org.xml.sax.helpers.DefaultHandler;

public class SecureSAXParser {

    public static void main(String[] args) {
        if (args.length != 1) {
            System.err.println("Usage: java SecureSAXParser <xml-file>");
            System.exit(1);
        }

        try {
            SAXParserFactory factory = SAXParserFactory.newInstance();
            configureSecurity(factory);

            SAXParser parser = factory.newSAXParser();
            SecureHandler handler = new SecureHandler();

            parser.parse(new File(args[0]), handler);

        } catch (ParserConfigurationException e) {
            System.err.println("Configuration error: " + e.getMessage());
            System.exit(1);
        } catch (SAXException e) {
            System.err.println("Parsing error: " + e.getMessage());
            System.exit(1);
        } catch (IOException e) {
            System.err.println("IO error: " + e.getMessage());
            System.exit(1);
        }
    }

    private static void configureSecurity(SAXParserFactory factory) throws ParserConfigurationException {
        try {
            factory.setNamespaceAware(true);
            factory.setValidating(false);
            factory.setXIncludeAware(false);

            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        } catch (SAXException e) {
            throw new ParserConfigurationException("Security feature not supported: " + e.getMessage());
        }
    }

    static class SecureHandler extends DefaultHandler {

        @Override
        public void startElement(String uri, String localName, String qName, Attributes attributes) {
            System.out.println("Start: " + qName);
        }

        @Override
        public void endElement(String uri, String localName, String qName) {
            System.out.println("End: " + qName);
        }

        @Override
        public void characters(char[] ch, int start, int length) {
            String content = new String(ch, start, length).trim();
            if (!content.isEmpty()) {
                System.out.println("Text: " + content);
            }
        }

        @Override
        public void warning(SAXParseException e) {
            System.err.println("Warning at line " + e.getLineNumber() + ": " + e.getMessage());
        }

        @Override
        public void error(SAXParseException e) throws SAXParseException {
            System.err.println("Error at line " + e.getLineNumber() + ": " + e.getMessage());
            throw e;
        }

        @Override
        public void fatalError(SAXParseException e) throws SAXParseException {
            System.err.println("Fatal error at line " + e.getLineNumber() + ": " + e.getMessage());
            throw e;
        }
    }
}

