```java
import java.io.*;

public class CommandExecutor {

    public static int executeCommand(String command) throws IOException, InterruptedException {
        if (command == null || command.trim().isEmpty()) {
            throw new IllegalArgumentException("Command cannot be null or empty");
        }

        String[] cmdArray = prepareCommand(command);
        Process process = Runtime.getRuntime().exec(cmdArray);

        new Thread(() -> {
            try (InputStream is = process.getInputStream()) {
                byte[] buffer = new byte[1024];
                while (is.read(buffer) != -1) {}
            } catch (IOException e) {}
        }).start();

        new Thread(() -> {
            try (InputStream is = process.getErrorStream()) {
                byte[] buffer = new byte[1024];
                while (is.read(buffer) != -1) {}
            } catch (IOException e) {}
        }).start();

        return process.waitFor();
    }

    private static String[] prepareCommand(String command) {
        boolean isWindows = System.getProperty("os.name").toLowerCase().contains("win");

        if (!isWindows) {
            return new String[]{"/bin/sh", "-c", command};
        }

        String trimmed = command.trim();
        String lower = trimmed.toLowerCase();

        boolean isShellScript = lower.matches(".*\\.(bat|cmd|btm)(\\s+.*)?$");
        boolean hasSpecialChars = trimmed.matches(".*[&|<>^].*");

        if (isShellScript || hasSpecialChars) {
            return new String[]{"cmd.exe", "/c", command};
        }

        return splitCommand(command);
    }

    private static String[] splitCommand(String command) {
        java.util.List<String> parts = new java.util.ArrayList<>();
        StringBuilder current = new StringBuilder();
        boolean inQuotes = false;

        for (char c : command.toCharArray()) {
            if (c == '\"') {
                inQuotes = !inQuotes;
                current.append(c);
            } else if (c == ' ' && !inQuotes) {
                if (current.length() > 0) {
                    parts.add(current.toString());
                    current = new StringBuilder();
                }
            } else {
                current.append(c);
            }
        }

        if (current.length() > 0) {
            parts.add(current.toString());
        }

        return parts.toArray(new String[0]);
    }
}
