import org.apache.tinkerpop.gremlin.structure.Graph;
import org.apache.tinkerpop.gremlin.structure.Vertex;
import org.apache.tinkerpop.gremlin.process.traversal.dsl.graph.GraphTraversalSource;
import static org.apache.tinkerpop.gremlin.process.traversal.dsl.graph.__.*;
import java.security.MessageDigest;
import java.nio.charset.StandardCharsets;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.Base64;

public class GraphEdgeCreator {
    private static final Set<String> EDGE_HASH_CACHE = ConcurrentHashMap.newKeySet();
    private static final ThreadLocal<MessageDigest> SHA256 = ThreadLocal.withInitial(() -> {
        try {
            return MessageDigest.getInstance("SHA-256");
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    });

    public static void createEdges(Graph graph, List<VertexBuilder> vertexBuilders) {
        GraphTraversalSource g = graph.traversal();

        for (VertexBuilder builder : vertexBuilders) {
            for (EdgeDefinition edge : builder.getEdges()) {
                String hash = computeHash(edge);

                if (EDGE_HASH_CACHE.contains(hash)) {
                    continue;
                }

                synchronized (EDGE_HASH_CACHE) {
                    if (EDGE_HASH_CACHE.contains(hash)) {
                        continue;
                    }

                    boolean exists = g.V().hasId(edge.getSourceId())
                        .outE(edge.getLabel())
                        .where(inV().hasId(edge.getTargetId()))
                        .hasNext();

                    if (!exists) {
                        Vertex source = g.V().hasId(edge.getSourceId()).next();
                        Vertex target = g.V().hasId(edge.getTargetId()).next();
                        source.addEdge(edge.getLabel(), target);
                    }

                    EDGE_HASH_CACHE.add(hash);
                }
            }
        }
    }

    private static String computeHash(EdgeDefinition edge) {
        String key = edge.getSourceId() + "::" + edge.getLabel() + "::" + edge.getTargetId();
        byte[] digest = SHA256.get().digest(key.getBytes(StandardCharsets.UTF_8));
        return Base64.getEncoder().encodeToString(digest);
    }

    public static class VertexBuilder {
        private final List<EdgeDefinition> edges = new ArrayList<>();

        public void addEdge(String sourceId, String targetId, String label) {
            edges.add(new EdgeDefinition(sourceId, targetId, label));
        }

        public List<EdgeDefinition> getEdges() {
            return edges;
        }
    }

    public static class EdgeDefinition {
        private final String sourceId;
        private final String targetId;
        private final String label;

        public EdgeDefinition(String sourceId, String targetId, String label) {
            this.sourceId = sourceId;
            this.targetId = targetId;
            this.label = label;
        }

        public String getSourceId() { return sourceId; }
        public String getTargetId() { return targetId; }
        public String getLabel() { return label; }
    }
}
