import java.io.BufferedReader;
import java.io.InputStreamReader;

public static String executeWithRoot(String command) throws Exception {
    ProcessBuilder processBuilder = new ProcessBuilder("su", "-c", command);
    processBuilder.redirectErrorStream(true);

    Process process = processBuilder.start();

    StringBuilder output = new StringBuilder();
    try (BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
        String line;
        while ((line = reader.readLine()) != null) {
            output.append(line).append(System.lineSeparator());
        }
    }

    int exitCode = process.waitFor();
    if (exitCode != 0) {
        throw new RuntimeException("Command failed with exit code " + exitCode + ": " + output);
    }

    return output.toString().trim();
}
