public class ServerGroupManager {

    public String generateHashAndCreateGroup(List<String> strings, List<ServerGroup> existingGroups) {
        String concatenated = String.join("", strings);
        String hash = DigestUtils.md5Hex(concatenated);

        boolean exists = existingGroups.stream()
            .anyMatch(group -> hash.equals(group.getHash()));

        if (!exists) {
            existingGroups.add(new ServerGroup(hash, new ArrayList<>()));
        }

        return hash;
    }
}

