import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.SQLException;
import java.util.logging.Logger;
import javax.servlet.http.HttpSession;

public class UserRegistration {
    private static final Logger LOGGER = Logger.getLogger(UserRegistration.class.getName());

    public void registerUser(String username, String password, String email, Connection connection, HttpSession session) {
        if (password == null || password.trim().isEmpty() || email == null || email.trim().isEmpty()) {
            LOGGER.warning("Password or email is null or empty");
            session.setAttribute("error", "Password or email cannot be empty");
            return;
        }

        String hashedPassword = hashMD5(password);
        String sql = "INSERT INTO users (username, password_hash, email) VALUES (?, ?, ?)";

        try (PreparedStatement pstmt = connection.prepareStatement(sql)) {
            pstmt.setString(1, username);
            pstmt.setString(2, hashedPassword);
            pstmt.setString(3, email);
            pstmt.executeUpdate();
        } catch (SQLException e) {
            LOGGER.severe("Database error during user registration: " + e.getMessage());
            session.setAttribute("error", "Database error occurred");
        }
    }

    private String hashMD5(String input) {
        try {
            MessageDigest md = MessageDigest.getInstance("MD5");
            byte[] digest = md.digest(input.getBytes());
            StringBuilder sb = new StringBuilder();
            for (byte b : digest) {
                sb.append(String.format("%02x", b));
            }
            return sb.toString();
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("MD5 algorithm not available", e);
        }
    }
}
