import java.time.LocalDateTime;
import java.util.List;

public class IntervalMerger {
    public static class Segment {
        LocalDateTime start;
        LocalDateTime end;

        public Segment(LocalDateTime start, LocalDateTime end) {
            this.start = start;
            this.end = end;
        }
    }

    public static String mergeIntervals(List<Segment> segments) {
        if (segments == null || segments.isEmpty()) {
            return "";
        }

        LocalDateTime minStart = segments.get(0).start;
        LocalDateTime maxEnd = segments.get(0).end;

        for (Segment segment : segments) {
            if (segment.start.isBefore(minStart)) {
                minStart = segment.start;
            }
            if (segment.end.isAfter(maxEnd)) {
                maxEnd = segment.end;
            }
        }

        return minStart + "-" + maxEnd;
    }
}
