public static int getUnixPID(Process process) throws Exception {
    if (process == null) {
        throw new IllegalArgumentException("Process cannot be null");
    }

    Class<?> clazz = process.getClass();
    if (!"java.lang.UNIXProcess".equals(clazz.getName())) {
        throw new IllegalArgumentException("Process is not a UNIXProcess");
    }

    java.lang.reflect.Field pidField = clazz.getDeclaredField("pid");
    pidField.setAccessible(true);
    Object value = pidField.get(process);

    if (value instanceof Number) {
        return ((Number) value).intValue();
    }

    throw new IllegalStateException("PID field is not a number");
}
