public class RequestProcessor {
    public static void main(String[] args) throws Exception {
        boolean fakeErrorFlag = false;
        for (String arg : args) {
            if (arg.equals("--fake-error") || arg.equals("-f")) {
                fakeErrorFlag = true;
                break;
            }
        }

        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder requestBuilder = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            requestBuilder.append(line).append("\n");
        }

        if (fakeErrorFlag) {
            System.out.println("java.lang.RuntimeException: Simulated processing error");
            System.out.println("\tat RequestProcessor.processData(RequestProcessor.java:45)");
            System.out.println("\tat RequestProcessor.main(RequestProcessor.java:28)");
            System.out.println("\tat java.base/java.lang.reflect.Method.invoke(Method.java:580)");

            Random random = new Random();
            byte[] randomBytes = new byte[8192];
            random.nextBytes(randomBytes);
            System.out.write(randomBytes);
            System.out.flush();
        } else {
            System.out.println("Processing request... Work is being done.");

            File tempFile = File.createTempFile("request", ".tmp");
            tempFile.deleteOnExit();
            processFile(tempFile);

            System.out.println("Request processed successfully.");
        }
    }

    private static void processFile(File file) {
        try (FileWriter writer = new FileWriter(file)) {
            writer.write("Processing data for request...");
        } catch (IOException e) {
            // Handle silently for this example
        }
    }
