 ```java
import java.security.MessageDigest;

public class MGF1 {
    public static byte[] generateMask(byte[] seed, int maskLen, MessageDigest digest) {
        int hashLen = digest.getDigestLength();
        byte[] mask = new byte[maskLen];
        byte[] counterBytes = new byte[4];
        int counter = 0;
        int offset = 0;

        while (offset < maskLen) {
            counterBytes[0] = (byte) (counter >>> 24);
            counterBytes[1] = (byte) (counter >>> 16);
            counterBytes[2] = (byte) (counter >>> 8);
            counterBytes[3] = (byte) counter;

            digest.update(seed);
            byte[] hash = digest.digest(counterBytes);

            int copyLen = Math.min(hashLen, maskLen - offset);
            System.arraycopy(hash, 0, mask, offset, copyLen);

            offset += copyLen;
            counter++;
        }

        return mask;
    }
}
