import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;

public class HashGenerator {
    private static final String PREFIX = "FIXED";

    public static String generateHash(String input, String namespace) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-1");

            byte[] namespaceHashBytes = md.digest(namespace.getBytes(StandardCharsets.UTF_8));
            String namespaceHash = bytesToHex(namespaceHashBytes);

            md.reset();
            byte[] keyHashBytes = md.digest(input.getBytes(StandardCharsets.UTF_8));
            String keyHash = bytesToHex(keyHashBytes);

            return PREFIX + ":" + namespaceHash + ":" + keyHash;
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException(e);
        }
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }
}
