import java.io.*;
import java.util.logging.*;
import javax.servlet.http.*;

public void displayConfigFile(HttpServletRequest request, HttpServletResponse response) {
    Logger logger = Logger.getLogger(getClass().getName());
    String filePath = request.getParameter("configPath");

    try {
        response.setContentType("text/plain");
        PrintWriter out = response.getWriter();

        if (filePath == null || filePath.isEmpty()) {
            out.println("Error: Configuration file path not specified.");
            logger.severe("Configuration file path not provided in request");
            return;
        }

        try (BufferedReader reader = new BufferedReader(new FileReader(filePath))) {
            String line;
            while ((line = reader.readLine()) != null) {
                out.println(line);
            }
        } catch (FileNotFoundException e) {
            out.println("Error: Configuration file not found: " + filePath);
            logger.log(Level.SEVERE, "Configuration file not found: " + filePath, e);
        } catch (IOException e) {
            out.println("Error: Unable to read configuration file: " + filePath);
            logger.log(Level.SEVERE, "Error reading configuration file: " + filePath, e);
        }
    } catch (IOException e) {
        logger.log(Level.SEVERE, "Error accessing response writer", e);
    }
}
