import scrapy
import quandl
import pandas as pd
from datetime import datetime

class QuandlStorageSpider(scrapy.Spider):
    name = 'quandl_storage'
    allowed_domains = ['data.example.com']
    start_urls = ['https://data.example.com/financials']

    custom_settings = {
        'USER_AGENT': 'QuandlIntegrationBot/1.0',
        'DOWNLOAD_DELAY': 1,
        'ROBOTSTXT_OBEY': True,
        'CONCURRENT_REQUESTS': 1
    }

    def __init__(self, quandl_api_key=None, dataset_code=None, **kwargs):
        super().__init__(**kwargs)
        quandl.ApiConfig.api_key = quandl_api_key or 'YOUR_QUANDL_API_KEY'
        self.dataset_code = dataset_code or 'USER/SCRAPED_DATA'

    def parse(self, response):
        rows = response.css('table.data-table tr')[1:]
        data_list = []

        for row in rows:
            date_cell = row.css('td.date::text').get()
            value_cell = row.css('td.value::text').get()

            if date_cell and value_cell:
                try:
                    data_list.append({
                        'Date': date_cell.strip(),
                        'Close': float(value_cell.strip().replace('$', '').replace(',', ''))
                    })
                except ValueError:
                    continue

        if data_list:
            df = pd.DataFrame(data_list)
            df['Date'] = pd.to_datetime(df['Date'])
            df = df.set_index('Date')

            try:
                quandl.upload_data(
                    code=self.dataset_code,
                    data=df,
                    replace=True
                )
                self.logger.info(f"Uploaded {len(data_list)} rows to Quandl dataset {self.dataset_code}")
            except Exception as e:
                self.logger.error(f"Quandl upload requires vendor permissions: {e}")
                df.to_csv(f'{self.dataset_code.replace("/", "_")}.csv')

        yield {
            'dataset_code': self.dataset_code,
            'records_scraped': len(data_list),
            'timestamp': datetime.now().isoformat()
        }
