def update_function(params, func):
   class UpdatedFunction:
       def __init__(self, params, func):
           self.params = params
           self.func = func
           self.__name__ = func.__name__
           self.__doc__ = func.__doc__
           for attr in ('__module__', '__qualname__', '__annotations__'):
               if hasattr(func, attr):
                   setattr(self, attr, getattr(func, attr))

       def __call__(self, *args, **kwargs):
           updated_kwargs = {**kwargs, **self.params}
           return self.func(*args, **updated_kwargs)

       def __repr__(self):
           return f"<UpdatedFunction '{self.__name__}' with params={self.params}>"

   return UpdatedFunction(params, func)

