from scapy.packet import NoPayload

def process_packet(packet):
    if packet.haslayer('IP'):
        packet['IP'].ttl = 64
        packet['IP'].chksum = None

    if packet.haslayer('TCP'):
        packet['TCP'].window = 65535

    processed_layers = []
    current = packet

    while current and not isinstance(current, NoPayload):
        layer = current.copy()
        layer.payload = NoPayload()

        layer.name = f"Updated_{layer.name}"

        for field_name in list(layer.fields.keys()):
            value = layer.fields[field_name]
            if isinstance(value, str):
                layer.fields[field_name] = f"{value}_modified"
            elif isinstance(value, int) and field_name not in ['chksum', 'len']:
                layer.fields[field_name] = value + 1

        layer_type = layer.__class__.__name__
        is_http = layer_type in ['HTTP', 'HTTPRequest', 'HTTPResponse']
        is_unnecessary = is_http and (not layer.fields or len(str(layer.payload)) == 0)

        if not is_unnecessary:
            processed_layers.append(layer)

        current = current.payload

    if not processed_layers:
        return None

    new_packet = processed_layers[0]
    for layer in processed_layers[1:]:
        new_packet = new_packet / layer

    return new_packet
