class InputReader:
    def __init__(self, source: str, fail_on_missing: bool = True):
        self.source = source
        self.fail_on_missing = fail_on_missing

    def __iter__(self) -> Iterator[str]:
        try:
            if self.source.startswith("s3://"):
                yield from self._read_s3()
            elif self.source.startswith(("http://", "https://")):
                yield from self._read_http()
            else:
                yield from self._read_file()
        except FileNotFoundError:
            if self.fail_on_missing:
                raise
            return

    def _read_file(self) -> Iterator[str]:
        if not os.path.exists(self.source):
            raise FileNotFoundError(f"File not found: {self.source}")
        with open(self.source, "r", encoding="utf-8") as f:
