function matchesSelector(selector, operator, value) {
  var attrValue = Sizzle.attr(this, selector);
  if (!operator) {
    return attrValue != null;
  }
  switch (operator) {
    case '=': return attrValue === value;
    case '!=': return attrValue !== value;
    case '^=': return attrValue != null && attrValue.indexOf(value) === 0;
    case '$=': return attrValue != null && attrValue.slice(-value.length) === value;
    case '*=': return attrValue != null && attrValue.indexOf(value) !== -1;
    case '~=': return attrValue != null && (' ' + attrValue + ' ').indexOf(' ' + value + ' ') !== -1;
    case '|=': return attrValue === value || (attrValue != null && attrValue.indexOf(value + '-') === 0);
    default: return false;
  }
}
