 function createMessageBus(target, origin) {
  var listeners = [];
  var channel, port, ie8Frame, lastIE8Data;

  if (typeof MessageChannel !== 'undefined' && !target) {
    channel = new MessageChannel();
    port = channel.port1;
    port.onmessage = function(e) {
      for (var i = 0; i < listeners.length; i++) {
        try { listeners[i](e.data); } catch(ex) {}
      }
    };
  } else if (typeof window !== 'undefined' && window.postMessage) {
    var handler = function(e) {
      if (origin && e.origin !== origin) return;
      for (var i = 0; i < listeners.length; i++) {
        try { listeners[i](e.data); } catch(ex) {}
      }
    };
    if (window.addEventListener) window.addEventListener('message', handler, false);
    else if (window.attachEvent) window.attachEvent('onmessage', handler);
  } else if (typeof document !== 'undefined' && document.body && document.createElement) {
    ie8Frame = document.createElement('iframe');
    ie8Frame.style.display = 'none';
    document.body.appendChild(ie8Frame);
    ie8Frame.onreadystatechange = function() {
      if (ie8Frame.readyState === 'complete' || ie8Frame.readyState === 'loaded') {
        var data = ie8Frame.contentWindow.name;
        if (data && data !== lastIE8Data) {
          lastIE8Data = data;
          try {
            var parsed = JSON.parse(data);
            for (var i = 0; i < listeners.length; i++) {
              try { listeners[i](parsed); } catch(ex) {}
            }
          } catch(e) {}
        }
      }
    };
  }

  return {
    post: function(message) {
      if (port) {
        port.postMessage(message);
      } else if (window.postMessage) {
        var dest = target || (window.parent !== window ? window.parent : null);
        if (dest) dest.postMessage(message, origin || '*');
      } else if (ie8Frame) {
        try {
          ie8Frame.contentWindow.name = JSON.stringify(message);
          ie8Frame.src = 'javascript:void(0);';
        } catch(e) {}
      }
    },
    on: function(callback) {
      listeners.push(callback);
      return function() {
        var idx = listeners.indexOf(callback);
        if (idx > -1) listeners.splice(idx, 1);
      };
    },
    getPort: function() {
      return channel ? channel.port2 : null;
    }
  };
}

