const getHash = (() => {
  const seen = new WeakMap();
  let counter = 0;

  return (item) => {
    if (item === undefined) return "undefined";
    if (item === null) return "null";
    const t = typeof item;
    if (t === "object" || t === "function") {
      if (seen.has(item)) return seen.get(item);
      const h = "obj" + (++counter);
      seen.set(item, h);
      return h;
    }
    if (t === "symbol") return t + ":" + item.toString();
    if (t === "bigint") return t + ":" + item.toString();
    return t + ":" + String(item);
  };
})();
