async function testToggleableColumns(cellClass, expectedText, targetHash) {
    if (window.location.hash !== targetHash) {
        await new Promise(resolve => {
            const handler = () => {
                if (window.location.hash === targetHash) {
                    window.removeEventListener('hashchange', handler);
                    resolve();
                }
            };
            window.addEventListener('hashchange', handler);
        });
        return testToggleableColumns(cellClass, expectedText, targetHash);
    }

    const cells = document.querySelectorAll(`.${cellClass}`);
    if (cells.length === 0) return false;

    if (cells[0].textContent.trim() === expectedText) {
        if (window.location.hash === targetHash) {
            window.location.hash = '';
            await new Promise(r => setTimeout(r, 0));
        }
        window.location.hash = targetHash;

        await new Promise(resolve => {
            const handler = () => {
                if (window.location.hash === targetHash) {
                    window.removeEventListener('hashchange', handler);
                    resolve();
                }
            };
            window.addEventListener('hashchange', handler);
        });

        return true;
    }

    return false;
}
