function loginUser(userName, password) {
    const users = {
        'admin': { password: 'admin123', expiryDate: new Date('2023-01-01') },
        'user1': { password: 'pass123', expiryDate: new Date('2025-12-31') }
    };

    const result = {
        isLoggedIn: false,
        alertMessage: ''
    };

    const user = users[userName];

    if (!user) {
        result.alertMessage = 'User not found';
        return result;
    }

    if (user.password !== password) {
        alert('Incorrect password');
        result.alertMessage = 'Incorrect password';
        return result;
    }

    document.cookie = `loggedIn=true;username=${encodeURIComponent(userName)};path=/;max-age=86400`;
    result.isLoggedIn = true;

    const now = new Date();
    if (user.expiryDate && now > user.expiryDate) {
        alert('Password has expired');
        result.alertMessage = 'Password has expired';
    } else {
        result.alertMessage = 'Login successful';
    }

    return result;
}
