function runCoroutines(iterable, token) {
  const queue = Array.from(iterable);

  while (queue.length > 0) {
    const coroutine = queue.shift();
    let result = coroutine.next();

    while (!result.done && result.value !== token) {
      result = coroutine.next();
    }

    if (result.done) {
      return result.value;
    }

    queue.push(coroutine);
  }

  return { done: true };
}

