#!/bin/bash

while getopts "a:v:" opt; do
    case $opt in
        a) ARCH="$OPTARG" ;;
        v) VERSION="$OPTARG" ;;
        *) exit 1 ;;
    esac
done

if [ -z "$ARCH" ] || [ -z "$VERSION" ]; then
    exit 1
fi

PKG_NAME="binary-package"
RPMBUILD_ROOT="${HOME}/rpmbuild"

mkdir -p ${RPMBUILD_ROOT}/{SOURCES,SPECS,BUILD,RPMS,SRPMS}

tar czf ${RPMBUILD_ROOT}/SOURCES/${PKG_NAME}-${VERSION}.tar.gz .

cat > ${RPMBUILD_ROOT}/SPECS/${PKG_NAME}.spec << EOF
Name:           ${PKG_NAME}
Version:        ${VERSION}
Release:        1%{?dist}
Summary:        Binary Package
License:        Proprietary
Source0:        %{name}-%{version}.tar.gz
BuildArch:      ${ARCH}

%description
Binary package for %{_arch}

%prep
%setup -q

%install
mkdir -p %{buildroot}/opt/%{name}
cp -a * %{buildroot}/opt/%{name}/

%files
/opt/%{name}/

%changelog
EOF

rpmbuild --target ${ARCH} -ba ${RPMBUILD_ROOT}/SPECS/${PKG_NAME}.spec

