const ArticleRenderer = ({ title, htmlContent, previousArticle, nextArticle }) => {
  return (
    <article className="article-container">
      <header className="article-header">
        <h1>{title}</h1>
      </header>

      <div 
        className="article-content" 
        dangerouslySetInnerHTML={{ __html: htmlContent }} 
      />

      <nav className="article-navigation">
        <div className="nav-previous">
          {previousArticle && (
            <a href={previousArticle.url} className="nav-link">
              <span className="nav-label">← Previous</span>
              <span className="nav-title">{previousArticle.title}</span>
            </a>
          )}
        </div>

        <div className="nav-next">
          {nextArticle && (
            <a href={nextArticle.url} className="nav-link">
              <span className="nav-label">Next →</span>
              <span className="nav-title">{nextArticle.title}</span>
            </a>
          )}
        </div>
      </nav>
    </article>
  );
};

export default ArticleRenderer;
