function getWorldInfo(url, targetOrigin = '*', timeout = 10000) {
  return new Promise((resolve, reject) => {
    const iframe = document.createElement('iframe');
    iframe.style.cssText = 'display:none;visibility:hidden;width:0;height:0;';

    const requestId = typeof crypto !== 'undefined' && crypto.randomUUID 
      ? crypto.randomUUID() 
      : Math.random().toString(36).substring(2) + Date.now().toString(36);

    let timer;

    const cleanup = () => {
      window.removeEventListener('message', messageHandler);
      clearTimeout(timer);
      if (iframe && iframe.parentNode) {
        iframe.parentNode.removeChild(iframe);
      }
    };

    const messageHandler = (event) => {
      if (event.source !== iframe.contentWindow) return;
      if (event.data?.requestId !== requestId) return;

      cleanup();

      if (event.data.error) {
        reject(new Error(event.data.error));
      } else {
        resolve({
          entryImage: event.data.entryImage,
          posterImage: event.data.posterImage || null
        });
      }
    };

    timer = setTimeout(() => {
      cleanup();
      reject(new Error('Timeout waiting for world info'));
    }, timeout);

    window.addEventListener('message', messageHandler);

    iframe.onload = () => {
      iframe.contentWindow.postMessage({
        type: 'GET_WORLD_INFO',
        requestId: requestId
      }, targetOrigin);
    };

    iframe.onerror = () => {
      cleanup();
      reject(new Error('Failed to load world URL'));
    };

    iframe.src = url;
    document.body.appendChild(iframe);
  });
}
