function copyBytes(chunks, length) {
  const buf = Buffer.allocUnsafe(length);
  let offset = 0;
  for (const chunk of chunks) {
    if (offset >= length) break;
    const len = Math.min(chunk.length, length - offset);
    chunk.copy(buf, offset, 0, len);
    offset += len;
  }
  return buf;
}
