function createBuffer(subject, encoding, noZero) {
  if (!Uint8Array.prototype.readUInt8) {
    Uint8Array.prototype.readUInt8 = function(offset) {
      if (offset < 0 || offset >= this.length) throw new RangeError('Index out of bounds');
      return this[offset];
    };
    Uint8Array.prototype.writeUInt8 = function(value, offset) {
      if (offset < 0 || offset >= this.length) throw new RangeError('Index out of bounds');
      this[offset] = value & 0xff;
      return 1;
    };
    Uint8Array.prototype.readUInt16BE = function(offset) {
      return (this[offset] << 8) | this[offset + 1];
    };
    Uint8Array.prototype.writeUInt16BE = function(value, offset) {
      this[offset] = (value >>> 8) & 0xff;
      this[offset + 1] = value & 0xff;
      return 2;
    };
    Uint8Array.prototype.readUInt32BE = function(offset) {
      return (this[offset] * 0x1000000) + (this[offset + 1] << 16) + (this[offset + 2] << 8) + this[offset + 3];
    };
    Uint8Array.prototype.writeUInt32BE = function(value, offset) {
      this[offset] = (value >>> 24) & 0xff;
      this[offset + 1] = (value >>> 16) & 0xff;
      this[offset + 2] = (value >>> 8) & 0xff;
      this[offset + 3] = value & 0xff;
      return 4;
    };
    Uint8Array.prototype.toString = function(encoding, start, end) {
      start = start || 0;
      end = end || this.length;
      const slice = this.subarray(start, end);
      if (encoding === 'hex') {
        return Array.from(slice).map(b => b.toString(16).padStart(2, '0')).join('');
      } else if (encoding === 'base64') {
        const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
        let result = '';
        for (let i = 0; i < slice.length; i += 3) {
          const b1 = slice[i];
          const b2 = slice[i + 1] || 0;
          const b3 = slice[i + 2] || 0;
          result += chars[b1 >> 2];
          result += chars[((b1 & 3) << 4) | (b2 >> 4)];
          result += chars[((b2 & 15) << 2) | (b3 >> 6)];
          result += chars[b3 & 63];
        }
        return result.replace(/A+$/, '').replace(/.$/, m => m + '='.repeat(3 - (slice.length % 3 || 3)));
      } else {
        return new TextDecoder().decode(slice);
      }
    };
    Uint8Array.prototype.write = function(string, offset, length, encoding) {
      offset = offset || 0;
      encoding = encoding || 'utf8';
      if (encoding === 'utf8' || encoding === 'utf-8') {
        const encoded = new TextEncoder().encode(string);
        const len = Math.min(length !== undefined ? length : encoded.length, this.length - offset);
        for (let i = 0; i < len; i++) this[offset + i] = encoded[i];
        return len;
      } else if (encoding === 'hex') {
        const len = Math.min(length !== undefined ? length : string.length / 2, (this.length - offset));
        for (let i = 0; i < len; i++) this[offset + i] = parseInt(string.substr(i * 2, 2), 16);
        return len;
      }
      return 0;
    };
    Uint8Array.prototype.copy = function(target, targetStart, sourceStart, sourceEnd) {
      targetStart = targetStart || 0;
      sourceStart = sourceStart || 0;
      sourceEnd = sourceEnd || this.length;
      const len = Math.min(sourceEnd - sourceStart, target.length - targetStart);
      for (let i = 0; i < len; i++) target[targetStart + i] = this[sourceStart + i];
      return len;
    };
    Uint8Array.prototype.fill = function(value, start, end) {
      start = start || 0;
      end = end || this.length;
      for (let i = start; i < end; i++) this[i] = value;
      return this;
    };
  }

  let buf;
  if (typeof subject === 'number') {
    if (subject < 0 || subject > 0x7fffffff) throw new RangeError('Invalid buffer size');
    buf = new Uint8Array(subject);
    if (!noZero) {
      buf.fill(0);
    }
  } else if (typeof subject === 'string') {
    encoding = encoding || 'utf8';
    if (encoding === 'hex') {
      if (subject.length % 2 !== 0) throw new Error('Invalid hex string');
      buf = new Uint8Array(subject.length / 2);
      for (let i = 0; i < buf.length; i++) buf[i] = parseInt(subject.substr(i * 2, 2), 16);
    } else if (encoding === 'base64') {
      const str = subject.replace(/[^A-Za-z0-9+/]/g, '');
      const len = Math.floor(str.length * 3 / 4);
      buf = new Uint8Array(len);
      const lookup = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
      let p = 0;
      for (let i = 0; i < str.length; i += 4) {
        const e1 = lookup.indexOf(str[i]);
        const e2 = lookup.indexOf(str[i + 1]);
        const e3 = lookup.indexOf(str[i + 2]);
        const e4 = lookup.indexOf(str[i + 3]);
        buf[p++] = (e1 << 2) | (e2 >> 4);
        if (e3 >= 0 && p < len) buf[p++] = ((e2 & 15) << 4) | (e3 >> 2);
        if (e4 >= 0 && p < len) buf[p++] = ((e3 & 3) << 6) | e4;
      }
    } else {
      buf = new Uint8Array(new TextEncoder().encode(subject));
    }
  } else if (subject instanceof ArrayBuffer) {
    buf = new Uint8Array(subject);
  } else if (subject instanceof Uint8Array || Array.isArray(subject)) {
    buf = new Uint8Array(subject);
  } else {
    throw new TypeError('Invalid subject type');
  }

  if (!(buf instanceof Uint8Array)) throw new Error('Buffer instantiation failed');
  return buf;
}
