```c
typedef struct buffer_chunk {
    struct buffer_chunk *next;
    const char *data;
    size_t len;
} buffer_chunk_t;

static inline char *copy_buffered_data(size_t *n, buffer_chunk_t *list) {
    char *buf = malloc(*n);
    if (!buf) return NULL;

    size_t copied = 0;
    buffer_chunk_t *chunk = list;

    while (chunk && copied < *n) {
        size_t to_copy = chunk->len;
        if (to_copy > *n - copied) {
            to_copy = *n - copied;
        }
        memcpy(buf + copied, chunk->data, to_copy);
        copied += to_copy;
        chunk = chunk->next;
    }

    *n = copied;
    return buf;
}
