import java.util.ArrayList;
import java.util.List;
import java.util.Random;

public class GaussianMutator {
    public static class MutationResult {
        private final double mutatedValue;
        private final List<Double> discreteValues;

        public MutationResult(double mutatedValue, List<Double> discreteValues) {
            this.mutatedValue = mutatedValue;
            this.discreteValues = discreteValues;
        }

        public double getMutatedValue() {
            return mutatedValue;
        }

        public List<Double> getDiscreteValues() {
            return discreteValues;
        }
    }

    public static MutationResult mutate(
            Random random,
            double value,
            double stdDevFactor,
            double minRange,
            double maxRange,
            int discreteCount) {

        double range = maxRange - minRange;
        double stdDev = range * stdDevFactor;

        double gaussianValue = random.nextGaussian() * stdDev;
        double mutated = value + gaussianValue;

        if (mutated < minRange) mutated = minRange;
        if (mutated > maxRange) mutated = maxRange;

        List<Double> discreteValues = new ArrayList<>(discreteCount);
        if (discreteCount > 1) {
            double step = range / (discreteCount - 1);
            for (int i = 0; i < discreteCount; i++) {
                discreteValues.add(minRange + (i * step));
            }
        } else if (discreteCount == 1) {
            discreteValues.add(minRange + (range / 2));
        }

        return new MutationResult(mutated, discreteValues);
    }
}
