public class ArrayProcessor {
    public static void PUnsignedFloat(float f) {
        int bits = Float.floatToIntBits(f);
        float recovered = Float.intBitsToFloat(bits);
        System.out.println("PUnsignedFloat: value=" + f + ", bits=" + bits + ", recovered=" + recovered);
    }

    public static void PDouble(double d) {
        long bits = Double.doubleToLongBits(d);
        double recovered = Double.longBitsToDouble(bits);
        boolean isNaN = Double.isNaN(d);
        boolean isInfinite = Double.isInfinite(d);
        System.out.println("PDouble: value=" + d + ", bits=" + bits + ", recovered=" + recovered + ", isNaN=" + isNaN + ", isInfinite=" + isInfinite);
    }

    public static void PLong(long l) {
        String str = Long.toString(l);
        Long obj = Long.valueOf(l);
        int compare = Long.compare(l, 0L);
        int bitCount = Long.bitCount(l);
        System.out.println("PLong: value=" + l + ", string=" + str + ", object=" + obj + ", compareToZero=" + compare + ", bitCount=" + bitCount);
    }

    public static void PUnsignedLong(long l) {
        String unsignedStr = Long.toUnsignedString(l);
        int compareUnsigned = Long.compareUnsigned(l, 0L);
        long divUnsigned = Long.divideUnsigned(l, 2L);
        long remUnsigned = Long.remainderUnsigned(l, 2L);
        System.out.println("PUnsignedLong: value=" + l + ", unsignedString=" + unsignedStr + ", compareUnsigned=" + compareUnsigned + ", divideUnsignedBy2=" + divUnsigned + ", remainderUnsignedBy2=" + remUnsigned);
    }

    public static void PInteger(int i) {
        String str = Integer.toString(i);
        Integer obj = Integer.valueOf(i);
        int compare = Integer.compare(i, 0);
        int bitCount = Integer.bitCount(i);
        int highestOneBit = Integer.highestOneBit(i);
        System.out.println("PInteger: value=" + i + ", string=" + str + ", object=" + obj + ", compareToZero=" + compare + ", bitCount=" + bitCount + ", highestOneBit=" + highestOneBit);
    }

    public static void PUnsignedInt(int i) {
        String unsignedStr = Integer.toUnsignedString(i);
        int compareUnsigned = Integer.compareUnsigned(i, 0);
        int divUnsigned = Integer.divideUnsigned(i, 2);
        int remUnsigned = Integer.remainderUnsigned(i, 2);
        long unsignedLong = Integer.toUnsignedLong(i);
        System.out.println("PUnsignedInt: value=" + i + ", unsignedString=" + unsignedStr + ", compareUnsigned=" + compareUnsigned + ", divideUnsignedBy2=" + divUnsigned + ", remainderUnsignedBy2=" + remUnsigned + ", toUnsignedLong=" + unsignedLong);
    }

    public static void processArray(float[] arr) {
        for (float f : arr) {
            PUnsignedFloat(f);
        }
    }

    public static void processArray(double[] arr) {
        for (double d : arr) {
            PDouble(d);
        }
    }

    public static void processArray(long[] arr) {
        for (long l : arr) {
            PLong(l);
            PUnsignedLong(l);
        }
    }

    public static void processArray(int[] arr) {
        for (int i : arr) {
            PInteger(i);
            PUnsignedInt(i);
        }
    }
}
