    public static Object getRandomValue(String type, Random random, Number min, Number max) {
        switch (type) {
            case "Integer":
                return min.intValue() + random.nextInt(max.intValue() - min.intValue() + 1);
            case "Double":
                return min.doubleValue() + (max.doubleValue() - min.doubleValue()) * random.nextDouble();
            case "Long":
                return min.longValue() + (long) (random.nextDouble() * (max.longValue() - min.longValue()));
            case "Boolean":
                return random.nextBoolean();
            default:
                throw new IllegalArgumentException("Unsupported type: " + type);
        }
    }
}
