 ```java
public class JsonGenerator {

    public String generateJson(Object obj) {
        if (obj == null) {
            return "{}";
        }

        return switch (obj) {
            case ObjectData o -> String.format("{\"first_name\":\"%s\",\"last_name\":\"%s\",\"ssn\":\"%s\"}", 
                escapeJson(o.firstName()), escapeJson(o.lastName()), escapeJson(o.ssn()));
            case GeoPoint g -> String.format("{\"lat\":%f,\"lon\":%f}", g.lat(), g.lon());
            case GeoShape s -> generateGeoShapeJson(s);
            default -> "{}";
        };
    }

    private String generateGeoShapeJson(GeoShape shape) {
        StringBuilder sb = new StringBuilder();
        sb.append("{\"type\":\"").append(escapeJson(shape.type())).append("\",");
        sb.append("\"coordinates\":[");
        double[][] coords = shape.coordinates();
        for (int i = 0; i < coords.length; i++) {
            sb.append("[").append(coords[i][0]).append(",").append(coords[i][1]).append("]");
            if (i < coords.length - 1) sb.append(",");
        }
        sb.append("]}");
        return sb.toString();
    }

    private String escapeJson(String input) {
        if (input == null) return "";
        return input.replace("\\", "\\\\")
                   .replace("\"", "\\\"")
                   .replace("\b", "\\b")
                   .replace("\f", "\\f")
                   .replace("\n", "\\n")
                   .replace("\r", "\\r")
                   .replace("\t", "\\t");
    }

    public record ObjectData(String firstName, String lastName, String ssn) {}
    public record GeoPoint(double lat, double lon) {}
    public record GeoShape(String type, double[][] coordinates) {}
}
