 import java.security.SecureRandom;

public class PasswordGenerator {
    private static final String MAIN_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
    private static final String END_CHARS = "0123456789";
    private static final SecureRandom random = new SecureRandom();

    public static String generatePassword(int length, int restrictedEndLength) {
        if (restrictedEndLength < 0 || restrictedEndLength > length) {
            throw new IllegalArgumentException("Invalid restricted end length");
        }

        StringBuilder password = new StringBuilder(length);

        for (int i = 0; i < length - restrictedEndLength; i++) {
            password.append(MAIN_CHARS.charAt(random.nextInt(MAIN_CHARS.length())));
        }

        for (int i = 0; i < restrictedEndLength; i++) {
            password.append(END_CHARS.charAt(random.nextInt(END_CHARS.length())));
        }

        return password.toString();
    }
}

