import java.math.BigDecimal;
import java.util.Random;

public class RandomValueGenerator {
    public static <T> T generateRandom(Random random, Class<T> type) {
        if (type == Byte.class || type == byte.class) {
            return type.cast((byte) random.nextInt(256));
        } else if (type == Short.class || type == short.class) {
            return type.cast((short) random.nextInt(65536));
        } else if (type == Integer.class || type == int.class) {
            return type.cast(random.nextInt());
        } else if (type == Long.class || type == long.class) {
            return type.cast(random.nextLong());
        } else if (type == Float.class || type == float.class) {
            return type.cast(random.nextFloat());
        } else if (type == Double.class || type == double.class) {
            return type.cast(random.nextDouble());
        } else if (type == Character.class || type == char.class) {
            return type.cast((char) random.nextInt(65536));
        } else if (type == String.class) {
            int length = random.nextInt(20);
            StringBuilder sb = new StringBuilder(length);
            for (int i = 0; i < length; i++) {
                sb.append((char) (random.nextInt(26) + 'a'));
            }
            return type.cast(sb.toString());
        } else if (type == BigDecimal.class) {
            return type.cast(BigDecimal.valueOf(random.nextDouble()));
        } else {
            throw new IllegalArgumentException("Unsupported type: " + type);
        }
    }
}
