import org.apache.lucene.index.LeafReader;
import org.apache.lucene.index.SortedNumericDocValues;
import org.apache.lucene.index.DocValues;
import org.hamcrest.MatcherAssert;
import org.hamcrest.Matchers;
import java.io.IOException;

public class LuceneNumericFieldComparator {

    public static void compareNumericFields(LeafReader reader1, int docId1, String field1,
                                           LeafReader reader2, int docId2, String field2) throws IOException {
        SortedNumericDocValues values1 = DocValues.getSortedNumeric(reader1, field1);
        SortedNumericDocValues values2 = DocValues.getSortedNumeric(reader2, field2);

        if (!values1.advanceExact(docId1)) {
            throw new IllegalArgumentException("Document " + docId1 + " not found in field " + field1);
        }
        if (!values2.advanceExact(docId2)) {
            throw new IllegalArgumentException("Document " + docId2 + " not found in field " + field2);
        }

        int count1 = values1.docValueCount();
        int count2 = values2.docValueCount();

        MatcherAssert.assertThat("Number of values must be equal", count1, Matchers.equalTo(count2));

        values1.load(0, count1);
        values2.load(0, count2);

        for (int i = 0; i < count1; i++) {
            long v1 = values1.nextValue();
            long v2 = values2.nextValue();
            MatcherAssert.assertThat("Value at index " + i + " must match", v1, Matchers.equalTo(v2));
        }
    }
}
