    Random random = new Random();
    int expectedHeartbeat = 1;
    int expectedClear = 1;
    int actualHeartbeat = 0;
    int actualClear = 0;

    boolean heartbeatFirst = random.nextBoolean();

    if (heartbeatFirst) {
        try {
            node.reportHeartbeat();
            actualHeartbeat++;
        } catch (Exception e) {
            // Operation failed
        }
        try {
            node.clearPrimary();
            actualClear++;
        } catch (Exception e) {
            // Operation failed
        }
    } else {
        try {
            node.clearPrimary();
            actualClear++;
        } catch (Exception e) {
            // Operation failed
        }
        try {
            node.reportHeartbeat();
            actualHeartbeat++;
        } catch (Exception e) {
            // Operation failed
        }
    }

    logger.info("Heartbeat difference: " + (expectedHeartbeat - actualHeartbeat));
    logger.info("Clear primary difference: " + (expectedClear - actualClear));
}
