import java.net.InetSocketAddress;
import java.util.ArrayList;
import java.util.List;

public class ConnectionBuilder {
    public List<InetSocketAddress> createSocketAddresses(List<String> hostsAndPorts, String username, String password,
                                                         String serverId, boolean createEnrichmentConnection,
                                                         String driverLocation, String driverName, int connectionTimeout) {
        List<InetSocketAddress> addresses = new ArrayList<>();

        for (String hostPort : hostsAndPorts) {
            String[] parts = hostPort.split(":");
            if (parts.length != 2) {
                throw new ArrayIndexOutOfBoundsException("Invalid format, expected host:port but was: " + hostPort);
            }
            String host = parts[0];
            int port = Integer.parseInt(parts[1]);
            addresses.add(new InetSocketAddress(host, port));
        }

        return addresses;
    }
}
