import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.ObjectInputStream;

public class SerializationUtils {
    @SuppressWarnings("unchecked")
    public static <T> T deserialize(byte[] data, Class<T> clazz) {
        if (data == null) {
            throw new RuntimeException("Input byte array cannot be null");
        }

        try (ByteArrayInputStream bis = new ByteArrayInputStream(data);
             ObjectInputStream ois = new ObjectInputStream(bis)) {

            Object obj = ois.readObject();

            if (!clazz.isInstance(obj)) {
                throw new RuntimeException("Deserialized object is not an instance of " + clazz.getName());
            }

            return (T) obj;

        } catch (ClassNotFoundException e) {
            throw new RuntimeException("Class not found during deserialization: " + e.getMessage(), e);
        } catch (IOException e) {
            throw new RuntimeException("Deserialization failed: " + e.getMessage(), e);
        }
    }
}
