 import java.io.IOException;
import java.io.OutputStream;
import java.nio.file.FileSystem;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Random;

public static Path writeRandomBinaryData(FileSystem fs, String folder, String fileName, long length) throws IOException {
    Path directory = fs.getPath(folder);
    Path filePath = directory.resolve(fileName);

    if (!Files.exists(directory)) {
        Files.createDirectories(directory);
    }

    Random random = new Random();
    byte[] buffer = new byte[4096];

    try (OutputStream out = Files.newOutputStream(filePath)) {
        long remaining = length;
        while (remaining > 0) {
            if (random.nextBoolean()) {
                out.write(random.nextInt(256));
                remaining--;
            } else {
                int chunkSize = (int) Math.min(buffer.length, remaining);
                random.nextBytes(buffer);
                out.write(buffer, 0, chunkSize);
                remaining -= chunkSize;
            }
        }
    }

    return filePath;
}

