import java.util.*;

public class RandomReplacer {
    private static final List<Object> discreteValuesHistory = new ArrayList<>();

    public static Result replaceRandomly(List<Object> original) {
        List<Object> modified = new ArrayList<>();
        if (original != null) {
            Random random = new Random();
            double stdDev = 0.2 * original.size();
            for (Object obj : original) {
                if (random.nextBoolean()) {
                    double val = random.nextGaussian() * stdDev;
                    Double newObj = val;
                    modified.add(newObj);
                    discreteValuesHistory.add(newObj);
                } else {
                    modified.add(obj);
                }
            }
        }
        return new Result(modified, new ArrayList<>(discreteValuesHistory));
    }

    public static class Result {
        public final List<Object> modifiedList;
        public final List<Object> allDiscreteValues;

        public Result(List<Object> modifiedList, List<Object> allDiscreteValues) {
            this.modifiedList = modifiedList;
            this.allDiscreteValues = allDiscreteValues;
        }
    }
}
