 import org.apache.lucene.index.LeafReaderContext;
import org.apache.lucene.index.SortedBinaryDocValues;
import org.apache.lucene.util.BytesRef;
import org.elasticsearch.index.fielddata.IndexFieldData;
import java.util.Arrays;
import java.util.Comparator;
import java.util.Random;

public class FieldDataComparator {

    public static SortedBinaryDocValues compareFieldData(
            Random random,
            LeafReaderContext context,
            IndexFieldData<?> fieldData1,
            IndexFieldData<?> fieldData2,
            Preprocessor preprocessor) {

        SortedBinaryDocValues values1 = (SortedBinaryDocValues) fieldData1.load(context).getDocsValues();
        SortedBinaryDocValues values2 = (SortedBinaryDocValues) fieldData2.load(context).getDocsValues();

        int maxDoc = context.reader().maxDoc();
        BytesRef[] comparisonResults = new BytesRef[maxDoc];

        for (int docId = 0; docId < maxDoc; docId++) {
            values1.setDocument(docId);
            values2.setDocument(docId);

            int count1 = values1.count();
            int count2 = values2.count();

            if (count1 == 0 || count2 == 0) {
                comparisonResults[docId] = null;
                continue;
            }

            BytesRef[] field2Array = new BytesRef[count2];
            for (int i = 0; i < count2; i++) {
                field2Array[i] = preprocessor.process(values2.valueAt(i));
            }

            Arrays.sort(field2Array, Comparator.naturalOrder());

            int randomIndex = random.nextInt(count1);
            BytesRef targetValue = preprocessor.process(values1.valueAt(randomIndex));

            int searchResult = Arrays.binarySearch(field2Array, targetValue, Comparator.naturalOrder());
            comparisonResults[docId] = searchResult >= 0 ? targetValue : null;
        }

        return new SortedBinaryDocValues() {
            private int currentDoc = -1;

            @Override
            public void setDocument(int doc) {
                this.currentDoc = doc;
            }

            @Override
            public int count() {
                return comparisonResults[currentDoc] == null ? 0 : 1;
            }

            @Override
            public BytesRef valueAt(int index) {
                return comparisonResults[currentDoc];
            }

            @Override
            public int docID() {
                return currentDoc;
            }

            @Override
            public int nextDoc() {
                currentDoc++;
                return currentDoc < maxDoc ? currentDoc : NO_MORE_DOCS;
            }

            @Override
            public int advance(int target) {
                currentDoc = target;
                return currentDoc;
            }

            @Override
            public boolean advanceExact(int target) {
                currentDoc = target;
                return comparisonResults[target] != null;
            }

            @Override
            public long cost() {
                return maxDoc;
            }
        };
    }

    public interface Preprocessor {
        BytesRef process(BytesRef value);
    }
}

