 import java.io.*;
import java.net.*;

public class ResourceLoader {
    public InputStream getResourceStream(String resourcePath) throws IOException {
        if (resourcePath == null) {
            throw new IllegalArgumentException("Resource path cannot be null");
        }

        try {
            URL url = new URL(resourcePath);
            return url.openStream();
        } catch (MalformedURLException e) {
            // Not a valid URL, treat as local resource
        }

        InputStream stream = getClass().getResourceAsStream(resourcePath);
        if (stream != null) {
            return stream;
        }

        stream = getClass().getClassLoader().getResourceAsStream(resourcePath);
        if (stream != null) {
            return stream;
        }

        File file = new File(resourcePath);
        if (file.exists()) {
            return new FileInputStream(file);
        }

        throw new FileNotFoundException("Resource not found: " + resourcePath);
    }
}

 import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class ConcurrentGraphTraversal {
    private final Map<Integer, List<Integer>> graph = new ConcurrentHashMap<>();
    private final Set<Integer> visited = ConcurrentHashMap.newKeySet();
    private final AtomicInteger vertexCount = new AtomicInteger(0);
    private final AtomicInteger edgeCount = new AtomicInteger(0);
    private final AtomicInteger completedThreads = new AtomicInteger(0);

    public void addVertex(int v) {
        graph.putIfAbsent(v, new CopyOnWriteArrayList<>());
        vertexCount.incrementAndGet();
    }

    public void addEdge(int u, int v) {
        graph.computeIfAbsent(u, k -> new CopyOnWriteArrayList<>()).add(v);
        graph.computeIfAbsent(v, k -> new CopyOnWriteArrayList<>()).add(u);
        edgeCount.incrementAndGet();
    }

    class TraversalThread extends Thread {
        private final int startNode;

        public TraversalThread(int startNode) {
            this.startNode = startNode;
        }

        @Override
        public void run() {
            try {
                traverse(startNode);
            } finally {
                completedThreads.incrementAndGet();
            }
        }

        private void traverse(int node) {
            if (!visited.add(node)) {
                return;
            }
            List<Integer> neighbors = graph.getOrDefault(node, Collections.emptyList());
            for (int neighbor : neighbors) {
                traverse(neighbor);
            }
        }
    }

    public static void main(String[] args) throws InterruptedException {
        ConcurrentGraphTraversal cg = new ConcurrentGraphTraversal();

        for (int i = 0; i < 8; i++) {
            cg.addVertex(i);
        }
        cg.addEdge(0, 1);
        cg.addEdge(0, 2);
        cg.addEdge(1, 3);
        cg.addEdge(2, 4);
        cg.addEdge(3, 5);
        cg.addEdge(4, 5);
        cg.addEdge(5, 6);
        cg.addEdge(6, 7);

        Thread[] threads = new Thread[3];
        threads[0] = cg.new TraversalThread(0);
        threads[1] = cg.new TraversalThread(3);
        threads[2] = cg.new TraversalThread(6);

        for (Thread t : threads) {
            t.start();
        }
        for (Thread t : threads) {
            t.join();
        }

        System.out.println("Vertices: " + cg.vertexCount.get());
        System.out.println("Edges: " + cg.edgeCount.get());
        System.out.println("Completed Threads: " + cg.completedThreads.get());
    }
}

