 import java.lang.reflect.Field;
import java.util.Collection;
import java.util.Map;

public class JsonGenerator {
    public static String toJson(Object obj) {
        StringBuilder sb = new StringBuilder();
        appendJson(obj, sb);
        return sb.toString();
    }

    private static void appendJson(Object obj, StringBuilder sb) {
        if (obj == null) {
            sb.append("null");
        } else if (obj instanceof String) {
            appendString((String) obj, sb);
        } else if (obj instanceof Character) {
            appendString(obj.toString(), sb);
        } else if (obj instanceof Number || obj instanceof Boolean) {
            sb.append(obj.toString());
        } else if (obj instanceof Enum) {
            appendString(((Enum<?>) obj).name(), sb);
        } else if (obj.getClass().isArray()) {
            appendArray(obj, sb);
        } else if (obj instanceof Collection) {
            appendCollection((Collection<?>) obj, sb);
        } else if (obj instanceof Map) {
            appendMap((Map<?, ?>) obj, sb);
        } else {
            appendObject(obj, sb);
        }
    }

    private static void appendString(String str, StringBuilder sb) {
        sb.append('"');
        for (int i = 0; i < str.length(); i++) {
            char c = str.charAt(i);
            switch (c) {
                case '"': sb.append("\\\""); break;
                case '\\': sb.append("\\\\"); break;
                case '\b': sb.append("\\b"); break;
                case '\f': sb.append("\\f"); break;
                case '\n': sb.append("\\n"); break;
                case '\r': sb.append("\\r"); break;
                case '\t': sb.append("\\t"); break;
                default:
                    if (c < ' ') {
                        sb.append(String.format("\\u%04x", (int) c));
                    } else {
                        sb.append(c);
                    }
            }
        }
        sb.append('"');
    }

    private static void appendArray(Object array, StringBuilder sb) {
        sb.append('[');
        int length = java.lang.reflect.Array.getLength(array);
        for (int i = 0; i < length; i++) {
            if (i > 0) sb.append(',');
            appendJson(java.lang.reflect.Array.get(array, i), sb);
        }
        sb.append(']');
    }

    private static void appendCollection(Collection<?> collection, StringBuilder sb) {
        sb.append('[');
        boolean first = true;
        for (Object item : collection) {
            if (!first) sb.append(',');
            appendJson(item, sb);
            first = false;
        }
        sb.append(']');
    }

    private static void appendMap(Map<?, ?> map, StringBuilder sb) {
        sb.append('{');
        boolean first = true;
        for (Map.Entry<?, ?> entry : map.entrySet()) {
            if (!first) sb.append(',');
            Object key = entry.getKey();
            appendJson(key == null ? "null" : key.toString(), sb);
            sb.append(':');
            appendJson(entry.getValue(), sb);
            first = false;
        }
        sb.append('}');
    }

    private static void appendObject(Object obj, StringBuilder sb) {
        sb.append('{');
        Class<?> clazz = obj.getClass();
        Field[] fields = clazz.getDeclaredFields();
        boolean first = true;
        for (Field field : fields) {
            if (!first) sb.append(',');
            field.setAccessible(true);
            try {
                appendJson(field.getName(), sb);
                sb.append(':');
                appendJson(field.get(obj), sb);
            } catch (IllegalAccessException e) {
                throw new RuntimeException(e);
            }
            first = false;
        }
        sb.append('}');
    }
}

