import java.util.*;
import java.util.function.ToDoubleFunction;
import java.util.stream.Collectors;

public static <T> Map<T, Double> computeNormalizedWeights(List<T> items, ToDoubleFunction<T> weightFunction) {
    double totalWeight = items.stream().mapToDouble(weightFunction).sum();
    return items.stream().collect(Collectors.toMap(
        item -> item,
        item -> weightFunction.applyAsDouble(item) / totalWeight
    ));
}
