import javax.xml.parsers.SAXParser;
import javax.xml.parsers.SAXParserFactory;
import org.xml.sax.SAXException;
import org.xml.sax.SAXParseException;
import org.xml.sax.helpers.DefaultHandler;
import java.io.File;

public class SAXErrorReporter {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java SAXErrorReporter <xml-file>");
            System.exit(1);
        }

        try {
            SAXParserFactory factory = SAXParserFactory.newInstance();
            factory.setValidating(true);
            factory.setNamespaceAware(true);

            SAXParser saxParser = factory.newSAXParser();

            DefaultHandler handler = new DefaultHandler() {
                @Override
                public void warning(SAXParseException e) throws SAXException {
                    System.err.println("Warning at line " + e.getLineNumber() + ", column " + e.getColumnNumber() + ": " + e.getMessage());
                }

                @Override
                public void error(SAXParseException e) throws SAXException {
                    System.err.println("Error at line " + e.getLineNumber() + ", column " + e.getColumnNumber() + ": " + e.getMessage());
                }

                @Override
                public void fatalError(SAXParseException e) throws SAXException {
                    System.err.println("Fatal Error at line " + e.getLineNumber() + ", column " + e.getColumnNumber() + ": " + e.getMessage());
                    throw e;
                }
            };

            saxParser.parse(new File(args[0]), handler);
            System.out.println("Parsing completed successfully.");

        } catch (SAXException e) {
            System.err.println("Parsing failed: " + e.getMessage());
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
            e.printStackTrace();
        }
    }
}
