import android.graphics.RectF;
import java.util.Random;

public class CropUtils {
    private static final Random RANDOM = new Random();
    private static final float MIN_SCALE = 0.1f;

    public static RectF calculateRandomCrop(RectF drawable, RectF viewport) {
        float drawableWidth = drawable.width();
        float drawableHeight = drawable.height();
        float viewportWidth = viewport.width();
        float viewportHeight = viewport.height();

        float drawableAspect = drawableWidth / drawableHeight;
        float viewportAspect = viewportWidth / viewportHeight;

        float maxCropWidth, maxCropHeight;

        if (viewportAspect > drawableAspect) {
            maxCropWidth = drawableWidth;
            maxCropHeight = drawableWidth / viewportAspect;
        } else {
            maxCropHeight = drawableHeight;
            maxCropWidth = drawableHeight * viewportAspect;
        }

        float scale = MIN_SCALE + RANDOM.nextFloat() * (1.0f - MIN_SCALE);

        float cropWidth = maxCropWidth * scale;
        float cropHeight = maxCropHeight * scale;

        float maxLeftOffset = drawableWidth - cropWidth;
        float maxTopOffset = drawableHeight - cropHeight;

        float left = drawable.left + RANDOM.nextFloat() * maxLeftOffset;
        float top = drawable.top + RANDOM.nextFloat() * maxTopOffset;

        return new RectF(left, top, left + cropWidth, top + cropHeight);
    }
}
