import java.util.ArrayList;
import java.util.List;
import java.util.Random;

public class SensorGenerator {

    public static List<SensorData> generateSensorData(
            List<LocationTime> locationTimes,
            List<double[]> standardDeviations,
            double stepPerSecond) {

        List<SensorData> sensorDataList = new ArrayList<>();
        Random random = new Random();
        int samplesPerStep = (int) Math.max(1, Math.round(stepPerSecond));

        for (int i = 0; i < locationTimes.size(); i++) {
            LocationTime locationTime = locationTimes.get(i);
            double[] stdDevs = standardDeviations.get(i);
            long baseTimestamp = locationTime.getTimestamp();

            for (int j = 0; j < samplesPerStep; j++) {
                double[] accData = new double[3];
                for (int k = 0; k < 3 && k < stdDevs.length; k++) {
                    accData[k] = random.nextGaussian() * stdDevs[k];
                }

                long timestamp = baseTimestamp + (long) (j * (1000.0 / stepPerSecond));
                sensorDataList.add(new SensorData(timestamp, "ACC", accData));
            }
        }

        return sensorDataList;
    }
}

class LocationTime {
    private long timestamp;

    public LocationTime(long timestamp) {
        this.timestamp = timestamp;
    }

    public long getTimestamp() {
        return timestamp;
    }
}

class SensorData {
    private long timestamp;
    private String type;
    private double[] data;

    public SensorData(long timestamp, String type, double[] data) {
        this.timestamp = timestamp;
        this.type = type;
        this.data = data;
    }

    public long getTimestamp() { return timestamp; }
    public String getType() { return type; }
    public double[] getData() { return data; }
}
