import java.net.InetSocketAddress;
import java.net.URI;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import org.apache.mina.transport.socket.DatagramConnector;
import org.apache.mina.transport.socket.nio.NioDatagramConnector;

public DatagramConnector setupDatagramConnection(String connectionUri) {
    try {
        URI uri = new URI(connectionUri);
        String query = uri.getQuery();

        if (query != null && query.contains("transferExchange=true")) {
            throw new IllegalArgumentException("Transfer exchange cannot be set to true");
        }

        String host = uri.getHost();
        int port = uri.getPort();
        if (host == null || port == -1) {
            throw new IllegalArgumentException("Invalid URI: host and port required");
        }

        int processorCount = Runtime.getRuntime().availableProcessors();
        ExecutorService executor = Executors.newFixedThreadPool(processorCount);

        NioDatagramConnector connector = new NioDatagramConnector(processorCount);
        connector.setExecutor(executor);
        connector.setDefaultRemoteAddress(new InetSocketAddress(host, port));

        return connector;
    } catch (Exception e) {
        if (e instanceof IllegalArgumentException) {
            throw (IllegalArgumentException) e;
        }
        throw new IllegalArgumentException("Failed to setup connection", e);
    }
}
