import java.io.*;
import java.util.Optional;
import java.util.concurrent.*;

public class CommandExecutor {
    public static int execute(String[] command, InputStream input, OutputStream output, Optional<Long> timeoutMillis) throws IOException, InterruptedException, TimeoutException {
        Process process = Runtime.getRuntime().exec(command);
        ExecutorService executor = Executors.newFixedThreadPool(3);

        Future<?> inputTask = executor.submit(() -> {
            if (input != null) {
                try (OutputStream processIn = process.getOutputStream()) {
                    input.transferTo(processIn);
                } catch (IOException e) {
                    throw new RuntimeException(e);
                }
            }
        });

        Future<?> outputTask = executor.submit(() -> {
            try (InputStream processOut = process.getInputStream()) {
                if (output != null) {
                    processOut.transferTo(output);
                } else {
                    processOut.transferTo(OutputStream.nullOutputStream());
                }
            } catch (IOException e) {
                throw new RuntimeException(e);
            }
        });

        Future<?> errorTask = executor.submit(() -> {
            try (InputStream processErr = process.getErrorStream()) {
                processErr.transferTo(OutputStream.nullOutputStream());
            } catch (IOException e) {
                // Ignore
            }
        });

        try {
            boolean finished;
            if (timeoutMillis.isPresent()) {
                finished = process.waitFor(timeoutMillis.get(), TimeUnit.MILLISECONDS);
                if (!finished) {
                    process.destroyForcibly();
                    throw new TimeoutException("Process timed out after " + timeoutMillis.get() + " ms");
                }
            } else {
                process.waitFor();
            }

            inputTask.get(5, TimeUnit.SECONDS);
            outputTask.get(5, TimeUnit.SECONDS);
            errorTask.get(5, TimeUnit.SECONDS);

            return process.exitValue();
        } catch (ExecutionException e) {
            throw new IOException("Stream processing error", e.getCause());
        } finally {
            executor.shutdownNow();
            process.destroyForcibly();
        }
    }
}
