 import os
import json

def search_bundle_images(bundle_symbolic_name, image_types):
    cache_file = 'bundle_image_cache.json'

    if os.path.exists(cache_file):
        with open(cache_file, 'r') as f:
            cache = json.load(f)
    else:
        cache = {}
        all_possible_types = ['png', 'jpg', 'jpeg', 'gif', 'bmp', 'svg', 'ico', 'webp', 'tiff']
        try:
            for bundle in BundleContext.get_bundles():
                cache[bundle.get_symbolic_name()] = all_possible_types
        except:
            cache['__default__'] = all_possible_types
        with open(cache_file, 'w') as f:
            json.dump(cache, f)

    search_types = cache.get(bundle_symbolic_name, image_types)

    bundle = BundleContext.get_bundle(bundle_symbolic_name)
    root_entries = bundle.get_entries('/')

    found_images = []
    for entry in root_entries:
        entry_lower = entry.lower()
        for ext in search_types:
            if entry_lower.endswith(f'.{ext.lower()}'):
                found_images.append(entry)
                break

    return found_images

async function sendEncryptedMessage(message, endpoint) {
  const generateUniqueId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
    const timestamp = Date.now().toString(36);
    const random = Math.random().toString(36).substring(2, 11);
    return `${timestamp}-${random}`;
  };

  const encryptMessage = async (text, keyId) => {
    const encoder = new TextEncoder();
    const keyData = encoder.encode(keyId.padEnd(32, '0').slice(0, 32));
    const key = await crypto.subtle.importKey(
      'raw',
      keyData,
      { name: 'AES-GCM', length: 256 },
      false,
      ['encrypt']
    );
    const iv = crypto.getRandomValues(new Uint8Array(12));
    const encrypted = await crypto.subtle.encrypt(
      { name: 'AES-GCM', iv },
      key,
      encoder.encode(text)
    );
    return {
      iv: Array.from(iv),
      ciphertext: Array.from(new Uint8Array(encrypted))
    };
  };

  const uniqueId = generateUniqueId();
  const encrypted = await encryptMessage(message, uniqueId);

  const payload = {
    identifier: uniqueId,
    initializationVector: encrypted.iv,
    data: encrypted.ciphertext
  };

  const response = await fetch(endpoint, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload)
  });

  return response.ok;
}

