function createClientTransaction(requestSender, sipRequest, transport) {
  const transactionId = `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

  const logger = {
    log: (message) => console.log(`[${transactionId}] ${message}`),
    error: (message) => console.error(`[${transactionId}] ${message}`),
    debug: (message) => console.debug(`[${transactionId}] ${message}`)
  };

  const transaction = {
    id: transactionId,
    requestSender: requestSender,
    request: sipRequest,
    transport: transport,
    logger: logger,
    send: function() {
      return this.transport(this.request);
    }
  };

  return transaction;
}
