const fs = require('fs').promises;
const path = require('path');

async function validateAndCreate(dirPath, options) {
  const { files = [], directories = [], createMissing = true } = options;

  try {
    const dirStats = await fs.stat(dirPath);
    if (!dirStats.isDirectory()) {
      throw new Error(`Path ${dirPath} is not a directory`);
    }
  } catch (err) {
    if (err.code === 'ENOENT') {
      throw new Error(`Directory ${dirPath} does not exist`);
    }
    throw err;
  }

  for (const dir of directories) {
    const fullPath = path.join(dirPath, dir);
    try {
      const stats = await fs.stat(fullPath);
      if (!stats.isDirectory()) {
        throw new Error(`${fullPath} exists but is not a directory`);
      }
    } catch (err) {
      if (err.code === 'ENOENT') {
        if (createMissing) {
          await fs.mkdir(fullPath, { recursive: true });
        } else {
          throw new Error(`Required directory missing: ${fullPath}`);
        }
      } else {
        throw err;
      }
    }
  }

  for (const file of files) {
    const fullPath = path.join(dirPath, file);
    try {
      const stats = await fs.stat(fullPath);
      if (!stats.isFile()) {
        throw new Error(`${fullPath} exists but is not a file`);
      }
    } catch (err) {
      if (err.code === 'ENOENT') {
        if (createMissing) {
          await fs.writeFile(fullPath, '', 'utf8');
        } else {
          throw new Error(`Required file missing: ${fullPath}`);
        }
      } else {
        throw err;
      }
    }
  }
}

