function sendMessageToIframe(iframe, eventName, data, callback) {
  const message = JSON.stringify({ eventName, data });

  if (typeof callback === 'function') {
    const uniqueName = 'msgListener_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
    const listener = function(event) {
      callback(event.data);
      window.removeEventListener('message', listener);
      delete window[uniqueName];
    };
    window[uniqueName] = listener;
    window.addEventListener('message', listener);
  }

  iframe.contentWindow.postMessage(message, '*');
}
