function initAutocomplete(config) {
    const input = document.querySelector(config.inputSelector);
    const suggestionsContainer = document.querySelector(config.suggestionsSelector);
    const template = Handlebars.compile(document.querySelector(config.templateSelector).innerHTML);
    let timeoutId;

    input.addEventListener('input', function() {
        clearTimeout(timeoutId);
        const query = this.value.trim();

        if (query.length < (config.minLength || 2)) {
            suggestionsContainer.style.display = 'none';
            return;
        }

        timeoutId = setTimeout(() => {
            fetch(`${config.apiUrl}?term=${encodeURIComponent(query)}`, {
                headers: { 'X-Requested-With': 'XMLHttpRequest' }
            })
            .then(response => response.json())
            .then(data => {
                if (!data || data.length === 0) {
                    suggestionsContainer.style.display = 'none';
                    return;
                }

                suggestionsContainer.innerHTML = template({ products: data });
                suggestionsContainer.style.display = 'block';

                const items = suggestionsContainer.querySelectorAll('.autocomplete-suggestion');
                items.forEach((item, index) => {
                    item.addEventListener('click', function() {
                        const product = data[index];
                        input.value = product.name;
                        input.dataset.productId = product.id;
                        input.dataset.productUpc = product.upc;

                        if (config.onSelect) {
                            config.onSelect(product);
                        }

                        suggestionsContainer.style.display = 'none';
                    });
                });
            });
        }, config.delay || 300);
    });

    document.addEventListener('click', function(e) {
        if (!input.contains(e.target) && !suggestionsContainer.contains(e.target)) {
            suggestionsContainer.style.display = 'none';
        }
    });
}
