function calculateTotalAfter2001(dataset, options) {
  options = options || {};
  var valueField = options.valueField || 'value';
  var yearField = options.yearField || 'year';
  var targetSelector = options.targetSelector || '#result';

  var filtered = _.filter(dataset, function(item) {
    return item[yearField] > 2001;
  });

  var total = _.reduce(filtered, function(sum, item) {
    return sum + (parseFloat(item[valueField]) || 0);
  }, 0);

  var years = _.uniq(_.pluck(filtered, yearField)).sort();

  $(targetSelector).html(
    '<div class="total-value">Total: ' + total + '</div>' +
    '<div class="years">Years included: ' + (years.length ? years.join(', ') : 'None') + '</div>'
  );

  return total;
}
