 const restify = require('restify');
const _ = require('lodash');
const async = require('async');

function createPingEndpoint(logger) {
  const server = restify.createServer({
    name: 'ping-api',
    log: logger
  });

  server.use((req, res, next) => {
    req.log.info({method: req.method, url: req.url, headers: req.headers}, 'REQUEST');
    next();
  });

  server.get('/ping', (req, res, next) => {
    async.waterfall([
      (callback) => {
        setImmediate(() => {
          callback(null, {message: 'pong', timestamp: new Date().toISOString()});
        });
      }
    ], (err, result) => {
      if (err) {
        const errorMessage = _.get(err, 'message', 'Internal Server Error');
        const statusCode = _.get(err, 'statusCode', 500);
        req.log.error({err: err}, 'Error processing ping');
        res.send(statusCode, {error: errorMessage});
        return next(false);
      }

      req.log.info({body: result, statusCode: 200}, 'RESPONSE');
      res.send(200, result);
      return next();
    });
  });

  return server;
}

module.exports = createPingEndpoint;

