function escapeString(str, map, unescape = false) {
  const escapeRegex = (s) => s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

  if (unescape) {
    const reverseMap = Object.fromEntries(Object.entries(map).map(([k, v]) => [v, k]));
    const pattern = Object.keys(reverseMap)
      .sort((a, b) => b.length - a.length)
      .map(escapeRegex)
      .join('|');
    const regex = new RegExp(pattern, 'g');
    return str.replace(regex, match => reverseMap[match]);
  } else {
    const pattern = Object.keys(map)
      .sort((a, b) => b.length - a.length)
      .map(escapeRegex)
      .join('|');
    const regex = new RegExp(pattern, 'g');
    return str.replace(regex, match => map[match]);
  }
}
