  const regexNumbers = /\bNumbers\b/gi;
  const regexDeuteronomy = /\bDeuteronomy\b/gi;
  const regexJoshua = /\bJoshua\b/gi;
  const regexJudges = /\bJudges\b/gi;
  const regexRuth = /\bRuth\b/gi;
  const regex1Samuel = /\b(?:1\s*Samuel|1st\s*Samuel|First\s*Samuel)\b/gi;
  const regex2Samuel = /\b(?:2\s*Samuel|2nd\s*Samuel|Second\s*Samuel)\b/gi;
  const regex1Kings = /\b(?:1\s*Kings|1st\s*Kings|First\s*Kings)\b/gi;
  const regex2Kings = /\b(?:2\s*Kings|2nd\s*Kings|Second\s*Kings)\b/gi;
  const regex1Chronicles = /\b(?:1\s*Chronicles|1st\s*Chronicles|First\s*Chronicles)\b/gi;
  const regex2Chronicles = /\b(?:2\s*Chronicles|2nd\s*Chronicles|Second\s*Chronicles)\b/gi;
  const regexEzra = /\bEzra\b/gi;
  const regexNehemiah = /\bNehemiah\b/gi;
  const regexEsther = /\bEsther\b/gi;
  const regexJob = /\bJob\b/gi;
  const regexPsalms = /\b(?:Psalms|Psalm)\b/gi;
  const regexProverbs = /\bProverbs\b/gi;
  const regexEcclesiastes = /\bEcclesiastes\b/gi;
  const regexSongOfSolomon = /\b(?:Song\s*of\s*Solomon|Song\s*of\s*Songs|Canticles)\b/gi;
  const regexIsaiah = /\bIsaiah\b/gi;
  const regexJeremiah = /\bJeremiah\b/gi;
  const regexLamentations = /\bLamentations\b/gi;
  const regexEzekiel = /\bEzekiel\b/gi;
  const regexDaniel = /\bDaniel\b/gi;
  const regexHosea = /\bHosea\b/gi;
  const regexJoel = /\bJoel\b/gi;
  const regexAmos = /\bAmos\b/gi;
  const regexObadiah = /\bObadiah\b/gi;
  const regexJonah = /\bJonah\b/gi;
  const regexMicah = /\bMicah\b/gi;
  const regexNahum = /\bNahum\b/gi;
  const regexHabakkuk = /\bHabakkuk\b/gi;
