async function makeServerRequest(url, data, errorCallback) {
  if (data && 'secretPhrase' in data) {
    if (data.account && data.account.errorCode === 5) {
      if (typeof errorCallback === 'function') {
        errorCallback(new Error('Account error code 5'));
      }
    }

    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(data)
    });

    return response;
  } else {
    const randomParam = Math.random().toString(36).substring(2);
    const separator = url.includes('?') ? '&' : '?';
    const requestUrl = `${url}${separator}rand=${randomParam}`;

    const response = await fetch(requestUrl, {
      method: 'GET'
    });

    return response;
  }
}
