 ```javascript
const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

function createPackages(packageName) {
  const version = '1.0.0';
  const buildDir = path.join(process.cwd(), 'build');

  const debDir = path.join(buildDir, `${packageName}_${version}_amd64`);
  const debianDir = path.join(debDir, 'DEBIAN');

  fs.mkdirSync(path.join(debDir, 'usr', 'bin'), { recursive: true });
  fs.mkdirSync(debianDir, { recursive: true });

  fs.writeFileSync(path.join(debianDir, 'control'), 
    `Package: ${packageName}\nVersion: ${version}\nArchitecture: amd64\nMaintainer: builder@example.com\nDescription: ${packageName}\n`);

  const binPath = path.join(debDir, 'usr', 'bin', packageName);
  fs.writeFileSync(binPath, '#!/bin/bash\necho "Hello from ${packageName}"');
  fs.chmodSync(binPath, 0o755);

  try {
    execSync(`dpkg-deb --build ${debDir}`, { stdio: 'inherit' });
  } catch (e) {
    console.error('dpkg-deb failed:', e.message);
    process.exit(1);
  }

  try {
    execSync('which rpmbuild', { stdio: 'pipe' });

    const rpmTopDir = path.join(buildDir, 'rpmbuild');
    ['BUILD', 'RPMS', 'SOURCES', 'SPECS', 'SRPMS'].forEach(d => 
      fs.mkdirSync(path.join(rpmTopDir, d), { recursive: true })
    );

    const rpmBuildDir = path.join(buildDir, 'rpm-src');
    fs.mkdirSync(path.join(rpmBuildDir, 'usr', 'bin'), { recursive: true });
    fs.copyFileSync(binPath, path.join(rpmBuildDir, 'usr', 'bin', packageName));

    const tarName = `${packageName}-${version}.tar.gz`;
    execSync(`tar czf ${path.join(rpmTopDir, 'SOURCES', tarName)} -C ${buildDir} rpm-src`);

    fs.writeFileSync(path.join(rpmTopDir, 'SPECS', `${packageName}.spec`),
      `Name: ${packageName}\nVersion: ${version}\nRelease: 1\nSummary: ${packageName}\nLicense: MIT\nSource0: ${tarName}\n%description\n${packageName}\n%prep\n%setup -q -n rpm-src\n%install\ncp -r usr %{buildroot}/\n%files\n/usr/bin/${packageName}\n`);

    execSync(`rpmbuild --define "_topdir ${rpmTopDir}" -bb ${path.join(rpmTopDir, 'SPECS', packageName + '.spec')}`, 
      { stdio: 'inherit' });

  } catch (e) {
    console.log('rpmbuild not available, skipping RPM');
  }
}

createPackages(process.argv[2] || 'package');
