function modifyJsonArray(jsonObj, targetObj) {
  const result = JSON.parse(JSON.stringify(jsonObj));
  const arrayKey = Object.keys(result).find(key => Array.isArray(result[key]));

  if (arrayKey) {
    result[arrayKey] = result[arrayKey].map(item => ({
      ...item,
      path: item.path !== undefined 
        ? `${item.path}/${targetObj.newPathComponent || targetObj.path || ''}` 
        : (targetObj.newPathComponent || targetObj.path || ''),
      sort: `${targetObj.newSortValue || targetObj.sortPrefix || ''}${item.sort !== undefined ? item.sort : ''}`
    }));
  }

  return result;
}

