function generateUniqueIdentifier(length, charset, existingCollection) {
  const existing = new Set(existingCollection);
  const maxAttempts = 10000;

  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    let id = '';
    for (let i = 0; i < length; i++) {
      id += charset.charAt(Math.floor(Math.random() * charset.length));
    }
    if (!existing.has(id)) {
      return id;
    }
  }

  throw new Error('Unable to generate unique identifier: possible exhaustion of available combinations');
}
