<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D Human Body Model</title>
    <style>
        body { margin: 0; overflow: hidden; }
        canvas { display: block; }
    </style>
</head>
<body>
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>
    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // Scene setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x222222);

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(0, 1.5, 3);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.target.set(0, 1, 0);
        controls.update();

        // Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.5);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(5, 10, 7);
        dirLight.castShadow = true;
        scene.add(dirLight);

        // Create texture for body front
        function createBodyTexture() {
            const canvas = document.createElement('canvas');
            canvas.width = 512;
            canvas.height = 512;
            const ctx = canvas.getContext('2d');

            ctx.fillStyle = '#2c3e50';
            ctx.fillRect(0, 0, 512, 512);

            ctx.fillStyle = '#e74c3c';
            ctx.beginPath();
            ctx.arc(256, 200, 80, 0, Math.PI * 2);
            ctx.fill();

            ctx.fillStyle = '#ecf0f1';
            ctx.font = 'bold 60px Arial';
            ctx.textAlign = 'center';
            ctx.fillText('BODY', 256, 400);

            const texture = new THREE.CanvasTexture(canvas);
            return texture;
        }

        // Materials
        const headMaterial = new THREE.MeshStandardMaterial({ 
            color: 0xffdbac,
            roughness: 0.3
        });

        const bodyTexture = createBodyTexture();
        const bodyFrontMaterial = new THREE.MeshStandardMaterial({ 
            map: bodyTexture,
            roughness: 0.5
        });
        const bodyOtherMaterial = new THREE.MeshStandardMaterial({ 
            color: 0x34495e,
            roughness: 0.7
        });

        const limbMaterial = new THREE.MeshStandardMaterial({ 
            color: 0x2980b9,
            roughness: 0.6
        });

        // Body materials array: right, left, top, bottom, front, back
        const bodyMaterials = [
            bodyOtherMaterial, // right
            bodyOtherMaterial, // left
            bodyOtherMaterial, // top
            bodyOtherMaterial, // bottom
            bodyFrontMaterial, // front
            bodyOtherMaterial  // back
        ];

        // Human group
        const human = new THREE.Group();

        // Head
        const headGeometry = new THREE.SphereGeometry(0.2, 32, 32);
        const head = new THREE.Mesh(headGeometry, headMaterial);
        head.position.y = 1.7;
        head.castShadow = true;
        human.add(head);

        // Body (torso)
        const bodyGeometry = new THREE.BoxGeometry(0.5, 0.6, 0.25);
        const body = new THREE.Mesh(bodyGeometry, bodyMaterials);
        body.position.y = 1.1;
        body.castShadow = true;
        human.add(body);

        // Arms
        const armGeometry = new THREE.BoxGeometry(0.12, 0.5, 0.12);

        const leftArm = new THREE.Mesh(armGeometry, limbMaterial);
        leftArm.position.set(-0.35, 1.1, 0);
        leftArm.castShadow = true;
        human.add(leftArm);

        const rightArm = new THREE.Mesh(armGeometry, limbMaterial);
        rightArm.position.set(0.35, 1.1, 0);
        rightArm.castShadow = true;
        human.add(rightArm);

        // Legs
        const legGeometry = new THREE.BoxGeometry(0.15, 0.6, 0.15);

        const leftLeg = new THREE.Mesh(legGeometry, limbMaterial);
        leftLeg.position.set(-0.15, 0.35, 0);
        leftLeg.castShadow = true;
        human.add(leftLeg);

        const rightLeg = new THREE.Mesh(legGeometry, limbMaterial);
        rightLeg.position.set(0.15, 0.35, 0);
        rightLeg.castShadow = true;
        human.add(rightLeg);

        scene.add(human);

        // Ground plane
        const groundGeometry = new THREE.PlaneGeometry(10, 10);
        const groundMaterial = new THREE.MeshStandardMaterial({ color: 0x555555 });
        const ground = new THREE.Mesh(groundGeometry, groundMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // Animation loop
        function animate() {
            requestAnimationFrame(animate);
            human.rotation.y += 0.005;
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
