function extractNames(text) {
  const patterns = [
    /(?:Dr|Mr|Mrs|Ms|Miss|Prof|Sir|Madam|Lady|Lord|Rev|Capt|Major|Col|Gen|Sgt)\.?\s+(?:[A-Z]\.?\s*){0,2}[A-Z][a-zA-Z]*(?:\s+[A-Z][a-zA-Z]*)?/g,
    /[A-Z][a-zA-Z]*(?:\s+[A-Z]\.?(?:\s+|\b)){0,2}(?:\s+[A-Z][a-zA-Z]*)+/g,
    /[A-Z][a-zA-Z]*(?:-[A-Z][a-zA-Z]*)*,\s+(?:[A-Z]\.?\s*){0,2}[A-Z][a-zA-Z]*/g
  ];

  const matches = [];

  patterns.forEach(regex => {
    let match;
    while ((match = regex.exec(text)) !== null) {
      const name = match[0].trim();
      const start = match.index;
      const end = start + name.length;

      if (name.length < 3 || /^[A-Z]\.$/.test(name)) continue;

      const isOverlapping = matches.some(m => 
        (start >= m.start && start < m.end) || 
        (end > m.start && end <= m.end)
      );

      if (!isOverlapping) {
        matches.push({
          name,
          start,
          end,
          context: text.slice(Math.max(0, start - 20), Math.min(text.length, end + 20))
        });
      }
    }
  });

  const unique = {};
  matches.forEach(m => {
    const key = m.name.replace(/\s+/g, ' ');
    if (!unique[key]) {
      unique[key] = { name: key, references: [] };
    }
    unique[key].references.push({
      position: { start: m.start, end: m.end },
      context: m.context
    });
  });

  return Object.values(unique);
}
