function createBenchmark(fn, iterations) {
  return function harness() {
    let start;
    let passed = true;
    const times = [];

    const b = {
      tic: () => { start = performance.now(); },
      toc: () => { const t = performance.now() - start; times.push(t); return t; },
      ok: (result) => { if (!result) passed = false; return result; },
      end: () => { passed = false; }
    };

    for (let i = 0; i < iterations && passed; i++) {
      fn(b);
    }

    return { times, passed, iterations: times.length };
  };
}
