function setupMessagePassing(id, callback) {
  let cleanup = () => {};
  const global = typeof window !== 'undefined' ? window : typeof self !== 'undefined' ? self : null;

  if (typeof MessageChannel !== 'undefined') {
    try {
      const channel = new MessageChannel();
      channel.port1.onmessage = (event) => {
        if (event.data === id) callback(id);
      };
      if (global && global.postMessage) {
        global.postMessage({__initChannel: true, id: id}, '*', [channel.port2]);
      }
      return () => channel.port1.close();
    } catch (e) {}
  }

  if (global && global.addEventListener) {
    const handler = (event) => {
      if (event.data === id || (event.data && event.data.id === id)) {
        callback(id);
      }
    };
    global.addEventListener('message', handler);
    cleanup = () => global.removeEventListener('message', handler);
  } else if (typeof localStorage !== 'undefined') {
    const key = `__msg_${id}`;
    let lastValue = localStorage.getItem(key);
    const intervalId = setInterval(() => {
      const current = localStorage.getItem(key);
      if (current !== null && current !== lastValue) {
        lastValue = current;
        callback(id);
      }
    }, 100);
    cleanup = () => clearInterval(intervalId);
  }

  return cleanup;
}
