```javascript
function createDraggableObject(element, startButton, stopButton, minX, maxX, minY, maxY) {
    let isDragMode = false;
    let isDragging = false;
    let startX, startY, initialLeft, initialTop;

    function onDragStart(e) {
        if (!isDragMode) return;
        isDragging = true;
        startX = e.clientX;
        startY = e.clientY;
        initialLeft = element.offsetLeft;
        initialTop = element.offsetTop;
        element.style.cursor = 'grabbing';
    }

    function onDrag(e) {
        if (!isDragging) return;
        e.preventDefault();
        const dx = e.clientX - startX;
        const dy = e.clientY - startY;

        let newLeft = initialLeft + dx;
        let newTop = initialTop + dy;

        if (minX !== undefined) newLeft = Math.max(newLeft, minX);
        if (maxX !== undefined) newLeft = Math.min(newLeft, maxX);
        if (minY !== undefined) newTop = Math.max(newTop, minY);
        if (maxY !== undefined) newTop = Math.min(newTop, maxY);

        element.style.left = newLeft + 'px';
        element.style.top = newTop + 'px';
    }

    function onDragEnd(e) {
        isDragging = false;
        element.style.cursor = isDragMode ? 'grab' : 'default';
    }

    startButton.addEventListener('mousedown', function() {
        isDragMode = true;
        element.style.cursor = 'grab';
    });

    stopButton.addEventListener('mousedown', function() {
        isDragMode = false;
        isDragging = false;
        element.style.cursor = 'default';
    });

    element.addEventListener('mousedown', onDragStart);
    document.addEventListener('mousemove', onDrag);
    document.addEventListener('mouseup', onDragEnd);
}
