```typescript
import type { ValidationMap, Validator } from 'prop-types';

export const createPropTypeChecker = (
  propTypes: ValidationMap<any>,
  componentName: string
): ((props: any) => void) => {
  const cache = new WeakMap<object, boolean>();

  return (props: any): void => {
    if (typeof props !== 'object' || props === null) {
      throw new Error(`Invalid props for ${componentName}: expected object`);
    }

    if (cache.has(props)) {
      return;
    }

    const errors: string[] = [];

    for (const [propName, validator] of Object.entries(propTypes)) {
      const error = validator(props, propName, componentName, 'prop', null);
      if (error instanceof Error) {
        console.warn(error.message);
        errors.push(error.message);
      }
    }

    if (errors.length > 0) {
      throw new Error(
        `Prop validation failed for ${componentName}:\n${errors.join('\n')}`
      );
    }

    cache.set(props, true);
  };
};
