function extendURLPrototype() {
  URL.prototype.hasBeenAdded = function(key) {
    const hash = this.hash.substring(1);
    if (!hash) return false;
    const params = new URLSearchParams(hash);
    return params.has(key);
  };

  URL.prototype.updateUrl = function(hashObj) {
    if (!hashObj || Object.keys(hashObj).length === 0) {
      this.hash = '';
    } else {
      const params = new URLSearchParams();
      for (const [key, value] of Object.entries(hashObj)) {
        params.set(key, value);
      }
      this.hash = params.toString();
    }
  };
}
