const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

function processFile(src_filename, dest_filename, arch, version) {
    let content = fs.readFileSync(src_filename, 'utf8');
    content = content.replace(/{{version}}/g, version);
    content = content.replace(/{{arch}}/g, arch);
    fs.mkdirSync(path.dirname(dest_filename), { recursive: true });
    fs.writeFileSync(dest_filename, content);

    try {
        execSync('which dpkg-deb', { stdio: 'ignore' });

        ['linux32', 'linux64'].forEach(targetArch => {
            const pkgDir = `package_${targetArch}`;
            const debianDir = path.join(pkgDir, 'DEBIAN');
            const binDir = path.join(pkgDir, 'usr', 'bin');

            fs.mkdirSync(debianDir, { recursive: true });
            fs.mkdirSync(binDir, { recursive: true });

            const debArch = targetArch === 'linux32' ? 'i386' : 'amd64';
            fs.writeFileSync(
                path.join(debianDir, 'control'),
                `Package: myapp\nVersion: ${version}\nArchitecture: ${debArch}\nMaintainer: user\nDescription: Application\n`
            );

            fs.copyFileSync(dest_filename, path.join(binDir, path.basename(dest_filename)));
            execSync(`dpkg-deb --build ${pkgDir}`);
        });
    } catch (err) {
        console.log('dpkg-deb is not installed, skipping .deb package creation');
    }
}
