function parseMetaEvent(stream, offset) {
  if (stream[offset] !== 0xFF) {
    throw new Error('Invalid meta event marker');
  }

  const subtypeByte = stream[offset + 1];
  let pos = offset + 2;

  let length = 0;
  while (stream[pos] & 0x80) {
    length = (length << 7) | (stream[pos] & 0x7F);
    pos++;
  }
  length = (length << 7) | stream[pos];
  pos++;

  const event = {
    subtype: '',
    numerator: undefined,
    denominator: undefined,
    metronome: undefined,
    thirtyseconds: undefined,
    key: undefined,
    scale: undefined,
    data: undefined
  };

  switch (subtypeByte) {
    case 0x58:
      if (length !== 4) {
        throw new Error(`Time signature meta event length mismatch: expected 4, got ${length}`);
      }
      event.subtype = 'timeSignature';
      event.numerator = stream[pos];
      event.denominator = Math.pow(2, stream[pos + 1]);
      event.metronome = stream[pos + 2];
      event.thirtyseconds = stream[pos + 3];
      pos += 4;
      break;

    case 0x59:
      if (length !== 2) {
        throw new Error(`Key signature meta event length mismatch: expected 2, got ${length}`);
      }
      event.subtype = 'keySignature';
      const keyByte = stream[pos];
      event.key = keyByte > 127 ? keyByte - 256 : keyByte;
      event.scale = stream[pos + 1];
      pos += 2;
      break;

    case 0x7F:
      event.subtype = 'sequencerSpecific';
      event.data = Array.from(stream.subarray(pos, pos + length));
      pos += length;
      break;

    default:
      event.subtype = 'unknown';
      console.error(`Unknown meta event subtype: 0x${subtypeByte.toString(16).padStart(2, '0')}`);
      pos += length;
      break;
  }

  return { event, newOffset: pos };
}
