import java.math.BigInteger;
import java.util.Arrays;
import java.util.Random;

public class UnsignedArrayProcessor {

    public static long[] processIntArray(int[] input) {
        if (input == null) return null;
        long[] result = new long[input.length];
        for (int i = 0; i < input.length; i++) {
            result[i] = Integer.toUnsignedLong(input[i]);
        }
        return result;
    }

    public static BigInteger[] processLongArray(long[] input) {
        if (input == null) return null;
        BigInteger[] result = new BigInteger[input.length];
        for (int i = 0; i < input.length; i++) {
            if (input[i] >= 0) {
                result[i] = BigInteger.valueOf(input[i]);
            } else {
                result[i] = BigInteger.valueOf(input[i] >>> 1).shiftLeft(1).add(BigInteger.valueOf(input[i] & 1));
            }
        }
        return result;
    }

    public static void main(String[] args) {
        int[] empty = new int[0];
        int[] singleZero = {0};
        int[] positiveValues = {1, 100, 1000, Integer.MAX_VALUE};
        int[] negativeValues = {-1, -100, Integer.MIN_VALUE};
        int[] mixedEdgeCases = {0, 1, -1, Integer.MAX_VALUE, Integer.MIN_VALUE, 42, -42};

        System.out.println("Empty: " + Arrays.toString(processIntArray(empty)));
        System.out.println("Zero: " + Arrays.toString(processIntArray(singleZero)));
        System.out.println("Positive: " + Arrays.toString(processIntArray(positiveValues)));
        System.out.println("Negative: " + Arrays.toString(processIntArray(negativeValues)));
        System.out.println("Mixed: " + Arrays.toString(processIntArray(mixedEdgeCases)));

        int[] largeArray = new int[10000];
        Random rand = new Random();
        for (int i = 0; i < largeArray.length; i++) {
            largeArray[i] = rand.nextInt();
        }
        long[] unsignedLarge = processIntArray(largeArray);
        System.out.println("Large array processed, size: " + unsignedLarge.length);

        long[] longArray = {0L, 1L, -1L, Long.MAX_VALUE, Long.MIN_VALUE};
        BigInteger[] unsignedLongs = processLongArray(longArray);
        System.out.println("Long values: " + Arrays.toString(unsignedLongs));
    }
}
