public class PairProcessor {
    public void processPairs(List<SimpleEntry<Integer, Boolean>> pairs, double percentage) {
        if (pairs == null || pairs.isEmpty() || percentage <= 0) {
            return;
        }

        int targetCount = (int) Math.ceil(pairs.size() * Math.min(percentage, 1.0));
        Random random = new Random();

        for (int i = 0; i < targetCount; i++) {
            boolean isLast = (i == pairs.size() - 1);

            if (isLast) {
                System.out.println("Current pair is the last one.");
            } else {
                System.out.println("Current pair is not the last one.");
            }

            if (!isLast && i > 0) {
                int previousIndex = random.nextInt(i);
                SimpleEntry<Integer, Boolean> currentPair = pairs.remove(i);
                pairs.add(previousIndex, currentPair);
            }
        }
    }
}

