import java.util.HashMap;
import java.util.Map;

public class DisjointPairCounter {
    public static int countDisjointPairs(int[] arr) {
        int n = arr.length;
        Map<Integer, Integer> valueToIndex = new HashMap<>();
        for (int i = 0; i < n; i++) {
            valueToIndex.put(arr[i], i);
        }

        UnionFind uf = new UnionFind(n);

        for (int i = 0; i < n - 1; i += 2) {
            int u = valueToIndex.get(arr[i]);
            int v = valueToIndex.get(arr[i + 1]);
            uf.union(u, v);
        }

        int disjointCount = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                long startTime = System.nanoTime();
                boolean isDisjoint = uf.find(i) != uf.find(j);
                long endTime = System.nanoTime();
                double milliseconds = (endTime - startTime) / 1_000_000.0;
                System.out.println("Pair (" + arr[i] + ", " + arr[j] + ") check took " + milliseconds + " ms");

                if (isDisjoint) {
                    disjointCount++;
                }
            }
        }

        return disjointCount;
    }

    static class UnionFind {
        private int[] parent;
        private int[] rank;

        public UnionFind(int size) {
            parent = new int[size];
            rank = new int[size];
            for (int i = 0; i < size; i++) {
                parent[i] = i;
            }
        }

        public int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public void union(int x, int y) {
            int rootX = find(x);
            int rootY = find(y);

            if (rootX == rootY) return;

            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX;
            } else {
                parent[rootY] = rootX;
                rank[rootX]++;
            }
        }
    }
}
