import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.UUID;

public static UUID generateMD5UUID() {
    try {
        MessageDigest md = MessageDigest.getInstance("MD5");
        byte[] input = Long.toString(System.currentTimeMillis()).getBytes();
        byte[] digest = md.digest(input);

        long mostSigBits = 0;
        long leastSigBits = 0;

        for (int i = 0; i < 8; i++) {
            mostSigBits = (mostSigBits << 8) | (digest[i] & 0xff);
        }
        for (int i = 8; i < 16; i++) {
            leastSigBits = (leastSigBits << 8) | (digest[i] & 0xff);
        }

        mostSigBits = (mostSigBits & 0xffffffffffff0fffL) | 0x0000000000003000L;
        leastSigBits = (leastSigBits & 0x3fffffffffffffffL) | 0x8000000000000000L;

        return new UUID(mostSigBits, leastSigBits);
    } catch (NoSuchAlgorithmException e) {
        throw new RuntimeException("MD5 algorithm not available", e);
    }
}
