import itertools
import random

def batch_generator(list_of_lists, batch_size, n_cycles):
    batches = [list_of_lists[i:i+batch_size] for i in range(0, len(list_of_lists), batch_size)]

    for batch in batches:
        lengths = {len(sublist) for sublist in batch}
        if len(lengths) != 1:
            raise ValueError("Batch contains lists of different lengths")

    indices = list(range(len(batches)))

    for cycle in itertools.islice(itertools.count(), n_cycles):
        random.shuffle(indices)
        for idx in indices:
            batch = batches[idx]
            for item_tuple in zip(*batch):
                yield item_tuple

    raise StopIteration
