const fs = require('fs');
const path = require('path');

function prepareAndSend(directory, filename, callback) {
  const filePath = path.join(directory, filename);

  fs.access(filePath, fs.constants.F_OK, (err) => {
    if (err) {
      return callback(new Error('File does not exist'));
    }

    fs.readFile(filePath, 'utf8', (err, data) => {
      if (err) {
        return callback(new Error('Error reading file'));
      }

      try {
        const templateEngine = require('ejs');
        const rendered = templateEngine.render(data, {});
        callback(null, rendered);
      } catch (error) {
        callback(new Error('Template rendering error'));
      }
    });
  });
}
