function parseCSSSelector(selector) {
  if (typeof selector !== 'string') return null;

  selector = selector.trim();
  if (!selector) return { input: '', parts: [] };

  const unescape = (str) => {
    return str
      .replace(/\\([0-9a-fA-F]{1,6})\s?/g, (_, hex) => 
        String.fromCharCode(parseInt(hex, 16)))
      .replace(/\\(.)/g, (_, char) => char);
  };

  const parseAttr = (content) => {
    const match = content.match(/^((?:\\.|[^=\]])+?)\s*(?:([~|^$*]?=)\s*((?:\\.|[^\]])*))?$/);
    if (!match) return { name: content.trim() };

    let [, name, op, value] = match;
    name = unescape(name.trim());

    if (op) {
      value = value.trim();
      if ((value[0] === '"' && value[value.length-1] === '"') || 
          (value[0] === "'" && value[value.length-1] === "'")) {
        value = value.slice(1, -1);
      }
      value = unescape(value);
      return { name, operator: op, value };
    }
    return { name };
  };

  const parts = [];
  let current = {
    combinator: null,
    element: null,
    id: null,
    classes: [],
    attributes: [],
    pseudos: []
  };

  const patterns = {
    combinator: /^\s*([>+~])\s*|^\s+/,
    universal: /^\*/,
    id: /^#((?:\\[0-9a-fA-F]{1,6}\s?|\\.|[^[>+~\s.#])+)/,
    class: /^\.((?:\\[0-9a-fA-F]{1,6}\s?|\\.|[^[>+~\s.#])+)/,
    attribute: /^\[((?:\\.|[^\]])*)\]/,
    pseudo: /^::?((?:\\[0-9a-fA-F]{1,6}\s?|\\.|[^[(>+~\s.#])+)(?:\((?:\\.|[^)])*\))?/,
    element: /^((?:\\[0-9a-fA-F]{1,6}\s?|\\.|[^[>+~\s.#*:])+)/,
  };

  let lastWasCombinator = true;

  while (selector) {
    let matched = false;

    if (!lastWasCombinator) {
      const comb = selector.match(patterns.combinator);
      if (comb) {
        if (current.element !== null || current.id !== null || 
            current.classes.length > 0 || current.attributes.length > 0 || 
            current.pseudos.length > 0) {
          parts.push(current);
        }

        current = {
          combinator: comb[1] ? comb[1].trim() : 'descendant',
          element: null,
          id: null,
          classes: [],
          attributes: [],
          pseudos: []
        };

        selector = selector.slice(comb[0].length);
        lastWasCombinator = true;
        matched = true;
      }
    } else {
      const ws = selector.match(/^\s+/);
      if (ws) {
        selector = selector.slice(ws[0].length);
        matched = true;
      }
    }

    if (!matched) {
      let found = false;

      const uni = selector.match(patterns.universal);
      if (uni) {
        current.element = '*';
        selector = selector.slice(uni[0].length);
        found = true;
      }

      if (!found) {
        const id = selector.match(patterns.id);
        if (id) {
          current.id = unescape(id[1]);
          selector = selector.slice(id[0].length);
          found = true;
        }
      }

      if (!found) {
        const cls = selector.match(patterns.class);
        if (cls) {
          current.classes.push(unescape(cls[1]));
          selector = selector.slice(cls[0].length);
          found = true;
        }
      }

      if (!found) {
        const attr = selector.match(patterns.attribute);
        if (attr) {
          current.attributes.push(parseAttr(attr[1]));
          selector = selector.slice(attr[0].length);
          found = true;
        }
      }

      if (!found) {
        const pseudo = selector.match(patterns.pseudo);
        if (pseudo) {
          const p = { name: unescape(pseudo[1]) };
          const full = pseudo[0];
          const parenIdx = full.indexOf('(');
          if (parenIdx !== -1) {
            p.argument = full.slice(parenIdx + 1, -1);
          }
          current.pseudos.push(p);
          selector = selector.slice(full.length);
          found = true;
        }
      }

      if (!found) {
        const elem = selector.match(patterns.element);
        if (elem) {
          current.element = unescape(elem[1]);
          selector = selector.slice(elem[0].length);
          found = true;
        }
      }

      if (found) {
        lastWasCombinator = false;
        matched = true;
      }
    }

    if (!matched) break;
  }

  if (current.element !== null || current.id !== null || 
      current.classes.length > 0 || current.attributes.length > 0 || 
      current.pseudos.length > 0) {
    parts.push(current);
  }

  return {
    input: selector,
    parts: parts
  };
}
```
